INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(310835, 'zhCN', '', '令我惊讶的是，洛瑟玛对此的反应……还算平静。\n\n也许我们已经说服了他，永歌森林的安全取决于与邻邦建立良好关系，无论对方是谁。', 66384),
(310653, 'zhCN', '', '坎扎开始抚摸火花。', 66384),
(310490, 'zhCN', '得知她平安抵达，我就放心了！\n\n谢谢你，如果不介意的话，就陪我坐一会儿吧。\n\n脚步太快，会让你错过身边的美好。', '得知她平安抵达，我就放心了！\n\n谢谢你，如果不介意的话，就陪我坐一会儿吧。\n\n脚步太快，会让你错过身边的美好。', 66384),
(310484, 'zhCN', '<这只小水豚看起来惊恐万分，孤立无援。>', '', 66384),
(310480, 'zhCN', '不过，能帮我个忙吗？\n\n那边最后一只小水豚吓坏了，对什么都瑟瑟发抖。我也哄不出来。你能带她去费洛神殿吗？在那儿给她找个能玩耍的好池子。\n\n她害怕大多数大块头生物，所以你可能没法骑坐骑。全程走过去可是一场马拉松……\n\n我倒是想去，但我不能惊动这些小家伙！', '不过，能帮我个忙吗？\n\n那边最后一只小水豚吓坏了，对什么都瑟瑟发抖。我也哄不出来。你能带她去费洛神殿吗？在那儿给她找个能玩耍的好池子。\n\n她害怕大多数大块头生物，所以你可能没法骑坐骑。全程走过去可是一场马拉松……\n\n我倒是想去，但我不能惊动这些小家伙！', 66384),
(310265, 'zhCN', '<一把折断的小巧匕首遗落在巨型角蛙与幼年水豚的尸体旁。\n\n你发现角蛙身上既有看似数只水豚留下的咬痕，也有数十道由小型武器造成的、慌乱的砍痕——就像旁边那把匕首。\n\n水豚的足迹和小巧的巨魔脚印在角蛙周围来回出现，表明角蛙打断了孩子与她的水豚伙伴的散步。\n\n有人在附近那只死去的水豚周围摆放了鲜花，想必是在祭奠它的牺牲。\n\n孩子的足迹偏离了小径，向河边延伸，而跟在后面的水豚足迹少了一对。>', '<一把折断的小巧匕首遗落在巨型角蛙与幼年水豚的尸体旁。\n\n你发现角蛙身上既有看似数只水豚留下的咬痕，也有数十道由小型武器造成的、慌乱的砍痕——就像旁边那把匕首。\n\n水豚的足迹和小巧的巨魔脚印在角蛙周围来回出现，表明角蛙打断了孩子与她的水豚伙伴的散步。\n\n有人在附近那只死去的水豚周围摆放了鲜花，想必是在祭奠它的牺牲。\n\n孩子的足迹偏离了小径，向河边延伸，而跟在后面的水豚足迹少了一对。>', 66384),
(310237, 'zhCN', '没看见我正忙着调试设备吗？', '', 66384),
(310202, 'zhCN', '', '阿拉托尔告诉我发生了什么。图拉扬竟然……\n\n<奥蕾莉亚的脸上闪过一丝苦痛。>\n\n他们怎么能瞒着我？还瞒了这么久？', 66384),
(310200, 'zhCN', '我本想等到击败萨拉塔斯之后，再告诉奥蕾莉亚关于阿曼尼小径发生的事。\n\n在与如此强敌决战的关头，我们绝不能心乱如麻。', '', 66384),
(310045, 'zhCN', '情况如何，$n？', '', 66384),
(310030, 'zhCN', '', '我能帮你什么忙吗，$n？', 66384),
(309797, 'zhCN', '欢迎，哈舒拉。枯木部族心怀感激，欢迎哈尔拉兹的宠儿。', '', 66384),
(309796, 'zhCN', '哈尔拉兹很高兴看到他的恩赐在枯木山崖帮到了你。\n\n他现在愿意助你一臂之力，但他首先需要你的帮助，哈舒拉。\n\n而且他觉得，你在帮他的同时，或许也是在帮你自己！', '', 66384),
(309775, 'zhCN', '你想知道万毒之母的事？好吧。\n\n她的名字在巨魔的各个分支和部族中都如雷贯耳。在战火纷飞的年代，人们总是频繁呼唤她，因为连神灵都对她的毒液忌惮三分。\n\n不过，我们祖先的传说称她起源于阿曼尼。许多人捍卫对她的信仰，其坚定程度丝毫不亚于对哈尔拉兹或费洛。\n\n多年前曾传出她的死讯，但再往前推几年，也有过同样的传闻。看来即便她东躲西藏、织网自保，死神总能找上门来。', '', 66384),
(309774, 'zhCN', '化身为可怖甲脊蜥的是莫塔姆拉，疫疾之神。\n\n莫塔姆拉和库尔吉实为一体两面。毒疮蔓延之处，必有解药相生。因此，许多钻研医术、草药学、炼金术——当然还有毒药的人，也会供奉这位甲脊蜥神灵。\n\n他的信徒前往残破神庙下，深入蜿蜒墓穴中他那简陋的神殿。莫非他正在那里抵御邪恶的虚空入侵者？', '', 66384),
(309773, 'zhCN', '你必须思考，什么是“危机”？\n\n危机，优秀的哈舒拉，其实就是变数。\n\n虽然你可能不信，但我告诉你，那些在大海中讨生活的渔夫，就活在凶险与变数之间。\n\n冒着踏入险境的代价，去搏取捕获奇珍异兽的机会！', '', 66384),
(309759, 'zhCN', '许多人，从工匠到农夫，都供奉这位丰饶之神。如果你配得上，他会视你为宠儿。如果你不够格，那你跟地上的尘土没什么两样。\n\n大伙都说，繁荣的气息迟早会飘到你跟前的！', '', 66384),
(309757, 'zhCN', '如果你钻研过医术、草药学或炼金术，库尔吉便会在北方的神殿时刻庇佑着你。我虽未曾踏上她的道路，但长者多鲁曾向我描绘过那里的景致。\n\n多鲁说，站在那里能俯瞰整个天空之桥，而阿曼尼扎就在远处的树影婆娑间若隐若现。', '', 66384),
(309754, 'zhCN', '每当阿曼尼族人踏出家门，大猛犸象便会注视着我们。\n\n若没有她和她族类的眷顾，我们每次外出狩猎、朝圣或在村庄间贸易时，恐怕都会像受惊的水豚一样战战兢兢。', '', 66384),
(309748, 'zhCN', '据我们历史的记录者所知，当我们追逐猎物从沙场一路来到这片未触及的祖阿曼土地时，奥伊一直在暗中庇佑我们的部族。我们没看见他们。我们不认识他们。但他们就在那里。\n\n如今供奉这位树木之主的人，不在任何神殿或祭坛，而在巨大的松树旁。\n\n他们说，是汲取了生长之灵才让松树变得如此参天。但若树木贪得无厌，汲取了过量的灵，它便会活化并陷入疯狂的暴怒。', '', 66384),
(309747, 'zhCN', '费洛神殿坐落在舒缓温泉中央的一座小岛上。那是迈萨拉沼泽外三座岛屿中最南边的一座。\n\n虽然他多半不会在你面前显形——除非你那身衣服底下藏着两三个叠罗汉的小孩。', '', 66384),
(309718, 'zhCN', '奉摄政王之命，银月城现已全城戒严。\n\n我们的城市腹背受敌，北有虚空侵袭，南有光绽蔓延。我们的船只和龙鹰仅限勇士等奎尔萨拉斯的保卫者调配。\n\n平民如欲离城，必须经由传送门。', '奉摄政王之命，银月城现已全城戒严。\n\n我们的城市腹背受敌，北有虚空侵袭，南有光绽蔓延。我们的船只和龙鹰仅限勇士等奎尔萨拉斯的保卫者调配。\n\n平民如欲离城，必须经由传送门。', 66384),
(309717, 'zhCN', '我这儿忙得不可开交，没空陪你训练，不过那边那个坩埚你随便用。', '', 66384),
(309716, 'zhCN', '', '长老们尚需时日来评估我们在地表行动的后果。\n\n不过，请放心，$n。当哈籁恩达尔深陷危机而我们却浑然不觉时，是你伸出了援手。这份恩情，我们绝不会忘。\n\n待时机成熟，哈籁尼尔定会助你一力抗击强敌。我对此深信不疑。', 66384),
(309702, 'zhCN', '<祝福祭坛正处于休眠状态。>', '<祝福祭坛正处于休眠状态。>', 66384),
(309690, 'zhCN', '我们……至少得让孩子们离开。\n\n用传送门行吗？\n\n苏拉玛总该欠我们族人一点人情。', '我们……至少得让孩子们离开。\n\n用传送门行吗？\n\n苏拉玛总该欠我们族人一点人情。', 66384),
(309689, 'zhCN', '我听说阿曼尼巨魔和那些教徒正从南方逼近。现在撤离还来得及吗？\n\n我们还能逃到哪儿去呢？', '我听说阿曼尼巨魔和那些教徒正从南方逼近。现在撤离还来得及吗？\n\n我们还能逃到哪儿去呢？', 66384),
(309678, 'zhCN', '', '洞悉盟友与仇敌之间的瓜葛是鳞长的职责。然而，无论我自认对这世界的冲突了解多少，来到此地后，那些认知大半都受到了冲击。\n\n联盟、部落，甚至是那些无阵营人士，似乎都放下了仇恨与旗帜，唯独剩下对美酒、美食与畅谈的渴求。\n\n我开始明白，为何离岛上的龙希尔会选择像平民一样生活。阿苏拉泰或许还不懂，但假以时日，他会明白的。无论旗帜、信条或营子如何，归根结底，我们首先都是龙希尔。', 66384),
(309677, 'zhCN', '随着我的族人日益倾向于平民化的生活，我承认……自己很难完全理解这种转变。\n\n对于一名战士而言，放下兵刃单纯地生活绝非易事。但在这里，我看到许多英雄都在拥抱生活！这想法虽然陌生，却颇为引人入胜，即便我仍未能全然领悟。\n\n或许我也该鼓励其他黑卫士，让他们明白，龙希尔的命运不应只有征战。如果他们看到自己的鳞长也在忙里偷闲，或许其他人也会效法。', '', 66384),
(309669, 'zhCN', '$n！你见到高阶大主教了吗？或者是将军？\n\n有消息说我们什么时候出兵吗？这……这局面怕是撑不了太久啊。', '$n！你见到高阶大主教了吗？或者是将军？\n\n有消息说我们什么时候出兵吗？这……这局面怕是撑不了太久啊。', 66384),
(309668, 'zhCN', '自阿古斯之战以来，从未有过如此纯粹的正义之战。正邪对立，黑白分明。绝不留情。\n\n我们要将毁灭带给敌人，在他们的巢穴中降下天罚！现在只差一个进攻的契机。', '自阿古斯之战以来，从未有过如此纯粹的正义之战。正邪对立，黑白分明。绝不留情。\n\n我们要将毁灭带给敌人，在他们的巢穴中降下天罚！现在只差一个进攻的契机。', 66384),
(309667, 'zhCN', '听说又有一支飞往虚影风暴的远征队全军覆没了。虽说圣光能击退敌人，但想顶着这天空裂痕杀进敌阵，恐怕行不通。\n\n无妨。我坚信我们伟大的领袖们定能想出良策，把大军送进风暴中心。', '听说又有一支飞往虚影风暴的远征队全军覆没了。虽说圣光能击退敌人，但想顶着这天空裂痕杀进敌阵，恐怕行不通。\n\n无妨。我坚信我们伟大的领袖们定能想出良策，把大军送进风暴中心。', 66384),
(309666, 'zhCN', '感谢圣光将我们集结于此。其他教派的信仰卫士也与我们并肩而立。\n\n在此地，我们不再只是圣光军团，而是先锋军！这景象何其宏伟，又何其令人生畏啊，勇士？\n\n我期待着与你并肩作战，以此终结这万物的浩劫。', '感谢圣光将我们集结于此。其他教派的信仰卫士也与我们并肩而立。\n\n在此地，我们不再只是圣光军团，而是先锋军！这景象何其宏伟，又何其令人生畏啊，勇士？\n\n我期待着与你并肩作战，以此终结这万物的浩劫。', 66384),
(309643, 'zhCN', '', '在这四处宝地之中，同一时间唯有一处真正称得上“丰饶”。\n\n只要赶上这风水宝地，我们慷慨的主人——钝顿，便会赐下他那最稀世的秘宝：“纯粹丰饶”。\n\n不过，想用汗水换取这份恩赐，你得先向他供奉一片“钝顿碎片”。\n\n这碎片蕴含着洛阿神灵的神力。只要是在福泽丰饶的土地上，无论是通过制造行当，还是采集矿草、剥皮钓鱼，都有机会得手。\n\n要是去了祖阿曼，那碎片更是遍地都是。不管是藏起来的宝箱，还是那些稀有野兽的尸首上，指不定都能翻出来！', 66384),
(309642, 'zhCN', '我们的虚空精灵同袍正在虚影风暴中苦苦支撑。去看看能不能帮上一把，帮他们稳住阵脚，抵御那无穷无尽的敌人。', '', 66384),
(309641, 'zhCN', '你在哈籁恩达尔的所作所为，为你赢得了一个千载难逢的机会——你可以大摇大摆地走进哈籁尼尔的领地，而不必担心遭到报复。那正好，我想可以从他们的传说和习俗里学到不少东西。\n\n去好好见识一番，回来讲给我听。', '', 66384),
(309640, 'zhCN', '阿曼尼巨魔有一套自己的法子，能从大自然里榨出各种资源来。虽说我更贪恋城里的舒适日子，但不去瞧瞧盟友有些什么好货色，未免太可惜了。\n\n哪怕这活儿得弄脏双手，也认了。', '', 66384),
(309639, 'zhCN', '萨瑟利尔的聚会……是个复杂的名利场。全是上流社会的虚与委蛇，勾心斗角。不过话说回来，为了维持永歌森林的秩序和安宁，他们倒也确实出了力。去吧，帮他们加固一下防线。', '', 66384),
(309634, 'zhCN', '去吧，闯荡世界，见敌必杀！敌人虽众，但我方盟友亦广。尽你所能去帮一把。\n\n完事了记得回来跟我复命。', '', 66384),
(309633, 'zhCN', '', '丰饶祝福会强化你，且随着你的收获和贡献不断增强。\n\n当你收获丰饶，你的基础能力——比如移动速度或战斗力——都会得到提升。\n\n当你贡献了足够多的丰饶，祝福本身也会进化。你能吸纳更远处的灵球，携带上限也会提升，还能强化更多的基础属性。\n\n我们脆弱的凡人之躯只能维持这种力量很短的时间。每次踏入丰饶之地，你都需要重新获取它。', 66384),
(309631, 'zhCN', '', '你采集到的丰饶可以在任意一处丰饶祭坛上交。\n\n慷慨的钝顿会接收这些贡品，并将你与同伴们的贡献汇聚起来。\n\n当贡品足够多时，洛阿将赏赐所有在场者一份荣耀的厚礼！', 66384),
(309630, 'zhCN', '', '可以通过击杀生物，或从草药、矿石等资源点采集来获取丰饶。\n\n在洛阿之力的作用下，所有的丰饶在产生时都会凝聚成球体。只需走近即可收集。\n\n查看你的丰饶之袋，看看你当前携带了多少。', 66384),
(309623, 'zhCN', '', '有什么特别想要的？', 66384),
(309622, 'zhCN', '', '愿丰收眷顾你，助祭。\n\n缺什么吗？', 66384),
(309612, 'zhCN', '让洛萨之子重返故地确实强人所难，但我们需要这里的东西，没别的办法。', '', 66384),
(309607, 'zhCN', '这么多年，我一直唯摄政王马首是瞻。\n\n可当那些疯疯癫癫的末日预言者说得都比他有道理时，我心里真的没底了。', '这么多年，我一直唯摄政王马首是瞻。\n\n可当那些疯疯癫癫的末日预言者说得都比他有道理时，我心里真的没底了。', 66384),
(309606, 'zhCN', '我在暗影里听到了动静。虚空来了。\n\n不光是天上，它们渗透进来了，就在我们身边。无处不在。\n\n只要你一挪开眼，影子就会动。', '我在暗影里听到了动静。虚空来了。\n\n不光是天上，它们渗透进来了，就在我们身边。无处不在。\n\n只要你一挪开眼，影子就会动。', 66384),
(309605, 'zhCN', '天要塌下来了。不是比喻，天真的塌下来了。\n\n为什么别人还有心思干别的？天都塌了啊！', '天要塌下来了。不是比喻，天真的塌下来了。\n\n为什么别人还有心思干别的？天都塌了啊！', 66384),
(309604, 'zhCN', '他们居然指望我们把身家性命都托付给什么“圣光先锋军”！\n\n凭什么信他们？那一帮子人以前可是效忠联盟的。甚至好多人现在还是联盟的走狗！', '他们居然指望我们把身家性命都托付给什么“圣光先锋军”！\n\n凭什么信他们？那一帮子人以前可是效忠联盟的。甚至好多人现在还是联盟的走狗！', 66384),
(309603, 'zhCN', '圣光指引我们跨越了那曾不可逾越的星海，瞬息之间降临此地守卫防线。\n\n勇士$p，能与你并肩作战是我的荣幸。得知你也回应了圣光的感召，更是令人振奋。', '圣光指引我们跨越了那曾不可逾越的星海，瞬息之间降临此地守卫防线。\n\n勇士$p，能与你并肩作战是我的荣幸。得知你也回应了圣光的感召，更是令人振奋。', 66384),
(309594, 'zhCN', '勇士，让你见笑了，我正抓紧时间喘口气。\n\n刚才为了护住太阳之井，我几乎耗尽了力量，才获准稍作休整。\n\n没想到这城里也没个安宁的地方。', '勇士，让你见笑了，我正抓紧时间喘口气。\n\n刚才为了护住太阳之井，我几乎耗尽了力量，才获准稍作休整。\n\n没想到这城里也没个安宁的地方。', 66384),
(309593, 'zhCN', '能调用的圣光使者太少了。虽然几乎整个白银之手骑士团都在这儿，但我们内心深处都清楚：这还远远不够。\n\n即便如此，我们仍将为这场战争燃尽最后一滴血。', '能调用的圣光使者太少了。虽然几乎整个白银之手骑士团都在这儿，但我们内心深处都清楚：这还远远不够。\n\n即便如此，我们仍将为这场战争燃尽最后一滴血。', 66384),
(309592, 'zhCN', '虚空妄图一口吞下银月城，乃至整个奎尔萨拉斯。若不加以阻止，它将永无休止地蔓延，直至万物归于死寂。\n\n这是它们楔入我们世界的桥头堡。我们必须将其拔除，不惜一切代价。', '虚空妄图一口吞下银月城，乃至整个奎尔萨拉斯。若不加以阻止，它将永无休止地蔓延，直至万物归于死寂。\n\n这是它们楔入我们世界的桥头堡。我们必须将其拔除，不惜一切代价。', 66384),
(309591, 'zhCN', '我非常同情银月城的百姓。他们遭的罪已经够多了。\n\n偏偏家园变成了圣光与虚空厮杀的最前线，这日子哪是人过的。\n\n我只能祈祷，当我们不惜代价拯救艾泽拉斯时，他们的信仰能撑住不崩塌。', '我非常同情银月城的百姓。他们遭的罪已经够多了。\n\n偏偏家园变成了圣光与虚空厮杀的最前线，这日子哪是人过的。\n\n我只能祈祷，当我们不惜代价拯救艾泽拉斯时，他们的信仰能撑住不崩塌。', 66384),
(309587, 'zhCN', '', '这对落锤镇会有帮助，$p，谢谢你。', 66384),
(309584, 'zhCN', '', '什么事，$c？', 66384),
(309557, 'zhCN', '我觉得我没法继续当血骑士了。\n\n无休止的操练，一次次被击倒，被射日者教官训斥……我觉得自己已经没有资格成为血骑士了。每天我都想退出，就像现在，我还躲在这里逃避职责。\n\n我觉得自己是个失败者。我本该成为一名伟大的战士，但现在我只想回家，陪我母亲喝几杯，借酒浇愁。更别提为了受训我背了一屁股债。\n\n我知道很多人在支持我。我的父母，朋友，甚至射日者教官都希望我成功。正因如此，当我感觉辜负了他们时，心里才更难受。\n\n我感到好迷茫。', '', 66384),
(309536, 'zhCN', '动作要快——尘粉一倒出来就开始溶解了！', '动作要快——尘粉一倒出来就开始溶解了！', 66384),
(309535, 'zhCN', '每次少量添加到小瓶中，直到达到我标记的刻度线。装满后告诉我，我来完成结界的制作。', '每次少量添加到小瓶中，直到达到我标记的刻度线。装满后告诉我，我来完成结界的制作。', 66384),
(309481, 'zhCN', '今天这片水域的脾气可不太好啊。', '', 66384),
(309479, 'zhCN', '', '噢，蒙特。这场欢迎仪式肯定出乎你的意料。', 66384),
(309478, 'zhCN', '我们的地表侦察兵带回了一种神奇生物的传闻，据说它能水陆空三栖。\n\n这种生物虽然体型小巧，却长着可怕的喙，叫声在夜空中回荡。\n\n所以，当然了，我们必须制作一个代表这种生物的玩具。', '', 66384),
(309476, 'zhCN', '我正在努力补货玩具。我原本主要卖武器，结果都被年轻人抢光了。\n\n <伊姆哈尤自豪地微笑着。>', '', 66384),
(309448, 'zhCN', '啊，别在意这肱二头肌。如果法术不听话，那……总得有点别的东西听话才行。\n\n我懂，我懂。一个靠蛮力的血精灵？相信我，我的导师们脸都要吓白了。但我打爆的练习假人比我成功施放的法术还多，既然如此，那就练肌肉吧。\n\n总有一天我的魔法水平会赶上来的。在那之前，我也只能举起那些我没法用漂浮术升起的东西了。', '', 66384),
(309432, 'zhCN', '你知道吗……我一直对祖父怀有深厚的感情。\n\n小时候，父母总是俗务缠身：无尽的职责、期望和要求。我不怪他们，但这意味我和姐姐大多时候是跟着祖父长大的。\n\n是他手把手带我踏入了奥术的大门，我至今还能听到他信誓旦旦地说，终有一天我的天赋会超越他。\n\n谈论他，就像留住他的一部分在身边。仿佛他记忆中的那束光，依然未曾消散。', '', 66384),
(309378, 'zhCN', '我能帮你什么忙吗？', '我能帮你什么忙吗？', 66384),
(309330, 'zhCN', '', '你是来协助我们研究的吗？', 66384),
(309291, 'zhCN', '', '你好。你是在寻求剥皮方面的指导吗？', 66384),
(309290, 'zhCN', '', '你好。你是在寻求草药学方面的指导吗？', 66384),
(309289, 'zhCN', '你好。你是在寻求附魔方面的指导吗？', '', 66384),
(309288, 'zhCN', '', '你好。你是在寻求裁缝方面的指导吗？', 66384),
(309287, 'zhCN', '你好。你是在寻求珠宝加工方面的指导吗？', '', 66384),
(309286, 'zhCN', '你好。你是在寻求制皮方面的指导吗？', '', 66384),
(309285, 'zhCN', '', '你好。你是在寻求工程学方面的指导吗？', 66384),
(309284, 'zhCN', '你好。你是在寻求锻造方面的指导吗？', '', 66384),
(309283, 'zhCN', '', '你好。你是在寻求铭文方面的指导吗？', 66384),
(309282, 'zhCN', '你好。你是在寻求炼金方面的指导吗？', '', 66384),
(309271, 'zhCN', '看来伊兹肯当初逃跑的原因真被大家说中了。', '看来伊兹肯当初逃跑的原因真被大家说中了。', 66384),
(309270, 'zhCN', '那毕竟是他们的母亲。这种家务事，轮不到我插嘴。', '那毕竟是他们的母亲。这种家务事，轮不到我插嘴。', 66384),
(309269, 'zhCN', '她是个多好的领袖啊。既然对我们好，对他们肯定也差不了。', '她是个多好的领袖啊。既然对我们好，对他们肯定也差不了。', 66384),
(309268, 'zhCN', '但愿夏安娜说的不是真的。趁伊兹肯还没走，我得去问个明白。', '但愿夏安娜说的不是真的。趁伊兹肯还没走，我得去问个明白。', 66384),
(309267, 'zhCN', '她待大家不薄。外头那些闲言碎语，我是一个字都不想信。', '她待大家不薄。外头那些闲言碎语，我是一个字都不想信。', 66384),
(309266, 'zhCN', '如果不是她那股子狠劲儿，许多阿曼尼人早就没命了。', '如果不是她那股子狠劲儿，许多阿曼尼人早就没命了。', 66384),
(309265, 'zhCN', '我不相信夏安娜说的那些话……可这世上还有谁比夏安娜更了解她呢？', '我不相信夏安娜说的那些话……可这世上还有谁比夏安娜更了解她呢？', 66384),
(309264, 'zhCN', '他们的母亲是位伟大的领袖。我们会怀念她的。', '他们的母亲是位伟大的领袖。我们会怀念她的。', 66384),
(309263, 'zhCN', '噢，你好呀，大个子朋友。别管加恩基。加恩基在休息！\n\n加恩基是跟斯基特一起来的——这地方生意太好了！生意好就说明蜡烛灭得快，得不停地点！\n\n那个坐椅子的灰老头说蜡烛和火把是魔法自动换的，但加恩基知道，那不是魔法。\n\n是狗头人换的！根本没有魔法！\n\n要买点吗？加恩基这儿什么蜡烛都有！', '', 66384),
(309262, 'zhCN', '我很少光顾人类的酒馆。那里的酒像水一样淡，椅子一坐就塌。而且那些人……对米莎往往不太友善。\n\n但这地方？酒够劲，椅子也意外地结实。至于米莎？\n\n<雷克萨回头看了一眼在炉火旁酣睡的巨熊。>\n\n看来她很中意这儿。行吧，那我就再喝个一两轮。能在这扇门里看见几张意想不到的老面孔，感觉还不赖。', '', 66384),
(309261, 'zhCN', '我这半辈子，走南闯北，进过的酒馆不计其数。尝过的好酒，结交的朋友，甚至是那几场混着拳头和酒杯的群架，都数不过来了。\n\n但这儿……即便我见多识广，也得承认，很少有哪家酒馆能像这儿一样独一无二。\n\n<陈在吧台椅上转过身，打量了一会儿奥术秘社的客人们，又转回去端起了酒杯。>\n\n等重波逛完四风谷，我得带他来这儿见识见识。说不定风暴烈酒酿造厂还能整出一款“奥术秘社特供”呢，你说呢？', '', 66384),
(309260, 'zhCN', '', '说实话，当初叔叔跟我吹嘘他又发现了一家“魔法酒馆”的时候，我是一百个不信。你也知道，只要酒对胃口，哪怕是美酒节那种破帐篷，在他眼里都跟施了“魔法”似的。\n\n我当时只想赶紧带哥哥和老爸去四风谷逛逛……但这回我得服气。这地方确实名副其实，充满了魔力。我们才刚落脚，居然就碰到了好几个熟人！\n\n也许等他们在酿酒厂忙活完，我能劝家里人也来这儿转转。我有预感，叔叔已经在琢磨要给这里搞点什么特供佳酿了。', 66384),
(309259, 'zhCN', '', '这地方……确实别有一番风味，对吧？\n\n离开卡兹阿加之后，我走过了不少地方，各地的风土人情都不一样。\n\n听过的故事，见证的历史，有的惊心动魄，有的却满是血泪。\n\n但这儿不一样。来自天南地北的人聚在同一个屋檐下，只为了寻一份简单和安宁。真不可思议……但我很喜欢这种感觉。\n\n<拂晓嘴角含笑，环顾四周。>\n\n我想，我该换个口味，再尝尝别的酒了。', 66384),
(309210, 'zhCN', '我在练我的“滋滋云”呢！虽然大部分时候它就只能挤出点小水花。\n\n但总有一天，我会召唤出一场大风暴，让所有人都吓一跳，也给我的家族争光。\n\n我会死命练的！', '我在练我的“滋滋云”呢！虽然大部分时候它就只能挤出点小水花。\n\n但总有一天，我会召唤出一场大风暴，让所有人都吓一跳，也给我的家族争光。\n\n我会死命练的！', 66384),
(309207, 'zhCN', '', '这么多传奇战士聚在一起居然没打起来，看来从我第一次跨过黑暗之门到现在，艾泽拉斯确实变了不少。追求和平固然高尚。也许他们中真有人觉得这和平能长久。\n\n但我心里跟明镜似的。毁掉一个王国，往往只需要致命的一刀。\n\n当战线拉开的时候，你最好清楚自己该站在哪边。反正我永远不会站错。', 66384),
(309178, 'zhCN', '你好。我在等我的爱人，拉胡法。\n\n你来这儿有何贵干？', '你好。我在等我的爱人，拉胡法。\n\n你来这儿有何贵干？', 66384),
(309164, 'zhCN', '', '我们让那个虚空行者见识了惹毛虚空精灵的下场，但它的阴谋也让我们折损了不少人手。\n\n我本是一腔热血来为正义而战的，谁承想会是这样！这里的黑暗远超我的预期。\n\n朗多雷与虚空纠缠不清，我对此并不后悔，但这虚影风暴正从里到外地撕碎我。\n\n赶紧把该办的事办了，然后回家吧。', 66384),
(309157, 'zhCN', '', '我打一开始就知道那该死的畜生没安好心。\n\n但我还是想抱有一丝幻想。结果证明，虚影风暴就是个让人绝望的深渊。\n\n不管那畜生在打什么鬼算盘，我们都奉陪到底！', 66384),
(309152, 'zhCN', '', '说实话，我从没听说过爱好和平的虚空行者。但凡有一丁点希望能顺藤摸瓜找到其他人，我们就得赌一把。\n\n虚影风暴这鬼地方让我们吃了太多苦头。你知道的，我们太需要一场胜利来提提气了。', 66384),
(309147, 'zhCN', '', '精灵的幻象指引我找到了这个虚空行者！\n\n它看着倒是没啥威胁，但别掉以轻心！暗影最擅长编织谎言，就像结网一样精细。', 66384),
(309132, 'zhCN', '我们现在明白了……过度的暴力只会导致无尽的死亡轮回。\n\n无尽……恰如这股虚空。', '', 66384),
(309128, 'zhCN', '虽然没看到什么顶级掠食者的影子，但我感觉得到，它在盯着我。它就在那儿！\n\n如果克利雅没看见，那她就是瞎了！她心里清楚，有什么东西就潜伏在地平线之外。我从她眼神里就能看出来。', '', 66384),
(309120, 'zhCN', '怪了，这些野兽的肉尝不出虚空的腐臭味。\n\n但当我咬下去的那一刻，周遭的空气仿佛都兴奋得颤栗起来。', '', 66384),
(309118, 'zhCN', '', '身为双界研究员，就是要参透朗多雷与虚空之间的羁绊。\n\n这股力量推动了我们族人的飞升……却也暗藏凶险。\n\n<她歪了歪头，眼神有些迷离。>\n\n马特瑞安和我选择搭档研究，正是因为我们性格互补。他狂热地拥抱虚空，而我保持……务实……和谨慎。\n\n我们深知这项工作可能会揭开何等疯狂的真相，依然并肩前行。\n\n这就是我们相互依存的原因。若有一天我被疯狂吞噬，我很庆幸有马特瑞安在场，他会做出必要的决断。', 66384),
(309100, 'zhCN', '我早该料到圣光之愿礼拜堂的情况会很糟，$p，毕竟他们大批的圣骑士都调去了太阳之井。\n\n泰罗索斯运气不错，正好我们赶到了，有你和阿拉托尔援手，现在一定能解围。', '', 66384),
(309088, 'zhCN', '', '议会必须听得进道理。事关重大，容不得他们袖手旁观。', 66384),
(309008, 'zhCN', '我也不是第一次跟虚空势力交手了……但从未见过如此规模的阵仗。以前我们进攻燃烧军团的据点时，虚空可没这么常见。\n\n即便在最偏远的战场，它们也只是像眼角的余光一样潜伏着。虽说洛萨克森教过我们应对之策，但眼前这支大军，完全超出了我们的认知。', '', 66384),
(309007, 'zhCN', '', '我见识过虚空大军的手段。我曾亲眼目睹它们与无穷无尽的恶魔大军厮杀。燃烧军团靠的是纯粹的毁灭蛮力，而虚空……它们像涨落的潮汐，像寄生的阴影，吞噬并渗透接触到的一切。\n\n但这回……这回的情况，即便是对虚空而言，也前所未见。', 66384),
(309005, 'zhCN', '没有圣光，何来暗影。', '没有圣光，何来暗影。', 66384),
(308999, 'zhCN', '', '我是艾丽，卡德加的朋友。我以前住在紫罗兰城堡的守护者圣殿里。\n\n我在那儿的书堆和阅读角里，度过了许多安宁静谧的岁月。\n\n可当蛛魔攻破达拉然时，我……\n\n<艾丽沉默了片刻。>\n\n城市沦陷后，我也像许多人一样，不知何去何从。外面的世界对我来说太喧嚣，太庞大了。\n\n是卡德加把我带到了这儿，这里既安全又清静。我欠他一份大人情。', 66384),
(308996, 'zhCN', '', '卡德加在多恩诺嘉尔康复后，带我来到了这个密室。\n\n这里虽不如守护者圣殿那般宏伟，但胜在清静。\n\n我不禁好奇，这地方究竟藏着怎样的秘密。', 66384),
(308995, 'zhCN', '', '随着莫尔杜恩的倒下，与萨拉塔斯的战局正朝着有利于我们的方向发展。', 66384),
(308994, 'zhCN', '我以前带着数不清的英雄游览沙塔斯。带着他们满城转悠，真是要把腿都跑断了！\n\n这差事终于结束的时候，我可算是松了口气。', '', 66384),
(308993, 'zhCN', '', '怎么？没想到在这一堆所谓的“艾泽拉斯精英”里能看见我？\n\n哼，反正还没人撵我走。不过我猜，多半是看在塞西莉亚那张甜美的笑脸上，而不是给我面子。\n\n迪菲亚兄弟会选了那条路，而我有我自己的道。他们想靠烧杀抢掠来继承我父亲的遗志？随他们去。我要实打实地帮西部荒野的农民，这才是正道。\n\n塞西莉亚想走“正规程序”。但她也不傻。我们都清楚，要是敌人玩阴的，你也得学会把手弄脏。\n\n所以我才在这儿，还跟一位女伯爵混在一起，这真是有意思。\n\n<梵妮莎嘴角掠过一丝不易察觉的笑意。>\n\n倒也不赖。真的，一点也不赖。', 66384),
(308991, 'zhCN', '', '你好，旅行者。\n\n我是塞西莉亚·克莱辛顿。我在暴风城一直致力于支持西部荒野的粮仓公会，希望能推动建立一个更公正的政府。\n\n眼下这局势，这活儿可不好干。贵族议会那帮人，借着国王不在，对自己不喜欢的提案就百般拖延；对自己有利的，嘿，这借口倒成了加速通过的理由！\n\n<塞西莉亚叹了口气。>\n\n抱歉，旅行者。我答应过梵妮莎，在奥术秘社这块净土不提那些糟心事。这儿多惬意啊！梵妮莎死活不说她是怎么摸到这儿的，不过以我对她的了解，肯定不像她吹得那么神不知鬼不觉。哼，我早晚得把实话套出来。', 66384),
(308990, 'zhCN', '奥术秘社可是个宝地，$p。有空常来坐坐！\n\n大家都得有个地儿放松放松，撒撒气嘛。', '', 66384),
(308987, 'zhCN', '现在要打那个什么“闪光卫士”了。大家都叫他们常胜将军，因为……算了，莫塔不想让$p难过。\n\n不过莫塔觉得……没准$p能赢呢？$p很壮实。队伍练得也狠。\n\n莫塔祝$p好运。没准能把那群常胜将军打趴下！\n\n还是说也能成常胜将军？不对，上次都跑出来了。\n\n但还是有机会赢闪光卫士的！', '', 66384),
(308986, 'zhCN', '队伍干嘛往外跑？跑得快反而输了。这算啥破计划。\n\n也许本来就没计划？\n\n莫塔以前也在队里，知道斗坑吓死人。\n\n是被吓跑的。队伍气坏了。\n\n所以莫塔就待在安全的地方，再也不下斗坑了。\n\n你还要去送死……啊不，去试试吗？', '', 66384),
(308985, 'zhCN', '队伍有名字了。\n\n但莫塔……搞不懂。“真菌追随屁屁”是个啥？\n\n在深坑里喊这个多费劲。还不如就叫“$p的队伍”。喊起来顺口多了。\n\n不过嘛，莫塔还是会喊的。', '', 66384),
(308984, 'zhCN', '听说队伍有名字了！好激动！\n\n名字起得好，莫塔喜欢。\n\n以后在斗坑里就能喊名字了，不用再喊“$p的队伍！$p的队伍！”了。', '', 66384),
(308983, 'zhCN', '很高兴见到你，大领主！这世道的变化真是让人始料未及。还得从我们重掌白银之手说起，当然，现在——简直难以置信——伟大的泰坦守护者提尔竟然真的归来了。\n\n能和你，还有这些见证了奇迹的伙伴们在奥术秘社喝上一杯，真是不赖。', '', 66384),
(308982, 'zhCN', '我是塔瓦德，$p。这世道的变化真是让人始料未及。\n\n谁能想到，那位伟大的泰坦守护者提尔竟然真的归来了？以前打死我都不信。\n\n能跟大伙这些亲历者在奥术秘社歇歇脚，感觉真不错。', '', 66384),
(308980, 'zhCN', '$p，回想我们刚认识那会儿，谁能料到会有今天这番际遇？先是在提尔之墓碰上科拉诺斯，接着重组提尔近卫帮他找回记忆，如今更是亲眼看着提尔行走在艾泽拉斯的大地上。要是当初你跟我说这些，我准以为你在说胡话。\n\n能和你，还有这些见证了奇迹的伙伴们在奥术秘社喝上一杯，真是不赖。', '', 66384),
(308865, 'zhCN', '我本该回家的，但是……\n\n你知道吗？算了。我觉得这儿挺好。\n\n不过还是谢谢你。我不逃了，就在这儿好好享受当下吧。', '我本该回家的，但是……\n\n你知道吗？算了。我觉得这儿挺好。\n\n不过还是谢谢你。我不逃了，就在这儿好好享受当下吧。', 66384),
(308863, 'zhCN', '我正在挑战自我，离开舒适的定居点去野外求生。\n\n但这太难了。面对必死的险境，我本来只有一根削尖的木棍和我的脑子。\n\n现在看来……我好像只剩下这根木棍了。', '', 66384),
(308862, 'zhCN', '别管我。我就是想不通这帮精灵是怎么搞的。\n\n哪怕是用魔法，能把这座城市重建得既像样又保留了古风？这工程量简直吓人。\n\n照理说，这么庞大的东西早该因为自重塌了，顺便把我们都埋进去。\n\n我敢赌五个铜板，这绝对是幻术。不全是假的，但那些你够不着、看不清的死角，绝对是障眼法。', '', 66384),
(308861, 'zhCN', '我有点后悔当个玩偶了。什么事都做不了！\n\n哎呀，我是想说……加入我们吧！\n\n对！', '我有点后悔当个玩偶了。什么事都做不了！\n\n哎呀，我是想说……加入我们吧！\n\n对！', 66384),
(308859, 'zhCN', '我想你是想再被修好一次，是吧？', '', 66384),
(308857, 'zhCN', '欢迎参加派对！', '', 66384),
(308851, 'zhCN', '带其他人来。传播我的——呃——我们社区的福音！', '', 66384),
(308849, 'zhCN', '加入我们吧！', '加入我们吧！', 66384),
(308845, 'zhCN', '那颗扣子正合适。忍着点，我这就用针把你缝好。\n\n你很幸运，这根针非常锋利。\n\n准备好了吗？', '', 66384),
(308843, 'zhCN', '恐怕我们这里的大部分物资都是给龙鹰准备的，$c。如果你需要什么，我姐姐萨拉在附近有家店。', '恐怕我们这里的大部分物资都是给龙鹰准备的，$c。如果你需要什么，我姐姐萨拉在附近有家店。', 66384),
(308838, 'zhCN', '<阿玛拉克兜帽下露出一丝不易察觉的微笑。>\n\n你是个见多识广的人，奥威娜的朋友。那么告诉我：信仰的恩赐会随着距离而消逝吗？\n\n是的，舒尔卡的道路是孤独的。但别误以为我们没有信仰。我对艾林哈籁的信仰比以往任何时候都更坚定。因为我知道她在呼唤我，即使我听不见。', '', 66384),
(308836, 'zhCN', '听不到。我们的入会仪式会在灵魂上留下伤疤。它改变了我们。它让我们对女神歌声的回响充耳不闻。\n\n这是一种孤独的存在。但这让我们能涉足族人无法涉足的地方。在寂静中，我们被屏蔽在裂隙那令人发狂的哭喊之外。', '', 66384),
(308833, 'zhCN', '舒尔卡是猎手、医者和向导。我们与灵魂和暗影打交道，以便勇闯艾林裂隙的危险并活着回来。我们还要确保那些危险不敢游荡出它们被诅咒的领地。\n\n这项技艺对我们来说并非易事。女神歌声的回响召唤我们走向野性的凶猛和丰饶的生长。但我们再也听不到那个召唤了——所以我们与其他的虚空声音交流。那些依然能传到我们耳中的声音。', '', 66384),
(308823, 'zhCN', '艾林之尘稀有且采集危险。它能以最纯粹的状态强化我们与艾林哈籁恩赐的联系，让我们能为后世记录历史，并保护我们免受外部世界腐化影响的侵蚀。\n\n哈籁尼尔长老负责控制和管理我们现有的艾林之尘的使用。即使对我们来说，它也只能在神圣仪式或极度危险的时刻使用。\n\n对于长老们拒绝奥威娜的请求，我并不感到惊讶。对他们来说，根须之外的世界根本就不存在。他们为什么要为了永远不会涉足的土地而消耗珍贵的资源呢？', '', 66384),
(308821, 'zhCN', '', '酒保问我要不要来点烈酒——我都已经是个死人了，还能烈到哪儿去？\n\n<她慢慢啜了一口，目光扫视着房间。>\n\n这地方很吵，闻起来像烧焦的麦芽酒……奇怪的是，这让我感觉像家一样。更奇怪的是，我可以坐在部落和联盟旁边，感受到某种近乎平静的东西。这里的欢快氛围很不寻常，但也令人欣慰。\n\n如果我们有什么共同点，那就是大家都把片刻的喘息视为珍宝。我们紧抓着它，生怕它消失，因为它通常确实会消失。\n\n如果你的酒尝起来像毒药，别看我。我正试着享受我的休息日。', 66384),
(308786, 'zhCN', '哈谢之路漫长而艰险，充满了试炼和危难。\n\n“哈舒拉”就是哈谢的侍从。他们追随哈谢的道路，为其而战，也为其而死。\n\n通常来说，呃，有两位侍从。但是，你看，我是个老头子了，我们的士兵又都受了伤，祖尔加也绝不会同意……\n\n我猜，莉亚德琳就只能当第二位了。\n\n<金杜鲁不确定地笑了笑。>\n\n一个辛多雷，还有一个卡多雷，竟然同时被授予哈舒拉的殊荣……这事儿我想想都觉得头晕。但我哪敢质疑洛阿的旨意呢？', '', 66384),
(308783, 'zhCN', '哈谢之路漫长而艰险，充满了试炼和危难。\n\n“哈舒拉”就是哈谢的侍从。他们追随哈谢的道路，为其而战，也为其而死。\n\n通常来说，呃，有两位侍从。但是，你看，我是个老头子了，我们的士兵又都受了伤，祖尔加也绝不会同意……\n\n我猜，莉亚德琳就只能当第二位了。\n\n<金杜鲁不确定地笑了笑。>\n\n一个被授予“哈舒拉”荣耀的精灵。但至少这第二位是你，$n——即便你不是祖阿曼的孩子，也是远亲，是我们流落在外的族亲！', '', 66384),
(308778, 'zhCN', '你是来查光木武器为什么迟迟不到货的吗？那你可来对地方了。\n\n暮光之刃发现了我们的营地，他们知道我们在给阿曼尼提供强力的光木武器，于是就不停地袭击我们，打断我们的工作。\n\n现在又冒出这么个小子冲进我们的营地，嚷嚷着他妹妹的事。我连应付暮光之刃的时间都没有，更没空照看什么精灵农夫家迷路的愤怒小鬼了！\n\n他年轻气盛，以为自己什么都懂。呵，我这把年纪也不是白活的……\n\n也许你能帮我把这两个麻烦都解决了。', '', 66384),
(308777, 'zhCN', '', '斯基特头上的蜡烛灭了，米里特帮帮他。斯基特找到了所有这些蜡烛！\n\n这儿有好多。要是借走一根，应该也没事吧？', 66384),
(308776, 'zhCN', '我不觉得我们见过面，是吧？我是米里特，这是斯基特。我喜欢结交新朋友，就像发现新宝藏一样。\n\n你想和我们坐一起吗？我们在休息，等着有人发现我们溜进来了。这儿真气派！', '', 66384),
(308775, 'zhCN', '这是我发现过的最豪华的洞穴！最棒的是我的好朋友们都在！有$n、斯基特，还有个豪华座位。\n\n瞧，那些软乎乎的垫子是第二棒的部分。你想和我们坐一起吗？我想念和你一起寻嗅探险的日子了。\n\n随时欢迎你来和我们挤一挤！', '', 66384),
(308774, 'zhCN', '没有小酒馆的消遣，那还叫什么冒险生活？或者说，大量的消遣。\n\n持续的危险让你的人生在眼前不断闪回。而我眼前闪回的，是我在未来日子里品尝这种佳酿的画面。我还有什么可抱怨的呢？', '', 66384),
(308624, 'zhCN', '', '而是用新的胜利重写历史的契机。', 66384),
(308623, 'zhCN', '', '我很感激你，哈舒拉。感谢你提醒那沧桑的家伙，这场战斗不是为了羞辱他过往的失败。', 66384),
(308620, 'zhCN', '少在那儿代表我，老蝙蝠！我会让你见识到，一旦狂暴者杀入战场，年龄根本不算什么！', '', 66384),
(308613, 'zhCN', '他们只是阿塔阿曼的记忆残响，既不知痛楚，也无惧死亡。', '', 66384),
(308612, 'zhCN', '', '他们都算不上你真正的同伴。', 66384),
(308600, 'zhCN', '', '虚空让我作呕。它带给我的痛苦已经够多了！那些暮光之刃的密教徒曾利用它毁了我最珍视的一切：我的村庄，还有我的母亲。\n\n如今看到虚空出现在我们的捕蟹场附近，给难民制造麻烦……那可怕的记忆便一遍又一遍地在我脑海中重演。\n\n让我们彻底查清这件事。越快越好。', 66384),
(308593, 'zhCN', '', '你要知道，暗松部族的生存智慧是无与伦比的。如果有必要，我们能在这里生存数年，死守神殿。', 66384),
(308592, 'zhCN', '唯一的问题是他们的肚子！但这批补给应该足够让我们所有人吃饱，再支撑一阵子！', '', 66384),
(308588, 'zhCN', '但为了确保我们最稚嫩的雏鹰能安全离巢，每一道伤口都是值得的。', '', 66384),
(308587, 'zhCN', '', '转告她，屏障坚不可摧。我们现在唯一的敌人就是耐心，因为我们得在这个笼子里继续等待。', 66384),
(308586, 'zhCN', '为了感谢你们的庇护，我们很乐意与你的住宅区分享我们的艺术心得，也想见识一下你的审美品位。\n\n你愿意装饰你的住宅吗？我们很想看看你是如何布置的，如果你带来了新的装饰，我们也会为此欢呼！\n\n还有一些人在银月城的袭击中受了伤，如果你能协助治疗他们，那就太好了。\n\n另外，我想科伦正在寻求帮助，为他的画作寻找灵感。尽管他性情古怪，但他确实是个杰出的画家。', '为了感谢你们的庇护，我们很乐意与你的住宅区分享我们的艺术心得，也想见识一下你的审美品位。\n\n你愿意装饰你的住宅吗？我们很想看看你是如何布置的，如果你带来了新的装饰，我们也会为此欢呼！\n\n还有一些艺术家在银月城的袭击中受了伤，如果你能协助治疗他们，那就太好了。\n\n另外，我想科伦正在寻求帮助，为他的画作寻找灵感。尽管他性情古怪，但他确实是个杰出的画家。', 66384),
(308585, 'zhCN', '', '别再比划了，你这笨蛋！你一直乱动，我没法给你治疗！', 66384),
(308584, 'zhCN', '永歌森林正遭受虚空与圣光的双重夹击。\n\n我们既要控制住局势，又要确保我们的生活方式得以延续，这就需要援手。\n\n我知道萨瑟利尔正在为宴会招募帮手，此外清除光绽的工作也需要人手。\n\n受难的不止我们。虽然难以启齿，但连阿曼尼巨魔都需要帮助……我还听说有个新种族也急需支援。\n\n我们也已主动向虚空发起反击，那边同样需要你的协助。\n\n事情……实在太多。若是你能伸出援手，我们将不胜感激。', '永歌森林正遭受虚空与圣光的双重夹击。\n\n我们既要控制住局势，又要确保我们的生活方式得以延续，这就需要援手。\n\n我知道萨瑟利尔正在为宴会招募帮手，此外清除光绽的工作也需要人手。\n\n受难的不止我们。虽然难以启齿，但连阿曼尼巨魔都需要帮助……我还听说有个新种族也急需支援。\n\n我们也已主动向虚空发起反击，那边同样需要你的协助。\n\n事情……实在太多。若是你能伸出援手，我们将不胜感激。', 66384),
(308582, 'zhCN', '', '局势如履薄冰。\n\n虽然这些过往的回响单打独斗很容易解决，但没过多久它们就会复活，卷土重来。', 66384),
(308576, 'zhCN', '感谢你庇护了我们的艺术家社区，还允许我们协助装点你的住宅区。\n\n你这片住宅区真是太棒了。简直是艺术家的天堂。', '感谢你庇护了我们的艺术家社区，还允许我们协助装点你的住宅区。\n\n你这片住宅区真是太棒了。简直是艺术家的天堂。', 66384),
(308575, 'zhCN', '感谢你庇护了我们的艺术家社区，还允许我们协助装点你的住宅区。看来你在这里才刚起步。\n\n不如等你见识了更多艾泽拉斯的风光后再回来？我们可不想让你分心，耽误了你的旅途。', '感谢你庇护了我们的艺术家社区，还允许我们协助装点你的住宅区。看来你在这里才刚起步。\n\n不如等你见识了更多艾泽拉斯的风光后再回来？我们可不想让你分心，耽误了你的旅途。', 66384),
(308573, 'zhCN', '', '你发牢骚的样子就像只老穿山甲。在那儿坐会儿，让骨头歇口气，然后再回屏障那儿去拼命。', 66384),
(308572, 'zhCN', '不管我们要砍翻多少个，敌军还是像潮水一样往城里涌。', '', 66384),
(308569, 'zhCN', '我年轻的时候，巴不得敌人杀个没完没了，好让我杀个痛快。\n\n可如今……这把老骨头已经是跟不上喽。', '', 66384),
(308568, 'zhCN', '', '你在阿塔阿曼或许能见到些熟面孔……但我敢说，他们可不像以前那么好客了。', 66384),
(308566, 'zhCN', '', '前阵子有个枯木部族的小丫头来过。可惜啊，我这儿不收水果和蘑菇……', 66384),
(308565, 'zhCN', '', '啊，这可是我的海象人古董茶壶。你不是第一个打听它的人了……', 66384),
(308564, 'zhCN', '', '远渡重洋的稀罕货！快来“海”淘一下，看看有没有中意的！', 66384),
(308511, 'zhCN', '这不是普通的蛋。\n\n贝洛朗在最初的虚空猛攻中陨落。萨拉塔斯的爪牙很清楚我们的软肋在哪，又该如何下手。\n\n那只伟大的凤凰被迫涅槃，重归卵壳。我们本以为它们早已破壳而出，但随着它们在壳中疗伤，太阳之井那汹涌的圣光一直在……改变着它。\n\n在它们重翔天际之前，我们将死守此地。', '这不是普通的蛋。\n\n贝洛朗在最初的虚空猛攻中陨落。萨拉塔斯的爪牙很清楚我们的软肋在哪，又该如何下手。\n\n那只伟大的凤凰被迫涅槃，重归卵壳。我们本以为它们早已破壳而出，但随着它们在壳中疗伤，太阳之井那汹涌的圣光一直在……改变着它。\n\n在它们重翔天际之前，我们将死守此地。', 66384),
(308509, 'zhCN', '退后，$c。\n\n你面前的是奥的最后一窝蛋。我们的职责是誓死保护它，哪怕牺牲自己。', '退后，$c。\n\n你面前的是奥的最后一窝蛋。我们的职责是誓死保护它，哪怕牺牲自己。', 66384),
(308503, 'zhCN', '<鲁伊亚嘲讽地哼了一声。>\n\n难道天一下雨，你们的族人就要哀叹苍穹崩塌吗？\n\n根须有时多，有时少。有时它们的形状或性情会改变。但它们总是伸向摇篮。只要哈籁恩达尔的根须保持完整，我们为什么要关心上面的世界发生了什么？\n\n你还有其他蠢问题吗？还是说你只是想拖延对你的审判？', '', 66384),
(308501, 'zhCN', '你面前的是鲁伊亚，莎拉达希尔的护根者。八十五年来，我一直守望着它受诅咒的根须，就像我的导师在回归大地之前所做的那样。', '', 66384),
(308500, 'zhCN', '', '阿扎伊本该杀了那个血精灵。\n\n<她上下打量着你，似乎不以为然。>\n\n这里不欢迎外人。尤其是那些来惹是生非的。\n\n你最好小心点。', 66384),
(308496, 'zhCN', '<当你靠近时，鲁伊亚露出了獠牙，显然很是厌恶。>\n\n你竟敢直视护根者的双眼？我应该把你的骨头扔给恐惧山猫。', '', 66384),
(308495, 'zhCN', '别提她，巨魔。\n\n莱尼娅死了。\n\n<他被绑着的双手攥成拳头。>\n\n他们就像夜色中的幽魂……\n\n是阿曼尼干的，我敢肯定。我知道。\n\n既然那是无差别的袭击，我又何必挑挑拣拣？随便哪个阿曼尼都行。\n\n为什么不能是他们？', '', 66384),
(308494, 'zhCN', '<他眯起眼睛打量着你。>\n\n你不是跟他们一伙的，对吧？\n\n……趁还来得及，帮我逃出这里。', '', 66384),
(308436, 'zhCN', '想变得像我们一样，你需要一些行头。\n\n首先是一枚扣子！', '', 66384),
(308435, 'zhCN', '你不是我们的一员。\n\n\n我们的一员。', '你不是我们的一员。\n\n\n我们的一员。', 66384),
(308429, 'zhCN', '这里很美吧？我非常喜欢。\n\n如果你腿上趴着一只睡着的水豚，那就绝对不能动。\n\n……这是我刚编的规矩。但这依然是个好规矩。', '这里很美吧？我非常喜欢。\n\n如果你腿上趴着一只睡着的水豚，那就绝对不能动。\n\n……这是我刚编的规矩。但这依然是个好规矩。', 66384),
(308413, 'zhCN', '若你抓得太紧，圣光便会溜走。你必须放松，让它流经你的身体。', '若你抓得太紧，圣光便会溜走。你必须放松，让它流经你的身体。', 66384),
(308412, 'zhCN', '唯有在宁静时刻，我们才能感受到圣光的温暖与奇迹。', '唯有在宁静时刻，我们才能感受到圣光的温暖与奇迹。', 66384),
(308411, 'zhCN', '奥伊，生长之神。在我们的众神中，这一位最为神秘。\n\n去那座被唤作“大树桩”的悬崖上找找那些参天巨木吧。向克拉格平发起挑战，奥伊自会裁定你是否够格。', '', 66384),
(308404, 'zhCN', '波尔，危机之神。在勇者面前，她显现为最凶猛的海兽：鲨鱼。\n\n只有那些敢在祖阿曼的惊涛骇浪中垂钓的勇士，才能得到她的青睐。', '', 66384),
(308399, 'zhCN', '钝顿，化身硕鼠的丰饶之神……即便在众神里头，他也算是个个性十足的家伙。\n\n去枯木村西边的神愈兽穴找找吧，他八成就在那儿。', '', 66384),
(308398, 'zhCN', '啊……沙德拉，诡诈之神。\n\n如今大家都不提倡供奉她了。如果你真想打听，就去找恶齿部族的佩尔娜·断齿吧。\n\n听说她最近正在枯木山崖那边调查，好像是有人在那儿偷偷信奉沙德拉。', '', 66384),
(308397, 'zhCN', '圣光并不要求你免受痛苦，只要求你让痛苦穿身而过。', '圣光并不要求你免受痛苦，只要求你让痛苦穿身而过。', 66384),
(308396, 'zhCN', '静止，亦是一种虔诚。', '静止，亦是一种虔诚。', 66384),
(308395, 'zhCN', '让圣光分担你的重担。', '让圣光分担你的重担。', 66384),
(308394, 'zhCN', '将你的悲伤卸于中央。圣光自会承载。', '将你的悲伤卸于中央。圣光自会承载。', 66384),
(308393, 'zhCN', '有时，静默才是通往圣光的至真之路。', '有时，静默才是通往圣光的至真之路。', 66384),
(308392, 'zhCN', '维拉玛，旅者之神，活在许多森林部族的心中。\n\n等你证明了自己是我们族人的盟友，这位伟大的猛犸神灵会亲自在你面前现身。', '', 66384),
(308391, 'zhCN', '化身为可怖甲脊蜥的是莫塔姆拉，疫疾之神。\n\n我听到些风声，说暮光教派的那帮家伙亵渎了我们的神灵。去残破神庙底下的墓穴里瞧瞧吧，亲眼看看那边到底发生了什么。', '', 66384),
(308389, 'zhCN', '啊，费洛，幼嗣之神。他化身为一只年迈的水豚。\n\n也许在枯木山崖，还有一两个孩子仍遵循旧俗，供奉着这位神灵。', '', 66384),
(308386, 'zhCN', '', '你多半会在阿梅达希尔的根须旁找到奥恩尚，他正对着自己的过错独自发呆。', 66384),
(308385, 'zhCN', '库尔吉，医药之神，通常以高贵的穿山甲之姿现身。\n\n它的神殿就坐落在阿塔阿曼东面的山丘上，只可惜今非昔比，已经有些破败了。', '', 66384),
(308338, 'zhCN', '我对某些洛阿神灵知之甚深……其他的就知之甚少了。\n\n但我可以给你指个大概的方位。\n\n你想找哪一位？', '', 66384),
(308335, 'zhCN', '祝福祭坛是供奉祖阿曼所有洛阿神灵的圣地。\n\n虽有专门供奉特定神灵的神殿和庙宇，但朝圣之路往往充满艰险——尤其是前往那些信徒寥寥的神灵驻地。\n\n有些神灵会对同时崇拜多个神灵感到不快，但你是独一无二的，哈舒拉。\n\n神灵看到了你的伟大，允许你同时崇拜他们中的许多位。并同样赐福于你。', '', 66384),
(308331, 'zhCN', '哈舒拉大驾光临，令我蓬荜生辉。\n\n有什么能帮你的吗？', '', 66384),
(308316, 'zhCN', '', '我会尽力的。', 66384),
(308314, 'zhCN', '<符文再次在你眼前变幻，变得清晰可辨。>\n\n我的武器既出……战争便终结了。\n\n……一切都结束了……城市被夷为平地……再无战争……再无……\n\n只有……最微末的生命幸存……历经亿万年演化……如今已成怪物、野兽……\n\n……在最后的浪潮中……终结降临前……我的……背叛了我……\n\n……将我囚禁……\n\n惩罚……只因我给予了他们所求之物……', '<符文再次在你眼前变幻，变得清晰可辨。>\n\n我的武器既出……战争便终结了。\n\n……一切都结束了……城市被夷为平地……再无战争……再无……\n\n只有……最微末的生命幸存……历经亿万年演化……如今已成怪物、野兽……\n\n……在最后的浪潮中……终结降临前……我的……背叛了我……\n\n……将我囚禁……\n\n惩罚……只因我给予了他们所求之物……', 66384),
(308313, 'zhCN', '', '天哪，你的时间线是我见过最乱的。', 66384),
(308312, 'zhCN', '<符文在你眼前再次变幻，直到你能辨识出只言片语。>\n\n……帝国……先发制人……\n\n……城市……陷落……又一座。直至虚无……\n\n……\n\n……他们需要我。他们请求我……伟大的阿金图安德……\n\n……制造武器……拯救苍生……', '<符文在你眼前再次变幻，直到你能辨识出只言片语。>\n\n……帝国……先发制人……\n\n……城市……陷落……又一座。直至虚无……\n\n……\n\n……他们需要我。他们请求我……伟大的阿金图安德……\n\n……制造武器……拯救苍生……', 66384),
(308190, 'zhCN', '嘿，你真赶来了！莫塔还盼着你来呢。\n\n已经在斗坑看过你战斗了。上次打得不错。\n\n但憎怨斗坑是危险的地方！尽量别送命，$p！\n\n所以莫塔要待在莫塔安全的地方。', '', 66384),
(308181, 'zhCN', '', '先锋军的部队正在集结，准备突袭虚影尖塔。你是来加入他们的吗？\n\n请注意，一旦突袭开始，就无法回头了。', 66384),
(308176, 'zhCN', '是的。我的人民。进入漩涡，你将知晓一切。', '', 66384),
(308162, 'zhCN', '<陌生的符文闪烁着虚空魔力，随即发生变幻。突然间，那些残缺不全的文字变得清晰可读。>\n\n我们伟大的人民……\n\n……我们筑起的城市……无法言喻的宏伟……在天际闪耀……\n\n普雷德西亚……闪耀着知识……与学术的光辉……\n\n……我们最伟大的武器……为了未来的战争。', '', 66384),
(308154, 'zhCN', '现在，兹尔丹和我将回归我们的游戏。感谢你的付出，希望能在战场上见到你，$c。', '', 66384),
(308153, 'zhCN', '煞戎努斯死在自己的竞技场里，真是恰如其分。在从你们的世界抓捕了这么多凡人之后，他理应承受你的怒火。', '', 66384),
(308152, 'zhCN', '', '你的英勇令人钦佩。希望能再在战场上见到你。', 66384),
(308151, 'zhCN', '', '你做得很好，凡人。煞戎努斯将不再威胁屠戮者高地，也不会再从你们的世界抓捕凡人去他的竞技场厮杀。', 66384),
(308132, 'zhCN', '', '消灭维迪奥斯的部队。如果你不想和联盟发生争执，就专注于虚空奴仆。', 66384),
(308130, 'zhCN', '让兹尔丹见识一下联盟的愤怒，$c。如果你不想弄脏手沾上部落的血，那里还有大把的虚空奴仆等着你收拾。', '', 66384),
(308129, 'zhCN', '', '迫不得已时会。如果我不这么做，我就不会站在这里了。她把这点说得很清楚。\n\n尽管如此，维迪奥斯和我控制着屠戮者高地。只要我们的冲突继续制造争斗和痛苦……为她的虚影风暴提供更多的虚空能量，她就乐意放任我们。这种安排对我们来说再合适不过了。\n\n没有多曼纳尔乐意侍奉他人。我们不妨碍她。\n\n目前是这样。', 66384),
(308127, 'zhCN', '', '我们多曼纳尔热爱精彩的战斗。无论是亲自下场还是作壁上观。我们经常潜入世界之间的缝隙，从其他世界挑选战士在我们的竞技场中战斗。\n\n艾泽拉斯曾是“禁区”。在萨拉塔斯入侵后就不再是了。\n\n维迪奥斯找到了联盟。我找到了部落。我被你们对荣耀的渴望所吸引。我找到了最值得的人，那些不愿放下仇恨的人。那些不接受和平会议和条约的人。\n\n我带他们来这里是为了实现他们最大的愿望：屠杀联盟。他们为此感谢我。我只是品尝他们仇恨的滋味。', 66384),
(308125, 'zhCN', '<维迪奥斯歪了歪头。>\n\n严格来说是的。所有多曼纳尔都被迫向萨拉塔斯俯首称臣。这违背了多曼纳尔的天性，但另一种选择是彻底毁灭。那有什么乐趣？\n\n尽管如此，萨拉塔斯知道她的哪些工具最有用。兹尔丹和我……让我们自己变得对她相当没用。还有其他更强大或更顺从的多曼纳尔，她可以更好地操纵。\n\n所以兹尔丹和我继续我们的战争，没有受到萨拉塔斯太多的干涉。我们只是……不在她的视野之内。\n\n目前是这样。', '', 66384),
(308124, 'zhCN', '甚至不值得我去吞噬……', '', 66384),
(308122, 'zhCN', '噢，仅仅是通过我们多曼纳尔让人畏惧的力量。我们可以潜入世界之间的缝隙，随心所欲地挑选角斗士。自愿者是最罕见的，也是最有趣的……\n\n艾泽拉斯本来已经“禁入”很长一段时间了。当萨拉塔斯推翻我们时，情况变了。\n\n兹尔丹和我立刻对部落和联盟产生了兴趣。我搜寻我能找到的最嗜血、最愤怒的联盟成员。那些愿意放弃从虚空手中拯救艾泽拉斯的使命，只为了有机会屠杀部落的人。\n\n能找到这么多，我深感欣喜。\n\n所以，他们是自愿来这里的。他们自愿以我的名义战斗。而我很享受这一点。', '', 66384),
(308120, 'zhCN', '如果你无意与部落争锋，那就考虑协助我，我仅仅是为了阻止兹尔丹将她的征服扩张到艾泽拉斯。', '', 66384),
(308110, 'zhCN', '你也听到那个声音了吗，$p？', '', 66384),
(308098, 'zhCN', '', '维迪奥斯是个狡诈的对手。他精通十八般兵器。每一场与他的对决，都千变万化，绝无雷同。\n\n我们最近的对抗已经演变成了大规模战役。少了几分决斗，多了几分战争。我虽更偏爱决斗，但这能保持维迪奥斯的头脑敏锐。历经亿万年岁月，我们偶尔也得换换花样。\n\n部落和联盟的到来只会让我们的游戏更加妙趣横生。', 66384),
(308059, 'zhCN', '看来我们达成了一致。竞技场见，$c。', '', 66384),
(308058, 'zhCN', '', '之后，我们要继续那无休止的战争，维迪奥斯——我们会焕发出新的活力。', 66384),
(308057, 'zhCN', '听起来确实是场赏心悦目的奇观。你会死在自己的竞技场里，煞戎努斯。', '', 66384),
(308054, 'zhCN', '确实——你把我的竞技场砸得稀巴烂！不过这很令人愉快！我没想到凡人有这般身手。我有个提议。', '', 66384),
(308053, 'zhCN', '', '煞戎努斯！我就知道。你总是热衷于影接环。我们已经终结了你的接体者。', 66384),
(308052, 'zhCN', '啊，你终于来了！原谅我的缺席，不像某些人，我是萨拉塔斯随叫随到的。', '', 66384),
(308047, 'zhCN', '这个年份不错。', '这个年份不错。', 66384),
(308045, 'zhCN', '这是我们较新的品种之一。只有大约一千两百年。', '这是我们较新的品种之一。只有大约一千两百年。', 66384),
(308044, 'zhCN', '噢，奶酪！是陈年的吗？', '噢，奶酪！是陈年的吗？', 66384),
(308034, 'zhCN', '我们从未有过这样的机会来研究虚空。', '', 66384),
(308031, 'zhCN', '', '若它指引你背离族群，就不该追随。', 66384),
(308030, 'zhCN', '', '难道我不该追随它的指引吗？', 66384),
(308029, 'zhCN', '', '我听得到她的声音！', 66384),
(308028, 'zhCN', '你的狂妄危及了我们在此建立的一切！', '', 66384),
(308027, 'zhCN', '但这指引也带来了傲慢。还有鲁莽。', '', 66384),
(308026, 'zhCN', '显而易见，孩子，艾林哈籁的指引确实降临于你。', '', 66384),
(308025, 'zhCN', '', '女神？', 66384),
(308024, 'zhCN', '', '（倒吸气）', 66384),
(308023, 'zhCN', '', '难道你们就只会在这些洞穴里苟且偷生，哀叹那枯萎的往昔吗？', 66384),
(308022, 'zhCN', '', '难道这不是我们一族的使命了吗？', 66384),
(308021, 'zhCN', '', '他们是在为拯救她而战！', 66384),
(308020, 'zhCN', '', '他们和我们一样，能听到女神的歌声！', 66384),
(308019, 'zhCN', '', '——任由他们的存在亵渎这片圣地。', 66384),
(308018, 'zhCN', '', '竟将那些外来者引至此处——', 66384),
(308017, 'zhCN', '孩子，你究竟还要违背多少神圣的传统？', '', 66384),
(308016, 'zhCN', '', '你早就把那东西丢得一干二净了，奥威娜。', 66384),
(308015, 'zhCN', '', '敬意？', 66384),
(308014, 'zhCN', '', '但如果你执意要动武……', 66384),
(308013, 'zhCN', '', '是出于敬意。', 66384),
(308012, 'zhCN', '', '我来这里是为了谈话。', 66384),
(308011, 'zhCN', '', '现身吧。', 66384),
(308010, 'zhCN', '', '够了。', 66384),
(307978, 'zhCN', '……永远无法挽回。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(307977, 'zhCN', '我的儿子，有些事情……', '', 66384),
(307976, 'zhCN', '（叹气）', '', 66384),
(307975, 'zhCN', '不要放弃希望，父亲。', '', 66384),
(307974, 'zhCN', '但并不是全部。', '', 66384),
(307973, 'zhCN', '我的那一部分已经随洛萨而去了。', '', 66384),
(307972, 'zhCN', '（叹气）我不能。', '', 66384),
(307971, 'zhCN', '我……', '', 66384),
(307970, 'zhCN', '做回那个你注定要成为的圣骑士。', '', 66384),
(307969, 'zhCN', '再次拿起它吧。', '', 66384),
(307968, 'zhCN', '怎么会？你是怎么——', '', 66384),
(307967, 'zhCN', '我……我的盾牌。', '', 66384),
(307966, 'zhCN', '是时候放下了。', '', 66384),
(307965, 'zhCN', '——你背负了这么多年……', '', 66384),
(307964, 'zhCN', '——那股怒火——', '', 66384),
(307963, 'zhCN', '那份内疚——', '', 66384),
(307962, 'zhCN', '我知道洛萨陨落那天发生了什么。', '', 66384),
(307961, 'zhCN', '现在应该是你原谅你自己了。', '', 66384),
(307960, 'zhCN', '我想……', '', 66384),
(307959, 'zhCN', '你能原谅我吗？', '', 66384),
(307958, 'zhCN', '你失控了。', '', 66384),
(307957, 'zhCN', '但在那一刻，', '', 66384),
(307956, 'zhCN', '我知道你绝不会有意伤害我。', '', 66384),
(307955, 'zhCN', '父亲。', '', 66384),
(307954, 'zhCN', '我们能——', '', 66384),
(307953, 'zhCN', '我本希望……', '', 66384),
(307952, 'zhCN', '阿拉托尔，我……', '', 66384),
(307951, 'zhCN', '我的儿子……', '', 66384),
(307933, 'zhCN', '<小巧的巨魔脚印通向地上一把摔碎的陶制茶壶。\n\n看起来拿茶壶的人绊倒了，把它摔了。\n\n壶盖裂成了两半，把手不见了，裂缝的样子表明它显然装不了水了。\n\n携带者选择把它留在这里，水豚正好奇地研究着它。>', '<小巧的巨魔脚印通向地上一把摔碎的陶制茶壶。\n\n看起来拿茶壶的人绊倒了，把它摔了。\n\n壶盖裂成了两半，把手不见了，裂缝的样子表明它显然装不了水了。\n\n携带者选择把它留在这里，水豚正好奇地研究着它。>', 66384),
(307916, 'zhCN', '', '嗯……是的，一定是那样。一个闯入者。', 66384),
(307906, 'zhCN', '', '说实话，我自己也不确定。达拉然坠入海中后，银色盟约试图打捞我们能找到的东西。在一次外出中，我们发现了这些幼龙和幸存者！显然，当达拉然被摧毁时，幼龙去救了他们。从那以后我们一直在照顾它们。\n\n有个传言说，达拉然的一位艺术家以某种方式创造了这些幼龙。据说她梦到了这些龙，画了很多画，但一幅也没卖。当被问及原因时，她说她是为达拉然画的——当达拉然的人民需要它们时，这些画就会活过来，龙会来帮忙。\n\n很疯狂的故事对吧？不过我们一直没法证实。', 66384),
(307904, 'zhCN', '', '噢，别管我，勇士$n。\n\n铲屎只是照顾神话野兽的乐趣之一。', 66384),
(307903, 'zhCN', '兹尔丹是我无数个时代的宿敌。我们在屠戮者高地为了统治权争斗，那是一场光荣的、无法抗拒的血腥浪潮。\n\n很多次我们都差点毁了对方。大片土地在我们之间几经易手。\n\n多么令人愉快的游戏。我不希望它变成别的样子。', '', 66384),
(307902, 'zhCN', '<一串水果、小水豚和巨魔的脚印从死青蛙处通向地上一个空篮子。\n\n篮子上有一个大洞，可能是在与角蛙搏斗时弄坏的。\n\n水豚似乎很喜欢水果，并且把篮子的损坏当成了一个快乐的意外。>', '<一串水果、小水豚和巨魔的脚印从死青蛙处通向地上一个空篮子。\n\n篮子上有一个大洞，可能是在与角蛙搏斗时弄坏的。\n\n水豚似乎很喜欢水果，并且把篮子的损坏当成了一个快乐的意外。>', 66384),
(307901, 'zhCN', '即使我的物品被烧毁了，我耳边还是不断听到那个声音。\n\n但现在，世界安静了，我又可以独立思考了！', '', 66384),
(307897, 'zhCN', '看到纳洛拉克我还心有余悸。太不可思议了，看着他治愈了弗戈！\n\n他向我展示了该用哪个法术。\n\n我知道该怎么帮助其他人了。有弗戈帮我，我们会一起解决这个问题的。', '', 66384),
(307892, 'zhCN', '不，不，不，弗戈！\n\n我们要怎么救弗戈？', '', 66384),
(307858, 'zhCN', '', '除此之外，还有什么值得一做吗？\n\n小$rs，你的领袖看不出我们多曼纳尔一族所拥有的战斗价值，这真可悲。在这里，目的只有一个。我们为战而生。\n\n只有勇者、强者和疯子，才懂得在此执剑的勇气。只有他们，才能品味酣畅淋漓的战斗带来的愉悦。\n\n在这片战场上，你不是为部落而战。你是为我而战。你的战斗与死亡皆是为了取悦我，我们将一同在对抗维迪奥斯的冲突中尽情狂欢。\n\n好好表现，我会赐予你无上的荣耀。', 66384),
(307854, 'zhCN', '这里离卡雷什十万八千里。我从未想过卷入这么多冲突。\n\n平静生活的念头似乎是地平线上遥不可及的幻影。', '这里离卡雷什十万八千里。我从未想过卷入这么多冲突。\n\n平静生活的念头似乎是地平线上遥不可及的幻影。', 66384),
(307853, 'zhCN', '我不知道我能不能应付这样的生活。我需要依靠其他人……\n\n<随着虚空在绷带下涌动，虚灵退缩了一下>。\n\n也许这些精灵中的一个能帮我弄清楚如何忍受这些震颤。', '痛楚难以忍受……就像我的本质被扭曲，正被硬生生地撕扯向两个方向。\n\n我记得影卫企图让殆希莫斯回归……那将带来何等的浩劫……\n\n<虚灵战栗着。>\n\n……然而，我体内有一种黑暗的冲动坚持要执行虚空的意志。难道我们注定要永远臣服于它吗？', 66384),
(307852, 'zhCN', '', '响应我号召的部落叛变者对联盟的血肉充满了杀意。你也一样吗？', 66384),
(307850, 'zhCN', '我越是冥想我的过去，它就变得越清晰。\n\n带着这种黑暗生活将会很艰难……但令人欣慰的是，我们并不孤单。', '', 66384),
(307849, 'zhCN', '燃烧在这些联盟叛变者心中的仇恨简直美味。你也是为了复仇而战吗？', '', 66384),
(307848, 'zhCN', '我们虚空精灵比大多数人更了解虚空发出的诱人低语。\n\n虽然有些人看不起我们，但多亏了联盟的接纳，我们注定不会像流放者一样苟活。\n\n如果我们不接纳这些虚灵，那就是残忍的虚伪。在触手可及的虚空中生活依然是值得过的生活……也是值得拯救的生活。', '我们虚空精灵比大多数人更了解虚空发出的诱人低语。\n\n虽然有些人看不起我们，但多亏了联盟的接纳，我们注定不会像流放者一样苟活。\n\n如果我们不接纳这些虚灵，那就是残忍的虚伪。在触手可及的虚空中生活依然是值得过的生活……也是值得拯救的生活。', 66384),
(307846, 'zhCN', '', '那场战斗！那种刺激！\n\n我看到你了，$c。你也是热血沸腾，跟我一样。\n\n我为那些不得不倒下的恶齿族人哀悼。但我们在战斗中兵戎相见，祖阿曼的每个巨魔都明白拔刀意味着什么。', 66384),
(307845, 'zhCN', '我们与家人的羁绊是无可替代的。我非常感谢你帮助我与姐姐团聚。\n\n如果可以的话，我们会找到更多像沃拉安这样的人。肯定还有其他人，我们可以将他们从黑暗的边缘拉回来。', '', 66384),
(307842, 'zhCN', '', '看看周围。即使在这片宇宙荒原，这些多曼纳尔也设法分清了部落和联盟。红方和蓝方。世道就是这样。\n\n不管有没有战争，总会有我们这样无法宽恕的人。无法遗忘的人。我在布伦纳达姆有家人。我妈妈那边的淳朴农夫。他们永远不会忘记，我也不会。\n\n战争可能结束了，但对于我们这些仍需战斗的人来说，战斗仍在继续。', 66384),
(307836, 'zhCN', '这里离卡雷什十万八千里。我从未想过卷入这么多冲突。\n\n平静生活的念头似乎是地平线上遥不可及的幻影。', '这里离卡雷什十万八千里。我从未想过卷入这么多冲突。\n\n平静生活的念头似乎是地平线上遥不可及的幻影。', 66384),
(307834, 'zhCN', '许多年前，我的人民在战场上赢得了荣耀。现在他们通过在议会中雄辩来赢得荣耀。这是一种安稳的生活，但这不适合我。\n\n我来到这个陌生的世界，是为了能在下次战争威胁到我的人民时做好准备。当那一天到来时，我将已经变得强大且久经沙场。\n\n你出现在这里告诉我，你也拥有寻求自身荣耀的勇气。愿你的祖先在战场上护佑你。', '', 66384),
(307832, 'zhCN', '很高兴能帮忙处理奇点锚点。它通过将异常的虚空能量压缩在熵流汇聚点周围来使其无效，有点像一台非常可怕的除湿机。太迷人了！\n\n自然，压缩矩阵必须保持完整，否则能量很可能会内爆。\n\n但在维迪卡尔的折跃发生器上进行制造工作，教会了我一些关于内爆和矩阵加固的知识。不必担心！', '', 66384),
(307831, 'zhCN', '复仇已经占据了我姐妹的心智。她被蒙蔽了双眼。\n\n她在对抗虚空的控制方面变得更坚强了，但她眼中只剩下了愤怒。', '', 66384),
(307823, 'zhCN', '我经历过一些黑暗的时期，$p。数不胜数。\n\n飞行确实对我大有裨益，当然，并非每个人都有一只狮鹫！\n\n如果你没有，那你得找到属于你自己的“狮鹫”。\n\n对我来说……笑话是良药。如果你在苦难面前笑不出来……好吧，苦难总会找上门来。倒不如一笑置之。\n\n和朋友痛饮一品脱会让任何问题显得微不足道。朋友情谊比酒更醇厚！\n\n有时候你只能硬着头皮往前冲，朝着那片开阔的天空，无论准备好与否。我们走吧？', '', 66384),
(307821, 'zhCN', '很多年前，我随毁灭之锤在这里征战，对抗洛萨的军队。\n\n与冠以他名字的人并肩作战真的很奇怪……与人类合作本身就很奇怪。\n\n但有一个人类的“怪异”彻底改变了我的看法。提里奥·弗丁。以前我对人类的了解仅限于他们因我们带来的战争而憎恨我的族人。\n\n但在其他人只看到待宰野兽的地方，弗丁看到了别的东西。他向我展示了仁慈和同情，即使我们在初次相遇时曾试图置对方于死地。\n\n通过提里奥，我看到人类和兽人并没有什么不同。有些人心怀荣誉；许多人则没有。岁月流转，我看到洛萨之子属于心怀荣誉的那一类。\n\n我想提里奥也会同意的。', '', 66384),
(307819, 'zhCN', '$p，这片区域到处都是这些伪装成黑暗部落的冒牌货。心怀荣耀的我们必须将他们驱逐出去。', '', 66384),
(307806, 'zhCN', '其中也包括在岸边钓早餐的枯木部族孩子们！', '', 66384),
(307805, 'zhCN', '来自祖阿曼的枯木巨魔都会前往哈尔拉兹的神庙朝圣，留下部分猎物作为供奉。', '', 66384),
(307804, 'zhCN', '自我们来到这片土地起，她就一直指引着阿曼尼，并始终是我们部族的化身和象征。', '', 66384),
(307803, 'zhCN', '', '很久以前，一位古老的神灵代言人在神庙的火焰中看到了幻象，带领部族前往安全地带，从此暗松部族便成了加亚莱的主要信奉者。', 66384),
(307802, 'zhCN', '', '等勇士恢复体力后再试一次。', 66384),
(307801, 'zhCN', '', '新兵！这项挑战是为了学会克制，而不仅仅是蛮力。', 66384),
(307800, 'zhCN', '等等，不！我很抱歉，我不是故意——', '', 66384),
(307799, 'zhCN', '', '在四位大神中，恶齿部族最推崇他，因为他直率的性子，以及他在战场上的统治力。', 66384),
(307797, 'zhCN', '起初，他们对我所说的一个字都不信。罗曼斯觉得我是在某种程度上嘲弄他。但昂卡的种子引起了他们的兴趣。\n\n他们只能提供理论。最可信的一种说法是，太阳之井的过度活跃通过大地本身传播了圣光的影响——直接渗入了永歌森林的树木和根须之中。既然所有的根须都通向哈籁恩达尔……\n\n<哈杜伦指向莎拉达希尔的根须。>\n\n在军团入侵时期，莎拉达希尔的根须曾屈服于暗影。也许这让它们变得特别容易受到太阳之井蔓延的圣光影响。', '', 66384),
(307796, 'zhCN', '我所求的不过是战斗和保卫家园的荣耀。\n\n或许还有把趁手的长矛。\n\n看看现在的我，嗯？', '', 66384),
(307794, 'zhCN', '', '你还站在这儿干什么，嗯？\n\n战士的修行永无止境。即使是像你这样技艺高超的人也不例外，$n。', 66384),
(307793, 'zhCN', '噢，一点点这魔法，一点点那魔法。失去了身体，需要个新的。老样子！\n\n但这只是我们第一次见面。没必要现在全说出来。\n\n西南边的海滩旁有个特别的地方。有空就来找我玩？', '', 66384),
(307791, 'zhCN', '是啊，所以我被困在这个玩偶的身体里了。那又怎样？', '', 66384),
(307784, 'zhCN', '手脚麻利点，还有很多事要做。', '手脚麻利点，还有很多事要做。', 66384),
(307780, 'zhCN', '祝你能找到她。如果找到了，她肯定会冲你吼。或者干脆再跑掉！', '', 66384),
(307779, 'zhCN', '坎扎？我看见她朝我们玩耍的那座木桥跑去了。', '', 66384),
(307773, 'zhCN', '', '这些怪物妄图将众生淹没在虚空之中……我不希望任何人遭遇这种命运！', 66384),
(307771, 'zhCN', '静下心来，沃拉安。迷失于复仇，与迷失于虚空并无二致。', '', 66384),
(307769, 'zhCN', '你可能听说了，我们在太阳之井遇袭点附近发现了一个隐蔽的军械库。\n\n虽说提阿姆信誓旦旦地说大部分装备完好无损，甚至还保留着魔力，但毕竟尘封了这么多年。我得先检查确认能不能用，再发下去。\n\n我是被派来建熔炉支援特遣队士兵的，有需要尽管开口！', '', 66384),
(307767, 'zhCN', '你好，$r，有什么能帮你的吗？', '', 66384),
(307760, 'zhCN', '', '我能看出你灵魂的一部分仍停留在过去，那场激战正酣之时。\n\n你想穿越到这个时刻之前吗？\n\n|cFF0000FF（你可以随时与加亚莱幻容对话，再次回到这个时间线的阿塔阿曼。）|r', 66384),
(307757, 'zhCN', '', '我能看出你的灵魂与另一个已经历过这场战斗的灵魂相连。\n\n你想穿越到这个时刻之后吗？\n\n|cFF0000FF（你可以随时与加亚莱幻容对话，再次回到这场战斗。）|r', 66384),
(307751, 'zhCN', '', '维迪奥斯已收到我的口信。他很快就会到。他最喜欢唇枪舌剑的谈判了。你查到了什么？', 66384),
(307750, 'zhCN', '痛楚难以忍受……就像我的本质被扭曲，正被硬生生地撕扯向两个方向。\n\n我记得影卫企图让迪门修斯回归……那将带来何等的浩劫……\n\n<虚灵战栗着。>\n\n……然而，我体内有一种黑暗的冲动坚持要执行虚空的意志。难道我们注定要永远臣服于它吗？', '痛楚难以忍受……就像我的本质被扭曲，正被硬生生地撕扯向两个方向。\n\n我记得影卫企图让迪门修斯回归……那将带来何等的浩劫……\n\n<虚灵战栗着。>\n\n……然而，我体内有一种黑暗的冲动坚持要执行虚空的意志。难道我们注定要永远臣服于它吗？', 66384),
(307746, 'zhCN', '灌注于我体内的虚空仍在嘶吼……但凝视这枚坠饰时，我在卡雷什生活的记忆便如利刃般刺破了黑暗。\n\n这颗宝石属于我的母亲……是我父亲送给她的礼物……象征着他们毫无保留的爱。\n\n暗影仍在催促我屈服……催促我去毁灭……但它们感觉更加遥远了……它们对我心智的腐蚀之握也不再那么牢固了。', '', 66384),
(307743, 'zhCN', '噢，是的。我是特遣队的驯兽师。我们需要随时准备好接收一支飞行编队。\n\n如果这还不够忙的话，他们还叫我处理特遣队收集到的任何标本。当然，连游侠队长都说不出我们要面对什么。\n\n这就是一个卑微中士的命啊。如果没别的事，我要回去干活了。', '', 66384),
(307740, 'zhCN', '请快点，我还有很多事要做。', '', 66384),
(307738, 'zhCN', '当然应该，但这要付出什么代价？\n\n一定有办法既能保存属于我们的遗产，又能击败家门口的敌人。\n\n不管暗谷女士怎么想，我们都可以两全其美。她对黑暗力量的痴迷，已经毁掉了她处理此类事务时本该有的谨慎。', '', 66384),
(307736, 'zhCN', '在她对待……一切事物的方式上！研究历史遗迹、调查奇异魔法，甚至保存力量圣物！\n\n与其说这位“暗谷女士”热衷于保存我们的历史，倒不如说她更想了解那些威胁着历史的黑暗力量。哪怕这意味着要采取更具破坏性的手段。', '', 66384),
(307734, 'zhCN', '噢，别告诉我你也打算站在暗谷女士那边，$C？', '', 66384),
(307732, 'zhCN', '', '神圣遗物学会的一员？我吗？恐怕你搞错了。\n\n我确实一直觉得他们的工作相当迷人——甚至还给泰瑟兰那些铺张的筹款会捐过钱，资助他的探险。\n\n但这很遗憾，那位高阶考察者从未批准我的入会申请。我想我肯定是在什么时候得罪过他。\n\n<暗谷女士露出一丝羞涩却又不怀好意的笑。>\n\n不过嘛，当需要一个既精通黑暗魔法又深谙历史的人时，却没人比我更合适了。\n\n他没法否认我的资历，于是就打发安多伦来给我上课……好吧，说实话，他那些唠叨我早就左耳进右耳出了。', 66384),
(307730, 'zhCN', '', '<暗谷女士叹了口气。>\n\n你也知道银月城现在的风气……带着我那帮……随从招摇过市可不太明智。\n\n趁着亲爱的布罗西纽斯不在，我找了个替代品。在他面前尽量规矩点，嗯？他对工作可是相当死心塌地的。', 66384),
(307728, 'zhCN', '', '<暗谷女士歪着头，上下打量着你。>\n\n好吧，像你这种$C大人物，找我有什么贵干？', 66384),
(307727, 'zhCN', '', '年纪……我可是大本营里资历最老的见习探险者！\n\n再加上我已经开始跟随莱阿娜研究神器了。她同意收我为徒。\n\n我从未见过像银月城这样宏伟的都市！我们去过一次瓦德拉肯，但这里的人气要旺得多。', 66384),
(307725, 'zhCN', '', '噢，你好呀！', 66384),
(307724, 'zhCN', '', '游侠队长认为，鉴于未来威胁重重，我在圣物研究方面的经验将是无价之宝。\n\n在此之前，我正为龙鳞探险队编录圣物，这时营地传来了太阳之井遇袭的噩耗。我便加入了赶回银月城的队伍。\n\n我也未曾遗忘，当年奎尔萨拉斯的人民是如何众志成城，驰援苏拉玛的。我会竭尽所能提供协助。', 66384),
(307722, 'zhCN', '', '你好，$r。', 66384),
(307720, 'zhCN', '我们有个小组一直在研究最近袭击中留下的遗物。这些物品似乎被注入了潜藏的虚空魔法，我相信这极大地激发了它们的潜能。\n\n其物理形态也发生了异变，外观变得相当骇人！很有意思，不是吗？\n\n一旦确认它们对我们无害，就可以着手以此装备部队，用敌人的力量来反制他们！', '', 66384),
(307718, 'zhCN', '这真是个惊人的发现！', '', 66384),
(307717, 'zhCN', '', '在萨拉塔斯攻击太阳之井期间，附近的一座建筑受损。当救援人员进入寻找幸存者时，他们发现了一个秘密的武器库，里面藏着护甲和武器，很可能是在多年前燃烧军团入侵时藏匿的。\n\n我们正在清点哪些物品仍然完好可用。我们需要所有能得到的武器和护甲。尤其是在游侠队长成立新特遣队之后。', 66384),
(307715, 'zhCN', '', '你好，我们有点忙，你有事吗？', 66384),
(307712, 'zhCN', '', '去吧，$rs。完事后就来加入我。我们将直面维迪奥斯。', 66384),
(307708, 'zhCN', '', '到我这儿来，$n。我的宿敌维迪奥斯的部队正在推进。', 66384),
(307706, 'zhCN', '', '无论如何，前往憎恨尖塔，$rs。我会在那里等你。', 66384),
(307691, 'zhCN', '这个$c杀死了我的接体者，还摧毁了我的家园。你确实让我刮目相看。如果这个凡人能召集他的盟友在我的竞技场里战斗，我就让你们自己解决争端！', '', 66384),
(307689, 'zhCN', '它被束缚住了，很好。$C，去找到并杀死接体者，我们在削弱这头野兽。最后一击留给你。', '', 66384),
(307688, 'zhCN', '', '即使我们要联手，可能也不足以终结这头怪物，维迪奥斯。', 66384),
(307687, 'zhCN', '我的皮具可能没有卡利卡的那么花哨，但料子可结实多了！', '我的皮具可能没有卡利卡的那么花哨，但料子可结实多了！', 66384),
(307686, 'zhCN', '针线跟皮革一样重要！', '针线跟皮革一样重要！', 66384),
(307683, 'zhCN', '', '我们很快就会回到我们的博弈中。在那之前，我只能勉强忍受与你并肩作战了。', 66384),
(307681, 'zhCN', '真是扫兴。我正欣赏着部落和联盟的厮杀呢。', '', 66384),
(307671, 'zhCN', '', '鉴于虚空对太阳之井的攻势，我们的主力部队正集中精力在奎尔萨拉斯进行抵抗。\n\n游侠将军哈杜伦·明翼指派我组建一支灵活的特遣队，以便在新威胁出现时迅速做出反应。还有一些宿敌正趁乱作祟，我们也会盯着他们。\n\n等到第一个任务下达时，我会联系你。', 66384),
(307669, 'zhCN', '', '你好，$c。你是来应征的吗？', 66384),
(307666, 'zhCN', '办事。\n\n私事。与你无关。', '办事。\n\n私事。与你无关。', 66384),
(307663, 'zhCN', '这个世界的原生植物……简直恶劣到了极点！\n\n你在这里找不到任何恬静的花朵。不，绝无可能。即使是虚影风暴的植物也在缓慢地互相吞噬，或是绞杀彼此，或是用慢性毒药毒害近邻。\n\n我拥抱虚空，正是为了寻求终结这一切的方法。我能否培育出一种既能抵御这残酷生态，又不至于沦为掠食者的植物？\n\n所以我将银月城的宁静之花移植到了各处。你可能已经见过它们了！目前看来，前景尚可，尽管我确实不得不给它们注入……些许虚空之力，才算有点起色。\n\n如果你看到盛开的花朵，尽管去修剪它们，因为孢子已经散播出去了。', '', 66384),
(307642, 'zhCN', '', '你注意到虚影风暴周围那些诡异的漩涡了吗？它们散发着一股奇特的海洋气息。\n\n为了一块上好的鱼肉，我什么都愿意做。怎么了？我可是海边长大的。\n\n那些漩涡有轻微的引力。我试着把鱼漂扔到一个漩涡上，耐心等着……嘿，你瞧，还真有东西上钩了！\n\n我本以为能钓上来什么深海巨兽！结果呢，钓上来的鱼虽然有趣，却普通得让人有点小失望。\n\n可我们周围根本没有水啊。这些漩涡一定是把空间扭曲到了某个有水的地方。\n\n难道这个世界上还有海洋？又或者，这些漩涡甚至能连通到其他世界？', 66384),
(307635, 'zhCN', '', '死亡与虚空魔法似乎在这些祭坛上发生了某种交汇与聚合。\n\n我虽然不愿承认……但我实在无法理解其原理。祭坛显然是多曼纳尔人所建，却完全由虚空魔法构成，而非死亡魔法。\n\n我们唯一的多曼纳尔盟友对此话题闪烁其词。这会是他们某种文化上的禁忌或仪式吗？或者他们根本无意用祭坛召唤死亡魔法，一切只是巧合？\n\n<查瑞紧锁眉头。>\n\n我最讨厌这种看不透的谜团。', 66384),
(307634, 'zhCN', '勇猛地战斗吧，$rs。我将去直面兹尔丹。你完事后就来与我并肩作战。', '', 66384),
(307605, 'zhCN', '到我这儿来，$n。我的宿敌兹尔丹发动了突袭。', '', 66384),
(307604, 'zhCN', '', '<长者多鲁警惕地看护着身边的难民。>\n\n我来断后，必须确保该撤的都撤干净了。', 66384),
(307602, 'zhCN', '愿太阳指引你。', '愿太阳指引你。', 66384),
(307589, 'zhCN', '我听说有位游学者在银月城里摆了个摊说书。他那儿应该有我们种族和太阳之井的传奇故事。', '我听说有位游学者在银月城里摆了个摊说书。他那儿应该有我们种族和太阳之井的传奇故事。', 66384),
(307562, 'zhCN', '', '这，便是艾林哈籁最厚重的赠礼：我们共享的这片生机。所以，勇往直前吧，继续你的旅途，愿艾林哈籁的恩典照亮你的每一步。感谢你，$n。', 66384),
(307561, 'zhCN', '', '但你已经证明，这一步迈得物有所值。我们如今不仅了解了艾林哈籁的广袤土地，更认识了她的芸芸众生与万千风俗。而他们，也同样认识了我们。', 66384),
(307560, 'zhCN', '', '当我们需要向这个世界的其他种族显露身份时，我曾犹豫过。这样的传统真的该被打破吗？', 66384),
(307558, 'zhCN', '', '尽管我们哈籁尼尔浪迹天涯，却总是隐于暗影，秘而不宣。', 66384),
(307554, 'zhCN', '图哈卡，亲爱的。就把头盔带上吧。这是个好头盔。能保你平安。求你了……一定要平安。', '', 66384),
(307553, 'zhCN', '精灵们会保护好他们的城市。部落不会在意几个叛徒的。我们必须让联盟认清他们的位置，你得理解——', '精灵们会保护好他们的城市。部落不会在意几个叛徒的。我们必须让联盟认清他们的位置，你得理解——', 66384),
(307552, 'zhCN', '我明白了。', '', 66384),
(307551, 'zhCN', '还有我的朋友，哈拉娜，她在那场战斗中死了。我不能就这么忘了他们是如何屠杀她的！', '还有我的朋友，哈拉娜，她在那场战斗中死了。我不能就这么忘了他们是如何屠杀她的！', 66384),
(307550, 'zhCN', '我知道。', '', 66384),
(307549, 'zhCN', '他们杀了拉斯塔哈。我的国王！我曾发誓要保护的人！你不能要求我从这场战斗中抽身。', '他们杀了拉斯塔哈。我的国王！我曾发誓要保护的人！你不能要求我从这场战斗中抽身。', 66384),
(307542, 'zhCN', '<赤瞳怒视着你。>\n\n如果你来这里不是为了战斗与荣耀，不是为了彻底战胜部落，那就滚吧。\n\n所有这些所谓的“部落和联盟必须共同面对的敌人”都只是障眼法。很可能是部落精心策划的，好让我们放松警惕。\n\n他们蹂躏了我们的土地，屠杀了我们的人民。绝无宽恕可言。', '', 66384),
(307541, 'zhCN', '我知道我在战场上是个累赘，所以我在这里尽我所能。任何退缩都是怯懦。像你这样的懦夫，不配做我的儿子。', '', 66384),
(307540, 'zhCN', '求你了，父亲，这只是毫无意义的复仇。你已经不适合战斗了！妈妈很担心你。回家吧。', '', 66384),
(307539, 'zhCN', '你就这么看轻你族人的牺牲吗？你的祖父战死在阿什兰，你却要袖手旁观，跟这群怪物把酒言欢？', '', 66384),
(307538, 'zhCN', '汤姆叹了口气。', '', 66384),
(307537, 'zhCN', '我心里很矛盾。\n\n一部分的我觉得是时候静观其变了。观察我姐姐如何处理我们的问题。向她学习。\n\n但另一方面……我老觉得这条路不对。如果我们不保持警惕，这将把我们的人民带入一个软弱的时代。', '', 66384),
(307535, 'zhCN', '', '我决定回来，留在祖阿曼。\n\n尽管由于我们两个民族之间那段血腥的冲突史，我曾长期与阿曼尼为敌，但这短时间的经历让我以全新的眼光看待他们。\n\n我深知，过去的痛苦和仇恨并非轻易能消弭。这依然是我今天要面对的漫漫长路。\n\n但是……通往未来的唯一道路就是前行。一步一个脚印。', 66384),
(307523, 'zhCN', '曾有一位名为缚魂者娜欣达利的虚灵，她捕获了卡雷什人的灵魂，并将他们束缚于虚空。当艾泽拉斯的部队在法力熔炉：欧米伽击溃影卫时，娜欣达利的行径才被制止。\n\n但在此之前，她已经将我太多的同胞转化为了黑暗的爪牙。沃拉安就是这样一位虚灵……她的裹布被虚空能量浸染……她的灵魂被虚空的意志束缚。\n\n如果他们中的一些人现在开始反抗……那么在影卫中，是否还有其他像他们一样的人？', '', 66384),
(307517, 'zhCN', '', '很好。现在，剩下的尸首都归我了。', 66384),
(307516, 'zhCN', '祖尔加的双眼燃起了复仇的烈焰。', '', 66384),
(307496, 'zhCN', '', '看吧，科弗？我就知道你行的。', 66384),
(307495, 'zhCN', '他吗？$B$B我发现老奈昆那会儿，他正受着伤，一头巨型迅叶龙正朝他逼近。我全凭运气，才一箭射中了那畜生的脖子。$B$B那一刻，我本想了结了老奈昆。赐他一个长眠。但是，仿佛大自然抓住了我的手，我下不了手。时至今日，我越发庆幸我那天的决定。', '', 66384),
(307480, 'zhCN', '', '你是干掉了主菌株，但我估计这怪东西没这么容易断根。\n\n我们受到的教导是，要尊重万物，视其为艾林哈籁的造物。但这些玩意儿……\n\n<吉卡勒叹了口气。>\n\n也许是我想太多了。我会先留在这儿，确保这片感染不会再扩散开去。', 66384),
(307473, 'zhCN', '', '外来者！快看我们发现了啥！', 66384),
(307459, 'zhCN', '除此之外，还有什么值得一做吗？\n\n小$rs，你的领袖看不出我们多曼纳尔一族所拥有的战斗价值，这真可悲。在这里，目的只有一个。我们为战而生。\n\n只有勇者、强者和疯子，才懂得在此执剑的勇气。只有他们，才能品味酣畅淋漓的战斗带来的愉悦。\n\n在这片战场上，你不是为联盟而战。你是为我而战。你的战斗与死亡皆是为了取悦我，我们将一同在对抗兹尔丹的冲突中尽情狂欢。\n\n如果这理由还不够，那我赐予你的丰厚奖赏，也足以助你保护那珍贵的世界免受萨拉塔斯的侵蚀。', '', 66384),
(307455, 'zhCN', '无论如何，我请求你的援助。前往哀痛尖塔，$rs。我会在那里与你汇合。', '', 66384),
(307418, 'zhCN', '你这旅行者可真够怪的。不过，在艾林哈籁的根须下，万物皆可安歇。', '你这旅行者可真够怪的。不过，在艾林哈籁的根须下，万物皆可安歇。', 66384),
(307404, 'zhCN', '我一向更喜欢在树根之间享受独处。', '', 66384),
(307390, 'zhCN', '就我个人而言，我正努力避免被开膛破肚、被蒸发或者被奇点吞噬。\n\n往大了说，我们在跟随你穿过传送门后，在这里建立了一个滩头阵地。这能把吞噬军团的注意力从入口引开。要是他们夺取了我们通往银月城腹地的传送门，那可就糟了。\n\n与此同时，我们的研究人员正试图消除虚空畸能，以免随时可能让我们所有人灰飞烟灭。', '', 66384),
(307320, 'zhCN', '', '我们既是丹青妙手，亦是历史的执笔者。我们借由画作，记录时代的真实——这份传统已由先辈之手代代相传。', 66384),
(307317, 'zhCN', '', '遵从先祖的教诲，以笔触承载历史，需要心如止水，下笔沉稳。', 66384),
(307312, 'zhCN', '起初，我们只是在安全距离外对这片区域进行侦察。在判断此地的生物不足为惧后，我们便开始采集各类样本。当遭遇敌对生物攻击时，我们能轻松将其斩杀，然而，正是它们飞溅的血液，注定了我们所有人的厄运。\n\n裂隙行者洛恩是第一个被感染的，但我们察觉时已经太晚了。那病原体的侵蚀悄无声息，它混淆了我们的判断。在体内那个东西的驱使下，我们一个接一个地背弃了职责，也抛弃了同伴。\n\n我们过于迷信自身的力量，最终倒在了一个潜藏于体内的敌人脚下。切记，不要重蹈我们的覆辙，千万别放松警惕。', '', 66384),
(307311, 'zhCN', '我很高兴能摆脱那段可怕的经历。', '', 66384),
(307309, 'zhCN', '', '非走不可吗？', 66384),
(307308, 'zhCN', '', '我知道我该和妈妈谈谈。但每当我开口说话……我听见的却全是你的声音。', 66384),
(307304, 'zhCN', '', '<坎扎朝着她为水豚铺开的毯子努了努嘴。\n\n看样子，她想让你把东西摆在毯子正中央。\n\n从她为水豚摆放的盘子和盛宴来看，你推测她布置了一场茶话会，希望能以此取悦费洛。>', 66384),
(307303, 'zhCN', '', '<坎扎朝你莞尔一笑，不经意地将一缕头发掠到耳后，目光随即便落在了自己的脚尖上。>', 66384),
(307291, 'zhCN', '有些历史，还是让它永不见天日的好。', '', 66384),
(307285, 'zhCN', '祖阿曼境内盘踞着许多司掌次级领域的小神灵。去找到他们的踪迹，再回到这里，便可以领受他们的祝福。', '祖阿曼境内盘踞着许多司掌次级领域的小神灵。去找到他们的踪迹，再回到这里，便可以领受他们的祝福。', 66384),
(307283, 'zhCN', '你的族人正在为自由与生存浴血奋战，你就只会说这些风凉话？那就滚吧！', '你的族人正在为自由与生存浴血奋战，你就只会说这些风凉话？那就滚吧！', 66384),
(307282, 'zhCN', '把优势拱手相让？荣耀只属于辛多雷——你忘了吗？', '把优势拱手相让？荣耀只属于辛多雷——你忘了吗？', 66384),
(307281, 'zhCN', '你的同胞就倒在身边，或死或伤，你就只说得出这种话？', '你的同胞就倒在身边，或死或伤，你就只说得出这种话？', 66384),
(307280, 'zhCN', '你难道忘了自己的历史？一旦有机会，阿曼尼会毫不留情地夺走我们的土地和性命！', '你难道忘了自己的历史？一旦有机会，阿曼尼会毫不留情地夺走我们的土地和性命！', 66384),
(307279, 'zhCN', '你疯了吗？看来除了阿曼尼，你的胡言乱语也该被我一并禁绝！', '你疯了吗？看来除了阿曼尼，你的胡言乱语也该被我一并禁绝！', 66384),
(307278, 'zhCN', '你是不是失心疯了？他们可是我们世代的宿敌！', '你是不是失心疯了？他们可是我们世代的宿敌！', 66384),
(307277, 'zhCN', '杀了我，我这些神兵利器的秘密也将一同埋葬。若你愿作我的宿主，便能执掌足以毁灭世界的力量。', '', 66384),
(307276, 'zhCN', '', '你没开玩笑吧？星辰在上，你和那个莱希卡斯真是一个模子刻出来的。\n\n<麦拉摇了摇头。>\n\n我该谢天谢地你没把我们一起送上天。接下来别再乱碰东西了，好运可不会有第二次。', 66384),
(307268, 'zhCN', '也罢，不过你得承认，刚才那一下挺过瘾的。', '', 66384),
(307253, 'zhCN', '停下？我们的战局才刚刚扭转！', '停下？我们的战局才刚刚扭转！', 66384),
(307252, 'zhCN', '阿曼尼败退了。胜利已唾手可得。', '阿曼尼败退了。胜利已唾手可得。', 66384),
(307251, 'zhCN', '把优势拱手相让？休想！荣耀归于辛多雷！', '把优势拱手相让？休想！荣耀归于辛多雷！', 66384),
(307250, 'zhCN', '阿曼尼来犯，辛多雷迎击——数千年来，这便是铁律！', '阿曼尼来犯，辛多雷迎击——数千年来，这便是铁律！', 66384),
(307249, 'zhCN', '我绝不辜负圣光与图拉扬的期望！继续猛攻！', '', 66384),
(307248, 'zhCN', '愿圣光引领你我前行。', '', 66384),
(307247, 'zhCN', '看看他们犯下的罪行！此仇我必报！', '看看他们犯下的罪行！此仇我必报！', 66384),
(307246, 'zhCN', '一个阿曼尼杂碎从背后偷袭，用长矛刺穿了他后就逃了……真是个卑劣的懦夫！', '一个阿曼尼杂碎从背后偷袭，用长矛刺穿了他后就逃了……真是个卑劣的懦夫！', 66384),
(307245, 'zhCN', '你难道瞎了吗，看不到眼前的敌人？他们胆敢来犯，我们就必须让他们血债血偿！', '', 66384),
(307244, 'zhCN', '圣光将为我们照亮前路！', '', 66384),
(307243, 'zhCN', '我早知必有此日！为了奎尔萨拉斯！', '我早知必有此日！为了奎尔萨拉斯！', 66384),
(307242, 'zhCN', '阿曼尼在你眼里或许不算什么，可一旦让他们得势，他们就会侵占我们的家园，屠戮我们的同胞！', '阿曼尼在你眼里或许不算什么，可一旦让他们得势，他们就会侵占我们的家园，屠戮我们的同胞！', 66384),
(307241, 'zhCN', '住手？该收手的不是我们——是他们！', '住手？该收手的不是我们——是他们！', 66384),
(307240, 'zhCN', '我要让他们的法术军械全都报废！', '我要让他们的法术军械全都报废！', 66384),
(307239, 'zhCN', '不是真正的威胁？他们是我们数个世代的宿敌！这种话决不能容忍！', '不是真正的威胁？他们是我们数个世代的宿敌！这种话决不能容忍！', 66384),
(307238, 'zhCN', '愿你箭无虚发！', '愿你箭无虚发！', 66384),
(307222, 'zhCN', '这声音是怎么回事？为什么怪物连石头都吃？我们必须查个水落石出。来！', '', 66384),
(307203, 'zhCN', '', '费洛挺可爱的，对吧？', 66384),
(307197, 'zhCN', '', '坎扎嘛……她跟别人不一样。\n\n她还是个娃娃的时候，不爱说话，不爱笑，眼神也总是躲躲闪闪的。\n\n多亏了父亲、她父亲还有她那个双胞胎姐姐，她才慢慢开始说话、玩闹，像个正常的孩子。\n\n可后来母亲过世了，她父亲的工作越来越脱不开身，她姐姐雅娜卡也得血病死了。\n\n雅娜卡走后，她就又把自己封起来了。我寻思着给她点时间缓缓。可这一晃，都三年了。', 66384),
(307150, 'zhCN', '<驮包兽向你俯首，随时听候你的差遣。>', '<驮包兽向你俯首，随时听候你的差遣。>', 66384),
(307133, 'zhCN', '能量超载！', '', 66384),
(307127, 'zhCN', '', '哈舒拉，多谢你……为我做的一切。', 66384),
(307126, 'zhCN', '什么？随你便。反正我身体好多了。你做的饭也一点不好吃。', '', 66384),
(307125, 'zhCN', '', '你说得对，父亲。别再找借口了……你的借口到头了！滚出我的家！', 66384),
(307124, 'zhCN', '胡闹！全是借口！撒谎！丫头，费洛根本不是你召来的！', '', 66384),
(307123, 'zhCN', '', '我……我非去见姐姐不可。见她最后一面。', 66384),
(307122, 'zhCN', '哼，现在倒肯开口了？为什么让你妈白白担心这么久？', '', 66384),
(307121, 'zhCN', '', '坎扎！你平安回来了，还有……你刚刚说什么了？', 66384),
(307120, 'zhCN', '', '妈妈……', 66384),
(307113, 'zhCN', '费洛开心地叽叽叫着打了声招呼，便一头扎进了自己的餐盘里。', '', 66384),
(307112, 'zhCN', '', '再会了，姐姐。我们……总有再见的一天。', 66384),
(307111, 'zhCN', '', '雅娜卡向坎扎点头致意并挥手道别，随后坎扎动身去追随费洛了。', 66384),
(307108, 'zhCN', '费洛打着哈欠伸了个懒腰，转身便要走。', '', 66384),
(307105, 'zhCN', '', '雅娜卡笑着点点头，随即双手往腰上一叉。', 66384),
(307104, 'zhCN', '', '你……没事吧？', 66384),
(307103, 'zhCN', '', '雅娜卡一见到坎扎，脸上便漾起了温暖的笑意。', 66384),
(307102, 'zhCN', '费洛的嘴里塞满了刺盖菇，慢慢点了点头。', '', 66384),
(307101, 'zhCN', '', '我姐姐……是和你一起来的？', 66384),
(307100, 'zhCN', '', '费洛……', 66384),
(307086, 'zhCN', '我去那片入侵区域的尽头，探查一下源头。', '', 66384),
(307085, 'zhCN', '……', '……', 66384),
(307083, 'zhCN', '我们走着瞧吧。', '', 66384),
(307079, 'zhCN', '如果那一切属实，我很庆幸我们让阿金图安德的知识随风而逝。我会如实报告我们的发现，但关于那件武器的所有细节已荡然无存。', '', 66384),
(307070, 'zhCN', '', '<坎扎仰头望着你，脸上绽放出一抹转瞬即逝的笑容。\n\n能有你这样耐心倾听、试图理解她的人，她似乎由衷地感到高兴。>', 66384),
(307054, 'zhCN', '', '<你正要动身，坎扎却拦下你，清了清嗓子。你心中一惊，以为她终于要开口说话了。\n\n谁知，她竟发出了一声足以乱真的野猪冲锋时的尖嚎，把你吓了一大跳。\n\n你领会了她的警告：当心野猪会为了这些刺盖菇跟你拼命。>', 66384),
(307052, 'zhCN', '', '<坎扎指了指脚边的蘑菇，捏着菌柄摘下一朵，巧妙地避开了带刺的菌盖。\n\n她用那双小手，灵活地剥去了菌盖上的刺。\n\n她把蘑菇递给你闻了闻。\n\n一股奇妙的香气钻入鼻腔，介于松露和蒜蓉之间。>', 66384),
(307041, 'zhCN', '这儿！这块石板肯定是这些碎石的源头。快，你能读懂它吗？', '', 66384),
(307039, 'zhCN', '', '坎扎朝你做了个手势，示意跟上。', 66384),
(307034, 'zhCN', '你无所畏惧。强大非凡。我赐予你知识。这个世界曾被称为普雷德西亚。', '', 66384),
(307031, 'zhCN', '幸会，$c。', '', 66384),
(307030, 'zhCN', '这种牺牲，还由不得你来做，$c。', '', 66384),
(307029, 'zhCN', '没错，到我这儿来。踏入那些涡流。', '', 66384),
(307027, 'zhCN', '但愿这堆篝火，也能为我们带来一份同样的庇佑。', '', 66384),
(307022, 'zhCN', '我可以为你指引本地的各个名胜。', '我可以为你指引本地的各个名胜。', 66384),
(307019, 'zhCN', '', '<坎扎兴奋地指着温泉池，吸引你的注意。\n\n她像扇动翅膀一样挥动手臂，随后假装盯着某个在空中飞行的东西。接着她做出了捕捉那个虚构飞行物的动作，并用力在掌心拍扁。\n\n你注意到池水周围有许多刺叮者在盘旋，使得岛外的水豚无法靠近温泉。\n\n或许坎扎是想让你清理掉它们，好让更多的水豚能在这儿放松？>', 66384),
(306896, 'zhCN', '', '凯莎抖落这些树枝，是为了摆脱旧日的毒素。', 66384),
(306895, 'zhCN', '如此鲜活、充满求知欲的灵魂……我有你们寻求的答案。来找我……', '', 66384),
(306894, 'zhCN', '也许等那个洛阿不搭理她了，她就会开始搭理我们了！', '', 66384),
(306893, 'zhCN', '', '父亲……求你了。那女孩也是身不由己。', 66384),
(306886, 'zhCN', '', '这些筋腱会把木柴捆在一起，直到火焰熄灭。', 66384),
(306885, 'zhCN', '这东西很结实。让我想起了我姐姐。', '', 66384),
(306884, 'zhCN', '', '倒是合适……对某些人来说，她是他们的靠山。但对我们来说，她冷酷如石。', 66384),
(306883, 'zhCN', '首先我们放下石头。象征她的一生。', '', 66384),
(306865, 'zhCN', '你要找哪位专业技能训练师？', '你要找哪位专业技能训练师？', 66384),
(306863, 'zhCN', '你在寻觅什么，$c？', '你在寻觅什么，$c？', 66384),
(306860, 'zhCN', '', '<坎扎眯起眼睛，上下打量着你。\n\n她攥紧拳头，用力跺了跺脚。\n\n很显然，她不打算心甘情愿地跟你回去。>', 66384),
(306856, 'zhCN', '', '阿曼尼永远欢迎你，$n。', 66384),
(306852, 'zhCN', '', '至少邪枝部族没抓走我，至少我父亲还活着回来了。\n\n我们这个小家已经承受了太多悲剧，无法再继续了。\n\n咦，我的小坎扎跑到哪儿去了？', 66384),
(306851, 'zhCN', '', '看她走的方向。\n\n还有她带走的东西。\n\n只有小孩子才能召唤费洛，而且只能用孩子的方式。\n\n那个茶壶，那个野餐篮……她是要去跟他玩。\n\n既然她打碎了茶壶，又弄丢了篮子里的食物，我真不知道她现在会怎么做……', 66384),
(306849, 'zhCN', '', '就算她到我死都不再跟我说一句话，我也心满意足了。\n\n我很高兴她回来了。也很难过我当初没听懂她想告诉我什么。\n\n她需要一个了结。她需要一个能让她安全做自己的地方。', 66384),
(306842, 'zhCN', '', '躲了很久。逃亡。艰难。\n\n定计划。骗那些可悲的堕落者。他们以为我们死了。但没有。\n\n不是和平。但后来，容易些了。', 66384),
(306841, 'zhCN', '', '数百年来，我们所能做的唯有求生。我们世界的原生巨兽也在抵抗军团，它们对恶魔和德莱尼一视同仁，皆为猎物。幸运的是，军团腐化这些原生生物的企图总是以宿主的死亡告终。\n\n我与一些心怀不满的恶魔追兵暗中勾结，策划了一场孤注一掷的豪赌。我们伪造了一场背水一战，让军团指挥部误以为我们已全军覆没。在那片灰烬之中，新生萌芽。\n\n那并非我们世界战争的终结。但那是我们第一次得以休养生息。', 66384),
(306840, 'zhCN', '', '看来是托了这位精灵的福，我们总算能交流了。容我自我介绍，并致以诚挚的谢意。\n\n我，是虚空来客图尔阿玛。我生于阿古斯，曾追随维伦登上吉尼达尔。和多数族人一样，当燃烧军团突袭我们千年前的避难所时，次元飞船把我们遗弃在了那里。\n\n全靠了你，我的人民才得以保全。这份恩情，我没齿难忘。', 66384),
(306834, 'zhCN', '', '我能帮你什么忙吗，$c？', 66384),
(306819, 'zhCN', '等等，他又跑了！抓住那个小怪物！', '', 66384),
(306818, 'zhCN', '我猜，至少他达到锻炼的目的了。', '', 66384),
(306816, 'zhCN', '它们离开水活不了多久的——快点！', '', 66384),
(306801, 'zhCN', '', '我在思考……你到底够不够格？还是说，没拿到好处你就先撂挑子了？', 66384),
(306781, 'zhCN', '虚空的触碰已被净化。这些力量既强大……又多变……并且其副作用看来……尚在可控范围。', '', 66384),
(306779, 'zhCN', '我是个战士，不是个跳舞的！他们怎么能指望我动作优雅？\n\n他们本该训练我如何战斗才对。\n\n这纯粹是浪费时间。', '', 66384),
(306777, 'zhCN', '<科弗没有停下舞步，完全沉浸在节奏中。他朝你眨了眨眼。>\n\n看来，我总算明白这跳舞的意义了。', '', 66384),
(306766, 'zhCN', '', '这种情况下我可没法上课！', 66384),
(306765, 'zhCN', '', '在那儿！他跑了——他正朝着花园街市的传送器跑过去！', 66384),
(306753, 'zhCN', '现在，该处理容器了。我们要增强它的效能。把它放在这里——小心点。', '', 66384),
(306750, 'zhCN', '首先，准备好净化之盐。这应该能保护我们的骑士免受苦痛那最残酷的副作用侵扰。', '', 66384),
(306749, 'zhCN', '苦痛似乎是一种可塑的力量……让我们看看它还能做些什么。', '', 66384),
(306746, 'zhCN', '这位血骑士在虚空入侵时被邪恶生物所伤，并自愿将躯体贡献出来供我研究。\n\n让我们看看，我们的苦痛之力能造就什么。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(306742, 'zhCN', '滚出我的视线，部落的猪猡。', '', 66384),
(306741, 'zhCN', '空气里满是兽人的腐臭和血腥味。这帮部落怪物装得好像自己比谁都高贵。他们算个屁。\n\n我们当中，可还有人记着他们的所作所为。', '', 66384),
(306740, 'zhCN', '', '这帮该死的联盟走狗，正削尖了脑袋想找由头报旧仇。\n\n他们想找茬？我高兴还来不及呢。', 66384),
(306739, 'zhCN', '', '跟你这联盟的走狗，我无话可说。', 66384),
(306738, 'zhCN', '要怎么在竞技场里拔得头筹？\n\n靠研究、靠苦练，还必须有耐心去面对失败、吸取教训、然后想办法活过今天。\n\n那些一心只想着报私仇的家伙，不过是群有勇无谋的匹夫。我来这儿，就是要让那帮怪物懂一个道理：小瞧我们的代价，就是他们的死期。我们必须变得比他们更强，而且要一直强下去。\n\n战个痛快，$c。', '要怎么在竞技场里拔得头筹？\n\n靠研究、靠苦练，还得有耐心去面对失败、吸取教训、然后想办法活过今天。\n\n那些一心只想着报私仇的家伙，不过是群有勇无谋的匹夫。我来这儿，就是要让那帮怪物懂一个道理：小瞧我们的代价，就是他们的死期。我们必须变得比他们更强，而且要一直强下去。\n\n战个痛快，$c。', 66384),
(306716, 'zhCN', '达纳斯指向你。', '', 66384),
(306712, 'zhCN', '', '对外来者而言，这也许算不上多奇怪。但其中的差异——以及危险——是显而易见的。\n\n我观察真菌人很多年了。没错，腐朽确实是他们的常态。但他们通常是有意识地吞噬，会顾及周遭的环境。他们本该知道，过度扩张或吞噬，对他们自己和其他事物一样，都意味着毁灭。\n\n但这些……东西……它们不一样。它们眼中毫无生气，饥渴也全无节制。就好像它们被附身了，被“腐朽”和“衰败”这个概念本身操控成了傀儡。\n\n哈籁尼尔可没那么容易被吓倒，$c。\n\n但这个……我们必须找到源头。而且要快。', 66384),
(306709, 'zhCN', '<殆希莫斯无视了你，转而专心偷听奥蕾莉亚和阿拉托尔的对话。>', '', 66384),
(306690, 'zhCN', '', '这些真菌人远比平时更具敌意，但他们几乎不发出任何声音。还有他们那空洞的眼神……\n\n我甚至怀疑这些东西到底还活没活着。', 66384),
(306689, 'zhCN', '', '真菌人很吵闹——吵得令人厌烦——但最近，芬加拉村却是一片寂静。', 66384),
(306642, 'zhCN', '这问题可真令人扫兴。\n\n那就干脆放弃任务，回银月城来见我吧。我想，我总能找到更合你口味的事。\n\n\n[放弃狩猎的方法：打开任务日志，选中该任务，点击放弃。随后返回银月城找阿斯塔洛，选取新的狩猎任务。]', '', 66384),
(306641, 'zhCN', '随着你逐步接近目标，我的水晶将逐渐被它们的苦痛填充。苦痛积蓄到一定程度，它们的位置就会向我们揭示。\n\n但苦痛是种变幻莫测的力量。有些狩猎能速战速决，有些则需要格外努力。', '', 66384),
(306640, 'zhCN', '任何能暂时将目标引出藏身处，或吸引其注意力的行为，都有助于我的魔法锁定他们的确切位置。\n\n\n[狩猎进度的来源包括：在此区域内挫败伏击、与陷阱互动、消灭凝结成形的苦痛、完成世界任务、拾取宝藏以及击败稀有敌人。]', '', 66384),
(306583, 'zhCN', '', '我必须解决这场螃蟹危机。不只是为了我饥肠辘辘的人民，也是为了我的母亲。她曾那么深切地关怀着恶齿部族。\n\n她为我们的家族感到骄傲，为我们世世代代守护恶齿部族的繁荣而自豪。人们知道可以指望我们填饱肚子，如果我辜负了这份信任呢？辜负了这个承诺？感谢纳洛拉克，我没有。\n\n现在我知道了，我是一名合格的领袖，就像我的祖先一样。', 66384),
(306582, 'zhCN', '', '我还有许多蟹笼要去装满。我母亲是带领过我们的、最具传奇色彩的河川行者之一，她教会了我捕蟹的一切。我们失去了她，\n\n她倒在了暮光之刃的手里，我不得不接过她的重担。若我沉溺于对她的思念，悲伤便会让我分心旁骛，无法化解这场危机。', 66384),
(306581, 'zhCN', '卡哈妮解决饥荒的壮举真正证明了她的实力。我一开始还对她有所保留，但现在我只想为她效力，让她为我骄傲！\n\n能有她这样的领袖真是我的荣幸。她绝对配得上历史上最伟大河川行者的称号。', '', 66384),
(306580, 'zhCN', '我是个新来的河川行者。人人都说卡哈妮的母亲是多么了不起的领袖，但我从没机会在她手下训练过。\n\n有时候我真担心，其他人信任卡哈妮只是因为她的出身。我对她还没那么大信心。', '', 66384),
(306579, 'zhCN', '', '我就知道卡哈妮能解决我们的螃蟹危机！她必须做到，不只是为了她的人民，也是为了家族的荣耀。\n\n她母亲非常非常在乎她……要是她能看到卡哈妮现在的样子？她一定会骄傲的，但我知道她绝不会惊讶。\n\n她一直都相信卡哈妮，就像我一样。', 66384),
(306578, 'zhCN', '', '眼下的日子的确不好过，但我相信卡哈妮！她的家族统领我们河川行者已经好几代了，她母亲更是我们有史以来最出色的领袖之一。\n\n我知道她一定能带我们渡过难关。', 66384),
(306556, 'zhCN', '听你老师的话。或者不听。我期待着吞噬你的本质。', '', 66384),
(306546, 'zhCN', '这场冲突代价高昂，但我掌管着账本，由我来决定何时付款、付给谁。', '', 66384),
(306480, 'zhCN', '', '父亲！她就是那个性子。你要是再敢这么说你的孙女，我就把热汤浇你头上。', 66384),
(306467, 'zhCN', '她走了也好。她不像她姐姐，野得很，对长辈没半点尊敬。', '', 66384),
(306455, 'zhCN', '这些多曼纳尔倒是成了不像盟友的盟友。他们大多都吃过萨拉塔斯的亏，或者有着她满足不了的野心。\n\n呵，敌人的敌人，姑且算是朋友吧。', '', 66384),
(306447, 'zhCN', '真遗憾。我真心希望这次不必再重蹈覆辙了。', '', 66384),
(306441, 'zhCN', '你们艾泽拉斯人来得正是时候。萨拉塔斯的出现彻底颠覆了我们的阶级秩序。\n\n从前，多曼纳尔仅凭力量与智谋便能功成名就，现在却要我们对她效忠和屈从。真是令人作呕。\n\n那些向萨拉塔斯屈服的多曼纳尔不配活着。杀光他们，抢走他们的财宝。', '', 66384),
(306412, 'zhCN', '我就知道你能行，但看你做事真是赏心悦目。', '', 66384),
(306410, 'zhCN', '仓促行动往往得不偿失……', '', 66384),
(306408, 'zhCN', '技艺高超的猎手，不管碰上多少陷阱都能轻松解除。', '', 66384),
(306406, 'zhCN', '水晶对你的触碰产生了积极反应。我记下了。', '', 66384),
(306377, 'zhCN', '', '远行者？不会吧？他为什么那么瞧得起那些浑身是泥的粗野家伙？我真是搞不懂……', 66384),
(306263, 'zhCN', '', '娜科泰克，你平安归来真是太好了！你先回望台去帮忙分发食物吧。', 66384),
(306262, 'zhCN', '', '我们上游的陷阱全被虚空堵塞了！我刚想清理一个，还没来得及动手，那只疯螃蟹就扑向了我！', 66384),
(306260, 'zhCN', '', '卡格拉真有意思——他为了讨好我都快把自己绊倒了，其实他根本用不着那样！\n\n我之前都没意识到他这么在乎我。能和他一起去庆典，我真挺期待的！\n\n<娜玛姬停顿了一下。>\n\n我知道扎卡希肯定很失望。我回头会跟他聊聊，谢谢他送我的漂亮头饰。希望他也能找到人一起去庆典！', 66384),
(306259, 'zhCN', '', '扎卡希好像很高兴我要和他一起去庆典，我也很期待呢！\n\n我从不知道扎卡希也能这么体贴。这头饰真漂亮——去庆典的时候我一定戴着！\n\n<娜玛姬停顿了一下。>\n\n我知道卡格拉肯定很失望。我回头会跟他聊聊，谢谢他送我的漂亮项链。希望他也能找到人一起去庆典！', 66384),
(306258, 'zhCN', '趁我们还没损失更多的子嗣，快消灭阿兹凯尔，$n。', '', 66384),
(306244, 'zhCN', '这儿几乎没螃蟹了！而且看起来都有点……病恹恹的？不过，总比什么都没有强！', '', 66384),
(306243, 'zhCN', '', '特纳吉，请把这些篮子送到望台去，娜科泰克负责侦察纳洛拉克之匿。记住，要让孩子和老人先吃！', 66384),
(306239, 'zhCN', '卡哈妮刚接手这份工作，肯定需要各种帮助。', '', 66384),
(306237, 'zhCN', '', '卡格拉！谢谢你的项链！我很乐意和你一起去庆典！', 66384),
(306236, 'zhCN', '', '扎卡希！谢谢你的头饰！我很乐意和你一起去庆典！', 66384),
(306227, 'zhCN', '我叫萨曼。我们这儿正缺个驯兽的好手。', '', 66384),
(306212, 'zhCN', '你八成能在北边的花园里找到她。不过我得提醒你，蒂芙可滑头得很。', '', 66384),
(306206, 'zhCN', '我是年轻一代阿曼尼战士里最强的！很快，我就能加入真正的战士行列，去保护我们的族人了。\n\n不过我会想念我的朋友——娜玛姬和卡格拉的。我们一直互相照应。以后不能时时刻刻跟他们在一起，感觉会很怪。', '', 66384),
(306205, 'zhCN', '蒂芙开心地啾啾叫。', '', 66384),
(306204, 'zhCN', '<这里发生过打斗。看起来像是薯身蟾在同类相残。>', '<这里发生过打斗。看起来像是薯身蟾在同类相残。>', 66384),
(306203, 'zhCN', '看来蒂芙只是需要活动活动筋骨。对不对啊，小姑娘？', '', 66384),
(306202, 'zhCN', '谁，玛洛？算是吧。\n\n我们逃离阿塔阿曼的时候，我在森林里发现了它。它当时吓坏了，我就把它抱起来了。\n\n我把它带到这儿喂养，还以为它会回森林去呢，结果它没走。\n\n看见这卷轴没？上面写着怎么好好照料山猫。既然它打算赖在这儿，我就得好好照顾它。\n\n你想摸摸它也行，它可喜欢被摸了！当然，只是在它乐意的时候。', '', 66384),
(306165, 'zhCN', '<卡格拉从卷轴上抬起头。>\n\n其他年轻的阿曼尼都取笑我，因为我不是战士的料。我不够强壮，也不够快，看见血还会反胃。\n\n不过娜玛姬和扎卡希不在乎这些，我们从小就是好朋友。\n\n我也许当不了战士，但我脑子好使。说不定有一天，我能成为一名神灵代言人呢！', '', 66384),
(306164, 'zhCN', '', '到村外和我汇合，我有种不祥的预感。', 66384),
(306163, 'zhCN', '', '芬加拉村从来不会这么安静，一定是出事了。', 66384),
(306160, 'zhCN', '<这些踪迹似乎是那生物留下的。它们一路延伸向侵蚀区域的深处。>', '<这些踪迹似乎是那生物留下的。它们一路延伸向侵蚀区域的深处。>', 66384),
(306148, 'zhCN', '你可算来了。阿曼尼狩猎大师还没露面。\n\n那这儿就只剩我俩了。打了这么久，你肯定累坏了吧，嗯？\n\n<你一眼就瞅见凯尔沃卓正慢吞吞地去摸他的武器，显然以为你没发现。>', '', 66384),
(306146, 'zhCN', '有什么需要吗？', '', 66384),
(306145, 'zhCN', '你要找祖尔加拉谈谈吗？', '', 66384),
(306137, 'zhCN', '', '维迪奥斯的抵抗不过是螳臂当车。你将助我扫清障碍，确立我的统治。\n\n立刻出击！进入战争模式，去收拾掉那些以他之名作战的代理人。', 66384),
(306122, 'zhCN', '兹尔丹居然有胆子跟我作对。我才是屠戮者高地天命所归的统治者。\n\n她放肆的日子到头了。进入战争模式，去收拾掉那些为她卖命的代理人。', '', 66384),
(306100, 'zhCN', '骚乱发生的地点离侵蚀繁花太近了，极其危险。', '', 66384),
(305956, 'zhCN', '', '总算有了一把足够锋利的爪子，合用。', 66384),
(305948, 'zhCN', '', '这里的事完成了。我们把这些材料带回去给阿莱利吧。', 66384),
(305938, 'zhCN', '', '灯笼的力量已经满溢，不住地嗡鸣。', 66384),
(305905, 'zhCN', '母亲永远不会给我犯错的机会。', '', 66384),
(305901, 'zhCN', '', '留神你在水下能憋多久气，可别淹死了！', 66384),
(305892, 'zhCN', '', '就快够了，$n。只要再从几个生物身上收集能量就行。', 66384),
(305891, 'zhCN', '', '这些生物非常强大！我们收集到的能量越来越多了。', 66384),
(305890, 'zhCN', '', '我能感到虚空能量正源源不断地汇入这盏提灯，$n。', 66384),
(305889, 'zhCN', '那家伙块头巨大，是我见过最大的鱼人了。难道是……神灵？我可不敢下去一探究竟！', '', 66384),
(305888, 'zhCN', '在你探索这片土地时，多留意那些未受污染的样本。这里有太多值得我们学习的东西。', '', 66384),
(305887, 'zhCN', '你感觉到了吗？那股若有若无的……饥饿的脉动。', '', 66384),
(305886, 'zhCN', '多加小心，$p！', '', 66384),
(305881, 'zhCN', '外来者！有空吗？', '', 66384),
(305867, 'zhCN', '嘘！能跟你说句话吗？', '', 66384),
(305855, 'zhCN', '眼睛放亮点，伙计。找宠物可不是件容易事。', '', 66384),
(305818, 'zhCN', '', '首领是个蜃鱼人？真有意思……\n\n我的印象里，蜃鱼人应该只待在黑暗深处，并且憎恨光明才对。这一只怎么会离地表这么近？\n\n而且它似乎还教会了它麾下的鱼人使用通灵魔法，这种行为简直闻所未闻。\n\n这仅仅是一次孤立事件吗？还是说蜃鱼人正在策划着更险恶的阴谋？\n\n<你感觉助手噶格噶格正望着远方出神，但他那套鱼人服的眼珠根本不会动，所以也无从判断。>', 66384),
(305809, 'zhCN', '<国王姆嘎姆嘎压低了声音，悄声说道：>\n\n看来我得在这儿困上一阵子了。但这戏我能演多久？总不能永远待在这儿吧，非得饿死不可！\n\n总有一天他们会发现我是吃素的。要是他们发现我根本不是鱼人该怎么办？或者……他们要是学我的样。\n\n鱼人主要是吃肉的，学我吃素对它们的健康是毁灭性的打击！\n\n<国王姆嘎姆嘎的声音透着焦虑，但他身上那套鱼人服却毫无表情，两只眼睛还分别瞅着不同的方向，直勾勾地盯着你。>\n\n也罢，我正好可以利用这个机会近距离研究鱼人。或许我可以给他们一些指引……然后说服他们，身为鱼人之神，我必须离开去帮助其他部族！', '', 66384),
(305791, 'zhCN', '', '我们失败了……', 66384),
(305790, 'zhCN', '', '（倒吸气）', 66384),
(305789, 'zhCN', '', '（喘息）', 66384),
(305788, 'zhCN', '', '（尖叫）', 66384),
(305787, 'zhCN', '', '（大喊）', 66384),
(305786, 'zhCN', '', '（呻吟）', 66384),
(305785, 'zhCN', '', '（粗重地喘息）', 66384),
(305784, 'zhCN', '', '（呻吟）', 66384),
(305783, 'zhCN', '', '我不想让你们看见……', 66384),
(305782, 'zhCN', '', '而你会将他拖入黑暗。', 66384),
(305780, 'zhCN', '', '他会看清你是个怪物。', 66384),
(305779, 'zhCN', '', '（呻吟）', 66384),
(305774, 'zhCN', '这里的景色美得令人窒息。我还是个小幼苗的时候就常来这儿了。从这儿能俯瞰整个哈籁恩达尔，看尽它的美好与丑陋，严酷与温柔。\n\n连甘尼都喜欢这儿，所以我决定把这里当成我的家。', '这里的景色美得令人窒息。我还是个小幼苗的时候就常来这儿了。从这儿能俯瞰整个哈籁恩达尔，看尽它的美好与丑陋，严酷与温柔。\n\n连甘尼都喜欢这儿，所以我决定把这里当成我的家。', 66384),
(305772, 'zhCN', '一件诡秘的多曼纳尔科技造物静置于你眼前，在虚空中发出轻柔的嗡鸣。', '一件诡秘的多曼纳尔科技造物静置于你眼前，在虚空中发出轻柔的嗡鸣。', 66384),
(305768, 'zhCN', '', '在阿曼尼帝国的全盛时期，我们本是同宗同源。但那是很久以前的事了，南方的恶齿部族后来选择了分道扬镳。\n\n听说他们甚至加入了部落，霸占了辛萨罗城。而这里的恶齿部族？我们依然誓死效忠阿曼尼。', 66384),
(305766, 'zhCN', '', '我背负断齿之名，深感自豪。', 66384),
(305760, 'zhCN', '<国王姆嘎姆嘎压低了声音，悄声说道：>\n\n只要我们能设法阻止深鳍鱼人的入侵，这些鱼人应该就会恢复和巨魔之间那种不情不愿但还算和平的共处状态。\n\n到那时，也就不再需要“鱼人之神”来保护他们了，我们就能脱身了！', '', 66384),
(305743, 'zhCN', '我已派遣我的勇士去消灭深渊之神！我们必将胜利！', '', 66384),
(305742, 'zhCN', '', '嗯……我在想……一个蜃鱼人？', 66384),
(305741, 'zhCN', '英雄回来了……是胜利归来，对吧？求你快点头吧，我在这儿站得腿都麻了。', '', 66384),
(305739, 'zhCN', '或者……还是算了！我想我还能再抽出几天时间陪陪你们……', '', 66384),
(305738, 'zhCN', '既然威胁已经解除，我必须离开你们了，我的孩子们！去吧，夺回你们的土地！', '', 66384),
(305737, 'zhCN', '凯旋的英雄！你消灭了深渊之神，证明了我，国王姆嘎姆嘎，才是真正的鱼人之神！', '', 66384),
(305734, 'zhCN', '<给深鳍鱼人首领的供品就在这儿。也许弄出点动静能把首领引出来？>', '<给深鳍鱼人首领的供品就在这儿。也许弄出点动静能把首领引出来？>', 66384),
(305620, 'zhCN', '看到点心，河鳞立刻站得笔直。', '', 66384),
(305612, 'zhCN', '终于……盘桓在这殿堂中的灵魂寻得了安宁。我希望有朝一日，我的姐妹们也能如此。而我……我会让音乐响彻这些大厅，直到她们回家。谢谢你们，勇士。', '', 66384),
(305562, 'zhCN', '', '世界之树滋养万物，赋予周围一切强健的生机。作为回报，我们必须悉心呵护它们。', 66384),
(305561, 'zhCN', '', '早在世界之树于哈籁恩达尔扎根之前，我们就已在此定居。', 66384),
(305559, 'zhCN', '<林莽爬行者舔了舔你的脸。>', '', 66384),
(305558, 'zhCN', '<河鳞忽略了你。>', '', 66384),
(305553, 'zhCN', '', '希望你在清除那些障碍时，能感受到我先祖世代传承的分量。', 66384),
(305552, 'zhCN', '', '你不仅在帮助维护世界之树的健康，更重要的是，你在遵循我们的传统。', 66384),
(305550, 'zhCN', '', '河鳞只是需要一个朋友帮他摆脱低落的情绪。谢谢你，$p。', 66384),
(305535, 'zhCN', '当你触碰这个箱子时，一股牵引力将你的心神引向了附近的几座高塔。', '当你触碰这个箱子时，一股牵引力将你的心神引向了附近的几座高塔。', 66384),
(305531, 'zhCN', '', '好好陪$p玩玩吧，河鳞！', 66384),
(305497, 'zhCN', '简直是暴殄天物。必须阻止这种影接行径。附近一定藏着个接体者。', '', 66384),
(305496, 'zhCN', '', '多么雄伟的野兽！竟被影接技术糟蹋成这样！', 66384),
(305482, 'zhCN', '见证吧！鱼人英雄凯旋归来了！', '', 66384),
(305481, 'zhCN', '', '万分感谢你找到了我，$n。也许很快我们就能继续研究了。\n\n前提是得先解决了这个，呃，洛阿的问题。', 66384),
(305480, 'zhCN', '毕竟，这样才更有戏可看嘛。\n\n密谋小径，这么说吧，是银月城一个见不得光的地界。那里龙蛇混杂，但是嘴巴很严，是潜行者和其他三教九流最常出没的地方。\n\n说来也巧，我跟这些不三不四的家伙处得相当融洽，主要是因为他们不但能酿出绝世美酒，谈天说地更是一绝。\n\n我和密谋小径里的一个“商人”组织交情匪浅。虽说他们算不上什么正规军，但可不容小觑——他们在暗处的功劳，可一点不比战场上的士兵们少。', '', 66384),
(305479, 'zhCN', '远行者是永歌森林边境的英勇守护者，没有谁比他们更熟悉这片森林。你或许已经知道，游侠将军在历史上一直是个声名显赫的头衔。\n\n别看他们总爱摆出一副超然物外、不屑权谋的姿态，但我可以跟你保证，他们和那些贵族们一样两面三刀。', '', 66384),
(305478, 'zhCN', '血骑士是我们的精灵战士。作为太阳眷顾的坚毅英雄与天命勇士，他们追随女伯爵莉亚德琳征战沙场，铲除辛多雷的敌人。\n\n他们的隐秘往事比我们所有人加起来都要多，但拿这个取笑他们可没意思。要我说，他们对自己那段不堪的过往还挺自豪的。', '', 66384),
(305477, 'zhCN', '魔导师是银月城最璀璨的明珠。他们是我们最智慧的学者、最精湛的奥术师和最老练的政治家，数百年的潜心钻研让他们的智慧如匕首般锋利。\n\n大法师罗曼斯统领着他们，但赢得他们的敬意千金难换。每个魔导师的自负比整个东部王国还大，而且从来没有两位魔导师能在任何事情上达成共识。', '', 66384),
(305476, 'zhCN', '', '谢谢，太谢谢了。我现在就过去！', 66384),
(305471, 'zhCN', '', '我是国王姆嘎姆嘎的助手！你可以叫我噶格噶格。\n\n因为我对鱼人很感兴趣，所以被派来协助大王进行研究。这其实还是我的第一个任务呢！\n\n当然啦，为了不暴露身份，我也得穿上鱼人服。你简直没法想象一个牛头人塞进这种衣服里有多费劲——我连拉链都几乎拉不到头！', 66384),
(305468, 'zhCN', '', '感谢大地母亲！你知道国王姆嘎姆嘎在哪儿吗？\n\n我们当时躲在一个小废墟里观察当地鱼人，但我去侦察深鳍鱼人的时候被发现了，然后被追得到处跑！\n\n等我回到营地，大王不见了，那片地方已经被入侵的鱼人占领了！\n\n最后为了保命，我只好躲到这里来。你知道他去哪儿了吗？他是不是被抓了？', 66384),
(305467, 'zhCN', '', '帮我们除掉那个该死的畜生。我会照看幸存者，护他们周全。', 66384),
(305460, 'zhCN', '', '效果很好。', 66384),
(305459, 'zhCN', '是的，你在那方面太熟练了。你就不能把你那把长柄武器收起来吗？真的很碍眼。', '', 66384),
(305458, 'zhCN', '', '还是偏爱双刃吗，维迪奥斯？我倒更怀念偏转你那根旧法杖魔法的感觉。', 66384),
(305456, 'zhCN', '', '当然有，而且态度相当坚决。你想亲眼看看结局如何吗？', 66384),
(305450, 'zhCN', '<从这些纸张散落的位置和周围的脚印来看，有人曾匆忙逃离，身后还有多个鱼人追赶。>\n\n看来攻击当地鱼人只是深鳍鱼人（我刚知道它们叫这名字）计划的一部分，他们的另一个目标是阿塔阿巴希的陵墓。\n\n深鳍鱼人展现出了在鱼人中前所未见的通灵法术力量——他们竟然能将巨魔遗骸复活成活动的亡灵！他们是从哪儿学到这种力量的？也许是从附近的邪枝巨魔那里？\n\n无论如何，这绝非一次随意的袭击。深鳍鱼人似乎在组建一支亡灵大军。至于目的何在，我也只能猜测。\n\n<脚印向西北方向延伸而去。>', '<从这些纸张散落的位置和周围的脚印来看，有人曾匆忙逃离，身后还有多个鱼人追赶。>\n\n看来攻击当地鱼人只是深鳍鱼人（我刚知道它们叫这名字）计划的一部分，他们的另一个目标是阿塔阿巴希的陵墓。\n\n深鳍鱼人展现出了在鱼人中前所未见的通灵法术力量——他们竟然能将巨魔遗骸复活成活动的亡灵！他们是从哪儿学到这种力量的？也许是从附近的邪枝巨魔那里？\n\n无论如何，这绝非一次随意的袭击。深鳍鱼人似乎在组建一支亡灵大军。至于目的何在，我也只能猜测。\n\n<脚印向西北方向延伸而去。>', 66384),
(305442, 'zhCN', '虚空在召唤……\n\n我必须吞噬，必须啃食，必须饱餐。\n\n为奴并不能将我从无尽的饥渴中解放，它只是“解放”了我，让我不必再为吞噬你的欲望而烦恼。\n\n既然主人的枷锁让我无法当场将你吞噬，那我只能为主人“调制饮品”了。\n\n离我远点，让我独自痛苦吧。', '', 66384),
(305439, 'zhCN', '<看这背包的样子，像是在打斗中被丢下的。\n\n打开一看，里面是旅行者常带的东西——口粮、衣物和一些纸张。你拿出其中一张纸。>\n\n国王姆嘎姆嘎和我当时正在悄悄观察这一地区的鱼人，突然，一个完全不同的深海鱼人部族从海里冒了出来。他们开始野蛮地攻击当地鱼人，并把他们拖进了海里。真不敢想他们会落得什么下场。\n\n我还注意到，这些入侵者对该地区的巨魔废墟表现出极大的兴趣。我打算偷偷靠近些，看看他们在捣鼓什么。', '<看这背包的样子，像是在打斗中被丢下的。\n\n打开一看，里面是旅行者常带的东西——口粮、衣物和一些纸张。你拿出其中一张纸。>\n\n国王姆嘎姆嘎和我当时正在悄悄观察这一地区的鱼人，突然，一个完全不同的深海鱼人部族从海里冒了出来。他们开始野蛮地攻击当地鱼人，并把他们拖进了海里。真不敢想他们会落得什么下场。\n\n我还注意到，这些入侵者对该地区的巨魔废墟表现出极大的兴趣。我打算偷偷靠近些，看看他们在捣鼓什么。', 66384),
(305434, 'zhCN', '我听说母亲去世了。这个$rl是？', '', 66384),
(305433, 'zhCN', '嗯。装备精良，架势尚可，自身技艺也算娴熟。\n\n你绝对是个完美的跟班材料！\n\n可惜，自从上次醉醺醺的牛头人、魔力宝典和卡德加的轮椅搞出那档子闹剧后，我就被禁止在奥术秘社签订契约了。\n\n要是你想当个随用随扔的炮灰，等到了外面再去找我吧。到时候我应该就能再签约了。', '', 66384),
(305431, 'zhCN', '然后好让那些玩弄圣光的狂热者在背后捅我一刀？一次教训还不够吗？\n\n听着，我是被天灾感染过，但最终夺走我性命的可是圣骑士的利刃。我可不想再体验一次了。\n\n我本想说服马瑞斯去跟那些吞噬虚空的猎手们学习几招，这样当那些先锋军想抓我时，我们还能施展些新把戏。\n\n总之，多谢你上次出手相助。我欠你一杯。', '', 66384),
(305428, 'zhCN', '哦，是你啊。\n\n要是你想找我去猎杀恶魔或寻找邪能圣物，就免开尊口了。我正在休假。\n\n这位工作狂马瑞斯先生需要痛饮一番，而我也得喂饱我的心魔——无论是字面还是隐喻上。\n\n自燃烧军团溃败以来，我们已经击杀、俘虏或囚禁了整整一百一十五个恶魔。\n\n我们值得好好喝上几杯。', '', 66384),
(305426, 'zhCN', '这段……休憩时光……确实令人放松。\n\n甚至还颇有收获。\n\n我讨厌这种感觉。\n\n萨格拉斯虽被推翻，燃烧军团也只剩一副空壳，但它依然在暗处滋长。我们必须追猎它们，直到扭曲虚空的尽头，乃至更远之处。\n\n不过首先……特德正在给我介绍一种名为“刑台玉露”的酒。听起来邪门得很，我一定要尝一尝。', '', 66384),
(305419, 'zhCN', '', '谢谢你，$p，我可不想一个人干这事儿。', 66384),
(305403, 'zhCN', '不！既然你不接受我的力量，那你也休想得到我的知识！', '', 66384),
(305401, 'zhCN', '艾泽拉斯已被一场又一场连绵不绝的战火撕得支离破碎。这片荒凉的景象，难道也是我们的宿命吗？', '', 66384),
(305400, 'zhCN', '这里真的曾存在过辉煌的帝国吗？难道仅仅因为一个人对知识不计后果的狂热追求，就导致了它们的覆灭？', '', 66384),
(305399, 'zhCN', '然后无疑会沦为你意志的奴隶，是吗？不，你的知识将随你一同埋葬。', '', 66384),
(305397, 'zhCN', '如此多的谜团！这究竟是什么文字？多曼纳尔语？虚灵语？还是某种……更古老的东西？', '', 66384),
(305393, 'zhCN', '幽灵，与我们分享你的知识！指引我们找到你！', '', 66384),
(305390, 'zhCN', '这个法术只需片刻。幽灵，告诉我，这个世界——普雷德西亚，曾经孕育过智慧生命吗？', '', 66384),
(305387, 'zhCN', '你要是再问一遍，你的手指可就要少几根了。现在，滚回去干活，奴才。摆正你自己的位置。', '', 66384),
(305386, 'zhCN', '见证我的勇士吧！我已赐予他祝福，他将代表你们出战！', '', 66384),
(305377, 'zhCN', '迷路了。上次你或是你那可怜的同族来问的时候，我们也迷路了。\n\n不必忧虑，我们的黑暗领主自会指引我们前往最需要我们的地方。', '', 66384),
(305375, 'zhCN', '不是第一次，也不会是最后一次。我听说部落和联盟也是这副德行。', '', 66384),
(305374, 'zhCN', '', '所以，为了击败共同的敌人，我们必须再次暂时搁置仇恨。', 66384),
(305373, 'zhCN', '', '你这懦夫，竟然堕落到用影接环来强化你的部队！你和萨拉塔斯没什么两样！', 66384),
(305372, 'zhCN', '你竟敢提出——！啊，我明白了。我们被操纵了。还有另一个多曼纳尔在场。', '', 66384),
(305370, 'zhCN', '兹尔丹很快就会到。她无法抗拒与我交锋的机会。你拿的是什么？', '', 66384),
(305368, 'zhCN', '我会了！我在跳舞呢！', '', 66384),
(305365, 'zhCN', '我的格斗教官里卡里非要我们所有人都去上什么舞蹈课。说什么为了“纪律”啊、“协调性”啊，还有“战斗之舞”什么的。\n\n但我宁愿去任何地方也不想待在这儿。这整件事根本毫无意义。', '', 66384),
(305354, 'zhCN', '连你都会？……这不可能。我永远也学不会了。', '', 66384),
(305353, 'zhCN', '<国王姆嘎姆嘎压低了声音，凑近悄声说。>\n\n你可得帮帮我！\n\n我本来是来这儿研究祖阿曼鱼人的，但他们遭到了另一个部族的攻击。我出手保护了他们，结果他们就把我当成了他们的神明，或者洛阿什么的！\n\n我哪知道怎么当神啊！我穿着这身戏服，连怎么装鱼人都够呛！\n\n而且我敢肯定，作为一名研究员，这么做绝对是违反职业操守的大忌。', '', 66384),
(305351, 'zhCN', '欢迎来到我的王国，旅行者。愿和平与繁荣与你同在！', '', 66384),
(305340, 'zhCN', '不，这不可能……你的武器终结了普雷德西亚所有的文明？你怎么能心安理得？你怎么还能苟存于世？', '', 66384),
(305321, 'zhCN', '我的帝国渴求一件能终结战争的武器。我如他们所愿。', '', 66384),
(305320, 'zhCN', '幽灵……你是阿金图安德？某种武器铸造师？', '', 66384),
(305307, 'zhCN', '坩埚里正咕嘟咕嘟冒着泡，煮着一锅臭气熏天的玩意儿。', '坩埚里正咕嘟咕嘟冒着泡，煮着一锅臭气熏天的玩意儿。', 66384),
(305247, 'zhCN', '这块石板是你刻的吗，幽灵？你的人民……你的文明……都在战火中陨灭了吗？', '', 66384),
(305229, 'zhCN', '也许吧。既然身在此地，无论如何，我都会竭尽所能侍奉圣光。\n\n只是我仍然好奇，为何我没有蒙受召唤。', '', 66384),
(305228, 'zhCN', '这确实是个……令人欣慰的可能性，也许是真的。相信这一点确实令人安心。\n\n但我无从确定。既然无法确定，我的道路便很明确——无论如何，都要继续坚定地、虔诚地追寻圣光。', '', 66384),
(305077, 'zhCN', '', '想来下注玩玩？', 66384),
(305070, 'zhCN', '你会战斗。很好。\n\n我们就是要你战斗。继续战斗。为鲜血而战。为死亡而战。\n\n我们喜欢你。', '', 66384),
(305067, 'zhCN', '这里的情况……颇为复杂。\n\n在屠戮者高地有三股多曼纳尔势力在明争暗斗。他们及其部队似乎对与我们交战兴趣不大，反而更热衷于……利用我们来相互攻击。他们好像对部落和联盟之间的历史宿怨很着迷。\n\n不知何时起，出现了一些部落和联盟的流亡者。看来多曼纳尔搜罗了他们能找到的最仇恨、最嗜血的战士，正以观看其自相残杀为乐。\n\n<裂隙守卫塞雷蒙摇了摇头。>\n\n哪怕我们根本经不起这样的内耗。部落或联盟的官方代表绝不会纵容此事。在如此混乱的局势下，我甚至怀疑他们是否知情。\n\n有些仇恨，确实深入骨髓。', '', 66384),
(305062, 'zhCN', '只有强者才能生存。我的人民太过软弱。而我战胜了死亡本身！现在，你们将助我重生。', '', 66384),
(305061, 'zhCN', '唯有我那完美的武器，方能止息流血。', '', 66384),
(305014, 'zhCN', '你可以随时用这座祭坛祈祷。', '你可以随时用这座祭坛祈祷。', 66384),
(304995, 'zhCN', '某种力量正将这些野兽从自然栖息地引诱至侵蚀繁花的深处。我们绝不能让它们去壮大光绽的势力。', '', 66384),
(304994, 'zhCN', '萨拉塔斯已经从我们手中夺走了一座城市。我绝不会让他们再夺走第二座。', '萨拉塔斯已经从我们手中夺走了一座城市。我绝不会让他们再夺走第二座。', 66384),
(304993, 'zhCN', '有意思……我还以为听到谁在说话呢。想必是风声吧……', '有意思……我还以为听到谁在说话呢。想必是风声吧……', 66384),
(304992, 'zhCN', '我不听叛徒说话。', '我不听叛徒说话。', 66384),
(304990, 'zhCN', '部落轰炸塞拉摩时，我的朋友和亲人就在那里。我们不过是权宜下的盟友，仅此而已。', '部落轰炸塞拉摩时，我的朋友和亲人就在那里。我们不过是权宜下的盟友，仅此而已。', 66384),
(304988, 'zhCN', '我仍然能闻到你身上的邪能味。算你们走运，我们眼下有共同的敌人。', '我仍然能闻到你身上的邪能味。算你们走运，我们眼下有共同的敌人。', 66384),
(304987, 'zhCN', '我会为保卫银月城而战，但我永远不会忘记，你们是如何背叛我们、加入部落的。', '我会为保卫银月城而战，但我永远不会忘记，你们是如何背叛我们、加入部落的。', 66384),
(304985, 'zhCN', '背叛我们、加入部落，感觉如何？', '背叛我们、加入部落，感觉如何？', 66384),
(304984, 'zhCN', '村庄里住着被遗忘者，和巨魔缔结了条约，又与兽人和平共处。\n\n这已不是我离开时的那个奎尔萨拉斯了。但我仍会像任何奎尔萨拉斯儿女一样奋力保卫它。\n\n只是，这儿不再给我家的感觉了。', '村庄里住着被遗忘者，和巨魔缔结了条约，又与兽人和平共处。\n\n这已不是我离开时的那个奎尔萨拉斯了。但我仍会像任何奎尔萨拉斯儿女一样奋力保卫它。\n\n只是，这儿不再给我家的感觉了。', 66384),
(304983, 'zhCN', '我当初离开永歌森林，是为了让它免遭战火。\n\n如今我们回来，也是为了同样的原因。我只希望留守故土的人们能够理解，我们当初为何离开，如今又为何归来。', '我当初离开永歌森林，是为了让它免遭战火。\n\n如今我们回来，也是为了同样的原因。我只希望留守故土的人们能够理解，我们当初为何离开，如今又为何归来。', 66384),
(304982, 'zhCN', '我已经好多年没见过奎尔萨拉斯的树木了。\n\n我都快忘了它们在微风中歌唱的模样。', '我已经好多年没见过奎尔萨拉斯的树木了。\n\n我都快忘了它们在微风中歌唱的模样。', 66384),
(304975, 'zhCN', '有点意思，我还没听说过这种凡人食物呢。它像蛋糕吗？在我对艾泽拉斯手艺的研究中，糕点的制作最让我着迷。那么，你肯定很喜欢糕点，对吧？我们就当你是喜欢的吧。\n\n我享受各种味道：心碎、嫉妒、恐惧……\n\n<殆希莫斯轻哼着舔了舔嘴唇。>\n\n接下来呢？我想象不出你们凡人还会聊些什么琐碎话题。不如这样——\n\n说说你害怕什么？', '', 66384),
(304971, 'zhCN', '', '我们不该认定他们想攻击我们，佩尔娜。他们看起来倒像是需要帮助。', 66384),
(304930, 'zhCN', '', '我现在正忙，勇士。有什么要紧事吗？', 66384),
(304922, 'zhCN', '邪枝巨魔似乎在煮一锅汤。闻起来有很浓的肉味和草药味。', '邪枝巨魔似乎在煮一锅汤。闻起来有很浓的肉味和草药味。', 66384),
(304906, 'zhCN', '总比当初创造出那个暗影要好。它已经失控了，$p，而且会不断散播痛苦，直到我们终结它为止。', '', 66384),
(304901, 'zhCN', '去吧，我会维持裂隙开启。如果发生任何意外，我会立刻把你拉出来。', '', 66384),
(304900, 'zhCN', '那影子究竟是什么？你去问十二个裂隙行者，他们会给你二十四种答案。显形、暗影映像、幻觉——想要理解它们，就像是试图抓住自己的影子。\n\n你要是几周前问我，我会说我懂。我当时确信我能创造出一个。结果，我召唤出了某个……只知折磨与痛苦的东西。\n\n所以，回答你的问题就是：我不知道。我只想让它彻底消失。', '', 66384),
(304897, 'zhCN', '', '那小子需要看个示范。向他展示一下伟大的$c是如何起舞的！', 66384),
(304895, 'zhCN', '如果来这儿能给我算学分，那行吧。但我真看不出这跟跳舞有什么关系。', '', 66384),
(304894, 'zhCN', '等等，我好像感觉到那个节奏了。', '', 66384),
(304872, 'zhCN', '', '很久以前，一棵叫诺达希尔的树在魔法之水上扎了根。我们曾见证，它的根须刺穿大地。我们曾等候，它寻找着艾林哈籁之光——就像所有扎根于世的根须一样。\n\n当诺达希尔的根须抵达哈籁恩达尔时，也带来了那闪烁的甘霖。久而久之，涓涓细流汇聚成了你眼前的飞瀑与湖泊。\n\n欢迎来到哈库艾，陌生人。这里欢迎你。', 66384),
(304841, 'zhCN', '', '我需要你留在这里，蕾欧娜。拿着这个熏香，将它放置在平台四周的基点上。', 66384),
(304837, 'zhCN', '我很好奇他们在探险中可能会发现什么样的独特标本。', '', 66384),
(304827, 'zhCN', '', '我陪你一起去，$n。', 66384),
(304824, 'zhCN', '如果我们能聚集足够的能量来启动它们，这些多曼纳尔装置就能帮我们定位你的斥候。', '', 66384),
(304812, 'zhCN', '等等，我……我很抱歉。', '', 66384),
(304811, 'zhCN', '', '我和你一样只能靠猜，没准你猜得更准。我敢说，即便是经验最丰富的裂隙行者，接触过的奇异神器也没你多。\n\n我的建议是：坚定意志，驾驭虚空。用莱希卡斯的话说就是：瞄准，射击。', 66384),
(304809, 'zhCN', '', '大多数朗多雷都向往自由，可莱希卡斯简直是桀骜不驯。\n\n我可不喜欢为了抓他而擅离职守。要不是他枪法还不错，我早就开个传送门把他扔回泰洛古斯裂隙了。\n\n他最好别是在浪费我们的时间。', 66384),
(304789, 'zhCN', '哈拉希尔是个古老的村子。世世代代，我们都把艾林之尘碾成鲜艳的颜料，这颜料的色素本身就能封存记忆。哈籁恩达尔所有的历史，都是从这里启程，被铭刻于岩石的。\n\n不过近来，我们村子又添了项新荣耀。你们管那棵树叫阿梅达希尔，是吧？它的根须现在正朝摇篮这边伸过来。作为护根者，我的职责就是确保它们安然无恙，这关系到哈籁恩达尔所有生灵的福祉。', '', 66384),
(304782, 'zhCN', '<这具尸体刚死不久，光孢也是最近才扎根的。>', '<这具尸体刚死不久，光孢也是最近才扎根的。>', 66384),
(304754, 'zhCN', '你可以在法师区西北角那个大阳台上找到伊利达雷。索桑·裂厄者就是你要找的人。\n\n不过，可别说是我让你去的。', '你可以在法师区西北角那个大阳台上找到伊利达雷。索桑·裂厄者就是你要找的人。\n\n不过，可别说是我让你去的。', 66384),
(304740, 'zhCN', '', '不管你在外面做了什么，似乎都奏效了。', 66384),
(304644, 'zhCN', '是我母亲派你来的吗？\n\n告诉她我晚饭会准时回家。\n\n在那之前我还有重要的大事要办呢！', '', 66384),
(304641, 'zhCN', '这是我思考和观察的地方。\n\n如果你也是来干这个的，就自己另找个地方吧！', '', 66384),
(304602, 'zhCN', '', '他们也许是想求助，但他们的村子就在附近。这也可能是个陷阱。多加小心，$n。', 66384),
(304599, 'zhCN', '', '你居然真的在纳洛拉克的洞穴里活下来了。你比我想象的要强嘛。你有资格和我们共事。\n\n不过，你终究是个闯入者。', 66384),
(304597, 'zhCN', '', '尽管她故作冷漠，但我能感觉到，祖尔加拉的内心深处依然渴望着她的神灵终能现身。', 66384),
(304593, 'zhCN', '有所求，便会受欢迎，旅行者。\n\n我从未见过你这样的同类，或许是艾林哈籁将我们的命运交织在了一起？', '有所求，便会受欢迎，旅行者。\n\n我从未见过你这样的同类，或许是艾林哈籁将我们的命运交织在了一起？', 66384),
(304592, 'zhCN', '斯托玛兰不只是一座要塞，它是一个仪式场。吞噬军团在这里拿虚空做实验——主要是研究怎么杀我们的新法子。他们把这片空间弄得像旧船帆一样破败不堪。成百上千的小裂口和破洞只会随着时间推移而扩大。\n\n奇点就是最危险的裂痕。它们大到足以自我维系，吞噬物质和能量，然后喷射到其他地方。\n\n在稳定状态下，它们几乎可以当作传送门使用，虽说目的地不可预测。不幸的是，它们往往会变得不稳定并爆炸。\n\n我们有反制措施，但造价昂贵且只能维持一时。', '', 66384),
(304529, 'zhCN', '我成功了！呃，我是说，感谢你的教导，里卡里。您是位出色的老师。', '', 66384),
(304528, 'zhCN', '', '达拉克，你的表现令我刮目相看。恭喜你，士兵。', 66384),
(304523, 'zhCN', '', '到此为止。你们俩都干得不错。', 66384),
(304522, 'zhCN', '', '达拉克，让我见识见识你的本事！$n，使出全力！', 66384),
(304521, 'zhCN', '我和我的指挥官在楼上等你。希望你跟你看起来一样强！', '', 66384),
(304513, 'zhCN', '', '啊啊啊啊啊——！', 66384),
(304510, 'zhCN', '', '我知道我能行的。也许是你刚才给我鼓劲儿不够大声？', 66384),
(304509, 'zhCN', '', '少废话，波穆！', 66384),
(304508, 'zhCN', '都跟你说了吧！', '', 66384),
(304507, 'zhCN', '', '三——！', 66384),
(304505, 'zhCN', '', '好吧，一……二……', 66384),
(304504, 'zhCN', '', '是吧，$n？', 66384),
(304503, 'zhCN', '', '才……才不是！我现在有新朋友给我撑腰了！', 66384),
(304502, 'zhCN', '噢，我们的小安妮是不是又要打退堂鼓了？', '', 66384),
(304490, 'zhCN', '', '化生台能为物品注入强大力量，增强它们的效果，使它们的潜能发挥到前所未有的高度！', 66384),
(304489, 'zhCN', '', '何等壮观的景象，不是吗？\n\n自达斯雷玛时代起，精灵们便凭借这座巨型熔炉锻造出威能无匹的铠甲。相传，炉中的火焰最初由一只凤凰的灵魂点燃，它将此地视为安巢之所，其力量至今仍在每件造物中流转。\n\n我们准许你分享这份馈赠。', 66384),
(304488, 'zhCN', '我们成功了，$n。我成了一名真正的卡达尼，这一切都归功于你。\n\n但伴随庆典而来的，也有悲伤。这便是狩猎之道。猎物必须走向生命的终点，才能满足猎人的需求。\n\n猎人不应在杀戮中寻求快感。无论是纤弱的漂流者还是强大的猛兽，在狩猎之道面前都是平等的。\n\n至于拉杜尼，它的血肉将为我们提供一周的食粮与物资。我感谢这头强大猛兽的献身。', '我们成功了，$n。我成了一名真正的卡达尼，这一切都归功于你。\n\n但伴随庆典而来的，也有悲伤。这便是狩猎之道。猎物必须走向生命的终点，才能满足猎人的需求。\n\n猎人不应在杀戮中寻求快感。无论是纤弱的漂流者还是强大的猛兽，在狩猎之道面前都是平等的。\n\n至于拉杜尼，它的血肉将为我们提供一周的食粮与物资。我感谢这头强大猛兽的献身。', 66384),
(304487, 'zhCN', '', '这一切都透着不对劲。\n\n我在此地看到的一切，以及我从回响中研究出的种种线索，都将我的思绪引向一个真相：这座城市正在自我净化。\n\n在短短几十年间，阿塔阿曼不仅沦为玛拉卡斯黑暗魔法的牺牲品，遭受了莫尔杜恩那令人作呕的虚空之力，还要承受与我们洛阿神灵重连的冲击。\n\n现在它有了反应。它正要把所有的污秽一并吐出，就像个在烈焰节前夜贪吃太多甜莓的孩子。\n\n只不过，它呕吐出来的却是那些早已逝去的战士和冒险者的记忆……', 66384),
(304486, 'zhCN', '多鲁大概知道这些回响为何出现在此。那是出于一个非常具体、非常明确的理由。\n\n但你要是问我的看法，我觉得这是先祖想狠狠给我们当头一棒。\n\n我们从未正视过真相——当年我们就知道祖尔金和玛拉卡斯的所作所为有些不对劲。也许我们谁也说不清……但到头来，你能感觉到一股黑暗始终紧随着他们。', '', 66384),
(304457, 'zhCN', '', '千万小心！我还不清楚我们这次要对付的是什么。', 66384),
(304438, 'zhCN', '', '祝你被那东西弄死时“玩”得开心。', 66384),
(304437, 'zhCN', '', '哈哈！才不。它现在黏上你了，这可是“你”的麻烦。我溜了！', 66384),
(304436, 'zhCN', '', '<坎扎不敢与你对视。她目不转睛地盯着自己的脚，绞着双手。>', 66384),
(304435, 'zhCN', '', '我的家园一如既往地苍翠繁茂，生机勃勃。但哈籁提不能故步自封。\n\n我们必须守护女神的所有造物——不只是我们最熟悉的那些。', 66384),
(304434, 'zhCN', '', '我不觉得这方法能行。\n\n但它好歹不再追我了，所以……我就先接受了。', 66384),
(304429, 'zhCN', '', '老实说，它现在盯上你了，我可真是松了口气。我感觉力气正慢慢回来。', 66384),
(304428, 'zhCN', '我在这里的狩猎已经完成了。但在圆满结束之前，我还有一个地方需要造访。', '我在这里的狩猎已经完成了。但在圆满结束之前，我还有一个地方需要造访。', 66384),
(304427, 'zhCN', '', '哈！这话从这么个老头嘴里说出来，可真难让人当真啊！', 66384),
(304426, 'zhCN', '我们以性命起誓，必将让阿塔阿曼重现往日荣光！', '', 66384),
(304425, 'zhCN', '', '那个人……', 66384),
(304424, 'zhCN', '森林巨魔部族再次向你致谢，哈舒拉。', '', 66384),
(304423, 'zhCN', '我还得再找几样材料，稍后在哈拉希尔与你会合。', '我还得再找几样材料，稍后在哈拉希尔与你会合。', 66384),
(304422, 'zhCN', '狩猎进行得如何，$n？\n\n我正在为哈拉希尔的铁匠艾尔雅特收集藤蔓。按照传统，向大工匠求助时得送上礼物。\n\n鞭笞者的藤蔓既坚韧又罕见，可谓一蔓难求，相信艾尔雅特一定会对我们的贡品感到满意。', '狩猎进行得如何，$n？\n\n我正在为哈拉希尔的铁匠艾尔雅特收集藤蔓。按照传统，向大工匠求助时得送上礼物。\n\n鞭笞者的藤蔓既坚韧又罕见，可谓一蔓难求，相信艾尔雅特一定会对我们的贡品感到满意。', 66384),
(304419, 'zhCN', '', '把最好的那块肉放桌上，让里珊开始动手切割。', 66384),
(304413, 'zhCN', '', '我愿献上我的灵魂，魔导师。', 66384),
(304412, 'zhCN', '朗多雷如今四面受敌，我过去的学生。得知未来将有你，以及那些足够强大、能追随你的人守护我们，我深感欣慰。', '', 66384),
(304411, 'zhCN', '', '凭借这份力量，我就能训练更多族人追随我的脚步。', 66384),
(304410, 'zhCN', '', '是的，她成功了，乌布里克。伊利达雷的力量与决心，如今已是她不可分割的一部分。', 66384),
(304409, 'zhCN', '我感觉到瑞文诺尔的黑暗气息突然消失了。你成功了？', '', 66384),
(304408, 'zhCN', '', '如果你在这儿失败了，蕾欧娜，你就死定了。我可不会救你。', 66384),
(304404, 'zhCN', '', '就是现在，$n，转折点已经到来。', 66384),
(304403, 'zhCN', '请退后一些，我们需要一点施法的空间。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(304402, 'zhCN', '能被邀请到这种地方来可真不错！你尝过这儿的“狼人之发”了吗？那酒劲儿可真大！\n\n我们的旧旅行日志上又添了不少新内容。真得谢谢你帮我们结了那笔酒钱！', '', 66384),
(304401, 'zhCN', '吉德文和我只不过想找茬在这里痛快地打上一两次架，但我感觉这地方没有那种氛围。\n\n不过倒是能从这些老古董口中听到不少故事。啊，我可没有冒犯的意思。', '', 66384),
(304400, 'zhCN', '能被邀请到这种地方来可真不错！你尝过这儿的“狼人之发”了吗？那酒劲儿可真大！', '', 66384),
(304395, 'zhCN', '看到奥威娜的出身地后，很多事突然就说得通了。我太理解那种想要逃离某个地方，最后却又回到原点的感受。\n\n能来到这里，对我来说意义非凡。', '', 66384),
(304394, 'zhCN', '', '蒙特带我参观了他在安德麦的家，在那里，我与周围的人都大不一样。\n\n在这里，我想让他感受到自己也是受欢迎的。举手之劳而已。', 66384),
(304388, 'zhCN', '', '哈库艾是一个充满秘密和神话的村庄。虽然祖尔阿沙传承着我们的记忆，长老守护着我们的传统，但我们这些哭泣之根的族人最常敬畏的，还是女神造物中那些我们尚未完全理解的部分。', 66384),
(304375, 'zhCN', '科坦脸上兴奋的神情瞬间严肃起来。', '科坦脸上兴奋的神情瞬间严肃起来。', 66384),
(304373, 'zhCN', '拉杜尼死了。我们成功了！那头野兽终于被干掉了！', '拉杜尼死了。我们成功了！那头野兽终于被干掉了！', 66384),
(304372, 'zhCN', '', '我们本想悄无声息地速战速决，但鱼人们另有打算。', 66384),
(304342, 'zhCN', '但也教会了我们在伞盖中要坚强，那里有时候也挺吓人的。', '', 66384),
(304341, 'zhCN', '欣尼要谢谢$p，教会了我们在可怕的斗坑中勇敢战斗。', '', 66384),
(304339, 'zhCN', '而且孢子滑翔者就在水池边上。要是中途打起来，准能把它们扑通扑通全推下水！', '', 66384),
(304338, 'zhCN', '嘿，想回水池去吗？那儿很棒。暖洋洋的。还湿乎乎的！', '', 66384),
(304337, 'zhCN', '', '吞噬军团正在捕捉本地的野兽并加以改造，很可能是想把它们变成对付敌人的武器。我们必须小心。', 66384),
(304336, 'zhCN', '孢誓英雄，这简直是再好不过的选择，$p！', '', 66384),
(304335, 'zhCN', '孢誓，好名字。让我们更加努力。我们已经结下誓约了。', '', 66384),
(304334, 'zhCN', '盖世斗士就是最好的选择。伞盖就是我们最出色的部分！', '', 66384),
(304332, 'zhCN', '下次你一定能记住，这名字确实拗口。', '', 66384),
(304331, 'zhCN', '我们源自孢子，彼此立誓。我们就是最棒的团队！', '', 66384),
(304330, 'zhCN', '盖世斗士这个名字是为了纪念布拉科的伞盖。多帅气啊。', '', 66384),
(304328, 'zhCN', '', '我们到那儿见，$n。', 66384),
(304302, 'zhCN', '<当你将这些液体混合时，得到了一种冒着泡泡嘶嘶作响的制剂，你猜测它能溶解某种顽固的黏稠物质。>', '<当你将这些液体混合时，得到了一种冒着泡泡嘶嘶作响的制剂，看起来似乎什么都能溶解。>', 66384),
(304301, 'zhCN', '<混合后，这些液体迅速蒸发，什么也没剩下。>', '<混合后，这些液体迅速蒸发，什么也没剩下。>', 66384),
(304300, 'zhCN', '<混合物沉淀后，几种液体似乎相互中和，最终变成了一团没有任何效果的棕色黏液。毫无用处。>', '<混合物沉淀后，几种液体似乎相互中和，最终变成了一团没有任何效果的棕色黏液。毫无用处。>', 66384),
(304283, 'zhCN', '感激不尽，长老。我绝不会辜负您和$n的期望。', '感激不尽，长老。我绝不会辜负您和$n的期望。', 66384),
(304277, 'zhCN', '<这个花瓶看起来足够结实，应该能够盛放腐蚀性液体。>', '<这个花瓶看起来足够结实，应该能够盛放腐蚀性液体。>', 66384),
(304268, 'zhCN', '你有没有过极其渴望某样东西，却与获得它的机会擦肩而过？而且还不是因为你自己的错。\n\n<科坦抱臂叹息。>\n\n现在我也只能认命了。', '你有没有过极其渴望某样东西，却与获得它的机会擦肩而过？而且还不是因为你自己的错。\n\n<科坦抱臂叹息。>\n\n现在我也只能认命了。', 66384),
(304266, 'zhCN', '你好啊，陌生人。身为哈籁尼尔，你一定听说过卡达尼试炼吧？\n\n<科坦抱臂叹息。>\n\n这项试炼是哈拉希尔猎人加入精英猎人团体“卡达尼”的机会，每个周期只举办一次，而且必须找到一位愿意指导你的卡达尼成员才能参加。\n\n我本该是被选中的一员，但现在我得等到下一个周期了。', '你好啊，陌生人。身为哈籁尼尔，你一定听说过卡达尼试炼吧？\n\n<科坦抱臂叹息。>\n\n这项试炼是哈拉希尔猎人加入精英猎人团体“卡达尼”的机会，每个周期只举办一次，而且必须找到一位愿意指导你的卡达尼成员才能参加。\n\n我本该是被选中的一员，但现在我得等到下一个周期了。', 66384),
(304264, 'zhCN', '那种更适合在耳边低语，而不宜付梓刊印的诗。\n\n不过，这里是个讲规矩的地方。不必担心。', '', 66384),
(304261, 'zhCN', '是诗歌朗读会，$g先生:女士;。\n\n我们欢迎城里各处的诗人来此，与……同道中人分享他们的篇章。\n\n一首好诗，能发人深省，你说对吗？', '', 66384),
(304260, 'zhCN', '这株花蕾发育不良，因为它沐浴不到圣光。', '这株花蕾发育不良，因为它沐浴不到圣光。', 66384),
(304258, 'zhCN', '欢迎。书架上的东西请自便。\n\n如果想带走什么，我可以替你包好。', '', 66384),
(304254, 'zhCN', '虽然那些窃取了洛阿神灵力量的先祖曾让我们蒙羞，但你今天的努力或许能为他们带来荣耀。', '', 66384),
(304253, 'zhCN', '', '收起你的同情心，$n。', 66384),
(304252, 'zhCN', '就算从这里，我也能看到战局的天平正重新向我们倾斜。', '', 66384),
(304251, 'zhCN', '', '哈！我只记得当年一次又一次地，把你这个被打得鼻青脸肿的可怜虫从战场上拖回来。', 66384),
(304250, 'zhCN', '承认吧，多鲁。你就是喜欢这种追忆往昔的感觉。', '', 66384),
(304249, 'zhCN', '', '你回来了。很好。神殿的位置都守住了吗？', 66384),
(304248, 'zhCN', '保持警惕，$n。这些回响虽然很弱，但你如果放松警惕，还是会被它们团团包围的。', '', 66384),
(304236, 'zhCN', '', '我还想带你看看你另一个哈籁尼尔的传统。这边走，就在那些绘满壁画的墙壁处。', 66384),
(304232, 'zhCN', '', '来吧，让我们继续深入大巢穴。', 66384),
(304231, 'zhCN', '意思就是我们可以把它弄坏！', '', 66384),
(304230, 'zhCN', '', '这该不会是我想的那个意思吧？', 66384),
(304229, 'zhCN', '没错，孩子们。你们马上就能亲手拆解这台机甲的结构了！', '', 66384),
(304228, 'zhCN', '', '我们稍后就回来！蒙特，现在我有更多东西要给你看。', 66384),
(304219, 'zhCN', '', '……知道了，爸爸。', 66384),
(304218, 'zhCN', '下次可得自己找哦，听见没？', '', 66384),
(304217, 'zhCN', '', '哦，嗨！欢迎回来！都找齐了吗？', 66384),
(304216, 'zhCN', '安贾莉，快回来！$c好心的带着你的草药回来了。', '', 66384),
(304215, 'zhCN', '把功课做完再说。让我看看你学到了什么。', '', 66384),
(304214, 'zhCN', '', '可是爸爸，我想去和其他人玩！', 66384),
(304213, 'zhCN', '感谢你帮助这些学徒。', '', 66384),
(304212, 'zhCN', '神灵会通过那根图腾来出力。你只是在传递他们的力量。', '', 66384),
(304211, 'zhCN', '埃基尔松。凯旋之神。天空、狂风、暴雨与雷霆的主宰！', '', 66384),
(304210, 'zhCN', '哈尔拉兹。狩猎之神。敏捷、狡猾、耐心。无论在何处，无论追捕何种猎物，他都是完美的猎手。', '', 66384),
(304209, 'zhCN', '', '加亚莱。烈火之神。魔法与万灵体内之火的主宰。', 66384),
(304208, 'zhCN', '', '纳洛拉克，战争之神。既顽固又严酷，但对他虔诚的信徒却忠心不二。', 66384),
(304207, 'zhCN', '每一笔落下，我都画入了决心与希望……还有一点你分享给我的感悟。', '', 66384),
(304206, 'zhCN', '没有你的帮助，我绝不可能完成这件事。正是你的善意，让我重新找回了自我。', '', 66384),
(304200, 'zhCN', '在你的照料下，这些材料或许能重获生机……而不是像我那样只带来毁灭。', '', 66384),
(304199, 'zhCN', '信任对我来说很难接受……但你展现了真正的温柔。', '', 66384),
(304197, 'zhCN', '我辜负了所有人，最愧对的是我自己。然而你挺身而出，让一切重回正轨。谢谢你。', '', 66384),
(304195, 'zhCN', '', '你能来看看我们真是太好了。\n\n这事儿可有意思了。你看，我当时正带着这个生物去调查其他类似的虚空干扰事件。结果它反倒吸引了其他生物过来研究它！我觉得它们相当好奇。\n\n当然也可能它们心怀恶意，想互相吞噬——这点我还在调查。\n\n我可能无意中发现了一个驱除灵异现象的赚钱门道，虽然我的本意只是想研究一下。\n\n很快我就能收集到一整套这类生物了。我得找个合适的地方把它们全都安置好！', 66384),
(304191, 'zhCN', '', '我研究各种稀奇古怪的虚空现象。我最喜欢解开谜团了。', 66384),
(304159, 'zhCN', '安贾莉，等等，这些该你自己动手！……又偷懒。', '', 66384),
(304150, 'zhCN', '', '村子周围就能找到草药！好啦，谢谢，再见！', 66384),
(304143, 'zhCN', '', '准备好就去挑战她吧。', 66384),
(304110, 'zhCN', '$n，这边。', '', 66384),
(304060, 'zhCN', '', '我这就去找他。你去伊姆哈约那里看看能不能找到比地精更讨纳胡特欢心的玩意儿。', 66384),
(304059, 'zhCN', '真是奇了怪了！我压根不知道这是怎么回事。', '', 66384),
(304058, 'zhCN', '嘿，库德兰，$p来了。他带那么多斧头干嘛？', '', 66384),
(304056, 'zhCN', '<这捆木板和绳索似乎是恶齿蟹笼的残骸。\n\n上面布满了巨大的爪痕，显然是被人蓄意而猛烈地撕成了碎片。被毁坏的虚空神器碎片也深深嵌在木头里。\n\n虽然这些碎片看来是顺流漂下的，显得杂乱无章，但河水并未冲走上面的污秽：碎片已经让木头完全浸透了虚空。>', '', 66384),
(304047, 'zhCN', '<螃蟹的尸体散落一地。有些肢体被撕扯下来，有些则被某种巨大的东西碾碎了……像是下颚？还是爪子？\n\n伤口中残留着虚空神器的碎片，虚空能量的痕迹从尸体中脉动而出。>', '', 66384),
(304005, 'zhCN', '', '那个陷阱应该能困住它。', 66384),
(304002, 'zhCN', '', '走吧，金克斯。我们离开这儿！', 66384),
(304001, 'zhCN', '<这只蜥蜴的头骨被一块石头精准地砸塌了。>', '<这只蜥蜴的头骨被一块石头精准地砸塌了。>', 66384),
(304000, 'zhCN', '暗松部族让我去跟阿曼尼巨魔谈话时当代表，但我没把自己当成什么领袖。', '', 66384),
(303999, 'zhCN', '', '我知道！', 66384),
(303997, 'zhCN', '<虽然只是过往的回响，但这副铁砧依然可以使用。>', '<虽然只是过往的回响，但这副铁砧依然可以使用。>', 66384),
(303996, 'zhCN', '', '哇，你好勇敢！', 66384),
(303994, 'zhCN', '', '我拿起这块大石头，正好砸中了它的眼睛！', 66384),
(303993, 'zhCN', '哇哦！', '', 66384),
(303990, 'zhCN', '', '就像这样。砰！', 66384),
(303989, 'zhCN', '', '那你后来怎么做的，安妮？', 66384),
(303988, 'zhCN', '', '然后它就朝我扑过来了！', 66384),
(303986, 'zhCN', '', '枯木巨魔的英魂永垂不朽！我在迈萨拉洞窟等你。', 66384),
(303974, 'zhCN', '这些回响弱得跟小水豚似的！正好给我的战士们当练手的靶子！', '', 66384),
(303973, 'zhCN', '感谢这些补给。特别是我们的战士在搜寻和保护巨鹰时受了不少伤。', '', 66384),
(303972, 'zhCN', '多鲁和老沧桑那边有什么消息？', '', 66384),
(303970, 'zhCN', '无穷无尽的敌军？哈哈！这可是磨炼技艺的大好机会！', '', 66384),
(303969, 'zhCN', '', '这是一场对抗历史的狩猎。你要加入我们吗，哈舒拉？', 66384),
(303968, 'zhCN', '', '多鲁来得正是时候。我们萨满祭司的补给快用完了。', 66384),
(303966, 'zhCN', '', '谢谢你，哈舒拉。也请替我们向多鲁转达谢意。', 66384),
(303963, 'zhCN', '', '愿烈焰护佑你，哈舒拉。', 66384),
(303954, 'zhCN', '你必须……阻止我。', '', 66384),
(303925, 'zhCN', '我女儿在培育草药和调制配方方面天赋异禀，可就是定不下心来，哪怕这关系到她的性命。\n\n眼下这世道疯成这样，我担心这种态度早晚会害了她。\n\n我不想对她太严厉，但是……这些技能她必须掌握。我们制作的药膏和药水可都是用来救命的东西啊。', '', 66384),
(303923, 'zhCN', '我毕生所求，不过是为保卫家园而战的荣耀。\n\n对了，最好再来把帅气的长矛。', '', 66384),
(303911, 'zhCN', '', '我原以为当个药剂师会很有意思，毕竟我喜欢照料植物。\n\n但没想到这活儿比想象中累得多。', 66384),
(303910, 'zhCN', '即便是我这把老骨头，也能从神灵代言人那儿学到很多。\n\n我打打杀杀的日子已经过去了，但还有其他方式能让我亲近神灵。', '', 66384),
(303904, 'zhCN', '', '达拉克的热情最初让我有些担忧。好斗过头的战士往往会太过鲁莽，缺乏成为真正强者所需的自律。\n\n但他的表现出乎意料。总是第一个到场，最后一个离开。提的问题都很关键，训练也比我的其他学生更加刻苦。\n\n要说谁最令我刮目相看，非他莫属。这一点连我自己都感到惊讶。', 66384),
(303902, 'zhCN', '', '情况有变。', 66384),
(303901, 'zhCN', '', '我才不跟血精灵说话，闯入者。滚开。', 66384),
(303898, 'zhCN', '', '见过暮光之刃没？嘁。我一个人就能摆平他们。我见过的世面多了。他们跟血精灵根本没法比。\n\n我爸爸教我使斧头。谁敢动阿曼尼的地盘，我就砍了谁！', 66384),
(303897, 'zhCN', '', '我老是梦见我变成一条蛇。我讨厌蛇。我晚上再也不想睡觉了。', 66384),
(303895, 'zhCN', '', '我看到一个纳尔丁！它从河边村子旁路过，但我哥哥非说是我瞎编的。我才没撒谎！', 66384),
(303893, 'zhCN', '', '你平常就穿成这样？你穿过靴子吗？我觉得靴子看起来傻乎乎的。', 66384),
(303892, 'zhCN', '', '有只鸟叼走了我的弓！我本想好好练习，这样就能帮妈妈打仗，让她早点回家了。我好想她！', 66384),
(303891, 'zhCN', '', '嘎啊啊！吓着你没？我爸爸说我的吼声很像纳洛拉克！', 66384),
(303890, 'zhCN', '', '爸爸说待会儿有大餐吃！你来吗？小孩先吃，不过你可以排我后面。', 66384),
(303887, 'zhCN', '', '村里来了好多阿曼尼巨魔，我得跟我妹妹挤一张床。烦死了！', 66384),
(303885, 'zhCN', '', '我妈妈说不准跟外来者说话。对不起。', 66384),
(303870, 'zhCN', '', '后退！', 66384),
(303869, 'zhCN', '', '你还在等什么？快去！\n\n<她脚下的地面已被鲜血浸透。她试图止血，但根本没用。>\n\n我们俩都已经无能为力了。这世上有些东西，连圣光也无法修复。', 66384),
(303860, 'zhCN', '', '等我给你示范一下怎么做，或许你就可以试试了！', 66384),
(303856, 'zhCN', '', '你好呀！你带吃的了吗？\n\n我饿了。', 66384),
(303846, 'zhCN', '干得漂亮。看你战斗总能让人热血沸腾。\n\n真为你朋友感到遗憾。为什么小光人总是这么急于牺牲自己呢？', '', 66384),
(303844, 'zhCN', '啊，一支小光人大军对抗无尽的虚空大群。我很乐意观赏这场好戏。', '', 66384),
(303825, 'zhCN', '', '消灭影卫我没意见。好好观察一下被标记后，那些尸体会发生什么。', 66384),
(303823, 'zhCN', '<这具尸体似乎覆盖着光绽孢子。>', '<这具尸体似乎覆盖着光绽孢子。>', 66384),
(303816, 'zhCN', '若要证明你的价值，就前往各个神灵圣地，从那些古代伟大战士的最后安息之地取回四枚信物。', '若要证明你的价值，就前往各个神灵圣地，从那些古代伟大战士的最后安息之地取回四枚信物。', 66384),
(303814, 'zhCN', '<女猎人之灵庄重行礼，已为下一次狩猎做好了准备，这将是人生伟大征途中的又一个篇章。>', '<女猎人之灵庄重行礼，已为下一次狩猎做好了准备，这将是人生伟大征途中的又一个篇章。>', 66384),
(303813, 'zhCN', '<孩童之灵舒展着肢体，宛如从漫长的睡梦中苏醒，随后茫然地眨着眼睛，打量着四周陌生的环境。但当看到你的那一刻，脸上绽放出明媚的笑容。>', '<孩童之灵舒展着肢体，宛如从漫长的睡梦中苏醒，随后茫然地眨着眼睛，打量着四周陌生的环境。但当看到你的那一刻，脸上绽放出明媚的笑容。>', 66384),
(303812, 'zhCN', '纳鲁因我们而死！', '', 66384),
(303811, 'zhCN', '这头畜生还脱缰了！', '', 66384),
(303788, 'zhCN', '重获新生。', '重获新生。', 66384),
(303787, 'zhCN', '直至死亡。', '直至死亡。', 66384),
(303786, 'zhCN', '始于生命。', '始于生命。', 66384),
(303785, 'zhCN', '感悟女神。', '感悟女神。', 66384),
(303784, 'zhCN', '踏上征程。', '踏上征程。', 66384),
(303783, 'zhCN', '始于微末。', '始于微末。', 66384),
(303773, 'zhCN', '', '果然。', 66384),
(303772, 'zhCN', '', '瓦莉拉叹了一口气。', 66384),
(303770, 'zhCN', '你好啊，年轻人。你是需要寄存宠物，还是在寻找走失的伙伴？', '你好啊，年轻人。你是需要寄存宠物，还是在寻找走失的伙伴？', 66384),
(303769, 'zhCN', '你好啊，年轻人。需要我帮忙找回你一两个走失的伙伴吗？', '你好啊，年轻人。需要我帮忙找回你一两个走失的伙伴吗？', 66384),
(303767, 'zhCN', '你知道吗，很久以前有一艘始祖龟的船在这附近失踪了。也许我能钓到一件属于我们的遗物！', '你知道吗，很久以前有一艘始祖龟的船在这附近失踪了。也许我能钓到一件属于我们的遗物！', 66384),
(303766, 'zhCN', '啊，你好，旅行者。这里虽然简陋，但如果你需要，欢迎在此稍作休息。\n\n我正忙着给我们的所有发现编目，实在停不下来！', '啊，你好，旅行者。这里虽然简陋，但如果你需要，欢迎在此稍作休息。\n\n我正忙着给我们的所有发现编目，实在停不下来！', 66384),
(303764, 'zhCN', '你长大以后想当什么？我喜欢枯木巨魔。也许我也能长出像他们那样的大獠牙！', '', 66384),
(303763, 'zhCN', '要追上斯特吉好难啊！你的腿那么长。也许你能帮我追上她？我累坏了！', '', 66384),
(303762, 'zhCN', '嘿，我正忙着呢！小斑想知道村里最适合藏猫猫的地方。找别人玩去！', '嘿，我正忙着呢！小斑想知道村里最适合藏猫猫的地方。找别人玩去！', 66384),
(303761, 'zhCN', '别让你的鱼线缠到我的，闯入者！我抓的鱼必须比我兄弟多！', '别让你的鱼线缠到我的，闯入者！我抓的鱼必须比我兄弟多！', 66384),
(303760, 'zhCN', '泽尔阿姨不准我和娜拉用鱼叉捕鱼。但她说了，要是我抓满一百条鱼，她兴许会教我！', '泽尔阿姨不准我和娜拉用鱼叉捕鱼。但她说了，要是我抓满一百条鱼，她兴许会教我！', 66384),
(303756, 'zhCN', '救命啊！芬利被人绑走了！', '', 66384),
(303754, 'zhCN', '看我的……', '', 66384),
(303751, 'zhCN', '放开他！', '', 66384),
(303750, 'zhCN', '队伍若是临阵脱逃，就永远不可能成为胜者。这是铁律。', '', 66384),
(303749, 'zhCN', '临阵脱逃是新手才会犯的错误，$p。', '', 66384),
(303747, 'zhCN', '有队名了吗，$p？你选了哪个？', '', 66384),
(303746, 'zhCN', '$p！我们得有个队名。没有队名可去不了憎怨斗坑！', '', 66384),
(303745, 'zhCN', '如果够强悍，就让真菌人们见识见识$r的实力。', '', 66384),
(303744, 'zhCN', '进入憎怨斗坑吧，$p。', '', 66384),
(303743, 'zhCN', '长老之灵将卷起的枕头放在祭坛上。', '长老之灵将卷起的枕头放在祭坛上。', 66384),
(303742, 'zhCN', '一个人类，平凡至极。近来他们总在我眼前晃悠。', '', 66384),
(303741, 'zhCN', '我会看着你的。', '', 66384),
(303740, 'zhCN', '至于这个！多么奇妙的小标本，正好可以加入我的收藏。', '', 66384),
(303739, 'zhCN', '猎人之灵将匕首放在祭坛上。', '猎人之灵将匕首放在祭坛上。', 66384),
(303738, 'zhCN', '孩童之灵将皮球放在祭坛上。', '孩童之灵将皮球放在祭坛上。', 66384),
(303726, 'zhCN', '<你的幻象先是被耀眼的光芒充斥，随后脑海中浮现出一个熟睡的孩童。在其身旁，静静地躺着一个破旧的皮球。虽在沉睡中，但孩童嘴角仍挂着笑意——那是玩球尽兴后疲惫而满足的微笑。>', '<你的幻象先是被耀眼的光芒充斥，随后脑海中浮现出一个熟睡的孩童。在其身旁，静静地躺着一个破旧的皮球。虽在沉睡中，但孩童嘴角仍挂着笑意——那是玩球尽兴后疲惫而满足的微笑。>', 66384),
(303725, 'zhCN', '', '我不会任由他们腐烂。', 66384),
(303710, 'zhCN', '告诉我发生了什么。', '告诉我发生了什么。', 66384),
(303709, 'zhCN', '他竟然绑架了芬利·莫格顿爵士！\n\n我们必须去救他。', '', 66384),
(303708, 'zhCN', '', '按住它！我再试一次。', 66384),
(303707, 'zhCN', '<影接环与野兽的皮毛紧密结合。英普利亚本可以完全控制它，强迫它为取悦她而战。\n\n看来阿纳伊斯曾试图移除这些暗影金属。但这只野兽没能撑过这个过程。>', '<影接环与野兽的皮毛紧密结合。英普利亚本可以完全控制它，强迫它为取悦她而战。\n\n看来阿纳伊斯曾试图移除这些暗影金属。但这只野兽没能撑过这个过程。>', 66384),
(303702, 'zhCN', '我可没工夫跟你闲扯。有事？', '我可没工夫跟你闲扯。有事？', 66384),
(303701, 'zhCN', '你最好手脚麻利点学会剥皮，不然就轮到别的玩意儿来剥你的皮了，闯入者。', '你最好手脚麻利点学会剥皮，不然就轮到别的玩意儿来剥你的皮了，闯入者。', 66384),
(303699, 'zhCN', '完美狩猎是心境与技艺的融合。它要求猎人保持冷静与专注，将武器视为肢体的延伸。当猎物再也无法分辨猎人与周遭自然环境时，这便是完美狩猎的境界。\n\n猎人必须精进不休，追求极致。唯有如此，才能得到狩猎之魂的真正垂青。', '完美狩猎是心境与技艺的融合。它要求猎人保持冷静与专注，将武器视为肢体的延伸。当猎物再也无法分辨猎人与周遭自然环境时，这便是完美狩猎的境界。\n\n猎人必须精进不休，追求极致。唯有如此，才能得到狩猎之魂的真正垂青。', 66384),
(303697, 'zhCN', '弗利克斯正被一只领地漂流者追杀！', '', 66384),
(303696, 'zhCN', '一株被激怒的鞭笞者想吃掉恩阿拉！', '', 66384),
(303695, 'zhCN', '一只投机的林莽爬行者正在攻击托穆！', '', 66384),
(303692, 'zhCN', '那只领地漂流者把不高兴惹毛了。', '', 66384),
(303649, 'zhCN', '', '我知道。在卡雷什发生那件事之后……\n\n双界行者说服我们与萨拉塔斯合作，而我当时则处处反对，认为绝不能信任一个虚空怪物。\n\n可我做对了吗？双界行者已经不在了。但如果我们当初没有与萨拉塔斯合作，迪门修斯就会吞噬一切。又或者……我们本可以找到另一条出路？\n\n如果我从一开始就选择信任双界行者，是不是就能阻止他的死亡？\n\n我在这里度过了那些最寒冷的夜晚，我彻夜难眠，翻来覆去地问自己这些问题。\n\n我曾告诉双界行者，他不再是我的导师。但那不是真话。在这里……我将再次领悟他的教训。\n\n虚空生物只有一个目标：活下去。我们可以利用这一点，让这份认知为我们所用。', 66384),
(303647, 'zhCN', '戴索姆是绝大多数腐蚀的源头。靠近城市的地方，我们已经清理得差不多了，但南部地区在很长一段时间里都处于废弃状态。直到最近，远行者才有能力重新在那片区域巡逻。\n\n所以那些邪恶的魔法就盘踞在土壤中，丝丝缕缕渗入了植物。然后动物吃掉了植物，腐蚀就变得更浓缩了。\n\n再然后，当动物又吃掉其他动物……好吧，你可想而知这会变成多大的麻烦了。', '', 66384),
(303645, 'zhCN', '这种艰苦的差事正是身为远行者的意义所在！我绝不会退缩。', '', 66384),
(303644, 'zhCN', '哦，各种各样的东西都有！\n\n草药和绿叶菜会最先发芽，接着是浆果灌木和会掉坚果的树。等它们给土壤遮挡了阳光，蘑菇就会在树根边冒出来。但这还只是个开始！\n\n灌木丛会藏起兔子和飞鸟，它们会成为山猫和陆行鸟的食物，而这些动物又会播撒更多的种子……这一切都是循环往复的！我们有得吃，大家就都有得吃。', '', 66384),
(303611, 'zhCN', '', '也许我们能找到更多可以救赎的卡雷什同胞，将这份誓言传承下去。', 66384),
(303610, 'zhCN', '', '你是对的，琪法安。谢谢你坚守誓言。', 66384),
(303609, 'zhCN', '', '很好。带我们去见你口中同样在反抗的人。', 66384),
(303608, 'zhCN', '', '选择……', 66384),
(303607, 'zhCN', '你的力量燃烧得如此耀眼。还有其他人在反抗。选择生路吧，我会指引你！', '', 66384),
(303606, 'zhCN', '沃拉安，求你了！操作导管的知识已经随迪扎尔一同消逝了。你没必要这么做！', '', 66384),
(303605, 'zhCN', '', '汇聚你内心的怒火。把那导管撕成碎片！', 66384),
(303604, 'zhCN', '$n，快走——我们躲到安全的地方去！', '', 66384),
(303603, 'zhCN', '你已经成功遏制了黑暗！别在现在白白送命了……求你了……', '', 66384),
(303602, 'zhCN', '', '感谢你一路护送我们到这里，琪法安。但我们就在此分别吧。', 66384),
(303601, 'zhCN', '', '我感觉到它在我身体里……随时都要爆发出来……', 66384),
(303595, 'zhCN', '我猜我还是去……给扫帚附魔吧。', '', 66384),
(303594, 'zhCN', '', '我本该派人传话的，但如你所见，我们这儿实在是忙不过来了。', 66384),
(303593, 'zhCN', '来吧，小熊们！为了远行者！', '', 66384),
(303573, 'zhCN', '<这只胖乎乎的幼芽正全神贯注地盯着附近灌木丛下的一个黑暗角落。你一靠近，它就发出嘶嘶声，那是警告你想让你离远点。>', '<这只胖乎乎的幼芽正全神贯注地盯着附近灌木丛下的一个黑暗角落。你一靠近，它就发出嘶嘶声，那是警告你想让你离远点。>', 66384),
(303572, 'zhCN', '<这只幼芽高昂着头。它的三颗脑袋把你上上下下打量了一番，发出一声短促的、带着嘲弄意味的鼻息。等它觉得无聊了，就转头面向摇篮——也许是在等女神亲自现身赐福给它呢。>', '<这只幼芽高昂着头。它的三颗脑袋把你上上下下打量了一番，发出一声短促的、带着嘲弄意味的鼻息。等它觉得无聊了，就转头面向摇篮——也许是在等女神亲自现身赐福给它呢。>', 66384),
(303571, 'zhCN', '<这只多头花幼芽睡得正香。起初听起来像是咆哮和咕哝的声音，其实是震天响的呼噜声。>', '<这只多头花幼芽睡得正香。起初听起来像是咆哮和咕哝的声音，其实是震天响的呼噜声。>', 66384),
(303570, 'zhCN', '<这只多头花幼芽一刻也安分不下来。随便有点什么声响、动静或是气味，都能勾起它的好奇心。>', '<这只多头花幼芽一刻也安分不下来。随便有点什么声响、动静或是气味，都能勾起它的好奇心。>', 66384),
(303568, 'zhCN', '你只需要四个芽体，每头一个。或者说十二个？这得看你怎么数那些脑袋了。', '你只需要四个芽体，每头一个。或者说十二个？这得看你怎么数那些脑袋了。', 66384),
(303567, 'zhCN', '你听起来很惊讶！你要知道，在它们那个……呃，在它们的……骨子里，它们其实是群被严重误解的、温顺又忠诚的生物。当然最后这点得看它们当天起床时的心情，但大多数时候，我们总是把它们视作危险的野兽。\n\n它们值得更好的生活，也应该回到属于它们的自然栖息地。', '你听起来很惊讶！你要知道，在它们那个……呃，在它们的……骨子里，它们其实是群被严重误解的、温顺又忠诚的生物。当然最后这点得看它们当天起床时的心情，但大多数时候，我们总是把它们视作危险的野兽。\n\n它们值得更好的生活，也应该回到属于它们的自然栖息地。', 66384),
(303565, 'zhCN', '感谢你为帮助我所做的一切。\n\n重新引入这些宏伟的野兽，能帮助这一带的生态系统恢复平衡。\n\n我那漂亮的花宝宝们应该能很快适应。多头花又结实又机灵，数量应该很快就能恢复正常。', '感谢你为帮助我所做的一切。\n\n重新引入这些宏伟的野兽，能帮助这一带的生态系统恢复平衡。\n\n我那漂亮的花宝宝们应该能很快适应。多头花又结实又机灵，数量应该很快就能恢复正常。', 66384),
(303564, 'zhCN', '你好啊，陌生人。你大概在纳闷，我怎么会被这些漂亮的多头花包围吧。我叫内塔尔，是附近瀑布群的守护者。\n\n这一带你还没见过多头花吧？虽然很难承认，但幽兰多头花的消失是我的错。是我允许过度狩猎，又缺乏管理，才让它们的数量锐减。\n\n我想弥补过失，把这些宏伟的幽兰多头花重新引回诺达希尔之根的瀑布群。', '你好啊，陌生人。你大概在纳闷，我怎么会被这些漂亮的多头花包围吧。我叫内塔尔，是附近瀑布群的守护者。\n\n这一带你还没见过多头花吧？虽然很难承认，但幽兰多头花的消失是我的错。是我允许过度狩猎，又缺乏管理，才让它们的数量锐减。\n\n我想弥补过失，把这些宏伟的幽兰多头花重新引回诺达希尔之根的瀑布群。', 66384),
(303562, 'zhCN', '我们所有懂打仗的战斗法师和魔导师都被派去前线了，剩下的人要么撤到了银月城，要么就来这儿了。\n\n我的专业是共振奥术理论，不是朝异世界的怪物扔火球。', '我们所有懂打仗的战斗法师和魔导师都被派去前线了，剩下的人要么撤到了银月城，要么就来这儿了。\n\n我的专业是共振奥术理论，不是朝异世界的怪物扔火球。', 66384),
(303553, 'zhCN', '我来收拾这里。你先去南部塔楼看看泰尔敏是否需要帮助。', '我来收拾这里。你先去南部塔楼看看泰尔敏是否需要帮助。', 66384),
(303550, 'zhCN', '', '在我们这儿，猎物浑身上下都能做成美味。\n\n尝过野猪心脏没？从小我就听老人们说，它特别难嚼就是因为吃了之后能获得野猪的力量。\n\n这个是真是假我说不准，但它吃起来是真香。', 66384),
(303549, 'zhCN', '', '在蜕皮！\n\n法力浮龙一年要蜕好几次皮。每当它们吸饱了法力，就会蜕掉旧的甲壳，长出新的。\n\n蜕下的甲壳会消散，将奥术魔法散布到整个森林，直到最终流回魔网。这是永歌森林生态系统至关重要的一环！\n\n眼下这场混乱扰乱了法力的自然流动，我们远行者必须介入。', 66384),
(303541, 'zhCN', '', '这里的法力浮龙数量远超我的预期。\n\n不知道是不是光绽影响了它们的迁徙习性？幸好我们来了。它们可能比平时更需要帮助。', 66384),
(303539, 'zhCN', '', '希望可怜的泰尔敏在南部塔楼那边能和我们一样顺利。', 66384),
(303538, 'zhCN', '', '不知道瓦尔萨琳完成了没有？你应该去北部塔楼看看。', 66384),
(303537, 'zhCN', '', '我觉得我们这次真的帮上大忙了！', 66384),
(303532, 'zhCN', '不知道可怜的泰尔敏在南部塔楼那边怎么样了。', '', 66384),
(303530, 'zhCN', '我敢打赌阿斯特雷肯定还需要帮助。我在这儿收尾，你回中央塔楼看看。', '', 66384),
(303529, 'zhCN', '这活儿干得漂亮！', '', 66384),
(303523, 'zhCN', '已经在斗坑看过你战斗了。上次打得不错。\n\n但憎怨斗坑是危险的地方！尽量别送命，$p！\n\n所以莫塔要待在莫塔安全的地方。', '', 66384),
(303515, 'zhCN', '你多半得送命。不过莫塔会给你助威的。说不定你能活下来呢！', '', 66384),
(303514, 'zhCN', '很高兴见到你，$p。我会去憎怨斗坑看你战斗的。', '', 66384),
(303505, 'zhCN', '我想创作一首家庭之歌。它将发自我心，以我母亲的旋律为主调，讲述她照顾我们这些小不点时对我们的期望。\n\n然后，它会加入我晚年生活的旋律，那时我反过来照顾她。在这条路上，我思索着我的歌，思索着贯穿我们一生的羁绊。', '', 66384),
(303504, 'zhCN', '我们暗松部族人丁太少，掺和不起那些打打杀杀。我们只想活下去。', '', 66384),
(303503, 'zhCN', '我想创作一首荒野之歌。它必须有奇迹的音符，也要捕捉那份失控的激动。\n\n它将拥抱前路，以及沿途激动人心的际遇。', '', 66384),
(303502, 'zhCN', '这片林子里处处是危险。千万别偏离大路。', '', 66384),
(303499, 'zhCN', '这名字起得妙极了。', '', 66384),
(303495, 'zhCN', '谁都没想到$p能击败闪光卫士。\n\n闪光卫士从未输过。\n\n直到$p训练出了一支队伍。\n\n这才尝到了失败的滋味。', '', 66384),
(303494, 'zhCN', '需要现成的药水，还是想学习如何自己制作？', '需要现成的药水，还是想学习如何自己制作？', 66384),
(303493, 'zhCN', '请原谅这儿的灰尘，$n。\n\n我们想把尖塔修复成一个防御营地……但进展不太顺利。\n\n不过，我们还在坚持。', '', 66384),
(303492, 'zhCN', '你是来寻求根系和孢子知识的吗？', '你是来寻求根系和孢子知识的吗？', 66384),
(303491, 'zhCN', '记忆固然重要，但你不能总活在过去。我们是为未来而歌！', '', 66384),
(303489, 'zhCN', '我想创作一首传承之歌。为此，我们必须回顾过去——以我们或许不愿面对的方式。传承既是我们的胜利，也是我们身后拖着的错误。\n\n我们离开时，是否让此地比我们来时更好了？\n\n这首歌就将围绕于此展开。', '', 66384),
(303485, 'zhCN', '我想创作一首悲伤之歌。不是为了沉溺于悲伤，而是为了在此徘徊，感受麻木之外的情感。\n\n不过，也许这也是一首爱之歌。当悲伤如此深沉，那便意味着爱曾更加伟大。', '', 66384),
(303484, 'zhCN', '我想创作一首群山之歌。这首歌必须给那些感到低落或被遗弃的人带来希望。\n\n胜利终将属于勇者！我来这里是为了寻找灵感。', '', 66384),
(303477, 'zhCN', '这些雕文跟我们的画也没什么两样。\n来吧，把羽毛笔蘸上墨水，我们这就开始把文字变成力量。', '这些雕文跟我们的画也没什么两样。\n来吧，把羽毛笔蘸上墨水，我们这就开始把文字变成力量。', 66384),
(303473, 'zhCN', '恕我失陪，我正忙着应对地平线上步步紧逼的光绽入侵。\n\n要是这些该死的构装体能动弹，我们就能轻而易举地建起一道防线，更好地守卫这个前哨站。\n\n唉，现在后悔也没用了。还是专注眼下能做的事吧。', '', 66384),
(303472, 'zhCN', '偏偏在这个时候……', '', 66384),
(303471, 'zhCN', '至少还得几个钟头，魔导师！', '至少还得几个钟头，魔导师！', 66384),
(303470, 'zhCN', '魔像的修理进度怎么样了？', '', 66384),
(303460, 'zhCN', '<一个锈蚀的格栅盖住了一个漆黑囚室的入口。\n\n你看不见下面潜伏着什么，但能听到动静。锁链的哐当声和湿漉漉的脚步声从黑暗中回响上来。\n\n一个饥饿的声音从深处传来。>\n\n肉……喂我……', '<一个锈蚀的格栅盖住了一个漆黑囚室的入口。\n\n你看不见下面潜伏着什么。\n\n一个微弱而饥饿的声音从深处传来。>\n\n肉……喂我……', 66384),
(303459, 'zhCN', '我们暗松部族散布在这片土地的各个角落。就连最高的山顶上都有！', '', 66384),
(303458, 'zhCN', '有太多同胞在这山谷里走过。我今天唱不出歌来。', '', 66384),
(303457, 'zhCN', '', '也许可以是啊。我们可以去个好玩的地方嘛……', 66384),
(303456, 'zhCN', '重点不在于终点，泰莎。', '', 66384),
(303455, 'zhCN', '', '这路也太长了，爸爸。大海真没劲。', 66384),
(303454, 'zhCN', '行吧，行吧。我正在酝酿情绪呢！', '', 66384),
(303453, 'zhCN', '', '上次是我点的火。这回轮到你了。', 66384),
(303449, 'zhCN', '', '我们到了吗？', 66384),
(303448, 'zhCN', '爸爸说这地方很神圣。我们得小声点！', '', 66384),
(303446, 'zhCN', '暗松部族没有固定的家。我们走到哪，哪儿就是家。', '', 66384),
(303443, 'zhCN', '', '远行者的职责，就是保护永歌森林免受大大小小的威胁。而那些小威胁，并不会因为大威胁的出现就自行消失。\n\n我愿意给泰尔敏一个机会，虽然他对我们的行事方式还抱有一些不切实际的幻想，但他明白这一点。', 66384),
(303437, 'zhCN', '$p让图克图克回到了队伍。\n\n感谢你说服图克图克，就算输了比赛也能继续做$p的朋友。\n\n憎怨斗坑见！', '', 66384),
(303436, 'zhCN', '布拉科以前害怕孢子滑翔者。$p帮布拉科试着克服。现在布拉科能跟它们战斗了！', '', 66384),
(303431, 'zhCN', '欣尼本来害怕会让队伍失望，但跟着$p训练后变得勇敢多了！', '', 66384),
(303428, 'zhCN', '要是输了，我们也能做一直切磋的好友！', '', 66384),
(303427, 'zhCN', '要是我们赢了，布拉科就还是图克图克的好朋友！', '', 66384),
(303426, 'zhCN', '得先把自己泡得再湿润些才行。', '', 66384),
(303420, 'zhCN', '憎怨斗坑太吓人了。还是水池又暖和又安全。', '', 66384),
(303419, 'zhCN', '$p？你怎么在这儿？图克图克已经退队了。', '', 66384),
(303415, 'zhCN', '肝菌从未想过能赢。\n\n别难过。\n\n但不该逃离斗坑，队伍却全跑了。\n\n所以$p就这样输了。', '', 66384),
(303414, 'zhCN', '但愿你能为菌子同懵找到新的吹箭手。', '', 66384),
(303413, 'zhCN', '这队名起得真棒。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(303412, 'zhCN', '但愿你能为尘菌将士找到新的吹箭手。', '', 66384),
(303411, 'zhCN', '但愿你能为孢誓英雄找到新的吹箭手。', '', 66384),
(303375, 'zhCN', '我的错，队长！我正带$n参观图书馆，结果一聊起故事就忘了时间，老毛病了。', '', 66384),
(303368, 'zhCN', '', '我遭遇了什么？这还不够明显吗？我死了。\n\n在对抗那个叛徒王子的战争中，无数远行者倒下了。在后来的岁月里，为了保护我们仅存的家园免遭天灾余孽的侵袭，更多的人倒下了。我们中的一些人，有幸得到了死亡的仁慈。而另一些人则没那么幸运。\n\n塔兰德拉曾经是一位魔导师。但从那以后，她便致力于学习更亵渎的法术，以此来减轻我们这些苟延残喘之人的痛苦。', 66384),
(303364, 'zhCN', '', '哦？冒险者居然会和卑微的女妖搭话。难怪塔兰德拉会喜欢上你。', 66384),
(303350, 'zhCN', '我们能一起解决游侠的问题！', '', 66384),
(303346, 'zhCN', '<弗利克斯的几颗脑袋正凑在一起，发出一阵阵低吼、呼噜和喉音，好像在进行某种深度的内部交流。\n\n然后它注意到了你。三条淌着口水的舌头从嘴里耷拉下来。也不知道这是看到你高兴，还是单纯饿了。>', '<弗利克斯的几颗脑袋正凑在一起，发出一阵阵低吼、呼噜和喉音，好像在进行某种深度的内部交流。\n\n然后它注意到了你。三条淌着口水的舌头从嘴里耷拉下来。也不知道这是看到你高兴，还是单纯饿了。>', 66384),
(303342, 'zhCN', '<幽兰多头花正在打呼噜。哪怕是以植物多头花的标准来看，它也圆润得有些过分了。托穆喷了口气，抬起一颗头，嗅了嗅你身边的空气，然后倒头又睡过去了。>', '<幽兰多头花正在打呼噜。哪怕是以植物多头花的标准来看，它也圆润得有些过分了。托穆喷了口气，抬起一颗头，嗅了嗅你身边的空气，然后倒头又睡过去了。>', 66384),
(303341, 'zhCN', '', '这封信不是空白的，里面有一张直通祖阿曼的地图。', 66384),
(303339, 'zhCN', '<走近时，野兽猛地转过身，三颗头死死盯着你，就像盯着猎物一样。它发出暴躁的嘶嘶声和低吼。\n\n很难说它对这突如其来的造访作何感想。>', '<走近时，野兽猛地转过身，三颗头死死盯着你，就像盯着猎物一样。它发出暴躁的嘶嘶声和低吼。\n\n很难说它对这突如其来的造访作何感想。>', 66384),
(303336, 'zhCN', '<幽兰多头花认出了你。它昂起身躯，三颗头颅俯视着你。中间的头嗅了嗅你周围的空气，然后轻轻地用头拱了拱你的肩膀。>', '<幽兰多头花认出了你。它昂起身躯，三颗头颅俯视着你。中间的头嗅了嗅你周围的空气，然后轻轻地用头拱了拱你的肩膀。>', 66384),
(303335, 'zhCN', '那当然！\n\n我干的可是极其重要……又“美妙”的差事……确保把合适的奥术水晶运到每个符文石的后勤工作。\n\n可是，光绽闹得每个点都压力很大，补给越来越紧张。即便如此，那帮该死的魔导师居然还……\n\n<特瑞尔捏了捏鼻子，皱起眉头，随即又恢复了镇定。>\n\n请别在意我的牢骚。我这人就是这样排解工作压力的。', '', 66384),
(303334, 'zhCN', '我快撑不住了——连接正在中断！', '', 66384),
(303333, 'zhCN', '等等——不，连接正在……', '', 66384),
(303332, 'zhCN', '', '这条项链……它将我从噩梦中唤醒……但虚空仍在体内燃烧。你们和我在一起不安全！', 66384),
(303329, 'zhCN', '你能看见我吗？这里的魔法正在——', '', 66384),
(303327, 'zhCN', '早不来晚不来，偏偏在这节骨眼上，符文石水晶供应出问题！那帮饭桶魔导师到底在搞什么鬼？\n\n而且，这黑锅最后肯定又得特瑞尔我来背……\n\n哦！失礼了。你在这里站了多久了？', '', 66384),
(303326, 'zhCN', '沃拉安……找回你项链的时候我就知道是你。给……', '', 66384),
(303324, 'zhCN', '', '小心点。那玩意儿很稀有，而且非常易燃。不过，烧起来的颜色倒是挺好看的。', 66384),
(303323, 'zhCN', '内塔尔陷入深思。', '内塔尔陷入深思。', 66384),
(303322, 'zhCN', '现在幼芽们都不在了，这儿太安静了。我在考虑收养一只林地爬行者。', '现在幼芽们都不在了，这儿太安静了。我在考虑收养一只林地爬行者。', 66384),
(303321, 'zhCN', '拜托了，请务必保护好我的幼芽。', '拜托了，请务必保护好我的幼芽。', 66384),
(303320, 'zhCN', '千万别在密闭空间打开它。那些烟雾能把死人都熏醒。', '', 66384),
(303318, 'zhCN', '图克图克小时候总是最后一个被选中。\n\n感谢你选择了图克图克。\n\n图克图克一定会在斗坑向$p证明，选择图克图克绝对没错。', '', 66384),
(303317, 'zhCN', '欣尼希望我们能在斗坑大展身手！\n\n斗坑很危险。有好多强壮的真菌人。\n\n我会紧跟着$p。', '', 66384),
(303315, 'zhCN', '我的幼芽们怎么样？它们都还好吗？', '我的幼芽们怎么样？它们都还好吗？', 66384),
(303313, 'zhCN', '布拉科要进入憎怨斗坑了，好激动！\n\n一定会好好保护$p、欣尼和图克图克。', '', 66384),
(303312, 'zhCN', '尽管他们已经脱离了影卫的控制，但虚空依然在这些虚灵的身体里肆意横行。\n\n而沃拉安……她现在连看我一眼都不愿意……', '', 66384),
(303311, 'zhCN', '真的，太感谢你了。', '', 66384),
(303310, 'zhCN', '你的勇气和坚定，再一次守护了永歌森林的安宁。', '', 66384),
(303309, 'zhCN', '我说的名字才对，就是尘菌将士。是你们俩在叫别的名字！', '', 66384),
(303308, 'zhCN', '我说……咱们得找人评理，$p。大家都想叫不同的名字！', '', 66384),
(303307, 'zhCN', '你们两个都说错名字了。', '', 66384),
(303306, 'zhCN', '等等，什么？', '', 66384),
(303282, 'zhCN', '老实交代，你是真知道自己在干什么，还是只是瞎摆弄工具碰运气？', '', 66384),
(303280, 'zhCN', '', '非同凡响，无论你做了什么，看来都奏效了。这个奇点现在应该能保持稳定。\n\n很高兴你挺身而出。我怀疑要是让莱希卡斯拿起那些工具，我们现在大概都没法站在这说话了。', 66384),
(303279, 'zhCN', '不得不说，它现在的状态比我最早发现时要……活跃得多。看来适当的担忧是有必要的。', '', 66384),
(303278, 'zhCN', '', '这个奇点已经开始自我撕裂了，它在崩塌前不会有任何预警。我可以下令撤离，但是……\n\n<麦拉眯起眼睛，在脑海中清点着朗多雷的兵力。>\n\n不，那样太耗时间了，我们的部队还是会被卷入爆炸。你、我、还有莱希卡斯，我们得解决这个问题。立刻。', 66384),
(303277, 'zhCN', '我就知道瞒不过麦拉的眼睛。在彻底核实情况前，我不想引起不必要的骚动，但我怀疑下层要塞又出现了一个失控的奇点。', '', 66384),
(303266, 'zhCN', '', '莱希卡斯，你这是要去哪里？', 66384),
(303265, 'zhCN', '我们将穿过战壕，伺机打击目标，然后从下方突袭要塞。', '', 66384),
(303264, 'zhCN', '来得正是时候。在攻势间隙我侦察了一番，我觉得我们要担心的不止是这个奇点。我相信你不介意深入敌后吧？\n\n反正也不可能比驻守这儿更危险了。麦拉可能乐意与敌人正面交锋，但我宁愿只通过瞄准镜看他们。', '', 66384),
(303263, 'zhCN', '', '莱希卡斯……继续你的侦察任务。但下次发现危险状况时，别拖拖拉拉不报告了。', 66384),
(303262, 'zhCN', '', '我们非常欢迎你协助防御奇点锚点，$p。', 66384),
(303246, 'zhCN', '', '暂时是这样。但堡垒上层那里还有一个奇点。', 66384),
(303245, 'zhCN', '看上去……它稳定了？', '', 66384),
(303242, 'zhCN', '盖世之菌一定会赢，因为我们训练最勤奋。\n\n而且建议也最多。\n\n大家互相提醒：“躲开剑！”“用剑砍！”\n\n边练边吼，效果才好。', '', 66384),
(303241, 'zhCN', '别打扰，得专注。\n\n建议要喊出来。\n\n不大声喊出来，怎么进步？', '', 66384),
(303231, 'zhCN', '我曾经担心沃拉安会遭遇最糟糕的结局……以为影卫对她的控制已经无力回天。\n\n但现在看来或许还有一线希望……', '', 66384),
(303230, 'zhCN', '新盾牌坚不可摧！\n\n试了一遍又一遍。\n\n等装备齐全，盖世之菌必定大获全胜。', '', 66384),
(303200, 'zhCN', '腐沼就是孢子风暴，它不会想逃的。\n\n再说，腐沼有围栏围着呢。\n\n真是个傻问题，$r。', '', 66384),
(303198, 'zhCN', '看见腐沼了吗？\n\n等腐沼准备好了，孢子风暴就能所向披靡。\n\n就连闪光卫士也得俯首称臣。\n\n眼下，我们正教它如何战斗，给它喂食，让它成长。\n\n然后……就是称霸憎怨斗坑。\n\n腐沼无人能挡。', '', 66384),
(303196, 'zhCN', '等我们的吹箭筒制作完成，真菌之力就能永远称霸憎怨斗坑。\n\n射程更远，\n\n轨迹更直，\n\n能装更多飞镖，\n\n必胜无疑。', '', 66384),
(303185, 'zhCN', '出发！', '', 66384),
(303184, 'zhCN', '命令你们都听到了', '', 66384),
(303183, 'zhCN', '就是你。', '', 66384),
(303182, 'zhCN', '终于找到了我盼望已久的。', '', 66384),
(303181, 'zhCN', '母亲，我独自度过了那么多年……', '', 66384),
(303180, 'zhCN', '这股黑暗永远触及不了我内心的东西……', '', 66384),
(303179, 'zhCN', '那是不可能的。', '', 66384),
(303178, 'zhCN', '', '就和我一样。', 66384),
(303177, 'zhCN', '', '让你变得铁石心肠……', 66384),
(303176, 'zhCN', '', '我害怕让你来到这个地方，和这些恐魔作战，会慢慢将你拖垮。', 66384),
(303175, 'zhCN', '母亲，我……', '', 66384),
(303174, 'zhCN', '', '现在的你让我无比骄傲。', 66384),
(303173, 'zhCN', '', '我想让你知道……', 66384),
(303172, 'zhCN', '', '你真是我的奇迹，阿拉托尔。', 66384),
(303171, 'zhCN', '我就知道这能行的。', '', 66384),
(303170, 'zhCN', '我一向说到做到，凡人。', '', 66384),
(303169, 'zhCN', '该兑现你的诺言了……', '', 66384),
(303168, 'zhCN', '晶塔网络稳定下来了，殆希莫斯。', '', 66384),
(303144, 'zhCN', '我没法直接把她带回来，但我们或许可以设立一个信标，好让她能找到我们的位置。', '', 66384),
(303143, 'zhCN', '抱歉，最强的毒药只供给真菌之力。\n\n这是为了在斗坑里取胜。\n\n不共享，你也买不到。', '', 66384),
(303142, 'zhCN', '感激不尽，$n，感谢你为我付出的一切。愿狩猎之运常伴你左右。', '感激不尽，$n，感谢你为我付出的一切。愿狩猎之运常伴你左右。', 66384),
(303141, 'zhCN', '挺身迎接狩猎吧，科坦，卡达尼。愿女神指引你未来的猎途。', '挺身迎接狩猎吧，科坦，卡达尼。愿女神指引你未来的猎途。', 66384),
(303140, 'zhCN', '科坦，正是你的决心、热忱与坚毅带你走到了这里。', '科坦，正是你的决心、热忱与坚毅带你走到了这里。', 66384),
(303139, 'zhCN', '$n，你现在已是卡达尼的一员。愿女神指引你未来的猎途。', '$n，你现在已是卡达尼的一员。愿女神指引你未来的猎途。', 66384),
(303134, 'zhCN', '', '尽快到那里与我们汇合，$n。', 66384),
(303130, 'zhCN', '', '纳鲁居然想招募伊利丹来对抗虚空？真是有意思。', 66384),
(303127, 'zhCN', '', '好极了。快去测试解药，务必确保万无一失。', 66384),
(303122, 'zhCN', '我对你深怀感激，$n。我相信有你在场，阿斯崔绝不会与你的族人起冲突。', '', 66384),
(303120, 'zhCN', '相信我，我倒希望我是错的，但我怀疑我们没那么好运。带路吧。', '', 66384),
(303119, 'zhCN', '', '行动吧。希望你的直觉别是在浪费时间。', 66384),
(303118, 'zhCN', '卡达尼是一群精英猎人，他们追求狩猎之道的完美。虽人数稀少，却在我族中享有盛名，或许只有舒尔卡能胜他们一筹，当然，或许靠的是恶名，这取决于你如何评判了。\n\n唯有最出色的卡达尼才有资格指导他人，而这样的机会往往要等待几个狩猎季节的轮回。在哈拉希尔的猎人中，成为卡达尼是每个人的毕生追求。', '卡达尼是一群精英猎人，他们追求狩猎之道的完美。虽人数稀少，却在我族中享有盛名，或许只有舒尔卡能胜他们一筹，当然，或许靠的是恶名，这取决于你如何评判了。\n\n唯有最出色的卡达尼才有资格指导他人，而这样的机会往往要等待几个狩猎季节的轮回。在哈拉希尔的猎人中，成为卡达尼是每个人的毕生追求。', 66384),
(303116, 'zhCN', '那个在山脊上摸摸索索的家伙是谁？别妨碍我报仇。', '', 66384),
(303114, 'zhCN', '容我辩解一下，几小时前它的规模还要小得多。', '', 66384),
(303113, 'zhCN', '', '你目睹了这一切却没想过要上报？', 66384),
(303108, 'zhCN', '', '如果有威胁，你要先向我汇报。你不能仅凭一个“直觉”就擅离职守。', 66384),
(303106, 'zhCN', '我觉得最好不要引发大家的恐慌情绪。', '', 66384),
(303056, 'zhCN', '当我回到长老阿卡齐面前时，我将不再是科坦，而是科坦，卡达尼。', '当我回到长老阿卡齐面前时，我将不再是科坦，而是科坦，卡达尼。', 66384),
(303052, 'zhCN', '是时候证明我有资格成为卡达尼的一员了。', '是时候证明我有资格成为卡达尼的一员了。', 66384),
(303050, 'zhCN', '<这颗巨大的深红水晶触感温热。你能感受到微弱而律动的能量。它悬浮在你面前，带着期待，带着渴求。>', '<这颗巨大的深红水晶触感温热。你能感受到微弱而律动的能量。它悬浮在你面前，带着期待，带着渴求。>', 66384),
(303048, 'zhCN', '拉杜尼被视为游荡在哈拉希尔边陲的最为凶险的野兽之一。\n\n我并不惧怕它，而是尊重它。\n\n<科坦看着你，点了点头。>\n\n等你准备好就行动，$n。既然你是导师，这就得由你来发起狩猎，我会紧随其后。', '拉杜尼被视为游荡在哈拉希尔边陲的最为凶险的野兽之一。\n\n我并不惧怕它，而是尊重它。\n\n<科坦看着你，点了点头。>\n\n等你准备好就行动，$n。既然你是导师，这就得由你来发起狩猎，我会紧随其后。', 66384),
(303047, 'zhCN', '', '暮光之刃要为他们杀害的每一个人血债血偿！', 66384),
(303040, 'zhCN', '', '也别让他们永远开不了口。我们得知道那些圣骑士在哪儿。', 66384),
(303039, 'zhCN', '', '密教渣滓，快说，他们在哪儿？不说就后果自负！', 66384),
(303035, 'zhCN', '', '<特莱亚妮丝抿了口饮料，一边盯着天上飞过的什么东西。>\n\n早晚的事……我非抓住你不可。', 66384),
(303021, 'zhCN', '看他们因你的痛苦而狂喜吧！', '', 66384),
(303011, 'zhCN', '你休想离开这个地方。', '', 66384),
(303004, 'zhCN', '来吧，被吞噬吧。', '', 66384),
(303003, 'zhCN', '我乃是使徒，你只是美餐。', '', 66384),
(302997, 'zhCN', '我听过拉杜尼的传说。无论如何，我都会怀着无上荣耀接受这个任务！', '我听过拉杜尼的传说。无论如何，我都会怀着无上荣耀接受这个任务！', 66384),
(302996, 'zhCN', '你要猎杀伟大的拉杜尼，一旦完成这场试炼，你就是卡达尼的一员了。', '你要猎杀伟大的拉杜尼，一旦完成这场试炼，你就是卡达尼的一员了。', 66384),
(302995, 'zhCN', '科坦，卡达尼从不会惧怕猎物。但今日你要面对的猎物，确实令人生畏。', '科坦，卡达尼从不会惧怕猎物。但今日你要面对的猎物，确实令人生畏。', 66384),
(302963, 'zhCN', '', '拉克图尔已经倒下。被你解救的生灵得以存活，迷失的魂灵也终得安息。这片洞窟暂时归于寂静。', 66384),
(302957, 'zhCN', '', '来自大地的慷慨赠礼。', 66384),
(302955, 'zhCN', '', '大自然的馈赠，很有用。', 66384),
(302953, 'zhCN', '', '这里有些金币。', 66384),
(302938, 'zhCN', '', '要做的事仍有许多。', 66384),
(302936, 'zhCN', '', '我没法……抱歉……', 66384),
(302932, 'zhCN', '', '不要浪费时间。', 66384),
(302929, 'zhCN', '', '现在你更有本事了。', 66384),
(302924, 'zhCN', '', '我能发挥更大的作用了。', 66384),
(302923, 'zhCN', '', '这是我应得的。', 66384),
(302922, 'zhCN', '', '好多了。', 66384),
(302921, 'zhCN', '', '稍等。', 66384),
(302917, 'zhCN', '科坦，现在加入孢子蝠的尾巴，再用鞭笞者的藤蔓将它们牢牢绑在一起。', '科坦，现在加入孢子蝠的尾巴，再用鞭笞者的藤蔓将它们牢牢绑在一起。', 66384),
(302915, 'zhCN', '', '抓紧时间。', 66384),
(302913, 'zhCN', '', '连影子都碰不到。', 66384),
(302911, 'zhCN', '', '唯快不破。', 66384),
(302906, 'zhCN', '', '我不这么认为。', 66384),
(302905, 'zhCN', '', '不得开口。', 66384),
(302904, 'zhCN', '', '住口吧。', 66384),
(302901, 'zhCN', '', '帷幕护身。', 66384),
(302900, 'zhCN', '', '暗影会保护你。', 66384),
(302898, 'zhCN', '', '不要浪费了。', 66384),
(302897, 'zhCN', '', '利用好这股力量。', 66384),
(302896, 'zhCN', '', '不用胆怯。', 66384),
(302894, 'zhCN', '', '我会帮你摆脱它。', 66384),
(302892, 'zhCN', '', '这个归我了。', 66384),
(302891, 'zhCN', '', '哼，讨厌的魔法。', 66384),
(302890, 'zhCN', '', '我来止血。', 66384),
(302889, 'zhCN', '', '振作起来。', 66384),
(302888, 'zhCN', '', '留在这里恢复。', 66384),
(302887, 'zhCN', '', '你的痛苦，我的欢乐。', 66384),
(302886, 'zhCN', '', '你的生命属于我。', 66384),
(302885, 'zhCN', '', '这个归我了。', 66384),
(302881, 'zhCN', '', '接住。', 66384),
(302880, 'zhCN', '', '这是给你的。', 66384),
(302879, 'zhCN', '', '深呼吸。', 66384),
(302875, 'zhCN', '好一件神兵利器，确实是当之无愧的杰作。', '好一件神兵利器，确实是当之无愧的杰作。', 66384),
(302869, 'zhCN', '', '下次再利索点儿。', 66384),
(302868, 'zhCN', '', '还不够快。', 66384),
(302867, 'zhCN', '', '我盯上你了。', 66384),
(302866, 'zhCN', '', '就是现在！', 66384),
(302865, 'zhCN', '成为卡达尼远不止是一个象征或使命，它是所有猎人的最高追求。哈拉希尔比其他村落更看重狩猎之道。\n\n最负盛名的舒尔卡有不少都出自哈拉希尔。', '成为卡达尼远不止是一个象征或使命，它是所有猎人的最高追求。哈拉希尔比其他部族更看重狩猎之道。\n\n最负盛名的舒尔卡有不少都出自哈拉希尔。', 66384),
(302864, 'zhCN', '', '我会好好品味这一击。', 66384),
(302862, 'zhCN', '', '我无影无踪。', 66384),
(302861, 'zhCN', '他们已经将沉歌和其他人押送到了影卫营。等待他们的只有无尽的恐怖与虚空。', '他们已经将沉歌和其他人押送到了影卫营。等待他们的只有无尽的恐怖与虚空。', 66384),
(302859, 'zhCN', '', '我们必须立刻通知乌布里克。', 66384),
(302858, 'zhCN', '', '我的飞升……完成了！', 66384),
(302853, 'zhCN', '这真是一柄卡达尼武器的杰作，就连阿卡齐也无法否认。', '这真是一柄卡达尼武器的杰作，就连阿卡齐也无法否认。', 66384),
(302850, 'zhCN', '首先由$n装上骨头，再由科坦装上獠牙。', '首先由$n装上骨头，再由科坦装上獠牙。', 66384),
(302849, 'zhCN', '这条项链有什么特殊之处吗？上面被附魔了吗？', '', 66384),
(302848, 'zhCN', '她只不过是个开始……', '她只不过是个开始……', 66384),
(302847, 'zhCN', '它们的价值不可估量。', '它们的价值不可估量。', 66384),
(302846, 'zhCN', '沉歌是你们的首领吗？', '', 66384),
(302831, 'zhCN', '不，不认识你。不，我们不接受预订。不，没得商量。\n\n老老实实排队，要不就拉倒。毕竟，这儿可是全城最火的早午餐店。\n\n你总不想因为不乐意站几个钟头就错过它吧，对吗？', '不，不认识你。不，我们不接受预订。不，没得商量。\n\n老老实实排队，要不就拉倒。毕竟，这儿可是全城最火的早午餐店。\n\n你总不想因为不乐意站几个钟头就错过它吧，对吗？', 66384),
(302830, 'zhCN', '未来是属于孩子们的。\n\n所以现在，我必须变出更多的蛋糕和咖啡，这样我们才能拥有那样的未来。\n\n<泰伦脸上露出一丝憧憬。>\n\n我怎么不记得我小时候上学有这么难……', '', 66384),
(302829, 'zhCN', '我才不是在暴食解压！就算我是又怎样？！就算我这学期挂科了又怎样……啊啊啊……啊……超多奶油的小蛋糕，我的最爱……', '我才不是在暴食解压！就算我是又怎样？！就算我这学期挂科了又怎样……啊啊啊……啊……超多奶油的小蛋糕，我的最爱……', 66384),
(302825, 'zhCN', '艾尔雅特，这件武器真是精美。$n，作为我的导师，就由你将这把长矛带给长老阿卡齐吧。我在那里与你会合。', '艾尔雅特，这件武器真是精美。$n，作为我的导师，就由你将这把长矛带给长老阿卡齐吧。我在那里与你会合。', 66384),
(302803, 'zhCN', '', '我还需要再收集些材料。到前面等我吧。', 66384),
(302800, 'zhCN', '审讯者泽纳达安肯定掌握了许多内幕消息。', '', 66384),
(302799, 'zhCN', '', '你的虚空之魂归我了。', 66384),
(302798, 'zhCN', '我正想劝我朋友，让她明白花光一个月薪水买文具、画笔和颜料是没问题的。\n\n<这位艺术家挂着平静的微笑，眼神却很疯狂，整个人都快垮掉了。>\n\n没事的。这很值。我们会画超多超多画的。', '我正想劝我朋友，让她明白花光一个月薪水买文具、画笔和颜料是没问题的。\n\n<这位艺术家挂着平静的微笑，眼神却很疯狂，整个人都快垮掉了。>\n\n没事的。这很值。我们会画超多超多画的。', 66384),
(302797, 'zhCN', '魔导师血誓和他的客人正在下面等你。', '魔导师血誓和他的客人正在下面等你。', 66384),
(302793, 'zhCN', '很多叛军都被转移到了其他地方。', '', 66384),
(302790, 'zhCN', '但现在他们反抗了。他们的领袖是一个被称为“沉歌”的虚灵。', '', 66384),
(302789, 'zhCN', '影卫内部有一群叛乱分子。他们都曾在法力熔炉：欧米伽被迫屈从于虚空的意志。', '', 66384),
(302786, 'zhCN', '这里的影卫乱成了一锅粥。\n\n你有什么有用的发现吗？', '', 66384),
(302785, 'zhCN', '这里的多曼纳尔似乎掌握了随意塑造虚空的高超技艺。也许那把刻刃就是他们的杰作之一。\n\n朗多雷对于改变自身本质、通过虚空力量探索自我这些事并不陌生。其他生物可能也有相似的渴望，这有什么值得大惊小怪的吗？对他们来说，刻刃这样的工具可能就像梳子对我们一样平常无奇。\n\n但它显然不是为我们这样的种族打造的。现在看起来它已经完全失去了活力，就是一块普通的石头而已。\n\n但我的阴影是怎么知道指引我来这儿的？是虚空在呼唤虚空吗？我们还有太多东西要学。', '', 66384),
(302780, 'zhCN', '', '我会免费治好他们，纯粹是出于我的一片好心。不过，也可以当是为未来投资嘛。\n\n总有一天，他们会欠我一个大人情的！', 66384),
(302779, 'zhCN', '该准备迎接湮灭的是你，我的小点心。连同你那些注定要毁灭的族人一起。', '', 66384),
(302777, 'zhCN', '', '准备迎接失望吧，空灵爪牙。在那之后，便是彻底的湮灭。', 66384),
(302773, 'zhCN', '那我就能成为真正的阿曼尼战士了！你也会成为我们的荣誉战士，对吧？', '', 66384),
(302770, 'zhCN', '', '我来掩护你！', 66384),
(302769, 'zhCN', '', '到我身后来！', 66384),
(302768, 'zhCN', '艾尔雅特上下打量了一下你，随即点头认可。', '艾尔雅特上下打量了一下你，随即点头认可。', 66384),
(302767, 'zhCN', '$n来了，这就是我的导师。', '$n来了，这就是我的导师。', 66384),
(302766, 'zhCN', '阿卡齐向我提起了你的导师，但如果你的导师不在场，我便无法锻造武器。', '阿卡齐向我提起了你的导师，但如果你的导师不在场，我便无法锻造武器。', 66384),
(302763, 'zhCN', '也许让长矛在你肚子里插上几年，你就能学到点教训了。', '', 66384),
(302762, 'zhCN', '', '我们在虚影尖塔等你，$n。', 66384),
(302753, 'zhCN', '我这就出发狩猎。愿女神庇佑，我们猎场再见。', '我这就出发狩猎。愿女神庇佑，我们猎场再见。', 66384),
(302752, 'zhCN', '创造出这个阴影后，我惊恐万分。当我在虚空中寻求指引时，我本想毁了它。\n\n但答案并非来自虚空。而是来自那个阴影。这就是为什么那个声音听起来如此熟悉。那是我自己的声音。\n\n它如此痛苦，却依然试图帮助我。', '', 66384),
(302745, 'zhCN', '你太弱了。死路一条！', '你太弱了。死路一条！', 66384),
(302744, 'zhCN', '我是最强的！我要杀光所有挑战者！', '我是最强的！我要杀光所有挑战者！', 66384),
(302741, 'zhCN', '你找到合适的骨头来制作武器了吗？\n\n别惊慌，$n，这些野兽的尸体一点都不会浪费。我们的采集者会从我们的猎物身上收集食物和材料。', '你找到合适的骨头来制作武器了吗？\n\n别惊慌，$n，这些野兽的尸体一点都不会浪费。我们的采集者会从我们的猎物身上收集食物和材料。', 66384),
(302740, 'zhCN', '又有人来抢夺牙魔的宝贝啦！', '又有人来抢夺牙魔的宝贝啦！', 66384),
(302724, 'zhCN', '欢迎光临洛瑟玛·塞隆与塔莉萨的庄园。', '欢迎光临洛瑟玛·塞隆与塔莉萨的庄园。', 66384),
(302723, 'zhCN', '你本该在攻击前先削弱$n，而不是在失手后像只穿山甲一样尖叫。', '', 66384),
(302722, 'zhCN', '凯尔沃卓，你被惩罚是因为你作弊，而且蠢到连藏都藏不好。', '', 66384),
(302712, 'zhCN', '等你拿到那个大家伙的战利品后，我就会在那儿帮你。', '', 66384),
(302710, 'zhCN', '等你拿到那些战利品，我们很快就能完成试炼了。', '', 66384),
(302701, 'zhCN', '我的发明能让我隐匿身形，但要是没有你帮忙，我恐怕找不到沃拉安的项链。', '', 66384),
(302700, 'zhCN', '真是风水轮流转啊。', '', 66384),
(302696, 'zhCN', '准备妥当后，来见我和长老阿卡齐。', '准备妥当后，来见我和长老阿卡齐。', 66384),
(302694, 'zhCN', '愿狩猎之魂指引你们。', '愿狩猎之魂指引你们。', 66384),
(302690, 'zhCN', '我们需要一位卡达尼来指导和培训年轻猎人。这并非死守传统，而是因为我们要去的大狩猎太过凶险。\n\n我能看出你历经世间凶险。我虽深知科坦的决心与毅力，却对你一无所知。\n\n只有你成为一名荣誉卡达尼，我才能放心让你指导科坦。\n\n你愿意接下这个重担吗？不仅仅是为了你自己，也是为了科坦的未来。但你们中只要有一人失败，都将失去重来的机会。', '我们需要一位卡达尼来指导和培训年轻猎人。这并非死守传统，而是因为我们要去的大狩猎太过凶险。\n\n我能看出你历经世间凶险。我虽深知科坦的决心与毅力，却对你一无所知。\n\n只有你成为一名荣誉卡达尼，我才能放心让你指导科坦。\n\n你愿意接下这个重担吗？不仅仅是为了你自己，也是为了科坦的未来。但你们中只要有一人失败，都将失去重来的机会。', 66384),
(302683, 'zhCN', '欢迎来到哈拉希尔。陌生人，你为何而来？', '欢迎来到哈拉希尔。陌生人，你为何而来？', 66384),
(302681, 'zhCN', '追上它，求你了，别让它伤害任何人。', '', 66384),
(302680, 'zhCN', '什么？不！它应该消失才对！', '', 66384),
(302667, 'zhCN', '', '谢谢你帮助我保全了希望，$p。正是因为我们的不懈努力，这些根须才有再次生长的机会。', 66384),
(302666, 'zhCN', '你难道是疯了吗，$n？！那东西是个怪物！你居然还帮助它逃脱了圣光的制裁？\n\n我曾经信任你，听从你的指挥，尊称你为大领主。或许，你从来就不是我心目中那个正直的圣骑士。', '', 66384),
(302648, 'zhCN', '<一座神圣水池的幻象浮现在你的脑海。孩童、猎人和护根者们都对你投以崇敬的目光。这是一段圆满的人生，或许并非尽善尽美，却让你感到无比充实。一缕温暖的微风在你耳畔轻语：“启程的时候到了。”\n\n亲朋好友将你抬至神圣水池，轻轻放入水中进行最后的沐浴。\n\n这个幻象是生命轮回的终章，象征着死亡。>', '<一座神圣水池的幻象浮现在你的脑海。孩童、猎人和护根者们都对你投以崇敬的目光。这是一段圆满的人生，或许并非尽善尽美，却让你感到无比充实。一缕温暖的微风在你耳畔轻语：“启程的时候到了。”\n\n亲朋好友将你抬至神圣水池，轻轻放入水中进行最后的沐浴。\n\n这个幻象是生命轮回的终章，象征着死亡。>', 66384),
(302646, 'zhCN', '<你的思绪渐渐迷蒙，身躯感受着岁月的侵蚀。伴随这种感觉，你仿佛经历了一段漫长人生。你在晨光中醒来，看着顽童们嬉戏，猎人们凯旋而归，倾听护根者们谈论着日常琐事。\n\n头顶上方，摇篮在呼唤着你的名字，吸引着你靠近。内心深处，你明白这便是生命之道，当你重返女神怀抱时，你将以新的形态重生，或为哈籁尼尔，或化作蝴蝶——生命本就是永恒的谜题。>', '<你的思绪渐渐迷蒙，身躯感受着岁月的侵蚀。伴随这种感觉，你仿佛经历了一段漫长人生。你在晨光中醒来，看着顽童们嬉戏，猎人们凯旋而归，倾听护根者们谈论着日常琐事。\n\n头顶上方，摇篮在呼唤着你的名字，吸引着你靠近。内心深处，你明白这便是生命之道，当你重返女神怀抱时，你将以新的形态重生，或为哈籁尼尔，或化作蝴蝶——生命本就是永恒的谜题。>', 66384),
(302644, 'zhCN', '<长老之灵微笑着，微微欠身以示敬意。她以疲惫的目光掠过你望向摇篮，而后又将目光重新投向你。你感到一阵疲惫。\n\n脑海中逐渐浮现出附近屋舍中一只枕头的影像。>', '<长老之灵微笑着，微微欠身以示敬意。她以疲惫的目光掠过你望向摇篮，而后又将目光重新投向你。你感到一阵疲惫。\n\n脑海中逐渐浮现出附近屋舍中一只枕头的影像。>', 66384),
(302642, 'zhCN', '<这座古老的祭坛的壁画上刻画着一位哈籁尼尔长老。她端坐在织锦地毯之上，沉浸于冥想之中。一个神秘球体环绕其身，似是世界或女神的象征。>', '<这座古老的祭坛的壁画上刻画着一位哈籁尼尔长老。她端坐在织锦地毯之上，沉浸于冥想之中。一个神秘球体环绕其身，似是世界或女神的象征。>', 66384),
(302637, 'zhCN', '离我远点！消失吧！', '', 66384),
(302635, 'zhCN', '我明白，相信我。我也说不清楚原因，但那个声音……给人一种值得信赖的感觉。它很熟悉，宛如大梦初醒。\n\n如果它能帮我摆脱这个阴影，那我就必须去看看它通向何方。', '', 66384),
(302632, 'zhCN', '这影子是我的罪责……我的过错。这里的虚空如此纯粹，如此……鲜活，而我真是太傻了。我早就见过这样的影子，朗多雷凝聚的暗影。我以为我也可能做到。\n\n可我错了。残破不堪的我根本无法逃避它，人又怎么能逃避自己的思绪呢？\n\n所以我来到了这里。我在虚空中寻找解脱的办法，有一个声音指引我一路向北，它向我许诺，有一件神器能让我卸下这个失败的作品。', '', 66384),
(302628, 'zhCN', '<灵魂带着敬意点头，你已赢得它的信任。对于猎人来说，世间至高的荣耀莫过于使其重获其生命的延伸——那些能让猎物得以迅速解脱的狩猎工具。\n\n随后，一幕幻象浮现在你眼前：一座重要的建筑中，猎人们与长老们围坐在神圣水池旁，分享故事与人生智慧。猎人们仰望着长老们，心怀憧憬，期盼有朝一日能荣列其中。\n\n这个幻象象征着生命壮阔征程的中章。>', '<灵魂带着敬意点头，你已赢得它的信任。对于猎人来说，世间至高的荣耀莫过于使其重获其生命的延伸——那些能让猎物得以迅速解脱的狩猎工具。\n\n随后，一幕幻象浮现在你眼前：一座重要的建筑中，猎人们与长老们围坐在神圣水池旁，分享故事与人生智慧。猎人们仰望着长老们，心怀憧憬，期盼有朝一日能荣列其中。\n\n这个幻象象征着生命壮阔征程的中章。>', 66384),
(302626, 'zhCN', '<一瞬间，你的内心万籁俱寂，鸟鸣兽语顿时清晰可闻。尽管有东西在你腿上爬动，你却心无旁骛，只专注于猎物，志在必得。\n\n你屏息凝神，只能听到弓弦绷紧的声音。箭矢蓄势待发，随即离弦而去，轨迹无懈可击，野兽轰然倒地。你纵身跃出藏身之处，娴熟抽出猎刀握在手中。\n\n当你靠近时，发现野兽虽然奄奄一息，却仍在苦苦挣扎，承受痛苦的煎熬。你俯身轻抚它的鬃毛，在它耳畔低语安慰与感恩之言。\n\n你手起刀落，果断而仁慈地终结了野兽的生命。>', '<一瞬间，你的内心万籁俱寂，鸟鸣兽语顿时清晰可闻。尽管有东西在你腿上爬动，你却心无旁骛，只专注于猎物，志在必得。\n\n你屏息凝神，只能听到弓弦绷紧的声音。箭矢蓄势待发，随即离弦而去，轨迹无懈可击，野兽轰然倒地。你纵身跃出藏身之处，娴熟抽出猎刀握在手中。\n\n当你靠近时，发现野兽虽然奄奄一息，却仍在苦苦挣扎，承受痛苦的煎熬。你俯身轻抚它的鬃毛，在它耳畔低语安慰与感恩之言。\n\n你手起刀落，果断而仁慈地终结了野兽的生命。>', 66384),
(302624, 'zhCN', '<一位成年哈籁尼尔的灵魂正在你面前盘旋，恭敬地向你点头致意。一件狩猎工具的影像在你脑海深处浮现，那是一把遗落在附近瀑布中的猎刀。>', '<一位成年哈籁尼尔的灵魂正在你面前盘旋，恭敬地向你点头致意。一件狩猎工具的影像在你脑海深处浮现，那是一把遗落在附近瀑布中的猎刀。>', 66384),
(302621, 'zhCN', '$p，你体味过孤独吗？那是我在银月城时的全部感受。和朗多雷在一起时，我以为找到了归属。\n\n<奥林瞥了一眼那逼近的阴影。>\n\n看来我只是把我的孤独也带到了这里。像其他一切一样，这个阴影是个错误。我可怜它。抹除它是最好的选择。', '', 66384),
(302619, 'zhCN', '<仔细观察后发现，这座祭坛描绘了猎人与猎物的故事。环形排列的图案展现了一位猎人潜行追踪猎物，随后隐匿一旁准备出击的场景。下一幕猎人立于猎物之上，摆出胜利姿态，然后他们返回家园，在需要时重新开始这个过程。>', '<仔细观察后发现，这座祭坛描绘了猎人与猎物的故事。环形排列的图案展现了一位猎人潜行追踪猎物，随后隐匿一旁准备出击的场景。下一幕猎人立于猎物之上，摆出胜利姿态，然后他们返回家园，在需要时重新开始这个过程。>', 66384),
(302617, 'zhCN', '', '就在那一瞬间，我所熟知的一切……都变得岌岌可危。\n\n还好有这段旅程可以让我专注于当下。', 66384),
(302614, 'zhCN', '', '祖尔加拉也许不相信洛阿会显灵，但我看得出，她心里其实是希望的。', 66384),
(302609, 'zhCN', '必须……想个……妙计。', '', 66384),
(302608, 'zhCN', '哇哦，够狡猾的！受死吧。', '', 66384),
(302607, 'zhCN', '', '怎么可能？我明明应该……', 66384),
(302606, 'zhCN', '被逼到绝路的野兽可是会拼命的……', '', 66384),
(302605, 'zhCN', '', '好虚弱……', 66384),
(302604, 'zhCN', '不该是这样！不该是这样！', '', 66384),
(302603, 'zhCN', '', '我经历过的痛苦远甚于此。滚开！', 66384),
(302602, 'zhCN', '你以为这就伤到我了？', '', 66384),
(302601, 'zhCN', '你竟敢靠近我？', '', 66384),
(302600, 'zhCN', '可悲的小东西……你的命是我的了！', '', 66384),
(302599, 'zhCN', '呃啊！湮没于黑暗之中吧！', '', 66384),
(302598, 'zhCN', '不知死活的血肉之躯……', '', 66384),
(302597, 'zhCN', '', '野蛮的小东西……！', 66384),
(302596, 'zhCN', '我绝不会向你这种人低头！', '', 66384),
(302595, 'zhCN', '你的追逐，让这家伙感到厌烦了。', '', 66384),
(302594, 'zhCN', '时机没到！时机没到！', '', 66384),
(302593, 'zhCN', '', '这也配叫狩猎？', 66384),
(302592, 'zhCN', '你是怎么——算了！', '', 66384),
(302591, 'zhCN', '', '呱？！', 66384),
(302590, 'zhCN', '哒哒哒！', '', 66384),
(302589, 'zhCN', '', '谁也别想猎捕我！', 66384),
(302588, 'zhCN', '哇啊？！', '', 66384),
(302587, 'zhCN', '又是你？怎么找来的？', '', 66384),
(302586, 'zhCN', '', '刺客之道，果然卑劣。', 66384),
(302585, 'zhCN', '', '你的力量……令人垂涎……', 66384),
(302584, 'zhCN', '虚空……终将了结你……', '', 66384),
(302583, 'zhCN', '', '防御系统功率仅剩百分之七十八。状态不佳！', 66384),
(302582, 'zhCN', '离我远点，你这榆木脑袋！', '', 66384),
(302581, 'zhCN', '', '所有烈焰，终将熄灭……', 66384),
(302580, 'zhCN', '烈焰……黯淡了……', '', 66384),
(302572, 'zhCN', '呃……谁知道当个远行者居然这么耗费体力？', '', 66384),
(302570, 'zhCN', '', '你把葡萄都踩好了！现在，你可以去雪莉那儿买些魔法酵母，或者……等上几年，让它自己发酵……', 66384),
(302569, 'zhCN', '我好像干掉了两个，但敌人还是源源不断地涌来……', '我好像干掉了两个，但敌人还是源源不断地涌来……', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(302567, 'zhCN', '他们的力量太黑暗了……我根本无法集中精神……', '他们的力量太黑暗了……我根本无法集中精神……', 66384),
(302564, 'zhCN', '我们试着想挡住他们……但他们的力量太强大了……', '我们试着想挡住他们……但他们的力量太强大了……', 66384),
(302557, 'zhCN', '你希望猎物的挣扎有多激烈？', '', 66384),
(302554, 'zhCN', '<一团迷雾笼罩了你的意识。此刻，你透过他人的双眼在观察。你变成了一个孩子，一个哈籁尼尔孩子。\n\n环顾四周，你看到远方有一座山峰，一棵巨树。你的族人正在收拾行装，准备远行。你能感受到内心的忐忑，但同时又充满了兴奋与对冒险的渴望。>', '<一团迷雾笼罩了你的意识。此刻，你透过他人的双眼在观察。你变成了一个孩子，一个哈籁尼尔孩子。\n\n环顾四周，你看到远方有一座山峰，一棵巨树。你的族人正在收拾行装，准备远行。你能感受到内心的忐忑，但同时又充满了兴奋与对冒险的渴望。>', 66384),
(302551, 'zhCN', '<一座水池的幻象浮现在你的脑海中，从背景中的成年哈籁尼尔来看，这应该是一处圣地。\n\n你看到哈籁尼尔的孩子们正在追逐你刚刚送给孩童之灵的皮球，他们在水池边玩耍，直至一个大人把他们轰走。\n\n这个幻象象征着生命的诞生与人生旅途的起点。>', '<一座水池的幻象浮现在你的脑海中，从背景中的成年哈籁尼尔来看，这应该是一处圣地。\n\n你看到哈籁尼尔的孩子们正在追逐你刚刚送给孩童之灵的皮球，他们在水池边玩耍，直至一个大人把他们轰走。\n\n这个幻象象征着生命的诞生与人生旅途的起点。>', 66384),
(302549, 'zhCN', '<虽然孩童之灵并未开口，但你仍感受到一股纯真无邪又充满冒险精神的气息。\n\n你的脑海中慢慢浮现出一个形状，那是一只遗落在附近灌木丛中的皮球。>', '<虽然孩童之灵并未开口，但你仍感受到一股纯真无邪又充满冒险精神的气息。\n\n你的脑海中慢慢浮现出一个形状，那是一只遗落在附近灌木丛中的皮球。>', 66384),
(302548, 'zhCN', '啊，没错！又一块送上门的新鲜好肉，正好端上我的餐桌。现身吧，不然我就亲自把你揪出来！', '', 66384),
(302547, 'zhCN', '这不是重点——', '', 66384),
(302546, 'zhCN', '那些密教徒出现得太快了！我们根本来不及组织防御！', '那些密教徒出现得太快了！我们根本来不及组织防御！', 66384),
(302545, 'zhCN', '', '是吗？看看她的皮肤，乌布里克，烙印仪式成功了。', 66384),
(302543, 'zhCN', '<这座古老的祭坛上刻画着哈籁尼尔孩童嬉戏的画面。>', '<这座古老的祭坛上刻画着哈籁尼尔孩童嬉戏的画面。>', 66384),
(302542, 'zhCN', '蕾欧娜，你竟敢直接跳进传送门，真是鲁莽。', '', 66384),
(302539, 'zhCN', '我在摇篮中聆听女神的话语，守护着她向我们倾诉的回忆。\n\n长久以来，总有和我一样的人负责守护回忆，将它们传承给值得托付的人。\n\n有些回忆过于危险，不该让任何人得知。', '', 66384),
(302522, 'zhCN', '', '我绝不会失去他！', 66384),
(302519, 'zhCN', '$p，圣光既会回应血色十字军的祈求，也会回应我、法奥或是泰罗索斯男爵的呼唤，这实在令我费解。', '', 66384),
(302495, 'zhCN', '', '你挥动了利刃。我操纵了你的意志。', 66384),
(302494, 'zhCN', '你……杀了她……', '', 66384),
(302492, 'zhCN', '', '没错，你眼前的就是金雾村的第一个酿酒缸，艾蕾恩的第一桶酒就是用它酿的。\n\n哦，当然。你可以摸它，甚至可以用它！\n\n先“以貌取人”，然后猜猜访客酿出的酒会是什么味道，这可是件乐事。去弄些葡萄来试试身手吧！', 66384),
(302490, 'zhCN', '', '自那以后，她酿出了成百上千种不同的美酒——但凡是认识她的人都知道，那款经典、纯粹的红酒，至今仍是她的心头好。', 66384),
(302489, 'zhCN', '', '将酵母加入缸中后，艾蕾恩的第一款佳酿便诞生了。', 66384),
(302488, 'zhCN', '', '作为你旅途体验的一环，你可以从杂货商雪莉那里买到一包这种神奇酵母。我们承诺包你满意，否则全额退款。', 66384),
(302487, 'zhCN', '', '发酵本该耗时数年。但我们的酿酒师研制出一种特殊酵母，它能在不牺牲风味的前提下，极快地完成发酵。', 66384),
(302486, 'zhCN', '', '为了遵循古法，她随后跳入缸中，用双脚将它们踩碎、混合。', 66384),
(302485, 'zhCN', '', '她酿造第一桶酒时，亲手挑选了十颗最完美的葡萄。', 66384),
(302484, 'zhCN', '', '旅店老板艾蕾恩是我们庄园的奠基人。', 66384),
(302475, 'zhCN', '<这个巨大的石缸是金雾村悠久酿酒史的见证。>', '', 66384),
(302474, 'zhCN', '<缸里是令人愉悦的碎葡萄混合物。\n\n但若不加速发酵，它在很长一段时间里都只能是葡萄汁……>', '', 66384),
(302473, 'zhCN', '<缸里已经装满了葡萄和酿造新酒的基础材料。\n\n现在需要有人进去跳一跳，把葡萄都踩烂！>', '', 66384),
(302471, 'zhCN', '<这个巨大的石缸是金雾村悠久酿酒史的见证，一件无价且坚固的传家之宝。\n\n它至今仍在使用。游客们可以亲身体验传统的酿酒工艺——跳进缸里，用脚踩碎葡萄！\n\n要开始的话，你大概需要十捆葡萄……>', '', 66384),
(302464, 'zhCN', '', '我们走着瞧吧！', 66384),
(302463, 'zhCN', '你从我这里什么都别想得到！', '你从我这里什么都别想得到！', 66384),
(302460, 'zhCN', '愿这烛火长明，既是为了那些挺身抵御天灾的勇士，也是为了那些在浩劫中逝去的生灵。', '愿这烛火长明，既是为了那些挺身抵御天灾的勇士，也是为了那些在浩劫中逝去的生灵。', 66384),
(302457, 'zhCN', '', '找个密教徒抓起来。我们在月亮圣殿后面碰头。', 66384),
(302453, 'zhCN', '', '只要有可能，$p——无论结果如何。\n\n或许有些根须还能得救。或许根须能重新长成一棵巨树。这样一棵树或许能保留我毕生奉献之物的一丝精华。\n\n又或许什么都没有，除了终有一日能坦然赴死的解脱感，因为我知道自己已竭尽全力。', 66384),
(302450, 'zhCN', '', '嘿，从我身上下去，你这黏糊糊的鳞片杀手！', 66384),
(302442, 'zhCN', '', '直到群星也黯淡……', 66384),
(302437, 'zhCN', '他跑了！正朝萨拉斯学院那边去了！', '', 66384),
(302423, 'zhCN', '', '谢谢，吉加尼姬！我们走，金克斯。', 66384),
(302422, 'zhCN', '', '别急，安妮，我会给你留一份的。', 66384),
(302421, 'zhCN', '', '香！这是烧烤咬鳞者吗？', 66384),
(302420, 'zhCN', '', '但比死寂更折磨人的是那种“确知”。那种确信我此生只能感受到死寂的认知。\n\n这感觉很像恐惧。但恐惧是关于可能发生的事——关于你不希望发生的事。而泰达希尔没了，我永远都不可能再……\n\n那种……“确知”，是我无法言喻的重担。', 66384),
(302418, 'zhCN', '', '是死寂，$p。泰达希尔不会对我“开口”，但我能听见她的声音，就如同你听见自然环境的声响。此刻我虽然正在与你交谈，但我能听见附近的潜行者，也能听见潺潺的流水声。\n\n泰达希尔原本就是那样的，而且不止如此——她成了我思绪中密不可分的一部分。多年以来皆是如此，然后……归于虚无。', 66384),
(302416, 'zhCN', '', '啊，他彻底垮掉了。', 66384),
(302414, 'zhCN', '', '我得全神贯注才能追踪他的圣光。我们先回营地再说。', 66384),
(302413, 'zhCN', '', '卡勒姆是我的，我也是他的。我要带他回家。', 66384),
(302412, 'zhCN', '', '你知道我们这个种族的寿命有多长吗？我们虚度了多少宝贵的时光，还美其名曰“耐心”？从遇见卡尔的那一刻起，我就发誓再也不浪费任何一瞬。我绝不会在这里失去他。', 66384),
(302404, 'zhCN', '<阿斯崔和赛多娜似乎没有察觉到你的幻影。>\n\n<你会对自己说些什么？>', '<阿斯崔和赛多娜似乎没有察觉到你的幻影。>\n\n<你会对自己说些什么？>', 66384),
(302380, 'zhCN', '这蠢货太强了！', '', 66384),
(302379, 'zhCN', '想得美。后会有期。', '', 66384),
(302378, 'zhCN', '', '还没完！我不能就这么完了！', 66384),
(302377, 'zhCN', '你这家伙还挺扎手。', '', 66384),
(302376, 'zhCN', '', '好饿……脑子转不动了。', 66384),
(302375, 'zhCN', '不！不！', '', 66384),
(302374, 'zhCN', '', '我可不是那么容易倒下的。', 66384),
(302373, 'zhCN', '哈！这点伤痛只会让我更强大。', '', 66384),
(302372, 'zhCN', '我不会让她失望的。你等着瞧。', '', 66384),
(302371, 'zhCN', '呃啊。我早就想来一场真正的战斗了。', '', 66384),
(302370, 'zhCN', '我会把你吃干抹净，等着瞧吧。', '', 66384),
(302369, 'zhCN', '你永远都挣脱不了这副枷锁。', '', 66384),
(302368, 'zhCN', '', '黎明将至，$c。', 66384),
(302367, 'zhCN', '我必将复仇！', '', 66384),
(302366, 'zhCN', '这家伙的根基开始松动了……', '', 66384),
(302365, 'zhCN', '这家伙还会回来的……', '', 66384),
(302364, 'zhCN', '', '我不喜欢靠得这么近……', 66384),
(302363, 'zhCN', '我们换个策略……', '', 66384),
(302362, 'zhCN', '', '还没到时候。', 66384),
(302361, 'zhCN', '我会回来的。我永远都会。', '', 66384),
(302360, 'zhCN', '', '真精彩。', 66384),
(302359, 'zhCN', '呀嗒嗒嗒嗒嗒……', '', 66384),
(302358, 'zhCN', '有两下子。', '', 66384),
(302357, 'zhCN', '', '暂时受挫而已。', 66384),
(302356, 'zhCN', '', '你避不开低语的……', 66384),
(302355, 'zhCN', '虚空时刻注视着……', '', 66384),
(302354, 'zhCN', '', '启动再校准程序！', 66384),
(302353, 'zhCN', '呸！看来我得调整一下交战模型了。', '', 66384),
(302352, 'zhCN', '', '尽管逃吧，小火花……我喜欢追逐猎物的感觉！', 66384),
(302351, 'zhCN', '我乃永不熄灭的余烬——我的烈焰终将重燃！', '', 66384),
(302335, 'zhCN', '抓到你了，笨蛋！', '', 66384),
(302334, 'zhCN', '很惊讶吧？希望如此。', '', 66384),
(302333, 'zhCN', '', '我扎到你了！', 66384),
(302332, 'zhCN', '这是什么？一只迷路的小崽子？', '', 66384),
(302330, 'zhCN', '', '我要把魔法从你的血肉里活活剥出来！', 66384),
(302329, 'zhCN', '黑暗中的闪光……我必须品尝它的味道！', '', 66384),
(302328, 'zhCN', '', '你是否感觉到了那股彻骨的寒意？', 66384),
(302327, 'zhCN', '死神来了！', '', 66384),
(302325, 'zhCN', '我要把你的尸体献给萨拉塔斯！', '', 66384),
(302324, 'zhCN', '站住，把命留下！', '', 66384),
(302323, 'zhCN', '我要把你吞噬殆尽！', '', 66384),
(302322, 'zhCN', '你倒是能给深陷之坑添点好料。', '', 66384),
(302321, 'zhCN', '', '燃烧吧，异端！', 66384),
(302320, 'zhCN', 'Archenon poros，罪人！', '', 66384),
(302319, 'zhCN', '这家伙会把你送进坟墓！', '', 66384),
(302318, 'zhCN', '这一击，就是你的末日！', '', 66384),
(302317, 'zhCN', '', '现在才想躲？已经晚了！', 66384),
(302316, 'zhCN', '你的行踪真是太好掌握了，猎物。', '', 66384),
(302315, 'zhCN', '', '呱啊啊啊！！！', 66384),
(302314, 'zhCN', '咔嚓咔嚓。', '', 66384),
(302313, 'zhCN', '', '你的死期到了。', 66384),
(302312, 'zhCN', '砸死你！', '', 66384),
(302311, 'zhCN', '来吧，让我们的兵刃分个高下。', '', 66384),
(302310, 'zhCN', '', '这下你可上我的当了……', 66384),
(302309, 'zhCN', '', '抓到你了！一切尽在我的掌握。', 66384),
(302308, 'zhCN', '你躲不过虚空的追踪！', '', 66384),
(302306, 'zhCN', '', '瞧我们发现了什么？更多零件！', 66384),
(302305, 'zhCN', '哈！高超的预判造就了完美的伏击！', '', 66384),
(302304, 'zhCN', '', '烈焰都听我号令，你也应当如此！', 66384),
(302303, 'zhCN', '烈焰永远先发制人！', '', 66384),
(302299, 'zhCN', '', '我没有忘记过去，但如果我们拒绝把握眼前的机会，就无法获得成长。', 66384),
(302284, 'zhCN', '', '我……庆幸自己看走了眼。庆幸我们能并肩抗击真正的敌人，并找回了一位久违的老盟友。', 66384),
(302283, 'zhCN', '没错，沙德拉的归来是天大的喜事。也许她需要一位祭司。或者两位？哈！我们得赶紧报告酋长！', '', 66384),
(302278, 'zhCN', '', '当然会了，$p！我是护根者，泰达希尔理应由我照顾，当然是我的责任。\n\n我一次又一次地告诉自己，我不可能预料到根须之上的威胁，谁都不可能料想得到！在某种程度上，我知道这的确是事实。\n\n可我依然是一名护根者，我将自己毫无保留地奉献给了泰达希尔。只要我还一息尚存，就不该让那棵树化为灰烬。', 66384),
(302273, 'zhCN', '', '这边，$n！', 66384),
(302270, 'zhCN', '', '我们急需组建一支搜救小队！我绝对不能失去他。', 66384),
(302241, 'zhCN', '', '奥威娜调节着她的过滤器，她愿意再次承受裂隙的沉重压迫。', 66384),
(302236, 'zhCN', '追击他们，上马！', '', 66384),
(302230, 'zhCN', '哈哈。难怪上级会选择你执行这次关键任务。你让所有困难都显得轻而易举。', '', 66384),
(302229, 'zhCN', '', '<莉亚德琳怔怔地望着下方的地面。>\n\n她跳下去了，没有丝毫迟疑或犹豫。\n\n就在刚才，她还说这上面除了“飞鸟和荆棘”什么都没有。\n\n但在埃基尔松开口之后，我相信她真正的信念已经浮出水面。\n\n那么，你呢……你打算跟着她跳吗？', 66384),
(302220, 'zhCN', '', '哈尔拉兹是现存最强大的洛阿之一。\n\n我可没傻到去和这么强大的力量为敌。我们联手，必将所向披靡！', 66384),
(302213, 'zhCN', '', '我们虽然没有祭坛，但也应该没问题。先把獠牙放上去。', 66384),
(302207, 'zhCN', '', '虚空夺走了我的一切。现在它又冲着银月城剩下的一切来了。', 66384),
(302205, 'zhCN', '', '$n！他们还好吗？神龛那边到底发生什么了？', 66384),
(302202, 'zhCN', '我感觉好多了。有希望总是好的。我现在就去。', '', 66384),
(302195, 'zhCN', '又见面了，$n。\n\n能见到老朋友感觉真好。当然，还有像赛多娜这样的新朋友。修补过去的裂痕终归是件好事。这也是海尔兰对我们的期望。\n\n我这儿还有些鬼花茶，要来点吗？', '', 66384),
(302193, 'zhCN', '多亏有你，我们都还撑得住。我祈祷在未来的战火中，你能与我们同在。', '', 66384),
(302187, 'zhCN', '', '他是我的！', 66384),
(302186, 'zhCN', '', '我要把你安全护送回家，卡尔！', 66384),
(302184, 'zhCN', '哇啊啊啊啊！', '', 66384),
(302183, 'zhCN', '哈！骗到你了。等等……那是什么？', '', 66384),
(302182, 'zhCN', '算你走运，$r。', '', 66384),
(302181, 'zhCN', '放了我，让我们看看谁才是“猎物”。', '', 66384),
(302179, 'zhCN', '', '把中了毒的受害者都立刻送到我这儿来。', 66384),
(302176, 'zhCN', '', '我们又见面了，$n。你带来的那种茶真的帮了我大忙。它完美取代了我以前喝的那些会把牙齿染黄的酒。\n\n阿斯崔偶尔会送些鬼花叶子过来，你要是感兴趣的话可以试试。他——抱歉——阿斯崔已经成为我希望经常见到的朋友。\n\n对了，既然是你把那封信从虚空怪物手里夺回的……所以你想看的话，我完全没有异议。信件就放在楼上的床铺上。', 66384),
(302174, 'zhCN', '', '达奇看起来好多了，可以上路了，但我们必须拿到解药！', 66384),
(302172, 'zhCN', '我得歇会儿。那段旅程可真够累的。', '', 66384),
(302168, 'zhCN', '', '我们头一回召唤艾林莎兰，失败了。但不要紧！我估摸着我知道哪儿出问题了。\n\n艾林莎兰应该是一条巨蛇。一条超——级大的蛇！所以，我们八成是需要更多的天之裂片。也许……我不知道。五百个！五百个天之裂片！这样一来，艾林莎兰那家伙想注意不到都难。\n\n但看在艾林哈籁的份上，我上哪儿去弄那么多……？', 66384),
(302167, 'zhCN', '阿纳伊斯……我求你了。离远点。', '', 66384),
(302166, 'zhCN', '', '哦，他是你的人吗？可惜我还没尽兴呢。', 66384),
(302162, 'zhCN', '', '本次策略相当直接明了。我们找到卡尔的位置，将他制伏，然后强行带回银月城。到了那里再制定后续计划。\n\n如果情况需要的话，我会亲手把英普利亚淹死在太阳之井里。你愿意与我并肩作战吗？', 66384),
(302154, 'zhCN', '什么？她可能正漂流在无垠的虚空中，也可能流落到了这颗星球的某个角落。', '', 66384),
(302153, 'zhCN', '', '乌布里克！蕾欧娜消失在了一个不稳定的虚空传送门里。快告诉我你一定有办法把她找回来。', 66384),
(302135, 'zhCN', '', '不，$n，你已被女神选中，注定与我们有着不同的命运。按照女神的旨意，你的旅程将在哈籁恩达尔之外，在根系之上的世界展开。', 66384),
(302124, 'zhCN', '感谢你的庇护，哈尔拉兹。', '', 66384),
(302123, 'zhCN', '邪枝部族还在继续酿造更烈的毒液。它们闻起来有蜘蛛的味道。你的狩猎得继续下去了。', '', 66384),
(302121, 'zhCN', '啊，你想看穿无形之物……一场有趣的狩猎在等着你呢。', '', 66384),
(302105, 'zhCN', '哈谢之路漫长而艰险，充满了试炼和危难。\n\n“哈舒拉”就是哈谢的侍从。他们追随哈谢的道路，为其而战，也为其而死。\n\n通常来说，呃，有两位侍从。但是，你看，我是个老头子了，我们的士兵又都受了伤，祖尔加也绝不会同意……\n\n我猜，莉亚德琳就只能当第二位了。\n\n<金杜鲁不确定地笑了笑。>\n\n哈舒拉的荣耀居然落到了一位血精灵头上，希望这不会进一步激怒洛阿神灵……', '', 66384),
(302101, 'zhCN', '哈谢之路漫长而艰险，充满了试炼和危难。\n\n“哈舒拉”就是哈谢的侍从。他们追随哈谢的道路，为其而战，也为其而死。\n\n通常来说，呃，有两位侍从。但是，你看，我是个老头子了，我们的士兵又都受了伤，祖尔加也绝不会同意……\n\n我猜，莉亚德琳就只能当第二位了。\n\n<金杜鲁不确定地笑了笑。>\n\n一个被授予“哈舒拉”荣耀的精灵。这年头真是什么事都有。', '', 66384),
(302100, 'zhCN', '我们尝试过你提议的方法，但我依然坚持自己的理念。\n\n对我豢养的这群野兽而言，只有最凶猛残暴者才能存活繁衍。', '', 66384),
(302098, 'zhCN', '', '亮刀吧。', 66384),
(302097, 'zhCN', '', '来跳舞吧。', 66384),
(302096, 'zhCN', '', '当心你的背后。', 66384),
(302092, 'zhCN', '菲多费库斯用充满渴望的大眼睛看着你。', '', 66384),
(302084, 'zhCN', '', '“直至群星寂灭。”我绝不是在开玩笑，我们一定会找到他。', 66384),
(302083, 'zhCN', '', '他的盾牌——沾满了鲜血。该死，必须继续搜索。', 66384),
(302082, 'zhCN', '', '卡尔的火绒盒——留下了激战的痕迹。她在强迫他与人搏斗。', 66384),
(302081, 'zhCN', '', '我这样还怎么上课啊？', 66384),
(302080, 'zhCN', '', '他们注定死亡……', 66384),
(302078, 'zhCN', '', '求你了，这次一定要成功！', 66384),
(302077, 'zhCN', '', '不行！必须找其他方法。', 66384),
(302076, 'zhCN', '鱼儿不仅是美味，更是赏心悦目的宝贝。你难道不觉得阳须非常漂亮吗？', '', 66384),
(302074, 'zhCN', '', '控制住它，让我来移除这些金属碎片。', 66384),
(302069, 'zhCN', '菲多害怕得发出呜咽。', '', 66384),
(302062, 'zhCN', '我说，训练条狗吧。我还说，能有多难呢。\n\n我真该管住我这张嘴。', '', 66384),
(302061, 'zhCN', '蛮锤部族的地方，鹰巢山，就在这条路上去！那里经常有矮人和联盟的人来攻击他们。\n\n我不是祭司，从不去沙德拉洛。现在有些人觉得那地方被诅咒了，邪门得很。\n\n<欧戈贝尔迅速做了几个手势，像是在驱邪避祸。>\n\n我提都不想提。你上别处打听去吧。', '', 66384),
(302060, 'zhCN', '沙德拉洛？不算近。\n\n隐匿石在北边。离沙德拉洛远点，邪枝部族现在控制着那些地方。', '', 66384),
(302058, 'zhCN', '祖瓦沙离沙德拉洛非常近……没错。\n\n<调和者亚曼伽似乎在仔细打量你，皱起了眉头。>\n\n但我们现在不谈这个。洛阿已经死了。', '', 66384),
(302055, 'zhCN', '', '我会前去探路。别耽误太久——时机就是一切。', 66384),
(302051, 'zhCN', '', '追随召唤。', 66384),
(302050, 'zhCN', '你的脑海深处响起若有若无的歌声，随之感到微微晕眩。', '你的脑海深处响起若有若无的歌声，随之感到微微晕眩。', 66384),
(302048, 'zhCN', '菲多费库斯拼命地抓挠着自己的肋腹部。', '', 66384),
(302045, 'zhCN', '菲多费库斯好奇地歪起脑袋。', '', 66384),
(302042, 'zhCN', '<真菌人摇了摇头。>\n\n小孢子们……', '', 66384),
(302021, 'zhCN', '', '斥候奈芬娜目不转睛地注视着火焰。', 66384),
(302020, 'zhCN', '', '这里的虚空能量过于浓烈。哪怕是现在，我都能感觉到它在撕扯我的灵魂本源……', 66384),
(302015, 'zhCN', '', '我们或许阻止了它进化成更加恐怖的存在。', 66384),
(302014, 'zhCN', '', '那个生物在不断积蓄能量……靠吞噬我们众人的精华来壮大自己。', 66384),
(302010, 'zhCN', '啊哼。我们的帮手来了。', '', 66384),
(302009, 'zhCN', '真是毒辣！我想不到你居然……', '', 66384),
(302008, 'zhCN', '……于是我就跟他说，“你的耳朵是挺长，可我的尾巴还要长！”', '', 66384),
(302007, 'zhCN', '现在，去狩猎吧！但千万小心，免得你自己沦为猎物。', '', 66384),
(302006, 'zhCN', '你对他们心慈手软，他们就会不遗余力地争取优势。', '', 66384),
(302005, 'zhCN', '多加小心，勇士，我们的魔法和猎物几乎一样致命。', '', 66384),
(302003, 'zhCN', '我一直都在追踪这个世界所面临的威胁。他们可谓是穷凶极恶。', '', 66384),
(302002, 'zhCN', '到港口附近找我，我会让你见识一下新的道路……', '', 66384),
(302001, 'zhCN', '我的同事正在想方设法地保护这座城市。而我自有办法。', '', 66384),
(302000, 'zhCN', '', '请原谅我的无礼，可我得请你暂时离开了。趁着法术还没失效，我们还要聊上许多事情……还要共饮一瓶稀罕的美酒。', 66384),
(301999, 'zhCN', '', '谢谢你，旅行者。即便只有几个小时，我也重新获得了感官。', 66384),
(301997, 'zhCN', '', '成功了。我……又一次完整了。哪怕只有片刻。我能感觉到海风的吹拂。', 66384),
(301996, 'zhCN', '', '……完成了。但是——', 66384),
(301995, 'zhCN', '', '好了。现在是最棘手的部分。Anar\'sin arkhana！Anar\'endal belore！', 66384),
(301994, 'zhCN', '', '很好，现在用水银来绘制仪式法阵。', 66384),
(301992, 'zhCN', '', '那可不。加肯定想他想得不行了。', 66384),
(301991, 'zhCN', '我们把萨满带回家。', '', 66384),
(301990, 'zhCN', '你小子可是在玩火，达克。算你走运，你妈妈是我最疼的姐妹。', '', 66384),
(301989, 'zhCN', '就是想让大伙儿松快点。日子再难，笑一笑，总能盼到天亮不是？', '', 66384),
(301988, 'zhCN', '你这是在干嘛？你得让大伙儿知道，酋长我罩得住场子。', '', 66384),
(301987, 'zhCN', '如今有沙德拉神灵相助，我们对付起邪枝巨魔的毒素来，可就得心应手多了！', '', 66384),
(301986, 'zhCN', '从迈萨拉冒出来的毒物和诅咒都快把我们压垮了。\n\n但我会拼尽全力，能救一个是一个。', '', 66384),
(301985, 'zhCN', '', '这样下去我们是找不到她的。先回啸影山脊吧。想把她找回来，我们非得请乌布里克帮忙不可。', 66384),
(301984, 'zhCN', '', '该死！她不在这儿。传送门的落点肯定不稳定。', 66384),
(301983, 'zhCN', '', '准备好了没，$r？', 66384),
(301982, 'zhCN', '就是它了。', '', 66384),
(301981, 'zhCN', '天晓得他们会从哪个旮旯里钻出来！', '', 66384),
(301980, 'zhCN', '迈萨拉就在跟前。我们得盯紧了，那地方进进出出的东西一个都不能放过。', '', 66384),
(301977, 'zhCN', '看来那些随暗谷女士远征归来的人都有些疲惫，但好在虚影风暴的编目工作总算可以继续了。\n\n女士似乎从她的旅途中带回了一些奇特的样本，但其他人却对此讳莫如深。', '', 66384),
(301971, 'zhCN', '', '不然呢？我要么请这位英雄帮忙，要么和疯癫的密教徒一个下场。', 66384),
(301970, 'zhCN', '', '真聪明啊，塔兰德拉。', 66384),
(301969, 'zhCN', '', '将你收集的龙血涂在蜡烛上。', 66384),
(301961, 'zhCN', '', '在你行侠仗义将我击倒之前，如果能听我解释几句，你愿不愿意相信我？', 66384),
(301960, 'zhCN', '', '她任由自己被那股力量吸了进去。快——趁传送门关闭前追上去！', 66384),
(301959, 'zhCN', '', '蕾欧娜，等等！', 66384),
(301958, 'zhCN', '', '我们需要浓度更高的虚空能量！', 66384),
(301957, 'zhCN', '', '这还不够。', 66384),
(301953, 'zhCN', '', '这场战斗令人精疲力尽，却也是十分痛快！现在所有神灵都加入了我们的事业。到外面来找我，我们要一起决定未来的道路。', 66384),
(301950, 'zhCN', '沉住气。你想要什么？', '', 66384),
(301949, 'zhCN', '不，我的小家伙——那正是她盼着的。', '', 66384),
(301948, 'zhCN', '', '你想想，我为你回家高兴，妈妈她……会不开心吗？', 66384),
(301946, 'zhCN', '', '爸爸！你得听我说啊。', 66384),
(301945, 'zhCN', '', '爸爸。', 66384),
(301944, 'zhCN', '我懂，朋友。美丽与痛苦总是相伴相生。', '', 66384),
(301943, 'zhCN', '我……我保证这绝对符合道德规范！其他时候它们都能得到精心的呵护！', '', 66384),
(301942, 'zhCN', '这些浮龙都要被打一顿吗？没有牺牲就没有收获。', '', 66384),
(301941, 'zhCN', '', '我们来到这片丰饶而又诡谲的土地，是为了研究这些巨石遗迹，并采集样本。\n\n我们本已对虚影风暴中无处不在的掠食者做好了准备，却依然防不胜防。陪同我的朗多雷斥候一个接一个地被感染了。他们变得焦躁不安，四散奔逃，消失在蜕躯之原的深处。\n\n我担心，即便他们能从野兽的利爪下幸存，最终也难逃这种……病原体的侵蚀。', 66384),
(301939, 'zhCN', '只要我一息尚存，我们村子就会以无上荣耀，永远铭记坦辛之名。', '', 66384),
(301929, 'zhCN', '<只有你能察觉到你自己的这一面。>\n\n<你会对自己说些什么？>', '<只有你能察觉到你自己的这一面。>\n\n<你会对自己说些什么？>', 66384),
(301928, 'zhCN', '能和这小家伙一起回家，真好，可难过的是，只剩我一个了。是你的援手改变了这一切，$r。', '', 66384),
(301918, 'zhCN', '', '我不知道这些密教徒要我们的莎台干什么。我保证不会被发现的。', 66384),
(301909, 'zhCN', '', '就是这样。这样有用吗？如果没效果，我可以调整咒语。\n\n抱歉，我在这方面还算新手……那些在达拉然研发的远古法术现在可不好弄到手。', 66384),
(301907, 'zhCN', '', '我不明白。你和哈杜伦所见的一切，我早已了然于胸。那么，祖尔阿沙所暗示的奇耻大辱究竟何在？\n\n既然你已寻得钥匙碎片，最后的回忆便将向我们展露。或许，我们两人都能在此处找到答案。', 66384),
(301905, 'zhCN', '还没完……你的枷锁将我们双双束缚，赶紧终结这一切！', '', 66384),
(301903, 'zhCN', '待在这儿。别乱跑。', '', 66384),
(301897, 'zhCN', '我们把这儿收拾干净，然后去找坦辛。', '', 66384),
(301895, 'zhCN', '', '你知道我不会干那种事。', 66384),
(301894, 'zhCN', '我的爱永不磨灭。', '', 66384),
(301893, 'zhCN', '我向我妻子起誓：我们的女儿将沐浴着她的力量茁壮成长。', '', 66384),
(301892, 'zhCN', '', '虚影风暴可不是什么休憩的好地方。\n\n但它对我们每个人都造成了沉重的负担。我只要一离开这个帐篷，这里的虚空之力几乎就要将我吞噬。所以，我只能留在这里，尽我所能地发挥作用。\n\n为了银月城。', 66384),
(301878, 'zhCN', '这感觉像是对复仇的炽热渴望。这绝不是海尔兰的情感。它太过残暴，太过恶毒。', '', 66384),
(301875, 'zhCN', '我感觉到了……怒火。让我们再仔细研究一下那个回响。', '', 66384),
(301825, 'zhCN', '', '塔兰德拉，这是谁？又是你的成果吗？', 66384),
(301824, 'zhCN', '', '啊！你来了。你——哦，天哪。', 66384),
(301812, 'zhCN', '这些教徒自以为聪明，但我的头脑和我的长矛一样锐利。', '', 66384),
(301811, 'zhCN', '<告解者勒维克的袍子被利落地切开。这绝非野兽造成的粗糙创口，而是经验丰富的剑士展现的精湛剑术。\n\n阴影在与他前额融合的诡异金属表面急速穿梭。>', '<告解者勒维克的袍子被利落地切开。这绝非野兽造成的粗糙创口，而是经验丰富的剑士展现的精湛剑术。\n\n阴影在与他前额融合的诡异金属表面急速穿梭。>', 66384),
(301810, 'zhCN', '<利安德隆的胸甲多处被洞穿。这些伤口看起来像阿拉希步枪的杰作。\n\n金属条带螺旋状缠绕在他的剑臂上。阴影在这些诡异金属的棱角间跳跃闪烁。>', '<利安德隆的胸甲多处被洞穿。这些伤口看起来像阿拉希步枪的杰作。\n\n金属条带螺旋状缠绕在他的剑臂上。阴影在这些诡异金属的棱角间跳跃闪烁。>', 66384),
(301809, 'zhCN', '嘿！快来救我出去！', '', 66384),
(301807, 'zhCN', '', '只有傻瓜才敢对恶齿部族动武！', 66384),
(301805, 'zhCN', '', '我告诉佩尔娜是你让我一个人行动的！', 66384),
(301804, 'zhCN', '', '我看见他了，$n！他们把艾达戈拖进了地穴！', 66384),
(301801, 'zhCN', '', '纳洛拉克向我们传授了顽强不屈的精神，顽强地对抗悲剧，顽强地对抗心碎。\n\n但我不能让艾达戈的回忆就此消失，或蒙受耻辱。', 66384),
(301796, 'zhCN', '', '有本事的话就跟上吧，$n！', 66384),
(301790, 'zhCN', '', '如果这是你的决定，那我别无选择，只能听命了，年轻的领袖。', 66384),
(301789, 'zhCN', '', '这位勇士会护送我前往村子。佩尔娜，你留下来保护其他族人。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(301785, 'zhCN', '', '艾达戈被丢在了村子里！他怎么才能安详地离去呢？', 66384),
(301781, 'zhCN', '你是个英明的领袖，利拉祖。你的父母都会为你骄傲的。', '', 66384),
(301780, 'zhCN', '', '我不会再要求你放下职责了，佩尔娜。你今天给我上了一课。', 66384),
(301779, 'zhCN', '', '作为你的荣誉守卫，保护你是我们的职责——就像你保护整个部族一样。', 66384),
(301763, 'zhCN', '什么……', '', 66384),
(301762, 'zhCN', '', '回到村子里后，我才明确意识到，我不该那么鲁莽地以身犯险。', 66384),
(301753, 'zhCN', '', '谢谢你的帮助，$n。我们该回去了。', 66384),
(301748, 'zhCN', '', '你是对的，艾达戈。对不起。回去之后，我会向其他人好好道歉的。', 66384),
(301747, 'zhCN', '', '可艾达戈……', 66384),
(301734, 'zhCN', '你是恶齿部族的领袖！你必须像巨熊一样顽强不屈，面对自己的悔恨也不能屈服。', '', 66384),
(301729, 'zhCN', '这是药茶吗？', '', 66384),
(301727, 'zhCN', '能看到你真是太好了，利拉祖，可你身为领袖，冒这么大风险来这里实在不妥！', '', 66384),
(301726, 'zhCN', '啊……好多了。等等，你和那孩子回来找我了？她到底在想什么？', '', 66384),
(301725, 'zhCN', '', '是杀手。', 66384),
(301724, 'zhCN', '', '但伊利达雷并非听命行事的士兵。我们是猎手。', 66384),
(301723, 'zhCN', '', '纳鲁想招募他，去对抗纳鲁眼中艾泽拉斯最大的威胁。', 66384),
(301722, 'zhCN', '', '这么说，是纳鲁找到了伊利丹，并警告他提防虚空？', 66384),
(301721, 'zhCN', '虚空夺走了你。正如它夺走海尔兰一样。', '', 66384),
(301719, 'zhCN', '', '<戴着眼镜的女士警惕地打量着你的武器。>\n\n在你对我表现得像个“狂热的冒险者”要替天行道之前，容我解释几句。\n\n对，我是个通灵师。我在购物清单上隐瞒了关键的细节，是为了增加你伸出援手的几率。但我向你保证，我绝无歹意。\n\n你眼前的女妖曾经是一名远行者，她是奎尔萨拉斯的英雄，现在却痛苦缠身。\n\n就让我完成这个仪式吧。事成之后，不管是拘捕我、消灭我还是怎么着，都随你的便。\n\n我们成交吗？', 66384),
(301715, 'zhCN', '', '等我们回去再谈。挖掘过往的秘密，总会招来各方的觊觎。', 66384),
(301714, 'zhCN', '我的宿命，还轮不到你这纳鲁来指手画脚。', '', 66384),
(301713, 'zhCN', '', '虚空是远比他们更可怕的敌人。而直面虚空，便是你的宿命。', 66384),
(301712, 'zhCN', '妙极了，说得好像他们还不够强似的。', '', 66384),
(301711, 'zhCN', '', '伊利丹，你的敌人远比萨格拉斯和他的燃烧军团更加强大。', 66384),
(301696, 'zhCN', '$p，我本希望父亲能重新拿起他的盾牌，再次担起他作为守护者的职责。\n\n但他显然还没准备好。也许，他永远都准备不好了。', '', 66384),
(301690, 'zhCN', '', '暗谷女士最后凝望了一眼这片景色，深深地叹了口气。', 66384),
(301689, 'zhCN', '', '好吧，我想我该告辞了。再见，感谢你的帮助。', 66384),
(301688, 'zhCN', '', '我已经把其他人送回了伏里吉恩那里，还挑选了一部分我的收藏品供他编目。我相信他会很高兴的。', 66384),
(301687, 'zhCN', '', '邪枝巨魔用强力的诅咒图腾玷污了埃基尔松的神殿。这些图腾正将埃基尔松强行拖拽至此，企图将她囚禁。\n\n埃基尔松正在反抗，而她的力量眼看就要把阿塔阿曼撕成碎片！\n\n刻不容缓！立刻摧毁那些被诅咒的图腾，在邪枝巨魔的仪式毁灭此地之前，把他们消灭干净。', 66384),
(301674, 'zhCN', '阿曼尼扎也太挤了！真高兴能先待在这儿，直到我们夺回恶齿巨魔的村子。', '阿曼尼扎也太挤了！真高兴能先待在这儿，直到我们夺回恶齿巨魔的村子。', 66384),
(301672, 'zhCN', '多亏有你和尼嘉，沙德拉归来了，我这就把消息传出去！', '', 66384),
(301670, 'zhCN', '', '我拒绝成为神灵代言人，我现在必须一心关注恶齿的福祉。\n\n而且，亚曼伽很擅长这个。', 66384),
(301668, 'zhCN', '', '<这本典籍中夹着好几封信件，那几页的内容关系到仪式研究，其中的符文令你毛骨悚然。看起来最新的一封信墨迹未干。>\n\n阿曼茜雅，\n\n你的生日就要到了，但我不得不承认，现在的日子一天不如一天了。情况已经不同于往日，可能永远都回不去了。\n\n不管怎样，我的研究都在继续，敌人的工具到了你的手里，或许就能成为和平的利器。也许吧，如果仪式能够达到我的预期，你就能获得这份当之无愧的礼物了。\n\n记住太阳之井的耻辱，\n\n塔兰德拉', 66384),
(301667, 'zhCN', '<你无法理解瓮中装着的究竟是什么，但它散发出扑鼻的恶臭，让人莫名地感到焦躁。\n\n你的汗毛甚至都倒竖了起来。>', '<你无法理解瓮中装着的究竟是什么，但它散发出扑鼻的恶臭，让人莫名地感到焦躁。\n\n你的汗毛甚至都倒竖了起来。>', 66384),
(301665, 'zhCN', '说不定我的下一部传奇，主角就是你呢，嗯？', '', 66384),
(301664, 'zhCN', '', '每当想起一件无法挽回的憾事，我就喝一杯。\n\n那可真是不少杯啊！', 66384),
(301661, 'zhCN', '<你面前的架子似乎深受喜爱，上面有很多不同寻常的装置，似乎也毫无关联。\n\n园艺工具和形如手术器械的工具挂在了一起。它们虽然比较干净，但显然经常被人使用。>', '<你面前的架子似乎深受喜爱，上面有很多不同寻常的装置，似乎也毫无关联。\n\n园艺工具和形如手术器械的工具挂在了一起。它们虽然比较干净，但显然经常被人使用。>', 66384),
(301657, 'zhCN', '', '我是瓦莉拉·萨古纳尔，一个选择自己道路的血精灵。\n\n我的过往……一言难尽，但我的忠诚始终由我做主。\n\n我曾与乌瑞恩家族并肩而战，我也是银月城及其摄政王的盟友。\n\n我不是谁的奴仆，也不是揣在别人兜里的密探——我只效忠于那些赢得我信赖的人。\n\n如果这对你来说足够了，那么或许，我们有合作的余地。', 66384),
(301651, 'zhCN', '魔导师！我们用来维持符文石充能的奥术水晶快见底了！', '魔导师！我们用来维持符文石充能的奥术水晶快见底了！', 66384),
(301650, 'zhCN', '无需担心！我相信新一批补给刚刚运到！', '无需担心！我相信新一批补给刚刚运到！', 66384),
(301647, 'zhCN', '', '那些东西竟然在他体内生长？$n，快把解毒剂带给其余被感染的斥候。我会留在这里观察这家伙的状况。', 66384),
(301646, 'zhCN', '我的……身体。它们终于消失了吗？', '', 66384),
(301645, 'zhCN', '', '现在再搅拌一会儿，我们来做最后的调整。', 66384),
(301643, 'zhCN', '', '接下来我们要彻底捣碎这些肝脏，释放其中的酶类。', 66384),
(301642, 'zhCN', '', '首先我们要细致地研磨血色花瓣。', 66384),
(301634, 'zhCN', '', '乌布里克让我照料这个德莱尼女子，因为我精通语言法术。但她老是怒视着我……\n\n看上去她似乎更中意你。如果你不通晓她的语言，我可以以奥术语言学者的身份传授给你我的专长。不过这种能力只对她管用。', 66384),
(301632, 'zhCN', '当初在外域，我们可是全靠我的笑话才撑过来的！', '', 66384),
(301631, 'zhCN', '库德兰一定会喜欢这个，$p。', '', 66384),
(301626, 'zhCN', '不用担心——我马上就能让沙德拉恢复力量。', '', 66384),
(301625, 'zhCN', '', '没错……出于恶毒的目的而收集毒液，对吧？\n\n我暂时不会计较。', 66384),
(301624, 'zhCN', '', '当然。你在炽蓝仙野助我重生。\n\n我们永远都是朋友，噬渊行者。', 66384),
(301620, 'zhCN', '', '是时候拓展我的信众了。\n\n枯木和恶齿的信徒我都接受，他们都很不错。', 66384),
(301619, 'zhCN', '', '我重生了！', 66384),
(301615, 'zhCN', '我衷心希望你能像我一样乐在其中。容我冒昧地问一句，我们算是好朋友了吗？', '', 66384),
(301610, 'zhCN', '', '他们肯定料想不到我们会来，哈尔拉兹。这一定会很有趣。', 66384),
(301609, 'zhCN', '', '第一个任务，就是向卑鄙的邪枝部族寻仇。', 66384),
(301607, 'zhCN', '', '纳洛拉克麾下的恶齿部族已准备就绪，愿与你、枯木部族以及哈尔拉兹携手，共御强敌。', 66384),
(301605, 'zhCN', '你找到壳了？我们开始吧！', '', 66384),
(301604, 'zhCN', '我总是为自己着想。但我确信最安全、最有趣的位置……就是在你身旁。', '', 66384),
(301603, 'zhCN', '我不会奢求你信任我，凡人。如果你从中有所领悟的话，那就是我们多曼纳尔绝不可信。', '', 66384),
(301602, 'zhCN', '让我们将这场小插曲抛诸脑后吧，$n。我依旧与你站在同一阵线。', '', 66384),
(301600, 'zhCN', '别客气，就当自己家一样。', '', 66384),
(301599, 'zhCN', '', '尼嘉·断齿一言不发，唇边却浮现出了一个微笑。', 66384),
(301598, 'zhCN', '我把所有的一切留在了辛特兰。我们现在都一样，都想夺回土地，找回神灵。', '', 66384),
(301593, 'zhCN', '', '从辛特兰来的枯木巨魔和恶齿巨魔，居然为了这事儿携手合作。', 66384),
(301592, 'zhCN', '糟糕了，仪式的力量减弱了。沙德拉！我们一定能找到你的壳！', '', 66384),
(301591, 'zhCN', '', '我信任哈尔拉兹。\n\n沙德拉可能需要一些时间，但我会凭借在这里目睹的一切来指引恶齿部族。', 66384),
(301583, 'zhCN', '冷静些，现在。我理解你的愤懑，但我们必须维持同盟关系。\n\n为了艾泽拉斯的存亡，对吧？来，来，接过这把利刃……', '', 66384),
(301582, 'zhCN', '我想我不能怪你有这种反应。\n\n不过，这确实是段愉快的旅程。至少对我而言。', '', 66384),
(301581, 'zhCN', '啊，原来你拥有健全的情感调节能力，是吗？真是索然无味。\n\n看来，我得找个心理创伤更严重的人来施加折磨。', '', 66384),
(301579, 'zhCN', '有意思……但这就是所谓极致的滋味了？我必须承认，我非常失望。\n\n也许野兽暴戾的味道确实胜过凡人的苦痛。', '', 66384),
(301578, 'zhCN', '没错，没错！这就是来自你痛苦的真实滋味。多么醉人的享受！谢谢你。', '', 66384),
(301577, 'zhCN', '好了，好了，$n。你瞒不过我的。我已经品尝过你痛苦的滋味。\n\n那味道真是绝妙。', '', 66384),
(301576, 'zhCN', '真有这种可能吗？我品尝到的味道仅仅是我自己的欲念？太耐人寻味了。\n\n我必须深思一下我洞察力不足的问题。', '', 66384),
(301568, 'zhCN', '请明白，我从未真正背叛过你。\n\n恐惧、悔恨、背叛、哀伤……你们凡人体验到的如此纯粹而深刻的痛苦。\n\n承受痛苦是你们的宿命。就像渴望品味你们的痛苦是我的天性。\n\n我利用了你们凡人对信任和友情的天然倾向，从你们那里榨取最深层的秘密。我操控了啃噬之境中的虚空之力，向你们展现最能重创你们的景象。\n\n所以请坦诚地告诉我……这就是你痛苦的顶点吗？\n\n我们的这次历程究竟给你造成了多深的创伤？', '', 66384),
(301567, 'zhCN', '这该死的箱子到底该放哪儿来着……', '这该死的箱子到底该放哪儿来着……', 66384),
(301566, 'zhCN', '我得确保每样东西都井井有条。魔导师血誓这边的物流工作……实在是太复杂了。', '我得确保每样东西都井井有条。魔导师血誓这边的物流工作……实在是太复杂了。', 66384),
(301565, 'zhCN', '没看见我正忙着吗？\n\n只要我够努力，魔导师血誓一定会认可我的才华！\n\n我要把这里的地板擦成银月城最亮的。', '没看见我正忙着吗？\n\n只要我够努力，魔导师血誓一定会认可我的才华！\n\n我要把这里的地板擦成银月城最亮的。', 66384),
(301563, 'zhCN', '我第一时间冲到这里检查眼睛的情况，结果发现邪枝部族已经在这儿了！', '', 66384),
(301562, 'zhCN', '', '快说，沙德拉的信徒。', 66384),
(301561, 'zhCN', '我知道这看起来很糟，但先听我解释！', '', 66384),
(301553, 'zhCN', '', '啊！一个冒险者！在这困顿的时候，我正盼着能看到你们呢。\n\n恐怕我的药剂店已经关门歇业了，不过，如果你在寻找有利可图的工作，那我确实需要你做几件微不足道的小事。', 66384),
(301552, 'zhCN', '', '真希望我们早点赶到。让我们护送剩下的人回方位点。', 66384),
(301551, 'zhCN', '费恩德尔想引开那个怪物……好让我们逃走……可我们都太虚弱了……', '费恩德尔想引开它……好让我们逃走……可我们都太虚弱了……', 66384),
(301550, 'zhCN', '', '这么多人都折在这个可恶的家伙手里……但我很高兴看到你们中的一些人平安无事。', 66384),
(301545, 'zhCN', '现在别走神！补给马上就到！', '现在别走神！补给马上就到！', 66384),
(301543, 'zhCN', '这个箱子里应该装着每个符文石需要的所有补给。准备妥当后就装货吧。', '', 66384),
(301534, 'zhCN', '别担心，我会给你解释的。再信我一次，到啸影山脊与我见面，利刃就归你了。', '', 66384),
(301533, 'zhCN', '够了！你为我献上了一场愤怒的盛宴。我感激不尽。', '', 66384),
(301532, 'zhCN', '够了！显然你比我想象的要聪明得多。', '', 66384),
(301530, 'zhCN', '血精灵为什么就不能自己解决自己的战争？这些低语真该死。', '', 66384),
(301529, 'zhCN', '', '你最好说到做到。', 66384),
(301528, 'zhCN', '别担心。不带上他，我们绝不离开。', '', 66384),
(301527, 'zhCN', '', '别叫我冷静，达克。其他人都死了，就他一个还吊着口气。', 66384),
(301526, 'zhCN', '冷静点，小姐。', '', 66384),
(301525, 'zhCN', '什么——你对这把利刃动了什么手脚？啊——！', '', 66384),
(301524, 'zhCN', '对，对！你的愤怒美味极了！', '', 66384),
(301523, 'zhCN', '我的灵感从未如此泉涌！我必须立刻动笔！', '', 66384),
(301522, 'zhCN', '这地方简直太美妙了。哪天我得来这儿避暑才行。', '', 66384),
(301520, 'zhCN', '', '有多少我们的精灵被引诱到这里，力量被吸干，只为营救朋友？', 66384),
(301519, 'zhCN', '', '虚空生物以吞噬一切的饥饿著称。很少见到这么……有心计的。', 66384),
(301511, 'zhCN', '', '尽你们所能地做好准备。', 66384),
(301510, 'zhCN', '', '我再一次请求你们协助，我们要挺身而战。', 66384),
(301509, 'zhCN', '我们从不需要他们。我们能依靠自己的力量！', '', 66384),
(301507, 'zhCN', '', '可是神灵呢？你们不能呼唤神灵来助阵吗？', 66384),
(301506, 'zhCN', '', '恕我多嘴……', 66384),
(301505, 'zhCN', '我已向族人发出呼唤，只能静观其变了。', '', 66384),
(301504, 'zhCN', '', '恶齿部族的伤亡也很惨重。', 66384),
(301503, 'zhCN', '逃回来的阿曼尼族人不多。', '', 66384),
(301502, 'zhCN', '', '没时间争执了。我们需要的是计划，托伦多？', 66384),
(301501, 'zhCN', '', '我们遭到了攻击，邪枝……', 66384),
(301499, 'zhCN', '', '在高地脚下与我汇合。我们不能再被打个措手不及！', 66384),
(301498, 'zhCN', '', '阿塔阿曼沦陷了。', 66384),
(301497, 'zhCN', '', '但我真的精疲力竭了。你看起来比我更能硬撑一点。', 66384),
(301495, 'zhCN', '', '“相信虚空行者”？这简直是史上最拙劣的陷阱。', 66384),
(301494, 'zhCN', '对。信任我。我们会在高地会师。', '', 66384),
(301493, 'zhCN', '我们现在在方位点东南的高地上。相信那个虚空行者！', '', 66384),
(301492, 'zhCN', '我们的队伍被虚影风暴中的猛兽击溃了。它正朝我们扑来。赶紧过来！', '', 66384),
(301484, 'zhCN', '', '我可没报名喂养虚空行者……但如果，有可能以此获得帮助……', 66384),
(301443, 'zhCN', '我们都为艺术做出了牺牲。我只是万万没想到，我的牺牲品竟然是……我进行艺术创作的能力本身！\n\n<他们疼得倒吸一口凉气。>\n\n喔啊。', '我们都为艺术做出了牺牲。我只是万万没想到，我的牺牲品竟然是……我进行艺术创作的能力本身！\n\n<他们疼得倒吸一口凉气。>\n\n喔啊。', 66384),
(301442, 'zhCN', '为画光绽而受伤，我无怨无悔。那份壮美，实在不容错过！', '为画光绽而受伤，我无怨无悔。那份壮美，实在不容错过！', 66384),
(301441, 'zhCN', '真没想到，我会如此感激母亲当年逼我上的那些击剑课。我可是凭着那点三脚猫功夫才捡回一条命。', '真没想到，我会如此感激母亲当年逼我上的那些击剑课。我可是凭着那点三脚猫功夫才捡回一条命。', 66384),
(301440, 'zhCN', '我的创作素材是愤怒、痛苦、恐惧与狂暴。这可比简单的水彩画要深奥得多。', '我的创作素材是愤怒、痛苦、恐惧与狂暴。这可比简单的水彩画要深奥得多。', 66384),
(301439, 'zhCN', '虚空入侵之后我才明白，画笔挥得再好，有时也不如一记老拳直接糊在敌人脸上管用。', '虚空入侵之后我才明白，画笔挥得再好，有时也不如一记老拳直接糊在敌人脸上管用。', 66384),
(301438, 'zhCN', '虚空生物的色彩真是迷人。只可惜，你一想画它们，它们就扑上来咬你。', '虚空生物的色彩真是迷人。只可惜，你一想画它们，它们就扑上来咬你。', 66384),
(301437, 'zhCN', '这点伤看着吓人，其实没什么。它是我为艺术献身的勋章。', '这点伤看着吓人，其实没什么。它是我为艺术献身的勋章。', 66384),
(301435, 'zhCN', '谢谢你，尼嘉。有我们两个在，谁也别想将它们夺走！', '', 66384),
(301434, 'zhCN', '', '你不在的时候，我来保护墓穴和遗物。', 66384),
(301430, 'zhCN', '我虽然来自辛特兰，但我同时崇拜着哈尔拉兹和沙德拉。\n\n枯木部族找到的盟友越多越好，这也包括了恶齿部族，还有尼嘉。', '', 66384),
(301425, 'zhCN', '我的背叛是否在你的舌尖留下了灼烧感？来吧，你对复仇的渴求将成为这把利刃的终极淬火！', '', 66384),
(301424, 'zhCN', '现在，惊天的真相即将揭晓！你这个蠢笨的凡人，我从头到尾都在玩弄你！', '', 66384),
(301415, 'zhCN', '我都没意识到沙德拉之牙不翼而飞了！你们把它拿给我看的时候，我实在是愧疚难当。', '', 66384),
(301413, 'zhCN', '', '调和者亚曼伽肯定是沙德拉洛的一名祭司。\n\n他想和我们说什么呢？', 66384),
(301412, 'zhCN', '', '情况没那么简单。\n\n哈尔拉兹让我们狩猎沙德拉。如果他是要让我们争取到沙德拉这个盟友呢？\n\n这就是为什么我们恶齿更喜欢纳洛拉克——有熊神在背后撑腰，打一架就完事了，清清楚楚！\n\n不过，盟友总归是多多益善的。', 66384),
(301411, 'zhCN', '没错，我们带来了她的两件遗物，希望她可以归来。但是邪枝巨魔正打算用她和她的子嗣来对付我们。', '', 66384),
(301410, 'zhCN', '', '你早就知道，沙德拉一直都在这里！', 66384),
(301409, 'zhCN', '', '它们居然没攻击我们？这可真出乎我的意料。', 66384),
(301403, 'zhCN', '', '暮光之刃对祖阿曼的第一波攻势就摧毁了恶齿莎台。大多数恶齿族人都想留在祖阿曼，不想南下，但我们还能去哪儿呢？\n\n我本希望能把恶齿难民都带到这儿来，但如果枯木部族打算像在辛特兰那样对待我们，那还是算了。\n\n各部族之间好不容易才维持了长久的稳定。但如果祖阿曼这里混进了外来的枯木巨魔……', 66384),
(301401, 'zhCN', '', '当年在奥特兰克与人类和精灵开战时，巨魔大军四分五裂，有些枯木、恶齿甚至邪枝部族南下去了辛特兰。\n\n邪枝巨魔大多留在了辛萨罗城里，但枯木和恶齿部族为了争夺地盘和神殿打得不可开交，其中就包括蜘蛛之神沙德拉的神殿。枯木巨魔对恶齿部族手段残暴，用蜘蛛毒液来攻击我的族人。\n\n就在最近，我们恶齿部族拿下了辛萨罗。所以，当部落摧毁了辛特兰的许多村庄时，枯木部族就离开了。有些去了西边。而有些肯定就在这里，潜伏在这些枯木巨魔之中。如果他们真的在这里，我们就绝不能信任他们。', 66384),
(301397, 'zhCN', '不是死，而是烂。真菌人和你不一样。\n\n我们打到太疼了就会停下。\n\n停下后可能会得到救助，比如……强力的队友会得到救助。\n\n也有可能留在地上腐烂。输掉的队伍，外来者和生物，都会在坑里腐烂。\n\n我们会把腐烂的都吃掉，这对大家都好。\n\n憎怨斗坑真是个好地方！', '', 66384),
(301396, 'zhCN', '憎怨斗坑是打架的地方。\n\n也是看打架的地方。\n\n还有打完之后欢呼的地方。\n\n还是把失败者吃掉的地方。\n\n还有……肝菌会押注输的一方。', '', 66384),
(301395, 'zhCN', '这里是憎怨斗坑。\n\n憎怨斗坑是真菌人，呃——啊。\n\n斗坑就是一切！', '', 66384),
(301391, 'zhCN', '要肝菌怎么做？\n\n想打一场？\n\n想押一场？', '', 66384),
(301389, 'zhCN', '', '我的职责是护卫永歌森林全境。', 66384),
(301376, 'zhCN', '打起精神！这绝非易事。一旦开始，就无法回头。你准备好了吗？', '', 66384),
(301372, 'zhCN', '', '我就知道这牵涉到沙德拉。必须追上去。', 66384),
(301371, 'zhCN', '菌子同盟是新冠军。我们配得上水池。配得上湿漉漉！', '', 66384),
(301370, 'zhCN', '尘菌将士是新冠军。我们配得上水池。配得上湿漉漉！', '', 66384),
(301369, 'zhCN', '孢誓英雄是新冠军。我们配得上水池。配得上湿漉漉！', '', 66384),
(301368, 'zhCN', '盖世斗士是新冠军。我们配得上水池。配得上湿漉漉！', '', 66384),
(301367, 'zhCN', '如果你还需要毒镖，就来找图克图克！我随时准备着。', '', 66384),
(301366, 'zhCN', '很高兴能向$p学习战斗，还有学着不怕孢子滑翔者。', '', 66384),
(301363, 'zhCN', '图克图克毒翻了所有人！那是胜利的关键！', '', 66384),
(301361, 'zhCN', '欣尼治疗了队伍。大家都没死！', '', 66384),
(301360, 'zhCN', '布拉科打赢了孢子滑翔者！菌盖安全了。', '', 66384),
(301354, 'zhCN', '即将迎战的是$p和菌子同盟！', '', 66384),
(301352, 'zhCN', '即将迎战的是$p和尘菌将士！', '', 66384),
(301349, 'zhCN', '即将迎战的是$p和孢誓英雄！', '', 66384),
(301343, 'zhCN', '即将迎战的是$p和盖世斗士！', '', 66384),
(301342, 'zhCN', '真菌人，我们期待已久的对决来了。闪光卫士回归了！', '', 66384),
(301339, 'zhCN', '', '作为断齿的一员，我是祖阿曼恶齿部族的骄傲。但断齿的威名远不止于祖阿曼。我们从未忘记枯木与恶齿部族之间那段灰暗的宿怨。', 66384),
(301320, 'zhCN', '', '你去哈尔拉兹神殿的时候，我会盯住枯木巨魔的。', 66384),
(301319, 'zhCN', '辛特兰的蛮锤矮人一直在骚扰我们，夺取属于我们的土地。我们让他们明白了，要么乖乖留在岩洞里，要么就把脑袋留下！\n\n我希望将他们彻底赶走，不过也挺喜欢和他们争斗的。我和闪电萨满祭司一起训练，学会了抵抗矮人的雷霆之箭。他们惊呆时的表情真是绝了！不过我需要一直留着这些脑袋，至少要留到烂了为止。\n\n现在我干脆只收集锤子了。', '', 66384),
(301289, 'zhCN', '', '大量的充能核心散落于此，虚影尖塔的残余能量依旧在其中噼啪作响。它们绝不能落入歹人之手。\n\n多曼纳尔显然也注意到了这点，并派出了吞噬军团来收集这些核心。\n\n此地戒备森严，但我已经控制了一个奇点传送网络。我们可以利用它进入设施的各个区域，并赶在吞噬军团之前将核心尽数回收。', 66384),
(301288, 'zhCN', '这里有很多脑袋可猎，都怪邪枝巨魔把这儿搞得一团糟。', '', 66384),
(301264, 'zhCN', '祖瓦沙是个小村子，我们在那儿调制各类混合物。离开辛特兰的时候，我们抛下了那地方，不过配方我全都带上了。我和表亲祖拉雷克以前一起住在那里。\n\n真怀念那个时候啊，祖拉雷克用药剂把自己本就黄色的毛发弄得更黄了……\n\n<调和者亚曼伽眉头紧锁，摇了摇头。>\n\n后来我再没见过他了，他可能还在老地方，也可能是死了。\n\n不是每个人都来到了这里，有些人觉得回到枯木山崖太丢脸了。', '', 66384),
(301261, 'zhCN', '隐匿石原本是第二次战争时期设立在辛特兰的一处据点。联盟的攻势很猛，死了不少同胞。\n\n现在呢？这地方到处都是软泥。我住在那附近的时候，人人都躲着那里，只有采幽灵菇的时候才会过去。\n\n软泥的黏糊可以涂在长矛上，不过你也要当心着点儿，别把武器给溶解了，哈哈！', '', 66384),
(301257, 'zhCN', '你想上一堂狩猎课吗？\n\n真遗憾，我正忙着打磨长矛，准备串起邪枝巨魔的脑袋。', '', 66384),
(301256, 'zhCN', '', '你对枯木巨魔有多少了解，$r？', 66384),
(301255, 'zhCN', '', '我听到有人提起，他们的辛特兰同胞就在屋子里。隔墙有耳啊。在你搜索的时候，要注意他们有没有提起过沙德拉。', 66384),
(301228, 'zhCN', '不管你觉得我干了什么……我意识到自己掺和上的时候已经来不及了。', '不管你觉得我干了什么……我意识到自己掺和上的时候已经来不及了。', 66384),
(301227, 'zhCN', '我之前就试过逃跑，他们让我不敢再跑了。', '我之前就试过逃跑，他们让我不敢再跑了。', 66384),
(301226, 'zhCN', '他们许诺让我看清真理，我眼前的却只有鲜血。', '他们许诺让我看清真理，我眼前的却只有鲜血。', 66384),
(301225, 'zhCN', '我可不是为崇拜暗影而来的，我只想找个使命。', '我可不是为崇拜暗影而来的，我只想找个使命。', 66384),
(301203, 'zhCN', '', '我暂时会看护它。记得过会儿再来看看我们。我们还会再见面的。', 66384),
(301179, 'zhCN', '布拉科害怕了也不需要躲。谢谢你和布拉科一起与孢子滑翔者对练。', '', 66384),
(301178, 'zhCN', '这其实还不错。它们打起来的时候会发出好笑的“噼啪”声。', '', 66384),
(301177, 'zhCN', '看不见菌盖的顶上！孢子滑翔者可能打过来，布拉科却不知道。', '', 66384),
(301176, 'zhCN', '菌盖没事？布拉科喜欢布拉科的菌盖。', '', 66384),
(301171, 'zhCN', '想要多练习一下？欣尼喜欢多多练习。', '', 66384),
(301170, 'zhCN', '这还不错，欣尼可以治疗，也许可以大打一场。', '', 66384),
(301169, 'zhCN', '也许欣尼真的可以做到。', '', 66384),
(301168, 'zhCN', '呵，还可以。你还好吗？欣尼还好。', '', 66384),
(301165, 'zhCN', '好的，朋友们。图克图克在憎怨斗坑边等你们。', '', 66384),
(301148, 'zhCN', '我的野兽会在暴力威胁下继续蓬勃生长。这就是多曼纳尔的生存之道。', '', 66384),
(301147, 'zhCN', '无论这种温和的训练法是否奏效，它都明显不合我的胃口。', '', 66384),
(301146, 'zhCN', '怎么样？这头野兽的战斗表现如何？', '', 66384),
(301145, 'zhCN', '如果图克图克不试，就不会失败。\n\n那样最安全。\n\n$p和队伍就不会生气。\n\n就不会失去新朋友$p、布拉科和欣尼。\n\n图克图克也不用躲在菌盖里伤心了。', '', 66384),
(301143, 'zhCN', '图克图克觉得图克图克做不到。\n\n不能像$p那样强大。\n\n只有一点点强，远远不够强。\n\n就算经过训练也不够格。', '', 66384),
(301141, 'zhCN', '<斥候丹娜的盔甲被圣光烧得一片焦黑。只有经验丰富的牧师才能施展如此威力的惩击。\n\n她的双手痛苦地蜷缩着，被嵌入皮肤的金属移植体牢牢固定。>', '<斥候丹娜的盔甲被圣光烧得一片焦黑。只有经验丰富的牧师才能施展如此威力的惩击。\n\n她的双手痛苦地蜷缩着，被嵌入皮肤的金属移植体牢牢固定。>', 66384),
(301140, 'zhCN', '$p是来告诉图克图克，说图克图克逃走是不对的吗？\n\n图克图克知道图……图克图克不够格入队。\n\n只能逃走。\n\n躲在水池里最安全。\n\n留在水池里就够啦。', '', 66384),
(301139, 'zhCN', '', '<拉斯亚埋头案前，对你的到来毫无反应。>\n\n大法师罗曼斯是我的主顾。我的使命就是为他寻觅、培育并呈上世间最顶级的美酒。\n\n所以，我很忙。<拉斯亚这才抬起头，漫不经心地打量着你。>你来这里是要找什么特别的东西吗？', 66384),
(301138, 'zhCN', '天灾军团、燃烧军团，现在又来个虚空……你根本想象不到，在这些宇宙势力轮番上阵糟蹋你的葡萄园的情况下，想要酿出一坛好酒有多难。', '', 66384),
(301137, 'zhCN', '灯盏花？绳藤蔓？爆弹种子？想要这些宝贝吗？\n\n都是你的，我的朋友。只要你付得起金币。', '', 66384),
(301136, 'zhCN', '', '永歌森林中藏着各种奇珍，关键是要知道去哪里寻找。有些东西甚至没被诅咒。', 66384),
(301132, 'zhCN', '', '<玛瑞琳女士凝视着你。虽然她一动不动，但目光却格外锐利。她从不在无谓的动作上浪费精力。>\n\n你好。欢迎光临我的酒窖。这些商品和技艺都来自我的故乡苏拉玛。艾蕾恩夫人慧眼识珠，准许我在此常驻。\n\n如果有兴趣品尝任何样品，尽管开口。', 66384),
(301128, 'zhCN', '', '让我告诉你一个秘密！我原本是个奶酪商，才刚涉足葡萄酒行业不久。这两种东西其实很相似——都是发酵的产物，变化多端，对环境高度敏感。而且永远让人意犹未尽，尤其是两者搭配在一起的时候。', 66384),
(301126, 'zhCN', '', '你知道烹饪中最重要的是什么吗？盐。要放很多很多盐，比寻常厨师认为该放的量还要多上好几把。\n\n我酿酒时也秉持同样的理念。我虽然钟爱经典红酒，但我追求的是那种极致的味道……一种浓郁的风味。它不只是轻轻撩拨你鼻尖，而是会充盈你的鼻腔并久久萦绕。从你闻到它的那一刻起，就踏上了一段复杂的感官之旅。\n\n我的酒会让你终生难忘。它只适合搭配少数食物，通常是新鲜奶酪，而且应该作为餐桌上的主角或独奏。我的酒要一口饮尽，而非细细品味，一个人在昏暗烟雾缭绕的房间里享用再合适不过。', 66384),
(301124, 'zhCN', '哦，你甚至都不用开口。\n\n你是来寻找爱的，对吧？你可找对人了，我这里应有尽有。', '', 66384),
(301123, 'zhCN', '', '你好啊，美人！今天真是个好日子，是吧？这座小镇也美极了！我们精灵保证它天天如此。我们就是这么富有品味。\n\n你需要些什么呢？', 66384),
(301122, 'zhCN', '经历了……过去那些事之后，还能过上这样的生活我已深感幸运。这是我记忆中最快乐的时光。看到他人享受你的创作成果，那种感觉实在难以言表。\n\n你要不要尝一尝？', '', 66384),
(301120, 'zhCN', '从前的我只是个卖杂货的普通商人……过着平淡的生活。<赫尔隆脸上露出待客常有的礼貌笑容，但其中却蕴含着更深沉、更真挚的情感。赫尔隆为你的到来感到欣喜。>\n\n后来某一天，我突然受到启发，想要尝试些新事物，创造属于自己的作品。毕竟人生只有一次——为何不放手一搏呢？', '', 66384),
(301119, 'zhCN', '', '请随意挑选。我一直在研制一种改良版红酒……你觉得这深紫色泽如何？\n\n<萨蕾妮突然面露惊恐，用手捂住了嘴。>\n\n哦，这可跟虚空没有半点关系，我保证。不然罗曼斯就要把我逐出金雾镇了。', 66384),
(301118, 'zhCN', '', '欢迎来到金雾村，这里拥有东部王国最顶级的美酒与酿酒师……我就是其中之一。<艾蕾恩举手投足间尽显优雅。她轻咬了一口完美的椭圆形葡萄。>我特别擅长用艾伦达尔瀑布附近生长的本地水果酿酒。走进银月城任何一家酒馆，你都能看到顾客在享用艾伦达尔佳酿。无论是谁，无论何种场合，都能在我这里找到心仪的美酒。\n\n今天需要我为你效劳吗？要在这里小住几日吗？', 66384),
(301107, 'zhCN', '<这名光铸德莱尼已经死去，被某种凶兽撕成了碎片。\n\n你注意到一块微小的水晶，正与圣光产生共鸣。\n\n你可以利用这块水晶向剑刃注入更多的圣光，破坏其平衡。\n\n下次殆希莫斯试图淬炼它时，这玩意儿可能会直接在他面前炸开。>', '', 66384),
(301093, 'zhCN', '图克图克谢谢$p……你让图克图克试过。', '', 66384),
(301092, 'zhCN', '但愿你能为盖世斗士找到新的吹箭手。', '', 66384),
(301091, 'zhCN', '图克图克干不了这个，$p。图克图克不干了。', '', 66384),
(301086, 'zhCN', '他真的已经拼尽全力了！', '他真的已经拼尽全力了！', 66384),
(301068, 'zhCN', '你……伤害了我……', '', 66384),
(301067, 'zhCN', '你……纠缠着我……', '', 66384),
(301066, 'zhCN', '你让我……受到伤害……', '', 66384),
(301065, 'zhCN', '依然……令人可悲……', '', 66384),
(301064, 'zhCN', '你永远……都不会足够强大……', '', 66384),
(301063, 'zhCN', '你依然……如此软弱……', '', 66384),
(301062, 'zhCN', '你……救不了任何人……', '', 66384),
(301061, 'zhCN', '你……没能救下我……', '', 66384),
(301057, 'zhCN', '这就是你的报应！', '', 66384),
(301056, 'zhCN', '死吧！', '', 66384),
(301055, 'zhCN', '可怜的畜生……', '', 66384),
(301054, 'zhCN', '怪物！', '', 66384),
(301053, 'zhCN', '一文不值的废物……', '', 66384),
(301052, 'zhCN', '可怜的渣滓……', '', 66384),
(301051, 'zhCN', '真是太弱了！', '', 66384),
(301043, 'zhCN', '', '我会将你的恩情铭记在心，$p。我会继续在这里兢兢业业，寻找每一丝可能性。', 66384),
(301042, 'zhCN', '', '但今天，你帮我保住了希望，而希望本身就意义重大。', 66384),
(301041, 'zhCN', '', '$p，我不知道这所做的一切是否真的能够实现我盼望的生长，也不知道泰达希尔是否仍一息尚存，是否能重焕生机。', 66384),
(301007, 'zhCN', '顺着路走，找绿火把，别声张。', '', 66384),
(301006, 'zhCN', '', '你觉得身后那家店的绿火把怎么样？我是不是也该搞几个。', 66384),
(301005, 'zhCN', '外面挂着绿火把的地方应该会卖浮龙。', '', 66384),
(300995, 'zhCN', '', '算是我们的幕后老板吧。\n\n我们帮他生产大买卖需要的东西，作为回报，这块安静的小地盘就归我们了。\n\n时候到了你自然会明白。', 66384),
(300985, 'zhCN', '', '啊，来了位新客人。维拉想亲自见见你，她就在楼上。', 66384),
(300984, 'zhCN', '', '万全的准备，是未来试炼的保障。', 66384),
(300983, 'zhCN', '', '干得不错，看来你能活下来了。', 66384),
(300982, 'zhCN', '', '很好，有了资源就能让你活下来。', 66384),
(300979, 'zhCN', '看到你的徽记之戒，卫兵点头致意。', '', 66384),
(300974, 'zhCN', '赞恩会给西尔他应得的分成。进去吧。', '', 66384),
(300973, 'zhCN', '赞恩会给德诺林他应得的分成。进去吧。', '', 66384),
(300972, 'zhCN', '赞恩会给兰达丽她应得的分成。进去吧。', '', 66384),
(300965, 'zhCN', '滚出我的视线。', '', 66384),
(300964, 'zhCN', '滚开，废物东西！', '', 66384),
(300951, 'zhCN', '', '我很了解弟弟，我打算给他一个改过自新的机会。我理应给他一个机会。', 66384),
(300950, 'zhCN', '', '你想让我要他的命还是怎么？这在祖阿曼算是正义之举。', 66384),
(300949, 'zhCN', '', '他是个大人了，他也能够理解并面对自己的行为所造成的后果。', 66384),
(300948, 'zhCN', '', '他现在那样也是我的错。我不该对他那么严厉，不管是现在还是儿时。', 66384),
(300947, 'zhCN', '', '我们是姐弟，我们什么都可以“嫉妒”，但也能放下嫉妒。', 66384),
(300946, 'zhCN', '', '你弟弟会因为你和神灵的关系而嫉妒你吗？', 66384),
(300945, 'zhCN', '', '他失去了追随者，眼看着我成了哈谢……这对他而言已经是个惩罚了。', 66384),
(300944, 'zhCN', '', '他们大多死在了莫尔杜恩手里。其他人呢？我不想因为惩罚弟弟而让部族再次分裂。', 66384),
(300943, 'zhCN', '', '祖尔加也是祖尔金的孙辈，他也掌握了力量。他口才不错，追随者很多。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(300938, 'zhCN', '', '有些日子，我会觉得——甚至希冀——泰达希尔终有一日会重生，$p。只是好日子并不常有。大部分时候，我没法去探求，也没有理由怀抱希望。\n\n我唯一确定的是，如果我就此放弃，泰达希尔就只会留在我消散的回忆和幻梦里。我不能……\n\n所以我为了希望而耕耘，即便在那些我心中毫无希望的日子里，我也是如此。', 66384),
(300933, 'zhCN', '勇士$n。\n\n我不确定这点小事是否值得你亲自过问。我们曾得到承诺，永歌森林会给我们提供食物和补给，因为我们的圣骑士和牧师已经快要油尽灯枯了。\n\n然而，这些……人……似乎并不愿意帮助或信任我们，即便他们城市的存亡，乃至整个艾泽拉斯的存亡，都系于我们的成败。\n\n如果我们要继续守望太阳之井，抵御那无情的虚空死亡，光靠魔法饼干和虚假的调味品可远远不够。\n\n你能代我们和这些人谈谈吗？或许他们会更信任你一些。', '勇士$n。\n\n我不确定这点小事是否值得你亲自过问。我们曾得到承诺，永歌森林会给我们提供食物和补给，因为我们的圣骑士和牧师已经快要油尽灯枯了。\n\n然而，这些……人……似乎并不愿意帮助或信任我们，即便他们城市的存亡，乃至整个艾泽拉斯的存亡，都系于我们的成败。\n\n如果我们要继续守望太阳之井，抵御那无情的虚空死亡，光靠魔法饼干和虚假的调味品可远远不够。\n\n你能代我们和这些人谈谈吗？或许他们会更信任你一些。', 66384),
(300912, 'zhCN', '一旦找到解决方案，我会立即联络。', '', 66384),
(300911, 'zhCN', '这些笔记一定藏着答案！卡茜雅……我不会让你白白牺牲。阿拉托尔，告诉洛瑟玛他有我的支持。', '', 66384),
(300887, 'zhCN', '', '亲眼目睹如此伟大的存在葬身烈火……那种痛苦无法言喻。但这痛苦并不是最难熬的。时间已经磨平了它的棱角。对我来说，$p，最艰难的是失去我终生的使命。身为护根者，我知晓我为何而生，亦知晓我愿为何而死。\n\n随着泰达希尔的离去……使命与意义的空缺比我想象的还要艰难。帮助哈尔玛拉的年轻哈籁尼尔和其他人，成了我新的重心。这让我免于被悲伤彻底吞没。', 66384),
(300886, 'zhCN', '', '我当时在大巢穴，和其他护根者在一起时……\n\n<哈加尔停了一下才继续说。>\n\n旁人看见了浓烟，便派人寻我。那时哈尔玛拉唯一的光亮，竟是头顶那燃烧的根须映照下来的。\n\n根须是最后着火的——而树身，早已化为乌有。', 66384),
(300874, 'zhCN', '', '或许听着奇怪。但多年来，泰达希尔便是我的一切。她被焚毁之后，我一直因为失去她而忧心忡忡。\n\n当你毕生致力于侍奉某样事物——尤其是像泰达希尔这般宏伟且充满生机的存在时——用冷冰冰的“它”来称呼实在太苍白了。', 66384),
(300870, 'zhCN', '', '我们又见面了，$p。那只老鼠就在前面上蹿下跳……准备好结束这场狩猎了吗？', 66384),
(300867, 'zhCN', '呵，问题虽简单，答案却不简单。\n\n我猜是我姐姐派你来找我的吧。她太了解我了，有时候我真希望她别这么了解我。\n\n告诉祖尔加拉，她那个不成器的弟弟很好，闯入者——不，$n，你至少值得我说句实话。\n\n等我看够了往事，很快就会返回阿曼尼扎。', '', 66384),
(300861, 'zhCN', '', '但我不会放弃另一个希望，希望通过我的努力，能让它再次焕发生机。', 66384),
(300860, 'zhCN', '', '我总是有个不切实际的希望，希望我对泰达希尔面临的威胁能有所了解，然后做出不一样的应对。', 66384),
(300859, 'zhCN', '', '去阿古斯。亲眼见证伊利丹所见证的一切。', 66384),
(300858, 'zhCN', '', '我们要去哪儿？', 66384),
(300857, 'zhCN', '', '跟我来。你必须明白伊利达雷牺牲的意义。', 66384),
(300850, 'zhCN', '青翠圣陵及其洞穴蕴藏着无数秘密，只有慧眼识珠者才能发现。', '青翠圣陵及其洞穴蕴藏着无数秘密，只有慧眼识珠者才能发现。', 66384),
(300849, 'zhCN', '', '成为护根者是我一生的骄傲，我最大的喜悦。', 66384),
(300848, 'zhCN', '', '我不知道你经历过什么样的失去，又背负着怎样的苦难。', 66384),
(300842, 'zhCN', '', '我们会为逝者哀悼。但现在，我们更该庆贺他们为我们争取来的一切。', 66384),
(300841, 'zhCN', '', '伟大的洛阿神灵，是您指引我们至此。但最终，必须由我们亲手终结这场战斗。', 66384),
(300838, 'zhCN', '$p，有空吗？', '', 66384),
(300836, 'zhCN', '', '必须采取一切手段了。难道你宁愿看着族人走向灭亡，也不愿意倾尽全力吗？', 66384),
(300833, 'zhCN', '你给我找个了活？我们去酒吧里谈，不要那么张扬。', '', 66384),
(300832, 'zhCN', '哈，逮住你了。听说你一直在打听我。', '', 66384),
(300817, 'zhCN', '$p，其他引导者又开始疲惫不堪了。\n\n希望你和法奥已经找到了解决办法？', '', 66384),
(300816, 'zhCN', '谢谢你，$p。我会确保这些圣物分发给需要它们的人。', '', 66384),
(300813, 'zhCN', '我无法进入太阳之井，$p。谢谢你帮忙收集圣物。', '', 66384),
(300808, 'zhCN', '虚空最终会将这些记忆扭曲成暴力的幻象，这完全在意料之中。', '', 66384),
(300806, 'zhCN', '可怜虫！', '', 66384),
(300805, 'zhCN', '我很难想象这种遭遇给你造成了怎样的精神创伤……', '', 66384),
(300804, 'zhCN', '多么骇人的经历。', '', 66384),
(300801, 'zhCN', '啊，我能感受到那个灵魂内心的煎熬。是因为你过去的某个过失吗？多么令人心碎。', '', 66384),
(300800, 'zhCN', '你理应承受……永恒的痛苦……', '', 66384),
(300799, 'zhCN', '你失败了……你的力量还差得远……', '', 66384),
(300798, 'zhCN', '怪物……你才是那个怪物……', '', 66384),
(300797, 'zhCN', '你永远……都不会足够强大……', '', 66384),
(300796, 'zhCN', '别……抛下我……', '', 66384),
(300795, 'zhCN', '你如此软弱……真是可悲……', '', 66384),
(300794, 'zhCN', '帮帮……我……', '', 66384),
(300789, 'zhCN', '', '有些时候，我们只能心怀希望。', 66384),
(300788, 'zhCN', '', '希望我们能够帮忙修复根须中的生命。', 66384),
(300784, 'zhCN', '也感谢你将这么重要的任务托付给我——这对你我都意义非凡。', '', 66384),
(300783, 'zhCN', '再次感谢你用天才的手艺来帮助我。', '', 66384),
(300781, 'zhCN', '他喜欢精制的东西。我希望披风复原之后，能让他感受到平静。', '', 66384),
(300780, 'zhCN', '这件披风原本的主人对我特别重要。', '', 66384),
(300779, 'zhCN', '请原谅。我知道它一定很美……可我必须先理清思绪。', '', 66384),
(300778, 'zhCN', '盖尔里？你还好吗？', '', 66384),
(300777, 'zhCN', '我做到了！披风完好如初了，我敢说它看起来……', '', 66384),
(300775, 'zhCN', '具象……它们是那件披风的回忆！', '', 66384),
(300774, 'zhCN', '各位，都打起精神来！我开工了！', '', 66384),
(300773, 'zhCN', '趁着羞红的脸还没被人看清，索尔文·明缝快步离去了。', '', 66384),
(300772, 'zhCN', '不管要面对什么，我都会保护你。', '', 66384),
(300771, 'zhCN', '有了这种力量，我们可能会具化出某种……具像。', '', 66384),
(300767, 'zhCN', '你有什么问题？', '你有什么问题？', 66384),
(300766, 'zhCN', '什么？', '什么？', 66384),
(300765, 'zhCN', '<精灵上下打量着你，随后笑了起来。>', '<精灵上下打量着你，随后笑了起来。>', 66384),
(300764, 'zhCN', '从我眼前消失。', '从我眼前消失。', 66384),
(300763, 'zhCN', '我真希望不用再面对这段回忆了……', '', 66384),
(300762, 'zhCN', '可惜要走到这个地步了，老朋友。', '', 66384),
(300717, 'zhCN', '你也看到有多少源生法力融入到了流丝里。缝补过程肯定……会很壮观。\n\n一定要做好万全准备，我开始纺织后就不能停下了。', '', 66384),
(300697, 'zhCN', '你真的是个法师吗？你的姿态糟糕透了。在它汲取能量时切勿移动。你会扰乱以太流的。', '', 66384),
(300677, 'zhCN', '随着研究的愈加深入，辛多雷变得愈加繁荣。我的工作直接关乎银月城的生死存亡。', '', 66384),
(300675, 'zhCN', '拿着这个水晶容器，用它给我们的试验品注入苦痛。\n\n武器、构造体、法力浮龙……我们可以把这种魔法注入它们体内，效果会非常喜人。', '', 66384),
(300672, 'zhCN', '抱歉，我只喝五百年的珍藏。', '', 66384),
(300671, 'zhCN', '', '很高兴见到你，捷斯。喝一杯吗？', 66384),
(300668, 'zhCN', '', '你在这颗星球上待了很久了吗，$n？这些顶级的虚空掠食者，正是我磨练镰刀技能的绝佳对手。', 66384),
(300653, 'zhCN', '', '但……既然你是我的哈舒拉，我……感谢你的这番话。', 66384),
(300652, 'zhCN', '', '骄傲？为我？哼。我本想说，你的话对我来说什么都不是。', 66384),
(300651, 'zhCN', '', '你没有重蹈我或是你祖父的覆辙，我为你感到骄傲。能参与你这段旅程，我也与有荣焉。', 66384),
(300646, 'zhCN', '', '你的处境，我感同身受。我也曾像你祖父那样，为了追求力量，不惜伤害任何人。', 66384),
(300644, 'zhCN', '', '你当时资源匮乏，处境艰难。我很难说当别人面临威胁时，我不会做出同样的选择——优先保护自己的家园。', 66384),
(300642, 'zhCN', '', '我只恨自己没能早点明白这些道理，没能当一个更好的领袖。', 66384),
(300641, 'zhCN', '', '也许吧。埃基尔松考验了我的意志，哈尔拉兹则逼我动脑子，而不是动拳头。', 66384),
(300640, 'zhCN', '', '听上去，你对神灵的信仰，好像越来越坚定了。', 66384),
(300632, 'zhCN', '', '哈尔拉兹不会眼睁睁看着他们去死。我相信，真到了那一步，埃基尔松也不会对我们见死不救。', 66384),
(300631, 'zhCN', '', '幸好，哈尔拉兹没有计较你祖父的所作所为，还是出手管了枯木部族的事。', 66384),
(300624, 'zhCN', '', '枯木部族当初需要我的帮助……可我却充耳不闻。当时我满脑子都是自己的人。', 66384),
(300623, 'zhCN', '', '为什么？我们救了枯木巨魔，你也找到了哈谢神坛，离成为真正的哈谢又近了一步。', 66384),
(300622, 'zhCN', '', '能得到哈尔拉兹的青睐是好事，可待在这里……只让我感到羞愧。', 66384),
(300608, 'zhCN', '', '快去吧，$p。对我来说最为重要的就是挡住这些烈焰！', 66384),
(300604, 'zhCN', '', '保住泰达希尔的残根是最重要的。天知道有多少根须可以得救呢？', 66384),
(300603, 'zhCN', '', '有许多饥肠辘辘的生物会用这里裸露的根须大饱口福。', 66384),
(300602, 'zhCN', '', '祖尔加拉，我看得出你心事很重。但我是真的想帮你。', 66384),
(300601, 'zhCN', '', '我不希望有任何会伤害到根须的东西来到附近，$p。', 66384),
(300600, 'zhCN', '', '怎么，精灵？当了我的哈舒拉，就以为有资格随便问我的私事了？', 66384),
(300506, 'zhCN', '', '非得要我亲自动手吗？', 66384),
(300492, 'zhCN', '离我的作品远点！', '', 66384),
(300490, 'zhCN', '如果阿拉蒂斯像个软骨头一样屈服了，那他落得如此可悲的下场也是活该。', '', 66384),
(300489, 'zhCN', '每个术士都必须在怯懦与诱惑间保持平衡。', '', 66384),
(300487, 'zhCN', '不过工具必须要小心处置，既不能丧失控制，也不能被反客为主。', '', 66384),
(300483, 'zhCN', '又是没头没脑的入侵者！', '', 66384),
(300465, 'zhCN', '走吧，神灵代言人允许你入内。', '走吧，神灵代言人允许你入内。', 66384),
(300464, 'zhCN', '停下！', '停下！', 66384),
(300412, 'zhCN', '我是医药之神，也就需要细致入微，仔细诊断。\n\n我会洞察你们的病痛，若是力所能及，我还会推荐一种疗法。可是否愿意遵嘱，就全看病患自身了。\n\n而且有些时候，病人也无药可救。生活本就是这样。', '', 66384),
(300372, 'zhCN', '……蜘蛛腿、黏稠的液体和随便什么小石头都有了，这就是你的逐项记录单了。很高兴能和你做生意。', '', 66384),
(300352, 'zhCN', '我被夹在两个誓言里左右为难。\n\n我对神灵有过誓言，也对阿库图发过誓。\n\n可这些誓言无法两全。', '', 66384),
(300326, 'zhCN', '啊，$n。海尔兰和其他人有什么消息吗？', '', 66384),
(300325, 'zhCN', '把破法杖给我，$n。', '', 66384),
(300303, 'zhCN', '', '我非常感谢你为泰达希尔和我伸出援手，$p。', 66384),
(300299, 'zhCN', '', '我很快就在神殿与你汇合，$p。', 66384),
(300283, 'zhCN', '……现在有太多的人把页岩和板岩混为一谈了，其实板岩……别走啊，你要上哪儿去？', '', 66384),
(300282, 'zhCN', '……你说法术穿透？这样我得安排一名专家了。过几天再来吧。', '', 66384),
(300281, 'zhCN', '我只想得知真相。', '我只想得知真相。', 66384),
(300274, 'zhCN', '是神灵唆使你这么干的。他就在上面，对不对？我要宰了他！', '', 66384),
(300271, 'zhCN', '你要为此付出代价，库尔吉！', '', 66384),
(300259, 'zhCN', '它在唤起你深埋心底的痛苦记忆。让我们把它们统统释放出来。', '', 66384),
(300258, 'zhCN', '天哪，我就怕会出现这种状况。这个地方能够窥探你的内心世界。', '', 66384),
(300187, 'zhCN', '', '在我们称之为家的峡谷峭壁间，蕴藏着某种事物。那是部落的心脏，是我们人民的魂魄。\n\n我们今日磨砺战技，只为当战争叩响城门时，我们早已严阵以待。', 66384),
(300136, 'zhCN', '不不不，我必须坚持原则！你去享受你的杀戮吧。我会在这里尽情品味你暴行所散发的迷人芳香。', '', 66384),
(300134, 'zhCN', '他知道城里的大部分人都碰不得，但没人会管密谋小径里失踪的精灵。', '', 66384),
(300130, 'zhCN', '时间不等人。准备离开时就告诉我一声。', '', 66384),
(300118, 'zhCN', '我寻求的是答案，可这些回忆……', '', 66384),
(300115, 'zhCN', '库尔吉，穿山甲之神，医药之神。我们将病痛带到他面前，他则告诉我们如何治疗。祖尔金还没当上督军的时候，我就是他的代言人了。\n\n库尔吉的医药知识源远流长。不论是疾病还是衰弱，他都能轻松诊断。当我们需要知道某人出了什么问题时，就会来问库尔吉。可现在，他不肯回应我们，还说阿库图已经死了？他是个背叛之神，是个哑巴之神。呸！\n\n<西吉塔压抑着怒火继续说。>\n\n医药之神让人等死，这样的神灵有什么用？\n\n神灵不肯告诉我们治愈阿库图的疗法，但我们也不是毫无希望。', '', 66384),
(300112, 'zhCN', '阿库图是祖尔金麾下的一名战士，在部落和联盟进攻阿塔阿曼的时候身负重伤。\n\n阿库图说，他光荣赴死的时刻还没有到来，所以我们必须抓紧时间拯救他。', '', 66384),
(300111, 'zhCN', '别用问题来烦我，督军都要没命了！', '', 66384),
(300109, 'zhCN', '多加小心，那里的灵魂很生气。', '', 66384),
(300108, 'zhCN', '', '明智的决定。仁慈就是弱点的象征。现在快去——时间紧迫。', 66384),
(300105, 'zhCN', '', '不要着急下洞穴里去。在地面为我的圣物注入能量，我会用它来强化我们地下作战的实力。', 66384),
(300090, 'zhCN', '', '竟敢威胁我的新盟友？把刑期改成两百年。', 66384),
(300088, 'zhCN', '菌子同焖因为离场而判负！', '', 66384),
(300087, 'zhCN', '尘菌将士因为离场而判负！', '', 66384),
(300086, 'zhCN', '孢誓英雄因为离场而判负！', '', 66384),
(300085, 'zhCN', '盖世斗士因为离场而判负！', '', 66384),
(300084, 'zhCN', '$p，你的队伍抛下了你。', '', 66384),
(300083, 'zhCN', '', '这段旅程会考验我们每一个人，不如速战速决吧，哈舒拉？', 66384),
(300082, 'zhCN', '', '但这不代表我们是朋友了。', 66384),
(300081, 'zhCN', '', '如果这就是你的动机，那我相信你。你的意见很中听，你的朋友也很有本事。', 66384),
(300079, 'zhCN', '', '哈哈哈哈，你还真是有趣，和长矛一样锋芒毕露，又和穿山甲盾牌一样笨重。', 66384),
(300077, 'zhCN', '', '好了！我和$n是你的哈舒拉。我们会陪你……', 66384),
(300075, 'zhCN', '', '虽然稀奇，但我从你的困境中看到了自己，我希望你能离自己的神再近一点。', 66384),
(300074, 'zhCN', '', '我们在方位点重新会合，$n。', 66384),
(300070, 'zhCN', '', '这段过去让我踏上了一条毫无荣光的道路。', 66384),
(300069, 'zhCN', '', '可我没说的是，他抓住了我，拷问我，折磨并杀害了我的许多同胞。', 66384),
(300068, 'zhCN', '', '我说过，我曾经和你的祖父对阵。', 66384),
(300067, 'zhCN', '', '够了，祖尔加拉。我承认过去的经历让我……和你的族人感同身受。', 66384),
(300065, 'zhCN', '他们的毒液更强。图克图克在憎怨斗坑里撑不住了。压力太大了！', '', 66384),
(300064, 'zhCN', '', '祖阿曼也就离摆脱暮光之刃又近了一步。', 66384),
(300063, 'zhCN', '欣尼光靠自己带不动队伍。欣尼必须要跑了。你也要跑！', '', 66384),
(300062, 'zhCN', '', '你别装作在乎我和阿曼尼了。', 66384),
(300061, 'zhCN', '', '你现在开始奉承我了？我知道你的目的，你想保护永歌森林的金色原野。', 66384),
(300060, 'zhCN', '', '等等……我不是说……祖尔加拉，成为哈谢将是个伟大的成就。', 66384),
(300058, 'zhCN', '', '对，闯入者。我们离你的目标又近了一步。走吧。', 66384),
(300057, 'zhCN', '', '你的差事还远没有完成，卡尔高戈。过来见见我们，$n。', 66384),
(300056, 'zhCN', '', '如果金杜鲁没说错，或许真有办法可以联系到神灵，就是这条“哈谢”之路。', 66384),
(300055, 'zhCN', '大不了我逃到扭曲虚空去！', '', 66384),
(300054, 'zhCN', '布拉科先跑了！不能让孢子滑翔者吃掉菌盖！布拉科对不起！', '', 66384),
(300048, 'zhCN', '这些石头本来是用来守护我们森林的，但光绽突然大量涌现……还有那些生物……根本防不住啊！', '这些石头本来是用来守护我们森林的，但光绽突然大量涌现……还有那些生物……根本防不住啊！', 66384),
(300046, 'zhCN', '够了。我们之间的盟约到此为止，碎夜。我要独自夺取那洞穴深处的力量。', '', 66384),
(300034, 'zhCN', '啊，我的线绳快用完了。', '', 66384),
(300033, 'zhCN', '完美——这正是我继续工作需要的东西。', '', 66384),
(300032, 'zhCN', '太好了，$c。这下我就不用停下手里的活儿去处理别的琐事了。', '', 66384),
(300030, 'zhCN', '', '非常感谢，$c。没人喜欢单薄的衣裳。', 66384),
(300021, 'zhCN', '啊，祖尔加拉。你是来我部族寻求萨满的力量的吗？', '', 66384),
(300019, 'zhCN', '', '我不要你信任我，我要你给我离开，不然我就向卫兵指控你入室行窃。\n\n至于你要不要亲自调查阿拉蒂斯，我才懒得管。\n\n不过我奉劝一句，阿拉蒂斯给你的任务注定无法完成。为了你自己考虑，你最好能快他一步，否则你这位术士同行就要变成同谋了。他可不是因为忠实而出名的。', 66384),
(300018, 'zhCN', '', '我不要你信任我，我要你给我离开，不然我就向卫兵指控你入室行窃。\n\n至于你要不要亲自调查阿拉蒂斯，我才懒得管。\n\n不过我奉劝一句，阿拉蒂斯给你的任务注定无法完成。为了你自己考虑，你最好能快他一步。他可不是因为和善而出名的。', 66384),
(300015, 'zhCN', '', '为什么你仍然留在这里？', 66384),
(300012, 'zhCN', '', '你们什么都没做到，拉克图尔仍会崛起！', 66384),
(300008, 'zhCN', '', '他们已经将城镇团团围住，我们无路可逃了。', 66384),
(299979, 'zhCN', '', '交易达成。你将分担它们的痛苦。别指望那些怪物会对你的善意心存感激。', 66384),
(299976, 'zhCN', '', '仁慈等同于软弱。不过你显然有多余的力量可以挥霍。很好。', 66384),
(299975, 'zhCN', '我要回村子和姐姐好好庆祝一下。', '', 66384),
(299969, 'zhCN', '非常感谢你的帮助。', '', 66384),
(299968, 'zhCN', '相信我，这全是好货！', '', 66384),
(299967, 'zhCN', '可能会起点小火，但这有助于销毁证据！', '', 66384),
(299958, 'zhCN', '', '这里的空气完全变了性质。由于受到虚空力量影响，连重力定律都变得捉摸不定。\n\n别急着下去。我们得先在地面做足准备。', 66384),
(299953, 'zhCN', '', '说真的？你的心肠还挺软。就我的了解，虚空的法则里容不下半点怜悯。任何获得都要付出相应的代价。\n\n话虽如此，你毕竟是我的合作者和战友。我可以改造我的圣物，降低它对受害者生命精华的汲取量。这样虽然会让它们元气大伤，但至少能保住小命。\n\n不过，圣物需要从使用者身上抽取部分精华来填补空缺。也就是说，只要你持有这件圣物，你的生命活力就会不断流失。这样的交易你能接受吗？', 66384),
(299948, 'zhCN', '', '卡尔高戈已经潜入这里了。但现在别急着深入洞穴。我们得先在地面布置妥当。', 66384),
(299943, 'zhCN', '简直是一场噩梦！明天大家都要返校了，校园却完全乱套了！\n\n有人把流明球茎放在实验室里不管，现在光绽蔓延得到处都是！\n\n我联系了一个地精商人，说是能卖些工业级的除草剂给我，就是安德麦用的那种。\n\n你能不能用除草剂帮我清理这个地方？', '', 66384),
(299924, 'zhCN', '菌子同盟！', '', 66384),
(299923, 'zhCN', '菌子同猛！', '', 66384),
(299922, 'zhCN', '菌子同懵！', '', 66384),
(299921, 'zhCN', '尘菌将士！', '', 66384),
(299920, 'zhCN', '孢誓英雄！', '', 66384),
(299919, 'zhCN', '盖世斗士！', '', 66384),
(299918, 'zhCN', '我们一起喊队名！', '', 66384),
(299917, 'zhCN', '我们去斗坑里打。', '', 66384),
(299916, 'zhCN', '我们现在是一队的了！', '', 66384),
(299902, 'zhCN', '要做的还有很多。准备战斗，准备去斗坑。$p说我们先做什么好？\n\n欣尼会听的。', '', 66384),
(299888, 'zhCN', '喔……那队名是什么呢？', '', 66384),
(299880, 'zhCN', '名字很重要，能让观众认识我们，让大家都认识我们。\n\n可以叫……绽放卫士？孢子之光？\n\n不，最好的建议是孢誓英雄。', '', 66384),
(299879, 'zhCN', '希望等时候到了，布拉科能准备好。布拉科会准备好的。\n\n$p有什么期望？$p准备好了吗？', '', 66384),
(299878, 'zhCN', '问得好。我们需要名字。没名字还怎么打！跑进斗坑时就没法一起大喊队名了！\n\n也许可以叫根节帮。菌柄卫士？\n\n不，叫盖世斗士！盖世斗士是最好的队名。', '', 66384),
(299876, 'zhCN', '很多，很多！我们需要最好的队名。需要想很多好名字，挑出最好的。\n\n真菌之力很棒，但已经被……真菌之力抢先了。尘菌人？碾盖者？\n\n尘菌将士！尘菌将士最棒了！', '', 66384),
(299874, 'zhCN', '非常期待能组成队伍！等不及要和$p一起到斗坑里去……展现我们的强大了。\n\n图克图克的毒性特别强！', '', 66384),
(299872, 'zhCN', '', '别让它利用你的疑虑！', 66384),
(299862, 'zhCN', '祖尔加拉，我小时候最后一次去埃基尔松神殿的时候你还陪着我呢，你不记得了吗？', '', 66384),
(299861, 'zhCN', '', '那时候我们做什么都跟现在不一样。', 66384),
(299860, 'zhCN', '我那个年代，大家都是一招一式地练习武艺！', '', 66384),
(299829, 'zhCN', '', '哈瓦扎尔就在附近。既已摆脱了那个想吞噬她的怪物，她看起来硬朗多了。', 66384),
(299828, 'zhCN', '哎呀！今天风和日丽，我的小飞蛾四处飞舞！\n是不是美得让人陶醉？\n\n那么，你是带着闪光粉末来做交易的，还是纯粹来欣赏我的宝贝的？', '哎呀！今天风和日丽，我的小飞蛾四处飞舞！\n是不是美得让人陶醉？\n\n那么，你是带着闪光粉末来做交易的，还是纯粹来欣赏我的宝贝的？', 66384),
(299824, 'zhCN', '', '我们走吧。', 66384),
(299820, 'zhCN', '赶紧维修，要是我们不够小心，就全要死在这儿了！', '', 66384),
(299814, 'zhCN', '', '$n！小心，别让它跑了。快抓住它！', 66384),
(299813, 'zhCN', '', '哈瓦扎尔，你会来的，并且——', 66384),
(299812, 'zhCN', '抓住他们！', '', 66384),
(299810, 'zhCN', '他们要跑了……！', '他们要跑了……！', 66384),
(299809, 'zhCN', '等等……', '等等……', 66384),
(299807, 'zhCN', '这会是个绝佳的祭品！', '', 66384),
(299806, 'zhCN', '', '多么可悲的表演！你们全都辜负了使命！', 66384),
(299804, 'zhCN', '', '洛阿神灵的事就别提了。他们早在很久以前就把我们扔下不管了。来，我们去看看难民的情况。', 66384),
(299802, 'zhCN', '', '它给我的感觉不太像幽魂，倒更像是某种意欲复仇的邪物。虚影风暴里这种东西可不少。\n\n我记得我读到过相关记载。我需要更多信息来缩小范围。把你观察到的一切都告诉我。', 66384),
(299800, 'zhCN', '', '我手头有关于超自然现象的资料。更确切地说，是那些披着超自然外衣的伪装者。\n\n我正在翻阅我的研究记录。', 66384),
(299788, 'zhCN', '', '真遗憾。可没什么魔药能治你的仪态……或是你那身味儿。', 66384),
(299787, 'zhCN', '', '别动什么歪脑筋。这里的草药可比你有价值多了。', 66384),
(299786, 'zhCN', '', '如果你在找什么爱情魔药，不如先试试微笑。既有效，又便宜。', 66384),
(299785, 'zhCN', '', '没错没错，样样都是有机的。但我的耐心可不是——早在两个客人前就用光了。', 66384),
(299784, 'zhCN', '你好啊，高贵的旅人！\n\n来点柠檬水吗？只要两枚银币，新鲜可口，还能帮我们在日托所买书！\n\n你肯定支持日托所，对吧？好品味加好品德，尽在这一杯！', '你好啊，高贵的旅人！\n\n来点柠檬水吗？只要两枚银币，新鲜可口，还能帮我们在日托所买书！\n\n你肯定支持日托所，对吧？好品味加好品德，尽在这一杯！', 66384),
(299764, 'zhCN', '时不时和老朋友们聚一聚，感觉真不赖。', '', 66384),
(299762, 'zhCN', '', '那么，来处理这个生物吧。', 66384),
(299761, 'zhCN', '', '老实说，在天下大乱之前，这地方已经开始变得有点无聊了。\n\n是，没错，是很漂亮。但除此之外呢？', 66384),
(299760, 'zhCN', '', '每年这个时候的叶子都最是可爱。好吧，其实一年四季都那么可爱。', 66384),
(299759, 'zhCN', '总得有人盯紧这些精灵，哪怕都过了这么些年。\n\n<塔泰轻笑出声。>', '', 66384),
(299758, 'zhCN', '', '人嘛，总会习惯这种城市的奢靡生活。', 66384),
(299748, 'zhCN', '这不过是另一部原型！', '', 66384),
(299747, 'zhCN', '风暴在我们身旁咆哮，但在这里，你可以获得片刻的安宁。', '', 66384),
(299746, 'zhCN', '', '要不是被它弄得这么虚弱，我早就能轻而易举地干掉它了。', 66384),
(299745, 'zhCN', '快走，抓紧时间——莉亚德琳急需支援来对付阿曼尼。', '', 66384),
(299744, 'zhCN', '这个地方的酷寒与饥饿感……简直是为我们量身打造的世界。然而，我内心却毫无波澜。\n\n我羡慕同胞们尚存的激情。但我清楚自己的本质：一头为杀戮而生的怪物。\n\n如果你还没接受这个事实，那就尽快吧。这已经是我们仅剩的一切。', '', 66384),
(299740, 'zhCN', '', '嗯，我发现它喜欢吃什么了。燃烧绷带会让它以为有暴露的灵魂可以享用。', 66384),
(299739, 'zhCN', '我理解你的疑问。即使在我们朗多雷内部，很多细节也不甚清楚。\n\n我们当中许多人，包括我本人，都曾在魔导师平台求学。罗曼斯曾经是我的导师。\n\n我认为，唯有知己知彼，才能攻克强敌。于是我带领一队研究人员，开始研究虚空的力量。我们发现了达尔坎·德拉希尔的日记，那家伙曾经背叛了银月城，投靠了巫妖王。他的罪行导致我们珍爱的一切几乎都在第三次战争中灰飞烟灭，而这都是源于他对虚空的研究。\n\n这下你应该明白了，虽然血精灵长期使用邪能之类的危险魔法，我们的研究还是遭到了斥责。我们不愿意停手，于是就被流放了。\n\n这个选择并不让我感到后悔，可族人为此承受的苦难令我痛心。', '', 66384),
(299738, 'zhCN', '', '你究竟是怎么学会那一招的？', 66384),
(299737, 'zhCN', '感谢理解，$p。\n\n希望你不会为了与我同行而走上这条路感到后悔。容我感慨一句……你能在此真是太好了。\n\n一路走来，我们失去了太多同伴。有人向虚空屈服，有人在疯狂中迷失……\n\n但你还在。当你怀疑自己的力量和坚韧时，请记住：\n\n你还在这里。这本身就已足够。\n\n谢谢你。', '', 66384),
(299735, 'zhCN', '其他人休息时，我可以负责守夜。\n\n看来这些野兽不知道恐惧是什么。我们会好好教教它们。', '', 66384),
(299734, 'zhCN', '魔导师平台。\n\n我的青春岁月在此度过，还掌握了最早一批法术。仲夏舞会上，我和萨洛法·金纱共舞，那种感觉……\n\n<乌布里克长叹一口气。>\n\n那些日子一去不返了。这地方变了样，我也不是从前的我。像你我这样的人不再受到欢迎。\n\n逝去的无法挽回。朗多雷必须开创自己的传统，组建自己的家庭。\n\n塑造我们自己的未来。', '', 66384),
(299733, 'zhCN', '好的核技师总有趁手的工具。', '', 66384),
(299729, 'zhCN', '我得救了！\n\n暮光之刃绑架了我，其他人也被困在这里！你必须把他们都救出来，不然就来不及了！\n\n有那么一把钥匙！你会先来救我的吧？', '我得救了！\n\n暮光之刃绑架了我，其他人也被困在这里！你必须把他们都救出来，不然就来不及了！\n\n有那么一把钥匙！你会先来救我的吧？', 66384),
(299728, 'zhCN', '你！求你了，救救我！', '你！求你了，救救我！', 66384),
(299726, 'zhCN', '我的力量输出已达巅峰！', '', 66384),
(299724, 'zhCN', '你好大的狗胆？！\n\n立刻把我的坩埚还回来，否则你将面对超乎想象的后果。\n\n我说，超乎你的想象！', '', 66384),
(299723, 'zhCN', '那帮讨厌的薯身蟾赶走了我，打断了实验。我在调制一种营养丰富的全新土壤。\n\n至于用途嘛，这就不关你的事了。这是我们芦塔尼族的秘密。还有，我警告你……别碰我的大锅！\n\n<科美特自言自语，仿佛你并不存在。>\n\n这地方太危险了。得想办法解决才行。话说回来，我要怎么回到盛放台地？', '', 66384),
(299721, 'zhCN', '', '噢，那我就放心了。它只想要$n，不是我。', 66384),
(299719, 'zhCN', '它就要到了……', '', 66384),
(299718, 'zhCN', '虚空……多么壮丽……', '虚空……多么壮丽……', 66384),
(299712, 'zhCN', '只需要再等一小会儿……', '', 66384),
(299711, 'zhCN', '', '我从未见过罗阿克连续传送这么多次。光是那魔法反噬就让我的牙根隐隐作痛。这里的虚空之力实在太过庞杂，既有好的，也有坏的。\n\n他会没事的，我保证。', 66384),
(299702, 'zhCN', '最后的导体找到了？一定要发出讯号才行。', '', 66384),
(299701, 'zhCN', '别忘了用导体发出讯号。', '', 66384),
(299699, 'zhCN', '', '不——！它是冲我来的。', 66384),
(299698, 'zhCN', '', '在那儿！在我们后面！', 66384),
(299696, 'zhCN', '', '还记得那把诡异的椅子吗？这次务必确保它老实呆在地上。', 66384),
(299694, 'zhCN', '', '别再乱吃东西了，小家伙。', 66384),
(299693, 'zhCN', '', '追随乌布里克的同胞们曾见识过许多世界。我们曾在多个位面与虚空交锋，从影卫那样的敌人手中夺回失地。\n\n在那无垠的深暗领域中，孤独往往也伴随着一种凄美。忧郁，而又寂静。\n\n但在这里，我们没那么好运。这个世界不过是个饲场。务必时刻保持警惕。', 66384),
(299692, 'zhCN', '总有那么一天，我再也不用自己买花来画了。', '', 66384),
(299679, 'zhCN', '', '洛萨克森！别再一意孤行了，我们已经胜利了！', 66384),
(299674, 'zhCN', '', '你打搅了我的仪式。', 66384),
(299673, 'zhCN', '金现在需要你，兄弟。', '', 66384),
(299669, 'zhCN', '我……谢谢你，姐姐。希望你是对的。', '', 66384),
(299668, 'zhCN', '', '回不到从前了，小加，但我不会让你被我埋没。你依然是我的左膀右臂，我的弟弟。', 66384),
(299667, 'zhCN', '祖尔加眯起了眼睛。', '', 66384),
(299666, 'zhCN', '', '独来独往也很难放弃。但我们有神灵，还有闯入者相助。', 66384),
(299665, 'zhCN', '', '我不想朝你大喊大叫的。我知道你的经历，祖父在我们眼中的形象是很难轻易放弃的。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(299664, 'zhCN', '', '他们离开是因为我们残害神灵，因为我们的祖父和恶毒的玛拉卡斯。', 66384),
(299663, 'zhCN', '我懂，可如果我们又依赖上了他们，而他们又消失了呢？他们一走了之，我们却分崩离析。', '', 66384),
(299661, 'zhCN', '抵抗住它，$p！你要驾驭暗影，别让暗影驾驭你！', '', 66384),
(299660, 'zhCN', '', '都不是！你不明白吗？我们与神灵的关系并非源于力量，而是源自信任。', 66384),
(299659, 'zhCN', '姐姐，那我问你，是你向神灵低头，还是他们向你低头？', '', 66384),
(299658, 'zhCN', '', '你不希望让神灵回来。祖尔加，为什么？他们从一开始就是文化中不可分离的一部分。', 66384),
(299657, 'zhCN', '我很高兴能粉碎暮光之刃，也很高兴能看到你的笑脸。', '', 66384),
(299656, 'zhCN', '', '怎么了，祖尔加？我们的胜利，神灵的归来，姐姐成为哈谢，这都不让你高兴吗？', 66384),
(299655, 'zhCN', '抱歉，姐姐，我没有庆祝的心情。', '', 66384),
(299654, 'zhCN', '', '啊，看来哈舒拉找到你了，弟弟。为什么不来聚会？你明明很喜欢跳舞的！', 66384),
(299649, 'zhCN', '我看到你眼睛瞪大了，“哈舒拉”。你说的对。就当我什么都没说。我们赢了。祖尔加拉赢了。', '', 66384),
(299648, 'zhCN', '是他们抛弃了我们。是——他们——抛弃了——我们。谁能保证他们不会再抛弃我们一次？', '', 66384),
(299646, 'zhCN', '洛阿神灵说我们的祖父，伟大的祖尔金，背叛了他们。可凭什么信他们？凭什么信我那个老糊涂叔叔？又凭什么信你这种闯入者？', '', 66384),
(299644, 'zhCN', '祖尔加拉看不到我的远见，可我也别无他法。而那些神灵？呸。', '', 66384),
(299643, 'zhCN', '莫尔杜恩来的时候，我仿佛看到了我设想的未来。有了光木，我们就能征服暮光之刃，然后拿下永歌森林。', '', 66384),
(299637, 'zhCN', '而我看到的是阿曼尼真正的力量——我们部族的潜力。我们应该去征服周围的种族！祖尔加拉根本不懂。', '', 66384),
(299635, 'zhCN', '我们对阿曼尼的未来有不同的看法。祖尔加拉想的是在祖阿曼内部发展壮大、保全阿曼尼的各个部族。', '', 66384),
(299632, 'zhCN', '我永远也成不了祖尔加拉那样的战士。我靠嘴皮子解决问题，而她靠拳头把问题砸烂。', '', 66384),
(299630, 'zhCN', '母亲去世时我们还小。我姐姐全凭自己的意志将各部族团结起来——没有依靠任何神灵。', '', 66384),
(299616, 'zhCN', '我不知道该躲哪里好！', '我不知道该躲哪里好！', 66384),
(299615, 'zhCN', '嘘！别让搜寻者发现你！', '嘘！别让搜寻者发现你！', 66384),
(299614, 'zhCN', '1……2……3……\n\n7……8……9……', '1……2……3……\n\n7……8……9……', 66384),
(299613, 'zhCN', '险恶映像现身，开始吞噬死者的尸体！', '险恶映像现身，开始吞噬死者的尸体！', 66384),
(299607, 'zhCN', '够了！够了，我告诉你们！他们在戴索姆废墟！', '够了！够了，我告诉你们！他们在戴索姆废墟！', 66384),
(299606, 'zhCN', '', '让他们尝点苦头，$p。', 66384),
(299605, 'zhCN', '', '你最好现在就说，否则有你后悔的。', 66384),
(299604, 'zhCN', '', '没准还能饶你活命！', 66384),
(299603, 'zhCN', '', '如果你愿意透露他们的去向，我们也能和和气气的。', 66384),
(299602, 'zhCN', '', '我们知道你抓了我的——你抓了我的朋友们。他们在哪儿？', 66384),
(299601, 'zhCN', '', '你看到它是怎么对待那些被标记的败者的吗？\n\n那绝不会是我的下场！', 66384),
(299600, 'zhCN', '行，布拉科已经够强了，但还需要朋友和导师。\n\n我们看完了就来找你。', '', 66384),
(299599, 'zhCN', '需要厉害的帮手吗？', '', 66384),
(299598, 'zhCN', '对，对，我们加入。\n\n我们一直想要组队，想交朋友！\n\n等会儿再来找你。', '', 66384),
(299597, 'zhCN', '你！你之前就在斗坑里。', '', 66384),
(299596, 'zhCN', '好机会，能变强。\n\n组队吧，看完比赛后再见！', '', 66384),
(299595, 'zhCN', '怎么了？', '', 66384),
(299593, 'zhCN', '走吧！我只是来旁观的。', '', 66384),
(299592, 'zhCN', '唔……下次再说吧！', '', 66384),
(299591, 'zhCN', '我还不够强。', '', 66384),
(299590, 'zhCN', '不行，太忙了。', '', 66384),
(299576, 'zhCN', '仔细看，但别掉进斗坑了！不然很快就会死。', '', 66384),
(299573, 'zhCN', '在憎怨斗坑见过你！你很强。', '', 66384),
(299569, 'zhCN', '斗坑里有很多厉害的生物。', '', 66384),
(299561, 'zhCN', '', '在那些尸体上使用烙印。这样就能把它引过去吞食尸体。', 66384),
(299560, 'zhCN', '', '如果让它吃饱的话，应该会让我——我是说，你——清静一会儿。我确信一定有办法彻底摆脱它。', 66384),
(299559, 'zhCN', '', '是一场决斗惹的祸。有人想让它吞噬我，但我反杀了那家伙。从那以后，它就一直像个跟屁虫一样吸食我的力量。\n\n起初我以为它会去吃我的对手，那倒也无所谓。它确实吃了，但回过头来总是要啃噬我。我曾是——现在也是——角力斗场上最顶尖的决斗者。', 66384),
(299557, 'zhCN', '', '我现在太虚弱了，无法与你战斗。我们能谈谈吗？', 66384),
(299536, 'zhCN', '你的发现……太惊人了！我们的神圣颜料不是简单调配——而是被赋予了生命。在那口回响大锅中，它们第一次获得了呼吸。', '', 66384),
(299523, 'zhCN', '现在我懂了。你带回的不只是遗物的传说……更让我们重温了威南的教诲。多谢了！', '', 66384),
(299522, 'zhCN', '艾林哈籁从不无故留下痕迹。那朵花不是馈赠……而是誓约。生机勃勃、神圣不凡、真真切切。感谢你还原了故事的真相。', '', 66384),
(299521, 'zhCN', '回响从不说谎。它为敢于聆听的勇者重现过往。前去吧，带着历史的声音归来。', '', 66384),
(299520, 'zhCN', '去吧，将手按在石头上，让灵魂与记忆对话。迎接你的未必温柔……但必将真实。', '', 66384),
(299519, 'zhCN', '伫立在她曾涉足的静谧之中……这份荣耀可不寻常。去吧，用心感受，而非仅仅聆听。', '', 66384),
(299497, 'zhCN', '', '来，穿越传送门。', 66384),
(299496, 'zhCN', '', '都结束了……', 66384),
(299493, 'zhCN', '这是我的！你休想拿走！', '这是我的！你休想拿走！', 66384),
(299491, 'zhCN', '<血骑士的脸因狰狞而扭曲，眼中闪烁着猩红的光芒。>', '<血骑士的脸因狰狞而扭曲，眼中闪烁着猩红的光芒。>', 66384),
(299490, 'zhCN', '疑神疑鬼，一派胡言！我才清楚，是你想要偷我的胸针！', '疑神疑鬼，一派胡言！我才清楚，是你想要偷我的胸针！', 66384),
(299489, 'zhCN', '本来一切都还好……直到我发现我的训练搭档想偷我的宝石！', '本来一切都还好……直到我发现我的训练搭档想偷我的宝石！', 66384),
(299487, 'zhCN', '<专家们争吵得面红耳赤。>', '<专家们争吵得面红耳赤。>', 66384),
(299486, 'zhCN', '我们城市的色彩变得如此鲜艳，食物的香气如此浓郁。简直美妙极了！', '我们城市的色彩变得如此鲜艳，食物的香气如此浓郁。简直美妙极了！', 66384),
(299484, 'zhCN', '<这名精灵紧握着一条镶嵌珠宝的项链，茫然地打量着四周。>', '<这名精灵紧握着一条镶嵌珠宝的项链，茫然地打量着四周。>', 66384),
(299455, 'zhCN', '嗯，你对于工艺有什么了解吗？', '', 66384),
(299454, 'zhCN', '我很荣幸能看到这绝伦工艺的源头。', '', 66384),
(299416, 'zhCN', '索尔文·明缝脸上一红，但什么话都没说。', '', 66384),
(299415, 'zhCN', '我一定要陪你同行。你的麻烦就是我的麻烦。', '', 66384),
(299414, 'zhCN', '你要知道，我这次得为你破不少规矩。', '', 66384),
(299393, 'zhCN', '收获颇丰啊，学徒！', '', 66384),
(299391, 'zhCN', '侦测到威胁！', '', 66384),
(299386, 'zhCN', '……行吧，看在能有机会接触这样一件绝世珍品的份上，我来修补吧。', '', 66384),
(299385, 'zhCN', '这件披风，完全是用萨拉斯的奥纹布制成的！这织工是我见过最精良的……', '', 66384),
(299384, 'zhCN', '我的要求很简单。我这儿有件从破碎残阳那时候传下来的披风，就想找个人补补。', '', 66384),
(299367, 'zhCN', '', '感谢你的帮助。后会有期，$n。', 66384),
(299366, 'zhCN', '', '我们在这里的行动重创了他们。希望这能让更多密教徒从他们的队伍里逃出来。', 66384),
(299365, 'zhCN', '', '暮光之刃可从不挑食，不管你来自哪个阵营，他们都会对你痛下杀手。', 66384),
(299364, 'zhCN', '', '我们回银月城吧。这地方……勾起了我一些宁愿忘掉的回忆。', 66384),
(299363, 'zhCN', '', '干脆利落的斩杀。这算是便宜他了。', 66384),
(299362, 'zhCN', '', '总的来说，这次救援很顺利。但还有些人被困在更糟的地方。', 66384),
(299310, 'zhCN', '', '住手！', 66384),
(299301, 'zhCN', '', '这应该管用。我的研究从不出错！', 66384),
(299300, 'zhCN', '', '我已经把那些附灵器物布置在这边了。过来看看。', 66384),
(299297, 'zhCN', '要么让这花朵吞噬我，要么就将我从这光芒四射的增生中解脱，但别拿空话来浪费我的时间！', '', 66384),
(299281, 'zhCN', '', '当心——她是影卫的人。听她的情报时，多留个心眼。', 66384),
(299277, 'zhCN', '', '我们有必要谈一谈。', 66384),
(299271, 'zhCN', '', '你！你遭到了某种无形之物的袭击？', 66384),
(299267, 'zhCN', '<奥威娜的瓣翼鸟期待地望着你。>', '<奥威娜的瓣翼鸟期待地望着你。>', 66384),
(299258, 'zhCN', '', '欢迎来到我们的炼金房，$p。这是个休息与探索的地方。\n\n就这些奥能样本而言，我不知道他们的主人是谁，也就没法将他们物归原主了。\n\n我打算试试灌注。在不同的人口中，奥术的滋味千变万化——可能甜蜜，可能酸涩，甚至可能不是一种味觉，而是一种感觉……我常听人说，像是气泡的感觉。', 66384),
(299257, 'zhCN', '<游侠维多兰眼神呆滞，气息急促，但最终稳定了下来。>\n\n克雷安？……克雷安，我们这次又惹上什么祸了？', '', 66384),
(299256, 'zhCN', '我今天的愿望单上可没有死里逃生这一条啊。维多兰差点就要射穿那条毒蛇的脑袋了。她的反应真快，仿佛知道我们就在那里。她根本就是在戏耍我们。\n\n<克雷安吮了一口饮料。>\n\n嗯，我已经感觉好多了。\n\n谢谢你，$p，我们欠你一份情了。', '', 66384),
(299255, 'zhCN', '要不是有你相助，我就会失去我的两名游侠……和朋友。\n\n正是依托金雾村这样的地方，银月城才能长久屹立。如果我们的镇子沦陷，主城也必将倾颓。这就是远行者之道。\n\n游侠维多兰可能无法完全康复了。不论我们与魔法有着怎样的关系，奥能都是生命精华的关键部分。纳迦公主肯定夺走了他的奥能。\n\n<哈斯温里奥瞥了一眼努米亚，神色顿时舒缓了。>\n\n努米亚向我保证，她正在鼓捣一些东西，什么奥术灌注的酒……听起来很有潜力。', '', 66384),
(299253, 'zhCN', '你也知道，没人对暗松部族发号施令。我们四处游荡，只听从各自内心火焰的指引。', '', 66384),
(299252, 'zhCN', '', '恶齿部族最好的工匠正在修理我们的武器，祖尔加拉。', 66384),
(299251, 'zhCN', '', '我们已经在尽快赶工了。但在上次袭击里，我们很多武器都坏了。', 66384),
(299238, 'zhCN', '', '不能再拖延了。我必须立刻返回哈籁恩达尔。', 66384),
(299233, 'zhCN', '祖尔加怒视着祖尔加拉。', '', 66384),
(299232, 'zhCN', '', '战士们，你们可以解散了。回去陪陪家人吧。逝者由我们来安葬。', 66384),
(299228, 'zhCN', '', '我留下来陪着布瑞克。万一他突然清醒了，或者想自己乱跑就不好了。', 66384),
(299201, 'zhCN', '我预计戴上它们就能获得充沛的精力与活力。', '', 66384),
(299200, 'zhCN', '', '很好。我会在那里等你。', 66384),
(299199, 'zhCN', '', '邪教这番“款待”我心领了。是时候离开了。', 66384),
(299198, 'zhCN', '', '他们很快就会追来。你最好赶快消失。', 66384),
(299197, 'zhCN', '', '你自由了。现在快跑吧。', 66384),
(299196, 'zhCN', '', '锁链解开了。快走，别回头。', 66384),
(299193, 'zhCN', '', '我看够了。今天，这些囚犯必须重获自由。至于折磨他们的人就是死路一条。', 66384),
(299192, 'zhCN', '', '他们给自己搭了个小堡垒……', 66384),
(299190, 'zhCN', '鲁斯苏拉叫停战斗，可蘑菇不听，植物不听，没有谁愿意停下来听！\n\n战争循环往复，菌盖打茎杆，茎杆打菌盖。\n\n鲁斯苏拉想出个办法来制止这一切……很奇特的办法，也许能奏效。\n\n首先，需要变得很大！', '鲁斯苏拉叫停战斗，可蘑菇不听，植物不听，没有谁愿意停下来听！\n\n战争循环往复，菌盖打茎杆，茎杆打菌盖。\n\n鲁斯苏拉想出个办法来制止这一切……很奇特的办法，也许能奏效。\n\n首先，需要变得很大！', 66384),
(299189, 'zhCN', '', '他刚才……是赤手空拳把那块烧红的炭递给你的？', 66384),
(299162, 'zhCN', '', '勇士。\n\n我的时间有限。你需要什么吗？', 66384),
(299145, 'zhCN', '你！有头脑的战士！快过来，要进行和平谈判！', '你！有头脑的战士！快过来，要进行和平谈判！', 66384),
(299135, 'zhCN', '你考虑的时候，我需要一顿美餐，一杯热酒。一起来吧，小子。还有你，$n。', '', 66384),
(299134, 'zhCN', '我还需要再想清楚，该怎么处置这面盾牌。', '', 66384),
(299130, 'zhCN', '太阳之井无法再维持现状了。我们在这场拉锯战中开始败下阵来。\n\n用不了多久，萨拉塔斯就会发起总攻。', '', 66384),
(299121, 'zhCN', '噢，别担心，不会因为我而受到影响的。', '', 66384),
(299110, 'zhCN', '我无法面对此刻集结在太阳之井的人们。', '', 66384),
(299105, 'zhCN', '血色十字军的创始人是我亲自祝圣的一名圣骑士。长久以来，我将他们看作是自己识人不明的产物，现在也这么想。', '', 66384),
(299078, 'zhCN', '', '这个……没有举起武器。\n\n奇怪。', 66384),
(299077, 'zhCN', '你不是来把我们捣成护土的？\n可疑……', '你不是来把我们捣成护土的？\n可疑……', 66384),
(299076, 'zhCN', '', '你要是不停下来，就只会缓慢而痛苦地死去！', 66384),
(299068, 'zhCN', '先锋军虔诚地信仰圣光，我也一样。但我感觉圣光令我满腔怒火，我……那些时候我不知道应该作何感想。', '', 66384),
(299062, 'zhCN', '', '我们急需你的援助。快来找我，圣光会送你前往奎尔丹纳斯。', 66384),
(299056, 'zhCN', '不，我的加拉。因为你是我的侄女；因为我知道，你的心中有火；因为我爱你胜过世间万物。', '', 66384),
(299055, 'zhCN', '', '那我去。为了我们的族人，也为了你，叔叔。', 66384),
(299053, 'zhCN', '', '“哈谢”？我又不是什么女祭司，也不是什么先知或领袖。', 66384),
(299052, 'zhCN', '如果说有谁能从神灵那里得到答案，那个人一定是你。', '', 66384),
(299045, 'zhCN', '', '你必须收集斯托玛兰核心才能在堡垒中构筑防御工事。一旦我们激活奇点锚点，这些防御工事将是保护它的关键。\n\n你想看看都能建造哪些防御工事吗？', 66384),
(299042, 'zhCN', '', '斯托玛兰堡垒中进行过无数关于传送门与虚空畸能的实验。\n\n奇点锚点是我们为消除此地潜在危险而创造的装置。一旦激活，它将中和此处所有残留的虚空能量。\n\n想必萨拉塔斯和吞噬军团对此会非常不悦吧！', 66384),
(299015, 'zhCN', '', '在黑暗中孤身一人，苦苦挣扎，却还是渴求力量。活该这么死去。', 66384),
(298877, 'zhCN', '圣光会净化一切！', '', 66384),
(298876, 'zhCN', '见识一下圣光的狂怒吧！', '', 66384),
(298875, 'zhCN', '撑住！我抓住你了！', '', 66384),
(298874, 'zhCN', '呃……护光者……我们……会和他们……一样……', '', 66384),
(298872, 'zhCN', '圣光有令，你们休想阻止！', '', 66384),
(298866, 'zhCN', '你们早晚会明白。', '', 66384),
(298861, 'zhCN', '你们心甘情愿地选择与圣光为敌。', '', 66384),
(298860, 'zhCN', '太有意思了！', '', 66384),
(298858, 'zhCN', '看来你需要我帮你一把。', '', 66384),
(298854, 'zhCN', '怎么了？感觉有点沉了吧！', '', 66384),
(298845, 'zhCN', '', '北部的虚灵能量发生了扰动。拿一件虚灵工具，你就能收集他们的能量了。', 66384),
(298844, 'zhCN', '', '虚灵部队正在重整旗鼓，但依然手足无措。拿上一件工具，去查明究竟是怎么回事。', 66384),
(298843, 'zhCN', '', '扰动暂时归于平静了。', 66384),
(298839, 'zhCN', '小心那些飞溅物。', '', 66384),
(298836, 'zhCN', '太吵了！', '', 66384),
(298835, 'zhCN', '奥威娜，$n，感谢女神！永歌森林危在旦夕！', '', 66384),
(298834, 'zhCN', '你在艾林裂隙中寻找答案的时候，我返回银月城请教了魔导师们。\n\n我们还没来得及讨论发现，就收到了远行者居所北部符文石的消息。光绽似乎因为某种原因而陷入了狂乱。如果不立即采取行动，整个永歌森林都会沦陷。\n\n但愿奥威娜的长老们能认清眼前的威胁。', '', 66384),
(298833, 'zhCN', '', '不成功，便成仁。', 66384),
(298832, 'zhCN', '', '我会带着你们一起走向下一个黎明。我不惜牺牲一切。', 66384),
(298831, 'zhCN', '', '加勒尔……我希望你能找到生前不曾获得的安宁。', 66384),
(298830, 'zhCN', '', '可愈合了的伤疤仍是一道伤疤。', 66384),
(298829, 'zhCN', '', '你让我学会了超越它，你的训诫让我学会了生活。', 66384),
(298828, 'zhCN', '最好捂上耳朵！', '', 66384),
(298827, 'zhCN', '', '我不会问你是否为我骄傲，又是否看见了我手上沾染的鲜血。', 66384),
(298826, 'zhCN', '', '可我的手依然在恐惧中颤抖，我的心中依然满是疑惑。', 66384),
(298825, 'zhCN', '', '圣光回应了，范德罗尔。我没有动摇，它回应了我。', 66384),
(298824, 'zhCN', '你打败了我的阿特洛苏斯？哦，这可太美妙了！', '', 66384),
(298821, 'zhCN', '队长，有我、维多兰还有$p在，你就放一万个心吧。', '', 66384),
(298820, 'zhCN', '我们一定能带回喜讯，队长。', '', 66384),
(298818, 'zhCN', '见证我的阿特洛苏斯吧！', '', 66384),
(298817, 'zhCN', '别被打中了。', '', 66384),
(298816, 'zhCN', '勇敢点。', '', 66384),
(298815, 'zhCN', '我都忘记这里有座雕像了。', '', 66384),
(298814, 'zhCN', '你扛得住！', '', 66384),
(298797, 'zhCN', '这下会很疼的。', '', 66384),
(298796, 'zhCN', '注意脚下！', '', 66384),
(298794, 'zhCN', '这边！', '', 66384),
(298792, 'zhCN', '', '对单独的花朵动手是无济于事的，我们需要采取更猛烈的措施。', 66384),
(298791, 'zhCN', '女神啊……', '', 66384),
(298790, 'zhCN', '', '他们都盼着为他献身，那就成全他们吧。', 66384),
(298789, 'zhCN', '', '我已经调集了所有能够上阵的牧师来抵挡虚空。这虽然没法击退吞噬军队，但能阻止不合时宜的凡人造成污染。', 66384),
(298788, 'zhCN', '', '我担心那个虚空精灵会溜回来，令我们在太阳之井的努力付诸东流。', 66384),
(298787, 'zhCN', '那好吧，维纳尔。看来我们的争执只会让狮鹫发怒。', '', 66384),
(298785, 'zhCN', '我理解你的担忧，科鲁斯。对我的族人而言，圣光和太阳之井是一回事。他们虽有怨言，但一定会接受先锋军的。', '', 66384),
(298781, 'zhCN', '为什么你不能再强一些？', '', 66384),
(298780, 'zhCN', '艾林之尘增强了我族对自然的掌控力，这应该足以克制光绽的快速生长了。', '', 66384),
(298776, 'zhCN', '我真想看着你们全都丧命！泰拉，干掉他们！', '', 66384),
(298774, 'zhCN', '即使此刻，在我胜利之时，我也得向她卑躬屈膝！', '', 66384),
(298773, 'zhCN', '', '当然，你得有礼有节地将它收下才行。', 66384),
(298772, 'zhCN', '', '又是一场战斗。我上次受的伤还没好呢！', 66384),
(298770, 'zhCN', '', '这一切……竟是为了那个卑劣的萨拉塔斯……', 66384),
(298769, 'zhCN', '', '暮光之刃要为他们残害的每一个人血债血偿。', 66384),
(298767, 'zhCN', '', '如果你的影卫当年就能捕获它，没让她夺取这股力量就好了。', 66384),
(298766, 'zhCN', '可我的职责未尽……我还……', '', 66384),
(298764, 'zhCN', '', '看来你有客人了，萨哈达尔。记住我们谈过的话。', 66384),
(298759, 'zhCN', '', '你们的苦难永无尽头。', 66384),
(298746, 'zhCN', '', '拜托，队长，请你接下来二十四小时别再逞英雄了。好好休息，喝上一杯。如果痛感加剧，立刻通知我。', 66384),
(298745, 'zhCN', '但他们没有这么做。他们吞噬了奥能，将剩余的都运到了无尽之海上。', '', 66384),
(298744, 'zhCN', '', '纳迦囤积的奥能足以对村子发起毁灭性的袭击了。', 66384),
(298741, 'zhCN', '她就是这么告诉萨哈达尔的。或许那些话是真的。', '', 66384),
(298733, 'zhCN', '体型适中的具象都提供不了多少艾林之尘。就算你狩猎几年，也只能收集到一小管。', '', 66384),
(298732, 'zhCN', '', '我们不能从轻松的猎物身上收集吗？', 66384),
(298729, 'zhCN', '', '他在用他们开启传送门！不能让他跑了。', 66384),
(298728, 'zhCN', '', '那个懦夫制作了一道屏障。摧毁虚空法器，屏障就会崩塌。', 66384),
(298727, 'zhCN', '太烫了！给盾牌泼水，让它冷却下来。', '', 66384),
(298726, 'zhCN', '', '安忒诺里安这样的渣滓就适合躲在这里。', 66384),
(298725, 'zhCN', '圣物送到了，太阳之井暂时安全了。', '', 66384),
(298721, 'zhCN', '谢谢，$n。我们的防线信仰坚定，但我们依然是血肉之躯。这些圣物能增强我们一段时间。', '', 66384),
(298719, 'zhCN', '$n，请你把圣物送过去，我有话要和阿拉托尔单独说。', '', 66384),
(298717, 'zhCN', '阿拉托尔，我无意让你背上更沉重的负担。礼拜堂之旅是拯救太阳之井的关键。', '', 66384),
(298714, 'zhCN', '不，阿拉托尔。我希望你能找到一条不同的道路。', '', 66384),
(298713, 'zhCN', '这是所有圣骑士的命运吗？要么牺牲并成为传说，要么被狂热和愤怒吞没？', '', 66384),
(298712, 'zhCN', '', '没有你，我们都到不了这里。', 66384),
(298709, 'zhCN', '', '我在它体内感受到了她的呼唤，这是艾林哈籁的造物！它不会伤害我！', 66384),
(298705, 'zhCN', '影卫冒着一切风险来壮大吞噬军团。要是风行者发现了我们的勾当——', '', 66384),
(298702, 'zhCN', '', '哦，这里可没有什么“陷阱”等着触发。你只需成功完成任务，一切按部就班。对你……还有你的族人来说都是如此。', 66384),
(298691, 'zhCN', '我还能听见……我依然听得见。', '我还能听见……我依然听得见。', 66384),
(298689, 'zhCN', '寂静，我需要寂静。', '寂静，我需要寂静。', 66384),
(298686, 'zhCN', '啊——我承受不住了！她在向我歌唱！', '啊——我承受不住了！她在向我歌唱！', 66384),
(298683, 'zhCN', '', '真是原始！你的魔杖和那些朋友无法和我匹敌！', 66384),
(298667, 'zhCN', '等你准备好了再来找我。还有，奥威娜……多保重。', '', 66384),
(298662, 'zhCN', '我必须返回太阳之井。先锋军需要我的智慧。', '', 66384),
(298660, 'zhCN', '闪耀吧，学徒！你丰饶的时刻所剩无几了！', '', 66384),
(298659, 'zhCN', '哎呀，不好，快点！你承受丰饶的极限就快到了！', '', 66384),
(298655, 'zhCN', '动作要快！丰饶之力很快就要撑爆你脆弱的躯体了！', '', 66384),
(298653, 'zhCN', '你们的作为为我增添了荣耀，你们必将获得丰厚的善报！', '', 66384),
(298652, 'zhCN', '', '我知道，但这也改变不了过去。', 66384),
(298649, 'zhCN', '了不起的贡献，我的学徒们！尽情享受这神圣的丰饶恩惠吧！', '', 66384),
(298648, 'zhCN', '为这丰饶的恩赐献上荣耀！', '', 66384),
(298646, 'zhCN', '进入我的领域！追寻那无边无际的丰饶荣光！', '', 66384),
(298645, 'zhCN', '别耽搁了！否则丰饶会被他人抢先夺走！', '', 66384),
(298644, 'zhCN', '你在寻找丰饶？此地应有尽有！你所要做的，仅仅是收获！', '', 66384),
(298643, 'zhCN', '繁荣昌盛，学徒！愿我的丰饶与荣光倾泻而下，如雨般洒落在你凡俗的生命中！', '', 66384),
(298641, 'zhCN', '如果你不介意的话，就请用我赠予你的纯粹丰饶，来换取你想要的吧。', '', 66384),
(298640, 'zhCN', '要明白，这种材料是独一无二的。只有当你做出最卓越的丰饶贡献时，我才会赐予你。', '', 66384),
(298639, 'zhCN', '真正卓越的丰饶成就，将会从我这里得到一份馈赠：纯粹丰饶。', '', 66384),
(298637, 'zhCN', '非常不错的开始。但要记住：你对丰饶的真正领悟，需要通过持之以恒的实践和勤勉的付出加以实现。', '', 66384),
(298636, 'zhCN', '啊，你这脆弱的肉体快要抵达极限了。我必须强行将你移出——当然，这是为了保护你。', '', 66384),
(298634, 'zhCN', '感觉到了吗？这股力量？这股苦痛？', '', 66384),
(298632, 'zhCN', '你收获和贡献得越多，我赐予你的丰饶祝福就越能增强你的能力。感受到那股力量了吗？', '', 66384),
(298631, 'zhCN', '你已经掌握了丰饶的基础。现在，在这个我为你精心设置的小小领域里，证明你的价值吧。', '', 66384),
(298630, 'zhCN', '我准备好将痛苦转化成力量了……', '', 66384),
(298629, 'zhCN', '靠近任意一座丰饶祭坛，你采集的物资便会被迅速地转化为贡献。', '', 66384),
(298628, 'zhCN', '当然，收获的丰饶如果只是沉睡在你的行囊深处，那就毫无意义。', '', 66384),
(298627, 'zhCN', '没错，就连敌人也是。别怕——这个只是为了指导你而召唤出来的。', '', 66384),
(298626, 'zhCN', '矿石、草药、可剥皮的野兽，还有很多——它们都是丰饶的满溢的源泉。', '', 66384),
(298625, 'zhCN', '丰饶自万物中涌流……就像这块矿石。去吧，尽情地采集吧。', '', 66384),
(298623, 'zhCN', '随着战斗结束，真菌人放下了长矛，请求哈籁尼尔停止屠戮。这是鲁斯苏拉的训诫：力量能带来胜利，但佐以仁慈才能取得更伟大的胜利。', '', 66384),
(298622, 'zhCN', '这个真菌人长到了不容忽视的体型，并想凭借一己之力终止战斗。它的一举一动不为击垮战士，而是为了将他们分隔。', '', 66384),
(298621, 'zhCN', '看，鲁斯苏拉，它倡导仁慈的呼声被淹没在战鼓声中。但鲁斯苏拉知道，它有办法在喧闹之中传达出自己的声音。', '', 66384),
(298620, 'zhCN', '第一场冲突被制止了，但怒火没有平息。双方的领袖都执迷不悟，除了一人。', '', 66384),
(298619, 'zhCN', '真菌人的顽强对上了芦塔尼的荆棘，哈籁恩达尔遍地血光。我们哈籁尼尔的介入不为胜利，而是为了剔除这吞噬一切的腐朽。', '', 66384),
(298618, 'zhCN', '去吧。走向它，它会回应你的呼唤。', '', 66384),
(298617, 'zhCN', '做得好，学徒。在我的领域里，你将找到无可估量的丰饶。', '', 66384),
(298616, 'zhCN', '这即是丰饶。', '', 66384),
(298615, 'zhCN', '到我身边来，年轻的学徒。你的教导现在开始。', '', 66384),
(298614, 'zhCN', '没有指引就深入裂隙的人可能会永远迷失。', '', 66384),
(298613, 'zhCN', '奥威娜，求你了，你知道艾林之尘在哪儿。', '', 66384),
(298611, 'zhCN', '但这也是唯一受我们掌控的。', '', 66384),
(298610, 'zhCN', '我有个小小的任务，一起来吧。除了你的感受，我们改变不了什么。', '', 66384),
(298609, 'zhCN', '这并不代表你不能努力地改变世界，改变自己，迎接转机。', '', 66384),
(298608, 'zhCN', '这个世界在许多方面都已支离破碎。你确实应该为此愤怒。', '', 66384),
(298607, 'zhCN', '你想说什么？', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(298606, 'zhCN', '每天，我在引导圣光时感受着它的灼烧，心想着我犯过的每一个错误。', '', 66384),
(298605, 'zhCN', '什么？', '', 66384),
(298604, 'zhCN', '唔，我想你说的一点没错。我确实惹出了好大的祸，你说呢？', '', 66384),
(298603, 'zhCN', '你创造了这种战争的理念。我一直遵守你的训诫，差点在自己的怒火中灰飞烟灭。', '', 66384),
(298602, 'zhCN', '你创立了白银之手，训练过我的父亲，我想这罪过也有你的一份。', '', 66384),
(298601, 'zhCN', '训练要求我们将圣光当作武器。这就是我身为圣骑士的意义吗？', '', 66384),
(298600, 'zhCN', '愿鲁斯苏拉之臂提醒我们收敛锋芒，当慈悲引导狩猎之时，哈籁恩达尔方能长久延续。', '', 66384),
(298599, 'zhCN', '$n，你发现了这把真菌长矛背后的秘密，这可是个难得的殊荣。很想知道你能挖出什么来。', '', 66384),
(298598, 'zhCN', '吩咐的……我都……做了……', '', 66384),
(298597, 'zhCN', '我不会和他们一起丧命！', '', 66384),
(298596, 'zhCN', '别害怕，我虔诚的追随者。我将用你们的力量开辟道路！', '', 66384),
(298595, 'zhCN', '没有别的救赎了！我们必须拯救自己！', '', 66384),
(298594, 'zhCN', '渗透者打算破坏我们成就的一切！消灭他们！', '', 66384),
(298415, 'zhCN', '我们看不清阿拉托尔所说的真相吗？', '', 66384),
(298410, 'zhCN', '', '是这样的。不过它被丢在这里，可能另有原因。', 66384),
(298404, 'zhCN', '……他们把前进的路封上了。来，$n，我们必须追上去。', '', 66384),
(298403, 'zhCN', '', '吞噬军团正在大举进军！坚持住，勇士们！', 66384),
(298402, 'zhCN', '', '影卫来袭！', 66384),
(298401, 'zhCN', '', '现在你们做主了，部落，让他们受苦吧。', 66384),
(298400, 'zhCN', '', '更多防御工事来了——激活它们！', 66384),
(298352, 'zhCN', '', '恩尼斯，队长已经包扎好了。我们来看看你取回的样本吧。', 66384),
(298329, 'zhCN', '已经够多了！很好，你们表现得很英勇。', '', 66384),
(298269, 'zhCN', '我们依然需要被虚空污染的残骸。幸好这在屠戮者高地并不稀缺。', '', 66384),
(298238, 'zhCN', '', '必须警告祖尔加。我们在小径的攻势已经开始！解决掉他们！', 66384),
(298228, 'zhCN', '部落赢了？怎么会这样？', '', 66384),
(298189, 'zhCN', '信标很快就要关闭了！', '', 66384),
(298187, 'zhCN', '虚灵用来存储能量的信标即将激活一段时间。我们来看看谁能取得最多的能量。', '', 66384),
(298186, 'zhCN', '', '长老们控制着艾林之尘的供应。我猜他们并不乐意与外来者分享。', 66384),
(298181, 'zhCN', '有入侵者！准备作战！', '', 66384),
(298180, 'zhCN', '虚空吞没一切！', '', 66384),
(298179, 'zhCN', '', '时间就快耗尽了。', 66384),
(298177, 'zhCN', '', '这次是部落占了上风，就和我预见的一样。', 66384),
(298175, 'zhCN', '', '拿上种子，给其他人看，也许就有答案。', 66384),
(298173, 'zhCN', '', '亲族的花变了，这个却没变。', 66384),
(298138, 'zhCN', '', '联盟收集的虚空最多，胜利属于他们。', 66384),
(298108, 'zhCN', '', '虚空的力量就存放在那些桶里。吸取它，将它送回你的营地。', 66384),
(298092, 'zhCN', '联盟获胜了！都在我意料之中！', '', 66384),
(298087, 'zhCN', '我不会让他们得逞。走，去看看你的同胞。我先向银月城报告这里的情况，然后就跟上来。', '', 66384),
(298086, 'zhCN', '没想到部落居然还有点本事。', '', 66384),
(298074, 'zhCN', '金雾村那些失踪的村民依然音讯全无。现在连游侠维多兰也不见了。', '', 66384),
(298069, 'zhCN', '哈斯温里奥队长！海岸传来了消息！', '', 66384),
(298059, 'zhCN', '战争实力的考验！护送你的多曼纳尔抵达终点，能走到最后就算胜利！', '', 66384),
(298047, 'zhCN', '$p，送他们走人！', '', 66384),
(298036, 'zhCN', '一点用都没有！这让我怎么工作啊。这些人根本欣赏不了我的手艺！', '', 66384),
(298034, 'zhCN', '', '$n，哈杜伦——我们必须保护哈尔玛拉！', 66384),
(298017, 'zhCN', '这个已经完全没救了……干脆铺满亮片，收工算了！', '', 66384),
(298015, 'zhCN', '唔……不不不，我还是喜欢长毛丝绒！', '', 66384),
(298009, 'zhCN', '我需要点上档次的！有品位的——我要闪光的雪纺纱！', '', 66384),
(297972, 'zhCN', '这看起来不够贵气——拜托，用长毛丝绒！', '', 66384),
(297969, 'zhCN', '这里的布料也太多了——把我的剪刀递过来！', '', 66384),
(297968, 'zhCN', '下一个！', '', 66384),
(297967, 'zhCN', '闪烁其词的人太多了……这里可能还酝酿着什么更大的阴谋。', '', 66384),
(297966, 'zhCN', '有帮手的话，至少能更快伺候好这些业余爱好者……', '', 66384),
(297964, 'zhCN', '秒？……难道是暮光之刃，到了这里？', '', 66384),
(297963, 'zhCN', '希望你的处境能比上一个客人好一点，旅行者。', '', 66384),
(297962, 'zhCN', '', '我们为什么要囤货？', 66384),
(297960, 'zhCN', '', '如果芦塔尼向你们的家园进军，他们的亲属或许知道些什么。你可以找到不少人。', 66384),
(297957, 'zhCN', '奥威娜……那是什么东西？', '', 66384),
(297956, 'zhCN', '', '这里有个芦塔尼？它手里的是什么？', 66384),
(297954, 'zhCN', '', '我把信留在箱子上了。去看看。', 66384),
(297953, 'zhCN', '我收到了太阳之井的消息，法奥的计划奏效了。守护者们又能继续抵挡虚影风暴了。', '', 66384),
(297952, 'zhCN', '洛萨之子会在这里逗留一阵子。奥术秘社需要我们保护。至少我还要再喝一杯。', '', 66384),
(297951, 'zhCN', '谢谢你一直以来的帮助，$n。银月城肯定很想念我们，我们该回去了。', '', 66384),
(297950, 'zhCN', '我本来想把盾牌挂起来。现在我会带上它，我要保护艾泽拉斯的人民。', '', 66384),
(297949, 'zhCN', '谢谢，谢谢大家。我不会让你们失望。', '', 66384),
(297947, 'zhCN', '也许我可以和德兹科一样，靠服务他人来展现这一点。在保护艾泽拉斯的时候，这面盾牌能时刻提醒我。', '', 66384),
(297946, 'zhCN', '我会的。法奥告诉我，不论是战争还是和平，白银之手都该为无法自保的人们挺身而出。', '', 66384),
(297944, 'zhCN', '确实很合适。', '', 66384),
(297938, 'zhCN', '你父亲拒绝了那份传承。你只要愿意就能接受。', '', 66384),
(297937, 'zhCN', '阿拉托尔，你打算怎么处置图拉扬的盾牌？', '', 66384),
(297932, 'zhCN', '哈哈哈……那根本就讲不通嘛。哈哈哈。', '', 66384),
(297929, 'zhCN', '……然后我就说，“如果那是我的狮鹫，那蹲在蛋上的是谁啊？”', '', 66384),
(297928, 'zhCN', '我们掌握了野兽的身形。', '', 66384),
(297927, 'zhCN', '看看周围吧。部落，联盟 ……受够了战争的人都会在这里歇息片刻。', '', 66384),
(297926, 'zhCN', '$n，帮我们带一轮饮料吧？记在我的账上。', '', 66384),
(297925, 'zhCN', '匿踪不是我们唯一的天赋。', '', 66384),
(297924, 'zhCN', '卡德加介绍的。这是在某个异想天开、花里胡哨的什么次元里头。有热菜冷饮，靠魔法出入。', '', 66384),
(297923, 'zhCN', '这是什么地方？好像都不在艾泽拉斯了。', '', 66384),
(297920, 'zhCN', '你考虑的时候，我需要一顿美餐，一杯热酒。一起来吧，小子。还有你，$n。', '', 66384),
(297919, 'zhCN', '我只需要再想清楚，该怎么处置这面盾牌。', '', 66384),
(297918, 'zhCN', '阿拉托尔……赞美圣光，这一切或许都是机缘。', '', 66384),
(297917, 'zhCN', '所以我就这么做了。我父亲还没有准备好改变，但我准备好了。', '', 66384),
(297916, 'zhCN', '我也是……可有个智者说过，“我们改变不了什么，除了自己的感受。”', '', 66384),
(297914, 'zhCN', '这……真扫兴。我还盼着他会有不同的反应。', '', 66384),
(297913, 'zhCN', '我给了，可他说“有些事情永远无法挽回”，然后拒绝了。', '', 66384),
(297912, 'zhCN', '你怎么还留着盾牌？没把它交给你父亲吗？', '', 66384),
(297911, 'zhCN', '停！温度不太合适。我们重来吧，准备好了就告诉我。', '', 66384),
(297910, 'zhCN', '加入凤凰羽毛，让温度再高一些。', '', 66384),
(297909, 'zhCN', '再给我一根钢锭。', '', 66384),
(297907, 'zhCN', '加些龙尘进去，增添一点力量。', '', 66384),
(297906, 'zhCN', '开始吧！我来捶打，你负责控制温度！', '', 66384),
(297905, 'zhCN', '这样阿拉托尔就有机会重铸父亲的盾牌了。他需要你帮他一把。', '', 66384),
(297904, 'zhCN', '我会让图拉扬暂时离开岗位，但这么做并不容易。', '', 66384),
(297902, 'zhCN', '你遗忘了传统的价值，奥威娜。到回响之穴去，好好回想一下身为哈籁尼尔意味着什么。', '', 66384),
(297900, 'zhCN', '$n，请到熔炉来找我，我需要你帮忙修理盾牌。', '', 66384),
(297895, 'zhCN', '这个主意很不错。', '', 66384),
(297894, 'zhCN', '我想……我想把盾牌修好，再还给他。', '', 66384),
(297892, 'zhCN', '我完全不知情，我都不知道父亲经历过什么。', '', 66384),
(297890, 'zhCN', '你的表现……真是无与伦比。', '', 66384),
(297889, 'zhCN', '久等了——我披挂上阵也需要时间。', '', 66384),
(297888, 'zhCN', '了不起！太精彩了！来！让我给你们准备些更有趣的。', '', 66384),
(297887, 'zhCN', '再让我瞧瞧你们刚才的潜力。', '', 66384),
(297886, 'zhCN', '我想你们至少能让它好好锻炼一番。', '', 66384),
(297885, 'zhCN', '你们赢了！来——别让自己闲着，我要准备让阿特洛苏斯陪你们打擂台！', '', 66384),
(297884, 'zhCN', '啊！我最新的玩具，塔兹拉尔！这场战斗注定难以忘怀。', '', 66384),
(297883, 'zhCN', '你们轻轻松松就解决了它们。布鲁托克，让他们明白什么叫追悔莫及。', '', 66384),
(297882, 'zhCN', '我的几丁高斯会是个完美的暖场。向我证明你们的价值。', '', 66384),
(297881, 'zhCN', '只要让大家看得开心，随便你们怎么闹腾。战斗开始！', '', 66384),
(297852, 'zhCN', '', '哼，你又给了我一次很好的忠告。也许你我二人比表面上要相近得多。', 66384),
(297851, 'zhCN', '晴风村需要你，勇士。那里遭遇了光绽的问题。', '', 66384),
(297849, 'zhCN', '', '坐下吧，我们马上开始仪式——但要做好准备。这可是战争之神，无论他梦到什么，我们都必须完成试炼。', 66384),
(297848, 'zhCN', '', '你的意思是我该为他感到惋惜？就因为他有什么“激动的情绪”，所以就被原谅吗？', 66384),
(297847, 'zhCN', '', '这一定就是利拉祖所说的火焰了。', 66384),
(297846, 'zhCN', '', '不，我是希望你能从中吸取教训。放下你对神灵和祖尔金的愤怒吧，这份怒火只会让你误入歧途。', 66384),
(297845, 'zhCN', '', '后来我才明白，祖尔金也是一样。他的愤怒情有可原，但这份愤怒在他心中溃烂，最终吞噬了他。', 66384),
(297844, 'zhCN', '在你处理其他事务的时候，我会和先锋军协商。', '', 66384),
(297843, 'zhCN', '', '我曾因祖尔金的所作所为而怒火中烧，多年来一心只想向他复仇。', 66384),
(297842, 'zhCN', '哈杜伦和你的哈籁尼尔朋友去协助应对这个威胁了。他们会在晴风村等你。', '', 66384),
(297841, 'zhCN', '我们无力同时对抗虚影风暴和光绽的侵袭。', '', 66384),
(297840, 'zhCN', '想想那无尽的可能……还有哪些生灵会拥有这样的力量？', '', 66384),
(297839, 'zhCN', '你猜得没错，这就是你父亲的盾牌。它在战场上四分五裂，碎片留在了这里。', '', 66384),
(297837, 'zhCN', '如果暮光之刃还握有其他情报，要么物归原主，要么就地销毁。把能带的都带走，其他的全烧掉。', '', 66384),
(297834, 'zhCN', '你救下了你的弟弟，也凭自己的力量，捍卫了你作为祖尔金孙女的领导地位。', '', 66384),
(297833, 'zhCN', '我才刚开始测试它的极限。来，见证它的无穷潜力吧。', '', 66384),
(297832, 'zhCN', '看来你明白为什么法奥要把你带来了。', '', 66384),
(297830, 'zhCN', '拜托你……为了领教明缝先生的绝世手艺，我已经等了很久了。', '', 66384),
(297827, 'zhCN', '', '奴仆们，别再让我失望了。', 66384),
(297826, 'zhCN', '', '要么宰了这些入侵者，要么被我吞噬。', 66384),
(297825, 'zhCN', '', '去吧。让我看看凭什么要容忍你们这群饭桶。', 66384),
(297824, 'zhCN', '', '证明你们的价值，可悲的走狗们。', 66384),
(297820, 'zhCN', '', '圣光仍在燃烧！那该死的纳斯雷兹姆！', 66384),
(297819, 'zhCN', '', '埃基尔松让你踏上哈谢之路的选择是正确的。祖尔加拉，你心中的火焰燃烧得如此炽烈。', 66384),
(297818, 'zhCN', '添上炭火！看那火焰腾空而起，让死寂的火焰重燃生机！', '', 66384),
(297759, 'zhCN', '', '我倒要看看下一个会是谁……', 66384),
(297709, 'zhCN', '', '就让火焰来考验我的灵魂吧。', 66384),
(297708, 'zhCN', '', '我们以后会时刻提防邪枝的动静。和我一起回去吧，酋长正准备犒赏你呢。', 66384),
(297707, 'zhCN', '', '那个怪物死了，邪枝巨魔也赶跑了，我们枯木部族总算能太平一阵子了。', 66384),
(297702, 'zhCN', '', '小心，$n。他看起来很强……很不稳定。', 66384),
(297699, 'zhCN', '我的灵魂在哪儿？你都干了什么？', '', 66384),
(297698, 'zhCN', '拉克图尔……醒了。拉克图尔……饿了！', '', 66384),
(297693, 'zhCN', '', '但那个怪物就交给你了。', 66384),
(297692, 'zhCN', '', '这里还有许多愤怒的灵魂。我会拖住他们，不让他们成为那个怪物的养料。', 66384),
(297690, 'zhCN', '', '她死了，邪恶却阴魂不散。', 66384),
(297685, 'zhCN', '', '有一些灵魂依然可以得救。你去和她交手，我来释放所有能找到的灵魂。', 66384),
(297684, 'zhCN', '不能对他们的恳请视而不见，但我在太阳之井分身乏术。我想请你帮忙，找到叛逃者并救出他们。', '', 66384),
(297683, 'zhCN', '', '她在做什么？她在撕裂灵魂，扭曲他们！把他们喂给那个怪物！', 66384),
(297677, 'zhCN', '', '情况比我们预想得更糟。我有多少族人在这里丧了命？', 66384),
(297669, 'zhCN', '', '如果那个怪物的创造者就在这里，我们就要阻止他们，还要将他们的造物一起消灭。', 66384),
(297668, 'zhCN', '这些意志薄弱的蠢货快让我烦死了，但为了维持社交礼仪，我还是得撑下去。\n\n侍者跑哪儿去了？我需要喝一杯来缓缓。', '这些意志薄弱的蠢货快让我烦死了，但为了维持社交礼仪，我还是得撑下去。\n\n侍者跑哪儿去了？我需要喝一杯来缓缓。', 66384),
(297662, 'zhCN', '', '使用亡者的灵魂来施展强力法术……希望他们将我的族人带到这里能有别的原因。', 66384),
(297661, 'zhCN', '', '那……很不自然。还有流入其中的能量……这是妖术。', 66384),
(297650, 'zhCN', '我相信你会全力以赴完成任务。', '', 66384),
(297649, 'zhCN', '', '这正适合我。', 66384),
(297647, 'zhCN', '头顶的风暴已经让银月城躁动不安了。我不能让人民因为其他理由而惶惶不安。', '', 66384),
(297645, 'zhCN', '暮光之刃夺走了敏感情报。不止关于塔奎林，还关乎整个奎尔萨拉斯。', '', 66384),
(297642, 'zhCN', '', '您还真是谨小慎微。摄政王，是什么任务？', 66384),
(297635, 'zhCN', '', '不彻底根除这罪恶的根源，绑架就不会停止。跟我来。', 66384),
(297633, 'zhCN', '', '打得好，$n。我把活着的都救出来了。可姆罗金为什么要将他们带来？', 66384),
(297629, 'zhCN', '今日港湾格外宁静。真是难得的恩泽。', '', 66384),
(297623, 'zhCN', '还有个枯木巨魔，姆罗金又能多赚一笔了。', '', 66384),
(297618, 'zhCN', '我的间谍飞鹰盯上了什么？一个闯入者，一个入侵者！可你休想抢走我的猎物！', '', 66384),
(297617, 'zhCN', '光绽控制了，我们又少了一条战线，可以专心抵御萨拉塔斯的部队了。', '', 66384),
(297616, 'zhCN', '', '我几乎站不稳了。但我们仍然不知道费恩德尔在哪……', 66384),
(297615, 'zhCN', '力量……流遍了我的全身！', '', 66384),
(297613, 'zhCN', '谁在偷我的礼物？谁把哈尔拉兹的猫崽子放跑了？', '', 66384),
(297611, 'zhCN', '', '就是他把我的族人带到了这里……暂时……先避开他。', 66384),
(297605, 'zhCN', '', '呵，我太了解那些“神神叨叨”的神灵代言人了。多谢了，沃恩扎拉。也许这次的试炼会简单点。', 66384),
(297603, 'zhCN', '', '我担心他们会成为黑暗目的的祭品。来，我会指引你。我们要把族人都救出来。', 66384),
(297601, 'zhCN', '', '我利用暗影窥探了洞窟里的情况。我看到了族人，有死有活，半死不活。', 66384),
(297599, 'zhCN', '', '$n。Oraka\'zul！我很幸运能和你一起行动。', 66384),
(297581, 'zhCN', '先是鱼人，又是纳迦！唉，接下来又会有什么？', '', 66384),
(297576, 'zhCN', '还有上古时期的谷物面包？这口感比射中靶心还要刺激。', '', 66384),
(297574, 'zhCN', '', '这是罗曼斯最喜欢的东西之一。要是不见了，他肯定会亲自传送过来找。', 66384),
(297572, 'zhCN', '纳迦正在走私黑市的水果？不，肯定不是这样……', '', 66384),
(297546, 'zhCN', '还有一个。过来吧。', '', 66384),
(297538, 'zhCN', '', '做得好。但我们还要保持警惕，不能让光绽再次蔓延。', 66384),
(297534, 'zhCN', '', '我们必须飞上高空，击退光绽！', 66384),
(297532, 'zhCN', '我们就要结束这一切了。最好赶紧处置殆希莫斯，别让他有机会背叛我们。', '', 66384),
(297520, 'zhCN', '她死得光荣。但眼看忠于我的人一个个死去……这正是我的重担。而作为哈谢，这也将成为你的重担。', '', 66384),
(297519, 'zhCN', '', '萨拉塔斯……她曾经也是凡人？', 66384),
(297516, 'zhCN', '随着你的力量增强，幻象变得愈发清晰……', '', 66384),
(297514, 'zhCN', '', '做得好，阿曼尼的小家伙。你……通过试炼了，去肩负起纳洛拉克的重担吧。', 66384),
(297509, 'zhCN', '它来了。虚空在上，它来了！外面有人吗？', '', 66384),
(297506, 'zhCN', '我们已经从灰烬中重建过家园了。没有艾林之尘，我们还能依靠什么？', '', 66384),
(297503, 'zhCN', '领袖的道路，本就意味着牺牲。哪怕是要牺牲至珍至爱之物。', '', 66384),
(297502, 'zhCN', '', '站住。在面对神灵之前，你必须先面对……并杀了我。', 66384),
(297501, 'zhCN', '', '怎么这么久才来？没有你在，神灵可不愿意跟我动手。', 66384),
(297487, 'zhCN', '', '回到火边来吧，你的最终试炼正等着你。', 66384),
(297485, 'zhCN', '', '了不起。你已经证明了自己的力量与耐力。可你的忠诚又会如何呢？', 66384),
(297482, 'zhCN', '', '阿曼尼对枯木部族的求援置之不理太久了。今天，这一切都该结束了。', 66384),
(297481, 'zhCN', '', '神灵意念中的季节正在变迁。狂风渐起，你唯一能做的就是找个地方躲起来。', 66384),
(297480, 'zhCN', '', '凛冬可不管你是谁。无论是哈谢、长老、孩童还是乞丐，谁都逃不过它的考验。', 66384),
(297479, 'zhCN', '', '哈哈哈！敌人的脑袋，就是我们胜利的战利品。', 66384),
(297478, 'zhCN', '', '做得好。就像藤蔓一样，有些枝条必须剪掉，主干才能活下去。部族总算能活下去了——至少暂时如此。', 66384),
(297477, 'zhCN', '有人正打算成为传奇。让他们的传说就此结束吧。', '', 66384),
(297476, 'zhCN', '整支远征军都和我的父亲有关，是吗？', '', 66384),
(297475, 'zhCN', '时刻关注战利品出现的机会，比如现在！', '', 66384),
(297474, 'zhCN', '', '阿曼尼的哈谢会派出最可靠的战士除掉这些家伙，这一切都是为了部族的存续。', 66384),
(297473, 'zhCN', '你喜欢好东西吧？那就去找到它们。', '', 66384),
(297472, 'zhCN', '', '寒冬时节，总会出现像“囤积者”那样的人，他们的贪婪会拖垮别人。', 66384),
(297470, 'zhCN', '嗯，怎么回事？好像是桩大事。', '', 66384),
(297464, 'zhCN', '什么怪味？快去给我一探究竟。', '', 66384),
(297463, 'zhCN', '那块肉已经放了很久了。你居然还把它吃了？有意思。', '', 66384),
(297461, 'zhCN', '我的计划是多么得天衣无缝！', '', 66384),
(297459, 'zhCN', '看看这些虚灵！他们的东西也能为我们所用。去抢夺吧。', '', 66384),
(297456, 'zhCN', '瞧？它们很有用，记住这一点。', '', 66384),
(297455, 'zhCN', '那些野兽需要好好管教，然后就能在战场上为你卖命了。', '', 66384),
(297452, 'zhCN', '怎么无所事事？你们联盟不该是斗士吗？快去证明我没看错。', '', 66384),
(297451, 'zhCN', '', '神灵梦见了阿曼尼的往昔，在那个年代，凛冬是他们唯一的敌人。为过冬做好准备，这是你的第一道试炼。', 66384),
(297449, 'zhCN', '', '哈谢的强大，源于麾下战士的实力。因此，你也要在纳洛拉克的梦境中接受考验。', 66384),
(297447, 'zhCN', '', '不必担心你那个想成为哈谢的朋友。纳洛拉克——沉睡者、战争之神，会亲自考验她的力量。', 66384),
(297443, 'zhCN', '', '看哪，雄鹰们朝着山顶的神庙飞过去了。或许这是给我们的一份邀请。', 66384),
(297440, 'zhCN', '', '神龛既已点亮，雄鹰们便开始行动了。', 66384),
(297437, 'zhCN', '', '做得好。我们需要时刻警惕，才能控制住盲目之花。', 66384),
(297436, 'zhCN', '', '一夜之间，哈籁恩达尔遍地都是苦花。赶快烧掉，别让它蔓延开。', 66384),
(297433, 'zhCN', '', '这应该能阻挠他们的行动了。', 66384),
(297432, 'zhCN', '', '虽然我们尽了全力，但影卫的阴谋诡计仍在继续。去干扰他们的行动。', 66384),
(297429, 'zhCN', '$p？感谢圣光。随着风暴消散，我们或许能有一丝胜算。', '', 66384),
(297428, 'zhCN', '', '那就让我们以风行者之名，共同拯救银月城吧。', 66384),
(297427, 'zhCN', '我们毕竟是风行者，从来没有什么外力能成功左右我们的意志。', '', 66384),
(297426, 'zhCN', '我……明白。但我向你保证，这种事永远不会发生在我身上，也不会发生在你身上。', '', 66384),
(297425, 'zhCN', '', '我害怕在危急关头，你会像洛萨克森一样被愤怒吞噬，就像我随时可能被虚空吞噬一样。', 66384),
(297424, 'zhCN', '', '阿拉托尔，这才是真正令我担心的事情。我担心的，从来都不是你会不会受伤，而是圣光会永远地改变你的本性。', 66384),
(297423, 'zhCN', '', '洛萨克森显然也不例外，而图拉扬，自然也是如此。', 66384),
(297422, 'zhCN', '', '也许吧。一千年来，我亲眼看着圣光如何坚定勇士们的决心，但也看到圣光……如何改变了他们。', 66384),
(297421, 'zhCN', '也许，正是这份信念，才让他在那种地方守住了本心，没有迷失自我。', '', 66384),
(297420, 'zhCN', '再想想洛萨克森皈依圣光之前的身份……', '', 66384),
(297419, 'zhCN', '这种事我见得多了——在血色十字军，在我父亲，甚至在我自己身上都见过。', '', 66384),
(297418, 'zhCN', '', '如今，他的狂热却威胁着整个银月城。', 66384),
(297417, 'zhCN', '', '这么久以来，洛萨克森一直认为我的判断力已经被虚空侵蚀了。', 66384),
(297416, 'zhCN', '', '做好准备。是时候去夺取掠食披肩了。', 66384),
(297415, 'zhCN', '我本来想把他们引开，没想到效果好得过头了。', '', 66384),
(297414, 'zhCN', '', '别浪费我的时间！', 66384),
(297407, 'zhCN', '行吧。回头见。', '', 66384),
(297404, 'zhCN', '圣光军团以前就对付过影卫虚灵，这次也没什么不同的。', '', 66384),
(297403, 'zhCN', '萨拉塔斯，诱惑的化身，就连敌人也会屈服于她的低语。\n\n现在你愿意听了吗？', '', 66384),
(297399, 'zhCN', '我告诉你个小秘密，呀。干掉那些妖术师，就能弄到他们的一些守护之灵。', '', 66384),
(297398, 'zhCN', '哇啊啊啊啊啊！', '', 66384),
(297392, 'zhCN', '哈哈哈！呃……我……饿了……', '', 66384),
(297391, 'zhCN', '嘎！需要……能量……', '', 66384),
(297390, 'zhCN', '啊！我要……你的灵魂……', '', 66384),
(297389, 'zhCN', '撕开你的灵魂！', '', 66384),
(297388, 'zhCN', '我抓住你了！', '', 66384),
(297387, 'zhCN', '必须……进食……', '', 66384),
(297386, 'zhCN', '哇！哈哈哈哈！', '', 66384),
(297385, 'zhCN', '拍扁你！', '', 66384),
(297384, 'zhCN', '砸碎！', '', 66384),
(297383, 'zhCN', '重击！', '', 66384),
(297382, 'zhCN', '你很擅长这个，看来该给你准备个全职岗位了吧？', '', 66384),
(297380, 'zhCN', '', '是部落变弱了，还是你不想要宝物了？快去找吧。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(297377, 'zhCN', '来帮忙把这些……活泼的小雏鸟培养成训练有素的坐骑吧。', '', 66384),
(297376, 'zhCN', '哇啊！哈哈！', '', 66384),
(297375, 'zhCN', '灵魂……不……太多了……', '', 66384),
(297373, 'zhCN', '我……感觉……不妙。', '', 66384),
(297372, 'zhCN', '我失去了……一切……', '', 66384),
(297361, 'zhCN', '需要更多力量，更多灵魂！', '', 66384),
(297359, 'zhCN', '是鲜活灵魂的气息！', '', 66384),
(297358, 'zhCN', '必须，攫取，更多！', '', 66384),
(297356, 'zhCN', '', '你的灵魂将被夺走。', 66384),
(297350, 'zhCN', '', 'Ma\'ako！Ma\'ako ka shadra！', 66384),
(297349, 'zhCN', '', '看来远方就有一处宝物。不要放过这个机会！', 66384),
(297348, 'zhCN', '', '抢占先机，夺取你的战利品。', 66384),
(297346, 'zhCN', '', '我要毒害你的灵魂！', 66384),
(297344, 'zhCN', '', '够了！你们不是邪枝的对手！', 66384),
(297342, 'zhCN', '', '我察觉到了即将发生的异动。去探索屠戮者高地，看看是什么情况。', 66384),
(297339, 'zhCN', '', '苦难钻心。', 66384),
(297335, 'zhCN', '', '晦暗急流！', 66384),
(297334, 'zhCN', '', '暗影激荡！', 66384),
(297332, 'zhCN', '', '虚空饿了！', 66384),
(297331, 'zhCN', '', '黑暗吞噬！', 66384),
(297329, 'zhCN', '', '撕碎暗影！', 66384),
(297325, 'zhCN', '', '被黑暗封印吧。', 66384),
(297324, 'zhCN', '', '你……怎么……', 66384),
(297322, 'zhCN', '', 'An\'daka taz no shada。Ke zulo numra kan！Ne\'hideh。Ne\'hideh！', 66384),
(297319, 'zhCN', '', '胆大妄为？那就去死吧！', 66384),
(297315, 'zhCN', '我不屈不挠！', '', 66384),
(297314, 'zhCN', '我冷酷无情！', '', 66384),
(297313, 'zhCN', '你败局已定！', '', 66384),
(297312, 'zhCN', '失败的标记！', '', 66384),
(297308, 'zhCN', '不得开口！', '', 66384),
(297307, 'zhCN', '安静！', '', 66384),
(297306, 'zhCN', '你不能……', '', 66384),
(297302, 'zhCN', '休想夺走启明星！Diel fin\'al！', '', 66384),
(297298, 'zhCN', '请保持静止。', '', 66384),
(297297, 'zhCN', '压制措施是必要之举。', '', 66384),
(297296, 'zhCN', '正在进行管束。', '', 66384),
(297295, 'zhCN', '必须遵守规范。', '', 66384),
(297294, 'zhCN', '遵从是唯一的选择。', '', 66384),
(297293, 'zhCN', '继续实施纪律维护手段。', '', 66384),
(297292, 'zhCN', '正在补给，请待命。', '', 66384),
(297291, 'zhCN', '', '你的折磨将来自墓穴彼岸。', 66384),
(297290, 'zhCN', '安全系统……错误……', '', 66384),
(297286, 'zhCN', '', '愚蠢的精灵，我早说过神灵已经沉寂了！你要是不信，我们就让那个老代言人亲口告诉你！', 66384),
(297282, 'zhCN', '所有学生都要遵守规范。', '', 66384),
(297281, 'zhCN', '真了不起。你有没有考虑过在远行者的队伍里任职？', '', 66384),
(297280, 'zhCN', '', '来，让他们受苦吧。', 66384),
(297279, 'zhCN', '我的远行者在晴风村需要帮手。尽你所能，去对付那里的动物。', '', 66384),
(297276, 'zhCN', '', '任务完成了。', 66384),
(297274, 'zhCN', '', '这里的引力能为你提供更多力量。利用好它，去消灭一些虚灵吧。', 66384),
(297273, 'zhCN', '我现在带你回家，我的挚爱。', '', 66384),
(297272, 'zhCN', '', '圣光令花苞绽放！', 66384),
(297271, 'zhCN', '', '花苞得到了滋养！', 66384),
(297267, 'zhCN', '', '你们这些虫子有点虫群的样子了。', 66384),
(297266, 'zhCN', '', '凭你一人是敌不过那头巨兽的。召集帮手，一起解决它。', 66384),
(297258, 'zhCN', '', '这是什么？试验用的灵魂送上门了？', 66384),
(297255, 'zhCN', '', '让他们起舞吧！', 66384),
(297254, 'zhCN', '', '拖住他们！', 66384),
(297253, 'zhCN', '', '被邪能淹没吧！', 66384),
(297252, 'zhCN', '', '邪能会吞噬你！', 66384),
(297251, 'zhCN', '', '待着别动……', 66384),
(297249, 'zhCN', '', '把你烧个干净！', 66384),
(297248, 'zhCN', '', '陪这个玩玩吧！', 66384),
(297247, 'zhCN', '', '天空……仍是……威胁……', 66384),
(297242, 'zhCN', '播下他们的命运！', '', 66384),
(297241, 'zhCN', '', '尝尝邪能的滋味！', 66384),
(297240, 'zhCN', '直击面门！', '', 66384),
(297239, 'zhCN', '', '这样一来，我们剩下的战士、武器和萨满就更少了……', 66384),
(297238, 'zhCN', '轻而易举！', '', 66384),
(297237, 'zhCN', '够了！', '', 66384),
(297236, 'zhCN', '到此为止了！', '', 66384),
(297235, 'zhCN', '粉碎之怒！', '', 66384),
(297234, 'zhCN', '飞斧断魂！', '', 66384),
(297233, 'zhCN', '我的女主人……逃走了……', '', 66384),
(297228, 'zhCN', '胜负马上见分晓。', '', 66384),
(297227, 'zhCN', '该出手了……', '', 66384),
(297226, 'zhCN', '赶紧的……', '', 66384),
(297225, 'zhCN', '用不着偷偷摸摸。', '', 66384),
(297224, 'zhCN', '无处可藏。', '', 66384),
(297223, 'zhCN', '我让你们休息了吗？快扔箱子！', '', 66384),
(297222, 'zhCN', '上面的！把箱子丢下去砸死他们！', '', 66384),
(297221, 'zhCN', '呃……见鬼……', '', 66384),
(297217, 'zhCN', '什么事都得我亲自来！', '', 66384),
(297216, 'zhCN', '', '咬咬！停下！', 66384),
(297215, 'zhCN', '', '调皮的小咬咬！', 66384),
(297214, 'zhCN', '', '畏惧邪能吧！', 66384),
(297213, 'zhCN', '', '躲得开烈焰吗！', 66384),
(297212, 'zhCN', '适者生存，你活不了。', '', 66384),
(297211, 'zhCN', '你躲得过我，也躲不开内克拉克斯！', '', 66384),
(297210, 'zhCN', '', '认清你的身份！', 66384),
(297209, 'zhCN', '', '退后，你们这些杂种！', 66384),
(297208, 'zhCN', '', '啊，我就要这个。', 66384),
(297206, 'zhCN', '', '咬咬，让妈妈尝一口！', 66384),
(297202, 'zhCN', '', '可是……我的……魔法……', 66384),
(297201, 'zhCN', '专攻要害。', '', 66384),
(297200, 'zhCN', '瞄准心脏。', '', 66384),
(297198, 'zhCN', '正中目标。', '', 66384),
(297192, 'zhCN', '你要为此付出代价！', '', 66384),
(297183, 'zhCN', '内克拉克斯，飞吧！', '', 66384),
(297182, 'zhCN', '消灭他们，内克拉克斯！', '', 66384),
(297181, 'zhCN', '播种，然后收割！', '', 66384),
(297180, 'zhCN', '', '如果光木武器还没准备好，或许暗松萨满能助我们一臂之力。', 66384),
(297179, 'zhCN', '内克拉克斯，出击！', '', 66384),
(297178, 'zhCN', '来我这儿，内克拉克斯！', '', 66384),
(297177, 'zhCN', '', '坚持下去，这些武器是我们对抗虚空的最大希望。', 66384),
(297176, 'zhCN', '干掉他们，内克拉克斯！', '', 66384),
(297173, 'zhCN', '惊恐地冻结吧。', '', 66384),
(297172, 'zhCN', '不许动！', '', 66384),
(297171, 'zhCN', '这下就不妙咯。来，伙计们，该到回忆的长廊上艰难跋涉了。', '', 66384),
(297170, 'zhCN', '碎片肯定都在黑暗部落手中，像战利品一样被瓜分了。', '', 66384),
(297165, 'zhCN', '', '你们族人的处境，远比我想象的危急得多。', 66384),
(297164, 'zhCN', '你不是在说笑吧！', '', 66384),
(297163, 'zhCN', '这地方唯一的圣器是……', '', 66384),
(297151, 'zhCN', '为了支援银月城的守护者，我们正在寻找神器。', '', 66384),
(297149, 'zhCN', '噢，你是个不错的猎物。', '', 66384),
(297147, 'zhCN', '指标送上门来了。准备好了吗，内克拉克斯？', '', 66384),
(297144, 'zhCN', '', '很好。记住你的发现，以后还用得着。', 66384),
(297143, 'zhCN', '', '这里的气息很是古怪。干扰那些虚灵，调查发生的情况。', 66384),
(297138, 'zhCN', '', '自从祖尔金倒下后，各个部族就分崩离析了。暮光之刃趁我们不再团结一致，正在将我们逐个击破。', 66384),
(297133, 'zhCN', '情况不妙。现在我们剩下的都是些老弱病残，还得饿着肚子。', '', 66384),
(297111, 'zhCN', '', '永歌森林和阿曼尼都不会容忍破坏约定的行为。做得好。', 66384),
(297110, 'zhCN', '', '有些邪枝潜行者试图混入永歌森林。寻找他们的魔法来源，把他们揪出来。', 66384),
(297103, 'zhCN', '哈！笑吧，$r，这笑话可真不赖。', '', 66384),
(297102, 'zhCN', '把那个邪恶的战利品带回枯木山崖。小沙德拉正缺个磨牙棒呢。', '', 66384),
(297101, 'zhCN', '大沃沃叫我们砍下邪枝部族的脑袋，你这可真是说到做到啊！', '', 66384),
(297100, 'zhCN', '', '暂且跟上去……但如果这虚空行者敢耍花样，我们随时动手。', 66384),
(297099, 'zhCN', '', '我从没听说过虚空行者会这般……热心肠……', 66384),
(297096, 'zhCN', '', '呃啊！救命！', 66384),
(297092, 'zhCN', '', '无处可藏！', 66384),
(297091, 'zhCN', '', '翻耕大地！', 66384),
(297089, 'zhCN', '', '永别了，老朋友……', 66384),
(297086, 'zhCN', '控制台生效了——立刻开始对接！', '', 66384),
(297085, 'zhCN', '只可惜，你也被虚空腐化了。', '', 66384),
(297084, 'zhCN', '在这么多人中，我以为只有你能理解，阿拉托尔。 ', '', 66384),
(297083, 'zhCN', '想想这会害死多少人啊——相信我们吧。', '', 66384),
(297082, 'zhCN', '洛萨克森，圣光不会这么要求我们。', '', 66384),
(297081, 'zhCN', '', '你们这些闯入者就没完了吗？行行好，在我亲自动手前，自己了断吧。', 66384),
(297080, 'zhCN', '', '我从未看得如此透彻，洛萨克森，可我不愿意去相信。 ', 66384),
(297079, 'zhCN', '虚空蒙蔽了你的判断，它从来都是这么做的！', '', 66384),
(297078, 'zhCN', '你会明白我才是对的，奥蕾莉亚。', '', 66384),
(297077, 'zhCN', '核技工程长，晶塔就要发生致命故障了！', '', 66384),
(297076, 'zhCN', '看起来还少了点什么。要想阻止洛萨克森的话，我们就得找到它们！', '', 66384),
(297075, 'zhCN', '你让整个银月城都有灭顶之灾！这么做不值得！', '', 66384),
(297073, 'zhCN', '不要再有……圣光……', '', 66384),
(297062, 'zhCN', '', '保护那朵花苞！', 66384),
(297056, 'zhCN', '', '去吧，$n。我会盯着这个家伙。', 66384),
(297054, 'zhCN', '太虚弱了……无法集中精力……', '', 66384),
(297023, 'zhCN', '我父亲也是法奥的弟子，可他从没跟我提过这些事。', '', 66384),
(297022, 'zhCN', '我……这场战争结束后，我想回到这里来帮你。除了直面虚空的恐怖，这同样也是我的使命。', '', 66384),
(297020, 'zhCN', '阿拉托尔，你想成为什么样的圣骑士？成为什么样的人？', '', 66384),
(297019, 'zhCN', '生命中的点点滴滴塑造了我们，但我们可以选择如何走向未来。', '', 66384),
(297017, 'zhCN', '我和大主教没那么熟悉。我只知道他去过别的世界，离这里很远，在难以想象的岁月中不停地战斗。', '', 66384),
(297015, 'zhCN', '我真想认识一下那个时期的他。', '', 66384),
(297014, 'zhCN', '阿隆索斯和我讲过他的第一批弟子。那位传说中的乌瑟尔显然很擅长治愈。', '', 66384),
(297010, 'zhCN', '', '只要我们帮助消灭了暮光之刃，那从此以后对光木的需求，以及对永歌森林的劫掠就都会停止。', 66384),
(297005, 'zhCN', '', '我们能解决城内城外的所有威胁。如果你真想加入这场战斗，那就跟我来吧。', 66384),
(297004, 'zhCN', '区区凡人的兵器，也想阻碍萨拉塔斯的伟大荣耀？！', '', 66384),
(297003, 'zhCN', '呃啊！你的武器竟然附魔了圣光？', '', 66384),
(296969, 'zhCN', '艾林哈籁和光绽的力量都由我掌控！', '', 66384),
(296964, 'zhCN', '血如泉涌！', '', 66384),
(296963, 'zhCN', '为你的罪行流血吧！', '', 66384),
(296962, 'zhCN', '记住利爪的滋味！', '', 66384),
(296961, 'zhCN', '听听我的咆哮！', '', 66384),
(296960, 'zhCN', '你们毫无胜算！', '', 66384),
(296957, 'zhCN', '我要惩罚你们！', '', 66384),
(296955, 'zhCN', '圣光任我呼唤！', '', 66384),
(296953, 'zhCN', '圣光的怒火！', '', 66384),
(296947, 'zhCN', '', '祖尔加拉，如果你愿意，我可以助你一臂之力。$n，等你完成任务就来找我。', 66384),
(296946, 'zhCN', '给我燃烧吧！', '', 66384),
(296945, 'zhCN', '都是为了……哈籁恩达尔……', '', 66384),
(296940, 'zhCN', '我是钦选者！', '', 66384),
(296938, 'zhCN', '见证我的力量吧！', '', 66384),
(296930, 'zhCN', '摧毁阿曼尼！击溃他们！为了萨拉塔斯的荣耀，播撒混乱！', '', 66384),
(296887, 'zhCN', '你逃不过战争之神的爪心。', '', 66384),
(296886, 'zhCN', '我的愤怒终将降临。', '', 66384),
(296883, 'zhCN', '做得好，你的力量足以与我匹敌。这场梦……该醒了。', '', 66384),
(296878, 'zhCN', '', '你是说你的祖父，祖尔金？', 66384),
(296875, 'zhCN', '', '记得一些。我记得祖父的怒火让他背叛了神灵，企图窃取他们的力量，结果却断绝了我们与众神的联系！', 66384),
(296841, 'zhCN', '最后的试炼就在眼前。准备好考验你的力量，迎接我的利爪了吗？', '', 66384),
(296835, 'zhCN', '远行者终于能有个休息的好去处了。谢谢你。', '', 66384),
(296834, 'zhCN', '我们喜欢野外，只要不在据点里就行。你能去解决那些害虫吗？', '', 66384),
(296824, 'zhCN', '', '搞定了。我的伙计已经离开了。', 66384),
(296822, 'zhCN', '', '是吗？那就先宰了他！', 66384),
(296820, 'zhCN', '', '好空洞的威胁。枯木不怕什么邪枝。', 66384),
(296818, 'zhCN', '', '敢把他带回去，死亡必将降临你的部族。', 66384),
(296803, 'zhCN', '白银之手就是为了将圣光用于战斗而创立的。圣骑士的功过荣辱，不就是以此为准吗？', '', 66384),
(296802, 'zhCN', '结果大多是寻常的物品，和战争没有关系。', '', 66384),
(296801, 'zhCN', '我以为这些圣物都是神兵利器。', '', 66384),
(296800, 'zhCN', '若是能取回来……是件好事。', '', 66384),
(296799, 'zhCN', '不过……他们手中的圣物或许能为我们所用，让太阳之井的守护者们振作力量。', '', 66384),
(296792, 'zhCN', '瞧瞧是谁来了！朋友，我正好提到你呢，当然是在夸你！来，别客气！', '', 66384),
(296791, 'zhCN', '注意了，各位！我们尊敬的勇士来了，这值得庆祝一下！', '', 66384),
(296790, 'zhCN', '我们的贵宾回来了！太好了！大家一起举杯相庆吧！', '', 66384),
(296789, 'zhCN', '所以他们才能将我的教义扭曲得面目全非，使友爱和守护变成了你我眼中一目了然的邪恶。', '', 66384),
(296786, 'zhCN', '所以血色十字军才会宣称，他们是在遵从圣光的意愿。', '', 66384),
(296785, 'zhCN', '然而，圣光无法辨别爱与仇恨。', '', 66384),
(296767, 'zhCN', '真菌腐烂……必须净化……', '', 66384),
(296765, 'zhCN', '我们会重新长出来的！', '', 66384),
(296764, 'zhCN', '鲁斯苏拉要把你们这些小树枝全掰断！', '', 66384),
(296756, 'zhCN', '回忆深沟', '回忆深沟', 66384),
(296684, 'zhCN', '嗯，精美绝伦。线工装饰的触感真是绝了。', '', 66384),
(296683, 'zhCN', '我一直渴望能有再次合作的机会。来吧，我们要锻造一把配得上你的盟友的武器。', '', 66384),
(296669, 'zhCN', '现实的构造在这里陷入混沌，变幻无常。我们需要你帮忙研究这种异象的残渣。', '', 66384),
(296668, 'zhCN', '这地方还有许多有待了解的东西。做得好！', '', 66384),
(296667, 'zhCN', '', '胜利转瞬即逝，但仍是一场关键的胜利。', 66384),
(296666, 'zhCN', '', '我们已经深入敌后，出击的时候到了！', 66384),
(296665, 'zhCN', '', '影卫正利用护盾来保护他们的新式武器。趁着还没被用来对付我们，赶紧毁掉它。', 66384),
(296664, 'zhCN', '', '只要我们联起手来，谁也无法阻止我们。', 66384),
(296659, 'zhCN', '', '不惜代价，只为生存。这个世界总算有些明智的规则了。', 66384),
(296658, 'zhCN', '', '虚空对这个世界的生灵产生了奇异的影响。去接触它们，掌握它们的本能。我要弄清它们的生命之源。', 66384),
(296637, 'zhCN', '聚影领地', '聚影领地', 66384),
(296636, 'zhCN', '$n，如果你能尽力收集一些，我和阿拉托尔可以准备好熔炉。', '', 66384),
(296635, 'zhCN', '昔日战争的武器流落在地里，使耕种工作变得难上加难。', '', 66384),
(296634, 'zhCN', '我的菌盖开裂了……鲁斯苏拉要复仇……', '', 66384),
(296627, 'zhCN', '', '这份报告恐怕会让洛瑟玛……心生疑窦。在他听的时候，你最好留在我的身边。', 66384),
(296623, 'zhCN', '', '我们必须尽快赶往圣光秘殿。', 66384),
(296620, 'zhCN', '戮日圣殿', '戮日圣殿', 66384),
(296595, 'zhCN', '最受人敬仰的圣骑士不会因为战争而信仰圣光。他们是为了保护自己最珍爱的事物而奋战的。', '', 66384),
(296579, 'zhCN', '攻击性？这个副作用不值一提，换来的力量却不容置疑！', '', 66384),
(296575, 'zhCN', '我们来看看这些源自苦痛的饰品能有什么效果。', '', 66384),
(296569, 'zhCN', '这股力量有些反复无常，但值得为此冒个险！', '', 66384),
(296564, 'zhCN', '附魔还需要完善，但要想取得进步，难免需要牺牲！', '', 66384),
(296562, 'zhCN', '', '暗松部族没有固定村落——他们是祖阿曼的游牧部落。失去了龙鹰之神后，他们也失去了精神支柱。', 66384),
(296561, 'zhCN', '', '恶齿部族首当其冲失去了家园——他们处在暮光之刃攻势的最前线。', 66384),
(296556, 'zhCN', '', '所有阿曼尼战士都骁勇善战，但这些难民中许多并非训练有素的战士。', 66384),
(296554, 'zhCN', '', '我会为阿曼尼子民尽我所能。', 66384),
(296541, 'zhCN', '我们即将迎来魔法探索的新时代，$n。你做得很好。', '', 66384),
(296540, 'zhCN', '连我们的构造体也可以改进！', '', 66384),
(296538, 'zhCN', '这些魔法加持的武器能够同时攻击身体与灵魂。', '', 66384),
(296536, 'zhCN', '只要轻轻一碰，我们就能产生维修与维护城市所需的能量。', '', 66384),
(296532, 'zhCN', '做得好，$n。你证明了自己是银月城防务中不可多得的一份子。', '', 66384),
(296531, 'zhCN', '它似乎是用于容纳不稳定物质的，比如苦痛……真是个好兆头。', '', 66384),
(296530, 'zhCN', '这个水晶容器……是用极为牢固的宇宙材料制成的，真是奇妙。', '', 66384),
(296529, 'zhCN', '', '没错！应该好好歇歇了。我跟德兹科、玛鲁在这儿卖力干活……时间比我预想的要长多了。\n\n德兹科和玛鲁好像很满足当个苦力，但我可不行。我成为烈日行者可不是为了搬砖头盖房子。\n\n我是烈日行者。对安瑟的信仰和战锤才是我的武器，不是什么榔头铁锹。在这个被黑暗包围的世界里，我们没能成为应有的光明。\n\n这不是我想待的地方。', 66384),
(296525, 'zhCN', '', '有什么需要吗，$p？', 66384),
(296524, 'zhCN', '德兹科在这里教会了我很多道理。就像荒野中的每一束阳光都珍贵无比，我们做的每一件小事都很重要。\n\n况且——在安瑟的光辉照耀下，我们也没权利去判断什么工作重要，什么又不重要。\n\n和他一起在这里，我发现为需要帮助的人伸出援手，是我干过的最有意义的事情。', '', 66384),
(296509, 'zhCN', '', '快看那边！你看到了吗？', 66384),
(296507, 'zhCN', '咔嚓咔嚓！', '', 66384),
(296506, 'zhCN', '拆成零件！', '', 66384),
(296495, 'zhCN', '赞美萨拉塔斯！', '赞美萨拉塔斯！', 66384),
(296494, 'zhCN', '展现你的荣耀吧！', '展现你的荣耀吧！', 66384),
(296490, 'zhCN', '我看见了！', '我看见了！', 66384),
(296488, 'zhCN', '只需要再等一会儿……', '', 66384),
(296471, 'zhCN', '', '如果你找到祖尔加……提醒他，不管发生什么，我和他永远都是血脉至亲。', 66384),
(296469, 'zhCN', '', '我感谢你，$n。不管你是不是闯入者，在我们阿曼尼的土地上，你都将受到礼遇。', 66384),
(296436, 'zhCN', '', '洛瑟玛答应说，他的魔导师能找到办法。机会难得！', 66384),
(296434, 'zhCN', '要是能直接对付萨拉塔斯，我们要给她一顿重捶，让她窜回那把匕首里去。', '', 66384),
(296432, 'zhCN', '', '所有先锋军，快去太阳之井！快！', 66384),
(296431, 'zhCN', '不！这些沉迷虚空的家伙救不了我们。只有圣光才能阻止萨拉塔斯的邪恶。', '', 66384),
(296430, 'zhCN', '形势危急！我们愿意接受所有帮助，甚至是魔导师乌布里克。', '', 66384),
(296425, 'zhCN', '萨拉塔斯的虚影风暴与太阳之井激烈碰撞。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(296396, 'zhCN', '我依然会在噩梦中回到那个时候。即使历经风雨，我还是会梦见这里。', '', 66384),
(296391, 'zhCN', '$n，你必须找到先锋军的领袖。太阳之井就要抵挡不住萨拉塔斯的猛攻了。', '', 66384),
(296383, 'zhCN', '萨拉塔斯的攻势更猛烈了！', '', 66384),
(296379, 'zhCN', '圣光需要一面透镜，通过使用者来汇聚力量。圣光会带来必然，它会对人们的坚决做出回应。', '', 66384),
(296378, 'zhCN', '我百思不得其解。', '', 66384),
(296376, 'zhCN', '他们虽然与圣光教会理念不同，引导这股力量的能力却是相同的。', '', 66384),
(296375, 'zhCN', '艾泽拉斯有许多文明都能引导圣光，有艾露恩、格罗尔，还有安瑟。', '', 66384),
(296374, 'zhCN', '你以为我会让你一个人独享这乐子？', '', 66384),
(296372, 'zhCN', '圣光寻觅的是一条道路，它不会指明手段。', '', 66384),
(296371, 'zhCN', '他们都告诉我圣光是善良的。可血色十字军……天理难容。', '', 66384),
(296370, 'zhCN', '我简直不敢相信，圣光居然回应了他们。', '', 66384),
(296369, 'zhCN', '可不管我有多么努力……恐怕永远都无法和他们相提并论。', '', 66384),
(296368, 'zhCN', '他们都是留下了不朽丰碑的传说。他们的英雄事迹是所有圣骑士效仿的榜样。', '', 66384),
(296367, 'zhCN', '在很小的时候，我就听过这些圣骑士的故事了。', '', 66384),
(296359, 'zhCN', '', '出发吧，祖尔加拉。带着我们的祝福，去碾碎你的猎物！', 66384),
(296357, 'zhCN', '大餐做好了，但我的背还需要歇息。你知道什么药方吗？', '', 66384),
(296350, 'zhCN', '那你怪罪的不是父亲，而是圣光？', '', 66384),
(296347, 'zhCN', '那正是我学会了要去崇拜的圣光。它指引着父亲，险些要了我的命。', '', 66384),
(296346, 'zhCN', '而是在他挥剑的时候……我看到他的眼里闪耀着圣光。', '', 66384),
(296345, 'zhCN', '我闷闷不乐，不只是因为父亲伤了我。', '', 66384),
(296344, 'zhCN', '有想法就说出来吧！别让情绪闷在肚子里发酵了。', '', 66384),
(296343, 'zhCN', '你满面的愁云，都快比萨拉塔斯的虚影风暴还大了。', '', 66384),
(296322, 'zhCN', '也许，我们做的这些平凡工作，本身就是真正的魔法。', '', 66384),
(296321, 'zhCN', '就算没做什么惊天动地的大事，多亏了我们，永歌森林的魔法依旧在蓬勃发展。', '', 66384),
(296315, 'zhCN', '阿隆索斯·法奥主教有办法支援太阳之井的卫士，还有阿拉托尔。', '', 66384),
(296314, 'zhCN', '太阳之井暂时保住了，但它的守护者们一刻都不能松懈。如果他们的力量耗尽……', '', 66384),
(296307, 'zhCN', '', '被苦痛淹没吧！', 66384),
(296306, 'zhCN', '', '懊悔与忏悔！', 66384),
(296305, 'zhCN', '', '泪别……亡魂……', 66384),
(296303, 'zhCN', '', '悔恨的……波澜！', 66384),
(296302, 'zhCN', '', '哀痛的……烈风！', 66384),
(296300, 'zhCN', '', '折磨的……狂风！', 66384),
(296299, 'zhCN', '', '终于……', 66384),
(296294, 'zhCN', '', '痛苦……感受吧！', 66384),
(296292, 'zhCN', '怒火无边！', '', 66384),
(296288, 'zhCN', '毁灭！', '', 66384),
(296287, 'zhCN', '摧残！', '', 66384),
(296286, 'zhCN', '消灭他们！', '', 66384),
(296285, 'zhCN', '跟我来！', '', 66384),
(296284, 'zhCN', '都给我站好！', '', 66384),
(296283, 'zhCN', '别挡我的道！', '', 66384),
(296282, 'zhCN', '尝尝我的斧头！', '', 66384),
(296281, 'zhCN', '尝尝我的利刃！', '', 66384),
(296279, 'zhCN', '弱者必死！', '', 66384),
(296278, 'zhCN', '毫无荣耀的……渣滓……', '', 66384),
(296272, 'zhCN', '风行者！你要血债血偿！', '', 66384),
(296269, 'zhCN', '要吐了……', '', 66384),
(296268, 'zhCN', '拉奇好难受……', '', 66384),
(296267, 'zhCN', '陪我玩吧！', '', 66384),
(296266, 'zhCN', '抓住你了！', '', 66384),
(296265, 'zhCN', '糟糕。', '', 66384),
(296264, 'zhCN', '哎呀！', '', 66384),
(296262, 'zhCN', '过来！', '', 66384),
(296261, 'zhCN', '拉奇……对不起……', '', 66384),
(296255, 'zhCN', '', '黑暗缭绕！', 66384),
(296251, 'zhCN', '', '你干了什么！', 66384),
(296250, 'zhCN', '', '蠢货！', 66384),
(296249, 'zhCN', '', '刺破你的心灵！', 66384),
(296247, 'zhCN', '', '我们……辜负了……女王……', 66384),
(296242, 'zhCN', '', '我们女王的大厅不容你们玷污！', 66384),
(296241, 'zhCN', '', '你们竟敢亵渎她的圣殿？滚开！', 66384),
(296236, 'zhCN', '没有看上去得那么糟糕……糟糕的是其他地方也急需我们这些游侠……\n\n<晨行者队长叹了一口气。>\n\n不过，远行者营地依然代表着我们的精神面貌，至少应该把这里收拾整洁。', '', 66384),
(296235, 'zhCN', '等等——那股奇怪的魔法又出现了！', '', 66384),
(296234, 'zhCN', '我本以为能干点更……有英雄气概的事，你懂的吧？', '', 66384),
(296230, 'zhCN', '', '我们今天干得不错。只希望这能达到泰尔敏的期望。', 66384),
(296229, 'zhCN', '我们没办法再等你的神灵了。如果是我逼得你不得不出手，那就这样吧！', '', 66384),
(296228, 'zhCN', '就凭你们也想挑战我？哈！你们的力量连我的屏障都打不破！', '', 66384),
(296227, 'zhCN', '你们的挣扎……倒还有点意思。但为了萨拉塔斯的荣耀，你们必须死！', '', 66384),
(296226, 'zhCN', '呸！我的仆从不过是些炮灰罢了！你们想杀多少就杀多少！', '', 66384),
(296225, 'zhCN', '', '哈！逃吧，小雏鸟们！在真正的火焰之力面前落荒而逃吧！', 66384),
(296224, 'zhCN', '', '来吧，哈舒拉！让他们尝尝你内心的烈焰！', 66384),
(296223, 'zhCN', '这些被虚空冲昏了头的杂种，真是再好不过的玩物了！', '', 66384),
(296222, 'zhCN', '你好啊，小哈舒拉。你是来陪我们玩的吗？', '', 66384),
(296221, 'zhCN', '', '干得漂亮。现在，我们的利爪可以尽情撕开这些软脚虾的皮肉了。', 66384),
(296220, 'zhCN', '', '我的疾风将扫平暮光之刃。摧毁那些导管！', 66384),
(296219, 'zhCN', '你就像是个真正的阿曼尼，哈舒拉！', '', 66384),
(296218, 'zhCN', '总算肯来战斗了吗？让敌人瞧瞧你从我这儿学到的本事！', '', 66384),
(296196, 'zhCN', '喂！我知道你在想什么。\n\n对，我的脚陷进去了，我也不打算再讨论眼前的状况了。\n\n他们说，“来探险者协会吧”，还说什么“特别有趣，造福世界”。我当时就该听奶奶的话。我们陷腿家可不该让自己陷进烂泥里。\n\n营地里的小伙子们肯定要说个没完了。\n\n如果看到我这副模样也没让你回心转意，那你可得多加小心了。那里有很多陷阱，还有暮光之刃出没。看清你往哪儿踩！', '', 66384),
(296180, 'zhCN', '对于很多虚空精灵来说，比如海尔兰，这种转变并非出于自愿。那些跟随乌布里克的人被泰洛古斯裂隙中的古老遗物意外改造了。一旦踏上这条路就再无回头的可能。不过绝大多数人都欣然接受了这种改变，拥抱了虚空赐予的力量。\n\n而像我这样的人，是后来才加入乌布里克追随者行列的。在那之前，我的人生轨迹完全由他人安排。我痛恨那种生活。所以我在自己选择的道路上找到了内心的宁静，在追求虚空奥秘的过程中发现了人生的意义。我主动前往泰洛古斯，让自己获得了新生。我选择成为朗多雷。\n\n虚空代表着无限的可能性和变革的力量。它确实危险，但武器本来就应该是危险的。', '', 66384),
(296170, 'zhCN', '', '是的，叔叔，可即便那样，洛阿也没有回应我们。', 66384),
(296156, 'zhCN', '', '战场上安静下来了。想必你的战士已经收拾掉了剩余的暮光之刃。', 66384),
(296154, 'zhCN', '光木、神灵、外来者……就算把这一切都算上，这场胜利也是用阿曼尼的血海换来的。', '', 66384),
(296153, 'zhCN', '', '终于……结束了。', 66384),
(296148, 'zhCN', '凡人根本不配取我性命。能杀死我的，只有神！', '', 66384),
(296147, 'zhCN', '那得看我的刀会不会先送她去见你！', '', 66384),
(296146, 'zhCN', '', '那如果是一个同时获得四位神灵祝福的凡人呢？', 66384),
(296143, 'zhCN', '我要亲手把你们的尸体献给萨拉塔斯！', '', 66384),
(296134, 'zhCN', '', '根须已经强健多了。谢谢你出手相助。', 66384),
(296133, 'zhCN', '', '哈尔玛拉的根须照看者需要帮手。你愿意帮忙吗？', 66384),
(296128, 'zhCN', '', '抱歉，闪亮的朋友，每人限点一首！明天再来吧。', 66384),
(296120, 'zhCN', '', '撤离仍在继续。', 66384),
(296119, 'zhCN', '', '嘿，闪亮的朋友。想点首歌吗？我的歌单还有空位。', 66384),
(296110, 'zhCN', '一杯添加了太阳果的鬼花茶。\n\n回想你人生中最艰难的时刻，然后一饮而尽。', '一杯添加了太阳果的鬼花茶。\n\n回想你人生中最艰难的时刻，然后一饮而尽。', 66384),
(296107, 'zhCN', '', '很好，我们这就去拆了莫尔杜恩的虚空屏障。', 66384),
(296106, 'zhCN', '感谢你为我做的一切，$n。明天我们在啸影山脊再见。', '', 66384),
(296104, 'zhCN', '<阿斯崔和赛多娜陷入了温馨的回忆，聊着那个她们都深深爱过的人。>', '', 66384),
(296103, 'zhCN', '这次谈话比我预想的顺利太多了。', '', 66384),
(296099, 'zhCN', '', '我已经恳求过洛阿神灵，请他们摧毁莫尔杜恩的虚空屏障。\n\n要是没有洛阿神灵，我们走不到这一步。\n\n但这场对抗莫尔杜恩的决战，必须由我们亲自动手。\n\n屏障即将瓦解。届时，战斗就将打响。\n\n你准备好了吗，哈舒拉？', 66384),
(296097, 'zhCN', '', '阿斯崔和赛多娜继续着他们的交谈，沉浸在共同的遐思中。', 66384),
(296096, 'zhCN', '哈哈，在泰洛古斯那个地方，这种茶叶简直是珍稀至极。', '', 66384),
(296095, 'zhCN', '', '他当年也是用花草茶把你叫醒的吗？', 66384),
(296094, 'zhCN', '', '不急的。阿斯崔，请留下来吧。如果你不介意的话，我想和你一起慢慢品味这茶的香气。', 66384),
(296093, 'zhCN', '我们先让你安静读完海尔兰的信吧，赛多娜。', '', 66384),
(296092, 'zhCN', '', '赛多娜和阿斯崔都笑了起来。', 66384),
(296091, 'zhCN', '太阳果让茶味柔和了许多。好主意，赛多娜。看来我们的品味相当一致。', '', 66384),
(296089, 'zhCN', '混乱的容身之地就在斗坑里。感谢你让它平静了下来。', '', 66384),
(296087, 'zhCN', '', '莫尔杜恩以为躲在屏障后面就能高枕无忧了？他想得美。', 66384),
(296086, 'zhCN', '斗坑吸引了很多威胁，别让它们蔓延出来。', '', 66384),
(296083, 'zhCN', '', '确实不错，口感很醇厚。这让我想起了以前的日子。', 66384),
(296081, 'zhCN', '', '他当时也是这么说的。我试着接受现实，可就是放不下。', 66384),
(296079, 'zhCN', '尝尝这茶吧，会让你舒服些。$n，你也想试试吗？毕竟是你亲手泡的。', '', 66384),
(296074, 'zhCN', '圣光同样索取着沉重的代价——那种死板的秩序让人窒息，束缚得人喘不过气。我们再也回不去了。', '', 66384),
(296072, 'zhCN', '', '虚空的诱惑力量，用痛苦换取强大。管它什么代价呢，对吧？太阳之井——重新焕发生机，我们对法力的依赖——也被治愈了。我们的同胞拼死拼活争取来的，难道还不够吗？', 66384),
(296071, 'zhCN', '还记得在虚影风暴中，这茶水会映照出我们负面情绪的影子。但它确实能带来些帮助。', '', 66384),
(296068, 'zhCN', '', '闻起来像苦药，也许加点永歌的柑橘能中和一下苦味。', 66384),
(296063, 'zhCN', '$G他:她;也带来了海尔兰的遗物。你应该还有不少茶叶吧，$n？', '', 66384),
(296058, 'zhCN', '', '你们当时都在风暴里？请进来吧。', 66384),
(296057, 'zhCN', '赛多娜，这位是$n。你介意$G他:她;一起来吗？', '', 66384),
(296038, 'zhCN', '有什么需要吗？\n\n我正忙着照看男爵的陆行鸟。', '', 66384),
(296035, 'zhCN', '这事跟我没关系。\n\n我不知道他们以为我干了什么，反正不是我干的。\n\n我敢肯定。这帮先锋军把我围得水泄不通，好像从来没见过术士似的。\n\n我也不清楚是因为我是亡灵，还是因为我穿得一身紫，或者是因为我召唤了虚空行者。', '', 66384),
(296034, 'zhCN', '这些圣骑士归我管，我觉得哪里需要他们就派到哪里去。\n\n既然银月城的头头们不愿意清理这些邪恶势力，那就由我们来代劳。', '', 66384),
(296033, 'zhCN', '这城里到处都有间谍。虚空最喜欢见缝插针，装成熟人的样子混进来。\n\n我绝不会让我的城市被内奸搞垮。', '', 66384),
(296032, 'zhCN', '也许营地里有人能够照顾它们……哇！这是什么？', '', 66384),
(296021, 'zhCN', '虽然危险……但直面危险，正是远行者的信条！', '', 66384),
(296020, 'zhCN', '那个装置可以测试生物的潜在腐蚀程度。我们分头行动效率会更高。', '', 66384),
(296001, 'zhCN', '你在海尔兰的遗物中找到的那封信，是写给赛多娜·暮塔的。她曾是海尔兰的妻子。几年前，海尔兰成为朗多雷后，他们便分开了。\n\n信中提到了“背叛”之类的字眼。即便无法相守，海尔兰心中依然爱着她。\n\n<阿斯崔望向赛多娜，难掩心中的苦涩。>\n\n被逐出银月城，让我们许多人的生活都变得举步维艰。家产和传家宝被尽数没收——家庭也因此支离破碎。\n\n但这是他们的选择，并非我们所愿。', '', 66384),
(295994, 'zhCN', '好漂亮的一朵花。土壤肯定非常健康，这都是多亏了我们。', '', 66384),
(295975, 'zhCN', '', '圣光在上，我……我很抱歉，阿斯崔。要不要进来坐坐？我们可以好好谈谈。', 66384),
(295971, 'zhCN', '我们被派往虚影风暴。那次任务是——算了，已经不重要了。他为保护他的人民献出了生命。', '', 66384),
(295969, 'zhCN', '海尔兰已经死了，赛多娜。', '', 66384),
(295968, 'zhCN', '', '山猫吃饱了，长老也满心欢喜。做得好，朋友。', 66384),
(295964, 'zhCN', '', '害虫正在大巢穴里肆虐。如果解决掉它们，长老或许就会高看我们一眼。带上一头恐惧山猫吧——它们一直都很贪吃。', 66384),
(295963, 'zhCN', '我们必须结束无谓的争斗。', '', 66384),
(295962, 'zhCN', '', '太好了，用它们做的和解大餐一定无与伦比。谢谢！', 66384),
(295961, 'zhCN', '', '我需要材料来烹制一道和解大餐，让芦塔尼和真菌人和平共处。帮我收集它们吧。', 66384),
(295960, 'zhCN', '没错，这座城像火药桶一样一点就着。', '', 66384),
(295959, 'zhCN', '', '怎么，来同情我的吗？他是不是也抛弃了你？', 66384),
(295957, 'zhCN', '我来这里只是为了送信。但或许……或许有些话是时候说出来了。\n\n$n，如果你觉得不自在想离开，我完全理解。这可能会涉及一些私人恩怨。无论如何我都能处理，我保证。', '', 66384),
(295956, 'zhCN', '他们的狂热令人钦佩。我一定不会辜负他们的牺牲。', '', 66384),
(295955, 'zhCN', '魔导师乌布里克的目光从阿斯崔转向你。', '', 66384),
(295951, 'zhCN', '我在银月城也经历过不少唇枪舌战。但我始终认为与我们的辛多雷同胞保持礼节更为明智。\n\n可惜阿斯崔并不这么想。让阿斯崔独自前往银月城，我实在放心不下。', '', 66384),
(295949, 'zhCN', '太好了！我们一举削弱了吞噬军团，还巩固了我们的防御。', '', 66384),
(295947, 'zhCN', '我早就料到，这些顽强的家伙会奉上一场精彩的狩猎。', '', 66384),
(295946, 'zhCN', '他们可悲的存在化作了我们守护城市的力量。有几分诗意在，对吧？', '', 66384),
(295945, 'zhCN', '你结束了他们的苦难，还补充了我们的力量。很高效！', '', 66384),
(295944, 'zhCN', '沧海一粟，浮光掠影。也许这样就够了……', '', 66384),
(295943, 'zhCN', '多么强大的能量！要是能让我控制一点点……', '', 66384),
(295942, 'zhCN', '真是收获满满。做得好。', '', 66384),
(295941, 'zhCN', '很可惜，但这是必要的。他们的牺牲将被铭记。', '', 66384),
(295939, 'zhCN', '元素？奥术？只要能有苦痛，我就不纠结了。', '', 66384),
(295938, 'zhCN', '看他们生气的样子！真有趣。', '', 66384),
(295937, 'zhCN', '刺客遇刺……多么令人愉快的稀景。', '', 66384),
(295936, 'zhCN', '纯粹的力量……也许朗多雷真的有些道理。', '', 66384),
(295935, 'zhCN', '金属不是魔法的对手。', '', 66384),
(295934, 'zhCN', '火焰越是明亮，烧起来就越是漂亮。', '', 66384),
(295933, 'zhCN', '暮光之刃侍奉着萨拉塔斯，但就连走狗也有力量。我们要夺走他们的力量。', '', 66384),
(295932, 'zhCN', '这些棘语者偏离了道路。收集他们的力量，用于我们的事业。', '', 66384),
(295931, 'zhCN', '失心者……多么贴切的名字。他们漫无目的地活了很久。去利用它们的韧性。', '', 66384),
(295930, 'zhCN', '这个死亡骑士已经没用了。我们要征用他们的苦难。', '', 66384),
(295929, 'zhCN', '这个吞噬军团的成员必须被干净利落地处决。', '', 66384),
(295928, 'zhCN', '多曼纳尔是萨拉塔斯的精锐力量，自然是个迷人的目标……', '', 66384),
(295927, 'zhCN', '啊，圣光，我极为珍视的力量。我们要从迷途之人手中将它夺回来。', '', 66384),
(295926, 'zhCN', '芦塔尼被注入了这个世界的力量。是时候培养这股力量了。', '', 66384),
(295925, 'zhCN', '就算是远行者，也无法完全避免腐化与背叛。', '', 66384),
(295924, 'zhCN', '我不会对巨魔的力量疏忽大意。我们要利用它。', '', 66384),
(295923, 'zhCN', '这个生物可能有些……喜怒无常。', '', 66384),
(295922, 'zhCN', '卡雷什造就了宇宙中最致命的掠食者。这就是其中之一。', '', 66384),
(295921, 'zhCN', '我很钦佩这些堕入虚空的同胞。他们的顽强该为我们所用。', '', 66384),
(295920, 'zhCN', '这家伙个子虽小，力量却很庞大。不要轻敌。', '', 66384),
(295919, 'zhCN', '这家伙的火光很明亮。让它的火焰熄灭吧。', '', 66384),
(295913, 'zhCN', '嗯哈哈哈哈哈……', '', 66384),
(295907, 'zhCN', '没错。在银月城要看好阿斯崔，别让阿斯崔惹是生非。为了阿斯崔好，也为了我好。罗曼斯已经够让我头疼的了。', '', 66384),
(295905, 'zhCN', '我不会逗留太久。反正那里也不欢迎我。', '', 66384),
(295902, 'zhCN', '裂隙已经封印。胧影堡垒再也威胁不到银月城了。', '', 66384),
(295897, 'zhCN', '黑暗部落和洛萨之子一样，深陷在第二次战争中无法自拔。', '', 66384),
(295896, 'zhCN', '', '多么奇特又可爱的花！浮龙肯定非常感谢你的帮助。', 66384),
(295895, 'zhCN', '', '浮龙的数量够了！你可以回来了！', 66384),
(295893, 'zhCN', '若不是我们同心协力，那绝无可能成功。我们回啸影山脊吧。', '', 66384),
(295892, 'zhCN', '', '你给我们带什么来了，小家伙？', 66384),
(295891, 'zhCN', '', '这是什么？我从没见过长相这么奇特的浮龙！', 66384),
(295879, 'zhCN', '', '我会在这里监控它们的进食模式。去帮助那些浮龙吧！', 66384),
(295857, 'zhCN', '一群……肮脏的……畜生……！', '', 66384),
(295854, 'zhCN', '如果你能打开接近萨拉塔斯的通路……先锋军就会离开。而你们能获得的力量就更不用说了。', '', 66384),
(295843, 'zhCN', '银月城的命运就掌握在我们手中。齐心协力！', '', 66384),
(295842, 'zhCN', '我能在城里庇护你们，可先锋军不会让你们靠近太阳之井。拿出成果就能改变情况。', '', 66384),
(295841, 'zhCN', '成果？我没有工具也没有援助，还被双方的狂热信徒追杀……', '', 66384),
(295804, 'zhCN', '我不是战士或领袖，那些都是过去的事了。\n\n但我仍有双手，仍有时间，在族人之中也还有着一席之地。和平期间的一顿大餐，能与战争中的兵刃起到同样的作用。\n\n所以我会采集食材，烹饪美食，不遗余力。这样就够了。', '', 66384),
(295803, 'zhCN', '哈尔玛拉的建立不是出自友谊，而是因为必要。\n\n哈籁尼尔、芦塔尼、真菌人……他们并不在意彼此。但无休无止的血光之灾没有任何意义，只会让这片土地生灵涂炭。\n\n于是我们建立了这个脆弱的地方，让和平能有维系的机会。', '', 66384),
(295794, 'zhCN', '火是准备好了，可我的背不行了。如果你愿意帮忙，我会感激不尽。', '', 66384),
(295761, 'zhCN', '我就想近距离观察一下虚影风暴——\n\n听我说。咱们没工夫在这里争论他们信不信任我的方法。你感受不到吗？虚影风暴不仅没有减弱——反而在增强。\n\n太阳之井撑不了多久了。我得想办法进入虚影风暴，但首先得在那帮狂热分子杀掉我之前把刚才收集的数据分析完。\n\n你能帮我劝劝他们吗？', '', 66384),
(295757, 'zhCN', '', '我们不会被你“提议”的帮助所打动，虚空精灵。', 66384),
(295755, 'zhCN', '见机行事，勇士。乌布里克和先锋军都是必不可少的。', '', 66384),
(295741, 'zhCN', '我们救了我们的队长……让她免于脚踝扭伤之苦。我们保卫了远行者营地……清除了那里的灰尘和捡破烂的。\n\n所以……我想我总算证明自己是个真正的远行者了，对吧？', '', 66384),
(295738, 'zhCN', '阿斯特雷，瓦尔萨琳——你们去帮助这里的其他游侠。', '', 66384),
(295718, 'zhCN', '我从一开始就没戏了。她怎么可能抛下扎卡希这样英武的斗士，来选择我这样的人呢？\n\n<卡格拉低头看着自己的脚。>\n\n我还是不去参加庆典了。不过……谢谢你帮了我。', '', 66384),
(295717, 'zhCN', '我不知道娜玛姬怎么会选了我！但我太高兴了！她明明有更好的选择。\n\n<扎卡希努力想要平静下来。>\n\n好！既然给了我机会，那我一定要牢牢把握！\n\n祝我好运吧！', '', 66384),
(295715, 'zhCN', '我已经尽力了。娜玛姬很聪明，卡格拉也很聪明，他们一定有很多共同话题。\n\n她做出了正确的选择。\n\n我应该去邀请其他人吗？我到底还要不要参加庆典？\n\n我也许还是专心训练吧。', '', 66384),
(295714, 'zhCN', '行，那就算在你头上。', '', 66384),
(295713, 'zhCN', '现在正需要大胆行动。放了他，全部责任都由我来承担。', '', 66384),
(295712, 'zhCN', '喜欢做出“大胆”的举动。你是这么说的吧，大法师？', '', 66384),
(295711, 'zhCN', '可是乌布里克……', '', 66384),
(295709, 'zhCN', '你没时间囚禁他，没理由处决他。', '', 66384),
(295708, 'zhCN', '娜玛姬选了我？没选扎卡希？他们俩看上去一直那么亲密……\n\n我一直梦想着这一天，但我从没想过它真的会实现！\n\n这是真的吗？不会是死后的幻觉吧？\n\n<卡格拉开始急促地喘气。>\n\n我现在该怎么办？我该说点什么？\n\n我是该夸她的獠牙呢？还是该给她一个拥抱？\n\n救命啊！', '', 66384),
(295706, 'zhCN', '他们效忠于我。虽然深受猜忌和骚扰，乌布里克和他的朗多雷一次次证明了他们对联盟的忠诚。', '', 66384),
(295705, 'zhCN', '不。这个……精灵……他效忠的对象不言自明。', '', 66384),
(295704, 'zhCN', '高阶指挥官，如果可以，还请你放了魔导师乌布里克。', '', 66384),
(295701, 'zhCN', '我调查虚空是为了帮助你们！', '', 66384),
(295696, 'zhCN', '是这样吗？\n\n要是我们再不主动出击，肯定会败给虚空。\n\n算了，伊利丹说过：“有时候所谓的命运，也可以自己掌握。”', '', 66384),
(295695, 'zhCN', '我赞成洛瑟玛的想法，但这事在政治上确实很麻烦。\n\n魔导师乌布里克不是银月城的人。他和那些朗多雷都是被流放的，所以洛瑟玛管不着他们。\n\n就算乌布里克真是银月城的人，他也是个魔导师，得听大法师罗曼斯的。显而易见的是，罗曼斯把乌布里克利用虚空魔法的行径当成了对他个人的背叛。', '', 66384),
(295694, 'zhCN', '那个多曼纳尔肯定是偷走了海尔兰的法术焦镜。不知怎的，那东西竟能帮助窥探银月城。\n\n我们必须立刻行动。', '', 66384),
(295673, 'zhCN', '圣光先锋军抓到魔导师乌布里克想要靠近太阳之井。我赶紧出面阻止，不然他们当场就把他给解决了。\n\n我和洛萨克森都清楚某些魔法的腐蚀性有多可怕。不过看起来，我们从过去的经历中学到的东西完全不一样。', '', 66384),
(295669, 'zhCN', '', '那就比比看，看到底是谁的战意更加昂扬，精灵！', 66384),
(295666, 'zhCN', '', '这口气，真是个地道的阿曼尼。不过……要说我没有同感，那就是在撒谎了。', 66384),
(295664, 'zhCN', '', '神灵赐予了我力量。但真正点燃我内心的，永远是战斗的激情！', 66384),
(295653, 'zhCN', '谢谢……你……', '', 66384),
(295648, 'zhCN', '你不能就这样倒下。', '', 66384),
(295625, 'zhCN', '萨拉塔斯饶恕……我的失败。', '', 66384),
(295622, 'zhCN', '虚空的大军浩浩荡荡，变化万千。你们无力抵挡即将降临的命运！', '', 66384),
(295593, 'zhCN', '蘑菇助你茁壮成长！', '', 66384),
(295592, 'zhCN', '', '我们赶紧回家去吧！', 66384),
(295591, 'zhCN', '', '哈籁尼尔永不言败！', 66384),
(295590, 'zhCN', '……看样子我们的口号还需要练练。', '', 66384),
(295586, 'zhCN', '……很诱人。\n\n太诱人了。\n\n我怀疑虚空手下建议的方法能不能信，但我们得做点什么。\n\n太阳之井现在还撑得住，但绝对不能保持平衡。要是再不改变什么，虚影风暴很快就会突破我们的防线。\n\n我们必须反击。', '', 66384),
(295585, 'zhCN', '伙计们！我们该喊什么口号？', '', 66384),
(295584, 'zhCN', '在这件事上，我不认可洛瑟玛的权威。这个虚空精灵是流亡者，天生就对太阳之井和我们的部队构成威胁。\n\n乌布里克不是银月城公民，在对抗虚空的战争中，我们也不用听摄政王的。\n\n他可以建议，但不能命令。', '', 66384),
(295583, 'zhCN', '再说你是被太阳之井召唤来的，乌布里克没有。这说明他要么被污染得太厉害，要么根本不配得到这种荣誉。', '', 66384),
(295582, 'zhCN', '我们不让魔导师乌布里克这样强大的虚空精灵靠近太阳之井是有道理的。几年前奥蕾莉亚·风行者靠近太阳之井的时候，光是她在那就影响了魔法。\n\n虽然她体内有个黑暗纳鲁，但我不敢让这么沉迷虚空的家伙靠近太阳之井。', '', 66384),
(295571, 'zhCN', '', '我们的占卜师也在研究这个问题。他们还没找到解决办法，但这个被虚空污染的精灵也没有。\n\n维迪卡尔派不上用场，因为这里有压制魔法。传送和飞行魔法都突破不了这场风暴。\n\n不过我们总会找到进去的办法。我们必须相信能找到一条路。', 66384),
(295568, 'zhCN', '', '这点我不怀疑。但问题是，我们能信任他给的路吗？还是他只是为了自己？\n\n我们得主动出击，但这正是虚空感染世界的手段。它们在你最绝望的时候帮你一把，然后把你的一切都夺走。\n\n安苏雷克女王、艾萨拉女王、节点之王萨哈达尔……这些人都是在最绝望的时候接受了虚空的帮助。\n\n我们得比他们聪明。', 66384),
(295564, 'zhCN', '', '为了银月城，我们的军团已经冒了够大的风险了。\n\n洛瑟玛小瞧了现在的局势。我们来这不是为了救一座城——而是为了救整个艾泽拉斯。', 66384),
(295556, 'zhCN', '', '圣光先锋军知道怎么对付虚空。那些力量很危险，会传染，像癌症一样蔓延吞噬。\n\n这就是它们的套路。先装成朋友或者给你好处，等你反应过来，又一个世界就被吃掉了。', 66384),
(295534, 'zhCN', '我会盯紧他们的一举一动。', '', 66384),
(295533, 'zhCN', '没错！敲吧，使劲敲响你们的战鼓！好多送些巨魔过来送死！', '', 66384),
(295532, 'zhCN', '杀了我的传送法师也没用！我们依然会踏平你们这座破烂的沼泽之城！', '', 66384),
(295530, 'zhCN', '它很有用，只是需要经历一番抗争。试试看——你会明白的。', '', 66384),
(295529, 'zhCN', '洛瑟玛被急昏头了。没错，我们得救银月城和太阳之井。但要借助虚空的力量……\n\n不行，乌布里克不光在用虚空魔法，还在用我们最大叛徒改良的技术。\n\n光靠圣光或奥术魔法找进入虚影风暴的办法确实更难，但比乌布里克的计划靠谱多了。', '', 66384),
(295527, 'zhCN', '我明白你们凡人就是通过分享这些私密之事来建立深厚的羁绊。谢谢你愿意满足我的好奇心。', '', 66384),
(295526, 'zhCN', '洛瑟玛可能觉得他在这有话语权，但乌布里克是魔导师，得听我的判决。\n\n更重要的是——他和他那伙人早就因为染指虚空魔法而被流放了。虚空魔法可不只是禁忌那么简单，它从本质上就是邪恶的。', '', 66384),
(295525, 'zhCN', '趁着利刃冷却的时候休息一下吧。来，和我说说你的事。', '', 66384),
(295523, 'zhCN', '能与你共处更久，真是令人愉悦。', '', 66384),
(295522, 'zhCN', '洛瑟玛派你来的？\n\n乌布里克以前是我的……同事，在他投靠虚空之前。他一向很冲动。\n\n他可能觉得这叫“勇敢”，但他对魔法的态度完全不把我们设立的安全界限当回事。\n\n现在他彻底越界了。', '', 66384),
(295512, 'zhCN', '', '那就这么定了！', 66384),
(295511, 'zhCN', '', '是卡格拉？还是扎卡希？\n\n卡格拉送了我一条漂亮的蛇颈龙牙项链。他虽然不是战士，但脑子很灵光。他人也很好聊，总能逗我笑。\n\n扎卡希送了我这个可爱的羽毛头饰，真是个惊喜。他很强壮，是个了不起的战士。知道他也有温柔的一面，让我更欣赏他的内心了。\n\n你觉得我该选谁？', 66384),
(295509, 'zhCN', '别开玩笑了，所有凡人都有后悔之事。我能从空气中尝到它的味道。\n\n你夺走过许多生命，不是吗？在那些逝去的生命中，必然有些会让你后悔吧。', '', 66384),
(295503, 'zhCN', '多么有趣的选择啊。\n\n说到我？我们虚空生物并非不懂得恐惧。面对更强大的力量时，我们也会感到畏惧。我害怕萨拉塔斯。\n\n我也畏惧你。\n\n<殆希莫斯咧嘴露出大大的笑容。>\n\n多说些，我太想知道了。那么说说后悔吧？你有什么后悔的事？', '', 66384),
(295487, 'zhCN', '真有趣。对我而言，我享受各种味道：心碎、嫉妒、恐惧……\n\n<殆希莫斯轻哼着舔了舔嘴唇。>\n\n不过我也很想尝尝你说的这些物质的“食物”。\n\n接下来呢？我想象不出你们凡人还会聊些什么琐碎话题。不如这样——\n\n说说你害怕什么？', '', 66384),
(295478, 'zhCN', '你们凡人的生命如此有趣，如此复杂。你们内心世界所孕育的强烈情感，令人垂涎。\n\n我多么渴望能更深入地了解你们。\n\n让我们聊聊天吧。说说你的故事。\n\n你最喜欢吃什么？', '', 66384),
(295462, 'zhCN', '', '说真的，我觉得那个说奥蕾莉亚的心脏是个黑暗纳鲁的流言，其实能解释很多事情。', 66384),
(295453, 'zhCN', '伙计们！搭把手！', '', 66384),
(295452, 'zhCN', '这里有踪迹。有什么东西还没走远，我们追！', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(295451, 'zhCN', '', '那里！我们找到绍麦尔了！', 66384),
(295449, 'zhCN', '等等……我感应到了……银月城。快看！就在脚下！', '', 66384),
(295448, 'zhCN', '这一定是某个多曼纳尔所为。海尔兰虽然伤到了它，但它一定也从他身上夺走了某些东西。', '', 66384),
(295447, 'zhCN', '走这边！', '', 66384),
(295446, 'zhCN', '这些裂隙……就像伤口，而且给我一种莫名的熟悉感。', '', 66384),
(295445, 'zhCN', '', '不管那是什么，就在这个方向。', 66384),
(295444, 'zhCN', '几十年前，在抵抗精灵和部落的战斗中，我们损失惨重——可那时候我们部族还很兴旺。\n\n现在，我们人丁稀少。太少了。我真怕再这么损失下去，阿曼尼和其他森林巨魔部族就都要绝迹了。\n\n我向埃基尔松祈祷，愿那一天永不降临。', '', 66384),
(295442, 'zhCN', '', '你们两个该不会以为我们会让你们单独行动吧？', 66384),
(295427, 'zhCN', '请协助我调配草药和灵魂颜料，好让我们为逝者踏上庄严谷的征程做足准备。', '', 66384),
(295425, 'zhCN', '', '我发誓，要是我去找纳洛拉克的时候你敢乱来，我就亲手拧下你的脑袋。', 66384),
(295424, 'zhCN', '', '你需要什么吗？', 66384),
(295421, 'zhCN', '', '死了这么多人……祖尔加，你都做了些什么？', 66384),
(295420, 'zhCN', '今天战士们阵亡的鲜血，必将汇成滔天巨浪，将那些入侵者从我们的土地上彻底冲走！', '', 66384),
(295415, 'zhCN', '', '村子最近经历了不少风波。但愿这场庆典能改善大家的情绪！\n\n自我出生以来，我们就没举办过洛阿庆典了。长老们告诉过我们大概会是什么样，但我还是有点紧张！', 66384),
(295407, 'zhCN', '如果晨行者队长真的被什么事耽搁了，那我们必须去救她。', '', 66384),
(295405, 'zhCN', '是啊！当时有股奇怪的魔法，然后……等等，晨行者队长是不是出什么事了？', '', 66384),
(295404, 'zhCN', '', '大惊小怪的！就是扭了下脚。这地方也太久没人打理，都荒了。', 66384),
(295403, 'zhCN', '队长！你……没事吧？', '', 66384),
(295402, 'zhCN', '', '画作会对每个人讲述不同的故事。', 66384),
(295401, 'zhCN', '我希望卡格拉没有看上她，否则我肯定毫无胜算。他可是村里最聪明的！', '', 66384),
(295378, 'zhCN', '你在仪式完成之前不能离开哈尔玛拉。', '你在仪式完成之前不能离开哈尔玛拉。', 66384),
(295377, 'zhCN', '我一直在等父亲亲口告诉她这件事。但是……现在看来只能由我来开这个口了。', '', 66384),
(295376, 'zhCN', '', '勇士！奥蕾莉亚刚刚抵达，就立即出发寻找我们那些失踪的军官了。', 66384),
(295361, 'zhCN', '感谢你所做的一切，$n。为了先锋军，为了银月城……还有为了我。', '', 66384),
(295360, 'zhCN', '谢谢你！我们这就重新集结，准备下一轮进攻。', '', 66384),
(295359, 'zhCN', '要不是你，我们早就没命了！', '', 66384),
(295358, 'zhCN', '圣光会庇护我们，但我们必须抓紧时间！', '', 66384),
(295357, 'zhCN', '尽快治疗伤员，在集结点重整！$n，掩护他们！', '', 66384),
(295356, 'zhCN', '扎卡希是年轻战士里的佼佼者。要是他对娜玛姬有意思，我的计划肯定成不了事！', '', 66384),
(295355, 'zhCN', '如果要说我从这里学到了什么，那就是吞噬军团最擅长利用和摧毁我们的信念。', '', 66384),
(295354, 'zhCN', '这些可怜人都是从各自队伍中走散的。我们必须待在一起行动。', '', 66384),
(295353, 'zhCN', '愿圣光护佑逝者，庇护生者。让我们齐心协力，将这股邪恶逐出我们的世界。', '', 66384),
(295351, 'zhCN', '我们必须冲出去，帮助仍在战场上奋勇抵抗的同伴。', '', 66384),
(295349, 'zhCN', '啊，$n。你来了。太好了。我正需要你的帮助。', '', 66384),
(295348, 'zhCN', '', '什么，世界末日的战争？\n\n要是他们一开始就说清楚，而不是像强盗一样直接抢，我早就把所有东西都给他们了。\n\n一车货我们出得起。不过希望他们记住这是在谁的地盘上。', 66384),
(295344, 'zhCN', '我现在明白圣光为何召唤你来参加这场战斗了。你是我们所有对抗虚空之人的榜样。', '', 66384),
(295338, 'zhCN', '自从来到这儿，那些虚空大炮就把我们死死地压在壕沟里。现在也该轮到他们尝尝厉害了。想不想试试？', '', 66384),
(295336, 'zhCN', '', '你！我听说过你的事。你就是那个勇士对吧！\n\n他们说你是来帮忙对付虚空的。\n\n可这些士兵跟我说需要我的货物去支援太阳之井，然后就要把我整车东西都搬走。既不请求，也不道谢，更别说给钱了。\n\n我又不认识他们！我怎么知道这不是联盟找借口抢我们东西？', 66384),
(295335, 'zhCN', '你说得对，乌布里克。解救你的同胞，确实为我们的进攻打开了突破口。', '', 66384),
(295324, 'zhCN', '把用虚空的都放了。他们可以在城里走动，但我们不能放这些渣滓接近太阳之井。', '', 66384),
(295323, 'zhCN', '我又不是密教徒，我是个术士。', '', 66384),
(295318, 'zhCN', '', '你们要走了魔导师、骑士、武器，现在还来抢食物？', 66384),
(295315, 'zhCN', '这是为了太阳之井。光靠魔法点心可活不下去。', '', 66384),
(295308, 'zhCN', '', '我们都以圣光作为指引，但我都认不出你那冰冷迂腐的信仰了。', 66384),
(295307, 'zhCN', '', '我们给你留下了些许兵力来抵挡虚影风暴。圣光保佑，这应该足够了。', 66384),
(295306, 'zhCN', '', '你再三要求我们找到接近萨拉塔斯的办法后立即离开。我们这就出发。', 66384),
(295304, 'zhCN', '我的士兵习惯了和圣光角力，他们也该学学其他战斗方式的窍门。', '', 66384),
(295303, 'zhCN', '做得好，$n！你的力量和信念都是先锋军效仿的榜样。', '', 66384),
(295286, 'zhCN', '我派女伯爵莉亚德琳向先锋军的指挥官传信，请他们立刻部署，和平地离开这座城。', '', 66384),
(295251, 'zhCN', '', '我好像听到北面传来的巨魔的叫喊声。这很反常。', 66384),
(295238, 'zhCN', '', '泰尔敏！我们正在找队长——哇，那是几只熊宝宝吗？', 66384),
(295237, 'zhCN', '战士们，给我上！', '', 66384),
(295230, 'zhCN', '这是你解救幼崽的谢礼……就像故事里说的一样！', '', 66384),
(295229, 'zhCN', '闯入者，想拿走光木，就从我的尸体上踏过去。光木打造的武器是——', '', 66384),
(295228, 'zhCN', '这股能量太过汹涌。我和乌布里克不一样——我快撑不住了。', '', 66384),
(295225, 'zhCN', '使用伪装，找到货物。', '', 66384),
(295218, 'zhCN', '血精灵脚下那片地，是他们从我们这儿偷走的！\n\n你们根本搞不懂。那片林地按理说是我们的。我们需要它！', '', 66384),
(295208, 'zhCN', '别理他的哭喊。看到刀刃现在如何自主汲取力量了吗？还有更多事要做，$n。到啃噬之境与我会合。', '', 66384),
(295207, 'zhCN', '哦，沃腾希翁，你怨恨的滋味正如我所期待的那般甘美。', '', 66384),
(295206, 'zhCN', '找到新玩具了，殆希莫斯？你一如既往地喜欢玩弄猎物呢。', '找到新玩具了，殆希莫斯？你一如既往地喜欢玩弄猎物呢。', 66384),
(295204, 'zhCN', '幸会，助祭。', '', 66384),
(295202, 'zhCN', '$c，你还磨蹭什么？来看看这些怪物到底会不会流血！', '', 66384),
(295189, 'zhCN', '真是美味啊。', '', 66384),
(295188, 'zhCN', '哦，我太过微不足道，不配与我们的旧领主们一起被毁灭，就像你一样。', '', 66384),
(295186, 'zhCN', '殆希莫斯？你还活着？我以为萨拉塔斯已经将你与其他领主一同吞噬了。', '殆希莫斯？你还活着？我以为萨拉塔斯已经将你与其他领主一同吞噬了。', 66384),
(295185, 'zhCN', '不要误会，$n。诺克希恩对萨拉塔斯毫无忠诚，只有嫉妒和贪婪。', '', 66384),
(295184, 'zhCN', '叛徒？诺克希恩，我们什么时候开始在意忠诚这种东西了？', '', 66384),
(295182, 'zhCN', '殆希莫斯！叛徒！', '殆希莫斯！叛徒！', 66384),
(295181, 'zhCN', '殆希莫斯耸了耸肩。', '', 66384),
(295172, 'zhCN', '哈！那得看你能提供给我们什么有价值的东西了。', '', 66384),
(295171, 'zhCN', '你的盟友很有意思，殆希莫斯。或许我们可以达成某种协议。', '你的盟友很有意思，殆希莫斯。或许我们可以达成某种协议。', 66384),
(295079, 'zhCN', '心火燃起，烈焰冲天！哈哈哈哈哈！', '', 66384),
(295078, 'zhCN', '直面你的火焰！直面你的火焰！如果不敢正视自己的火焰，心中便徒有火种！', '', 66384),
(295077, 'zhCN', '嗯……看样子你吃了还没死。那……应该就算能吃吧！', '', 66384),
(295076, 'zhCN', '始祖龟给我们送来了些食物接济难民。能麻烦你看看……这些东西能不能吃吗？', '', 66384),
(295069, 'zhCN', '赞美库尔吉。你带回来的这些药草，能为我们照料的伤员减轻不少痛苦。', '', 66384),
(295068, 'zhCN', '很多人还没从暮光之刃的袭击中恢复过来。帮我们去库尔吉神殿附近采些草药来制药吧。', '', 66384),
(295067, 'zhCN', '火之子民心满意足！烈焰之母面露微笑！今天真是鱼获丰收的一天！', '', 66384),
(295066, 'zhCN', '火之子民想吃新鲜的食物！去游！去潜！去捕猎！给我们找来足够多的鱼当做盛宴！', '', 66384),
(295061, 'zhCN', '', '暮光之刃那帮家伙藏在代言人的安息处。让他们见识见识哈舒拉是怎么保卫祖阿曼的！', 66384),
(295060, 'zhCN', '', '你把他们都解决了，$n。多亏了你，我们土地上的暮光走狗又少了一批。', 66384),
(295059, 'zhCN', '', '你帮我们找回了传家宝和遗物。哈舒拉，我们恶齿部族和我们的先祖都感谢你。', 66384),
(295058, 'zhCN', '有些事情需要我们去拨乱反正。', '', 66384),
(295057, 'zhCN', '', '暮光之刃正在洗劫我们的村庄，抢走了许多珍贵的圣物。快把它们夺回来！', 66384),
(295049, 'zhCN', '死了这么多人。到底是为了什么？你也该随他们而去。', '', 66384),
(295019, 'zhCN', '', '可惜我们被迫动用武力。好言相劝解决不了所有问题。', 66384),
(295018, 'zhCN', '', '这些入侵者不受祖尔加拉保护。入侵者没有那种权利。不用手下留情！', 66384),
(295009, 'zhCN', '', '但我清楚，我与我的人民同在。他们是我坚实的后盾，我亦然。', 66384),
(295008, 'zhCN', '', '我知道你是什么。我曾试图放开你，但我失败了。', 66384),
(295007, 'zhCN', '', '你已经无可救药了。你已彻底沦为虚空。', 66384),
(295006, 'zhCN', '', '我当过比这更糟的实验品。', 66384),
(295000, 'zhCN', '但我们必须战斗。只要我们还在坚持，那些牺牲就不是徒劳。这茶让我重新记起了这一点。谢谢。', '', 66384),
(294997, 'zhCN', '阿曼尼、天灾军团、燃烧军团……我埋葬了太多战友。', '', 66384),
(294996, 'zhCN', '鬼花？有意思，这花能有多像鬼呢？', '', 66384),
(294979, 'zhCN', '我们万万不能让他们占了上风，对吧？', '', 66384),
(294978, 'zhCN', '你的目标在这里获取力量。摧毁力量之源，避开他们的守卫。', '', 66384),
(294977, 'zhCN', '他们会逃回去舔舐伤口，我们再抓住机会重创他们。', '', 66384),
(294976, 'zhCN', '让猎物以为你对他们的袭击毫无防备，再让他们为误判而后悔。', '', 66384),
(294975, 'zhCN', '多么奇妙的恐惧啊。', '', 66384),
(294974, 'zhCN', '别急着干掉他们，享受狩猎的过程，让神器饱餐他们的恐惧。', '', 66384),
(294972, 'zhCN', '大家都在盯着天空，可我听说南边也有危险逼近。\n\n什么圣光植物？巨魔？偏偏还是在太阳之井衰弱的时候？\n\n既然我们弱到连家都保不住，为什么不干脆投靠虚空，获得它的力量？', '大家都在盯着天空，可我听说南边也有危险逼近。\n\n什么圣光植物？巨魔？偏偏还是在太阳之井衰弱的时候？\n\n既然我们弱到连家都保不住，为什么不干脆投靠虚空，获得它的力量？', 66384),
(294971, 'zhCN', '“先锋军”还带来了一个联盟圣骑士，正是因为他，我的家人才会惨死异国。\n\n现在我们却要欢迎他们进城，就因为天上的威胁比他们更可怕？', '“先锋军”还带来了一个联盟圣骑士，正是因为他，我的家人才会惨死异国。\n\n现在我们却要欢迎他们进城，就因为天上的威胁比他们更可怕？', 66384),
(294970, 'zhCN', '圣光先锋军占领了我们的街道。虚空遮蔽了我们的天空。我们的血骑士和法师人手不够，根本守不住永歌森林。\n\n这不就是我们珍视的一切即将毁灭的征兆吗？', '圣光先锋军占领了我们的街道。虚空遮蔽了我们的天空。我们的血骑士和法师人手不够，根本守不住永歌森林。\n\n这不就是我们珍视的一切即将毁灭的征兆吗？', 66384),
(294969, 'zhCN', '你就是那个让无数辛多雷赞不绝口的“勇士”吧。\n\n看看那片天空，你还能信誓旦旦地说我们面临的不是末日吗？', '你就是那个让无数辛多雷赞不绝口的“勇士”吧。\n\n看看那片天空，你还能信誓旦旦地说我们面临的不是末日吗？', 66384),
(294894, 'zhCN', '瓦莉拉，我收到了报告，暮光之刃的密教徒中有人打算脱身，但他们担心会在逃跑时被捕。', '', 66384),
(294889, 'zhCN', '你的智慧救了你。用我的祝福去帮助他们恢复吧。告诉他们，只听从我或者纳尼亚的指令。', '', 66384),
(294888, 'zhCN', '我必须亲眼看看事发的地点。', '', 66384),
(294887, 'zhCN', '特泯纳斯虽已被击败，但胧影堡垒仍被敌军占据。你在那里并不安全，阿斯崔。', '', 66384),
(294885, 'zhCN', '我们都有需要弥补的过错。胧影堡垒见，$n。', '', 66384),
(294883, 'zhCN', '我已经接受了那些追随我前往泰洛古斯的人所面对的后果。只要我尚存一息，就会对我们的人民负责。', '', 66384),
(294882, 'zhCN', '啊，又见面了。不，我和这位交手得够多了。', '', 66384),
(294874, 'zhCN', '危险是这行的家常便饭，但巨额利润也是。', '', 66384),
(294856, 'zhCN', '', '不是说我在多曼纳尔的巢穴中有多自在，但我们的训练必须继续。', 66384),
(294853, 'zhCN', '别信那些谎话！看看天空吧！死亡降临了！', '别信那些谎话！看看天空吧！死亡降临了！', 66384),
(294852, 'zhCN', '太阳之井的尖啸正是先锋军所为！你们都看不出来吗？！', '太阳之井的尖啸正是先锋军所为！你们都看不出来吗？！', 66384),
(294851, 'zhCN', '先锋军早晚会抛弃我们！他们毫不在乎太阳之井！', '先锋军早晚会抛弃我们！他们毫不在乎太阳之井！', 66384),
(294850, 'zhCN', '虚空降临了！', '虚空降临了！', 66384),
(294841, 'zhCN', '', '那我就先告辞了。我们一家人已经很久没有团聚了，而且阿拉托尔也想和我聊聊。', 66384),
(294840, 'zhCN', '', '既然野兽都解决了，那我可以自己返回营地了。', 66384),
(294836, 'zhCN', '我劝你还是慢一点比较好。', '', 66384),
(294818, 'zhCN', '', '暮光之刃。和其他邪教组织一个德行。躲在面具后面，靠着偷来的力量作威作福。', 66384),
(294782, 'zhCN', '我不会再让你空等了。你已经证明了自身的价值。', '', 66384),
(294780, 'zhCN', '离我远点！', '', 66384),
(294777, 'zhCN', '', '为了荣耀。为了荣光。为了部落！', 66384),
(294776, 'zhCN', '', '见到你真是太好了。也许有朝一日我们能在战场上并肩而战。', 66384),
(294772, 'zhCN', '是时候回去履行职责了。回见。也许晚点该去隐士喝一杯。', '', 66384),
(294693, 'zhCN', '', '鲜血与雷鸣！真没料到会在这里遇见你。', 66384),
(294692, 'zhCN', '', '$n，到这儿来！我正讲到你的英勇表现呢。', 66384),
(294690, 'zhCN', '篝火的火光摇曳起舞，诉说着不曾证实的命运，召唤着你靠近。', '篝火的火光摇曳起舞，诉说着不曾证实的命运，召唤着你靠近。', 66384),
(294688, 'zhCN', '', '我理解传统的重要性，但你做了一件令人敬佩的事。出于对你先祖的敬意，我不会再干扰这场仪式。', 66384),
(294686, 'zhCN', '', '如果这些文件丢了，摄政王这一辈子都要头疼了。', 66384),
(294685, 'zhCN', '', '你身手不错，$n。我很期待能够再次和你共事。', 66384),
(294684, 'zhCN', '那就是我和你讲过的那位。到这儿来，$n。', '', 66384),
(294683, 'zhCN', '我无法充分表达对你所做一切的谢意。\n\n很欣慰有你与我们并肩作战，$n。联盟敬重责任心和传统，同时也尊崇荣誉和开拓进取的勇气，尤其是在时势所需的时候。\n\n希望日后还有相聚的机会。', '', 66384),
(294681, 'zhCN', '其他人都在啸影山脊集结，对吧？我去那里与你们会合。', '', 66384),
(294680, 'zhCN', '', '我还记得自己的部族仪式。它给了我使命，却不是我现在承担的使命。', 66384),
(294677, 'zhCN', '', '没有声响也没有毒云——很好。我看看里面是什么。', 66384),
(294676, 'zhCN', '', '开锁交给我，你来解除陷阱。', 66384),
(294643, 'zhCN', '', '还不错，$n。现在我们去看看他们究竟想挖得多深吧。', 66384),
(294642, 'zhCN', '', '我会留在暗影中从上方监视。别担心，如果形势有变，你不是孤军奋战。', 66384),
(294641, 'zhCN', '', '这座山头给了我们地利优势。可别浪费了。', 66384),
(294627, 'zhCN', '', '有幸存者！我们来得还不算太晚！', 66384),
(294618, 'zhCN', '虽然我感谢你的同伴对我生存能力的信任，但我更感激你的及时援手。\n\n我会避开你们的仪式。', '', 66384),
(294616, 'zhCN', '除了名称之外，我们对世界之根的了解少之又少。必须携手发掘更多奥秘。', '', 66384),
(294615, 'zhCN', '护根者会因世界之根重归故土而欣慰。', '', 66384),
(294613, 'zhCN', '露丽菈成为了第一位护根者，也是第一位根行者。', '', 66384),
(294612, 'zhCN', '为缔结契约，根须奉献了自身的一部分，露丽菈亦是如此。他们共同铸就了世界之根。', '', 66384),
(294611, 'zhCN', '林根之路连通着所有的巨树，穿越了整个艾泽拉斯乃至远方。', '', 66384),
(294610, 'zhCN', '根须现在将她视作一位盟友——一位守护者。它们向新的卫士揭示了林根之路的秘密。', '', 66384),
(294609, 'zhCN', '她运用刚获得的力量驱除了毒物。她治愈了焦灼的火痕，解开了纠缠的结节。', '', 66384),
(294608, 'zhCN', '根须弯曲复原，她的争斗也从肉体转移到了心灵。', '', 66384),
(294607, 'zhCN', '她握住了根须，使它们服从自己，从而与世界的意志取得联系。', '', 66384),
(294605, 'zhCN', '她发现我们用来变形成野兽的那种能力，使她得以和根须产生联系。', '', 66384),
(294604, 'zhCN', '露丽菈和她的追随者不会坐视自己的家园遭到破坏。', '', 66384),
(294603, 'zhCN', '女猎手露丽菈最先发现了垂死的根须。这片土地遭到了焚烧和毒害。', '', 66384),
(294602, 'zhCN', '遥想当年我们并不知道，艾泽拉斯地表的战争也会影响到这里。', '', 66384),
(294587, 'zhCN', '这家伙的启蒙仪式肯定很了不起。', '', 66384),
(294586, 'zhCN', '我在追忆之穴中见过许多仪式的壁画。每一幅都是成长为独特传说的种子。我很好奇你的故事会是怎样的。', '', 66384),
(294577, 'zhCN', '我还记得自己的成年仪式。如今我担任着阿梅达希尔的护根者。今天，我们要为你在哈籁提中寻找合适的位置。', '', 66384),
(294564, 'zhCN', '', '所以你就是大家口中的那位勇士。\n\n多亏你在太阳之井立下的功劳，我的许多族人才能幸存至今。我很感激你。\n\n不过现在，要是能让这些精灵明白这场战争的重要性就好了——这比单纯守护他们的城市重要得多。', 66384),
(294563, 'zhCN', '等等！给我回来！', '', 66384),
(294562, 'zhCN', '那是我的声音。这……这究竟是什么？', '', 66384),
(294561, 'zhCN', '你太弱小，而今还孤身一人。', '', 66384),
(294557, 'zhCN', '太苦了。太烈了。呃，我的头……', '', 66384),
(294553, 'zhCN', '干得漂亮，$n！有乌布里克帮忙，你可算是给了吞噬军团沉重的一击。', '', 66384),
(294534, 'zhCN', '我迫不及待想再次看你大显身手。', '', 66384),
(294533, 'zhCN', '让我们在节点希纳斯继续愉快的冒险吧。我会去那里找你。', '', 66384),
(294532, 'zhCN', '为何我当时不在那里？每次我需要他时他都在我身边……', '', 66384),
(294531, 'zhCN', '', '先锋军，把没钉在墙上的武器全都带上，我们出发！', 66384),
(294530, 'zhCN', '', '如你所愿，大主教。', 66384),
(294529, 'zhCN', '将军，你该去太阳之井检查我们的部队了。我和摄政王还有要事相商。', '', 66384),
(294528, 'zhCN', '', '那就满足我们的所有需求，还要替我们挡住敌人。', 66384),
(294527, 'zhCN', '太阳之井决不能沦陷。', '', 66384),
(294526, 'zhCN', '', '光是这些人手还不够呢。正是凭借我们部队的坚定信仰，太阳之井才挡得住虚空。', 66384),
(294525, 'zhCN', '为了强化太阳之井，你们已经要走了许多血骑士！奎尔萨拉斯因此而防卫空虚！', '', 66384),
(294521, 'zhCN', '我们都未曾有机会好好认识彼此，互通姓名，不是吗？\n\n海尔兰在胧影堡垒献出了生命。他的牺牲挽救了众人，包括我和麦拉在内。阿拉托尔派你去寻找他，而你只带回了他的日记。\n\n若要我用一个词来形容海尔兰，那就是可靠。他总是在关照他人，尤其是阿斯崔。他们彼此相依。', '', 66384),
(294516, 'zhCN', '我们如愿给予了虚空沉重打击。但代价……', '', 66384),
(294512, 'zhCN', '我必须继续前行，这是他的意愿。', '', 66384),
(294511, 'zhCN', '', '这一定就是间谍网络的心脏了。', 66384),
(294510, 'zhCN', '', '我猜洛瑟玛有些需要暗中完成的差事。别忘了最幽深的影子正是由太阳投下的。', 66384),
(294508, 'zhCN', '我需要直面自己的那一部分。营地再会，$n。我们还有工作要完成。', '', 66384),
(294507, 'zhCN', '海尔兰虽已离去，但我依然在此。', '', 66384),
(294503, 'zhCN', '', '女神已经指明道路。从她的话语中，我明白你将踏上与众不同的征程。\n\n你会亲眼见证女神的山川大海、密林荒漠、万千生灵和璀璨文明。你必须切身感受她的造化，唯有如此方能寻觅到她。', 66384),
(294482, 'zhCN', '', '我来自萨满祭司世家。虽然我没有选择聆听心灵之声的道路，而是走上了刀锋之途，但我尊重你们的传统和仪式。\n\n我们也有相似的仪式，叫做“奥姆瑞戈”。看来我们两族或许没有想象中那么不同。\n\n未来如果能够再次相遇，那将是我的荣幸。当然，前提是你愿意离开哈籁恩达尔，恰好来到奥格瑞玛。\n\n<盖尔塔点头致意，恭敬地行礼。>', 66384),
(294481, 'zhCN', '我不像其他人那样注重精神层面，我对这些仪式理解有限。德莱尼或许会懂。你听说过德莱尼吧？\n\n哈加尔和奥威娜向我保证，只要我不添乱，等你的启蒙仪式结束就送我回家。\n\n在暴风城我们也举办庆典，有丰盛的美食、动听的音乐和欢声笑语。当然少不了大量麦酒。或许你会和家人外出狩猎，或者约上好友一起……\n\n<阿尔顿顿住，尴尬地笑了笑。>\n\n算了，不说这些了。你们的仪式很有意义。我至少认识四个人会对你们的文化很感兴趣。', '', 66384),
(294478, 'zhCN', '它的幼崽逃过了一劫……真是奇了，连我都不知道是哪种魔法起了作用！', '', 66384),
(294475, 'zhCN', '可怜的生物……我们来得太晚了。', '', 66384),
(294474, 'zhCN', '<露丽菈说得没错。根系正在凋零。\n\n就像这片土地上的其他根系和生灵一样，它们都被地表世界的战火所焚烧毒害。\n\n露丽菈下定决心要亲自出手，帮助大地修复从艾泽拉斯降下的创伤。>', '<露丽菈说得没错。根系正在凋零。\n\n就像这片土地上的其他根系和生灵一样，它们都被地表世界的战火所焚烧毒害。\n\n露丽菈下定决心要亲自出手，帮助大地修复从艾泽拉斯降下的创伤。>', 66384),
(294469, 'zhCN', '被俘的朗多雷就像一条锁链。只要打断这条锁链，我们的总攻就能真正开始。', '', 66384),
(294440, 'zhCN', '美妙。这下它真要成为一把足以传世的利刃了。', '', 66384),
(294409, 'zhCN', '听见了吗？有生物在求救——援助弱小是远行者的职责！', '', 66384),
(294407, 'zhCN', '', '我们早就听过传闻了，什么时候才能记在心里呢？', 66384),
(294406, 'zhCN', '就快完成了！圣光先锋军的同伴们留下了一些圣光碎片。去取一片来，好吗？', '', 66384),
(294404, 'zhCN', '莫塔卡被困住了。可时至今日，那个生物仍在艾林裂隙中肆虐。', '', 66384),
(294393, 'zhCN', '', '这间简陋的小屋？我选择了这座位于哈尔玛拉社区中心的建筑，是为了离伟岸的泰达希尔根系更近一些。自其诞生之日起，这棵世界之树及其根系就饱经磨难与创伤。然而，根系依然坚韧不拔，生生不息。\n\n我望向屋外，回想起我的族人前往哈籁恩达尔途中所受的苦难。他们舍弃了诸多珍视之物，众多同胞在迁徙途中殒命，随后而来的便是那场疯狂。\n\n然而我们依然屹立于此，坚强如初，正如我们的传统般坚不可摧，赋予我们独特的身份。\n\n至于泰达希尔，终有一日，其根系会痊愈，世界亦会复原。', 66384),
(294391, 'zhCN', '一路上吱吱喳喳叫个不停。我简直笑得合不拢嘴。', '', 66384),
(294390, 'zhCN', '这都怪我的野性太有魅力。', '', 66384),
(294389, 'zhCN', '', '她足足跟踪了你快一个钟头。', 66384),
(294388, 'zhCN', '地图上明明说那个洞穴是废弃的！', '', 66384),
(294387, 'zhCN', '那次太逗了。你必须承认，这可是个好故事。', '', 66384),
(294386, 'zhCN', '', '只希望我们这次别再撞见什么愤怒的河狸了。', 66384),
(294385, 'zhCN', '你会爱上那儿的瀑布的。', '', 66384),
(294382, 'zhCN', '虚空即是杀戮，是混沌，是暴力。它美得惊心动魄。我们多曼纳尔中许多人想为这种美赋予形态，也是很自然的事。\n\n这个世界已被虚空彻底渗透，甚至大地本身都弥漫着它的气息。所以，我们找到了塑造它的方法，以驾驭虚空之力改造大地。\n\n当虚幻的力量让你能够影响现实之时，那种感觉令人无比沉醉。', '', 66384),
(294381, 'zhCN', '传统让我们团结一心、坚韧不拔，凭借坚定的意志和远大志向渡过难关。它让我们专心致志，与内心本性保持和谐。传统务实高效，指导我们应对威胁、作出抉择，并为族人规划未来。', '', 66384),
(294331, 'zhCN', '探求者沉默地坐着。就在那里，我们听见了歌声。', '', 66384),
(294330, 'zhCN', '她不在光明之中——她是那光明留下的温暖。', '', 66384),
(294328, 'zhCN', '这好像是一块盾牌的碎片。', '', 66384),
(294308, 'zhCN', '给这满城傲慢血精灵中的一个——赛多娜·暮塔，她是海尔兰的一位故人。\n\n海尔兰在我们抵达银月城之前写下了这封信。他告诉我想亲手交给她。在我们踏入虚影风暴传送门前，他曾尝试过。\n\n如今这些都已不重要了。', '', 66384),
(294301, 'zhCN', '我明白了。海尔兰已经不在了。', '', 66384),
(294300, 'zhCN', '这次任务是个错误。', '', 66384),
(294299, 'zhCN', '付出如此之多，却仍然落后。你有其他人的消息吗？', '', 66384),
(294298, 'zhCN', '放松点！陆行鸟很任性，而且跑得可快了！', '', 66384),
(294296, 'zhCN', '你撒的都是什么种子？这些花和我见过的都不一样！', '', 66384),
(294284, 'zhCN', '用晶化虚空来强化刀锋！', '', 66384),
(294273, 'zhCN', '以虚空火盆的火焰锻烧刀刃！', '', 66384),
(294272, 'zhCN', '从虚空储存器中萃取精华。将其放入暗影中淬火！', '', 66384),
(294271, 'zhCN', '将巨兽骨粉洒在虚空灼燃的刀刃上，这将使金属更为坚韧。', '', 66384),
(294270, 'zhCN', 'Anu bala belore\'alon，malanore。', '', 66384),
(294269, 'zhCN', '干得漂亮！植物已经开始冒头了——里面还有些挺奇特的品种！', '', 66384),
(294259, 'zhCN', '下一次，我会去向本地人打听！', '', 66384),
(294258, 'zhCN', '在回响寂灭之焰面前，谁都无法听见女神的歌声。', '', 66384),
(294257, 'zhCN', '奥巴约深知，回响寂灭之焰是他们最大的希望。', '', 66384),
(294253, 'zhCN', '屠杀哈籁尼尔！夷平哈籁恩达尔！让所有人都加入这刺耳的合唱！', '', 66384),
(294239, 'zhCN', '遗憾的是，我们不知道怎样重燃回响寂灭之焰。但愿将来有机会……', '', 66384),
(294236, 'zhCN', '真羡慕你能见到奥巴约，亲自了解回响寂灭之焰，$p。', '', 66384),
(294235, 'zhCN', '她并不为此哀痛，而将它视作责任。免除回响的困扰后，她在裂隙中狩猎暗影，为同样做出牺牲的人指点迷津。', '', 66384),
(294234, 'zhCN', '但在那之前，它暂且交由你照料。或许这是培育它成长的最佳途径。', '', 66384),
(294233, 'zhCN', '奥巴约发现，做出牺牲的并不只有回响寂灭之焰。她再也听不见女神的声音，她们之间的联系被烧毁了。', '', 66384),
(294232, 'zhCN', '假以时日，菲多费库斯必将成为令人闻风丧胆的恐怖存在。', '', 66384),
(294231, 'zhCN', '听到这个消息我很欣慰。虽然不愿承认，但你确实做得很好，凡人。', '', 66384),
(294230, 'zhCN', '$n！我正要开始呢。虽然是对技术的考验，但我可以修好它。', '', 66384),
(294229, 'zhCN', '于是，烈焰被拆分成了三个结界，将那头猛兽困住，拯救了哈籁恩达尔。', '', 66384),
(294228, 'zhCN', '奥巴约知道，回响寂灭之焰中剩余的力量不足以将莫塔卡彻底消灭。', '', 66384),
(294225, 'zhCN', '', '我离开血色十字军的时候，心里满是疑虑、恐惧和迷茫，$p。\n\n这是我这辈子最艰难的决定。\n\n但我看清了，我曾经深信不疑的一切都是错的。\n\n真高兴能帮助艾莉瑟走上同样的救赎之路。', 66384),
(294224, 'zhCN', '', '我曾为了让被遗忘者和人类和解而牺牲了生命，$p。这是一项崇高的事业，而我至今仍在为之努力。\n\n感谢你和阿隆索斯把艾莉瑟带到我这里。\n\n她很渴望学习，也很想弥补过去的过错。', 66384),
(294223, 'zhCN', '裂隙的不谐歌声使具象受尽了折磨，可回响寂灭之焰为它们带去了平静。', '', 66384),
(294222, 'zhCN', '', '多谢你当初在我逃离十字军时饶我一命。\n\n多年来我疑虑渐生，却总是强行压下。\n\n$p，和佳莉娅与马丽拉的交谈，正让我对这个世界产生截然不同的理解。\n\n这种感觉既像是坠入深渊，又像是瞬间获得了自由。\n\n有她们相助，我相信我会有一个更好的归宿。', 66384),
(294221, 'zhCN', '不过，有个名叫莫塔卡的生物在裂隙中领导着具象，整个哈籁恩达尔都受到了威胁。', '', 66384),
(294220, 'zhCN', '哈籁尼尔一向对艾林裂隙避之不及。女神之歌的不谐回声会引发疯狂。裂隙中的凶暴具象则会带来死亡。', '', 66384),
(294219, 'zhCN', '', '当心脚下！我在收集暮叶，把其他两人采的东西包装起来。\n\n要是绍麦尔在，早就想出对策了。他总有办法。可他不在了。现在只能靠我。\n\n<娜耶莉沉默片刻。>\n\n不管付出什么代价，我都要把他救回来。幸好你在这里……我们得相互扶持。', 66384),
(294218, 'zhCN', '', '哦！没听见你的脚步声……还以为是瓣翼鸟呢。\n\n我、我在采火叶和喃花。它们香气怡人，处理得当能让反应更加敏捷。\n\n绍麦尔常说我的手很适合这种细致的工作……我希望他能回来。我想念他。所以哪怕害怕，我也要帮忙。', 66384),
(294215, 'zhCN', '啧。别这样悄悄摸摸靠近我，我差点把荧光根都吓掉了。\n\n这些植物？能让你精神焕发。要是那只巨大的羽毛怪再回来，可能派得上用场……我才不怕呢。只是……总得有人做好准备。\n\n绍麦尔一直保护着我们。现在该轮到我们保护别人了。明白吗？', '', 66384),
(294214, 'zhCN', '现在给我滚，你们两个！你们不配出现在我面前。', '', 66384),
(294213, 'zhCN', '若它还有丝毫力量值得我吞噬，我定会将它生吞活剥！', '', 66384),
(294211, 'zhCN', '我真是愚不可及，竟然将心血浪费在这样一条孱弱蠕虫身上！', '', 66384),
(294209, 'zhCN', '什么？', '', 66384),
(294202, 'zhCN', '第二次战争早就结束了。你们流血换来的和平不能再被他们打破了。', '', 66384),
(294201, 'zhCN', '黑暗部落正准备掠夺另一处边境村落。拿上最后的盾牌碎片，然后击溃他们的部队。', '', 66384),
(294192, 'zhCN', '', '光绽很顽强，我们也必须这么顽强。', 66384),
(294191, 'zhCN', '', '精准攻击？我当时就该把所有人都叫上。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(294190, 'zhCN', '不————我还会回来的！', '', 66384),
(294186, 'zhCN', '告诉我……那野兽恐怖吗？凶猛吗？致命吗？', '', 66384),
(294185, 'zhCN', '', '它们能送我们下去，但要速战速决。我不能让它们和光绽长期接触。', 66384),
(294184, 'zhCN', '', '他对女神的信仰变成了仇恨，这都是光绽所为吗？', 66384),
(294183, 'zhCN', '', '我会封锁林根之路，这次他逃不掉了。', 66384),
(294182, 'zhCN', '有了光绽，我能让哈籁尼尔恢复到该有的模样。可你却在妨碍我。', '', 66384),
(294181, 'zhCN', '', '鲁伊亚在这里？', 66384),
(294180, 'zhCN', '光绽已经完全失控了，你不可能永远压制住它。', '', 66384),
(294177, 'zhCN', '', '原来鲁伊亚一直躲在这种地方……', 66384),
(294175, 'zhCN', '擅闯我们的花园是要付出代价的，光绽会让你血债血偿。', '', 66384),
(294174, 'zhCN', '', '那个看着很危险，必须摧毁它，不能让注能结束。', 66384),
(294173, 'zhCN', '安度因·洛萨战死后，我父亲集结了联盟，带他们取得了胜利。', '', 66384),
(294172, 'zhCN', '我父亲图拉扬参加了这场战争，但他很少跟我提及这段经历。', '', 66384),
(294171, 'zhCN', '', '大规模进攻只会导致光绽继续蔓延。直击最危险的地方才是上策。', 66384),
(294170, 'zhCN', '', '艾林之尘数量有限，我们必须针对光绽最为活跃的区域。', 66384),
(294169, 'zhCN', '这场战争给黑暗部落都留下了严重的创伤。他们还在这里打一场早就失败的战争。', '', 66384),
(294167, 'zhCN', '你来啦！法奥，为什么把我们带到这荒凉的地方来？', '', 66384),
(294166, 'zhCN', '我才不是为殆希莫斯做事，我在这里是为了监视他。\n\n我们多曼纳尔永远在争夺权力。就算你浅薄的目光无法洞察，我们也始终在争权夺位。\n\n殆希莫斯的庇护所为我提供了培育大批怪物所需的资源。作为交换，我的怪物们守卫着殆希莫斯。所以暂时，我们是盟友。\n\n但我确信这种关系终将改变。殆希莫斯也心知肚明。\n\n比多曼纳尔更致命的，只有拥有成群利爪獠牙的多曼纳尔。', '', 66384),
(294164, 'zhCN', '让幼崽们自相残杀必定能培育出暴虐和畸形！\n\n但你们凡人却提到另一种策略。你们称之为……关爱。也许我该尝试一下。', '', 66384),
(294163, 'zhCN', '现在让我看看什么叫“征服”！', '', 66384),
(294162, 'zhCN', '让我看看什么叫“凶残”！', '', 66384),
(294161, 'zhCN', '我……可那不是我的盾牌呀。', '', 66384),
(294160, 'zhCN', '他说的有理，小子。这么好的盾牌一定渴望着保护士兵，让士兵去保护更多人。', '', 66384),
(294158, 'zhCN', '谁都有可能崩溃，但我们可以重新振作起来，变得更为顽强。', '', 66384),
(294157, 'zhCN', '哎呦！糟透了！没听过这么糟的主意。', '', 66384),
(294156, 'zhCN', '这场冒险的结局，与我的预期完全不同。不过我觉得这或许也是一种恰到好处的致敬。', '', 66384),
(294155, 'zhCN', '唔……我已经考虑过了。我想将它挂在这面墙上，作为警示。', '', 66384),
(294147, 'zhCN', '菲多费库斯站在兹托克的尸体上发出胜利的咆哮。', '', 66384),
(294145, 'zhCN', '菲多费库斯已准备好证明自己了。到南边的兽穴与他会合，亲眼见证我们培育出的凶残生物。', '', 66384),
(294139, 'zhCN', '这真是个了不起的地方，$p。\n\n谢谢你在我的旅程中伸出援手。\n\n我们帮了很多人，这对我自己也很有意义。', '', 66384),
(294132, 'zhCN', '菲多费库斯对着微小的爆爬虫发出充满自信的咆哮。', '', 66384),
(294120, 'zhCN', '莫非这就是你们凡人所说的……友情吗？希望真是如此。', '', 66384),
(294119, 'zhCN', '奇怪，我竟想要更深入地了解你。也希望你能了解我。', '', 66384),
(294118, 'zhCN', '把乌瑟尔的工具包托付给我……也许它还能再次发挥治愈的作用。', '', 66384),
(294117, 'zhCN', '从那以后，我尽力为圣光服务，但一直背负着失望和对所见苦难的愤懑。', '', 66384),
(294116, 'zhCN', '', '她的故事激励我投身圣光事业。虽然我从未见过她，但我会珍藏这件东西的，$p。谢谢你。', 66384),
(294115, 'zhCN', '', '就算是队长，有些时候也需要亲自动手。', 66384),
(294113, 'zhCN', '', '听好了，仆从。若是百年之后，你仍对我们的契约不满，我允许你重新谈判条件。', 66384),
(294112, 'zhCN', '', '玛尔拉德是我们人民的英雄，$p。我能感受到他的圣光——它依然留在这块水晶里。', 66384),
(294111, 'zhCN', '菲多费库斯对虚空精灵展露凶态。', '', 66384),
(294109, 'zhCN', '', '$p，你还撑得住吗？我知道你肩上的担子很重。\n\n说实话，我自己也……快到极限了。', 66384),
(294108, 'zhCN', '$p，多年来，我一直对乌瑟尔训练阿尔萨斯这件事耿耿于怀，但他原谅了我。这反而让我更加愧疚。', '', 66384),
(294106, 'zhCN', '$p——我不是第一次看到邪恶势力袭击太阳之井了。虽然很疲惫，但我会像以前一样坚持下去。', '', 66384),
(294105, 'zhCN', '', '这正合我意，但别忘了谁才是主宰。也许变成低等形态一段时间能让你牢记这一点。', 66384),
(294104, 'zhCN', '', '谢谢你，$p。我已经感受到它的力量了。我会好好运用它的。', 66384),
(294101, 'zhCN', '', '说实话，$p——虽然能来太阳之井确实是莫大的荣幸，但实在是累得够呛。\n\n希望你带来了好消息，或者更多援助？', 66384),
(294098, 'zhCN', '狂妄的精灵！我会回来的，只为见证你的末日！', '', 66384),
(294097, 'zhCN', '', '我欣赏你的气魄，卡尔高戈。正因如此，我才命你回到我身边。', 66384),
(294096, 'zhCN', '你以为你获胜了？我乃永恒！我即虚空！你们不过是凡间蝼蚁！', '', 66384),
(294092, 'zhCN', '规则很简单。找到我们其中一个人后，我们就到峡谷尽头集合。简单吧？\n\n<绍麦尔神情严肃起来。>\n\n准备开始了吗？', '', 66384),
(294091, 'zhCN', '菲多停下脚步，在那些狰狞的骨头前瑟缩不前。', '', 66384),
(294081, 'zhCN', '', '你总算来了，泰尔敏！我差点就让其他人先出发了！', 66384),
(294080, 'zhCN', '你完成任务后，到我的野兽旁与我会合。', '', 66384),
(294071, 'zhCN', '', '别打什么歪主意，布罗西纽斯。', 66384),
(294063, 'zhCN', '<卡尔高戈用饱含恶意的眼神瞪着你。>', '', 66384),
(294058, 'zhCN', '我希望情况并非如此……可不管怎样，我们对永歌森林的责任不会改变。', '', 66384),
(294057, 'zhCN', '不过自从城破之后，就再没人见过那些精魂了。也许它们和我们无数的同胞一起，早已消逝了。', '', 66384),
(294054, 'zhCN', '过去的游侠是森林的看护者，他们看护着林中漫游的各种奇妙精魂。', '', 66384),
(294053, 'zhCN', '这正是我备受鼓舞的原因——我想成为那些古老传说的一部分。你来看看这个。', '', 66384),
(294052, 'zhCN', '你或许会觉得意外，但我们游侠也是有图书馆的。毕竟，我们的历史和辛多雷本身一样古老。', '', 66384),
(294043, 'zhCN', '先喂饱这野兽，然后带它绕着山脊走走，让它能够……展示它的威严。', '', 66384),
(294042, 'zhCN', '材料都已摆在桌上。烹饪、喂食，还有照料这生物的任务都交给你了。', '', 66384),
(294037, 'zhCN', '', '啊……！我的天穹琉璃收集工作要暂停一下了……！', 66384),
(294035, 'zhCN', '', '你的精神真是坚韧不拔，库利。我为你骄傲。不过下次别让陌生人帮你采集迅叶龙之蕨了，知道吗？下周你要补偿我双倍的量。', 66384),
(294034, 'zhCN', '', '我们的家园到处都是奇迹。所有东西都那么古怪神秘！我确信艾林莎兰就在那里。我只是还没找到召唤他的方法！', 66384),
(294033, 'zhCN', '', '第一次尝试失败了。但这不代表艾林莎兰不存在！只能说我还遗漏了什么。', 66384),
(294032, 'zhCN', '', '失望？！怎么会！', 66384),
(294031, 'zhCN', '', '别太失望，小家伙。谜团和传说都是靠不住的东西。', 66384),
(294029, 'zhCN', '', '……等等。就这样？这——不可能！我明明觉得……', 66384),
(294028, 'zhCN', '', '看！开始了！', 66384),
(294015, 'zhCN', '', '找到你了！快来。把裂片丢进水池里！', 66384),
(294013, 'zhCN', '<生物发出低沉的咆哮。若不是它体型太小，这声音定会令人胆寒>。', '', 66384),
(294007, 'zhCN', '<这只小型巨兽抬头望着你，急切期待着它的营养点心。>', '', 66384),
(294006, 'zhCN', '准备好就说一声！', '', 66384),
(293986, 'zhCN', '太好了！到宁静休憩所来找我，我们会帮你的陆行鸟配上鞍具。', '', 66384),
(293982, 'zhCN', '', '跟紧我，我会用黑暗遗物匣强化你。让我们彻底终结它的违逆。', 66384),
(293980, 'zhCN', '', '什么……这真是难以置信。她是我的祖母。她曾经照顾过那些从暴风城逃到洛丹伦的难民。', 66384),
(293978, 'zhCN', '', '不管这是什么菌，它最大的奴仆肯定就在附近。保持警惕。', 66384),
(293977, 'zhCN', '', '希望你带回来的是好消息，$p。大家都累坏了。\n\n要不是之前法奥的权杖给了我们帮助，我们早就撑不住了。', 66384),
(293976, 'zhCN', '', '烧掉它，$c，趁着还没蔓延开，赶紧烧掉。', 66384),
(293975, 'zhCN', '', '多加小心，我有一种不好的预感。', 66384),
(293929, 'zhCN', '这片土地与它该有的模样截然不同，但它和曾经的样貌相比也有了许多变化。\n\n只要你愿意去滋养，它总能一点点恢复。', '', 66384),
(293886, 'zhCN', '', '感受周围的虚空之力，$n。决不能让卡尔高戈夺取这股力量。', 66384),
(293840, 'zhCN', '法奥，你最好知道自己在做什么。', '', 66384),
(293839, 'zhCN', '如果我能把盾牌修好，也许就能让父亲想起来他成为圣骑士的本心。', '', 66384),
(293837, 'zhCN', '联盟……图拉扬……一切都在顷刻间改变了。', '', 66384),
(293829, 'zhCN', '既然这孩子找到了所有盾牌碎片，我们可以开始了。', '', 66384),
(293824, 'zhCN', '我会将这些材料带到大锅旁，但烹饪须由你完成。', '', 66384),
(293820, 'zhCN', '随便挑一份邀请函，在宫廷中争取他们的青睐。不过也得注意：辛多雷不喜欢遭到冷落。', '', 66384),
(293819, 'zhCN', '啊，辛多雷的一流政治真是壮观，对吧？', '', 66384),
(293791, 'zhCN', '有些生灵陷入了贪婪，只为填补她离去之后留下的空虚。', '', 66384),
(293790, 'zhCN', '有些生灵忘却了她的歌声，聆听着随之而来的死寂。', '', 66384),
(293789, 'zhCN', '有些生灵依然与她合声共唱。', '', 66384),
(293788, 'zhCN', '这些生灵记得她曾经的所在地。', '', 66384),
(293787, 'zhCN', '', '我的兄弟一有困扰就会心烦意乱。就请你去帮他分忧吧。', 66384),
(293778, 'zhCN', '哈！萨瑟利尔居然邀请密谋小径的人参加聚会？也许我的商品能赚到一些金币。算我一个。', '', 66384),
(293777, 'zhCN', '我痛恨这种行事方式。但为了这场战争，血骑士需要资源，那就开始吧。', '', 66384),
(293776, 'zhCN', '', '帮泰尔敏的忙？我想书里有些诗句他会很喜欢的。', 66384),
(293775, 'zhCN', '', '亲爱的，即使他不邀请我也会出席。为了贵族圈子，我和他已经多次上演这种游戏了。我去准备一下。', 66384),
(293774, 'zhCN', '我真想着要把它送回去呢！反正马上就要在野外生火做饭了。', '', 66384),
(293773, 'zhCN', '', '谢啦！光是训练这帮小崽子就够我忙的了，哪还有时间看书！', 66384),
(293765, 'zhCN', '', '这是为了募集军费而聚会吗？很好，我可以花时间与贵族周旋，为远行者的金库筹措一些资金。', 66384),
(293758, 'zhCN', '还从来没有外来者完成过这些试炼。或许你确实感受过艾林哈籁的抚触。', '', 66384),
(293757, 'zhCN', '这是我父亲的盾牌吗？它是怎么破的？', '', 66384),
(293748, 'zhCN', '你真是我的救星！我先……找个地方把这东西放下，然后就去图书馆找你。', '', 66384),
(293746, 'zhCN', '', '奥术渴望着我！', 66384),
(293745, 'zhCN', '晨行者队长真是格外开恩，竟然让一个法师加入了远行者部队。\n\n我没想到要跑这么多路，干这么多体力活，还天天一身泥！\n\n但我绝不会让游侠部队失望的！', '', 66384),
(293737, 'zhCN', '噢，发给密谋小径的邀请函不是无心之失。我一向喜欢出人意料的戏码。', '', 66384),
(293736, 'zhCN', '辛多雷的政治牵涉到许多微妙的技艺，就像一种复杂的舞蹈，而我们天生就会跳。', '', 66384),
(293733, 'zhCN', '很好，努米亚，试试用它来对付纳迦，这或许可以剥夺他们的力量。', '', 66384),
(293732, 'zhCN', '', '魔杖迅速接受了奥能……', 66384),
(293731, 'zhCN', '这一杯敬……商人……精明强干的大师，永歌森林的守护者！Anu belore dela\'na!', '', 66384),
(293730, 'zhCN', '这一杯敬远行者，荒野的卫士，永歌森林的守护者！Anu belore dela\'na!', '', 66384),
(293729, 'zhCN', '这一杯敬血骑士，坚定不移的圣光信徒，永歌森林的守护者！Anu belore dela\'na！', '', 66384),
(293728, 'zhCN', '这一杯敬魔导师，奥术秘法的大师，永歌森林的守护者！Anu belore dela\'na！', '', 66384),
(293727, 'zhCN', '', '忘恩负义的畜生！你竟敢违背契约？快追上它！', 66384),
(293724, 'zhCN', '', '自从踏入这个世界，卡尔高戈就开始违抗我的命令。帮我献祭它吧，它已经毫无价值了。', 66384),
(293721, 'zhCN', '', '每个新发现都让我们离清除异常、恢复环境平衡更近一步。', 66384),
(293712, 'zhCN', '这个我们就拭目以待吧。狩猎的旅途可能很漫长。', '', 66384),
(293707, 'zhCN', '', '看到他们了吗？追上从村里跑出来的间谍！', 66384),
(293706, 'zhCN', '', '哈尔拉兹是狩猎之神。而沙德拉是他的宿敌。他一定很乐意狩猎沙德拉。', 66384),
(293690, 'zhCN', '谁会把完好的魔杖一丢了之？你们魔导师这么挑剔的吗？', '', 66384),
(293687, 'zhCN', '不稳定的奥能……他们要找的肯定就是这个。', '', 66384),
(293680, 'zhCN', '看来这是个大闹一场的好机会。你要是也想来找点乐子，那就和我说一声。', '', 66384),
(293679, 'zhCN', '山里的兽人有的不只是一块碎片——他们还在囤积武器。', '', 66384),
(293665, 'zhCN', '', '尼嘉·断齿放声大笑，赞许地点了点头。', 66384),
(293664, 'zhCN', '这就是信任。有了神灵相助，我们能做的不只是抵抗！', '', 66384),
(293663, 'zhCN', '', '我们可以一起抵抗邪枝部族。', 66384),
(293662, 'zhCN', '这里的情形大不相同。枯木部族过去是、将来也永远是你们的盟友。我们正倾尽全力守护大家的安全。邪枝部族才是真正的死敌。', '', 66384),
(293661, 'zhCN', '', '不，我来自辛特兰。在那儿，枯木部族曾四处狩猎恶齿族人。我只是想确认一下，这里的枯木部族是否还恪守旧习，像我这样的难民是否真的安全。', 66384),
(293660, 'zhCN', '尼嘉。我还在纳闷你为何造访我们的村落。是为了沙德拉吗？', '', 66384),
(293659, 'zhCN', '', '我和你一起去，$n。', 66384),
(293658, 'zhCN', '沙德拉。枯木很荣幸能恭迎你的归来。', '', 66384),
(293657, 'zhCN', '不出所料，你已经开始编织蛛网了！欢迎来到祖阿曼，沙德拉。', '', 66384),
(293656, 'zhCN', '', '嗯。看来百废待兴。我重生的时机倒是恰到好处。', 66384),
(293655, 'zhCN', '出现了一枚蛛卵！', '', 66384),
(293654, 'zhCN', '你得协助它破壳——动作一定要轻！', '', 66384),
(293653, 'zhCN', '回到你忠诚的枯木和恶齿部族身边吧！', '', 66384),
(293652, 'zhCN', '沙德拉，我们带来了你的牙，你的眼，和你的壳，令它们再度齐聚。', '', 66384),
(293651, 'zhCN', '在中间站好，全神贯注地盯紧三个仪式用品。', '', 66384),
(293650, 'zhCN', '我很熟悉沙德拉这一神灵。在丧命之前，她一直很关照辛特兰的枯木巨魔，她会强化他们的武器，通过孩子的复眼来赐予他们智慧。可惜的是，她屡次遭到凡人的利用，也因此变得愤愤不平。只要她能协助我的子民对抗邪枝部族，这里就欢迎她。\n\n如今的蜘蛛之神虽然渺小，但她很快就能壮大。我会一直盯着她。她形单影只的时候经历了不少苦难，也遭到过许多恶劣的对待。我会指引她将那股力量用于正途。', '', 66384),
(293648, 'zhCN', '你的狩猎结束了。', '', 66384),
(293640, 'zhCN', '', '这话我爱听。我去一趟远行者营地，之后会去那里找你。', 66384),
(293637, 'zhCN', '我会让远行者引以为傲的，队长！', '', 66384),
(293634, 'zhCN', '', '泰尔敏，你的任务会更棘手……但你的奥术天赋在南塔将大有用武之地。', 66384),
(293618, 'zhCN', '', '从迈萨拉的深处找回我的外壳，我们就能一起惩罚邪枝巨魔。', 66384),
(293617, 'zhCN', '', '卑鄙的邪枝部族正在危害我的孩子，阻止我的归来。', 66384),
(293616, 'zhCN', '', '啊，我的枯木巨魔。还有个恶齿巨魔。着实有趣。', 66384),
(293615, 'zhCN', '', '沙德拉！求你，和我们谈谈吧。', 66384),
(293614, 'zhCN', '', '等你准备好开始了就告诉我。', 66384),
(293612, 'zhCN', '哈斯温里奥队长派你来的？他肯定在忧心忡忡吧。\n\n等我把发现成果递交上去，他肯定也不会好受的。\n\n纳迦正从多个来源收集奥能，并将它们囤积在这里……他们显然在利用奥能强化自己，但大部分奥能都被运到了海上。\n\n至于去了哪里，交给谁用，只有时间才会揭晓。', '', 66384),
(293611, 'zhCN', '我……我的计算出现了严重的错误！\n\n在这最黑暗的时刻，我以为我们都要完蛋了……或许纳迦掌握着活命的关键。\n\n他们不愿分享那股力量。我现在明白了，我知道他们为什么要留我一命了。求你了，放我出去！', '', 66384),
(293610, 'zhCN', '', '但我们还需要弄到眼睛。但愿这样就足够联系她了。', 66384),
(293609, 'zhCN', '', '神灵在回应我们！', 66384),
(293608, 'zhCN', '', '啊！既然你能发现我，那隐形药水的效果肯定是衰退了。我该走了。幸好第一个找到我的是你。\n\n我偷了一些奥能的样品，当然是用来调查的。有这些就够了……', 66384),
(293607, 'zhCN', '', '我觉得邪枝巨魔已经意识到沙德拉仍能被召唤，并正试图阻止我们——甚至想抢走她！', 66384),
(293606, 'zhCN', '', '邪枝部族一直以来都难辞其咎——我同意。我们去和神灵谈谈吧。', 66384),
(293605, 'zhCN', '', '加库尔……是哈籁尼尔最优秀的画家之一。他很少收徒，但他说我深具潜力，前途远大。\n\n我从年轻的时候就和他一起生活了。呃，我想是更年轻的时候。我通常一整天都在调和颜料，学习如何创作我们的圣画。\n\n他走了之后……我还有很多东西要学。没了他的指点，我也不知道何去何从了。', 66384),
(293602, 'zhCN', '你迟到了！快上工！', '', 66384),
(293577, 'zhCN', '没有别人了。几乎所有圣骑士都被圣光召唤到太阳之井去了。\n\n达里安算是欠我个人情，因为他曾经想杀了我，把提里奥的遗体变成他的四骑士之一。\n\n而且他也不想看到虚空在对抗艾泽拉斯的斗争中占据上风。\n\n所以当我请求支援时，黑锋骑士团挺身而出，前来支援我们。', '', 66384),
(293491, 'zhCN', '', '到哈库艾等我。我们要召唤一条翔龙！', 66384),
(293446, 'zhCN', '找不到东西了吗？你算是找对人了。', '', 66384),
(293444, 'zhCN', '', '亲爱的，你有预约吗？正式接待时间在明晚。', 66384),
(293442, 'zhCN', '', '<她起初以严厉的目光审视着你，随后展露出淡淡的微笑。>\n\n盔甲不错。\n\n在找什么人吗？我本该帮游侠给龙鹰备鞍的，不过这事可以先放放。', 66384),
(293440, 'zhCN', '若有所需，请快点说。我们的时间安排极为紧迫。', '', 66384),
(293437, 'zhCN', '', '邪枝部族正在洗劫墓穴，还抢走了一切！听我解释……', 66384),
(293416, 'zhCN', '我会告知萨瑟利尔男爵，您很快就会到访。', '', 66384),
(293408, 'zhCN', '', '快，守住我们西部的前线！', 66384),
(293407, 'zhCN', '', '敌人正在从东面靠近！', 66384),
(293406, 'zhCN', '', '北部的防御遭到了袭击！', 66384),
(293405, 'zhCN', '', '他们正在冲击南部的防线！', 66384),
(293398, 'zhCN', '我之前没有完全和你们坦诚相告。', '', 66384),
(293395, 'zhCN', '', '奇点锚点应该可以暂时封印虚空畸能。我们必须在充能期间保护它。', 66384),
(293393, 'zhCN', '', '设备损毁了。重整队伍，做好战备，我们之后再试一次。', 66384),
(293392, 'zhCN', '', '奇点锚点受损严重，它快要支撑不住了！', 66384),
(293391, 'zhCN', '', '奇点锚点受到了损伤，快把它们赶回去！', 66384),
(293390, 'zhCN', '', '敌人来了。保护好奇点锚点！', 66384),
(293385, 'zhCN', '我们……先专心地激活哨兵吧。', '', 66384),
(293384, 'zhCN', '我的母亲奥蕾莉亚比任何人都更了解如何对付虚空。但我已经几周没见过她了。我只希望……', '', 66384),
(293383, 'zhCN', '大主教图拉扬是位志得意满的战场指挥官。只是……我觉得他有时候忘了，他其实还有别的身份。', '', 66384),
(293382, 'zhCN', '请原谅我父亲的语气。说好听点，我们对事情的看法也不总是一致。', '', 66384),
(293379, 'zhCN', '', '但愿这足以扼制他们的蔓延，让其他地区能够逃过一劫。', 66384),
(293378, 'zhCN', '', '盛放晶格中长满了凶暴的芦塔尼。去修建一下吧。', 66384),
(293339, 'zhCN', '', '它们都在逃往同一个地方。我们要查明那究竟是哪里。', 66384),
(293336, 'zhCN', '噢，我不会让你那么快就送命的。', '', 66384),
(293335, 'zhCN', '你不太擅长躲藏，是吗？', '', 66384),
(293334, 'zhCN', '别这么快就被捉住，我还要细细品味呢。', '', 66384),
(293325, 'zhCN', '我赐予你力量，让你能看见隐匿的沙德拉之眼。', '', 66384),
(293324, 'zhCN', '', '兄弟，小声点。', 66384),
(293322, 'zhCN', '解决掉那束被圣光诅咒的杂草。', '', 66384),
(293321, 'zhCN', '你明白我的意思，$p。', '', 66384),
(293320, 'zhCN', '那个残忍的圣光怪物必须付出代价！它横行霸道，居然对鱼下手。', '', 66384),
(293319, 'zhCN', '这肯定会是最新鲜的一批！', '', 66384),
(293315, 'zhCN', '你必须解决那些害虫，不然我的名声就要毁了！', '', 66384),
(293310, 'zhCN', '', '世界之树的欣荣并不需要什么。哈籁恩达尔几乎是它们根须的完美家园。但干旱、寄生虫和其他危险确实会出现。\n\n这既是为了我们哈籁尼尔，也是为了世界之树本身。这赋予了我们使命，让我们时时刻刻都能意识到这个家园的重要性。我们不惜用生命保护这里，因为我们的所作所为不止会影响到我们。', 66384),
(293309, 'zhCN', '用你们取回的武器，引导其中的圣光，将这个怪物赶回虚空去！', '', 66384),
(293306, 'zhCN', '', '你是圣光中的灯塔。我们必将取胜，不惜代价。', 66384),
(293305, 'zhCN', '不过，我还能靠这两吨重的光祝钢铁机甲来壮胆。', '', 66384),
(293303, 'zhCN', '我奶奶教过我怎么打好仗，在绝境中顽强抗争，还教了我信仰圣光。', '', 66384),
(293295, 'zhCN', '', '你的思维太狭隘了。我们需要让先锋军全力出击才能击败萨拉塔斯。', 66384),
(293291, 'zhCN', '', '这样抽调部队，留下来强化太阳之井的人将寥寥无几！', 66384),
(293281, 'zhCN', '我发现了黑暗部落的领袖。最后的碎片在她身上。', '', 66384),
(293280, 'zhCN', '法奥为什么要带我来这儿？这件圣物肯定还有什么没告诉我的秘密。', '', 66384),
(293279, 'zhCN', '我研究过第二次战争，可对在场的各位来说，那不是历史，而是亲历。', '', 66384),
(293277, 'zhCN', '除非你想尝点苦头，否则别碰我的狩猎长矛。矛尖上蘸的毒液可是来自隐匿石的。', '', 66384),
(293276, 'zhCN', '喜欢我的战利品吗？蛮锤矮人曾愚蠢地进犯我们的村子。我从南边一路把它带到了祖阿曼！', '', 66384),
(293275, 'zhCN', '', '我们逃离辛特兰的时候，我带上了一些祖瓦沙的配方和遗物。不过这里能用的材料不太一样。', 66384),
(293273, 'zhCN', '小子，你真以为我会泄露他的计划吗？那他们可要念叨个没完了。', '', 66384),
(293272, 'zhCN', '这就是法奥的第三课。你们这些好管闲事的老头给我准备了什么？', '', 66384),
(293270, 'zhCN', '', '我们有幸能生活在哈籁恩达尔，并将它视作是一份责任。世界之树的根须在这片土地上蜿蜒曲折，我们必须照顾好根须，让它们能够继续欣荣。\n\n我是瑟伊娜，诺达希尔的主管护师。这是一份需要认真对待的庄严职责。', 66384),
(293267, 'zhCN', '', '我认得这根牙齿。这是沙德拉洛的沙德拉之牙！这下糟了，它怎么会在邪枝巨魔手里？它应该被藏起来了啊。', 66384),
(293266, 'zhCN', '', '这是本地蛙种身上的毒液？我靠这些样本能配出解毒剂，不过这根牙……', 66384),
(293265, 'zhCN', '', '我们来瞧一瞧……', 66384),
(293263, 'zhCN', '枯木部族在钻研医药和治疗药水的同时，也没落下对毒液和毒药的研究。', '', 66384),
(293259, 'zhCN', '', '替托尔巴尼报仇雪恨。', 66384),
(293258, 'zhCN', '哈尔拉兹派你来的？', '', 66384),
(293257, 'zhCN', '去找调和者亚曼伽谈谈。他通晓东部王国各地的毒液。', '', 66384),
(293246, 'zhCN', '她没有归来，但她留存的事物在寂静中绽放，留给了那些铭记不忘的人们。', '', 66384),
(293245, 'zhCN', '我们随着歌声发出呼唤。她没有应答，但她留下的事物做出了回应。这样就够了。', '', 66384),
(293242, 'zhCN', '他们追随的不是道路，而是感觉的回响。', '', 66384),
(293241, 'zhCN', '石头中回荡着她的歌声，但这个却有些不同。歌声在其中荡漾，盼望着分享它的曲调。', '', 66384),
(293239, 'zhCN', '枯木部族顽强地抵抗着邪枝巨魔和暮光之刃……但我们已经疲惫不堪了。', '', 66384),
(293238, 'zhCN', '探求者没有大声疾呼，祈求女神归来。他们留守在回忆依存的地方，默默聆听，静静等待。', '', 66384),
(293234, 'zhCN', '', '我们从村子出发，一直沿着道路走，就遭到了森林里的埋伏。我听到有个声音叫嚷着什么测试新的毒液。\n\n达基很快就被击中，连路都走不了。我就以最快的速度把他拖到了这里。', 66384),
(293233, 'zhCN', '最后一块盾牌的碎片，我好像认出它的主人了。', '', 66384),
(293232, 'zhCN', '他揣着到处走还真是奇怪。', '', 66384),
(293231, 'zhCN', '这就是我们在找的碎片之一，原本可能是一件盔甲或盾牌。', '', 66384),
(293219, 'zhCN', '', '池塘就在南边。祝你好运，$c。', 66384),
(293196, 'zhCN', '沙德拉-艾罗萨是我曾经知晓的一位远古神灵。她是毒蜘蛛女王。我知道她已经被赞达拉巨魔所害。\n\n沙德拉在祖阿曼的势力向来不大。有些阿曼尼巨魔曾前往南方寻找她，崇拜她。我不知道邪枝巨魔是否崇拜沙德拉，他们可能都不知道这是她的牙。\n\n可如果他们真的知道……那就很令人担忧了。他们可能想要阻止她的归来，甚至将她扭曲来给自己卖命。她的毒液在邪枝巨魔手中很是可怕。\n\n沙德拉的身躯虽然脆弱，但她的毒液万万不可低估。', '', 66384),
(293194, 'zhCN', '邪枝部族还在袭击我的山猫和枯木巨魔。', '', 66384),
(293192, 'zhCN', '如果你准备好了，现在可以安全返回村子了。', '', 66384),
(293190, 'zhCN', '我看毒液正在失效。我原本就在这里，我能看得见，能有感觉……却说不了话，还动不了！', '我看毒液正在失效。我原本就在这里，我能看得见，能有感觉……却说不了话，还动不了！', 66384),
(293137, 'zhCN', '', '夏安娜笑了起来。', 66384),
(293136, 'zhCN', '蛙毒不如蜘蛛毒液那么强劲，但也不算太差……', '', 66384),
(293135, 'zhCN', '毒液妖术师拉克西斯欢快地哼着小曲。', '', 66384),
(293124, 'zhCN', '', '敌人企图冲垮我们西部的防御——那里需要增援！', 66384),
(293121, 'zhCN', '', '敌人即将从北面袭来。准备作战，$p！', 66384),
(293116, 'zhCN', '', '敌人正在东方集结，快去那里构筑防线！', 66384),
(293107, 'zhCN', '', '我在河对岸的庄严谷等你。', 66384),
(293098, 'zhCN', '做好准备，$c。', '', 66384),
(293084, 'zhCN', '啊，$c。我想你正在为即将到来的战斗做准备吧？', '', 66384),
(293083, 'zhCN', '赶紧完成改装，不然我们都会闷死的！那边的空气比我奶奶的羊肉汤还要浓稠。', '', 66384),
(293075, 'zhCN', '这个“我们”，当然指的就是你。', '', 66384),
(293070, 'zhCN', '', '他出生后就一直在把姐姐当成耳旁风了。', 66384),
(293068, 'zhCN', '眼看就要成功了！那些顽皮的鱼儿确实开始接纳你了。', '', 66384),
(293067, 'zhCN', '这条鱼已经相当好了。但我们可以做得更好。', '', 66384),
(293066, 'zhCN', '如果我答应你，我的任务可以带你远离这地方呢？', '', 66384),
(293055, 'zhCN', '', '你弟弟有很多次违抗你的命令。我知道他是你的家人，可他不该承担后果吗？', 66384),
(293054, 'zhCN', '', '祖尔加拉长叹一声。', 66384),
(293036, 'zhCN', '库德兰已经去黑石塔的入口处了，$n。他发现了下一块碎片的去向。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(293035, 'zhCN', '黑暗部落把它们当作战利品陈列，可它们代表的只有失败。', '', 66384),
(293032, 'zhCN', '', '哈哈！谢谢，莉亚德琳。没有你，没有我的两位哈舒拉，我肯定做不到这些。', 66384),
(293030, 'zhCN', '', '态度？你不觉得我拿着斧子咄咄逼人地走上前去，纳洛拉克就会高看我一眼？', 66384),
(293029, 'zhCN', '如果你真明白我们行事方式的重要性，你就该严格照办。也许你还太年轻，太单纯了。\n\n不过没关系。我们的传统和仪式会将你塑造成命中注定的哈籁尼尔。\n\n既然我们已经接触了外人，这些传统就变得愈发关键。他们的思想——他们的理念——威胁着我们的生活方式。', '', 66384),
(293027, 'zhCN', '', '圣光对你另有安排，$n。我能感觉得到。', 66384),
(293026, 'zhCN', '我和其他圣光信徒一样赞美圣光，$n。\n\n不过我还会穿上厚重的盔甲，带上一些战争机器。', '', 66384),
(293023, 'zhCN', '你走的是一条不同的路。我们其他人将坚守旧道。虽然这不是传统的道路，但你所走的道路是通往我们未来的众多歧途之一。保重，愿女神在旅途中指引你。', '', 66384),
(293020, 'zhCN', '这回应该就是了吧？', '', 66384),
(293019, 'zhCN', '啊，又来一条！快瞧瞧。', '', 66384),
(293015, 'zhCN', '我以远行者、魔导师助手的身份为银月城效力了数十年，也曾是无数追寻者的导师。\n\n如今，作为教头，我的职责并非为他们指定道路，而是指引他们，走向那条能引发其灵魂共鸣的道路。每条路的要求都截然不同，而我在每条路上都略有涉猎，足以知晓该寻找何种特质。\n\n我并非在塑造英雄——我只是在帮他们认清自己早已拥有的力量。', '', 66384),
(293013, 'zhCN', '', '也许吧。但他应该也不想被自命不凡的“外来者”精灵正式接见。', 66384),
(293012, 'zhCN', '', '戴尼尔的做法也许看起来严苛，但他坚持传统自有他的道理。在仪式进行期间，你必须遵循我们族人的传统。我当初在奥威娜的仪式上也对她说过同样的话。', 66384),
(293011, 'zhCN', '我们总是被琐事分心，你的启蒙仪式才是优先要务。正是这些传统，让哈籁恩达尔得以在其他地区深陷冲突时仍能繁荣昌盛。', '', 66384),
(293010, 'zhCN', '', '你的动机是好的。现在，你还可以考虑一下态度。', 66384),
(293009, 'zhCN', '', '就剩下最后的仪式了，对吗？这样就能造就哈谢？我就能帮助族人了？', 66384),
(292997, 'zhCN', '滚开，你这长过头的卷心菜！', '', 66384),
(292996, 'zhCN', '', '我没拿斧子算你走运，畜牲！', 66384),
(292992, 'zhCN', '', '可在最黑暗的时刻，我满怀善念地向圣光祈愿，而圣光回应了我。', 66384),
(292991, 'zhCN', '我很享受占卜它的过程。替我行事，消灭他们。', '', 66384),
(292990, 'zhCN', '一次失误就会断送性命。让他们后悔暴露了自己的藏身处吧。', '', 66384),
(292989, 'zhCN', '他们近在咫尺了。你品尝到那份恐惧了吗？我尝到了，多么美味。', '', 66384),
(292987, 'zhCN', '我的魔法揭示了它的藏身之地。把那里染成红色。', '', 66384),
(292986, 'zhCN', '啊，逃窜的老鼠停下来喘气了。宰了它。', '', 66384),
(292985, 'zhCN', '', '我获得了圣光，却产生了理所当然的优越感。那是我犯下的错误。', 66384),
(292983, 'zhCN', '啊，启蒙者！你今天将迈出重大的一步。', '', 66384),
(292964, 'zhCN', '', '但精神之旅，只要认真对待，那不论成败都有其价值。', 66384),
(292963, 'zhCN', '欢迎你，$n。你的步伐中透着决意。今日前来所为何事？', '', 66384),
(292958, 'zhCN', '远行者们身姿如此优雅，穿梭林间，仿佛与自然浑然天成。\n\n他们和自然的联结，他们守护人民的方式，都令人叹为观止。\n\n我总是钦佩他们平衡力量与敏锐的手段，他们行动时悄无声息，却又万无一失。', '', 66384),
(292957, 'zhCN', '血骑士们勇猛、高傲，且在职责面前坚定不移。\n\n我钦佩他们不惜一切代价引导太阳之井之力保卫银月城的方式。\n\n他们的力量与荣耀激励着我，他们真正诠释了守护与奉献的意义。', '', 66384),
(292956, 'zhCN', '魔导师们真是太厉害了——他们精通奥术，御使魔法随心所欲，仿佛与生俱来一般。\n\n我总是钦佩他们的自律和才智——以及他们毫不犹豫掌控那股磅礴力量的姿态。\n\n若我能学到他们知识的皮毛，便已三生有幸。', '', 66384),
(292955, 'zhCN', '', '我……说不好。我不知道。', 66384),
(292951, 'zhCN', '', '远行者是奎尔萨拉斯的耳目与刀刃。我们匿踪潜行，迅猛出击，在危险临近前便已卫护了我们的人民。\n\n我们从不坐视战争兵临城下——我们在荒野中截击威胁，并于战火燃起前将其扑灭。这需要技巧、直觉，以及必要时孤身前行的意志。\n\n但若你有此决心，便再无他事能胜过身披绿金战袍的荣耀。', 66384),
(292942, 'zhCN', '血骑士是银月城的剑盾，受信条、力量与荣耀的约束。\n\n我们是天选的少数，挥舞太阳之井的威能，以不移的信念捍卫我们的人民。我们的道路充满戒律、牺牲，以及保护弱者那不容动摇的意志。\n\n若你渴望与我们同行，就须准备好面对源自内心与外界的种种挑战——只因血骑士的忠诚与力量，必将经受永恒的考验。', '', 66384),
(292941, 'zhCN', '', '你在加亚莱试炼中的表现令人很不安。你没事吧？', 66384),
(292940, 'zhCN', '', '我没事。我感觉卸下了一份负担，却又扛起了另外一份。', 66384),
(292938, 'zhCN', '魔导师是真正的奥术宗师与学者，肩负着指引银月城魔法命运的重托。\n\n我们引导魔法的流向，驾驭其浩瀚之力以庇护人民、拓展认知。我们不单是法术的施展者：我们还是远古秘辛的守护者，受信念与戒律束缚。\n\n踏上魔导师之路，便意味着此生将无尽地求索知识，并致力于掌控那股塑造世界的力量。', '', 66384),
(292934, 'zhCN', '', '他们正在绑架先锋军的军官，$n。这究竟只是野兽的饥渴本能，还是萨拉塔斯在搜集情报？', 66384),
(292922, 'zhCN', '', '先锋军制服的碎片……军官徽章……跟我猜的一样。', 66384),
(292921, 'zhCN', '', '我猜是阿拉托尔派你来帮我的吧？我这儿正缺人手呢。', 66384),
(292908, 'zhCN', '$n，借一步说话。我恳请你，别把我母亲牵扯到阿曼尼小径发生的事情里。', '', 66384),
(292907, 'zhCN', '', '我辜负了……族人……', 66384),
(292904, 'zhCN', '很久以前，阿曼尼帝国掌控着祖阿曼周边所有的土地。这个地方后来成为了你们口中的辛特兰和阿拉希高地。\n\n但当祖尔金战死、洛阿神灵不再回应我们时，我的族弟们远走辛特兰和阿拉希高地，希望能夺回那里的控制权，重回往昔的生活。我们虽同属枯木部族，但如今已相去甚远——他们甚至崇拜起了别的洛阿。\n\n有些辛特兰的亲戚不久前被赶出了那里。有些与阿拉希高地的好战同胞沆瀣一气，希望能继续追寻暴力。而追求和平的巨魔都回到了祖阿曼，回到了我们身边。', '', 66384),
(292901, 'zhCN', '憎怨斗坑是观看战斗的绝佳去处！', '', 66384),
(292850, 'zhCN', '', '我在外面守着，呃，应该叫放哨。你找到一堆天穹琉璃的时候就喊一声，我马上会跑过来的！', 66384),
(292834, 'zhCN', '先锋军的士兵满怀信心地冲出去，却又一个个被抬回了这里的医护所。', '', 66384),
(292830, 'zhCN', '$n，去向指挥官山脉之拳报到吧。如果你愿意加入战争机甲突击队，那将是我们的荣幸。', '', 66384),
(292824, 'zhCN', '', '我们需要花好几个星期采集迅叶龙之蕨……', 66384),
(292823, 'zhCN', '啊，可是护根者！', '', 66384),
(292822, 'zhCN', '', '跟我走，你们两个。这位旅行者得去收拾你们惹出的麻烦。我们也该好好谈谈什么叫尊重了。', 66384),
(292811, 'zhCN', '', '欢迎，$n。\n\n今日对你而言意义非凡——这是你的成年仪式，你将从此确立在我们社会中的位置，并随我们追随女神的圣意，共同守护我们的传统。', 66384),
(292810, 'zhCN', '呃哦……你、你好，护根者卡玛瑞。', '', 66384),
(292809, 'zhCN', '', '库利，等等！哦不，女神啊，她跑了。', 66384),
(292808, 'zhCN', '', '艾林莎兰真的存在！我会向你们所有人证明的！', 66384),
(292807, 'zhCN', '', '库利愤怒地抽泣着。泪水在她眼角闪烁。', 66384),
(292806, 'zhCN', '面对现实吧，库利！根本就没有什么艾林莎兰！', '', 66384),
(292805, 'zhCN', '', '才不要！像你这样的小不点不能玩天穹琉璃。而且，你居然以为它是什么飞龙掉下来的呢！', 66384),
(292804, 'zhCN', '', '求你们了！还给我！那些天之裂片是我的！', 66384),
(292793, 'zhCN', '我那更强奥术力量的秘诀？嘿，那就是洋葱兑香蕉汁！', '', 66384),
(292785, 'zhCN', '我收到了魔导师乌布里克的消息。通往虚影风暴的通道打开了！', '', 66384),
(292773, 'zhCN', '', '你来了。我想你不会害怕几只小鸟吧？不怕？太好了。', 66384),
(292771, 'zhCN', '', '$n，该由你来绘制自己的故事了。', 66384),
(292770, 'zhCN', '旋律？外来者？$n的心智被这些扰动污染了！', '', 66384),
(292769, 'zhCN', '', '我也听见了。', 66384),
(292768, 'zhCN', '', '女神！', 66384),
(292767, 'zhCN', '那是什么旋律？', '', 66384),
(292764, 'zhCN', '', '但你的启蒙仪式结束后，他们应该就安全了。', 66384),
(292763, 'zhCN', '', '我会去寻找外来者。', 66384),
(292759, 'zhCN', '你还不错嘛，$n。谢谢你帮助我兄弟。\n\n下次我也要一起玩！', '你还不错嘛，$n。谢谢你帮助我兄弟。\n\n下次我也要一起玩！', 66384),
(292758, 'zhCN', '你做了许多人都不会做的事。我这条命都是你给的。\n\n希望我们的道路以后还能交汇。', '', 66384),
(292757, 'zhCN', '你不仅帮助了恩里阿安，更重要的是，你帮我们处理了裂隙的难题。\n\n为此，我向你致以诚挚的谢意，$n。', '', 66384),
(292754, 'zhCN', '裂隙中的许多教训都是用命换来的。你现在是聪明点儿了。', '', 66384),
(292753, 'zhCN', '对不起，阿玛拉克。我的头脑不太清醒。', '', 66384),
(292752, 'zhCN', '恩里阿安刚完成仪式，现在还很虚弱。他应该多等一会儿。\n\n莫塔卡肯定会夺走他的性命。', '', 66384),
(292751, 'zhCN', '', '$n，追随幻象，追随内心，去寻找女神吧。', 66384),
(292750, 'zhCN', '', '传统也规定我们要追随女神的歌声，戴尼尔。', 66384),
(292749, 'zhCN', '不可以！传统规定我们都要留在哈籁恩达尔！', '', 66384),
(292748, 'zhCN', '', '外来者，歌声，今天在这里发生的一切……', 66384),
(292747, 'zhCN', '', '维持住林根之路，奥威娜。', 66384),
(292745, 'zhCN', '什么？', '', 66384),
(292743, 'zhCN', '那是你和艾林裂隙的联系。就让它为你指路。', '', 66384),
(292742, 'zhCN', '我准备好开始了。', '', 66384),
(292741, 'zhCN', '你找到举行仪式的地方了，恩里阿安。', '', 66384),
(292738, 'zhCN', '法奥！你和你的朋友到落锤镇来有何贵干？这个世界不会又要灭亡了吧？', '', 66384),
(292734, 'zhCN', '我们要让裂隙中的小型裂痕崩裂，以免它们增大。', '', 66384),
(292721, 'zhCN', '这就是我提到过的$p。', '', 66384),
(292711, 'zhCN', '我弟弟舒阿一不小心走进了艾林裂隙。我进入裂隙救了他，结果被打晕了。\n\n醒过来以后，舒阿已经不见了，但他很安全。我很走运，一位舒尔卡救了我，现在还成了我的导师。\n\n但我在裂隙中逗留了太久。我与艾林哈籁的联系很紧密，所以裂隙之歌早晚会把我逼疯，就算离开这里也逃不过那个命运。\n\n所以我必须斩断和女神的联系。\n\n等我再也听不见女神的歌声了，又该怎么和族人团聚？如何去见我的弟弟？所以我要成为一名舒尔卡，加入他们，在裂隙中守护哈籁恩达尔免受内部疯狂的侵袭。', '', 66384),
(292709, 'zhCN', '', '住口！都住口！还有你，外来者，跟我来。', 66384),
(292708, 'zhCN', '', '可那才是正确的做法。', 66384),
(292707, 'zhCN', '这次你要专心点，$n！', '', 66384),
(292704, 'zhCN', '你想来点什么？', '', 66384),
(292688, 'zhCN', '恩里阿安面色不佳，他需要帮助。\n\n请务必找到他，$n。', '恩里阿安面色不佳，他需要帮助。\n\n请务必找到他，$n。', 66384),
(292684, 'zhCN', '谢谢你帮我，$n。没有人比得上你！\n\n<压低声音，神秘兮兮地说。>\n\n别告诉别人我偷偷跑出来见恩里阿安的事。', '谢谢你帮我，$n。没有人比得上你！\n\n<压低声音，神秘兮兮地说。>\n\n别告诉别人我偷偷跑出来见恩里阿安的事。', 66384),
(292683, 'zhCN', '', '女神，请赐我们勇气，让我们能面对即将揭晓的秘密，接受不容忘却的真相。', 66384),
(292682, 'zhCN', '', '这地方，她的声音很响亮。又……很惊恐。一直都是这样吗？', 66384),
(292681, 'zhCN', '', '阿克瑟姆说我们必须放弃对女神的猜想，这是什么意思？真相到底有多么可怕，才不能让我们得知？', 66384),
(292679, 'zhCN', '', '我们要用水和精华先做好准备。完成之后我会在这里等你。', 66384),
(292678, 'zhCN', '要不是这位英雄，我就没命了。', '', 66384),
(292676, 'zhCN', '', '这位英雄救了我。', 66384),
(292674, 'zhCN', '$n！你本该直接过来，不该插手外来者的事。', '', 66384),
(292670, 'zhCN', '我还以为自己死定了。感谢你的搭救！', '', 66384),
(292669, 'zhCN', '', '谢谢你，陌生人。我欠你一条命。', 66384),
(292666, 'zhCN', '到追忆之穴来，完成你的启蒙仪式。', '', 66384),
(292663, 'zhCN', '你应该关心的是传统仪式，不是什么鲁莽的冒险！', '', 66384),
(292657, 'zhCN', '', '戴尼尔从来就没喜欢过我，甚至在我与外界接触之前便是如此。\n\n至少，他以前还会把这种厌恶藏在心里。他并非唯一对我心存芥蒂之人。\n\n不过我要告诉你——假如我能回到过去，让我选择是否要与外来者接触，我依然会做出同样的选择。外来者能教会我们许多宝贵的知识。\n\n嘘，此时此地不宜谈论这些想法。', 66384),
(292656, 'zhCN', '', '你也要参加这个仪式吗？真是太好了！\n\n我还记得我经历的时候，在结束时，戴尼尔和哈加尔都予以了我祝福。我本来受到传统的束缚，但后来听到了召唤，我的内心被撕裂了，多次止步不前，但那种召唤逐渐加强，就像来自我灵魂的最深处。\n\n不用为我的选择担心，你应该把今天当作新旅程的开端，加以庆祝。', 66384),
(292655, 'zhCN', '外来者不该来到这里，更不能是今天。', '', 66384),
(292654, 'zhCN', '', '他们不明白哈籁恩达尔有多危险。我们必须找到他们。', 66384),
(292646, 'zhCN', '', '这是外来者的战装。他们没了装备毫无还手之力，甚至敌不过小型猛兽。这下糟了。', 66384),
(292645, 'zhCN', '', '你为何而来？你听见了……？唔。', 66384),
(292644, 'zhCN', '你感到胸口发闷，脑海深处隐约传来一首歌。', '你感到胸口发闷，脑海深处隐约传来一首歌。', 66384),
(292643, 'zhCN', '', '追随召唤，追随内心。', 66384),
(292642, 'zhCN', '培育根系需要时间和专注，这是传统能够保持安全稳定的两大基石。', '', 66384),
(292638, 'zhCN', '', '风暴让我的卡尔高戈桀骜难驯。我的小宝贝，这才是你的本性吗？一头浑然未开的野兽？\n\n坦白说，我本对你另眼相看。', 66384),
(292626, 'zhCN', '到治愈祭坛前，找到破碎的法杖，你就能有所了解。', '', 66384),
(292622, 'zhCN', '', 'Lok-tar，朋友。谢谢你。', 66384),
(292621, 'zhCN', '后会有期。', '', 66384),
(292620, 'zhCN', '', '对，旅途，是时候送你们回家了。', 66384),
(292613, 'zhCN', '', '你被女神标记了，$n。该是你踏上旅程的时候了。', 66384),
(292611, 'zhCN', '', '不，我其实不太想。你也不需要再向我证明什么了，除非你打算做些傻事。', 66384),
(292608, 'zhCN', '', '赛伊拉叹了一口气。', 66384),
(292607, 'zhCN', '', '只要女神召唤，我就会前去。', 66384),
(292606, 'zhCN', '', '到了某个时候，奥威娜，你就不能再下来了。', 66384),
(292604, 'zhCN', '你必须准备好改变对女神的认知。真相一旦得知，就再也无法忘却。接下来就回不了头了。', '', 66384),
(292603, 'zhCN', '', '我们怎么才能让心灵做好准备？', 66384),
(292602, 'zhCN', '时候到了。你对我们历史的热忱追求和战斗能力不容置疑。你已经准备好得知摇篮最深刻的真相了。', '', 66384),
(292597, 'zhCN', '', '你的仪式快要结束了，$n。你看到了什么？传承之石向你展示了什么？', 66384),
(292588, 'zhCN', '', '树木参天，并非只有根系。天地广阔，不局限于哈籁恩达尔。', 66384),
(292579, 'zhCN', '你是“神灵代言人”，对吧？那就去给它进言啊！让库尔吉给我们发挥作用！你立过誓的！', '', 66384),
(292578, 'zhCN', '妖术领主的法杖？可任何使用法杖的家伙……都是黑暗……', '', 66384),
(292577, 'zhCN', '随便你怎么说。我不需要你了，我自己能想办法！', '', 66384),
(292576, 'zhCN', '你应该使用它的，西吉塔！背信弃义的叛徒！', '', 66384),
(292575, 'zhCN', '不！快治愈我，你这一无是处的神灵。你应该为阿曼尼效命。', '', 66384),
(292574, 'zhCN', '把你留在这里的不是我。你是否愿意前行，只取决于你自己的选择。', '', 66384),
(292573, 'zhCN', '却依然是血肉之躯，无法享有永恒的生命。你必须理解这个道理。', '', 66384),
(292572, 'zhCN', '我乃是督军，我父亲也是督军，我们都是神圣的战士……', '', 66384),
(292570, 'zhCN', '明白了。妖术领主的法杖是为了伤害神灵而诞生的。我破坏了它……使黑暗魔法反噬了我们。我其实无意伤害任何人的。', '', 66384),
(292569, 'zhCN', '我怎么可能已经死了？这是诡计。你弄错了！', '', 66384),
(292568, 'zhCN', '你明白这根法杖的意义了吗，西吉塔？', '', 66384),
(292567, 'zhCN', '有些时候，我也无计可施，谁都无计可施。', '', 66384),
(292566, 'zhCN', '我的药品并非无尽，生命也终有尽头。', '', 66384),
(292565, 'zhCN', '那我呢？快放了我！', '', 66384),
(292562, 'zhCN', '我不得不在誓言之间做出选择。阿库图死期已到，但让他接受命运并不是我的责任。', '', 66384),
(292561, 'zhCN', '永别了，阿库图。我把法杖……还有愧疚……都送进了烈火。', '', 66384),
(292557, 'zhCN', '西吉塔想走的时候就可以走。其他人也一样。', '', 66384),
(292554, 'zhCN', '', '我们背靠背，心连心。为了艾泽拉斯！', 66384),
(292553, 'zhCN', '我们团结一致！为了奎尔萨拉斯！为了艾泽拉斯！', '', 66384),
(292552, 'zhCN', '', '我与你并肩作战！', 66384),
(292550, 'zhCN', '这是真正的你吗，$n？去探寻你的本真。', '这是真正的你吗，$n？去探寻你的本真。', 66384),
(292547, 'zhCN', '暮光之刃在永歌森林的渗透到底有多深？', '', 66384),
(292528, 'zhCN', '<你心中响起一曲无声之歌。虽难以辨清歌词，但你从内心深处感受到一种召唤。某种事物在牵引着你，渴望与你交流。>', '', 66384),
(292504, 'zhCN', '', '外来者……还挺激烈。法杖给你，你证明自己的力量了。', 66384),
(292503, 'zhCN', '', '接受挑战！', 66384),
(292501, 'zhCN', '', '阿克瑟姆觉得你有资格获得知识。虽然说知识就是力量，但你的力量足够掌控它吗？', 66384),
(292500, 'zhCN', '', '来，让我们看看阿克瑟姆挑学生的眼光如何。', 66384),
(292499, 'zhCN', '', '哈籁恩达尔是个危险的地方，每个瀑布底下都有秘密。当然，你得胆大才敢去看。', 66384),
(292498, 'zhCN', '<你没有发现有趣的事物，这简直就是一场疯狂的哈籁尼尔追逐游戏。>', '<你没有发现有趣的事物，这简直就是一场疯狂的哈籁尼尔追逐游戏。>', 66384),
(292497, 'zhCN', '<你发现了破碎的木块，但都没什么特别的。法杖不在这里。>', '<你发现了破碎的木块，但都没什么特别的。法杖不在这里。>', 66384),
(292496, 'zhCN', '<你发现的小型物品失窃的证据，但没有发现完好的物品。>', '<你发现的小型物品失窃的证据，但没有发现完好的物品。>', 66384),
(292494, 'zhCN', '我们的要求得罪了库尔吉，督军。他说，你已经死了……', '', 66384),
(292493, 'zhCN', '那个神灵必须照我说的做。来，拿上这根妖术领主的法杖。我们要夺取库尔吉的力量，成就祖尔金的荣耀！', '', 66384),
(292485, 'zhCN', '他们为自己降下了诅咒。\n\n自取祸患可能比人们想象得更为容易。', '', 66384),
(292481, 'zhCN', '在内心深处，他们其实知道真相。可是否愿意面对……那是他们自己背负的考验。', '', 66384),
(292479, 'zhCN', '我是库尔吉。埃基尔松已在风中传达了你的名字，$n。\n\n我很荣幸能与你相识。\n\n这座神龛前的情况不是你的责任，而是他们自己选择的命运。他们不愿承认事实。他们遗忘了自己的死亡……以及导致了死亡的背叛。\n\n如果你愿意代表他们出手干预，那我也准许你。', '', 66384),
(292476, 'zhCN', '我们可以谈谈。', '', 66384),
(292475, 'zhCN', '你是洛阿神灵的朋友。', '', 66384),
(292464, 'zhCN', '我需要答案。库尔吉本尊能给我答案吗？', '', 66384),
(292456, 'zhCN', '', '住手！我认输！我早就不相信十字军了，我也不想为他们献出生命。', 66384),
(292444, 'zhCN', '', '我当时正在灰谷边缘巡逻，一道刺眼的绿色闪光让我几近目盲。醒来时就在这里了。\n\n我在和那头野兽搏斗时丢了斧头。现在我欠你一条命。', 66384),
(292442, 'zhCN', '我正在艾尔文森林的一棵大树附近执行例行巡逻任务。突然出现了一道绿色闪光，接下来我就来到这里了。\n\n这个地方的自然环境既残酷又无情。', '', 66384),
(292430, 'zhCN', '祖尔加拉会为族人做出最好的选择。\n\n但洛阿神灵呢？嗯。也许我们都能从中学到什么。', '', 66384),
(292424, 'zhCN', '哦，我的宝贝，这可不行。让我们重来一遍。', '', 66384),
(292421, 'zhCN', '太精彩了！看看你们带来了什么！', '', 66384),
(292420, 'zhCN', '阿拉托尔，圣光虽然能强化它的信徒，但这股力量的道德与准则来自我们的内心。', '', 66384),
(292417, 'zhCN', '', '在你忙着的时候，我从此地生长的药用植物处收集了一些叶片。我最后一次见到鲁加尔的时候，他给我展示过叶片的样子。\n\n它们制成的药膏可以涂抹在伤口处，好像可以加快愈合的速度。', 66384),
(292413, 'zhCN', '我已经期待着你回来的时候了。', '', 66384),
(292412, 'zhCN', '卡莉，我亲爱的姐妹。能找到这样乐于助人的旅行者是不是非常幸运？', '', 66384),
(292411, 'zhCN', '', '是的，瓦德。', 66384),
(292410, 'zhCN', '朋友！你帮了我们一个大忙。索莱尔的家名将因此沐浴荣光。', '', 66384),
(292406, 'zhCN', '感谢你救了我，$G兄弟:姐妹;。我欠你一条命，或者至少欠你个拥抱，哈。\n\n图尔阿玛一直在研究送我们回家的方法。请原谅她对你的戒备，我们曾与背叛军团的堕落者结盟，但也付出了惨痛的代价。\n\n<朱拉斯紧握着他的纳鲁吊坠，深深叹息。>\n\n被遗弃的滋味，我们同样体会至深。', '', 66384),
(292405, 'zhCN', '', '我听说过我们光铸同胞的故事，但直到现在才亲眼见到。能在这种地方见到你真是个奇迹，$G兄弟:姐妹;。\n\n我是图尔阿玛。我的职责是守护我的族人——虚空来客，并护送他们回家。', 66384),
(292400, 'zhCN', '圣光之愿危在旦夕，整个世界都危在旦夕，我需要专心作战。', '', 66384),
(292399, 'zhCN', '可这就是掌握圣光的意义吗？一场对抗邪恶的永恒之战？', '', 66384),
(292398, 'zhCN', '我不该让我的疑虑成为保护这里的绊脚石。', '', 66384),
(292397, 'zhCN', '我担心一直留在这里对抗天灾的话，我就会变得和父……我会被怒火和愤懑掌控。', '', 66384),
(292396, 'zhCN', '我已向黑锋骑士团求援，但也需要你的帮助来击退最新一轮的攻势。', '', 66384),
(292395, 'zhCN', '被召唤到太阳之井的防御者太多了，天灾军团几乎就要闯入礼拜堂了。', '', 66384),
(292394, 'zhCN', '泰罗索斯男爵，我不知道情况居然会如此严峻。我们能做什么吗？', '', 66384),
(292392, 'zhCN', '', '$n，不必畏惧生死试炼。\n\n一切皆是循环。万物终将在不灭之焰中涅槃。', 66384),
(292391, 'zhCN', '她苏醒了。是她。\n\n新生的加亚莱是只母鸡！咯咯咯！\n\n这是吉兆。治愈的征象。洛阿重归平衡的预兆。', '', 66384),
(292390, 'zhCN', '影卫营', '影卫营', 66384),
(292389, 'zhCN', '', '感激不尽，加亚莱。你的试炼让我对自己有了全新的认识，我也期待着在未来的考验中能学到更多。', 66384),
(292310, 'zhCN', '看啊！那是最后的试炼。面对面，去直面你自己！', '', 66384),
(292309, 'zhCN', '', '不，接受帮助让我们变得更强大。我绝不会让自己的傲慢害了我的族人。', 66384),
(292308, 'zhCN', '', '祖尔加拉发出震天动地的战吼。', 66384),
(292259, 'zhCN', '我就是喜欢看他们惊慌失措的样子。', '', 66384),
(292257, 'zhCN', '落锤镇还有许多民众等待救助，$p。\n\n你伸出援手帮助需要的人，这正体现了对安瑟的敬意。', '', 66384),
(292241, 'zhCN', '啊！我……毫无感觉。西吉塔的话又一次落空了。', '', 66384),
(292240, 'zhCN', '库尔吉！我献上你的这部分肉身，愿你治愈我的病痛，让我远离死亡。我要求得到你治愈的力量！', '', 66384),
(292208, 'zhCN', '把肝脏拿给我，我什么都得试试。', '', 66384),
(292206, 'zhCN', '好痛苦，真痛苦！\n\n没完没了的痛苦。\n\n快让它……停下。', '', 66384),
(292203, 'zhCN', '好好享受吧。', '', 66384),
(292202, 'zhCN', '我心爱的小玩物们都躲到哪里去了……', '', 66384),
(292196, 'zhCN', '', '堕落者。你把朱拉斯送回给我们，说明你已经唾弃了萨格拉斯的军团。\n\n很好。在这样的地方见到你真是个奇迹，$G兄弟:姐妹;。\n\n我是图尔阿玛。我的职责是守护我的族人——虚空来客，并护送他们回家。', 66384),
(292184, 'zhCN', '放他们进来！我正等着收货呢。快点！', '', 66384),
(292180, 'zhCN', '正如我一直坚信的那样，祖尔加拉已经成长为哈谢了。', '', 66384),
(292176, 'zhCN', '', '我现在只想要……这些杀戮同族的叛徒……付出代价！', 66384),
(292175, 'zhCN', '如果这些饰品唤起的记忆足以对抗虚空的影响，那就还有希望！我们只是需要时间。', '', 66384),
(292174, 'zhCN', '', '黑暗涌过我的身体……如同一股洪流……所过之处荡然无存……', 66384),
(292172, 'zhCN', '<这名圣骑士被残忍地献祭给了不知名的虚空力量。她无神的双眼直瞪着天空。>', '<这名圣骑士被残忍地献祭给了不知名的虚空力量。她无神的双眼直瞪着天空。>', 66384),
(292170, 'zhCN', '', '只有我能开启这条路。也只有我能确保无人跟随他们穿过。', 66384),
(292169, 'zhCN', '', '只有我能开启这条路。也只有我能确保无人跟随他们穿过。', 66384),
(292168, 'zhCN', '心中燃火——炭中生焰。\n\n驱散疑虑——净化心灵！', '', 66384),
(292166, 'zhCN', '', '谜团弯弯曲曲。\n\n但至少圣光……不会兜圈子。', 66384),
(292165, 'zhCN', '', '必须开启。也必须关闭。只有我能。', 66384),
(292164, 'zhCN', '你没有听到那些心跳声吗？', '', 66384),
(292163, 'zhCN', '', '走吧，新朋友！我们要去收集天穹琉璃了！', 66384),
(292160, 'zhCN', '画布上的每一笔都是来自过去的轻声细语——是等待重新诉说的记忆碎片。这些遗物虽然寂静无声、静止不动，却承载着被时间洪流掩埋的真相。\n\n当它们的回响被唤醒时，会有怎样的故事苏醒呢？\n\n来吧，让你的好奇心成为解开失落秘密的钥匙。', '', 66384),
(292159, 'zhCN', '这些墙壁里隐藏的真相，只向那些准备好承受的人显现。', '', 66384),
(292158, 'zhCN', '这里的画作反映着我们过去的阴影，虽然微弱但依然延续存在。\n\n总有一天，你也许能为它们增添光彩。', '', 66384),
(292157, 'zhCN', '我们周围的这些遗物正在沉睡，等待着能理解其深意的人来唤醒。\n\n总有一天，你也许会成为唤醒其故事的人之一。', '', 66384),
(292152, 'zhCN', '', '<图尔阿玛迎上朱拉斯的目光，眼中交织着内疚与决心。>', 66384),
(292147, 'zhCN', '我会把沃拉安带到安全的地方。在前面与我们会合。', '', 66384),
(292146, 'zhCN', '', '琪法安？是你吗？', 66384),
(292145, 'zhCN', '这边，$n！', '', 66384),
(292136, 'zhCN', '', '哇哦……对一个芦塔尼来说，你长得挺奇怪的。你的花朵和装饰品都哪儿去了？', 66384),
(292101, 'zhCN', '没错，那是几年前的事了。但天灾已不再构成威胁，有人“建议”我退休。\n\n是强烈建议。\n\n适应新生活……一直很难。', '', 66384),
(292099, 'zhCN', '看起来塔奎林这些日子确实更加宁静了。希望能一直保持下去。', '', 66384),
(292080, 'zhCN', '如果沃拉安在影卫营，或许还来得及。去那里与我会合！', '', 66384),
(292072, 'zhCN', '', '我真不敢相信加库尔留了一块幻象石给我！这里头存放着怎样的回忆呢？\n\n我们要赶紧动身，否则芦塔尼很快就会发现我们的。', 66384),
(292066, 'zhCN', '', '暮光之刃造成的混乱如此严重，连纳拉丁都被迫逃离领地。阿曼尼在人数上完全没有优势可言。\n\n我希望祖尔加拉真如她表现出来的那般强大。', 66384),
(292065, 'zhCN', '多亏了我们的光木武器，莫尔杜恩被打跑了。我们应该乘胜追击。', '', 66384),
(292064, 'zhCN', '我们等待酋长祖尔加拉的决断。', '', 66384),
(292063, 'zhCN', '这次会议本可以进行得更顺利。\n\n至于洛阿神灵的事……那个精灵最好别插手我们的内政。', '', 66384),
(292062, 'zhCN', '我们没剩多少人了。我们暗松部族谋定而后动。\n\n我们会聆听火焰。如果战斗的时刻来临，我们必将出击。', '', 66384),
(292061, 'zhCN', '', '阿曼尼部族对枯木部族要求过高，而我们正承受邪枝部族的重压。', 66384),
(292060, 'zhCN', '', '我是恶齿的勇士，但利拉祖代表整个部族。', 66384),
(292059, 'zhCN', '', '我代表恶齿部族发言！', 66384),
(292058, 'zhCN', '', '让我们尽一切努力抵抗暮光之刃。\n\n我们和阿曼尼有共同的敌人。腹背受敌对我们没有好处。', 66384),
(292057, 'zhCN', '沃拉安还活着……但她的精神足以抵御虚空吗？', '', 66384),
(292055, 'zhCN', '', '我们可以坐车了！', 66384),
(292040, 'zhCN', '', '弩炮是个不错的诱饵，但我的斧子要是能劈上莫尔杜恩的脑门，他可就没法装看不见了。\n\n我们开始吧。我的人民早就等不及了。', 66384),
(292039, 'zhCN', '你将见证我们光木火炮的神威！', '', 66384),
(292038, 'zhCN', '', '祖尔加拉打算与莫尔杜恩正面交锋。我要与她同行。此战只许胜，不许败。\n\n准备好就开火。愿你箭无虚发。', 66384),
(292037, 'zhCN', '他们很安全。我把他们藏在附近了，避开了战场的视线。\n\n一有机会，我就带他们离开这里。', '', 66384),
(292035, 'zhCN', '你，沃拉安……沉歌……你和其他人会成为众多此类存在中的先驱。', '', 66384),
(292034, 'zhCN', '看看你的四周。这些虚空精灵已经建立起了一个能与虚空共存的社会。', '', 66384),
(292033, 'zhCN', '如果你能够抵抗，那么或许还有其他人也能。更多迷失的姐妹们……父亲们……', '', 66384),
(292032, 'zhCN', '', '加库尔是我的良师，也是我的益友。我不会坐视那些芦塔尼偷窃他的东西！', 66384),
(292031, 'zhCN', '', '但即便此刻，黑暗仍潜藏在我们之中。我们不能留下。', 66384),
(292030, 'zhCN', '我们的弩箭足够朝莫尔杜恩的护盾射击几轮。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(292028, 'zhCN', '', '琪法安……关于你的记忆……关于家园的记忆……唤醒了我们。', 66384),
(292027, 'zhCN', '', '绘漆已经准备好了，但它们能保持形状吗？拿起画笔，把它们涂在画布上。在回响大锅开始搅动之前，我们必须确认颜料能够正常流动。', 66384),
(292024, 'zhCN', '', '接受我的力量，让它在你手中流淌！召唤颜料，控制它，把它送回回响大锅，这样我就能用手印封印束缚住它。', 66384),
(292023, 'zhCN', '', '不，不，不！不该这样流动！颜料想要逃跑！快踩住！别让它们逃掉，否则它们会把故事一起带走的！', 66384),
(292022, 'zhCN', '哈籁尼尔的记忆逐渐消退时，她找到了将回忆束缚在世间的方法。空有色彩无法传承历史——她还需要别的。', '', 66384),
(292015, 'zhCN', '多美的风景啊，不是吗？', '', 66384),
(292012, 'zhCN', '我在银月城为治安官效力多年，但一直更钟爱这片土地。\n\n我爱上了这个小镇。爱它的宁静，爱它远离城里那些窥探的目光。\n\n虚影风暴威胁着我们所有人，银月城却迟迟不肯施以援手。这让我深感不安。\n\n这里的人民，需要一个能给他们应得之物的人。', '', 66384),
(292007, 'zhCN', '那都不算是个回答。唔。', '', 66384),
(292003, 'zhCN', '', '这算不上什么胜利，我们不过是用鲜血给平民换来了一条生路。', 66384),
(291996, 'zhCN', '', '在主宰者之座与我会合，异界人。多曼纳尔那里有我们需要的东西。', 66384),
(291993, 'zhCN', '', '托伦多，守住这里，等祖尔加一开火，你就趁乱带幸存者撤退。', 66384),
(291986, 'zhCN', '', '没时间管祖尔加了，现在必须集中精力在纳洛拉克身上。走吧。', 66384),
(291980, 'zhCN', '牺牲？他们是英雄。他们是为了夺回阿塔阿曼的光木，像真正的阿曼尼一样倒下的英雄。', '', 66384),
(291972, 'zhCN', '等我把这里的孩子们安顿好，就去帮祖尔加准备弩炮。', '', 66384),
(291970, 'zhCN', '我们必须护卫族中德高望重的长者！\n\n他们传承着部族的智慧，铭记着我们昔日的荣光！', '', 66384),
(291968, 'zhCN', '', '多年前，玛拉卡斯就是在这里毙命的。当时他的勇士试图利用阿曼尼的洛阿同时对抗联盟和部落。\n\n那次惨败后，针对永歌森林的袭击变得迟缓，后来完全平息了。我想知道从那以后阿曼尼都在谋划什么。', 66384),
(291967, 'zhCN', '$n！我们在啸影山脊汇合。', '', 66384),
(291966, 'zhCN', '我们相识多年，不过交往并不深入。他肯定听说过我们重返永歌森林的消息。\n\n安忒诺里安对塔奎林保护心切，对虚影风暴的威胁深感忧虑。他之所以主动联系我，大概是认为我在这里的实验设施能发挥更大作用，我的研究确实有其价值。\n\n他明白我们越早解决这个问题，他的民众就越安全。我完全理解他的立场，也感激他的支持。', '', 66384),
(291960, 'zhCN', '', '保持警惕，$c。\n\n这片沼泽里住满了鱼人。\n\n他们已经抢走了我们的货，还夺走了托尔巴尼的命。\n\n准备好你的武器。', 66384),
(291958, 'zhCN', '卡茜雅曾是我的学生，但我们抵达永歌森林后不久她便失踪了。我当时以为，她因为我们仍被孤立排斥而心生不满，或许已经返回泰洛古斯了。\n\n她如此聪慧，对研究又那般专注……从这本笔记残页来看，她似乎终于找到了突破口。\n\n<乌布里克满脸痛苦。>\n\n真希望我能亲眼见证她的成就。', '', 66384),
(291954, 'zhCN', '阿曼尼必须采取大胆的行动。光木值得我们去冒险和牺牲。\n\n当你感觉到暮光之刃在光木长矛的尖端扭曲时，你就会看到光。哈！\n\n这理应属于我们，我们会比任何精灵用得都好。', '', 66384),
(291948, 'zhCN', '', '阿克瑟姆就指望你了。搜索那只大匪鸟的巢穴，寻找所有可能指明法杖去向的线索。', 66384),
(291937, 'zhCN', '你竟敢跟我说话？我该割了你的舌头才对。', '', 66384),
(291936, 'zhCN', '', '你正漫步于危机之地。', 66384),
(291935, 'zhCN', '看好你的脚下，看清楚了再踏。', '', 66384),
(291921, 'zhCN', '如果它一去不返，哈籁尼尔的历史将会蒙受重大损失。', '', 66384),
(291920, 'zhCN', '根源法杖的每一任主人都为它织入了新的生命。这活生生的记录是所有先人的传承。', '', 66384),
(291919, 'zhCN', '', '萨兰蒂亚，等等！', 66384),
(291918, 'zhCN', '', '拂晓之心可能没有多少时间了！我们快走！', 66384),
(291917, 'zhCN', '当世界充斥着混乱之时，唯有家族纽带能带来慰藉。\n\n我无法原谅影卫虚灵犯下的恐怖罪行，但我选择铭记我的姐妹沃拉安。', '', 66384),
(291916, 'zhCN', '', '准备好了。而且我知道，我不必独自前行。', 66384),
(291915, 'zhCN', '你准备好接受仪式，了解不容忘却的回忆了吗？', '', 66384),
(291914, 'zhCN', '你要保护的不只是哈籁尼尔，还有所有与女神同在的生灵，所有艾林哈籁的孩子，这世上所有的人。', '', 66384),
(291913, 'zhCN', '要想追随这条道路，探明女神的想法，你就必须变得强大。强大的目的是为了保护，而不是牺牲。', '', 66384),
(291912, 'zhCN', '', '其他人追随我，是因为他们和我一样坚信，我们能找到女神并拯救她。我该怎么做呢，阿克瑟姆？', 66384),
(291911, 'zhCN', '牺牲自我，实属崇高。牺牲他人，则是疯狂。你依然愿意踏上这条路吗？', '', 66384),
(291910, 'zhCN', '', '我……我……', 66384),
(291909, 'zhCN', '你不害怕要做出必要的牺牲吗，奥威娜？就算要牺牲自己也毫不害怕吗？可如果要你牺牲别人呢？', '', 66384),
(291908, 'zhCN', '', '不管女神有什么要求，我都愿意照做。我不会害怕。', 66384),
(291907, 'zhCN', '我必须继续调查光绽的情况，就算要前往你的故乡也未尝不可。', '', 66384),
(291900, 'zhCN', '是山猫之神指引我们来到这里，还庇护了我们。姐姐，他已经选我做他的代言人了。', '', 66384),
(291898, 'zhCN', '嘿。\n\n加亚莱正在等候你们所有人，$p。你们准备好见面了吗？', '', 66384),
(291897, 'zhCN', '朱拉斯满怀希望地注视着渐趋稳定的传送门。', '', 66384),
(291896, 'zhCN', '', '一座哈谢神殿，和我们在埃基尔松神庙附近点燃的那些很像。', 66384),
(291895, 'zhCN', '她的理论是对的。起效了！', '', 66384),
(291894, 'zhCN', '你听说过警卫吗？警卫最初是为了满足阿古斯启迪者的虚荣野心而打造的。但在我们的伟大逃亡中，它们成为了保护我们死去同胞免受恶魔侵扰的重要工具。\n\n警卫承载着我们死去同胞的灵魂，让他们得以继续与敌人战斗。我想这个警卫的战斗岁月已至尽头。但它仍在继续充当数十个德莱尼灵魂的容器。\n\n这并非理想的安排。如此多的灵魂被紧密地挤压在一起，会使他们陷入混乱。但我打算将他们安全送回我们的家园，将他们能安葬在我们的大陵墓中。', '', 66384),
(291870, 'zhCN', '', '要是我把心里话说出来，你是不是又要开始说教了？教我怎么放下埃基尔松那些话带来的，那股烧心的愤怒和刺骨的羞愧？', 66384),
(291868, 'zhCN', '', '祖尔加拉，你看起来……心事重重的样子，埃基尔松赐予了我们祝福，这难道不是件好事吗？', 66384),
(291858, 'zhCN', '', '愤怒是一种很强大的情绪。我的同胞也曾一度被愤怒吞噬。', 66384),
(291856, 'zhCN', '', '叔叔，以前我最爱听您讲这些故事了。可就算在当时，我也在怀疑它们是不是真的。', 66384),
(291855, 'zhCN', '关于去埃基尔松神庙的事，你还记得多少？', '', 66384),
(291854, 'zhCN', '我一直努力想让你们俩——你和祖尔加——都能爱戴洛阿之神。', '', 66384),
(291853, 'zhCN', '', '我还记得埃基尔松、哈尔拉兹、加亚莱和纳洛拉克的故事，记得他们是如何守护我们的。', 66384),
(291852, 'zhCN', '', '我们爬上了神庙，祖尔加却跌了下去。我没能得到神灵的祝福，我的母亲也死了。', 66384),
(291850, 'zhCN', '埃基尔松任命我为她的代言人，这是她赐予我的无上荣耀。', '', 66384),
(291847, 'zhCN', '', '在与阿曼尼多年的交战中，我对他们的文化略知一二。\n\n多数人并不知晓，“阿曼尼帝国”实则由数个不同部族组成，只是以建立时最强大的部族命名罢了。\n\n每个部族一直供奉着自己的洛阿，遵循着自己的习俗。但眼下看来，他们的“帝国”比以往任何时候都要分崩离析。\n\n我觉得这没什么好惊讶的。我只是怀疑祖尔加拉是否真能团结他们。', 66384),
(291844, 'zhCN', '<温柔的帕希用天真而困惑的眼神看着你。\n\n血液不够所有德莱尼使用。也许不是每个人都需要经过鲜血浸润？>', '', 66384),
(291843, 'zhCN', '……朋友……？', '', 66384),
(291814, 'zhCN', '', '等等，祖尔加拉！你不要命了吗？', 66384),
(291806, 'zhCN', '', '想得到我的眷顾，就必须敢于攀登绝顶，而不畏惧跌落深渊。', 66384),
(291799, 'zhCN', '', '瓦德是我那个蠢得可笑的哥哥，晚点我会想个更客气的说法的。', 66384),
(291798, 'zhCN', '你好，我勇敢的朋友！今天我们能为你提供什么服务？', '', 66384),
(291797, 'zhCN', '继续探究哈籁尼尔和我们的历史吧。我倒想看看你，还有其他人，是否有资格见证这些回忆。', '', 66384),
(291796, 'zhCN', '女神与我分享了自己的回忆，而我只会将它们分享给理解其重要性的人。', '', 66384),
(291795, 'zhCN', '我是阿克瑟姆，我聆听着摇篮的声音。我承载着大部分哈籁尼尔都不知晓的智慧。', '', 66384),
(291790, 'zhCN', '', '唉，麻烦了。\n\n纳鲁……信不过。他们看着是好的……但会要了你的命。我还不想死。\n\n所以，信不过。', 66384),
(291789, 'zhCN', '', '纳沙波尔。好地方。很多……盐？红色的盐。紫色的水。大野兽，很多，聪明。兄弟姐妹小的时候，打猎。\n\n有时，不安全。但我们建造。和悔过的堕落者交朋友。只有几个。建造家园，我们的。', 66384),
(291788, 'zhCN', '', '……泰拉？我知道。纳鲁。是的。\n\n来自我们。和我们一起。但不是朋友。想让我们离开家园，去后面。是，额……\n\n<图尔阿玛想解释的概念似乎很复杂。她沮丧地呼出一口气，放弃了。>\n\n你懂吗？', 66384),
(291787, 'zhCN', '', '哼。<图尔阿玛轻蔑地挥了挥手。>\n\n圣光的走狗。他们打他们的。不帮我们。我也不帮。', 66384),
(291786, 'zhCN', '', '留在这。帮帮兄弟姐妹。你帮忙。帮你。\n\n<图尔阿玛罕见地对你露出微笑。>\n\n然后，回家。', 66384),
(291785, 'zhCN', '', '我的人民是虚空使者。我属于他们，属于我们最安全的家园。\n\n然而，我还是想能亲眼看看维伦，让他知道我们还好好地站着。想和可能从中受益的同胞分享我在无垠黑暗中的发现。想见识见识在我们分开的几千年里，其他奥术师和虚空法师的魔法进步到了什么地步。\n\n只要是为了守护我的人民，我可以回去。虽然不会太久，但……可以。', 66384),
(291784, 'zhCN', '', '哼。不管她犯了什么罪，都不该是那个下场。他们在试图帮忙，纳鲁，用他们自己的方式。这点我当然看得出来。\n\n尽管如此。当初是我的直觉让我拒绝了阿克蒙德和基尔加丹，这让我的同僚们大吃一惊。现在，我的直觉对纳鲁也发出了同样的警告。那就是，说到底，如果我们不能成为他们想要的那个样子，他们就会想方设法来“修正”我们。\n\n我想要的，不过是和我的人民安度余生。但如果必须掌握力量才能活下去，那么，我宁愿这力量属于我自己。', 66384),
(291782, 'zhCN', '', '纳沙波尔。利刃之栖。那是一个拥有自然美景的世界。猩红的盐碱平原延绵至清凉的紫色湖泊。我们的河道中遍布巨大坚固的睡莲叶。在和平时期，经常能看到德莱尼在上面小憩，顺流而下。我们的年轻人很早就开始学习战斗，比在阿古斯时还要早。为了在拥有智慧的巨兽袭击下生存，武艺和奥术技能必不可少。\n\n我们经历了冲突与复兴的循环。我们与少数生活在我们中间的军团叛逃者结成了意想不到的盟友。我们大体上拒绝了最初引发我们大流亡的力量——无论是邪能、虚空还是圣光。\n\n我们的萨亚德人是杰德尼摔跤的天才。看他们比赛是一种享受。', 66384),
(291781, 'zhCN', '我先去侦查沃拉安的下落。', '', 66384),
(291777, 'zhCN', '对你而言，毫无意义。对我们而言，却是对家园刻骨铭心的回忆。', '对你而言，毫无意义。对我们而言，却是对家园刻骨铭心的回忆。', 66384),
(291776, 'zhCN', '她给你的这些饰物有什么特殊含义？', '', 66384),
(291775, 'zhCN', '我听见她了……\n\n或许我应该尽快换岗。', '我听见她了……\n\n或许我应该尽快换岗。', 66384),
(291774, 'zhCN', '艾林裂隙是一片危险的土地，由腐化最深的梦境和最为可怕的梦魇构成。所以我们要在这里警戒，必须要保护族人的安全。', '艾林裂隙是一片危险的土地，由腐化最深的梦境和最为可怕的梦魇构成。所以我们要在这里警戒，必须要保护族人的安全。', 66384),
(291773, 'zhCN', '离边缘远点儿。掉下去的人都会丧命——而哈籁尼尔死得更快。', '离边缘远点儿。掉下去的人都会丧命——而哈籁尼尔死得更快。', 66384),
(291771, 'zhCN', '哈尔拉兹告诉我你会来。欢迎你，哈舒拉！', '', 66384),
(291765, 'zhCN', '', '你的意思是，那阵迷雾是把你从邪枝部族手下救了出来？而不是让你迷了路？', 66384),
(291763, 'zhCN', '', '……我认识。她找到了通往我们世界的道路，急切地想把我们带走，许诺我们要去奔赴更伟大的命运。\n\n对于是否应该欢迎她，我的族人意见不一。我持反对意见，而我的弟弟却在她的存在中找到了慰藉。当我们被多曼纳尔绑架时，她就在场。\n\n朱拉斯说我疑神疑鬼，仅仅因为我怀疑这世上是否存在仁慈的生物，会仅仅出于本性善良就赠送我们次元飞船和抚慰人心的心灵旋律。\n\n你是怎么知道她的？', 66384),
(291762, 'zhCN', '', '看来确实如此。我看见了远处他们闪烁的兵刃。\n\n<图尔阿玛轻蔑地挥了挥手。>\n\n虽然奥术一直是我值得信赖的朋友，但圣光对我可是糟透了。我很高兴能回敬他们这份“恩情”。', 66384),
(291760, 'zhCN', '多曼纳尔从各个维度抓捕凡人竞争者投入他们的搏击斗坑。我们这些能自由站在这里的人，之所以被容忍，仅仅是因为我们愿意提供暴力。\n\n如果你要踏入竞技场，我希望那是出于你自己的意愿。让他们看看，我们是坚不可摧的。', '', 66384),
(291759, 'zhCN', '', '这说明我们离得很近了。你有没有感觉有人在暗中盯着我们？', 66384),
(291754, 'zhCN', '', '祝你好运吧。当然了，就算他把你生吞活剥了，我晚上也照样睡得着。', 66384),
(291751, 'zhCN', '', '好吧，要与沉睡的战争之神交流，你必须坐在他的篝火旁。不过，去过的人可没有一个回来。', 66384),
(291749, 'zhCN', '', '我以性命起誓，利拉祖。只要得到纳洛拉克的祝福，我必将铲除祖阿曼所有的威胁。', 66384),
(291740, 'zhCN', '阿曼尼的援军？无所谓，正好用更多的混乱和死亡来取悦萨拉塔斯！', '', 66384),
(291736, 'zhCN', '我们将乘着埃基尔松之风翱翔——就像过去一样。', '', 66384),
(291713, 'zhCN', '勇士，你揭露了奎尔萨拉斯面对的众多威胁。我们必须一起计划后续的行动。', '', 66384),
(291711, 'zhCN', '我感激你们迄今的努力。你们阻止了该死的光绽，揭露了邪教组织，保卫民众免受阿曼尼侵袭。\n\n但每种情况都还有更多事要处理。若想迎来光明未来，我们必须深入了解。让我们考虑下一步行动。', '', 66384),
(291710, 'zhCN', '', '我会遵照摄政王的命令在此守望。但愿我们的决定性胜利能震慑阿曼尼，让他们不敢再次进犯。\n\n阿拉托尔……我为他担忧。\n\n如果真如他所言——阿曼尼在与暮光之刃作战——那我们确实有理由重新审视策略。我虽不是祖阿曼的盟友，但也深知不该向拥有共同敌人的对象开战。\n\n去找到阿拉托尔，$p。他的直觉向来敏锐。', 66384),
(291709, 'zhCN', '我跟着奥威娜第一次离开哈籁恩达尔的时候，就明白了她的决心。\n\n我不会让她独自彷徨。\n\n艾林裂隙的危险超乎想象……但我能找到帮助她的办法。', '', 66384),
(291708, 'zhCN', '暂时风平浪静……可只要暮光之刃手里有区域的地图，就可能再次来袭。', '', 66384),
(291707, 'zhCN', '我会向伊利达雷汇报的。今天干得不错。', '', 66384),
(291706, 'zhCN', '快！我们得回密谋小径去。必须找到“非法降雨”，追查赞恩的下落，彻底终结这场邪能交易。', '', 66384),
(291702, 'zhCN', '这可不是好征兆，$p。', '', 66384),
(291701, 'zhCN', '滚吧。换个行当干。', '', 66384),
(291700, 'zhCN', '', '我、我真的不知道。我只负责搬货而已。我发誓！', 66384),
(291699, 'zhCN', '赞恩在哪里？', '', 66384),
(291693, 'zhCN', '你以为我真的那么蠢吗？赞恩会要了我的命的！', '', 66384),
(291689, 'zhCN', '我找到码头管理员了。你去跟他聊聊。我在这里望风，以防情况有变。', '', 66384),
(291671, 'zhCN', '', '准备好寻找纳洛拉克了吗？时间紧迫。', 66384),
(291657, 'zhCN', '', '我记得你。阿曼尼扎的那个闯入者。\n\n金杜鲁真的让你和莉亚德琳当了哈舒拉？哼。\n\n现在到处都在传，说你帮祖尔加拉走上了哈谢之道，洛阿神灵们也回来了。\n\n但我可没从纳洛拉克的窝里听到半点动静。\n\n<利拉祖双手叉腰。>\n\n果然。你们是最后才来找我们的，对吧？我们一样需要帮忙！', 66384),
(291645, 'zhCN', '去港口那边，告诉他们你是来提赞恩的货的。我们要切断他们的供应链，把货物当作证据带走。我在那边等你。', '', 66384),
(291644, 'zhCN', '不！不行，不能在这！', '', 66384),
(291642, 'zhCN', '阿曼尼苟活在我们昔日辉煌的废墟之中，闯入者。\n\n如今我们或许只能困守深山，但我们的帝国曾经幅员辽阔，四面环海。\n\n这一切本可重归我们手中。只要我们有足够的勇气伸手去夺取。', '', 66384),
(291636, 'zhCN', '', '我会留在这个世界，直到确信我所有的族人都从多曼纳尔手中获释。在那件事上，我希望能得到你的支持。作为回报，你也可以依靠我。\n\n然后，当这里不再需要我时，我会找到回家的路。', 66384),
(291631, 'zhCN', '本维斯，你这个蠢货！女主人的恩宠都浪费在你身上了！', '', 66384),
(291630, 'zhCN', '你们的城市沦陷了。为何还要抗拒萨拉塔斯？', '', 66384),
(291629, 'zhCN', '在痛苦中哀嚎吧！让萨拉塔斯听听你们的惨叫，亲眼看着你们的城市烧成灰烬！', '', 66384),
(291622, 'zhCN', '', '这里聚集了这么多阿曼尼巨魔——各个部族的都有。\n\n我已经很久没见过我们这么齐心了。\n\n哈舒拉，这看起来更像是一场庆功宴，而不是休整。庆祝莫尔杜恩的完蛋，这倒也说得过去。\n\n<祖尔加拉狡黠地一笑。>\n\n准备好体验阿曼尼的狂欢了吗？', 66384),
(291616, 'zhCN', '你在那边待了挺久。有什么发现吗？', '', 66384),
(291597, 'zhCN', '', '现在您可以先看看这些未处理的邪能，检验一下品质。', 66384),
(291596, 'zhCN', '', '不过别担心。很快就会有更多注能浮龙到货。我会专门给您备一些。', 66384),
(291595, 'zhCN', '', '可惜随着虚空的威胁越来越严重，货源有些跟不上需求了。', 66384),
(291594, 'zhCN', '', '这里是个避风港，志同道合的人可以在这里自由聚会。\n\n当然，也可以尽情享受……任何他们想要的东西。\n\n你不必担心暴露。赞恩会确保我们的行动万无一失。', 66384),
(291591, 'zhCN', '', '啊，生面孔。很高兴看到越来越多的辛多雷开始了解我们的服务。\n\n请问欢享之巢能为您做些什么？', 66384),
(291590, 'zhCN', '', '啊，我感觉到了一股强大的气息。\n\n抱歉没能第一时间招待您，尊敬的$g大人:女士;。请问欢享之巢能为您做些什么？', 66384),
(291589, 'zhCN', '', '凯斯媞亚鄙夷地看了你一眼，然后离开了。', 66384),
(291588, 'zhCN', '', '好。粉尘准备好后立刻带来给我。别让我久等。', 66384),
(291585, 'zhCN', '', '还有最后一批货，不过快搞定了。', 66384),
(291584, 'zhCN', '', '我的工作时间很紧。你能多快分解掉这批遗物？', 66384),
(291583, 'zhCN', '', '是时候向莫尔杜恩发起反攻了。我们走。', 66384),
(291573, 'zhCN', '他还有救，但必须把他立即送出裂隙。', '', 66384),
(291572, 'zhCN', '艾林之尘的力量来自于女神。如果它能帮上你，奥威娜，那我会帮你收集它。', '', 66384),
(291571, 'zhCN', '你们！你们夺走了她，偷走了她！都去死吧！', '', 66384),
(291568, 'zhCN', '战鼓敲响的时候，你们都死哪儿去了？你们就这么眼睁睁地看着阿塔阿曼陷落！', '', 66384),
(291566, 'zhCN', '阿曼尼怎么有胆子再来威胁辛多雷？', '', 66384),
(291512, 'zhCN', '', '为了你的小命着想，我建议你在阿曼尼扎收好武器，时刻紧跟着我。', 66384),
(291506, 'zhCN', '', '$n，我们有许多事要商议。\n\n但先去村子吧。', 66384),
(291492, 'zhCN', '', '有了神灵的祝福，我们一定能将暮光之刃赶出祖阿曼。为了阿曼尼！', 66384),
(291485, 'zhCN', '祖尔加拉！你弟弟根本不听劝，已经带着战士冲出去了。这根本就是在送死！', '', 66384),
(291483, 'zhCN', '', '为阿塔阿曼复仇！让这些入侵者记住这片土地属于我们！', 66384),
(291449, 'zhCN', '', '是来练追踪，还是练箭术？说吧，来干嘛的？', 66384),
(291448, 'zhCN', '血骑士之道，在于寻求平衡。你想开辟怎样的道路？', '', 66384),
(291447, 'zhCN', '魔法的探索，是一条发现与审慎并存的路。你想钻研哪种奥秘？', '', 66384),
(291446, 'zhCN', '哇，他们都太厉害了！\n\n远行者们那么英勇，用高超的技艺和与自然的默契守护着我们。\n\n血骑士们那么强大无畏，带着荣耀和使命感站在最前线。\n\n还有魔导师们……他们才华横溢，用知识和无穷的奥术力量改变世界。\n\n你已经近距离见过他们了。你觉得我该走哪条路？你在我身上看到了哪种未来？', '', 66384),
(291371, 'zhCN', '放松，感受韵律，别去在意缰绳。', '', 66384),
(291363, 'zhCN', '', '谢谢，$n。你在这儿交上了不少朋友，长不长羽毛的都有。', 66384),
(291361, 'zhCN', '那是暮光之刃的成员。你是对的，阿拉托尔。快，回塔奎林去！', '', 66384),
(291360, 'zhCN', '', '这次可得把尸体给藏好了！', 66384),
(291359, 'zhCN', '', '这些虚空与圣光的小鸟们，太爱多管闲事了。处理掉他们。', 66384),
(291312, 'zhCN', '西尔悄悄将一枚徽记之戒塞给你。', '', 66384),
(291311, 'zhCN', '你问得太大声了。', '', 66384),
(291310, 'zhCN', '德诺林悄悄将一枚徽记之戒塞给你。', '', 66384),
(291309, 'zhCN', '恐怕刚好卖完了。如果感兴趣的话，我还有其他生物出售。', '', 66384),
(291308, 'zhCN', '', '兰达丽女士悄悄将一枚徽记之戒塞给你。', 66384),
(291307, 'zhCN', '', '不管你在暗示什么，我们都不碰那种魔法。', 66384),
(291306, 'zhCN', '在艾林之尘的闪光中，赛奥约破解了为绘画赋予生命的秘密。借助强大而危险的力量，她将这份传承托付给了祖尔阿沙。', '', 66384),
(291305, 'zhCN', '赛奥约在颜料遗留的残渣中寻找答案，想要拼凑出尚未发现的启示。', '', 66384),
(291304, 'zhCN', '这不是普通的颜料。其中的艾林之尘开始躁动！混乱飞溅而出——回响大锅晃动不止，难驯的色彩腾空飞起。', '', 66384),
(291303, 'zhCN', '凭借锅中制作的颜料，赛奥约将自己的灵魂倾注到绘画中，并找到了原本不属于自己的回忆。', '', 66384),
(291302, 'zhCN', '回响大锅最初属于祖尔阿沙赛奥约。她不是寻常的艺术家，而是连通着遗忘之物的桥梁。', '', 66384),
(291301, 'zhCN', '烈焰升腾。迎接挑战吧。净化你的灵魂！', '', 66384),
(291299, 'zhCN', '火种准备好燃烧了。燃尽污秽，净化一切。神龛自会为你指明道路。', '', 66384),
(291298, 'zhCN', '对！烈焰回来了，加亚莱之火熊熊燃烧！飞回家吧，烈焰的主人！飞吧！', '', 66384),
(291297, 'zhCN', '我看到了你心中的火焰。去找到更多火炭，更多火种，让烈焰之灵重燃吧！', '', 66384),
(291296, 'zhCN', '难道说……这就是火种？我们正需要的那团火焰？', '', 66384),
(291291, 'zhCN', '烈焰之灵早已熄灭，它曾是无数人胸中的烈火。净化你的内心，它自会复燃重现！', '', 66384),
(291290, 'zhCN', '我会在街上保持警戒。', '', 66384),
(291288, 'zhCN', '我不能把我的士兵借给祖尔加拉，但可以在她成为哈谢的道路上尽力协助。', '', 66384),
(291286, 'zhCN', '枯木部族对加亚莱知之甚少，不过他那神神叨叨的神灵代言人还住在东边的神庙里。', '', 66384),
(291283, 'zhCN', '哈谢之路？在我小时候，我奶奶常在篝火旁给我讲哈谢的传说。', '', 66384),
(291282, 'zhCN', '祖尔加怒视着库拉玛拉。', '', 66384),
(291237, 'zhCN', '', '又是你们？还有那个精灵。\n\n<库拉玛拉轻蔑地上下打量着你。>\n\n要是祖尔加拉带着你到处招摇，却没把你开膛破肚，那我们肯定是遇到大麻烦了。\n\n作为枯木军团的统帅，我在这个哨所监视着邪枝部族。\n\n<库拉玛拉指向远方邪枝部族的临时沼泽营地。>', 66384),
(291236, 'zhCN', '', '我们的战士一个接一个地失踪，你却要我去追寻一个虚无缥缈的神灵幻影？', 66384),
(291227, 'zhCN', '', '不管怎么说，他们都一样是死了，祖尔加！', 66384),
(291225, 'zhCN', '', '是吗？那你为了从密教徒手中夺回这些光木，又赔上了多少战士的性命？', 66384),
(291224, 'zhCN', '', '哈！哈尔拉兹？你是不是聋了，$r？我们告诉过你，洛阿早就离去了！\n\n就算他们还在，现在也没人进得去哈尔拉兹神庙。邪枝部族已经和暮光之刃联手要剿灭我们。\n\n我们陷入两线作战，邪枝部族如今每夜都在袭击我的村庄。\n\n更糟糕的是那些迷雾。邪枝部族和暮光之刃用它遮蔽哈尔拉兹神灵和神庙周边区域。\n\n许多勇士进去了，但无一生还。', 66384),
(291223, 'zhCN', '姐姐，你回来了！就在你对那些神灵卑躬屈膝的时候，我已经掌握了真正的力量！', '', 66384),
(291220, 'zhCN', '', '正如你所见——芦塔尼是一种人形生物，但完全由植物构成。他们是我故乡的原住民。据我了解，他们从未踏足过地表……直到如今。\n\n而且这些芦塔尼看起来与我熟悉的那些不同。他们被改变了，被扭曲了。这让我深感忧虑。', 66384),
(291199, 'zhCN', '我的魔法持续时间很短，但能帮你追踪邪能。我们稍后汇合。', '', 66384),
(291198, 'zhCN', '用你的视觉追踪邪能，$ct。我们稍后汇合。', '', 66384),
(291197, 'zhCN', '发挥你的……特长吧，恶魔。我们一会儿碰面。', '', 66384),
(291193, 'zhCN', '但事实已经无从知晓了。求你，帮帮恩里阿安。', '', 66384),
(291189, 'zhCN', '据说，当第一位哈籁提屈服于裂隙的疯狂，那产生的影子就是莫塔卡。', '', 66384),
(291184, 'zhCN', '闯入者！快来帮我灭火——快点！', '', 66384),
(291179, 'zhCN', '', '它们还是源源不断！艾林哈籁，听听我们的呼声……降下您的援助吧！', 66384),
(291172, 'zhCN', '', '这是哈谢的专属法杖——那位能团结族人、驾驭洛阿神力的领袖。\n\n若洛阿再次与我们交流，这根法杖必不可少。\n\n我们已经很久……很久没有真正的哈谢了。\n\n但老人家总得抱点希望不是！', 66384),
(291166, 'zhCN', '', '他们是我们两位神圣的洛阿神灵！哈尔拉兹，狩猎之神；埃基尔松，凯旋之神！\n\n埃基尔松的眼睛能看穿一切。哈尔拉兹则藏在影子里。但他能揭示所有被隐藏的东西！\n\n我是……呃，我曾经是埃基尔松——凯旋之神的代言人！\n\n哦，我多想再听一次洛阿神灵的低语啊。就在此刻，就在神殿被暮光之刃毁掉之前。\n\n但洛阿如今沉默不语……也许他们听得见我们，也许听不见。也许他们试图回应，却因我们的罪孽而无法传达。\n\n如果我们有一位哈谢……也许……', 66384),
(291161, 'zhCN', '可是战争改变了这些圣骑士的使命。', '', 66384),
(291155, 'zhCN', '那样最好。我们是兄弟，无论如何都是，永远都是。', '那样最好。我们是兄弟，无论如何都是，永远都是。', 66384),
(291154, 'zhCN', '我明白。虽说公务缠身，但我还没忙到没空来看你。', '', 66384),
(291153, 'zhCN', '他们管不了我偷偷溜出来的。我就说吧？', '他们管不了我偷偷溜出来的。我就说吧？', 66384),
(291152, 'zhCN', '我又没有流放你，傻瓜。我很想念你。', '我又没有流放你，傻瓜。我很想念你。', 66384),
(291151, 'zhCN', '多亏了阿玛拉克和你，$p，我感觉好多了，但我现在也是舒尔卡的一员了。我必须留在裂隙里，也算是一种自我流放吧。', '', 66384),
(291150, 'zhCN', '对不起。裂隙快要把我逼疯了，我那时很危险。', '', 66384),
(291149, 'zhCN', '你从我面前跑开了。我还以为你死了呢！', '你从我面前跑开了。我还以为你死了呢！', 66384),
(291148, 'zhCN', '你在干什么？你不该来这里的！', '', 66384),
(291144, 'zhCN', '我明白，法奥。我会把其他人召集起来等你到来。', '', 66384),
(291143, 'zhCN', '舒阿？舒阿！', '', 66384),
(291142, 'zhCN', '恩里阿安！', '恩里阿安！', 66384),
(291133, 'zhCN', '', '[德莱尼语]Dioniss aca，小弟弟。', 66384),
(291132, 'zhCN', '', '德莱尼。流亡者。\n\n我的第一次流亡，始于我们伟大的逃亡之日。维伦的话语唤醒了我的心灵。我们所有登上吉尼达尔的人，就此被一体流放出阿古斯。我祈祷自己做出了正确的选择。\n\n第二次流亡，是在军团伏击我们世界的那天。当时我和朱拉斯正在地下寻找矿物来替换坏掉的能量核心。他曾恳求我们的母亲离开飞船来帮帮他的姐姐。大地在魔能机甲的脚下颤抖。等我们回到地表时，邪火大炮已经迫使吉尼达尔升空。他们不得不离开。他们别无选择。这一点我很清楚。\n\n而现在……又一次。\n\n我需要一些时间独处。但我会去外面找到你。在某个安全的地方，我们可以好好谈谈。', 66384),
(291131, 'zhCN', '', '我们的同胞带来了我们期待已久的机会。是时候与多曼纳尔开战了。', 66384),
(291130, 'zhCN', '', '在主宰者之座与我会合，异界人。多曼纳尔那里有我们需要的东西。', 66384),
(291129, 'zhCN', '如果是早有图谋，他们会趁着日冕村沦陷的时候进攻。一定另有隐情。', '', 66384),
(291128, 'zhCN', '还没结束呢，乌布里克。他们不可能偷走了一切。', '', 66384),
(291127, 'zhCN', '尽管我提出要援助银月城，现在却无能为力了。', '', 66384),
(291126, 'zhCN', '', '远行者都去调查异动了，日冕村完全没有防备。', 66384),
(291125, 'zhCN', '我会仔细调查你们说的情况。我们之后再作比对。', '', 66384),
(291124, 'zhCN', '我非常感谢你们三位将小镇的安危视为己任。', '', 66384),
(291121, 'zhCN', '<日记最后一页写着昨天的日期。>\n\n他们知道我想逃。不知道是怎么露的馅。\n\n我必须马上逃离……现在谁也帮不了我了。我被那些甜言蜜语蒙蔽了……全都怪我。我太害怕了，早该看穿的。\n\n绝不能让他们拿到我的研究成果。不能再给他们提供任何弹药了。\n\n请原谅我。', '<日记最后一页写着昨天的日期。>\n\n他们知道我想逃。不知道是怎么露的馅。\n\n我必须马上逃离……现在谁也帮不了我了。我被那些甜言蜜语蒙蔽了……全都怪我。我太害怕了，早该看穿的。\n\n绝不能让他们拿到我的研究成果。不能再给他们提供任何弹药了。\n\n请原谅我。', 66384),
(291120, 'zhCN', '祖尔金烦躁地低吼了一声。', '', 66384),
(291117, 'zhCN', '你确定没有把它一起收进行囊吗？', '', 66384),
(291116, 'zhCN', '我的法杖！你的眼睛和神圣的埃基尔松一样尖，快帮我找找。', '', 66384),
(291115, 'zhCN', '再等一下，小祖尔加。', '', 66384),
(291114, 'zhCN', '求您了，叔叔，我们正在遭受攻击！只拿需要的东西就好，我们得赶快离开这里！', '', 66384),
(291112, 'zhCN', '我们的土地？这里曾经都是“我们的土地”，一草一木都是我们的！', '', 66384),
(291111, 'zhCN', '', '没有必要再继续流血了。停止你们的袭击，交出光木，回到你们的土地上去。', 66384),
(291101, 'zhCN', '待我归来之时，小哈籁尼尔，你就是我的了。', '', 66384),
(291100, 'zhCN', '结束了。我会到外面等你。', '', 66384),
(291095, 'zhCN', '', '德莱尼。是一个词。明白吗？意思是：流亡者。\n\n<图尔阿玛叹了口气，移开视线。>\n\n需要独处。需要时间。\n\n会再见的。会找到你。在安全之地。', 66384),
(291090, 'zhCN', '来吧，你的精华也归我了。', '', 66384),
(291089, 'zhCN', '只要消灭了你，我就能成为舒尔卡了。', '', 66384),
(291087, 'zhCN', '', '[德莱尼语]Dioniss aca，dolos.。', 66384),
(291083, 'zhCN', '', '我们没有时间了。', 66384),
(291082, 'zhCN', '', '我们到那儿见，$p。', 66384),
(291071, 'zhCN', '家园……', '', 66384),
(291068, 'zhCN', '', '温柔的海风芬芳弥漫在洞穴中。', 66384),
(291064, 'zhCN', '我的姐妹沃拉安或许已迷失在虚空中，但我们也许还能找回她的记忆。', '', 66384),
(291062, 'zhCN', '影卫虚灵的能量读数来自那个方向。', '', 66384),
(291061, 'zhCN', '阿隆索斯告诉我，他一直都希望白银之手能够致力于这样的服务。', '', 66384),
(291060, 'zhCN', '白银之手通常不会参与这类事情吧？', '', 66384),
(291058, 'zhCN', '不过，任由苦难祸及无辜……这才是最邪恶的。', '', 66384),
(291056, 'zhCN', '不好意思，$g先生:女士;。这里只准工人进入。我们时间很紧。\n\n你有什么事吗？', '', 66384),
(291052, 'zhCN', '', '骑士们，留下来守卫永歌森林，我们跟上他们，$n。', 66384),
(291051, 'zhCN', '', '边境？哈！要是你想死在祖阿曼，死在暮光之刃手里，我可不会拦你——但你的军队必须留下。', 66384),
(291049, 'zhCN', '', '跟我来，兄弟姐妹们。脚步要轻。', 66384),
(291048, 'zhCN', '', '图阿玛尔，这位二度流放者向你感激地点了点头，随即转身带领她的人民前往安全之地。', 66384),
(291037, 'zhCN', '', '我们能抽调的大部分远行者，都在西边的日冕之树建立防线。\n\n哈杜伦带了我们一小队人来这条林根之路。他说能从这儿弄来增援。不过我得承认，我盼着的援军，可不止一个$c和……一个来路不明的家伙。\n\n<瓦尔丽雅意有所指地瞟了奥威娜一眼。>', 66384),
(291028, 'zhCN', '', '$n，快到这里来！情况……越来越糟了。', 66384),
(291009, 'zhCN', '闯入者，你来这里干什么？\n\n你难道不该去讨好那些洛阿神灵吗？', '', 66384),
(291006, 'zhCN', '恩里阿安，不。你的力量还远远不够！', '', 66384),
(291005, 'zhCN', '我知道接下来要干什么。我必须消灭莫塔卡。', '', 66384),
(290993, 'zhCN', '', '阻止他们对奇点锚点的袭击！', 66384),
(290989, 'zhCN', '我会仔细调查的。不过我很高兴能有你在，我需要你帮个小忙。', '', 66384),
(290988, 'zhCN', '真的？确实非常诡异。', '', 66384),
(290987, 'zhCN', '密教？这样的告发非同小可啊。', '', 66384),
(290986, 'zhCN', '对有些人来说是的。其他人只要能挥舞大锤惩奸除恶就行。', '', 66384),
(290985, 'zhCN', '这就是成为烈日行者的意义吗？', '', 66384),
(290981, 'zhCN', '想到我们宁静的小镇可能出现什么不测，我就心痛。', '', 66384),
(290980, 'zhCN', '去吧，$n，告诉他。', '', 66384),
(290979, 'zhCN', '魔导师乌布里克！研究进展如何？', '', 66384),
(290975, 'zhCN', '$n，返回圣光秘殿。这场抗争还远远没有结束。', '', 66384),
(290953, 'zhCN', '', '<你走近时，图尔阿玛睁开眼，对你点了点头。\n\n随后，她的目光越过你，向一个路过的虚空住民投去一道不加掩饰的冷笑。>', 66384),
(290950, 'zhCN', '', '啊，稀客——但我依旧欢迎。\n\n欢享之巢能为你做什么？', 66384),
(290949, 'zhCN', '朱拉斯失声痛哭。图尔阿玛则别过脸去，悄悄擦掉了眼角的泪。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(290948, 'zhCN', '', '我不能让多曼纳尔追上你。没别的办法了，兄弟。', 66384),
(290947, 'zhCN', '你说你不来？！你这是什么意思！', '', 66384),
(290946, 'zhCN', '', '当然，神圣遗物学会将不遗余力地提供援助。你有兴趣的话就告诉我。', 66384),
(290945, 'zhCN', '阿曼尼小径事关重大。我绝不允许他们再度侵犯奎尔萨拉斯。', '', 66384),
(290944, 'zhCN', '你要回到那里去？请务必小心，图尔阿玛。', '', 66384),
(290942, 'zhCN', '你要调查那就去吧，阿拉托尔。但我希望你能尽快赶到小径。', '', 66384),
(290941, 'zhCN', '', '要去见虚空人了。后会有期。', 66384),
(290939, 'zhCN', '', '图尔阿玛看向你，然后指向上方。', 66384),
(290938, 'zhCN', '', '多曼纳尔那里有我们用得上的东西，我们要去找到它。兄弟姐妹们，别因为血的事责怪这个异乡人。', 66384),
(290937, 'zhCN', '', '从太阳之井里爆发出的能量——比我接触过的任何魔法都要强大，而我可以算是见多识广了。他们说那支军队可以保护我们，但我还听说，爆发就是他们导致的！他们明白自己摆弄的是什么吗？', 66384),
(290935, 'zhCN', '', '发生了这么多事，还有……天上那个疯狂的暗影漩涡，客人们全被吓跑了。要不是我打理着这个地方，我都不一定还留在这儿。你想要客房，那客房有的是。', 66384),
(290934, 'zhCN', '洛瑟玛！我控制了区域，但他们正在向阿曼尼小径进发。', '', 66384),
(290932, 'zhCN', '感谢你的援助。洛瑟玛告诉了我日冕村发生的事。\n\n日冕村本在我的守护之下，但我们听到树木倒塌的声响便去查看。我以为是光绽搞的鬼——但没想到阿曼尼会如此明目张胆地入侵。\n\n我会处理光绽问题。至于阿曼尼巨魔，那就交给洛瑟玛了……但愿他不会在这过程中再失去一只眼睛。\n\n<哈杜伦眨了眨眼。>', '', 66384),
(290931, 'zhCN', '太阳之井的涌动刺激到了龙鹰，它们能够感知到危险的降临。我从没见它们这么紧张过。如果动物受到了这样的影响，永歌森林的其他地方会怎么样？', '', 66384),
(290929, 'zhCN', '', '上回奎尔丹纳斯被阴影笼罩的时候，是阿尔萨斯带着天灾大军袭击我们的王国。现在又有一支大军踏上了我们的街道，却说是来保护我们的……真是这样吗？', 66384),
(290927, 'zhCN', '', '二度流放的图尔阿玛研究着眼前形成的微弱传送门。', 66384),
(290926, 'zhCN', '', '别抱怨了。看，它起效了。', 66384),
(290925, 'zhCN', '下次能不能提前说一声！', '', 66384),
(290924, 'zhCN', '', '过来，朱拉斯。', 66384),
(290923, 'zhCN', '朱拉斯面无表情地看着图尔阿玛把血泼在自己身上。', '', 66384),
(290921, 'zhCN', '<一堆整齐的木材，取自被砍伐的光绽树。>', '', 66384),
(290916, 'zhCN', '<他上下打量着你，一言不发。\n\n你听到了房间里其他人的窃笑声。>', '', 66384),
(290915, 'zhCN', '啊，欢迎来到我们的动物园。我们饲养着来自奎尔萨拉斯各地甚至更远地方的生物。\n\n如果你想要的品种需要特殊许可才能购买，不用担心。我们很乐意帮你搞定这个小麻烦——只需一笔小钱就行。', '', 66384),
(290906, 'zhCN', '', '你预约了吗？现在这个时候很难约到。有源源不断的有钱客户希望预知自己的未来。', 66384),
(290905, 'zhCN', '<这个阿曼尼惨死于光绽中涌出的生物之手。>', '<这个阿曼尼惨死于光绽中涌出的生物之手。>', 66384),
(290892, 'zhCN', '', '鲁伊亚撤退了，艾林之尘也已到手，我们可以击退疯狂了。', 66384),
(290889, 'zhCN', '', '那个袋子……里面还有种子吗？', 66384),
(290888, 'zhCN', '', '看来鲁加尔倒下前干掉了不少敌人。', 66384),
(290883, 'zhCN', '圣光先锋军需要驻地和给养。', '', 66384),
(290882, 'zhCN', '我准备好开始仪式了，就等你了，$p。', '', 66384),
(290881, 'zhCN', '首先，我们要布置结界。我已经感觉到有具象在凝结了。', '', 66384),
(290879, 'zhCN', '', '真菌裂口的水池曾是那般澄澈。这就是一方失衡的恶果——真菌人过度繁衍，彻底污浊了水源。', 66384),
(290878, 'zhCN', '', '鲁加尔献出了生命，但还不足以赢下这场战斗。他是个令人畏惧的战士，但在绝对的数量优势面前，连他也倒下了。\n\n鲁加尔死了，他的种子失窃，同伴也遭到绑架，这显然都是真菌人所为。\n\n沿着找条路走就能找到真菌裂口，我们必须接近那里。等你做好准备就告诉我。', 66384),
(290876, 'zhCN', '有入侵者？守卫们，保护长老！', '', 66384),
(290875, 'zhCN', '', '行了，奥威娜。鲁伊亚会面对审判的。来，我们该撤回日冕之树了。', 66384),
(290874, 'zhCN', '', '我感觉到他在用根须逃跑。我们要……', 66384),
(290872, 'zhCN', '', '我们挡住了攻势。奇点锚点已经激活了！', 66384),
(290871, 'zhCN', '', '快，勇士。趁着敌人还没有兵临城下，快在奇点锚点周围布置防线！', 66384),
(290870, 'zhCN', '', '喂食花朵！', 66384),
(290868, 'zhCN', '这个生物肯定是从光绽里钻出来的！我们应该去通知魔导师。', '', 66384),
(290867, 'zhCN', '仪式场地就在那里！', '', 66384),
(290866, 'zhCN', '这……我不确定。我们只能回过头去换一条路了。', '', 66384),
(290865, 'zhCN', '啊……我感觉到仪式场地就在附近了。', '', 66384),
(290864, 'zhCN', '我们必须小心，这里的某些东西能够将我们撕碎。', '', 66384),
(290863, 'zhCN', '好痛苦，仿佛我的一部分被撕扯了下来。', '', 66384),
(290861, 'zhCN', '它在指引我们进入裂隙。我们要跟上去。', '', 66384),
(290858, 'zhCN', '我感觉到附近有什么东西……在牵动着我。', '', 66384),
(290857, 'zhCN', '', '敌人正在从南方逼近。不能让他们抵达奇点锚点！', 66384),
(290855, 'zhCN', '……再为差点就要降临的灾难道个歉。', '', 66384),
(290854, 'zhCN', '成功了！通往虚影风暴的路打开了，我们去通报洛瑟玛。', '', 66384),
(290853, 'zhCN', '那……那是什么怪物？$p，你去拖住它，争取时间让我引导法术，结束这场混乱！', '', 66384),
(290852, 'zhCN', '$p！我知道该怎么做了！我需要让启明星与虚影风暴调谐。', '', 66384),
(290851, 'zhCN', '出了什么大问题……快去，我想到解决办法后就会立即跟上。', '', 66384),
(290850, 'zhCN', '帮我破解启明星周围的结界！', '', 66384),
(290849, 'zhCN', '制服他！我来搞定这些护盾。', '', 66384),
(290848, 'zhCN', '骗子！谁都别想碰到启明星！', '', 66384),
(290847, 'zhCN', '瑟拉奈尔！退下！我有洛瑟玛亲自颁发的许可！', '', 66384),
(290844, 'zhCN', '虽然难看，但很有效果。启明星应该就在前面了。', '', 66384),
(290843, 'zhCN', '我好像被……扣押了。前面的构造体正在强化罗曼斯的法术。摧毁它。', '', 66384),
(290842, 'zhCN', '你别想再前进了，乌布里克。新的防御措施就是专门为你准备的。', '', 66384),
(290841, 'zhCN', '罗曼斯为了拦住我居然做到这个地步……', '', 66384),
(290840, 'zhCN', '祝你有……愉快的……一天……', '祝你有……愉快的……一天……', 66384),
(290838, 'zhCN', '未授权访客。', '未授权访客。', 66384),
(290837, 'zhCN', '我好怀念这间书库啊，但我们不能在此久留。', '', 66384),
(290835, 'zhCN', '噢，当心那些管理员。这些大厅里的知识……很有力量。', '', 66384),
(290834, 'zhCN', '既然来了，我还要去拿几样东西。我们到出口再见。', '', 66384),
(290833, 'zhCN', '他果然给我留了消息。恐怕你们不得不制服卫兵了。', '', 66384),
(290832, 'zhCN', '我警告过你了，乌布里克！魔导师平台永远不会对你开放！快走，省得……', '', 66384),
(290831, 'zhCN', '未授权访客，请立即站住。', '未授权访客，请立即站住。', 66384),
(290830, 'zhCN', '魔导师平台中存放着能帮我们进入虚影风暴的钥匙……暮光启明星。', '', 66384),
(290801, 'zhCN', '好吧……但如果这堂课和其它的一样……', '', 66384),
(290800, 'zhCN', '我之前和你谈过新道途的事，阿拉托尔。我们该开始寻找了。', '', 66384),
(290693, 'zhCN', '', '这运来的究竟是什么？', 66384),
(290676, 'zhCN', '', '艾林哈籁的根须，这地方臭不可闻，难怪真菌人会喜欢。', 66384),
(290671, 'zhCN', '假装是个有钱的买家，你肯定能找到邪能贩子。', '', 66384),
(290660, 'zhCN', '安忒诺里安勋爵好像在庇护每一个人。', '', 66384),
(290646, 'zhCN', '', '生面孔，补给品……他们似乎在做什么准备。', 66384),
(290645, 'zhCN', '', '别担心，安忒诺里安勋爵会保护我们的。', 66384),
(290644, 'zhCN', '圣光终将胜利。我们必须坚守信念。', '', 66384),
(290643, 'zhCN', '', '快看天空！就连圣光也抛弃了我们。', 66384),
(290637, 'zhCN', '', '当心脚下……别踩着小爪子了！\n\n你到栖木来有何贵干？', 66384),
(290636, 'zhCN', '$n，看这边。几个精灵一看我靠近就立马跑了。但他们落下了点东西。', '', 66384),
(290629, 'zhCN', '', '塔奎林的民众在恐惧中哭喊。他们渴求解脱。\n\n他们走过的路如此漫长，太阳之光几乎将他们遗弃……', 66384),
(290626, 'zhCN', '所以大家才在讨论你懂的那件事。我们需要一切能弄到的武器。', '所以大家才在讨论你懂的那件事。我们需要一切能弄到的武器。', 66384),
(290625, 'zhCN', '虚空不会等我们。学院的训练太慢了。', '虚空不会等我们。学院的训练太慢了。', 66384),
(290624, 'zhCN', '还要两年才毕业？银月城可能撑不了两个月了！', '还要两年才毕业？银月城可能撑不了两个月了！', 66384),
(290623, 'zhCN', '再贵也值得。这玩意儿曾经拯救我们人民免于灭族。现在还能再次拯救我们。', '再贵也值得。这玩意儿曾经拯救我们人民免于灭族。现在还能再次拯救我们。', 66384),
(290622, 'zhCN', '你的门路很管用。我的手下从密谋小径搞到了货源。这东西贵是贵，但必不可少。', '你的门路很管用。我的手下从密谋小径搞到了货源。这东西贵是贵，但必不可少。', 66384),
(290621, 'zhCN', '对，但我们需要金子。邪能并不便宜。也许可以给赞恩干活。去跟他谈个交易吧。', '对，但我们需要金子。邪能并不便宜。也许可以给赞恩干活。去跟他谈个交易吧。', 66384),
(290620, 'zhCN', '如果虚空像天灾那样攻击城市，就没人保护密谋小径了。我们得有自己的武器。', '如果虚空像天灾那样攻击城市，就没人保护密谋小径了。我们得有自己的武器。', 66384),
(290619, 'zhCN', '远行者不在，正好方便了我们的凶手。', '', 66384),
(290602, 'zhCN', '', '鲁加尔是战士，是赫赫有名的猎手，也是我的导师。他倾囊相授，教会了我一切。他是我们之中最优秀的，直到后来上了岁数。\n\n不久前，他开始一门心思打理花园。他……他正和其他芦塔尼培植了新品种的特拉塔克，那种根菜美味可口，但生长周期十分缓慢。\n\n鲁加尔坚信自己可以缩短周期，同时提高产量。只可惜，他永远无法验证自己的对错了。', 66384),
(290600, 'zhCN', '', '我不敢相信鲁加尔已经陨落了。我们本该一起狩猎的……\n\n<她垂下头，陷入了沉默。片刻后，她颤抖着深吸一口气，强行挺直了脊梁。>\n\n除了这里倒下的这一位，和鲁加尔同行的芦塔尼或许还有生还者。我们不能任由他们自生自灭。这里的真菌人举动太过反常。', 66384),
(290598, 'zhCN', '跟我来。', '', 66384),
(290593, 'zhCN', '<这个真菌人遍体鳞伤，已经丧命。腐朽和霉变的气味弥漫在空中。>', '', 66384),
(290592, 'zhCN', '我的朋友是狩猎归来之后才变得怪异的……', '我的朋友是狩猎归来之后才变得怪异的……', 66384),
(290589, 'zhCN', '当然不是。', '当然不是。', 66384),
(290588, 'zhCN', '他一向都是那样的吗？', '他一向都是那样的吗？', 66384),
(290586, 'zhCN', '', '不！我们需要查明这里发生了什么。', 66384),
(290585, 'zhCN', '', '我们要赶快了，$n。', 66384),
(290582, 'zhCN', '', '圣光……灼烧……', 66384),
(290572, 'zhCN', '', '金杜鲁……但愿你说得对。为了阿曼尼！', 66384),
(290560, 'zhCN', '', '哇，这么快就道别了！', 66384),
(290559, 'zhCN', '我会把种子带回银月城，魔导师或许能研究出什么来。', '', 66384),
(290558, 'zhCN', '我这一生都在忠诚地侍奉圣光，$p——甚至为此失去了一只眼睛。\n\n虽然有些圣骑士比我更强，但为数不多。\n\n可是除了少数守卫和我们的侍从，几乎所有人都被派到银月城去对抗虚空了。\n\n我不禁怀疑自己是否在某方面辜负了圣光，却想不出原因何在。', '', 66384),
(290557, 'zhCN', '', '小心点。上次我也遇到了，最后只能把那个小无赖留下了。', 66384),
(290556, 'zhCN', '我不知道它是想咬上一口，还是把蛋糕当成了自己的兄弟。', '', 66384),
(290553, 'zhCN', '我没被召唤到太阳之井，唯一好处是我还能够组织圣光之愿的防务。', '', 66384),
(290552, 'zhCN', '', '先别管这些了，你需要救治。', 66384),
(290551, 'zhCN', '我们的两个小辈还在外边！', '', 66384),
(290548, 'zhCN', '不准将外来者带进哈籁恩达尔！奥威娜前往地表世界，让你们得知了我们的存在，这已经违背了律法。现在还来这一出？\n\n奥威娜当你是朋友，算你走运。否则我会用根须把你捆起来，扔去喂迅叶龙。', '', 66384),
(290545, 'zhCN', '<远行者侦察报告，记录了数起令人忧虑的事件。戴索姆废墟的异常动静，诡异虚空生物的出现，人员失踪——清单还在延续。\n\n尽管报告层出不穷，似乎很少有人采取实际行动。>', '<远行者侦察报告，记录了数起令人忧虑的事件。戴索姆废墟的异常动静，诡异虚空生物的出现，人员失踪——清单还在延续。\n\n尽管报告层出不穷，似乎很少有人采取实际行动。>', 66384),
(290544, 'zhCN', '<前夜的例行巡逻安排被划掉了。卫兵队长留了张便条：>\n\n今晚我将独自巡视边界。总督有令。好好享受休假。\n\n莱', '<前夜的例行巡逻安排被划掉了。卫兵队长留了张便条：>\n\n今晚我将独自巡视边界。总督有令。好好享受休假。\n\n莱', 66384),
(290542, 'zhCN', '<这本书充满了古怪的布道，完全不像精灵平常接触的那些。\n\n书中特别强调圣光所投下的阴影具有重要意义，还警告即将到来的日食需要被平息安抚。>', '<这本书充满了古怪的布道，完全不像精灵平常接触的那些。\n\n书中特别强调圣光所投下的阴影具有重要意义，还警告即将到来的日食需要被平息安抚。>', 66384),
(290541, 'zhCN', '欢迎来到塔奎林！\n\n即便在最黑暗的时刻，塔奎林依然屹立不倒。安心休憩吧——苦难的日子已成过往。\n\n新的希望即将来临。一切都会好转的。\n\n也许你的到来自有天意，即便你暂时还不明白。', '欢迎来到塔奎林！\n\n这座小镇历经了不少风雨。\n\n苦难的日子已成过往。新的希望即将来临。\n\n你的到来自有天意，即便你暂时还不明白。', 66384),
(290540, 'zhCN', '<这些看起来像是卫兵队长偶尔放在新人欢迎包裹里的便条。>\n\n前路也许看似未卜，但真相就在眼前。\n\n到塔奎林南边来找我们。确保没有被人跟踪。', '<这些看起来像是卫兵队长偶尔放在新人欢迎包裹里的便条。>\n\n前路也许看似未卜，但真相就在眼前。\n\n到塔奎林南边来找我们。确保没有被人跟踪。', 66384),
(290539, 'zhCN', '', '把艾林之尘分发给这里的战士。这能赋予他们力量来反击光绽的威胁。', 66384),
(290536, 'zhCN', '这种光绽也许真的能为先锋军所用。至少我需要一探究竟。', '', 66384),
(290535, 'zhCN', '', '快下来，小猫咪！', 66384),
(290534, 'zhCN', '太阳之井这里承载着太多期望，$p。\n\n这是沉重的责任，但比逃避责任要轻松得多。\n\n谢谢你帮我们分担这个重担。', '', 66384),
(290531, 'zhCN', '光绽正在永歌森林中蔓延，要想阻止它就必须立即行动了。形势严峻啊，奥威娜。', '', 66384),
(290522, 'zhCN', '', '金杜鲁要我们留下祭品，我看，用敌人的脑袋来当祭品是再好不过了。', 66384),
(290521, 'zhCN', '我们得赶紧找到祖尔加，不然就晚了。', '', 66384),
(290520, 'zhCN', '住手！没必要再流血了。', '', 66384),
(290518, 'zhCN', '', '不过，雄鹰回到这里似乎是个好兆头。', 66384),
(290513, 'zhCN', '', '我准备好举行舒尔卡的仪式了。这能在进入艾林裂隙后保护我们……一段时间。', 66384),
(290511, 'zhCN', '洛瑟玛，我们找到了附近藏身处的线索——', '', 66384),
(290498, 'zhCN', '运用你的感知追踪邪能，$c。我们稍后汇合。', '', 66384),
(290488, 'zhCN', '痕迹很微弱……但我仍能感受到它的存在。', '', 66384),
(290487, 'zhCN', '这个……\n\n说实话，我们就是将裂隙里钻出来的软泥直接碾碎，被裂隙的影响压垮时就互帮互助。\n\n我们能做的只有这些了。', '这个……\n\n说实话，我们就是将裂隙里钻出来的软泥直接碾碎，被裂隙的影响压垮时就互帮互助。\n\n我们能做的只有这些了。', 66384),
(290485, 'zhCN', '艾林裂隙对哈籁尼尔十分危险，女神之声在那里最为强大，我们会在她的呼唤中迷失。逃逸的生物也可以分泌软泥来威胁我们。\n\n必须有人采取措施，让裂隙的影响不会扩散到哈籁恩达尔的其他地区。所以我们来了。', '艾林裂隙对哈籁尼尔十分危险，女神之声在那里最为强大，我们会在她的呼唤中迷失。逃逸的生物也可以分泌软泥来威胁我们。\n\n必须有人采取措施，让裂隙的影响不会扩散到哈籁恩达尔的其他地区。所以我们来了。', 66384),
(290449, 'zhCN', '<控制殆希莫斯和殆希莫斯耗尽了阿拉托尔的专注力，他咬紧牙关奋力坚持。>', '', 66384),
(290443, 'zhCN', '', '这里的虚空十分浓重，甚至可以咽下去。既然掌握了力量，我很乐意接受它的考验。这股冰冷而混乱的烈风令我喜不自胜。\n\n其他人固守着安全的边界，可我们术士已经将它超越，我们还能再次取得突破。\n\n我就在此地，掌控着一切。', 66384),
(290440, 'zhCN', '迷雾结界消散了！我们快去找祖尔加。', '', 66384),
(290439, 'zhCN', '<在花瓶内，新鲜的血脉凝团渗入灰烬中。>', '', 66384),
(290437, 'zhCN', '<灰烬沉积在花瓶底部。>', '', 66384),
(290436, 'zhCN', '<在花瓶内，新鲜的骨化甲壳利牙置于灰烬之上。>', '', 66384),
(290434, 'zhCN', '<灰烬沉积在花瓶底部。>', '', 66384),
(290425, 'zhCN', '', '自从这里还是半片废墟以来，我就没见过如此大量的物资进出。\n\n总督怎么指望我把这些全都记录下来？', 66384),
(290424, 'zhCN', '外来的帮手并不常见，但也并非禁忌。上前来，$c。', '', 66384),
(290423, 'zhCN', '', '把武器放在我看得见的地方。', 66384),
(290422, 'zhCN', '太弱了，简直不堪一击……', '', 66384),
(290418, 'zhCN', '我在那里等你。', '', 66384),
(290417, 'zhCN', '安忒诺里安勋爵最在意的莫过于人民的安危。他肯定想要得知此事。', '', 66384),
(290414, 'zhCN', '导师说裂隙的上方有一处峭壁，让我到峭壁的北边找他。', '', 66384),
(290413, 'zhCN', '待我与其他人商讨完毕，我会考虑的。', '', 66384),
(290412, 'zhCN', '', '<这位法师在你靠近时嗅了嗅空气，完好的那只眼睛眯起打量着你。犹豫片刻后，她不情愿地用流利的艾瑞达语开口。>\n\n你散发着邪能的恶臭。省去我们互相比划交流的尴尬吧，但别把我错认成堕落者。我们是德莱尼。流亡者。幸存者。\n\n我是图尔阿玛。守护我族虚空来客并引导他们回家是我的职责。', 66384),
(290411, 'zhCN', '', '我恐怕只能忍受损失了。先是巨树被感染，再是库扎特，然后又是那些商人。\n\n不过，幸好奥威娜能够回来。但我怀疑女神很快又要把她唤走了。', 66384),
(290410, 'zhCN', '', '我们必须想办法治愈光绽的感染者。这座村子已经失去了太多。', 66384),
(290405, 'zhCN', '', '这一位在盛放台地绽放，却一直在艾林裂隙收集种子。\n\n哈拉希尔既不在我们的花园附近，也不在裂隙周围。', 66384),
(290374, 'zhCN', '', '<你感受到图尔阿玛周围空气中熟悉的奥术波动。她似乎和你一样，能通过奥术语言理解盟友的语言。她认出了你的能力，露出会意的微笑。>\n\n一位法师同僚。正好，我们沟通起来简单多了。\n\n我是图尔阿玛。守护我族虚空来客并引导他们回家是我的职责。', 66384),
(290373, 'zhCN', '我们亡灵与圣光的关系很复杂，我的情况比大多数人更甚。\n\n圣光在灼烧我。我学会了忍受这种痛苦并继续作为牧师侍奉它，但由于当了多年的大主教，圣光在我身上的共鸣比别人更强烈。\n\n太阳之井也是如此。在外面，它带来持续的灼痛感——剧烈，但还能承受。\n\n如果我走进去，我会像扑火的飞蛾一样被圣光完全吞噬。', '', 66384),
(290370, 'zhCN', '自从那件事之后，我已经很久没有这样靠近太阳井了……', '', 66384),
(290369, 'zhCN', 'Krona，陌生人。抱歉，但我必须专注于手头的工作。要保护我逝去的同胞，时间至关重要。', '', 66384),
(290368, 'zhCN', '不只是这个原因——虽然光是这个就够了。\n\n我一直努力成为英雄。而且很成功。他们甚至称呼我为救赎者阿拉托尔。\n\n挥剑冲锋，运用圣光的力量……\n\n我开始怀疑圣光本身是否像我理解的那样纯净简单。\n\n在我思考这些的时候，虚空却在步步紧逼。\n\n所以我想我会依靠法奥的指引，直到重新找到方向。\n\n或者至少，能重新看清脚下的路。', '', 66384),
(290366, 'zhCN', '$p。\n\n抱歉，我现在没什么心情聊天。', '', 66384),
(290365, 'zhCN', '$p，感谢你前来援助。圣光先锋军一直在维持仪式来牵制萨拉塔斯，但他们的耐力不如我。\n\n你能做的任何事都可能为我们争取时间。', '', 66384),
(290364, 'zhCN', '', '$p！我每天都在想，是你把我从血色十字军中拯救出来，给了我重新侍奉圣光的机会。\n\n现在你又让我能够继续这样做。再一次感谢你。', 66384),
(290363, 'zhCN', '', '我忍不住思考，$p，是什么让萨拉塔斯走上了这条路。我猜她的过往和虚空一样黑暗。\n\n但更让我痛心的，是想到所有被她伤害的人——所有因她的阴谋而死去的生命。这就是我们必须用太阳之井阻止她的原因，无论我们多么疲惫不堪。', 66384),
(290362, 'zhCN', '', '老实说，$p，我以为跟随父亲踏入死亡领域时，我的人生就已经到达顶峰了。\n\n现在我们要面对一个更加神秘莫测的敌人。虽然令人恐惧，但我很庆幸能贡献自己的力量。', 66384),
(290361, 'zhCN', '我要研究卡茜雅的笔记。我不会让她枉死的。', '', 66384),
(290360, 'zhCN', '', '自从我从外域来到这里后，太阳之井一直是圣光的指引，也代表着血精灵身份的真正意义。\n\n能参与这件事让我倍感荣幸，$p。', 66384),
(290359, 'zhCN', '这些笔记……卡茜雅？不！', '', 66384),
(290358, 'zhCN', '请节哀顺变，魔导师。我会派人妥善处置那具遗体。', '', 66384),
(290357, 'zhCN', '我经历了太多，$p，从圣骑士的创建到阿尔萨斯背弃圣光……\n\n我曾以为击败燃烧军团和提尔的归来预示着美好的未来，但虚空已经把我们的世界推向了黑暗的深渊。\n\n谢谢你帮我找到了继续战斗的勇气。', '', 66384),
(290355, 'zhCN', '', '那是阿隆索斯的法杖吗，$p？我离开血色十字军时，是他欢迎我加入教团的。\n\n既然他把法杖托付给你，我想我也可以信赖你。', 66384),
(290354, 'zhCN', '', '我们阿拉希帝国没有什么能与太阳之井媲美，$p。\n\n保护它极其重要。感谢你的协助。', 66384),
(290353, 'zhCN', '', '我的人民对虚空的侵蚀不陌生——过去，正是对洛阿神灵的信仰让我们战胜了强敌。\n\n今天，对我洛阿的信仰，以及对提尔教诲的尊崇，将指引我的战锤。我祈祷这已经足够。', 66384),
(290352, 'zhCN', '安瑟希望我们像他那样抵抗虚空。\n\n在你的帮助下，我依然能够做到这一点。', '', 66384),
(290351, 'zhCN', '', '这些年来，我目睹了虚空夺走无数战士的生命……\n\n吞噬一切，永无止境，就像燃烧军团一样。甚至犹有过之。\n\n我祈祷，$p，这场冲突不要持续几千年之久。', 66384),
(290333, 'zhCN', '我们要回去向银月城报告。他们必须得知这里的情况。', '', 66384),
(290329, 'zhCN', '', '芦塔尼……他们是被迫生长的。你所说的圣光可能就是原因。', 66384),
(290321, 'zhCN', '感谢你的帮助，$p。我也会去收集那些生物的毒素……只要我没有先晕过去的话。', '', 66384),
(290303, 'zhCN', '舒阿，你休想再出去了。', '舒阿，你休想再出去了。', 66384),
(290299, 'zhCN', '', '虚影尖塔必将倒塌，虚灵们！', 66384),
(290298, 'zhCN', '我们触及圣光的道路虽然各有不同，但我们是为了同一个使命而聚集于此：为了守护艾泽拉斯！', '', 66384),
(290297, 'zhCN', '旅途好漫长，我都快要枯萎了。\n\n花点时间欣赏一下这小东西的花瓣，居然感觉精神都好了不少。', '', 66384),
(290296, 'zhCN', '', '虚空奴役了你们，却赋予了我力量！', 66384),
(290295, 'zhCN', '如果太阳之井沦陷，我们就再也无法阻止吞噬军团了！', '', 66384),
(290294, 'zhCN', '我知道你们很疲惫，很难继续坚持，但我们必须坚持！', '', 66384),
(290291, 'zhCN', '请你要找到他，$p。告诉他回家来。', '请你要找到他，$p。告诉他回家来。', 66384),
(290288, 'zhCN', '愿黑暗、潮湿与腐朽与你相伴！', '', 66384),
(290287, 'zhCN', '友善的芦塔尼还真不多见。', '', 66384),
(290286, 'zhCN', '精彩的派对。很高兴看到萨瑟利尔还没忘怎么操办个好派对。\n\n而且这也是个好机会，那些平日里对贫民区避之不及的贵族们，这会儿也变成我们的客人了。', '', 66384),
(290285, 'zhCN', '', '这里有点憋闷，不过总比在舞厅强。', 66384),
(290283, 'zhCN', '虽然我很厌恶这种毫无意义浪费时间的行为，但为了赢得战争，血骑士确实需要筹集必要的资金。', '', 66384),
(290281, 'zhCN', '这位是米卡，负责掌管哈尔玛拉的芦塔尼事务。', '', 66384),
(290280, 'zhCN', '愿这位陌生人根深蒂固。', '', 66384),
(290271, 'zhCN', '', '我听说萨瑟利尔男爵对你推崇备至。在这样的圈子里，他的青睐可是炙手可热的。\n\n若你能将他的恩泽分享给魔导师，我相信我们能达成双赢的协议。', 66384),
(290185, 'zhCN', '系统……故障。', '', 66384),
(290183, 'zhCN', '指令——众神之父严禁任何个体通行。', '', 66384),
(290178, 'zhCN', '', '我几年前接受过这些试炼，那时的我还比较年轻。所有哈籁尼尔都必须在成年之时接受试炼的考验。\n\n这场仪式标志着我们步入成年，也会在部族之内为我们铺就未来的道路。', 66384),
(290177, 'zhCN', '', '我很高兴你能毫发无伤地完成试炼，$n。当然，你没有让我失望。\n\n我知道你既能干又可靠，所以我才会觉得，我们有必要与你分享这些历史和秘密。', 66384),
(290175, 'zhCN', '虽然历经坎坷，但没有我克服不了的困难。我很高兴你也能够通过。\n\n我喜欢哈籁尼尔。他们与大自然关系紧密，是自然的保护者，与我们游侠如出一辙。\n\n真是个奇妙的民族啊，他们用画作来传承历史，这种手段是我从未见过的。\n\n哈加尔说，哈籁尼尔周围的其他画作也讲述了一些故事。我真想找到它们，再体验一下那段往事。', '', 66384),
(290174, 'zhCN', '哈籁尼尔的历史真是奇妙，他们肯定是最先听到艾泽拉斯之歌的，而艾泽拉斯就是他们口中的艾林哈籁。', '', 66384),
(290102, 'zhCN', '那武器……光木……他们并非想要征服永歌森林。他们只是在保护自己免受暮光之刃的威胁。', '', 66384),
(290101, 'zhCN', '让我来鼓舞其他人？法奥的想法总是很有新意。', '', 66384),
(290092, 'zhCN', '法奥派你来的？他是个好人。\n\n你知道他创立了我的圣骑士团吗？他培训了我——白银之手就是他的遗产。\n\n很好，$p。我服从命令。这就是我选择的道路。', '', 66384),
(290090, 'zhCN', '哦——你好，$p。\n\n我只是……在看这座圣泉。我想出来透透气。\n\n有什么地方需要我吗？你是为了这个来找我的？', '', 66384),
(290085, 'zhCN', '', '我……我会考虑的。但你必须明白，这些人——我的族人——我们已经有了自己的家园。他们都有家人，有被夺走的挚爱。\n\n换位思考一下，这等同于抛下你拥有的一切与我们同行，寄望于一个新的世界会比你所知所爱的故土更加安全。\n\n这些事我们之后再谈，现在在此地驻足交谈十分危险。', 66384),
(290078, 'zhCN', '', '天呐，你瞧瞧布罗西纽斯。多听话。链子都不用拴。我真希暗谷望能知道自己有多走运。\n\n<露西亚瞥了一眼自己的虚空行者，一脸嫌弃地撇了撇嘴。>\n\n风暴把你惯野了，卡尔高戈。跟你一比，它简直就是条野狗。', 66384),
(290075, 'zhCN', '', '归于虚无吧。', 66384),
(290072, 'zhCN', '<朱拉斯瞪大双眼看着你，似乎无法理解。>\n\n啊？啊？？不，不！朋友！不懂古代语！好可怕！', '', 66384),
(290071, 'zhCN', '感谢你救了我，$G兄弟:姐妹;。我欠你一条命，或者至少欠你个拥抱，哈。\n\n图尔阿玛一直在研究送我们回家的方法。请原谅她对你的戒备，她对圣光和那些仍具有圣光恩赐的人怀有某种……怨恨。与她不同，我始终坚守信仰。\n\n<朱拉斯紧握着他的纳鲁吊坠，深深叹息。>\n\n但我也不否认自己曾经感到被遗弃。', '', 66384),
(290070, 'zhCN', '<朱拉斯绽放出灿烂的笑容，向你竖起大拇指。>\n\n谢谢，真是太感谢了！来抱一个！', '', 66384),
(290065, 'zhCN', '', '我怎么会忘记！克罗库、萨格雷背叛者们，还有那些你难以想象其身世的人！我们都是幸存者。他们同样也是德莱尼，我自豪地站在我的族人身后！\n\n在这漆黑冰冷的深暗领域中，我们独自度过了数千年。被同胞抛弃，被圣光遗忘！我们彼此守护，抵御虚灵的掳掠，对抗寄生的畸体，还有此刻仍在骚扰我们的虚空怪物。\n\n然而，我们依然建立了一个珍贵的家园，那里才是我们必须返回的归处。', 66384),
(290063, 'zhCN', '', '我确实是艾瑞达。但首先，我是个德莱尼。我唾弃那些横跨宇宙追猎我族的恶魔——那些暴君，堕落者。但此刻威胁我族的怪物并不是他们。\n\n$c，我的人民需要你，我恳请你伸出援手。', 66384),
(290061, 'zhCN', '', '<图尔阿玛专注地聆听你讲述自她与德莱尼人分离后的历史。>\n\n我已经听闻我们在阿古斯的胜利。近来，我们遇到的带着邪痕、寻求救赎的同胞比以往任何时候都要多。很遗憾，当时我们未能与你并肩作战。\n\n我们还有太多要事需详谈，$G兄弟:姐妹;，希望日后能有时间。但此地并不安全，我的人民必须返回家园。', 66384),
(290059, 'zhCN', '', '能在这种地方见到你真是个奇迹，$G兄弟:姐妹;。\n\n我是图尔阿玛。我的职责是守护我的族人——虚空来客，并护送他们回家。', 66384),
(290058, 'zhCN', '', '与吉尼达尔上的同族分离数千年，难免在我们之间刻下裂痕。我该解释一下。\n\n我们中的许多人曾追随先知维伦，在他的带领下逃离萨格拉斯的军团。或许你知晓我们曾寻求庇护的诸多世界，也许你自己也曾像我们一样踏足其中——冰雪世界、迷雾丛林、无垠海洋。我们在任何世界都无法长久安居。\n\n军团一如既往地来袭，而我和其他未能及时返回次元飞船的族人被留在了这里。我们注视着吉尼达尔升入天际，直到它化作一个闪烁的光点，然后，消失不见。\n\n从那以后，我们就在深暗领域中独自生存。孤身前行。', 66384),
(290057, 'zhCN', '', '<图尔阿玛施展她的魔法。借由共通的奥术语言，你们能够正常交流。>\n\n我曾在艾瑞达斯闪耀的大厅中修习。这是我族人掌握的一门罕见技艺。无论你来自何方，你的魔法造诣显然不容小觑。', 66384),
(290055, 'zhCN', '看我带什么来了！我们失散已久的同族！$G他:她;救了我。', '', 66384),
(290051, 'zhCN', '$n，等等！有埋伏！', '', 66384),
(290050, 'zhCN', '神灵总会在危急关头回应我们。现在，只要有合适的人开口——一个走在哈谢之路上的人，他们或许就会回应！', '', 66384),
(290047, 'zhCN', '当祖尔加拉还是孩童，她祖父仍为酋长时，洛阿神灵依然是阿曼尼文化的核心——从阿曼尼诞生起就一直是这样。\n\n所有阿曼尼酋长都必须向神灵献身。但只有少数人获得神灵祝福，成为哈谢——不仅是首领，不仅是神灵的代言人，更是令人敬畏的战士和族群支柱。\n\n这正是祖尔加拉必须踏上的征程，愿神灵庇佑！这才是拯救我们的道路。\n\n而你……你愿意帮她一把吗？没错，你不是阿曼尼，但你够强。我能感觉到，埃基尔松已经给了你无数次胜利。我想不出比你更适合当她哈舒拉的人了。', '', 66384),
(290034, 'zhCN', '库拉玛拉，这里需要你的部队。', '', 66384),
(290023, 'zhCN', '', '遇到虚灵。是朋友。在……曼塔斯看到——呃……\n\n<图尔阿玛比划出一个球形，然后用手指变出几道奥能火花。>\n\n对我们好。帮助我们。然后离开。\n\n明白吗？', 66384),
(290021, 'zhCN', '朱拉斯朝你示意。图尔阿玛仔细打量着你，其他难民则带着敬畏低声议论。', '', 66384),
(290020, 'zhCN', '看我带什么来了！一位英勇的异乡人！正是它救了我。', '', 66384),
(290017, 'zhCN', '朱拉斯感激地躬身行礼，随后指向西北方地平线。', '', 66384),
(290012, 'zhCN', '卡萨梅，回响之穴的祖尔阿沙，我会在试炼之旅中为你引路。', '', 66384),
(290010, 'zhCN', '', '如果你能获得女神的认可，他们就会意识到，外来者也有可能获得女神的召唤。这应该就能让他们相信你是来帮忙的……并且我们也需要他们的帮助。\n\n我的族人不能继续躲藏在根须之下了。树木遭殃，根须也没法独善其身。我们不能对地表世界视而不见。', 66384),
(289995, 'zhCN', '', '快走，$n！没时间了！我……马上就……啊……！\n\n<奥蕾莉亚挣扎着想要起身，却因体力不支而倒了下去。>', 66384),
(289994, 'zhCN', '我都记不清上次拉断弓弦是什么时候的事了。远行者新兵的冲刺速度都比这快。\n\n<赛德拉斯揉捏着左手的前臂，脸上抽了一下。>\n\n是空气中的能量，是虚空在作祟。我们都如同紧绷的弦，我们全都太紧张了。', '', 66384),
(289993, 'zhCN', '洞中的壁画气势恢宏，它们真的保存了哈籁尼尔人民的回忆吗？', '', 66384),
(289991, 'zhCN', '', '我曾是泰达希尔的护根者。随着这棵伟大的世界之树毁于一旦，我的职责也随之终结。\n\n我们哈籁尼尔虽世代隐居，但如今已不能再继续这样的生存之道。\n\n根系仅是巨树的一部分。纵使根系是护根者的重心所在，真正的护根者也当保护并照料整棵树木。\n\n我始终在想，当时我是否能做些什么来阻止那场浩劫。正是那场焚毁巨树的大火，让我愿意倾听你的想法。', 66384),
(289990, 'zhCN', '我这辈子一直都在听父亲和母亲的故事，这也让我背负起了难以实现的期望。\n\n亲眼看着母亲战斗的身姿，再利用我的所学所获……虽然这个地方危机四伏，但能和她并肩作战感觉真好。', '', 66384),
(289989, 'zhCN', '', '我是哈加尔，身为长老，也曾是护根者。我在此见证你接受挑战，并将如实报告你的成败。', 66384),
(289988, 'zhCN', '', '若你确实聆听过女神的歌声，试炼中应当能应对自如。或许她如同昔日召唤奥威娜那样，也在召唤着你。', 66384),
(289987, 'zhCN', '', '回响之穴中贮藏着我族的回忆和历史。如果你能熬过挑战，就能从中学到很多。', 66384),
(289984, 'zhCN', '奥威娜已经去和长老们谈话了。等你准备好了就告诉我，$n。', '', 66384),
(289980, 'zhCN', '议会已经集结起来审判奥威娜的“罪行”了。等你做好准备，我们会和她一起受审。', '', 66384),
(289946, 'zhCN', '太可怕了……连晨风村都显得不值一提了。', '', 66384),
(289944, 'zhCN', '', '我们会熄灭太阳之井的光辉！', 66384),
(289940, 'zhCN', '圣光能让你喘息片刻，但还要继续前行！', '', 66384),
(289933, 'zhCN', '', '你们的宝贝神器现在属于萨拉塔斯了！', 66384),
(289932, 'zhCN', '如果你执意要去，那就需要舒尔卡。你对他的看法改变不了事实。', '', 66384),
(289922, 'zhCN', '银月城必须知晓此事。', '', 66384),
(289919, 'zhCN', '鲁伊亚是莎拉达希尔的护根者。\n\n自从我最近接任阿梅达希尔的护根者以来，一直都是他在指导我。', '', 66384),
(289916, 'zhCN', '护根者肩负着守护和照料世界之树根系的重任。我是阿梅达希尔的护根者，刚接手这份职责不久。\n\n我们负责照料根系，维持其健康，驱除害虫和一切可能危害巨树根须的威胁。', '', 66384),
(289912, 'zhCN', '感谢你找到了孩子们，但仅凭这点还不足以让你在我族领地自由来去。\n\n与外界接触本已违背族规。奥威娜不仅向外人揭示了哈籁尼尔的存在，甚至暴露了哈籁恩达尔本身。\n\n她必须为她的罪行付出代价。你也不例外。', '', 66384),
(289911, 'zhCN', '', '我想帮助奥威娜，可她不愿意到该去的地方去。', 66384),
(289910, 'zhCN', '我不记得上次被拘禁起来是什么时候的事了。这种手段还挺新颖的！你们说现在该怎么称呼这种材料呢？光接素材？\n\n<殆希莫斯咧嘴大笑，又突然停了下来，从头到脚仔细打量着你。>\n\n这么一想，它其实和你们的光铸手段不太一样。轮到我来讯问你的时候，我很乐意把每个细节都刻在你袒露的背上。', '', 66384),
(289901, 'zhCN', '', '哈籁恩达尔就在下方，上面那回旋的根系就是摇篮，是与女神艾林哈籁息息相关的至高圣地。\n\n下面则是哈拉希尔，制漆师的村子。我们要去那里停歇片刻。经过漫长的分别，我现在只想再饱览故乡的风光。', 66384),
(289900, 'zhCN', '难怪他们的保护欲那么强……这是不曾触及的美丽。', '', 66384),
(289896, 'zhCN', '谢谢你，$n。没有你我肯定活不下去。', '', 66384),
(289895, 'zhCN', '那个东西……是直接从梦魇中钻出来的。阿玛拉克说它很古老，所有遇害的舒尔卡的精魂都集中在它体内。\n\n我们能击败它吗？', '', 66384),
(289887, 'zhCN', '不论结果如何，我都要感谢你的善良，$n。如果出现了最悲惨的结局，也请你转告舒阿。', '', 66384),
(289886, 'zhCN', '这是紧要时刻，恩里阿安要么挺过仪式，要么永远迷失。', '', 66384),
(289884, 'zhCN', '没想到风行者女士竟然也有一个属于自己的黑暗纳鲁。这件事远比想象的要复杂得多……', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(289880, 'zhCN', '', '我们要给那个船长放个终生长假……', 66384),
(289876, 'zhCN', '恩里阿安正处于危难关头。如果他没法完成仪式，斩断他和艾林哈籁的联系，他就会被裂隙的疯狂彻底吞噬。\n\n幸好有你陪在他的身边。舒尔卡不能这么做，我们可以提供指引，但不得直接出手干预。', '', 66384),
(289873, 'zhCN', '看到了吗，$c？那些密教徒之所以烧毁光木，就是因为畏惧它的力量。', '', 66384),
(289871, 'zhCN', '你，还有你——把剩下的弩炮箭矢都搬到祭坛那边去。', '', 66384),
(289865, 'zhCN', '', '救救我的小猫吧，圣骑士先生！', 66384),
(289858, 'zhCN', '我必须完成仪式，斩断我与女神的联系，否则她的不谐之歌会让我失去神智、性命，或许还有更惨的命运。', '', 66384),
(289848, 'zhCN', '', '符文石……我们是可以挡住增生，可挡不住那些……怪物！', 66384),
(289846, 'zhCN', '', '哈籁尼尔之道要求我们不得接触外面的世界。我们恐怕得不到盛情的款待，但光绽的威胁确实不是在地表世界上发源的。\n\n我的人民此刻必须要加入战斗了。就算他们愿意留我们一命，说服他们参战也是一项艰巨的挑战。', 66384),
(289845, 'zhCN', '', '我很高兴能够回到故乡，再次触碰哈籁恩达尔的根须。我已经离家太久了。', 66384),
(289843, 'zhCN', '是大法师罗曼斯要求我陪同你和奥威娜前往哈籁恩达尔的。作为远行者游侠，我可以发现光绽的迹象。\n\n奥威娜怀疑这场感染发源于她的故乡，我就陪同你们来追查源头了。', '', 66384),
(289841, 'zhCN', '我是银月城的游侠将军哈杜伦·明翼。我负责领导远行者，我们这些游侠的本事在艾泽拉斯无人能比。算上其他世界那也是数一数二的。', '', 66384),
(289840, 'zhCN', '亲眼目睹哈籁尼尔的故乡是个举世无双的机会。他们一直保守着秘密，世界之树的根须从来没有传出过哈籁恩达尔的消息。', '', 66384),
(289836, 'zhCN', '<阿拉托尔露出了苦笑。>\n\n还不是时候，$n，我只是来把她带回家的。\n\n我以后会告诉她的，但那是以后，等我们安全了，等局势不再那么紧迫了。\n\n我可不希望她对父亲发火啊。\n\n所以，$n，你也要守口如瓶。就让我找个合适的时候向母亲坦白吧。\n\n至于现在，我们有仗要打。', '', 66384),
(289834, 'zhCN', '她还活着！她就在这里！\n\n我从内心深处之道，她一定还活着，只是去某个地方狩猎了……她一直都是这样。\n\n<阿拉托尔的微笑中隐含着忧伤。>\n\n可是这一次，我们也来了。这一次，我们要一起狩猎。', '', 66384),
(289832, 'zhCN', '<阿拉托尔愁眉不展。>\n\n我的头脑中感受到了一股压力，心中也泛起了从未有过的恐惧……', '', 66384),
(289815, 'zhCN', '前面情况不妙！保持警惕！', '', 66384),
(289804, 'zhCN', '<这个守卫的遗体被利爪撕得血肉模糊。当你检查伤口时，一根植物藤蔓从尸体内部冒了出来。>', '<这个守卫的遗体被利爪撕得血肉模糊。当你检查伤口时，一根植物藤蔓从尸体内部蜷曲伸出。>', 66384),
(289780, 'zhCN', '我已经忙不过来了，拜托你帮我一把。\n\n我在艾林裂隙中逗留得太久，耳畔尽是她的不谐之歌。\n\n<年轻的哈籁尼尔咳嗽了起来。>\n\n这在一点点夺走我的生命……令我陷入疯狂。我都不知道哪个命运会先降临。', '', 66384),
(289779, 'zhCN', '是怪物！它们从光绽里钻出来了！', '是怪物！它们从光绽里钻出来了！', 66384),
(289778, 'zhCN', '', '懦夫的罪行，会在阴影里投下长长的烙印……', 66384),
(289775, 'zhCN', '你的侵占到此为止了！', '你的侵占到此为止了！', 66384),
(289765, 'zhCN', '艾林哈籁之根啊！你是谁？', '', 66384),
(289759, 'zhCN', '你是从哪儿来的？我活了这么多年，从没见过像你这样的！', '', 66384),
(289757, 'zhCN', '', '跟上踪迹，它应该能带我们找到答案。', 66384),
(289743, 'zhCN', '', '你是怎么来到这里的，闯入者？外来人不得进入哈籁恩达尔！', 66384),
(289735, 'zhCN', '', '是谁——你是什么生物？退后，这是警告！', 66384),
(289729, 'zhCN', '这个地方……我们仿佛穿越了时空。', '', 66384),
(289725, 'zhCN', '我必须找到我兄弟。我知道他还活着！', '我必须找到我兄弟。我知道他还活着！', 66384),
(289718, 'zhCN', '', '嘘！这边！', 66384),
(289710, 'zhCN', '我对先祖发誓，你要是不马上离开，我就把你扛起来带走！', '', 66384),
(289708, 'zhCN', '哈！我从你小时候起就这么教你的！', '', 66384),
(289705, 'zhCN', '', '那是大主教的妻子吗？哦，我是说女朋友。我还以为她个子会高一些呢。她的心脏真的是一颗黑暗纳鲁吗？', 66384),
(289704, 'zhCN', '', '你不是先锋军的人吧？我倒是不介意是谁救了我。刚才和你在一起的那位女士是谁？', 66384),
(289703, 'zhCN', '', '哦，不。又有一个传送门！', 66384),
(289700, 'zhCN', '', '我的虚空行者想我诉说了虚影风暴的事。这场飞旋的风暴充斥着疯狂和暴力。\n\n正好用它来测试一下我的本事。', 66384),
(289698, 'zhCN', '别管它了，阿拉托尔，去看看奥蕾莉亚吧。现在由我来挽救这次任务。', '', 66384),
(289694, 'zhCN', '', '攻势放缓了。做得好！', 66384),
(289693, 'zhCN', '你休想逃离……圣光。', '', 66384),
(289691, 'zhCN', '你归于圣光了！', '', 66384),
(289689, 'zhCN', '', '圣光生生不灭……', 66384),
(289686, 'zhCN', '', '圣光夺走了一切！', 66384),
(289683, 'zhCN', '我将滋养……大地。', '', 66384),
(289680, 'zhCN', '好多的……圣光！', '', 66384),
(289666, 'zhCN', '', '那些商人要么在说谎，要么就是不知道自己感染了光绽，如今他们已经将其散播到了村子各处。\n\n我们必须在感染进一步蔓延前控制住局面！', 66384),
(289655, 'zhCN', '准备出发！愿圣光保佑你！', '', 66384),
(289653, 'zhCN', '', '我很高兴你能通过试炼，$n。我的族人一向神神秘秘的，但能和你分享我们的历史真是太好了，朋友。', 66384),
(289594, 'zhCN', '', '今天天气真不错，你说呢？', 66384),
(289593, 'zhCN', '最近的光绽也离村子很远。它们是怎么一路生长到这里来的？', '', 66384),
(289592, 'zhCN', '如果你还没来得及见到阿拉托尔的话，就去找找他吧。他现在正在营地的另一侧照顾伤员。', '', 66384),
(289591, 'zhCN', '突如其来的生长也许和太阳之井的强化有关。我应该没有想错，这或许能成为先锋军的助力。', '', 66384),
(289590, 'zhCN', '光绽最初是在太阳之井复原时出现的，那是很多年前了。但它从未像现在一样如此接近文明。', '', 66384),
(289581, 'zhCN', '这里出了什么事？', '', 66384),
(289580, 'zhCN', '', '陆行鸟……横冲直撞……', 66384),
(289579, 'zhCN', '在虚影风暴中，常规的探查法术基本没用。所以我特地打造了这个调谐平台，可以用它来侦测我们现在面对的威胁。', '', 66384),
(289576, 'zhCN', '我们现在四面受敌！必须立即进行战术评估。乌布里克！$n可以协助你。', '', 66384),
(289567, 'zhCN', '好了，现在跟紧他。', '', 66384),
(289566, 'zhCN', '纳鲁陨落了！这股力量……全献给了萨拉塔斯……我却什么也得不到！', '', 66384),
(289565, 'zhCN', '', '被感染的芦塔尼在散播光绽！昂卡哪儿去了？！', 66384),
(289556, 'zhCN', '', '完成你的使命，再回到虚影尖塔，萨哈达尔。你将会得到许诺的力量。', 66384),
(289552, 'zhCN', '举手之劳。', '', 66384),
(289551, 'zhCN', '它们应该不再算是麻烦了。', '', 66384),
(289550, 'zhCN', '', '谢谢你。那些陆行鸟太可怕了！', 66384),
(289549, 'zhCN', '', '你能替我去看看先锋军的指挥官吗，$n？我必须让将军明白，太阳之井决不能沦陷。', 66384),
(289547, 'zhCN', '', '$n，你愿意跟我们一道前往吗？我们永远欢迎你的力量。', 66384),
(289414, 'zhCN', '我可怜的小猫太惨了！谢谢你。', '', 66384),
(289409, 'zhCN', '圣光会抚平伤痛的，小朋友。', '', 66384),
(289404, 'zhCN', '老头子，神灵在几十年前就不再眷顾我们了。说实话，没有他们我们反而过得更好了。', '', 66384),
(289403, 'zhCN', '', '恐惧让他们都疯了！', 66384),
(289402, 'zhCN', '<洛萨克森对此嗤之以鼻。>\n\n所有兽人都是嗜血成性的暴徒吗？所有熊猫人都是无酒不欢的武僧吗？所有精灵都是狂妄自大的势利鬼吗？\n\n成就我们的并非出身，而是自己的选择。这道理对我们纳斯雷兹姆适用，对你们凡人又何尝不是？\n\n我已经和过去一刀两断了。我不愿意满嘴谎言，变换身形，两面三刀。这绝不是圣光之道。\n\n圣光净除了我过去的污点，它的光辉令我脱胎换骨，成为了圣光先锋军的士兵。', '', 66384),
(289399, 'zhCN', '', '那个懦夫……我们很感谢你。', 66384),
(289398, 'zhCN', '', '黄昏……在召唤……', 66384),
(289397, 'zhCN', '我们要拆掉那个护盾，快！', '', 66384),
(289393, 'zhCN', '在我们朗多雷被流放的时候，奥蕾莉亚·风行者终于回到了银月城。她曾经跨越了许多世界，在永恒的时光中与恶魔抗争，那时的她只想重新感受到太阳之井的温暖。\n\n可在旅途中，她吸收了黑暗纳鲁鲁拉的精华，她所产生的转变和朗多雷如出一辙。她也变成了虚空的生物。\n\n而圣光和虚空又是紧密相连，密不可分的。\n\n在靠近太阳之井的时候，圣光与她的虚空发生了激烈的碰撞，令黑暗生物从中涌现。要不是我们最伟大的英雄在场，太阳之井可能就彻底转为虚空了。\n\n因此，许多人都希望将我们永远驱逐出境，而我们必须流亡在外。所以一定要多加小心。', '', 66384),
(289391, 'zhCN', '来！回去给萨拉塔斯报个信吧！', '', 66384),
(289388, 'zhCN', '', '这个从没见过这种光花。但裂隙会一如既往地保护我们。', 66384),
(289381, 'zhCN', '这是基姆，卖的是哈阿尔诺的庄稼。', '', 66384),
(289379, 'zhCN', '虚影尖塔确实令人畏惧。不过再坚固的建筑，也有倒塌的一天。\n\n这次也不例外。', '', 66384),
(289377, 'zhCN', '', '说实话，今天开头不太顺，但结局我很满意。再次谢谢你！', 66384),
(289375, 'zhCN', '少夸张了。你这不活得好好的，嗯？', '', 66384),
(289374, 'zhCN', '我差点就死在外面了，老头子。', '', 66384),
(289372, 'zhCN', '芦塔尼都在光明中盛放，只有孢子种会在黑暗中萌发。', '', 66384),
(289371, 'zhCN', '', '是时候让这家伙尝尝厉害了！', 66384),
(289369, 'zhCN', '', '就是那个该死的大块头把我抓到这儿来的。', 66384),
(289347, 'zhCN', '为什么陌生人前来打扰？', '', 66384),
(289330, 'zhCN', '也许吧。但那样就没意思了，别哼哼唧唧的。', '', 66384),
(289329, 'zhCN', '你们要是帮我解开，我能做得更好。', '', 66384),
(289328, 'zhCN', '我……得回去向他道谢。我之前错得太离谱了。', '', 66384),
(289327, 'zhCN', '今天你命不该绝！', '', 66384),
(289326, 'zhCN', '圣光会保护你！', '', 66384),
(289319, 'zhCN', '', '噢，圣光啊，真的是你！这——太好了！', 66384),
(289318, 'zhCN', '', '$n，你做到了。还成功救出了那名军官。', 66384),
(289317, 'zhCN', '但我必须讨回这个公道。暮光之刃必须为我妹妹的死付出代价！', '', 66384),
(289315, 'zhCN', '<麦拉的手依然紧握着利刃。>\n\n我不会再让这个地方夺走更多的同胞了。', '<麦拉的手依然紧握着利刃。>\n\n我不会再让这个地方夺走更多的同胞了。', 66384),
(289314, 'zhCN', '<赛德拉斯露出一个扭曲的微笑，随后皱着眉头捂住了身体的一侧。>\n\n我从没想过能够在另一个风行者的麾下服役。情况好像和上回没什么两样嘛。', '', 66384),
(289313, 'zhCN', '<暗谷女士怒视着洛萨克森。>\n\n算那个混球走运，奥蕾莉亚还在这里。等我们完事了，他就要为海尔兰的遭遇付出代价。', '<暗谷女士怒视着洛萨克森。>\n\n算那个混球走运，奥蕾莉亚还在这里。等我们完事了，他就要为海尔兰的遭遇付出代价。', 66384),
(289312, 'zhCN', '看来你们都完好无损啊？\n\n<他缓缓点了点头。>\n\n很好，$n。看来这小子悟到第二课了。\n\n而且没把命丢掉。', '', 66384),
(289309, 'zhCN', '等等！回来，你这个莽撞的小子！', '', 66384),
(289307, 'zhCN', '<阿拉托尔将绷带压在赛德拉斯胸前的伤口上。>\n\n如果我们迟到片刻，他就没救了。', '', 66384),
(289306, 'zhCN', '嗯。真没想到一个外来者能这么快就掌握我们的手艺。\n\n看来我这个老师当得不错。\n\n<他差点露出笑容，赞许地向你点了点头。>', '', 66384),
(289305, 'zhCN', '那个多曼纳尔的饥渴令人不安。别误会了，朋友——饥渴是撕弗鲁姆的权利。不过他也应该具备头脑，才能品出滋味来。撕弗鲁姆就像是个无底的大洞。实话实说，我觉得特泯纳斯留着他，就只是为了戏弄沱兰提亚。她可忍受不了有头脑简单的白痴身居高位。', '', 66384),
(289303, 'zhCN', '亲爱的沱兰提亚，对多曼纳尔来说真是个悲哀。你知道她曾经打算把披肩据为己有吗？特泯纳斯觉得这个企图特别滑稽，于是饶了她一命，还提拔她做了副官。沱兰提亚必须永远守护她没有实力争夺的东西。现在，去她的领域中找找吧。那个地窟里尽是渴求鲜血的野兽和软弱的虚空之子，随随便便就能解决。结果她还和垂死挣扎的凡人一样，怎么也不肯放手。', '', 66384),
(289300, 'zhCN', '闻到了吗？胧影堡垒的藏骨所传来了喜人的臭味。虽然不合我的品味，但也有着强烈的魅力。', '', 66384),
(289299, 'zhCN', '我……没看清是谁。\n\n你听我说，是真的有人来袭击。他们是从祖阿曼方向来的。\n\n除了阿曼尼还能有谁？\n\n对不对？\n\n<他移开了目光。>', '', 66384),
(289295, 'zhCN', '莱尼娅死了。\n\n<他被绑着的双手攥成拳头。>\n\n他们就像夜色中的幽魂……\n\n是阿曼尼干的，我敢肯定。\n\n既然他们杀人不分青红皂白，我又何必讲究？随便哪个阿曼尼都可以。\n\n为什么不能是他们？', '', 66384),
(289293, 'zhCN', '死了这么多人……都是暮光之刃干的？', '', 66384),
(289290, 'zhCN', '', '喂！有人在吗？谁来帮帮我！', 66384),
(289289, 'zhCN', '', '快，$n！我会为你撑住裂隙的开口，这样你就能跳进去救她了。', 66384),
(289287, 'zhCN', '我们用穿山甲的油脂混上龙鹰巢的灰，调制成油来封存光木。这就是加工光木的秘诀。\n\n如果不经处理就保存圣光，武器很快就会失效或失去圣光。面对暮光之刃，一把黯淡无光的光木武器跟普通武器没什么区别。', '', 66384),
(289286, 'zhCN', '还有一个试炼。哈加尔在前面等你。愿艾林哈籁与你同在，$n。', '', 66384),
(289285, 'zhCN', '哼。用神灵的魔法来保存圣光……这主意不错。', '', 66384),
(289283, 'zhCN', '', '自上次相遇以来，我跋涉千里，聆听着女神的声音。地表世界有太多值得学习的东西。\n\n我仍在寻找她引我来此的原因。不过……很高兴再次见到你，$p。', 66384),
(289281, 'zhCN', '', '我是哈籁尼尔的奥威娜。我的族人极少远离故土。但世界之歌在召唤我。无论女神指引我前往何方，我都会遵从。', 66384),
(289275, 'zhCN', '真是峰回路转又一波三折呀。难道是我误会了？小光人不是一向崇尚团结和沉着的吗？真是美味可口，简直太有趣了。', '', 66384),
(289273, 'zhCN', '虚空只垂涎着我们的世界，这个想法是不是太愚蠢了呢？\n\n看看我们周围吧——太阳之井的圣骑士，银月城的防御者，还有来自其他世界的人。我都认不出那些异世界俘虏的着装。\n\n虚空的贪婪没有尽头，它会毫不挑剔地吞噬一切，我们怎么可能击败这样的敌人呢？', '', 66384),
(289272, 'zhCN', '这地方的罪恶无法用语言来形容。', '', 66384),
(289271, 'zhCN', '', '准备好你的武器，$p。这个世界只认得武力——我们也必须准备好用武力回应。', 66384),
(289270, 'zhCN', '这是诚心实意的好奇，还是疑神疑鬼的猜忌？你让我很受伤啊，朋友。我对你们袒露心胸，几乎心胸大开了。\n\n掠食披肩虽然受到众人的垂涎，但它确实来之不易。萨拉塔斯会将它赐给攀登宇宙之梯、踏上累累白骨的人。\n\n唉，这是一份可怕的赐福。力量会招引力量，所有拥有它的人必须时刻保持警惕，时刻提防着前来撕咬自己的獠牙。或许这就是萨拉塔斯将它拱手相让的原因。要让仆从保持机敏，又时刻在偏执中挣扎，这不就是最好的手段了吗？', '', 66384),
(289268, 'zhCN', '这么渺小的一支军队，竟敢入侵萨拉塔斯军团的基地。这究竟是可爱的狂妄，还是可怜的挣扎？', '', 66384),
(289267, 'zhCN', '别被表面的文明给骗了。这座“庄园”和这地方的其他角落一样污秽。', '', 66384),
(289266, 'zhCN', '看看这个地方——这些尖塔，这些建筑。它们不是被建造出来的——而是被塑造出来的。土壤和岩石被虚空魔法所塑造。\n\n多曼纳尔对虚空的控制力真是非同凡响。想想我们能从他们身上学到多少东西。', '', 66384),
(289260, 'zhCN', '纯粹的奥术能量……这活儿应该不难。', '', 66384),
(289259, 'zhCN', '<哔哔睁大双眼瞪着你，随后发出了介于喇叭和汽笛之间的古怪声响。>', '<哔哔睁大双眼瞪着你，随后发出了介于喇叭和汽笛之间的古怪声响。>', 66384),
(289255, 'zhCN', '', '魔导师晨炎轻笑一声，抿了口酒。', 66384),
(289253, 'zhCN', '你的脑袋同样价值不菲。好好记住这一点。', '', 66384),
(289251, 'zhCN', '', '害命谋财的家伙居然在教训我，还真是讽刺。', 66384),
(289250, 'zhCN', '我是在守护密谋小径。你们这些人都应该这样做，而不是假装银月城容不下我们。', '', 66384),
(289248, 'zhCN', '', '当然了。阿拉蒂斯再也不会碍我的事了，况且让密谋小径的人卷入之后，你们要的价格还挺便宜。', 66384),
(289247, 'zhCN', '这些道路的安全不容有失。构造体是必要的震慑手段。', '', 66384),
(289245, 'zhCN', '', '太阳之井在上，你真的要带着那样的东西穿过这里吗？\n\n你自己看看！羽毛蓬乱，躁动不安，胆战心惊！就在你上一班巡逻之后，我花了好几个小时才让它们平静下来。', 66384),
(289244, 'zhCN', '在这场战争中，我们才是正义的！', '', 66384),
(289242, 'zhCN', '', '以圣光之名——滚开，你这畜生！', 66384),
(289241, 'zhCN', '', '这血迹还是新鲜的……等等，$n，你听到什么了吗？', 66384),
(289238, 'zhCN', '何必追根究底，你的光铸朋友不是说得很明白了吗？我们多曼纳尔仅仅只是邪恶的黑暗生物而已！\n\n我们唯一的渴望，就是看着你们凡人受尽苦难，并品尝由此产生的每一丝痛楚。\n\n我们只有邪恶的心灵，怎么可能创造出奇妙的设施、照看精美的园林，怎么可能和大家分享遥远世界的传说？\n\n<殆希莫斯身体前倾，双眼盯着你的武器，流露出了明显的欢愉。>\n\n分享那些世界的住民所掌握的绝伦工艺？\n\n不不不，我们一心只想统帅萨拉塔斯的吞噬军团，并以她的名义蹂躏那些无畏的英雄。\n\n<殆希莫斯抬起头来，露出了饥渴的狞笑。>\n\n面对如此珍馐，我们如何拒绝得了？', '', 66384),
(289235, 'zhCN', '圣光先锋军已经不堪重负了，我们连一名士兵都分不出来。\n\n图拉扬必须留下来统领全军。幸好我自己也领导过许多次深入死地的任务。\n\n我们决不能失败。', '', 66384),
(289234, 'zhCN', '', '魔导师晨炎露出微笑。', 66384),
(289233, 'zhCN', '我很乐意响应洛瑟玛的召唤，加入这次虚影风暴的突击任务，直接打击困扰着圣光先锋军的黑暗枢纽。\n\n我们会刺穿风暴，让部队摆脱纷扰。\n\n还有……\n\n<阿拉托尔转过了脸。>\n\n我母亲那边已经很久没有传来消息了。我总感觉……感觉如果我还能找到奥蕾莉亚，那一定就是在这个地方，她肯定已经在攻击萨拉塔斯了。', '', 66384),
(289213, 'zhCN', '你管这叫完美？我有个朋友为此送了命。', '', 66384),
(289212, 'zhCN', '', '我很欣慰这件小事能够完美收场。', 66384),
(289211, 'zhCN', '', '对阿拉蒂斯而言，这真是个糟糕的结局。', 66384),
(289209, 'zhCN', '', '这具尸体被啃了一半，被那群食腐的畜生撕得不成样子了。', 66384),
(289197, 'zhCN', '', '这应该是先锋军中的一员。这名士兵肯定是被人从床上拖走，然后在这峡谷里被……分食了。', 66384),
(289190, 'zhCN', '', '在刃锋穴窟与我们会合。', 66384),
(289183, 'zhCN', '欢迎来到摇篮。', '', 66384),
(289179, 'zhCN', '这小子把一桩跟我们毫不相干的命案怪到我们头上。\n\n他的妹妹是否真的死于阿曼尼之手，我说不好。但就算真是如此，也赖不到我们这儿任何一个人头上。\n\n他现在要是想不通，也许以后能想通。趁他伤心的时候，给他个机会，对我们来说不过举手之劳。', '', 66384),
(289178, 'zhCN', '把刀刃装上去，$n。握稳了，小子。', '', 66384),
(289176, 'zhCN', '赶紧打磨，孩子。别抱怨了——让$n专心干活。', '', 66384),
(289171, 'zhCN', '什么？我还被绑着呢！这样叫我怎么帮忙？', '', 66384),
(289163, 'zhCN', '是非不分的$r！你难道是疯了吗？！那东西是个怪物！你居然还帮助它逃脱了圣光的制裁！\n\n等这个任务结束，我们有的好谈了。', '', 66384),
(289162, 'zhCN', '趁卫兵还没来，赶紧回密谋小径去。$n，我们去拿报酬。', '', 66384),
(289160, 'zhCN', '捷斯，你不必——', '捷斯，你不必——', 66384),
(289159, 'zhCN', '他的人头有赏金。我会把我的那份分给大家。', '', 66384),
(289158, 'zhCN', '是的。他死了。他再也抓不了人了。', '', 66384),
(289157, 'zhCN', '魔导师死了吗？', '魔导师死了吗？', 66384),
(289153, 'zhCN', '我需要检查其他人的情况。你从他尸体上拿走想要的东西后，到楼上来找我。', '', 66384),
(289152, 'zhCN', '唔——真希望是我亲手做了他……但至少他死了。', '', 66384),
(289147, 'zhCN', '<阿拉托尔急促地呼吸着空气，满脸都是冷汗。>\n\n其实我自己刚才也没底……谢谢你，$n。', '', 66384),
(289145, 'zhCN', '一定要阻止他们！去收集散落在战场上的神圣能量，我可以用它来炸碎他们！快去！', '', 66384),
(289144, 'zhCN', '我要再捅你一刀，混蛋！', '', 66384),
(289142, 'zhCN', '我们又碰面了，$n。你还带了新老鼠来替换放掉的那些。真贴心。', '', 66384),
(289133, 'zhCN', '我……好饿……', '我……好饿……', 66384),
(289132, 'zhCN', '他承诺收我做学徒……', '他承诺收我做学徒……', 66384),
(289130, 'zhCN', '我……觉得我能走了。', '我……觉得我能走了。', 66384),
(289129, 'zhCN', '他说……会带我离开密谋小径……', '他说……会带我离开密谋小径……', 66384),
(289126, 'zhCN', '我以为自己就要死了……', '我以为自己就要死了……', 66384),
(289123, 'zhCN', '该死！把所有人从水晶里救出来。我来——萨维，快醒醒！', '', 66384),
(289122, 'zhCN', '这是什么……', '', 66384),
(289121, 'zhCN', '快来！没时间耽搁了。', '', 66384),
(289119, 'zhCN', '让他后悔把那根法杖给你。', '', 66384),
(289118, 'zhCN', '还没见到阿拉蒂斯。但我觉得结界后面有动静。保持警惕。', '', 66384),
(289116, 'zhCN', '我会全部告诉你。走吧，$n。我们有人要收拾。', '', 66384),
(289115, 'zhCN', '要是明天听到阿拉蒂斯的“趣闻”，我会很高兴的。', '', 66384),
(289114, 'zhCN', '邪能是一种工具，它们提供的力量既强大又危险。辛多雷再清楚不过了。', '', 66384),
(289113, 'zhCN', '把结界破坏者放在祭坛上。我会从这些物品中抽取魔力重新调谐它。', '', 66384),
(289112, 'zhCN', '做掉这个术士更有价值。我们只需要调谐这东西。然后破掉他的结界。', '', 66384),
(289111, 'zhCN', '一把能用的结界破坏者？那可值不少钱。', '', 66384),
(289110, 'zhCN', '', '提高警惕，$n。这些生物随时可能从任何地方冒出来。', 66384),
(289108, 'zhCN', '在这边。老规矩：你去跟他们聊天，我负责进去。', '', 66384),
(289107, 'zhCN', '最后一个目标了。这里监视更严，但我能绕过去。继续帮我分散工人的注意力。', '', 66384),
(289106, 'zhCN', '我们从这里开始。你去分散那边工人的注意力，我好潜进去。', '', 66384),
(289101, 'zhCN', '', '这片土地流淌的虚空能量预示着无限的力量。但代价是什么？', 66384),
(289100, 'zhCN', '', '我已将我们的发现告知了乌布里克。他也认为此地对我们所有人都构成威胁。\n\n但是，我们必须承受虚影风暴给我族带来的危险。\n\n这关乎艾泽拉斯的存亡。', 66384),
(289086, 'zhCN', '哈！杀了这么多，竟然连警报都没响。看来他们对这种混乱已经习以为常了。 ', '', 66384),
(289085, 'zhCN', '看起来这里的生物全部都沉浸在虚空之中，就连最微小的螨虫也不例外。保持警惕。 ', '', 66384),
(289076, 'zhCN', '而暗影也能归于圣光。我明白了，母亲。我们可以就地取材，用他们的材料来束缚并捕获那个多曼纳尔。 ', '', 66384),
(289075, 'zhCN', '', '圣光与暗影——本就是一体两面。只要推一把，圣光就能堕为暗影。', 66384),
(289071, 'zhCN', '', '对着渺小的井祈祷吧，它抵挡不了萨拉塔斯的神力！', 66384),
(289070, 'zhCN', '我们要抢的商店服务的都是银月城的权贵。意思是他们有好东西，他们损失多少金币我都不在乎。', '', 66384),
(289068, 'zhCN', '捷斯愤怒地瞪着文件，然后朝地上啐了口唾沫。', '', 66384),
(289066, 'zhCN', '不知道他叫什么名字，但我认识这个术士混蛋。他抓人好几个月了，而且那些人都没有回来。', '', 66384),
(289064, 'zhCN', '如果她觉得我会感兴趣，那就让我看看。', '', 66384),
(289062, 'zhCN', '', '阿拉托尔，$p！保护我们完成仪式！', 66384),
(289061, 'zhCN', '交给我们吧！我们会清空密室的！', '', 66384),
(289060, 'zhCN', '', '你们是仅存的先锋军战士了。', 66384),
(289059, 'zhCN', '如果要谈，那我们就去酒馆里谈。进去的时候别再找麻烦了。', '', 66384),
(289058, 'zhCN', '行了，够了。你要找我？好，现在找到了。', '', 66384),
(289043, 'zhCN', '见鬼！先锋军，后撤！', '', 66384),
(289041, 'zhCN', '', '图拉扬！我们必须到太阳之井重新集结，不然就太迟了。', 66384),
(289038, 'zhCN', '快，$p！我们需要你帮忙对付那头巨兽！', '', 66384),
(289037, 'zhCN', '阿扎伊饶了那精灵一命，很有气度。\n\n拉卡尼不明白这一点。她被怒火蒙蔽双眼，被过往的痛苦吞噬。\n\n就像那精灵小子一样。\n\n她看不到这是让他学习和改变的机会。\n\n对我们来说也是如此。', '', 66384),
(289036, 'zhCN', '', '阿扎伊就该杀了那个血精灵。\n\n这里不欢迎陌生人，尤其是那些来惹是生非的人。', 66384),
(289035, 'zhCN', '', '把这些文件副本拿去吧。请转告他，我愿意出一笔可观的酬金来解决这个麻烦。', 66384),
(289034, 'zhCN', '', '捷斯以前替我办过一些……差事。而且我恰好知道，他可能对阿拉蒂斯有着特殊的兴趣。', 66384),
(289033, 'zhCN', '我们都静不下心来，但暮光之刃正紧盯着我们的一举一动。\n\n他们步步紧逼，现在我们只要踏出营地就会遭到袭击，更别说干什么正经活了。\n\n我们暂时只能靠手头这点东西将就着了。', '', 66384),
(289032, 'zhCN', '', '你也和我一样闲得发慌，是吧？\n\n在阿扎伊允许我们把存货运到村子之前，我们都得在这儿干等着。\n\n他只是想确保我们的安全，毕竟上一批人一去不回。但我宁愿冒险面对暮光之刃，也不想在我们的族人急需这些武器时傻站在这里无所事事。', 66384),
(289030, 'zhCN', '母亲——', '', 66384),
(289029, 'zhCN', '', '看你手中的文件，我猜是阿拉蒂斯指使你这么做的。过来，我就不会召唤卫兵。', 66384),
(289028, 'zhCN', '', '啊，你终于来了。就是你这肆无忌惮的窃贼在破解我的法阵。', 66384),
(289026, 'zhCN', '为了圣光！', '', 66384),
(289025, 'zhCN', '圣光先锋军！随我冲锋！把这些入侵者赶回他们的虚空去！', '', 66384),
(289022, 'zhCN', '关键是要夺回那些文件。切勿让我失望。', '', 66384),
(289021, 'zhCN', '啊，她的防护正在衰弱。我的魔法之前无法抵达这里，但现在不同了。', '', 66384),
(289020, 'zhCN', '', '感谢圣光！你把神器夺回来了。', 66384),
(289018, 'zhCN', '', '我们不能纵容这些虚灵掠夺我们的神器！', 66384),
(289017, 'zhCN', '我们都同意这一点。阿拉托尔，坚守阵线。$p，去夺取那些武器！', '', 66384),
(289016, 'zhCN', '很好。这个导管能带你找到法阵链条中的下一环。千万别失败了。', '', 66384),
(289015, 'zhCN', '结界破坏者已与守护此处导管的奥术魔法完成调谐。使用它，护盾便会瓦解。', '', 66384),
(289014, 'zhCN', '那他就是我们的第一个目标。我们必须削弱风暴和敌人的力量！出发！', '', 66384),
(289013, 'zhCN', '', '有一群被称为“多曼纳尔”的强大存在，正以萨拉塔斯之名统领着吞噬军团。其中一个就在监控附近的节点，但我一直没法靠近。', 66384),
(289012, 'zhCN', '', '很好，因为没它你八成活不下去。现在听好了。', 66384),
(289009, 'zhCN', '阿拉托尔！你把阵型毁了。', '', 66384),
(289008, 'zhCN', '依然糟糕，不过结界破坏者的充能应该够用了。过来这边。', '', 66384),
(289007, 'zhCN', '唉，你的姿态糟糕透了。在它汲取能量时切勿移动。你会扰乱以太流的。', '', 66384),
(289006, 'zhCN', '她伪造了针对我的敲诈材料，妄图阻挠此事。你肯定看得出来，这是一桩天大的冤案。', '', 66384),
(289005, 'zhCN', '她无法适应辛多雷族面临的全新挑战。正因如此，我才主动请缨接替她的位置。', '', 66384),
(289004, 'zhCN', '如我方才所言，结界匠人由魔导师晨炎统领。她在战后接掌了这个空缺职位，但此后的表现实在令人失望。', '', 66384),
(289003, 'zhCN', '拿上这个结界破坏者，用我书房四周的能量储池为它充能。我相信这个任务对你而言并不困难。', '', 66384),
(289002, 'zhCN', '', '放心，$p，我还没疯。我和我的仆从早就习惯这种疯狂了。 ', 66384),
(289000, 'zhCN', '', '记得告诉他是萨维派你来的。别忘了我应得的那一份。', 66384),
(288995, 'zhCN', '我们根本抽不出人手！那些虚灵火炮把我们彻底压制住了。', '', 66384),
(288987, 'zhCN', '那个生物虽然力量强大，却承受着强烈的痛苦。我被愤怒压垮时也是在痛苦中盲目攻击。虚空和圣光都是一样的吗？', '', 66384),
(288981, 'zhCN', '圣光先锋军，列阵迎敌！守住大门！', '', 66384),
(288979, 'zhCN', '上马，$n。我们必须抢在圣光先锋军发起攻击前赶到大门！', '', 66384),
(288977, 'zhCN', '', '该死，他已经硬闯进来了。', 66384),
(288976, 'zhCN', '', '身手不错，不过闹剧该收场了。', 66384),
(288975, 'zhCN', '你好啊，小点心，你怎么飘到我这儿来了？', '', 66384),
(288964, 'zhCN', '图拉扬已经忘了，牺牲一切换来的胜利毫无意义。', '', 66384),
(288958, 'zhCN', '全都救出来了！感谢圣光！', '', 66384),
(288957, 'zhCN', '他们击沉了一艘船！把绳子抛给幸存者！', '', 66384),
(288956, 'zhCN', '清除空域，把能找到的幸存者都救出来！', '', 66384),
(288955, 'zhCN', '如果保护不了那些船，我们就是送船上的人民航向死亡了！', '', 66384),
(288954, 'zhCN', '<海尔兰转过头来看着你，露出了微弱的笑容。>\n\n抱歉了，等着一切结束，我会在银月城的茶会上补偿你们二位。', '', 66384),
(288953, 'zhCN', '阿拉托尔，$p！疏散人民的船遇袭了！', '', 66384),
(288951, 'zhCN', '让圣光为你领路吧。', '', 66384),
(288950, 'zhCN', '让圣光治愈你的创伤。', '', 66384),
(288948, 'zhCN', '圣光在上，免除伤痛吧。', '', 66384),
(288947, 'zhCN', '', '看那边，塔楼底部那个就是他们的首领。', 66384),
(288946, 'zhCN', '结束了，道路扫清了。', '', 66384),
(288936, 'zhCN', '来吧，$p。我们去为幸存者扫清道路！', '', 66384),
(288931, 'zhCN', '不行！我的人民岂能毫不设防！', '', 66384),
(288930, 'zhCN', '趁着还有机会，我们必须反击！', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(288929, 'zhCN', '我们去找先锋军的余部。大主教最不喜欢被辜负了。', '', 66384),
(288928, 'zhCN', '$n！这边！', '', 66384),
(288926, 'zhCN', '大主教发出了召唤，追寻荣光，不惜此身！', '', 66384),
(288925, 'zhCN', '邪恶的虚空爪牙！准备受死吧！', '', 66384),
(288924, 'zhCN', '点燃你们心中的圣火，我的同胞们！我们应召来痛击虚空！', '', 66384),
(288923, 'zhCN', '萨拉塔斯！要是我当时能摧毁那该死的匕首就好了！', '', 66384),
(288922, 'zhCN', '', '必须有人留守太阳之井！它要是沦陷就全完了！', 66384),
(288921, 'zhCN', '$n，去找阿拉托尔！我会集结先锋军，准备发起突击！', '', 66384),
(288920, 'zhCN', '我们的部队分散了，吞噬军团就要冲垮我们了！', '', 66384),
(288918, 'zhCN', '', '就算有了援军，我们也无法长久抵御吞噬军团的进攻。动作快，$p。', 66384),
(288917, 'zhCN', '在我的圣光庇佑下治疗！我们会保护你的！', '', 66384),
(288912, 'zhCN', '', '热闹看够了吗，特泯纳斯？有胆量就下来过两招！', 66384),
(288910, 'zhCN', '', '我见识过你的身手，$p。我知道你远不止这点实力。', 66384),
(288905, 'zhCN', '', '拿着，海尔兰太谦虚了。你可以告诉他这话是我说的。', 66384),
(288901, 'zhCN', '', '振作起来，朗多雷。你还没有完全屈服呢。', 66384),
(288899, 'zhCN', '是-是谁？别过来！', '是-是谁？别过来！', 66384),
(288898, 'zhCN', '你说得对，我该去和其他人坐在一起。', '你说得对，我该去和其他人坐在一起。', 66384),
(288754, 'zhCN', '', '别卖关子了。魔导师阿拉蒂斯情况如何？', 66384),
(288738, 'zhCN', '', '再吃几口……胃口真不错！这是好兆头。', 66384),
(288685, 'zhCN', '克利雅，我们必须全力抓住这个机会。', '', 66384),
(288684, 'zhCN', '在我们的研究中，谨慎从未带来过任何进展！', '', 66384),
(288683, 'zhCN', '水很新鲜，干草也堆好了，兽栏里又是稀松平常的一天。', '', 66384),
(288682, 'zhCN', '', '虚影风暴唤醒了我们体内的某种东西，马特瑞安。我们必须保持警惕。', 66384),
(288672, 'zhCN', '', '抓紧时间。我们必须在特泯纳斯回到堡垒前拿到披肩。', 66384),
(288671, 'zhCN', '借用我宠物的视野。我会告诉你削弱风暴的办法。', '', 66384),
(288655, 'zhCN', '圣光是我们对抗虚空最强大的武器。记住这点，否则你终将被腐化吞噬。 ', '', 66384),
(288654, 'zhCN', '年轻的阿拉托尔也早已证明了自己的价值。我希望在他们二人的圣光之下，你内心的暗影能够得到平衡。 ', '', 66384),
(288649, 'zhCN', '', '萨拉塔斯和她的吞噬军团袭击了奎尔丹纳斯岛的太阳之井。圣光召唤你前去相助，$p。', 66384),
(288626, 'zhCN', '', '拜托了，$n！在马特瑞安造成更大破坏之前阻止他。', 66384),
(288621, 'zhCN', '成为进步的载体是至高的科学荣誉，我们绝不能在此刻放弃。', '', 66384),
(288413, 'zhCN', '吞噬……或被吞噬……', '', 66384),
(288412, 'zhCN', '饥渴……永无……止境', '', 66384),
(288410, 'zhCN', '不！我要宰了你！', '', 66384),
(288409, 'zhCN', '终于……解脱了……', '', 66384),
(288408, 'zhCN', '凡人！你的灵魂将滋养我的造物！', '', 66384),
(288401, 'zhCN', '谢谢，奥威娜。这真是莫大的荣幸了。谢谢你带我……带我们进来。', '', 66384),
(288400, 'zhCN', '', '你所绘制的印记，将与无数个世代的前人印记留在一起。现在，你也是哈籁恩达尔的一部分了。', 66384),
(288398, 'zhCN', '你要是粗心到把同伴都弄丢了，$c。要知道，我有办法帮你找回你丢的东西。我这里提供兽栏服务。', '', 66384),
(288397, 'zhCN', '你要是粗心到把同伴都弄丢了，$c。要知道，我有办法帮你找回你丢的东西。', '', 66384),
(288396, 'zhCN', '奎尔萨拉斯虽大，但我的陆行鸟对这片天熟得很。说吧，想去哪里？', '', 66384),
(288394, 'zhCN', '', '不是每个旅行者都有资格享受这份宁静，但你……还算凑合。你就偷着乐吧。', 66384),
(288393, 'zhCN', '', '不是每个旅行者都有资格享受这份宁静，但你似乎是个例外。如果需要，就留下吧。', 66384),
(288387, 'zhCN', '哈，放马过来！这还不够我塞牙缝的。你还有什么本事？', '', 66384),
(288386, 'zhCN', '', '我们花了许多世代的时间，找到了最适合蘑菇的香料与草药配比。不过也要小心，别被刺激着了。', 66384),
(288385, 'zhCN', '呵，这里面放了什么？有点儿辛辣，但也不算太辣。', '', 66384),
(288384, 'zhCN', '嘿，有人喜欢炸药，有人喜欢腐蚀剂，也有人喜欢经典的动能。', '', 66384),
(288383, 'zhCN', '', '这是为我制作的第一批武器之一。我试过许多类型的武器，但最合适的还是爪子。', 66384),
(288362, 'zhCN', '阿玛克希说，其他的枯木食谱也会利用到毒液，她肯定很高兴能继续探索吧。每当我要尝试新的东西，她都会充满激情！\n\n<古舒喜笑颜开。>\n\n我这本世间绝无仅有的烹饪书可算是开了个好头！', '', 66384),
(288361, 'zhCN', '我尝过许多赞达拉的佳肴，但我还没尝过阿曼尼的美食！', '', 66384),
(288360, 'zhCN', '哈！如果它能经得住她那些食谱的折腾，那就没什么能毁掉它。也许我会顺道去尝尝鲜，老求知者！', '哈！如果它能经得住她那些食谱的折腾，那就没什么能毁掉它。也许我会顺道去尝尝鲜，老求知者！', 66384),
(288359, 'zhCN', '你该把它给你女儿。是叫阿玛克希，对吧？她正带着整个营地的人尝试新食谱呢。', '', 66384),
(288358, 'zhCN', '我们的东西经得起岁月的考验，带壳的。也许我们看重的是同样的东西。', '我们的东西经得起岁月的考验，带壳的。也许我们看重的是同样的东西。', 66384),
(288357, 'zhCN', '呵。这口锅……考虑到它的年代，成色好得惊人。就像我们一样！', '', 66384),
(288356, 'zhCN', '现在你要把它给我？你耍什么花样，始祖龟？你来这儿到底是为了什么？', '现在你要把它给我？你耍什么花样，始祖龟？你来这儿到底是为了什么？', 66384),
(288355, 'zhCN', '一个旧锅？你给我寄了几十封信让我来这儿，结果你发现的就是一个旧锅？', '一个旧锅？你给我寄了几十封信让我来这儿，结果你发现的就是一个旧锅？', 66384),
(288353, 'zhCN', '长老雷舍恩，我们在浅滩发现了一个被遗弃的枯木部族陶罐。我是特地来物归原主的。', '', 66384),
(288352, 'zhCN', '一个纳鲁，被萨拉塔斯的部队捕获了……我们必须想想办法，$n。', '', 66384),
(288344, 'zhCN', '', '这个始祖龟不会死的。\n\n<阿玛克希看起来有些沮丧，但脸上的笑容很是狰狞。>\n\n要是我的肠胃和他一样就好了！我能品尝多少致命的美食啊。\n\n我要探索他的极限，这样我们才能公平地吃喝！', 66384),
(288338, 'zhCN', '', '我会为你开发个食谱，让你好好感受一下它的威力。', 66384),
(288337, 'zhCN', '太有趣了！我会把它记载烹饪书里。', '', 66384),
(288336, 'zhCN', '', '有意思……它对你基本没什么效果。光是那点爆鳗浆糊，就足够麻痹我两天了。', 66384),
(288335, 'zhCN', '哇！我浑身都有刺痛感！这就是你提到的麻痹作用吗，阿玛克希？', '', 66384),
(288334, 'zhCN', '古舒咬下了一大块爆鳗野猪肉。', '', 66384),
(288333, 'zhCN', '那么，快吃吧！', '', 66384),
(288332, 'zhCN', '', '看上去很不错，你烹饪的时间够长了。', 66384),
(288331, 'zhCN', '啊，闻起来就有一股浓烈的气味！', '', 66384),
(288330, 'zhCN', '', '现在把所有食材都串起来，烹烤一会儿，让两种毒素能充分混合。', 66384),
(288329, 'zhCN', '', '我带了头野猪让你宰。我们要把爆鳗糊当佐料抹上去。', 66384),
(288328, 'zhCN', '', '现在捣碎爆皮海藻。只用叶尖，毒素大多聚在那里。', 66384),
(288327, 'zhCN', '', '先从鳗鱼胃开始。挤压它们，把所有汁水都榨出来。', 66384),
(288321, 'zhCN', '这些材料蕴含着强大的魔法能量。走吧，还剩下一个目标。', '', 66384),
(288318, 'zhCN', '幸会，$c。你在寻找什么特别的东西吗？', '', 66384),
(288306, 'zhCN', '这把剑看起来还有些能量。我们回小径吧。', '', 66384),
(288302, 'zhCN', '', '我向圣光祈求，而你回应了我的呼唤。确实，它的辉光指引你来到此地。', 66384),
(288300, 'zhCN', '', '你难道就没一个关于打架的故事吗？', 66384),
(288299, 'zhCN', '我喜欢这个故事！', '', 66384),
(288298, 'zhCN', '就这样，牛头人编出了他们最了不起的篮子。', '', 66384),
(288293, 'zhCN', '你好。你是在寻求采矿方面的指导吗？', '', 66384),
(288281, 'zhCN', '圣光与我们同在。萨拉塔斯将在此终结！', '', 66384),
(288276, 'zhCN', '', '我们祈求援助，太阳之井给出了回应。现在我们必须证明自己配得上这份恩赐。', 66384),
(288231, 'zhCN', '威南握着死敌的遗骨，带领盟友找到了一个满是魔法之尘的洞穴。在那里，遗骨被绑成了护身符——让手与心得以平衡。', '', 66384),
(288223, 'zhCN', '不留痕迹的教训很快就会被遗忘。于是威南取走了死敌的遗骨，想制成护身符作为纪念。', '', 66384),
(288222, 'zhCN', '皮开肉绽的野兽倒在威南死去的同胞身旁。他们是死于野兽的利爪，还是他自己的？ 怒火让他变得麻木，直到故乡的气息将他从深渊拉了回来。', '', 66384),
(288221, 'zhCN', '威南发现了族人遇袭的根源。于是，猎物变成了猎手，开始追逐深埋在寂静洞穴中的真相。', '', 66384),
(288220, 'zhCN', '在一场场战斗中，尖牙利爪对上了藤蔓荆棘……他们深陷于狂乱中，在疯狂的深渊边摇摇欲坠。', '', 66384),
(288219, 'zhCN', '哈籁尼尔刚踏上这片土地时，他们得到的不是迎接，而是獠牙与狂怒。这里的生物来势汹汹，却不知何故。', '', 66384),
(288215, 'zhCN', '', '直接杀了他算了。动手吧，阿扎伊。', 66384),
(288213, 'zhCN', '我们必须引导尽可能多的民众前往银月城避难。我需要你的协助，$p。', '', 66384),
(288210, 'zhCN', '<鲁玛站在一大堆零零碎碎的玩意儿和宝贝旁边。这似乎就是她想给你看的东西。\n\n鲁玛喘着气，咧开嘴笑得灿烂，眉毛弯得像天上的太阳。\n\n她凝视着你，眼神里满是期待，显然为自己的收藏品感到无比自豪。>', '<鲁玛站在一大堆零零碎碎的玩意儿和宝贝旁边。这似乎就是她想给你看的东西。\n\n鲁玛喘着气，咧开嘴笑得灿烂，眉毛弯得像天上的太阳。\n\n她凝视着你，眼神里满是期待，显然为自己的收藏品感到无比自豪。>', 66384),
(288203, 'zhCN', '我找到了一条应该有用的魔法项链。赶紧离开这里吧。', '', 66384),
(288199, 'zhCN', '有了这个装置，你就可以在相对安全的地方观察战术局势了。', '', 66384),
(288197, 'zhCN', '', '马特瑞安从来都不会放过任何一个未经验证的理论。', 66384),
(288196, 'zhCN', '勇士，很高兴再次见到你。', '', 66384),
(288194, 'zhCN', '好啦！我们要按按钮啦！都往后站！', '', 66384),
(288193, 'zhCN', '按下去！', '按下去！', 66384),
(288192, 'zhCN', '来一个！', '来一个！', 66384),
(288189, 'zhCN', '这样不对，再试一次吧。', '', 66384),
(288187, 'zhCN', '我怎么没见你出手对付那个莽夫？你这只会闻土的杂种狗！', '', 66384),
(288186, 'zhCN', '什么样的魔导师会被一只大猫吓得屁滚尿流？你这不入流的跟屁虫……', '', 66384),
(288184, 'zhCN', '莱娜曾率军抵挡军团，她的圣物怎么会是这种东西？', '', 66384),
(288183, 'zhCN', '受玛拉的英勇所启发，白银之手才得以创立。她的圣物却是一本难民的祷言集。', '', 66384),
(288182, 'zhCN', '玛尔拉德的战斗技巧举世闻名。他留下的圣物却是块冥想水晶。', '', 66384),
(288181, 'zhCN', '克罗姆保护了洛丹伦的人民。这件圣物却不是武器，而是一把锻工锤。', '', 66384),
(288180, 'zhCN', '乌瑟尔是最初的，也是最伟大的白银之手圣骑士之一。我没想到看到的不是战锤，而是治疗工具。', '', 66384),
(288172, 'zhCN', '洛萨克森，要是你想羞辱我，至少也要用点心琢磨琢磨。', '', 66384),
(288135, 'zhCN', '想要升级你的护甲或武器吗？我们有很多工匠可以为你效力。', '', 66384),
(288134, 'zhCN', '我更擅长智取而非依靠蛮力，祝你好运。', '', 66384),
(288133, 'zhCN', '这次，我同意梅雷多尔的看法。抱歉，我也帮不上忙。', '', 66384),
(288131, 'zhCN', '今天真是倒霉到家了……', '', 66384),
(288130, 'zhCN', '难以置信……', '', 66384),
(288127, 'zhCN', '', '原生山兽的子嗣已经所剩无几，我们对它们心怀敬意。欢迎来到哈籁恩达尔，蒙特。去见见我的族人吧。', 66384),
(288126, 'zhCN', '这附近不会还有棘刺熊在徘徊吧？', '', 66384),
(288125, 'zhCN', '去找奥威娜吧！我暂时没事了。好乖的小动物，好乖好乖，满身棘刺的……小熊动物。', '', 66384),
(288124, 'zhCN', '金油锅在上啊！这下总算松了口气！感谢帮助。', '', 66384),
(288104, 'zhCN', '奥威娜在安德麦帮助过我们，我想也该去拜访一下她的老家。\n\n可以这么说，我连大门都迈不过去。你或许觉得我已经习惯了，才不是呢！我每次想要挣脱，这头野兽就会咆哮起来。\n\n我打算什么也不做，看看奥威娜能想出什么点子来。', '', 66384),
(288101, 'zhCN', '嘿，朋友！我碰巧被晾在了这个地方，正盼着看到朋友的面孔呢。\n\n<加兹鲁维咧嘴而笑，做作的笑容透露着他的不快。>', '', 66384),
(288100, 'zhCN', '', '加兹鲁维来参观我的家乡了？在遇到麻烦之前，他走得倒比我预想的要远。', 66384),
(288097, 'zhCN', '', '嗯？出什么事了？', 66384),
(288075, 'zhCN', '严格来说不算是我的。不过我在这里度过的时光最长。\n\n奥术秘社是由一位比我更早期的肯瑞托法师所创建的。\n\n在远征德拉诺的艰苦岁月里，我和洛萨之子常来这儿，就当是回老家看一眼。\n\n多年来，来这儿的人越来越多，现在这里已成为一个魔法避难所，供老友和战友相聚。', '', 66384),
(288073, 'zhCN', '$p，很高兴见到你。你觉得奥术秘社如何？', '', 66384),
(288072, 'zhCN', '阿拉托尔，其实我们早就想带你看看这个地方了。总算是找着机会了。', '', 66384),
(288054, 'zhCN', '暮光之刃。我没想到他们会渗透到永歌森林。我绝不会放过他们的。\n\n他们必将为自己的恶行偿命。', '', 66384),
(288053, 'zhCN', '有眼无珠的蠢货……', '', 66384),
(288052, 'zhCN', '银月城援助了我们什么？什么也没有！', '', 66384),
(288051, 'zhCN', '', '我是……对的……吗？', 66384),
(288050, 'zhCN', '', '虚空会拯救我们！', 66384),
(288014, 'zhCN', '这些始祖龟讲的故事又臭又长。我宁愿他们跟我打一架。', '这些始祖龟讲的故事又臭又长。我宁愿他们跟我打一架。', 66384),
(288013, 'zhCN', '你光靠空谈怎么换得到故事？你要靠行动！', '你光靠空谈怎么换得到故事？你要靠行动！', 66384),
(288012, 'zhCN', '你试过旅店老板的饮料吗？我的獠牙都麻了。', '你试过旅店老板的饮料吗？我的獠牙都麻了。', 66384),
(288011, 'zhCN', '你没看见我正忙着吗，$c？', '你没看见我正忙着吗，$c？', 66384),
(288010, 'zhCN', '我没见过始祖龟。他们为什么要了解我们？', '我没见过始祖龟。他们为什么要了解我们？', 66384),
(288009, 'zhCN', '克里卡什要我给他讲个故事，但他没让我讲完。我的剑都抵在他的脖子上了！', '克里卡什要我给他讲个故事，但他没让我讲完。我的剑都抵在他的脖子上了！', 66384),
(288007, 'zhCN', '你要是想听故事，就要准备好打上一场。枯木部族可不兴花拳绣腿。', '你要是想听故事，就要准备好打上一场。枯木部族可不兴花拳绣腿。', 66384),
(288006, 'zhCN', '你需要什么吗？', '你需要什么吗？', 66384),
(287985, 'zhCN', '', '如果你受得了苦味，生长在水中的深渊之根可以帮你屏住呼吸。', 66384),
(287981, 'zhCN', '斯特吉跑向安全的地方。', '斯特吉跑向安全的地方。', 66384),
(287980, 'zhCN', '斯特吉浑身都是蓝色，就和古舒一样！但它体型很小。它需要进食，请你一定要找到她！', '', 66384),
(287954, 'zhCN', '', '你打得也不错。但别急着创造自己的传奇。', 66384),
(287953, 'zhCN', '母亲，您果然名不虚传。', '', 66384),
(287939, 'zhCN', '', '我们什么都没解决。这些芦塔尼肯定变了。我必须返回哈籁恩达尔再做调查。', 66384),
(287936, 'zhCN', '$n，去找乌布里克，我会守住这里。', '', 66384),
(287916, 'zhCN', '跟我们来吧！', '', 66384),
(287915, 'zhCN', '快！追上那只狗！', '', 66384),
(287914, 'zhCN', '……那本日记？！', '', 66384),
(287913, 'zhCN', '那是……', '', 66384),
(287912, 'zhCN', '但愿我们能有一条实在的线索，总好过现在这样捕风捉影……', '', 66384),
(287911, 'zhCN', '天才。搞不好那本日记是自己长腿跑了！', '', 66384),
(287902, 'zhCN', '$p，见到我父亲的生涯起点让我深受启发。\n\n他当年的模样——那才是我渴望成为的圣骑士。而不是他后来变成的那个样子。\n\n你愿意帮助我吗？', '', 66384),
(287890, 'zhCN', '我几乎认不出他们口中那个年轻时的图拉扬了，$p。他听起来，完全就是个我不认识的陌生人。', '', 66384),
(287883, 'zhCN', '', '其他部族为什么没有回应我们的战鼓？', 66384),
(287874, 'zhCN', '我……我是一名见习求知者！我在汇编一本食谱大全，这样就能获得第一个卷轴了。', '', 66384),
(287873, 'zhCN', '', '我们的……菜肴？怎么会？', 66384),
(287872, 'zhCN', '很好。这样我们就算认识了。求知者古舒可以向你请教美食的智慧了。', '', 66384),
(287871, 'zhCN', '', '如果父亲说你能留下来，我们就允许你扎营。你将受到我的监督。', 66384),
(287868, 'zhCN', '噢，我做梦都不敢想，小家伙。我们要耐心等待。', '', 66384),
(287866, 'zhCN', '', '别动！', 66384),
(287865, 'zhCN', '去找枯木部族的长老雷舍恩。这肯定是一场误会。', '', 66384),
(287864, 'zhCN', '', '一封信？我们的长老可没说过允许这种背着大壳的入侵者待在这儿。你必须离开！', 66384),
(287863, 'zhCN', '别慌，朋友们。我们有你们长老的信函，准许我们研究这里的神器。', '', 66384),
(287858, 'zhCN', '长老雷舍恩自顾自地笑着。', '长老雷舍恩自顾自地笑着。', 66384),
(287857, 'zhCN', '', '肮脏的暴发户！你会像其他人一样流血而死。', 66384),
(287854, 'zhCN', '一个凡人救世主，在这里？看来我们还有希望。', '一个凡人救世主，在这里？看来我们还有希望。', 66384),
(287852, 'zhCN', '始祖龟可以留下。和我一样倔强的家伙可不常见啊！', '始祖龟可以留下。和我一样倔强的家伙可不常见啊！', 66384),
(287851, 'zhCN', '这就是你想要的结果吗，萨哈达尔？', '这就是你想要的结果吗，萨哈达尔？', 66384),
(287848, 'zhCN', '虚空连自己人都会吞噬。我们已经一无所有了。', '虚空连自己人都会吞噬。我们已经一无所有了。', 66384),
(287847, 'zhCN', '那个始祖龟是认真的？他真的跑来这儿露脸了？\n\n<长老雷舍恩开怀大笑。>\n\n他不停地给我寄信！而我一直不理他。后来我终于向他发起挑战，让他别等什么批准，爱干什么就干什么。结果他说他偏要等！\n\n这叫人怎么拒绝？我就给他寄了“批准信”。我好多年没写过这东西了！\n\n他赢得了我的尊重。求知者可以随心所欲。但枯木部族会盯着那些始祖龟——就像我们盯着领地里所有的访客一样。', '那个始祖龟是认真的？他真的跑来这儿露脸了？\n\n<长老雷舍恩开怀大笑。>\n\n他不停地给我寄信！而我一直不理他。后来我终于向他发起挑战，让他别等什么批准，爱干什么就干什么。结果他说他偏要等！\n\n这叫人怎么拒绝？我就给他寄了“批准信”。我好多年没写过这东西了！\n\n他赢得了我的尊重。求知者可以随心所欲。但枯木部族会盯着那些始祖龟——就像我们盯着领地里所有的访客一样。', 66384),
(287845, 'zhCN', '我能帮你什么忙吗，$c？', '我能帮你什么忙吗，$c？', 66384),
(287833, 'zhCN', '你要让那些闯入者，那些入侵者，在阿塔阿曼作战？', '', 66384),
(287831, 'zhCN', '', '我们需要战士来保护城市。祖尔加，除了他们还有谁能帮我们？', 66384),
(287826, 'zhCN', '', '我将与神圣遗物学会的成员一同深入敌军腹地。你有什么需要吗？', 66384),
(287808, 'zhCN', '真是美味。离完全解锁披肩已经成功了一半。', '', 66384),
(287807, 'zhCN', '吞噬它。感受她的权柄化为你的力量。', '', 66384),
(287701, 'zhCN', '', '请准许我们进入祖阿曼！暮光信徒已经在我们的边境聚集，我们不能再等了！', 66384),
(287693, 'zhCN', '', '光绽会夺走生命，再重新生长。不能放任这个恶性循环继续存在了。', 66384),
(287692, 'zhCN', '', '看来，如果没人能够保护符文石，就连它们也无法阻止光绽的爆发。', 66384),
(287691, 'zhCN', '', '这些植物的生长都是被强迫的，但我不知道其中的缘由。', 66384),
(287605, 'zhCN', '', '夏安娜犹豫了。', 66384),
(287604, 'zhCN', '', '我侄女？好，我会去的。', 66384),
(287603, 'zhCN', '而且，这也是你侄女的第一次狩猎。', '', 66384),
(287602, 'zhCN', '全家一起狩猎，你当然是我的家人。', '', 66384),
(287601, 'zhCN', '', '你们会欢迎我吗？', 66384),
(287600, 'zhCN', '下个月，我要在我的那片森林里狩猎了。你愿意一起来吗？', '', 66384),
(287599, 'zhCN', '', '我很抱歉，我没给过你帮助我的机会。', 66384),
(287598, 'zhCN', '我很抱歉，我把你和她一起抛下了。', '', 66384),
(287597, 'zhCN', '', '现在向火焰倾诉我们的遗憾。告诉它那些我们在她生前没来得及说的话。', 66384),
(287596, 'zhCN', '', '他们从没相信过我。', 66384),
(287595, 'zhCN', '你没和他们说过？', '', 66384),
(287594, 'zhCN', '', '部族依然爱着她。', 66384),
(287593, 'zhCN', '那我们为什么还要用这种方式纪念她？', '', 66384),
(287592, 'zhCN', '', '只有安慰人的谎话而已。', 66384),
(287591, 'zhCN', '她走的时候……有什么遗言吗？', '', 66384),
(287590, 'zhCN', '', '她病了。我们知道她难逃一死，只是时间问题。', 66384),
(287589, 'zhCN', '她是怎么死的？', '', 66384),
(287588, 'zhCN', '', '因为我知道，这样她就没法再害你了。', 66384),
(287587, 'zhCN', '因为你不用再给我收拾烂摊子了吧？', '', 66384),
(287586, 'zhCN', '', '不。她变本加厉了。但实话实说，我很高兴你选择了离开。', 66384),
(287585, 'zhCN', '我走之后，她有变得好一点吗？', '', 66384),
(287584, 'zhCN', '其实还挺好的，我日子过得不错。', '', 66384),
(287583, 'zhCN', '', '森林里的生活怎么样？', 66384),
(287582, 'zhCN', '', '但看着我为你挡下的每一道伤疤，我依然感到自豪。', 66384),
(287581, 'zhCN', '', '没有。', 66384),
(287580, 'zhCN', '你被我连累而受罚的时候，你想过我会有多么愧疚吗？', '', 66384),
(287579, 'zhCN', '', '你是我的弟弟，我有责任保护你。', 66384),
(287578, 'zhCN', '你也一样。', '', 66384),
(287577, 'zhCN', '我就知道有些事情永远不会改变。', '', 66384),
(287576, 'zhCN', '', '伊兹肯，采集孢子的时候要小心，你也不想惹恼那些野猪吧。', 66384),
(287533, 'zhCN', '嗷，哈，哈哈哈。', '', 66384),
(287532, 'zhCN', '哦，这东西倒真有点意思。', '', 66384),
(287531, 'zhCN', '别，别这样。你都表现成这样了，我还怎么拒绝你呢？', '', 66384),
(287530, 'zhCN', '仁慈在这里可行不通。不过，你的好意我心领了。', '', 66384),
(287529, 'zhCN', '哦？那我们就开始吧。', '', 66384),
(287511, 'zhCN', '帮忙？还是来确保我们守规矩，别自相残杀？', '', 66384),
(287510, 'zhCN', '', '我没想到你会现身。这位是来帮忙举行仪式的。', 66384),
(287509, 'zhCN', '我听说母亲去世了。这个$r是？', '', 66384),
(287508, 'zhCN', '', '弟弟，是你吗？', 66384),
(287491, 'zhCN', '让大海把我们留下的痕迹都冲干净。', '让大海把我们留下的痕迹都冲干净。', 66384),
(287490, 'zhCN', '没错！让它沉到海底去。', '没错！让它沉到海底去。', 66384),
(287489, 'zhCN', '赶紧把东西扔下船！我们担不起被发现的风险。', '赶紧把东西扔下船！我们担不起被发现的风险。', 66384),
(287472, 'zhCN', '正是。我们在这儿多耽搁一分钟，就多一分危险。', '正是。我们在这儿多耽搁一分钟，就多一分危险。', 66384),
(287464, 'zhCN', '真有意思，只要有人一问起来，他们的货就立马人间蒸发了。', '真有意思，只要有人一问起来，他们的货就立马人间蒸发了。', 66384),
(287462, 'zhCN', '嗯。我可不想成为他们茶余饭后的谈资。', '嗯。我可不想成为他们茶余饭后的谈资。', 66384),
(287446, 'zhCN', '这里的兽人和食人魔早就是我们的心腹大患了，$p。', '', 66384),
(287438, 'zhCN', '你带来了什么？', '', 66384),
(287422, 'zhCN', '', '唔，比如太阳之井上空变成漩涡的时候？……不好意思，我有些手足无措了。', 66384),
(287411, 'zhCN', '这个谜题肯定就是逃出生天的关键。', '', 66384),
(287408, 'zhCN', '在哈籁提赶到前，我们只能寄希望于减少损失了。森林或许只有彻底毁灭这一个下场。\n\n不过，现在来了这么多哈籁尼尔，还有他们的艾林戏法，我们真有机会击退这股疯狂了。', '', 66384),
(287406, 'zhCN', '', '议会回绝了我们的号召，哈籁提不会与光绽抗衡。\n\n但我可以，我一定会挺身而出。有了艾林之尘，我们可以抵御那股影响。', 66384),
(287405, 'zhCN', '哎呀呀，你们还真是弄得一团糟啊。', '', 66384),
(287402, 'zhCN', '你看什么看？', '你看什么看？', 66384),
(287380, 'zhCN', '', '$p，洛瑟玛派我来帮你对付那个鼠辈。', 66384),
(287371, 'zhCN', '一个虚空样本！去找找还有没有别的。', '', 66384),
(287367, 'zhCN', '安忒诺里安总督主动联系我，为我的虚影风暴研究提供了这个场地。\n\n看来至少还有人能认清大局。这场危机威胁着我们所有人。', '', 66384),
(287333, 'zhCN', '$n，希望你能帮忙打扫和送货。阿拉托尔可以帮我干活，有些事情需要更多帮手。', '', 66384),
(287332, 'zhCN', '我先行告辞了，我必须找到伊崔格，还有些事情要去安排。', '', 66384),
(287330, 'zhCN', '', '我已经看够了，马特瑞安。这些手段实在太过分了。', 66384),
(287329, 'zhCN', '', '去查清楚是哪家公司在糟蹋这片海岸。查到了就回来告诉我。', 66384),
(287294, 'zhCN', '', '我必须赶回去向乌布里克禀报，以免更多朗多雷遭遇同样的命运。Shorel\'aran。', 66384),
(287293, 'zhCN', '', '做了这么多研究，我却没能预见到最坏的结果。感谢你的帮助，$n。', 66384),
(287292, 'zhCN', '', '必须让长老得知此事。随风同行吧！', 66384),
(287291, 'zhCN', '', '眼前的景象令我心痛不已，我美丽的家园，不在了……', 66384),
(287290, 'zhCN', '', '疯狂已经掌控了根须，我们必须在这儿阻止它。', 66384),
(287279, 'zhCN', '女神已不再栖居于摇篮里了，但她的影响依然存在。艾林裂隙是个极为危险的地方，不适合哈籁尼尔进入。\n\n我斩断了女神的联系才得以在此侍奉。除非你想在下面的裂隙中立马丧命，否则最好听我的劝。', '', 66384),
(287263, 'zhCN', '那我们就毁了他们，虚灵会为我们提供军火。', '', 66384),
(287257, 'zhCN', '我太蠢了。你们只是普通人——和我们没什么两样。那晚发动袭击的是暮光之刃！', '', 66384),
(287244, 'zhCN', '我就差那么一点点。卡茜雅……她的笔记试图从虚影风暴中汲取什么。我觉得能逆转通道把我们送进去，但这些页面根本不完整。缺失的部分太多了。\n\n我需要那些遗失的页面……而且我非常确定偷走它们的是谁。', '', 66384),
(287238, 'zhCN', '我们才是顶级捕食者，我们即是虚空！', '', 66384),
(287230, 'zhCN', '鲜血……\n\n虚空……\n\n顶级捕食者……\n\n我们终于明白了一切是如何联系在一起。我们此刻终于领悟了自己的使命。', '', 66384),
(287227, 'zhCN', '风中低语着力量的许诺。\n\n而我向来不拒绝送上门的好处。', '', 66384),
(287179, 'zhCN', '援军就交给我们了，你和瓦莉拉一起去！', '', 66384),
(287177, 'zhCN', '我相信你，$n。去找到安忒诺里安，取回我们要的信息，再消灭他。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(287172, 'zhCN', '卡茜雅的研究涵盖了协助银月城所需的前几个步骤。我敢用性命打赌，后面几页都被安忒诺里安抢走了。', '', 66384),
(287171, 'zhCN', '烈焰之翼重振翱翔！\n\n加亚莱划破天空，多年来第一次为我们心中注入温暖。她的余烬指引着我们的兵刃，与阿曼尼并肩，直刺那些阴影笼罩的敌人心脏！', '', 66384),
(287170, 'zhCN', '很高兴再见到你，$p。\n\n哈尔拉兹已经为你向长老求情了。我很感激能再次为我们帝国的荣光举起武器。', '', 66384),
(287169, 'zhCN', '', '我是佩尔娜，人称“断齿”，恶齿部族战士。\n\n无论这些年发生了什么，在内心深处，我们从未忘记根在祖阿曼。\n\n我们要为保卫家园而战！', 66384),
(287165, 'zhCN', '这个巢……被光绽增生扼杀了。我们要帮它脱困。', '', 66384),
(287164, 'zhCN', '啊！看起来……闻起来，是本地的宠物在给地盘留下标记。它们显然非常焦虑。', '', 66384),
(287163, 'zhCN', '这里的树丛被践踏过，可怜的动物肯定吓坏了。', '', 66384),
(287076, 'zhCN', '不，这个从没见芦塔尼有过那种行为。', '', 66384),
(287049, 'zhCN', '护身符就此诞生了，它既是警告，也是提醒。我们不能局限于本能。', '', 66384),
(287038, 'zhCN', '', '永歌森林的圣光居然会在哈籁恩达尔引发这样的浩劫。', 66384),
(287033, 'zhCN', '不！就差那么一点……', '', 66384),
(287028, 'zhCN', '$n！把虚空碎片带到中央传送门。如果我没想错，这样就可以反转通路，开启进入往虚影风暴的路。', '', 66384),
(287027, 'zhCN', '我们要修好这个老旧的构造体，再消灭所有密教徒。', '', 66384),
(287026, 'zhCN', '我会最后一次尝试破解卡茜雅的笔记。它们或许就是揭露虚影风暴秘密的钥匙。', '', 66384),
(287024, 'zhCN', '想跑？胆小鬼！这胜利本该是我们的！', '', 66384),
(287005, 'zhCN', '我的族人将回忆、经历和智慧注入了这些墙壁。\n\n等你准备好了就触碰壁画吧。', '', 66384),
(287004, 'zhCN', '触碰这些画，其中艾林之尘会让它揭示我们的真理。', '', 66384),
(287003, 'zhCN', '', '愿艾林哈籁指引你。祝你好运。', 66384),
(286998, 'zhCN', '这张永歌森林的地图上标出了暮光之刃的目标……其中还有风行村！', '', 66384),
(286970, 'zhCN', '', '长老已经发话了。他们希望你能重温过去，并意识到你行为的愚蠢。', 66384),
(286969, 'zhCN', '谢谢你让我认清了真正的敌人是谁，也让我学会做事要三思而后行。', '', 66384),
(286961, 'zhCN', '立刻到大巢穴去！议会将决定你的命运。', '', 66384),
(286957, 'zhCN', '难以置信。$n，快来看。', '', 66384),
(286956, 'zhCN', '真是不可思议，林根之路的尽头居然还有一个世界。哈籁恩达尔能在无数个世纪中保持隐秘，这着实是了不起的壮举。\n\n虽然我们的主要目标还是光绽，但我不得不承认，我确实很有兴趣了解哈籁尼尔和这个世界之中的世界。', '', 66384),
(286955, 'zhCN', '奥威娜太急躁、太鲁莽了。她在哈籁恩达尔之外见过那些事之后，现在肯定也会同意了。\n\n遗憾的是，长老们可能又有些太谨慎了。', '', 66384),
(286895, 'zhCN', '部落早就抛下了这段黑暗的过去。要是这些人当时和我们同行就好了。', '', 66384),
(286884, 'zhCN', '', '跟我来，精灵。我们靠近点，分散他的注意力。', 66384),
(286883, 'zhCN', '过来这边，$n！我来装箭，你负责射击。', '', 66384),
(286878, 'zhCN', '躲到旅店里去。那里安全！', '', 66384),
(286838, 'zhCN', '', '$p，萨拉塔斯和她的吞噬军团正在围攻太阳之井。圣光选择了你来保护它。', 66384),
(286837, 'zhCN', '啧！黑暗部落。他们还妄想着打赢第二次战争，我们连第四次战争都讲和了。就不能与时俱进吗！', '', 66384),
(286836, 'zhCN', '走吧，库德兰，我们要去侦察其它的黑暗部落营地。', '', 66384),
(286828, 'zhCN', '相信奥威娜的人比她想象得更多。我愿追随她奔赴天涯海角。', '相信奥威娜的人比她想象得更多。我愿追随她奔赴天涯海角。', 66384),
(286827, 'zhCN', '我准备好战斗了！它们休想腐化我挚爱的哈籁恩达尔。', '我准备好战斗了！它们休想腐化我挚爱的哈籁恩达尔。', 66384),
(286826, 'zhCN', '我们必须尽力保护生态系统。', '我们必须尽力保护生态系统。', 66384),
(286825, 'zhCN', '这诡异的光绽是怎么在我们的土地上蔓延的？我一直以为哈籁恩达尔很安全啊。', '这诡异的光绽是怎么在我们的土地上蔓延的？我一直以为哈籁恩达尔很安全啊。', 66384),
(286824, 'zhCN', '我不想和这些可怜的芦塔尼一样被赶出家园。我想要帮助他们。', '我不想和这些可怜的芦塔尼一样被赶出家园。我想要帮助他们。', 66384),
(286813, 'zhCN', '要么别打扰我们干活，要么就拿起斧头过来帮忙。', '', 66384),
(286811, 'zhCN', '这小子正经历的考验会磨练他的性格，他正需要这个。\n\n不过你得确保他别在这个过程中把自己害死。这愚蠢的小子……', '', 66384),
(286809, 'zhCN', '我来这里是为了复仇。\n\n结果找到了意想不到的答案。\n\n谢谢你，$n。要不是你出手相救，我的愚蠢可能早就让我送命了。', '', 66384),
(286808, 'zhCN', '<凯罗浑身是血，伤痕累累，微弱地呻吟着，几近昏迷。>', '', 66384),
(286807, 'zhCN', '你……你是来救我的？我猜是那个老木匠派你来的……', '', 66384),
(286804, 'zhCN', '', '这个觉醒了，这个不再改变了。', 66384),
(286750, 'zhCN', '保险箱里的是什么？', '', 66384),
(286749, 'zhCN', '能救的人都得救了，可我的研究……', '', 66384),
(286748, 'zhCN', '从头到尾，安忒诺里安一直比我抢先两步。我们还是先回书房吧。', '', 66384),
(286745, 'zhCN', '', '真好骗！', 66384),
(286743, 'zhCN', '你没事！你见过乌布里克吗？', '', 66384),
(286740, 'zhCN', '去保护好平民，我会找到安忒诺里安……让他付出代价。', '', 66384),
(286739, 'zhCN', '我不会放任密教徒夺走这座镇子！', '', 66384),
(286725, 'zhCN', '这个的许多朋友在光花里没了。如果这能带来希望，这个愿意听。', '', 66384),
(286708, 'zhCN', '', '你来了。不幸的是，我们的恐惧不是空穴来风。', 66384),
(286702, 'zhCN', '', '欢迎来到我的家园，哈尔玛拉。我曾是泰达希尔的护根者，但那段岁月已成往事。', 66384),
(286700, 'zhCN', '', '艾林之尘。也许就是它使昂卡没受到光绽的影响。', 66384),
(286699, 'zhCN', '这颗种子……外面裹着……', '', 66384),
(286698, 'zhCN', '', '我们会留下来保护哈加尔和其他人。', 66384),
(286695, 'zhCN', '', '你消灭了众多的恶性增生，这些哈阿尔诺的杂草将会滋养大地。\n\n希望战斗能够彻底结束。', 66384),
(286693, 'zhCN', '噢，女神啊……', '', 66384),
(286681, 'zhCN', '我要亲手结果祖尔加的性命！', '', 66384),
(286677, 'zhCN', '', '太阳之井重新点燃后的某个时候，光绽便出现了。起初只是零散的异常生长斑块——本来没什么可担心的。当圣光通过太阳之井注入我们体内时，似乎也同样注入了植物群落。确实非常神奇！\n\n我们向来能够塑造周围的森林，但光绽似乎更加顽固。它更狂野，更难驯服——就好像拥有自己的意识……当然这种想法很荒谬。它们终究只是植物罢了。植物哪会思考。', 66384),
(286666, 'zhCN', '', '欢迎来到晴风村。', 66384),
(286656, 'zhCN', '我到哈阿尔诺的时间没比你早多久。这里显然遇到大麻烦了。我们要做不少事情才能缓解周围的苦难。\n\n究竟是怎么走到这个地步的？', '', 66384),
(286645, 'zhCN', '', '图尔阿玛。\n\n<她指了指自己。>\n\n我的工作，保护兄弟姐妹。带他们回家。', 66384),
(286641, 'zhCN', '去收集艾林之尘，$p。动作快。', '', 66384),
(286640, 'zhCN', '不……愤怒控制了我……吞噬了我。我绝不……绝不能……让这种事再发生。', '不……愤怒控制了我……吞噬了我。我绝不……绝不能……让这种事再发生。', 66384),
(286632, 'zhCN', '用龙鹰灰油将圣光保存在木材的纹理中。', '', 66384),
(286612, 'zhCN', '', '这个见过很多花。能开花是好事，对吧？', 66384),
(286595, 'zhCN', '', '一旦我们开始仪式，萨拉塔斯就会向这个入口派遣军队阻挠我们。\n\n在仪式完成前，你必须挡住他们。', 66384),
(286594, 'zhCN', '那些虚空魔法斗篷……我以前见过！', '', 66384),
(286593, 'zhCN', '', '我们并未抛弃阿曼尼。是阿曼尼背叛了我们。\n\n妖术领主玛拉卡斯蛊惑督军祖尔金，要他不择手段地打造强大的战士。\n\n他们找到了一种亵渎神明的方法，抽取我们的力量灌注到四个阿曼尼化身体内。像你一样的闯入者阻止了他们——他消灭了那些化身、玛拉卡斯和祖尔金。\n\n我舍弃了自己的神庙。哈尔拉兹遁入迷雾养伤；加亚莱受创最重，其火焰在玛拉卡斯的吞噬下彻底熄灭。纳洛拉克化身为愤怒本体，只有在山峦深处长眠才能获得安宁。\n\n若祖尔加拉想成为哈谢并摧毁暮光之刃，就需要我们所有洛阿神灵的祝福——而非仅仅是我一个。\n\n洛阿神灵与阿曼尼的纽带必须重新巩固。', 66384),
(286591, 'zhCN', '', '我将阿曼尼视如己出。但孩子们有时会走上歧路。', 66384),
(286576, 'zhCN', '谁能想到，世界之树根系的核心竟藏着一个完整的世界，实在令人叹为观止。', '', 66384),
(286565, 'zhCN', '', '暗影之握！虚空控制了他！', 66384),
(286561, 'zhCN', '', '马特瑞安，我们追寻这头野兽太久了。我们应该回去禀报了。', 66384),
(286527, 'zhCN', '暗影会……吞没你……', '', 66384),
(286526, 'zhCN', '好极了……等等，那边在闪光的是什么？', '', 66384),
(286525, 'zhCN', '我对虚影风暴的研究……都被暮光之刃偷走了！', '', 66384),
(286517, 'zhCN', '到目前为止这趟旅程很有收获，$p。准备好继续下一段了吗？', '', 66384),
(286516, 'zhCN', '谢谢你，德兹科。我很钦佩你在这里所做的一切。我一定会回来的。', '', 66384),
(286515, 'zhCN', '现在我必须借走阿拉托尔和$n了。最后一件圣物的安排已经完成了。', '', 66384),
(286499, 'zhCN', '不，克利雅。我们听懂了那些低语，明白它们许下的承诺。', '', 66384),
(286490, 'zhCN', '金属废料都已经清理干净了！我们要用残渣做些有用的东西。', '', 66384),
(286487, 'zhCN', '', '我从小到大就没回过那座神庙。那里除了飞鸟和荆棘，什么都没有。', 66384),
(286478, 'zhCN', '', '让我直面灵魂深处潜藏的羞耻吧。', 66384),
(286462, 'zhCN', '没错。天黑前我们必须赶回码头，多待一刻都可能出变故。', '没错。天黑前我们必须赶回码头，多待一刻都可能出变故。', 66384),
(286461, 'zhCN', '他们的账本是挺干净，可背地里干的勾当，比船底的污水还脏。', '他们的账本是挺干净，可背地里干的勾当，比船底的污水还脏。', 66384),
(286459, 'zhCN', '最好别跟他们掺和。那帮家伙的嘴，比洛瑟玛的钱袋子还松。', '最好别跟他们掺和。那帮家伙的嘴，比洛瑟玛的钱袋子还松。', 66384),
(286448, 'zhCN', '$p！骑上来！撤回太阳之井！', '', 66384),
(286435, 'zhCN', '别解开他的镣铐，让他折腾个够吧。', '', 66384),
(286434, 'zhCN', '别急于求成，要专注，细节之处见真章。', '', 66384),
(286433, 'zhCN', '拉卡尼想要那精灵的命。\n\n在你来之前，那小子确实闹出了不小的动静。不过说实话，他对我们没什么威胁，不过是个农夫家的孩子——和我们一样的平民。\n\n即便如此，如果他戴着镣铐跟不上你，沦为敌人的猎物，那也是他命该如此。', '', 66384),
(286412, 'zhCN', '', '让他们过去。$c身上沾的，是我们敌人的血。', 66384),
(286404, 'zhCN', '继续前进！不要向黑暗屈服！', '', 66384),
(286397, 'zhCN', '', '懦弱的孩子！你接受帮助，不过是因为你害怕独自一人！', 66384),
(286388, 'zhCN', '', '前进！我们要把暗影赶回去！', 66384),
(286387, 'zhCN', '恰恰相反。我们要去见一个正在广行善举的人。这也正是我未能做到的事。', '', 66384),
(286386, 'zhCN', '落锤镇？和炽焰黎明有关吗？', '', 66384),
(286374, 'zhCN', '', '欢迎。你的最终试炼就在下方。\n\n如果你能活下来，我的族人就会接纳你。准备好开始了，就进入地下堡吧。', 66384),
(286368, 'zhCN', '', '多亏了艾林之尘。这是我们将其奉为圣物的原因之一。', 66384),
(286367, 'zhCN', '这些画……我从没见识过这样的魔法。', '', 66384),
(286366, 'zhCN', '这原本不该发生的！我们快走。', '', 66384),
(286361, 'zhCN', '我们的渴望得到了回应，世界的深处传来了歌声。', '', 66384),
(286360, 'zhCN', '我们必须继续了解。', '', 66384),
(286359, 'zhCN', '稍等——这根桩子不太听话。', '', 66384),
(286356, 'zhCN', '谢谢你帮助落锤镇，$p。', '', 66384),
(286355, 'zhCN', '', '祖尔加……不……', 66384),
(286354, 'zhCN', '', '第一滴血由你们流下，去死吧！', 66384),
(286353, 'zhCN', '我可以用卡德加借我的这本魔典，开一道回银月城的传送门，$p。', '', 66384),
(286337, 'zhCN', '永远都没有尽头吗？总会有人继续将怨恨奉为教义。', '', 66384),
(286336, 'zhCN', '这把剑是在十字军堕入仇恨前就铸成的。也许它应该回到一位真正秉持正义的主人手里。', '', 66384),
(286335, 'zhCN', '这些新兵要永远依靠仇恨来唤起圣光吗？', '', 66384),
(286333, 'zhCN', '圣光……会为十字军择示……新的领袖……', '', 66384),
(286331, 'zhCN', '你们这些异端竟敢妨碍我的圣礼？', '', 66384),
(286330, 'zhCN', '走吧！你要是愿意投降，就交出武器，离开这个鬼地方，再也别回来。', '', 66384),
(286329, 'zhCN', '', '入侵者……为十字军英勇就义的时刻到了。', 66384),
(286328, 'zhCN', '还有谁能教他们……圣光的教义？', '', 66384),
(286327, 'zhCN', '我要让这些新兵看看怎么惩戒不信者！', '', 66384),
(286326, 'zhCN', '', '事情都发生过，事情都将会发生，我就是这么说的。', 66384),
(286324, 'zhCN', '', '我们的根须会在莎拉达希尔附近休养生息。我的林地会复苏的。', 66384),
(286323, 'zhCN', '', '我们的家园闪耀着光芒，对芦塔尼很危险。我们会等到光明熄灭了再回去。', 66384),
(286322, 'zhCN', '', '我是芦塔尼的尊者，我是林地的代言人。', 66384),
(286311, 'zhCN', '太阳之井是圣光的导体！穆鲁牺牲了自己，造就了这一口圣井！', '', 66384),
(286310, 'zhCN', '', '我现在可以听到女神的声音，但它轻如耳语。舒尔卡怎么忍受得了这样的空虚？', 66384),
(286308, 'zhCN', '', '虚影风暴出现后，我们又在南边折损了三名斥候！', 66384),
(286307, 'zhCN', '', '你是什么人……你来这里做什么？', 66384),
(286305, 'zhCN', '新来的？太棒了！', '', 66384),
(286303, 'zhCN', '', '我很久没在塔奎林见过如此紧张的气氛了。', 66384),
(286302, 'zhCN', '', '祖尔加，不管有没有光木，我们的同胞都需要援手。你带上那个精灵去找幸存者。', 66384),
(286300, 'zhCN', '行吧，$C，拿上武器。把你碰到的阿曼尼都武装起来。', '', 66384),
(286288, 'zhCN', '在虚影风暴的无尽深渊面前，我们深知绝望是何种滋味。\n\n阅读这份传单便是你觉醒的第一步。\n\n继续南行吧，疲惫的朝圣者。塔奎林不过是旅途中的歇脚地。\n\n我们敬爱的领袖将为我们指引前路。', '在虚影风暴的无尽深渊面前，我们深知绝望是何种滋味。\n\n阅读这份传单便是你觉醒的第一步。\n\n继续南行吧，疲惫的朝圣者。塔奎林不过是旅途中的歇脚地。\n\n我们敬爱的领袖将为我们指引前路。', 66384),
(286287, 'zhCN', '风暴步步逼近，银月城却袖手旁观。我们必须自力更生，掌握自己的命运。\n\n塔奎林为你准备了一席之地。团结起来，我们将获得安全。联合一心，我们将守护同胞。\n\n如果你有兴趣，请到安忒诺里安总督府咨询。\n\n欢迎所有人加入。有军事经验者尤佳。', '风暴步步逼近，银月城却袖手旁观。我们必须自力更生，掌握自己的命运。\n\n塔奎林为你准备了一席之地。团结起来，我们将获得安全。联合一心，我们将守护同胞。\n\n如果你有兴趣，请到安忒诺里安总督府咨询。\n\n欢迎所有人加入。有军事经验者尤佳。', 66384),
(286286, 'zhCN', '<一份欢迎手册，附带城镇地图。几处要地被特别标注：总督府、守卫前哨和乌布里克的实验室。>\n\n塔奎林欢迎所有新来者！你是来寻求和平吗？还是寻求安全？追寻真相？\n\n我们承诺为你提供这一切，而且不止于此。\n\n总督十分重视你的关切！他在密切关注着我们所有人！', '<一份欢迎手册，附带城镇地图。几处要地被特别标注：总督府、守卫前哨和乌布里克的实验室。>\n\n塔奎林欢迎所有新来者！你是来寻求和平吗？还是寻求安全？追寻真相？\n\n我们承诺为你提供这一切，而且不止于此。\n\n总督十分重视你的关切！他在密切关注着我们所有人！', 66384),
(286262, 'zhCN', '我才不管那些巨魔怎么说呢。\n\n他们根本不是什么伐木工——而是一群恶魔。\n\n他们趁着夜色杀害了我的妹妹，烧毁了我家的农场！\n\n是啊是啊，你们人人都想给我上一课。可让我赤手空拳、被绑着上战场，这能学到什么教训？\n\n你们分明就是想让我去送死。', '', 66384),
(286261, 'zhCN', '趁现在还来得及，救我出去。', '', 66384),
(286257, 'zhCN', '托伦多派你来查问光木武器为何迟迟未到？那你可来对地方了。\n\n暮光之刃发现了我们的营地，他们知道我们在给阿曼尼提供强力的光木武器，于是就不停地袭击我们，打断我们的工作。\n\n现在又冒出这么个小子冲进我们的营地，嚷嚷着他妹妹的事。我连应付暮光之刃的时间都没有，更没空照看什么精灵农夫家迷路的愤怒小鬼了！\n\n他年轻气盛，以为自己什么都懂。呵，我这把年纪也不是白活的……\n\n也许你能帮我把这两个麻烦都解决了。', '', 66384),
(286255, 'zhCN', '我不禁在想，我们的族人是否也能从这些技术中获益……\n\n这些知识应该能帮助我的家人抵御虚空的威胁。……保护我仅剩的家人。', '', 66384),
(286231, 'zhCN', '对不起，我现在明白了，我不该这么轻易下定论。', '', 66384),
(286230, 'zhCN', '不用谢，小家伙。现在回你的农场去吧，祖阿曼不是你这样的精灵小子该来的地方。', '', 66384),
(286226, 'zhCN', '你们的人袭击了我们的农场，杀害了我的妹妹，我还需要明白什么？', '', 66384),
(286224, 'zhCN', '仅仅一小块光木就蕴含着如此强大的力量，这些巨魔比我们想象的要聪明多了。', '', 66384),
(286223, 'zhCN', '没想到暮光之刃会在这里……而且人数如此之多。', '', 66384),
(286222, 'zhCN', '快去，在斥候指挥官杀死那小子之前解决他。', '', 66384),
(286221, 'zhCN', '小子，去帮$n砍木头吧。', '', 66384),
(286216, 'zhCN', '咱们用光木是有原因的。小子，你根本不明白这里真正的威胁是什么。', '', 66384),
(286193, 'zhCN', '那光木暴露了他们的行踪！还把他们震晕了？', '', 66384),
(286191, 'zhCN', '让这小家伙看清谁才是真正的敌人。', '', 66384),
(286168, 'zhCN', '欢迎来到我的庇护所。有任何需要请尽管开口。', '', 66384),
(286135, 'zhCN', '', '托伦多，我要你的报告。我们的士兵什么时候能上战场？', 66384),
(286134, 'zhCN', '这就是第二课。引导圣光需要的是信念和决心。就算它们误入歧途，那也一样。', '', 66384),
(286133, 'zhCN', '这个地方挂满了圣光教会的装饰，侍奉的却是邪恶的使命。', '', 66384),
(286129, 'zhCN', '这个地方曾经更加辉煌，那时它真正为圣光教会效力。\n\n起初，在赛丹和亚历山德罗斯的领导下，它在洛丹伦行了许多善事。\n\n但后来，十字军走上了邪路，对异族产生了仇恨，这种仇恨引导着几十年来的行动。', '', 66384),
(286125, 'zhCN', '啊，是啊，梅雷多尔。你那天才魔法是毁了一本好好的日记，但至少说明，你在惹祸方面的天赋已经登峰造极了。', '', 66384),
(286123, 'zhCN', '好吧，瓦迪斯，我倒真得谢谢你。你那套没用的法子，配上这团乱七八糟的破事，总算是相称了一回。', '', 66384),
(286119, 'zhCN', '你来了，$n。我们要进去找阿拉托尔。我的宣讲对这些狂徒只是对牛弹琴。', '', 66384),
(286118, 'zhCN', '他们占领我的教堂时抢走了许多圣物。那些圣物应该用于我们的事业，助我们抵挡萨拉塔斯。', '', 66384),
(286104, 'zhCN', '', '奥威娜摇了摇头。', 66384),
(286099, 'zhCN', '', '那你就管好邪枝部族，别让他们三更半夜绑走我们的人！', 66384),
(286081, 'zhCN', '愿森林为你指条近路，反正我们的法师是靠不住了。', '', 66384),
(286077, 'zhCN', '长老们提前传过话，允许你们参加试炼。我们就看看艾林哈籁是否真的向你发出了呼唤。\n\n这是一个千载难逢的机会，你将有幸了解我们的族人、文化和历史。\n\n准备好开始了就告诉我。', '', 66384),
(286071, 'zhCN', '祝你好运。我们先去前面搜索，不过带着瓦迪斯这个累赘也是白搭。', '', 66384),
(286065, 'zhCN', '萨拉塔斯小看了圣光先锋军和辛多雷的意志！我们今日必将获胜，必将令虚空永劫不复！', '', 66384),
(286053, 'zhCN', '<阿拉托尔突然停下脚步，示意你也保持不动。>\n\n等等。有人过来了。', '', 66384),
(286050, 'zhCN', '谢谢你，天灾的势力减弱了。支援太阳之井所需的圣物随你取用。', '', 66384),
(286049, 'zhCN', '我从加入白银之手开始就一直在这么做了。', '', 66384),
(286048, 'zhCN', '我的第一课是，师从昔日的英雄们，了解他们的圣光因何而启。', '', 66384),
(286037, 'zhCN', '好地方，正好让我不用再想圣骑士的事了。', '', 66384),
(286035, 'zhCN', '到圣光之愿去收集圣物，让先锋军能振作士气。', '', 66384),
(286029, 'zhCN', '唔。这些守护者奉献了自己的信仰和力量，现在都已经精疲力尽了。我们要帮他们重振气力。', '', 66384),
(286028, 'zhCN', '这就是你的办法？用法杖震击他们？', '', 66384),
(286018, 'zhCN', '', '摄政王……阿曼尼巨魔入侵了永歌森林。游侠将军已经率队前去驱逐了。', 66384),
(286006, 'zhCN', '很好！你们都来了。我们需要克服一场信仰危机！', '', 66384),
(286005, 'zhCN', '真是个忧心忡忡的孩子。被父亲在胸口刻下伤痕的时候就会这样。不必担心——我自有安排。', '', 66384),
(286003, 'zhCN', '瑟拉奈尔，虚空闯进来了！我们……我们来不及……', '', 66384),
(285998, 'zhCN', '', '我一直担心我的力量会伤害到我关心的人。但在我的设想中，那总归是我一时软弱，令体内的黑暗纳鲁趁虚而入。\n\n我从未想过，逼我出手的竟会是我的一位老战友。', 66384),
(285997, 'zhCN', '洛萨克森！', '', 66384),
(285994, 'zhCN', '我知道这个谜团的答案就隐藏就在这里。我们只需将其找出。', '', 66384),
(285983, 'zhCN', '放弃吧，地表居民！你们的圣光会将你们洗刷干净！', '', 66384),
(285979, 'zhCN', '休息吧，凡人。去寻求救援。', '', 66384),
(285977, 'zhCN', '这里的虚空之力……感觉格外强烈。或许是殆希莫斯搞的鬼？', '', 66384),
(285959, 'zhCN', '不用担心我，可是泰拉的痛苦……我深深地感受到了，你肯定也一样。\n\n我知道踏上这条道路肯定会付出代价，但在此之前，我从没产生过这样的感觉。', '', 66384),
(285955, 'zhCN', '$n，我们必须检查其他人的情况。', '', 66384),
(285937, 'zhCN', '', '这边走，哈杜伦，$n。', 66384),
(285936, 'zhCN', '我们居然来到了世界之树的根须底下，这景象令人叹为观止。我们以前都不知道，这地下居然还有一个广阔的世界。\n\n这是艾泽拉斯的其他人从未获得过的机会。\n\n我已经准备好动身了，就等你了。', '', 66384),
(285929, 'zhCN', '他们砍倒的树……就是它导致了日冕村的毁灭！阿曼尼要为此付出代价！', '', 66384),
(285928, 'zhCN', '', '我们已倾尽全力，至少眼下如此。\n\n我不能沉浸在悲痛中……真正的战斗才刚开始。', 66384),
(285927, 'zhCN', '所以是垮塌造成了光绽的爆发……谢谢。好好休息，这里交给我们。', '', 66384),
(285923, 'zhCN', '啊，没错。祖尔加拉希望某位$c参加此次会议！我看就是你，那位助我脱困的$c。\n\n很好。阿曼尼急需更多盟友。你，以及在座的各位首领。\n\n至于莉亚德琳的到场……虽然我不太情愿，但我没资格质疑祖尔加拉的决定。', '', 66384),
(285922, 'zhCN', '', '我们恶齿巨魔因暮光之刃失去了长老和家园，我父亲和我祖父都没能幸免。\n\n现在，由我来领导恶齿部族。', 66384),
(285909, 'zhCN', '', '我相信我们是在做正确的事情。我们一定会坚持到底，不惧艰险。', 66384),
(285908, 'zhCN', '', '是药三分毒，再好的东西，用多了也一样。', 66384),
(285907, 'zhCN', '就算有那位魔导师的实验，我还是觉得那东西变成这副样子，不全是因为他。', '', 66384),
(285906, 'zhCN', '', '要我说，能把圣光逼到这个地步的那个家伙，才是真正的怪物。', 66384),
(285905, 'zhCN', '那到底是个什么鬼东西？圣光真能造出这种怪物？', '', 66384),
(285900, 'zhCN', '', '你是来帮忙的吗？', 66384),
(285896, 'zhCN', '哈加尔虽然不再是护根者了，但她掌握的智慧不可度量。我相信她不会带奥威娜走上歧路。', '', 66384),
(285889, 'zhCN', '', '这位光荣的护根者可以为你介绍。', 66384),
(285885, 'zhCN', '维护传统是有理由的。传统保护着我们和这片土地，小辈们不该提出质疑。', '', 66384),
(285882, 'zhCN', '在这个世界的地带，有几处“节点”，正是它们在维系着风暴。', '', 66384),
(285825, 'zhCN', '殆希莫斯脸上浮现出一个微笑。', '', 66384),
(285824, 'zhCN', '空灵爪牙，告诉我打破这场风暴的办法。', '', 66384),
(285822, 'zhCN', '哎呀，我都好久没受到客人的无礼对待了，上一次还是……呃，我不该说出口。\n\n我认得清自己的败局，现在还是先文明交流吧。', '', 66384),
(285818, 'zhCN', '啊，没错，就是那个弄丢日记的“天才”写的！彻头彻尾的蠢货！', '', 66384),
(285817, 'zhCN', '你那双“慧眼”要是真的管用，我们早就该找到日志了！', '', 66384),
(285816, 'zhCN', '年轻一代的胆魄总能令我感到惊讶。', '', 66384),
(285813, 'zhCN', '', '长老不愿意牺牲任何艾林之尘。我们必须另寻他法。', 66384),
(285811, 'zhCN', '血色十字军？你居然想要传播他们的圣光？', '', 66384),
(285808, 'zhCN', '$p！我们要拯救太阳之井。更重要的是，我们得帮这个颓丧的年轻人振作起来。', '', 66384),
(285793, 'zhCN', '', '我们争取到了哈籁提的协助，心中怀着艾林的赐福，我们一定能够驱退这场疯狂。\n\n但我们要做的还不止这些。还有鲁伊亚，他必须为自己的行径付出代价。', 66384),
(285786, 'zhCN', '', '啊，好吧，如果你想要清静一点，躲开这些喧闹的……访客，那就去找城内的红色旗帜。我们不准联盟进入那些区域。', 66384),
(285785, 'zhCN', '', 'Bal\'a dash，malanore。\n\n皇家贸易区在这动荡时期为人们保持着一丝常态。集市的各种服务在这里都向特定客户开放。', 66384),
(285784, 'zhCN', '', '我被召唤到这里是有原因的。', 66384),
(285779, 'zhCN', '我身后的门仅限部落成员入内。别靠近红色的旗帜和树木，否则你就是自讨苦吃。', '', 66384),
(285778, 'zhCN', '联盟不可以越过这道门。这就是你的界限了，“英雄”。', '', 66384),
(285777, 'zhCN', '抱歉，我实在没空分心。\n\n我们虽然允许联盟在集市里走动，但这不代表我们可以掉以轻心。说不定他们是在试探我们的底线。', '', 66384),
(285761, 'zhCN', '', '我早该知道祖尔加会这么做。\n\n俗话说，山猫改不了捕食的本性，蛇也换不了鳞片……\n\n可他毕竟是我的弟弟，我还以为他能明白事理……\n\n哪怕他能听我一次就好了！\n\n如果在洛阿神灵赶来援助我们之前，祖尔加就带着大家去送了死，那走这哈谢之路还有什么意义？！', 66384),
(285760, 'zhCN', '', '既然我获得了纳洛拉克的祝福，也接下了他的重任——那我们就能召集全体族人，彻底解决莫尔杜恩！', 66384),
(285754, 'zhCN', '这是提特姆，从哈阿尔诺过来做生意的。', '', 66384),
(285753, 'zhCN', '', '你确定你弟弟会听你的命令？', 66384),
(285751, 'zhCN', '<魔导师梅雷多尔和游侠瓦迪斯似乎正在吃饭。\n\n弄丢的日记已经不见了。看来日记就是在这前后丢的。>', '<魔导师梅雷多尔和游侠瓦迪斯似乎正在吃饭。\n\n弄丢的日记已经不见了。看来日记就是在这前后丢的。>', 66384),
(285750, 'zhCN', '<魔导师梅雷多尔和游侠瓦迪斯似乎正沿着小路边走边聊。\n\n那本弄丢的日记就摆在眼前。看来日记不是在这个时候丢的。>', '<魔导师梅雷多尔和游侠瓦迪斯似乎正沿着小路边走边聊。\n\n那本弄丢的日记就摆在眼前。看来日记不是在这个时候丢的。>', 66384),
(285748, 'zhCN', '<魔导师梅雷多尔和游侠瓦迪斯似乎正在对练。\n\n那本弄丢的日记就摆在眼前。看来日记不是在这个时候丢的。>', '<魔导师梅雷多尔和游侠瓦迪斯似乎正在对练。\n\n那本弄丢的日记就摆在眼前。看来日记不是在这个时候丢的。>', 66384),
(285736, 'zhCN', '这是利扎姆，从哈阿尔诺过来做生意的。', '', 66384),
(285733, 'zhCN', '银月城的命运，乃至整个艾泽拉斯的未来，都可能取决于这次任务的成败。Anu belore dela\'na。', '', 66384),
(285717, 'zhCN', '要是这些花扎了根，哈尔玛拉就完了！', '', 66384),
(285706, 'zhCN', '虚空的力量，终究还是小看了圣光。', '', 66384),
(285703, 'zhCN', '', '我们都是阿曼尼，弟弟。我们只是需要对彼此更宽容一些。', 66384),
(285702, 'zhCN', '怎么，又来数落我的不是了，姐姐？你在怕我比你更像个阿曼尼吗？', '', 66384),
(285701, 'zhCN', '我能尝到杀戮的滋味！', '', 66384),
(285699, 'zhCN', '', '不！祖父，就算这会毁了我们所谓的“家族的荣耀”，我也不会重蹈您的覆辙！', 66384),
(285698, 'zhCN', '蠢丫头！你居然跟一个精灵站在一起？你这是在玷污我们家族的荣耀！', '', 66384),
(285694, 'zhCN', '这些低语令我感到窒息。', '这些低语令我感到窒息。', 66384),
(285692, 'zhCN', '这种光绽和我预想的不太一样。', '', 66384),
(285689, 'zhCN', '何等庸俗的同伴情谊。你们会像殆希莫斯一样，认清自己的身份。', '', 66384),
(285688, 'zhCN', '', '大部分芦塔尼都有领地意识，只有少数几个地方能与他们和平往来。', 66384),
(285685, 'zhCN', '', '在神殿与我会合。我会带上炭火。我的灵魂已准备好迎接一切挑战。', 66384),
(285680, 'zhCN', '', '当心，神灵代言人！', 66384),
(285678, 'zhCN', '', '他虽然疯言疯语，但似乎和洛阿的联系很深。拿着这块炭火，$n，让我们试试能不能开启试炼。', 66384),
(285672, 'zhCN', '', '叔叔，洛阿已经好多年没跟你说话了，你怎么就觉得他们现在会回应我们？', 66384),
(285671, 'zhCN', '孩子，你没有经历过神灵同在的那个世界。他们曾是我们的力量，我们的希望。', '', 66384),
(285667, 'zhCN', '', '狩猎大师，那你愿意帮助我们追猎莫尔杜恩和暮光之刃吗？', 66384),
(285665, 'zhCN', '他们都将成为我的猎物，阿曼尼的小家伙。愿暗影永远庇护你。', '', 66384),
(285664, 'zhCN', '', '你恢复之后就下来，其他人还等着呢。', 66384),
(285662, 'zhCN', '', '你在哈尔玛拉会看到罕见的景象，芦塔尼和真菌人能和平共处。', 66384),
(285661, 'zhCN', '', '继续前进。哈谢神殿会指引我们找到哈尔拉兹神庙。', 66384),
(285660, 'zhCN', '', '我们现在该怎么办？这迷雾……根本穿不过去。', 66384),
(285659, 'zhCN', '', '啊，你醒啦。欢迎来到哈尔玛拉。', 66384),
(285656, 'zhCN', '圣光与我们同在，希望也是。', '', 66384),
(285630, 'zhCN', '你的造型好多了，看来是没问题了！', '', 66384),
(285627, 'zhCN', '这台古董幻化机在运输过程中受损了。你能修好它吗？', '', 66384),
(285603, 'zhCN', '', '五个呢！南边发生了怪事，可我们的人数都不够巡逻了。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(285599, 'zhCN', '洛瑟玛可能已经安排好了撤离，阿拉托尔。先锋军还需要你！', '', 66384),
(285597, 'zhCN', '我去打听一下，看看能否找到线索。', '', 66384),
(285589, 'zhCN', '', '在墓穴中时，我注意到邪枝的人好像也看不清这雾。嗯……', 66384),
(285585, 'zhCN', '', '我们会救回你的战士，也会找到通往哈尔拉兹神庙的路。', 66384),
(285584, 'zhCN', '', '小心那片迷雾，祖尔加拉。那东西不正常，我怀疑邪枝部族用它来掩盖什么见不得人的勾当。', 66384),
(285574, 'zhCN', '', '接下来你必须寻求哈尔拉兹的祝福。他虽然行踪诡秘，但他的代言人能帮你找到他。', 66384),
(285573, 'zhCN', '', '枯木部族的神灵代言人都去世了。但也许库拉玛拉能助我们一臂之力。', 66384),
(285551, 'zhCN', '', '我得带个样本回远行者营地。说不定那里有人能研究出点名堂。', 66384),
(285550, 'zhCN', '', '这朵花……充满了圣光。除了光绽外，我从没见过这种东西。光是靠近就觉得晃眼。', 66384),
(285546, 'zhCN', '去吧。我在这儿等着，看看还有没有人能回来。', '', 66384),
(285545, 'zhCN', '哈里斯叹了口气。', '', 66384),
(285544, 'zhCN', '塞蒂娜——！', '', 66384),
(285543, 'zhCN', '', '跟我来！光站着傻等可救不了人！', 66384),
(285528, 'zhCN', '', '试炼……我小时候，金杜鲁带我来过……我想起来了！', 66384),
(285517, 'zhCN', '', '关于你父亲。当他——等等。你听到什么了吗？', 66384),
(285514, 'zhCN', '我们在根须中努力开辟道路，最后来到了哈籁恩达尔。但那个故事更深刻，也更危险。', '', 66384),
(285510, 'zhCN', '可惜，似乎只有我一个人明白当下局势的严峻。', '', 66384),
(285509, 'zhCN', '', '我们前方的敌人还不够多吗？但凡能结盟的，我一个都不会丢下。', 66384),
(285508, 'zhCN', '很快我们就能集齐所有东西了。在这畜生对我们动歪脑筋之前，最好先宰了它。', '', 66384),
(285507, 'zhCN', '', '马特瑞安，那些是用来研究分析的！', 66384),
(285505, 'zhCN', '', '准备好了吗？我们离得很近了，可我感到的不适却更为强烈。', 66384),
(285504, 'zhCN', '', '这地方有着自己的法则——虚空可以利用它，那我们也必须利用。', 66384),
(285503, 'zhCN', '就没有……别的出路吗……？', '就没有……别的出路吗……？', 66384),
(285502, 'zhCN', '虚空……毁了我们……', '虚空……毁了我们……', 66384),
(285501, 'zhCN', '', '节点之王萨哈达尔统率着影卫的残部，这是一群鲁莽地运用虚空的虚灵。他原先是迪门修斯最忠诚的追随者之一。\n\n我们在法力熔炉：欧米伽击败他后，萨拉塔斯将他带到了某个遥远的界域。他和他的虚灵曾一度脱离，但很快又心甘情愿地重归她的麾下。\n\n萨哈达尔虽然自诩为霸王，如今却只是萨拉塔斯手下的一条丧家之犬。', 66384),
(285500, 'zhCN', '', '我们从来没试过给龙鹰注入这么强大的力量。应该……没问题的。', 66384),
(285499, 'zhCN', '', '骑上去，它准备出发了！', 66384),
(285498, 'zhCN', '有了你们的帮助，不少人就能活着逃到银月城了！', '', 66384),
(285481, 'zhCN', '殆希莫斯居然愿意帮助我们……热情得令人生疑。我不喜欢和动机不明的人合作。', '', 66384),
(285480, 'zhCN', '', '<奥蕾莉亚分神了一会儿，随后才将目光锁定在你的身上。>\n\n我很高兴能在这里得到支援。我们必须粉碎萨拉塔斯的阴谋。', 66384),
(285478, 'zhCN', '', '艾林之尘——女神残留的意志凝结成的形态。它能增强我们的魔法，使我们穿越到不同的世界。', 66384),
(285477, 'zhCN', '我身上好麻呀。这是什么？', '', 66384),
(285476, 'zhCN', '在这里，连天上飞的都长着一嘴獠牙。', '在这里，连天上飞的都长着一嘴獠牙。', 66384),
(285475, 'zhCN', '小心，$p。这家伙看起来饿坏了。', '小心，$p。这家伙看起来饿坏了。', 66384),
(285470, 'zhCN', '', '看，哈籁恩达尔。', 66384),
(285464, 'zhCN', '', '我要提醒你们两个，我的族人不欢迎外来者，可能也不再欢迎我了。', 66384),
(285459, 'zhCN', '我的同胞，死了？怎么会这样？', '', 66384),
(285454, 'zhCN', '日记本？缺了很多页……奇怪。我们去找乌布里克，他肯定想知道这个。', '', 66384),
(285450, 'zhCN', '', '……我不会欺骗你们。我们确实需要帮助。虽然我不信任你们，但如果你们想干掉暮光之刃，那我们可以合作。', 66384),
(285449, 'zhCN', '别管他们了，姐妹。我们有光木就够了。我们阿曼尼，不需要其他部族的帮助。', '', 66384),
(285432, 'zhCN', '', '我忙得很，没工夫回答陌生人的问题。\n\n你到底想要什么？', 66384),
(285428, 'zhCN', '住手！', '', 66384),
(285426, 'zhCN', '', '纳拉丁快把神龛都毁了，那些栖息在这里的鹰巢也快保不住了。', 66384),
(285425, 'zhCN', '这圣光……燃烧着洛萨克森的怒火……就像我父亲当年的一样……', '', 66384),
(285424, 'zhCN', '', '那我们就必须击垮他们。', 66384),
(285423, 'zhCN', '$n，用圣光赐予我力量吧，我来试着拖住他们！', '', 66384),
(285422, 'zhCN', '', '纳拉丁是通常栖息在北边森林洞穴里的巨人。他们本该老实待在那儿的。\n\n现在他们挡了我的道，而我们时间紧迫。所以，他们必须消失。', 66384),
(285421, 'zhCN', '', '阿拉托尔！阻止他们！', 66384),
(285420, 'zhCN', '记得在前往神庙途中点亮神龛。还有，别忘了给埃基尔松献上祭品！', '', 66384),
(285418, 'zhCN', '', '神庙已经被纳拉丁占领了。我们正好一路杀过去，免得路上无聊。来吧，“哈舒拉”。', 66384),
(285409, 'zhCN', '我游历过不少地方。确切地说，游历过不少世界。\n\n但我觉得，我们在这片荒芜岩石上完成的工作是我做过的最棒的事。生命循环很重要，这是我第一次站在循环的创造一面而不是杀戮一面——说实话，感觉真好。\n\n你呢？你感觉如何？', '', 66384),
(285408, 'zhCN', '', '这到底能对我们的研究有什么帮助？', 66384),
(285407, 'zhCN', '多么神奇的结果……', '', 66384),
(285377, 'zhCN', '', '艾林之尘……长老们不会轻易让出的。可我们总得试试。', 66384),
(285370, 'zhCN', '担心我会计划要逃跑吗？恰恰相反，照这个样子，你们永远别想甩掉我。', '', 66384),
(285369, 'zhCN', '', '<乍一看，这似乎只是树上冒出的一朵奇怪的花。仔细一瞧，你发现这朵花占据了供其生长的尸体。这棵树也不是在附近生长的，而是从尸体里长出来的。>', 66384),
(285367, 'zhCN', '<洛萨克森凝望着前方。>', '', 66384),
(285366, 'zhCN', '这股熟悉的寒冷，它在向我呼唤……', '', 66384),
(285360, 'zhCN', '', '我……用尽……全力了……', 66384),
(285357, 'zhCN', '很抱歉，我还需要陪他们一会儿。去找麦拉吧，反正她的报告比我的详细。', '', 66384),
(285354, 'zhCN', '<海尔兰过于关心阿斯崔了，都没有发现你的靠近。>', '', 66384),
(285353, 'zhCN', '', '$n，你和风行者女士能回来就好。\n\n我们已经有所发现，我们一族的独特能力很适合在虚影风暴中求生，并最终将其逼退。但同样的，我们也很容易受到这股力量的诱惑。', 66384),
(285351, 'zhCN', '那是当然，不用着急！我们眼前可没有贪得无厌的树人大军，他们也不会跨过河来吃掉我们。', '', 66384),
(285345, 'zhCN', '', '谢谢你，$n。你帮我的族人回到了这个世界。我想，女神一定会很高兴。', 66384),
(285344, 'zhCN', '奥威娜，你们的努力拯救了永歌森林。只要哈籁尼尔愿意，你们在银月城永远都有一席之地。', '', 66384),
(285342, 'zhCN', '你的族人拯救了我们的家园，奥威娜——还为此付出了沉重的代价。你们的牺牲将被铭记。', '', 66384),
(285341, 'zhCN', '我坚持要求你到银月城与我会合。', '', 66384),
(285335, 'zhCN', '放肆的崽子。你的僭越到此为止了。', '', 66384),
(285334, 'zhCN', '', '鲁伊亚！你在与艾林哈籁的意志作对！快停止这场疯狂！', 66384),
(285333, 'zhCN', '', '不要露怯。鲁伊亚很强，但他只有一个人。该做个了断了。', 66384),
(285332, 'zhCN', '我们以前从没和哈籁尼尔的护根者交过手。有什么需要了解的吗？', '', 66384),
(285323, 'zhCN', '', '艾林哈籁的祝福赐我们力量。今天，我们要为她的所有造物而战！', 66384),
(285322, 'zhCN', '阻止仪式！奋起反击！永歌森林绝不会陷入火海！', '', 66384),
(285321, 'zhCN', '', '帮手来了，小苗子。 ', 66384),
(285320, 'zhCN', '', '长老哈加尔？', 66384),
(285318, 'zhCN', '可怜的奥威娜。你一个人是阻止不了光绽的。', '', 66384),
(285316, 'zhCN', '', '它们没完没了！艾林哈籁，赐我力量吧！', 66384),
(285312, 'zhCN', '这不是普通的戏法！继续射击，别送命了！', '', 66384),
(285311, 'zhCN', '随时都可以，罗曼斯！', '', 66384),
(285308, 'zhCN', '天真的奥威娜。这股狂热不会再屈服于我们神圣的家园了。我用这盛放的花来对付它的创造者！', '', 66384),
(285307, 'zhCN', '', '护根者鲁伊亚？这眼前的疯狂是？', 66384),
(285304, 'zhCN', '光绽已经蔓延到河边了。太阳之光保佑，我们没有时间了。', '', 66384),
(285302, 'zhCN', '', '如果你引爆符文石，整片森林都会烧毁。', 66384),
(285296, 'zhCN', '这样不会有进展的。传话给罗曼斯，让魔导师尽快赶往日冕之树。', '', 66384),
(285295, 'zhCN', '我不惜一切。', '', 66384),
(285294, 'zhCN', '', '我们收集的艾林之尘都耗尽了。你打算怎么做，哈杜伦？', 66384),
(285291, 'zhCN', '我把能找到的帮手都带来了。', '', 66384),
(285290, 'zhCN', '', '没有艾林之尘，眼前的考验十分严峻。做好准备。', 66384),
(285277, 'zhCN', '少了哈籁尼尔和他们的戏法，我们对抗光绽的手段寥寥无几。', '', 66384),
(285232, 'zhCN', '', '不对劲，太不对劲了。', 66384),
(285231, 'zhCN', '我还以为光绽可以成为先锋军的帮手……结果他们才是罪魁祸首？', '', 66384),
(285225, 'zhCN', '', '是芦塔尼，我故乡才有的生物。他们不该出现在这里。', 66384),
(285224, 'zhCN', '快，附近有一块符文石，我们去安全的地方调查一下。', '', 66384),
(285222, 'zhCN', '分头行动吧，这样能调查更多地方。我等会儿再与你们会合。', '', 66384),
(285221, 'zhCN', '', '$p，我们必须查明导致这些生物突然生长的原因。', 66384),
(285220, 'zhCN', '', '他们宣称这是他们的领地，而我们是在进犯。', 66384),
(285219, 'zhCN', '这些生物仿佛受到了圣光的祝福，却很……凶残。', '', 66384),
(285217, 'zhCN', '', '这些生物……让我想起了故乡，却生活在地表上。原本不该是这样的。', 66384),
(285216, 'zhCN', '母亲说你很熟悉荒野。你觉得这都是怎么回事？', '', 66384),
(285212, 'zhCN', '', '你所说的光绽显然已经失控了。我们必须查明是什么惊扰了它。', 66384),
(285211, 'zhCN', '', '魔导师，你第一次看到这种光绽异动，是在什么时候？', 66384),
(285203, 'zhCN', '你是奥威娜，对吧？我母亲奥蕾莉亚和我说起过你。', '', 66384),
(285202, 'zhCN', '用这个奥术发射器保持联系。', '', 66384),
(285201, 'zhCN', '阿拉托尔，太阳之井需要你。', '', 66384),
(285179, 'zhCN', '这里不需要你！', '', 66384),
(285178, 'zhCN', '这轮不到你来决定！', '', 66384),
(285156, 'zhCN', '', '行了！我们终于找到反击的办法了。', 66384),
(285154, 'zhCN', '', '艾林哈籁之赐在上，艾林之尘保护了昂卡，也将保护这些芦塔尼。', 66384),
(285153, 'zhCN', '是从上面传来的，才没过几天，莎拉达希尔就全被占了。', '', 66384),
(285149, 'zhCN', '', '谢谢，阿玛拉克。我对你的感激无以言表。', 66384),
(285145, 'zhCN', '这样我们就有机会消灭一个具象了。', '', 66384),
(285143, 'zhCN', '具象是个严峻的威胁，但它们也是艾林之尘最主要的来源。', '', 66384),
(285142, 'zhCN', '在裂隙最黑暗的深处，艾林之尘凝聚成了你面前的怪物。', '', 66384),
(285140, 'zhCN', '没了。被偷走了！她去哪儿了？', '', 66384),
(285139, 'zhCN', '', '昂西艾？别这样！', 66384),
(285138, 'zhCN', '', '不！女神！她……她……阿玛拉克？$n？', 66384),
(285137, 'zhCN', '你找回自己了。很好，你的朋友就没那么走运了。', '', 66384),
(285136, 'zhCN', '黑暗的根须。奥威娜，集中精神！听我的声音！', '', 66384),
(285133, 'zhCN', '', '我在顺着朦胧的声音漂流，朋友。她在安慰我，迎接我，我……', 66384),
(285132, 'zhCN', '', '他不在这。结界……我需要更多艾林之尘。$n，快。', 66384),
(285131, 'zhCN', '', '仪式只会模仿舒尔卡的牺牲，不是永久性的，也并不完美。我们必须尽快找到阿玛拉克。', 66384),
(285129, 'zhCN', '', '她的声音沉寂了，我从没感受这种孤独。这就是阿玛拉克的生活吗？', 66384),
(285122, 'zhCN', '如果你坚持的话，就需要使用艾林之尘来保护你的心智和灵魂。', '', 66384),
(285118, 'zhCN', '虽然时隔已久，你还是回到这里想要进入裂隙？你一点没变啊，奥威娜。', '', 66384),
(285115, 'zhCN', '摇篮中的女神被扯走时，暴力留下了永远无法愈合的伤口。', '', 66384),
(285114, 'zhCN', '她痛苦的哀嚎孕育了没有形体的恐魔，令进入的人陷入疯狂。', '', 66384),
(285112, 'zhCN', '在我们之中，她最清楚收集的代价了。她要是愿意挥霍，那就自己进裂隙去拿。', '', 66384),
(285110, 'zhCN', '你要我们把艾林之尘分给外来者？简直荒唐！', '', 66384),
(285109, 'zhCN', '', '在大巢穴里问问，尽力打探一下。', 66384),
(285104, 'zhCN', '其他人会返回银月城。还有……许多要讨论的事。', '', 66384),
(285103, 'zhCN', '女伯爵莉亚德琳，占领小径。不管怎样，我们控制了据点，就要守住它。', '', 66384),
(285102, 'zhCN', '勇士！我们将祖尔加逼入了绝境。是时候结束这场入侵了！', '', 66384),
(285101, 'zhCN', '恶心的阿曼尼！以圣光之名，我会净化这些怪物！', '', 66384),
(285098, 'zhCN', '这里流的血……太疯狂了。我父亲呢？他必须看到这一幕！', '', 66384),
(285097, 'zhCN', '是暮光之刃！他们才是真正的威胁！', '', 66384),
(285093, 'zhCN', '', '来不及了，阿拉托尔。但我们可以治疗需要的人。', 66384),
(285092, 'zhCN', '我们必须阻止他们！', '', 66384),
(285086, 'zhCN', '你要是不愿作战，就别妨碍我！', '', 66384),
(285083, 'zhCN', '快，我们要赶往阿曼尼小径，把事情的真相告诉他们！', '', 66384),
(285080, 'zhCN', '哈！你做到了！', '', 66384),
(285079, 'zhCN', '又有挡路的魔法。这些地砖或许就是答案。', '', 66384),
(285073, 'zhCN', '阿曼尼巨魔肯定不欢迎不速之客。幸好这些结界年代很久远。', '', 66384),
(285072, 'zhCN', '既然保护得那么好，我们必须小心前行。跟我来，尽量别出声。', '', 66384),
(285071, 'zhCN', '这个地方……看上去满是符文，遍布结界。', '', 66384),
(285043, 'zhCN', '谢谢你，莉亚德琳。希望哈杜伦能告诉我们这是怎么回事。', '', 66384),
(285042, 'zhCN', '', '我会和幸存者留下善后。', 66384),
(285041, 'zhCN', '', '北边传来了垮塌的声响，然后……突然到处都是光绽！', 66384),
(285040, 'zhCN', '听上去好像是有人砍倒了一棵树。远行者前去调查了。', '', 66384),
(285039, 'zhCN', '', '光绽原本在河对面。它怎么会在这里爆发？', 66384),
(285038, 'zhCN', '', '这个地方简直就是被荒野本身吞没了。', 66384),
(285037, 'zhCN', '', '圣光在上……', 66384),
(284695, 'zhCN', '', '我们过去是——现在也是。他对虚空心存疑虑并没有错，我只希望他也能试着信任我。', 66384),
(284694, 'zhCN', '我一直以为你和洛萨克森是朋友。', '', 66384),
(284693, 'zhCN', '握紧你们的武器。不要相信虚空的蛊惑。', '', 66384),
(284689, 'zhCN', '', '安忒诺里安勋爵不在，有事可以找我。', 66384),
(284688, 'zhCN', '不对劲。去看看她摆弄的保险箱里放了什么。', '', 66384),
(284686, 'zhCN', '', '安忒诺里安勋爵公务繁忙。当奎尔萨拉斯其他地方都在分崩离析时，还有谁来保卫塔奎林呢？\n\n也许我可以代为效劳？', 66384),
(284685, 'zhCN', '昨天晚上，有个女虚空精灵匆忙跑了出去，好像是在逃命。', '', 66384),
(284684, 'zhCN', '听起来像是卡茜雅。她会不会留下了什么？我们得去看看。', '', 66384),
(284681, 'zhCN', '希望塔奎林能提供你寻找的一切，旅行者。', '', 66384),
(284664, 'zhCN', '', '世界之歌召唤我前来。目前我只知道这些。', 66384),
(284658, 'zhCN', '', '我听见了世界之歌，于是前来应答。', 66384),
(284646, 'zhCN', '把这些带回我的书房吧。', '', 66384),
(284645, 'zhCN', '这是最后的样本了。这到底是为了什么？', '', 66384),
(284644, 'zhCN', '起作用了！快看那东西的大小啊！', '', 66384),
(284642, 'zhCN', '卡茜雅……你究竟在做什么？', '', 66384),
(284632, 'zhCN', '我们去最后一个地方。', '', 66384),
(284631, 'zhCN', '她是直接从虚影风暴中进行召唤吗？为什么？', '', 66384),
(284630, 'zhCN', '又是怪物！', '', 66384),
(284628, 'zhCN', '这地方在虚影风暴下暴露得更多，情况可能很危险。', '', 66384),
(284358, 'zhCN', '感激你为我们的族人伸出援手。', '感激你为我们的族人伸出援手。', 66384),
(284357, 'zhCN', '欢迎，陌生人。愿你能在此找到安宁。', '欢迎，陌生人。愿你能在此找到安宁。', 66384),
(284347, 'zhCN', '虚空能量的样本。好，拿上它，再去别的地方试试。', '', 66384),
(284346, 'zhCN', '是裂隙！', '', 66384),
(284345, 'zhCN', '卡茜雅的笔记主要记录的是……召唤？我们来看看。', '', 66384),
(284343, 'zhCN', '那我们就并肩作战。我绝不会抛下你的。', '', 66384),
(284342, 'zhCN', '', '真希望图拉扬也在这里，洛萨克森或许会听他的话。', 66384),
(284341, 'zhCN', '洛萨克森此刻的眼神，与我当年在父亲眼中所看到的一模一样。', '', 66384),
(284340, 'zhCN', '', '现在不是说客套话的时候，必须马上行动！ ', 66384),
(284339, 'zhCN', '别表现得那么心急，野兽。你骗得了奥蕾莉亚，可骗不过我。', '', 66384),
(284338, 'zhCN', '感受到了吗？披肩就在附近。', '', 66384),
(284335, 'zhCN', '死了！发疯的还不只有库扎特！', '', 66384),
(284334, 'zhCN', '', '萨拉塔斯利用她的幽暗之心以及这片土地本身的力量，筑起了她的虚影尖塔。\n\n这股汹涌的能量汇聚成了虚影风暴。我不久便察觉，她的矛头直指太阳之井。\n\n我当然想驰援银月城。但在那里我不受欢迎……况且，留在此地我也能发挥更大的作用。', 66384),
(284332, 'zhCN', '', '在得知幽暗之心的存在之后，我就一直在追击萨拉塔斯。她离开卡兹阿加时，我追踪她去了卡雷什，她试图在那里阻止迪门修斯重现世间。\n\n艾泽拉斯的英雄们驰援银月城之后，我依然在追击她，片刻都没有松懈。\n\n她重新收编了影卫虚灵，为他们打开了通路，来到了这个诡异的地方。我也一起溜了进来。\n\n这场风暴混沌无常，没有退路。但我不需要退路了，我的猎物就在此地。', 66384),
(284328, 'zhCN', '我有很多身份，凡人。我是纳斯雷兹姆，是恶魔，也是死神。但最重要的是，我还是一名光铸者。\n\n我的同胞纳斯雷兹姆，也就是恐惧魔王，我们最出名的就是化形能力、欺诈鬼谋，以及……善变的忠诚。\n\n曾经有一段时间，我在燃烧军团中与同胞们并肩作战。我一丝不苟地追随我们那冷酷无情的主子，并尽心尽责地向他们报告。我们一无所求，唯一的目标就是灭绝虚空，就算要让整个世界陪葬也在所不惜。\n\n可后来，我遇见了德莱尼，目睹了他们的圣光。于是我明白了，真正击败虚空的唯一办法，就是去接受它的反面，去和圣光融为一体。\n\n其他的纳斯雷兹姆都不明白，我就只能与他们决裂了。圣光就是我唯一的路途。', '', 66384),
(284324, 'zhCN', '昂卡，在盛放台地长出来的，交易艾林裂隙的种子，所以在这里。', '', 66384),
(284323, 'zhCN', '幸会。愿这位陌生人根深蒂固。带来用作交易的种子了吗？', '', 66384),
(284321, 'zhCN', '没什么光花。这个陌生人得做生意，不然就走。', '', 66384),
(284320, 'zhCN', '陌生人是过来做生意的吗？', '', 66384),
(284315, 'zhCN', '如果陌生人想做买卖，这里也有好东西。', '', 66384),
(284303, 'zhCN', '这是我第三回被抢劫了！', '', 66384),
(284301, 'zhCN', '全镇的人都在担心天空中那个东西。', '', 66384),
(284298, 'zhCN', '可疑？比如在我们头顶上逐渐逼近的巨型虚空风暴吗？别的没有。', '', 66384),
(284296, 'zhCN', '有什么事吗？这些天我忙得不可开交。', '', 66384),
(284291, 'zhCN', '我们总会拦截到这样的盒子，里面可能什么都有。届时我们还需要你的帮助。', '', 66384),
(284290, 'zhCN', '我们最近截获了一批跨维度货物，科技巫师却没法破开它们的安保措施。如果你走运的话，或许能把它们打开？', '', 66384),
(284289, 'zhCN', '我在深暗领域中目睹过几百个……数千个世界。\n\n在那些陷入战争与黑暗的世界上，我们奋勇抗击着燃烧军团。\n\n可我从没见过这样的地方。这弥漫口中的异味，这深入骨髓的寒意。\n\n这里存在着更为黑暗的事物，是萨拉塔斯。', '', 66384),
(284286, 'zhCN', '', '跟我来。森林部族的首领们已经到齐了，就等我们去商议作战计划。', 66384),
(284285, 'zhCN', '我准许朗多雷进入银月城，甚至允许他们接近太阳之井，这一决定引起了许多人的质疑。我再清楚不过了，他们当然会对效仿达尔坎·德拉希尔的家伙产生愤怒和恐惧。\n\n达尔坎曾经也是我的朋友，他的背叛依然令我心如刀绞。\n\n然而，朗多雷的流放也引起过许多人的质疑。这些精灵都有亲朋好友，他们并未被所有人放弃。\n\n在眼下的这个时刻，我们绝不能再抱有分歧了。', '', 66384),
(284279, 'zhCN', '不管你从哪儿来，我也照样做你的生意。', '', 66384),
(284270, 'zhCN', '我们不欢迎陌生人，不过我想可以破例一次。', '', 66384),
(284260, 'zhCN', '许多朗多雷都曾在魔导师平台钻研魔法，我也一样。这里本来是我们的家。罗曼斯曾经是我的同学。\n\n我认为，唯有知己知彼，才能攻克强敌。于是我带领一队研究人员，开始研究虚空的力量。我们发现了达尔坎·德拉希尔的日记，那家伙曾经背叛了银月城，投靠了巫妖王。他的罪行导致我们珍爱的一切几乎都在第三次战争中灰飞烟灭，而这都是源于他对虚空的研究。\n\n这下你应该明白了，虽然血精灵长期使用邪能之类的危险魔法，我的研究还是遭到了斥责。我们不愿意停手，于是就被流放了。\n\n这个选择并不让我感到后悔，可族人为此承受的苦难令我痛心。', '', 66384),
(284258, 'zhCN', '', '虚空和圣光并不总是完全对立的。我的信仰保护着我，让虚空的邪恶不敢近身。\n\n不管风暴的彼岸隐藏着什么，信仰依然会保护我。尽管信赖我吧。', 66384),
(284257, 'zhCN', '<海尔兰一言不发地打量着战友们的装备，见你靠近才抬起头来。>\n\n啊，$n，我们的秘密武器来了。有你在我就知道，我们此行不会是白白送死。银月城怕是有一半的居民都盘算着这么做。虚空现在已经过时了，风暴和精灵都不受待见啦。\n\n我真希望他们的态度能有所好转，当然，主要是针对我们。就帮他们找个合适的理由吧。', '', 66384),
(284256, 'zhCN', '不久之前，我还把这里当作是自己的家。大家都对我寄予厚望，我深受器重和嘉许，直到我的天赋异禀让我偏离了原本的人生之路。直到那一刻，我才向他们展示了真实的自我。\n\n<阿斯崔辛酸地抬头仰望天空。>\n\n我不是为了拯救他们而来的。我想让他们做个见证，让他们知道是自己错了。', '', 66384),
(284255, 'zhCN', '银月城上一次陷入战火的时候，我还只是远行者部队的一名军官。我记得那个时候，就像现在一样，我和战友们在城墙上并肩列队。随后有消息传来，说游侠将军战死了，我们都不相信。直到后来，树林里钻出了亡灵大军……\n\n<赛德拉斯摇了摇头。>\n\n现在的感觉，就和那时候一样。有些事情永远都不会改变吗，$p？', '', 66384),
(284254, 'zhCN', '', '我以前是个破法者，魔导师平台就是我的家。\n\n我研究虚空都是为了帮助同胞，却不曾想过会和它融为一体，也没有想到我会背井离乡。\n\n可罗曼斯听过劝告吗？魔导师真的理解了吗？没有。\n\n<麦拉满面怒容。>', 66384),
(284252, 'zhCN', '殆希莫斯微微勾起手指，不动声色地唤你上前。', '', 66384),
(284248, 'zhCN', '特别是你，$r。别以为我会忘记上一次的遭遇。', '', 66384),
(284216, 'zhCN', '光绽的蔓延来得十分突然。是你对商人的质问激发的吗？它是不是感受到了威胁？它真的有感觉吗？\n\n问题实在太多，但我们可能离答案更近了。', '', 66384),
(284178, 'zhCN', '', '库扎特平时都很平静，但被激怒的时候特别危险。小心点，$n。', 66384),
(284160, 'zhCN', '剩下的交给圆顶工人就行了。圆顶护盾非常敏感。后会有期，我们可能还需要你来帮忙。', '', 66384),
(284159, 'zhCN', '来得正好！虚空孢子又穿过了我们的护盾。必须赶紧清扫掉，不能让它们在生态圈里滋长。', '', 66384),
(284116, 'zhCN', '家园虽毁，但我绝不放弃抵抗！', '', 66384),
(284092, 'zhCN', '我们不能继续待在这里，必须赶到银月城！', '我们不能继续待在这里，必须赶到银月城！', 66384),
(284078, 'zhCN', '', '我们原本想离开这里，但四面八方都被包围了。\n\n我不想知道下面那个东西是什么，但那是我们唯一的逃生路径！', 66384),
(284072, 'zhCN', '外面那头笨拙的野兽？它看起来很温顺……这一定是什么把戏。', '', 66384),
(284071, 'zhCN', '库扎特发疯了！', '', 66384),
(284068, 'zhCN', '我想要的东西已经到手了。等救了你的城市，你再慢慢悼念你的朋友吧。', '', 66384),
(284066, 'zhCN', '', '你准备好了吗？', 66384),
(284037, 'zhCN', '求你帮帮我，我得离开这里！', '求你帮帮我，我得离开这里！', 66384),
(284034, 'zhCN', '有条船即将开往银月城。我不能再待下去了，必须赶上那艘船！', '有条船即将开往银月城。我不能再待下去了，必须赶上那艘船！', 66384),
(283974, 'zhCN', '梦魇无处不在！我快撑不下去了！', '梦魇无处不在！我快撑不下去了！', 66384),
(283970, 'zhCN', '', '我的家园……现在该怎么办？', 66384),
(283963, 'zhCN', '我会先赶过去，你尽快跟上。', '', 66384),
(283956, 'zhCN', '滚出去！我保证你们永远没法在这儿干了！', '', 66384),
(283954, 'zhCN', '等等，$n。这儿有个人。她手里攥着的是什么？', '', 66384),
(283921, 'zhCN', '饿啊！太……饿了……', '', 66384),
(283920, 'zhCN', '盛宴又添美味！', '', 66384),
(283916, 'zhCN', '要是你执意继续向节点扔纳鲁，那我也不拦你，请便。', '', 66384),
(283857, 'zhCN', '我们脱离前线也许能发挥更大作用，甚至可以避免不必要的牺牲。我了解虚空的运作方式，而你是个传奇人物。', '', 66384),
(283852, 'zhCN', '欢迎来到银月城。', '', 66384),
(283851, 'zhCN', '<罗曼斯心情轻蔑地盯着你。>', '', 66384),
(283845, 'zhCN', '银月城感谢你的援助。', '', 66384),
(283832, 'zhCN', '圣光就从来没有照耀过这个地方吗？\n\n如此邪门的黑暗，这里的生物居然还在其中狂欢。我们必须时刻提防那些被虚空浸染的盟友，别让他们被此地的力量诱惑了……', '', 66384),
(283796, 'zhCN', '菲琳，去找先锋军！我会护送大家前往太阳之井。', '', 66384),
(283795, 'zhCN', '我们需要转移伤员！', '', 66384),
(283794, 'zhCN', '', '谢谢，安度因。愿神圣烈焰能保护我们。', 66384),
(283793, 'zhCN', '', '圣光会守护我先祖的土地！', 66384),
(283775, 'zhCN', '我相信洛萨克森曾有一样的感觉。', '', 66384),
(283774, 'zhCN', '', '将我的报告交给洛瑟玛。告诉他……我们别无选择。', 66384),
(283771, 'zhCN', '先去阻止那个被圣光冲昏头的笨蛋。我随后就与你们会合，用披肩削弱风暴。', '', 66384),
(283766, 'zhCN', '你不知道我等待了多久，小小的阿塔哈谢，我等着伙伴前来证明自己的实力，然后回到我的身边。\n\n自从多年前祖尔金和玛拉卡斯那两个叛徒伤了我，我便回到此处观察、等待、疗伤——期盼着会有哈谢前来……\n\n然而我的伙伴遭到了袭击，我的孩子也一样。\n\n我已经放弃了希望。', '', 66384),
(283755, 'zhCN', '', '去把那个逞英雄的老顽固找回来，我要好好教育他一顿。', 66384),
(283754, 'zhCN', '', '我和海尔兰还有暗谷女士走散了。你一定要找到他们。', 66384),
(283753, 'zhCN', '很好。替我告诉阿斯崔，我很抱歉。恐怕我赶不回去喝下午茶了。', '', 66384),
(283752, 'zhCN', '', '不，你们休想从我手中夺走它！', 66384),
(283751, 'zhCN', '', '我要把你们统统喂给野兽。', 66384),
(283749, 'zhCN', '打碎她的玩具，爬上食物链顶端。我们亲爱的小沱兰提亚会把这当成对她的挑战。', '', 66384),
(283748, 'zhCN', '潜入成功。找到那批货物。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(283739, 'zhCN', '', '许多人都见过纳鲁，并将他们视作圣光的化身。可我很清楚，这并不能概括纳鲁的本质。\n\n我如今掌握的魔法能力并不是与生俱来的。我从黑暗纳鲁鲁拉那里获得了真正的力量，她现在就寄宿在我的体内。她是我虚空力量的极大源泉。\n\n为了驾驭这股力量，我经历了漫长而艰辛的过程——并用获得的这股力量来保护我所珍爱的一切。\n\n洛萨克森的想法没错，如果能在对抗萨拉塔斯的战斗中争取到纳鲁的支援，我们就可以扭转颓势。', 66384),
(283738, 'zhCN', '', '过了这么久，又能和儿子团聚，我确实很高兴，可我希望……\n\n<奥蕾莉亚突然移开了视线，皱起了眉头。她叹息一声，恢复了状态。>\n\n没有时间了，我们都必须专心地执行任务。', 66384),
(283735, 'zhCN', '', '<奥蕾莉亚的视线不停地摇摆着。>\n\n小心天空！这里没有任何安全的地方。\n\n我察觉到了一股扰动，以为是更多萨拉塔斯的部队。结果却是你和阿拉托尔。\n\n不久之前，我追踪萨拉塔斯和她的虚灵来到了这个诡异的地方。我一直在猎杀她，但是……\n\n<奥蕾莉亚的声音越发微弱，你注意到她身旁闪烁着紫色的微光。>\n\n这里的虚空过于强大，令人……心神涣散，沉迷其中。\n\n然后你就出现了，阿拉托尔也是。我们必须谨慎行事。', 66384),
(283721, 'zhCN', '不！我们要集中力量发起反击！', '', 66384),
(283713, 'zhCN', '这是一段漫长而艰苦的旅程，我们一路上遭遇了许多艰难险阻。', '', 66384),
(283712, 'zhCN', '不是所有人都听从女神的召唤，但哈籁提一直追随着歌声。', '', 66384),
(283695, 'zhCN', '如此多——如此多的虚空！', '', 66384),
(283691, 'zhCN', '这里是开启传送门最稳固的地点，可殆希莫斯的野兽挡住了去路。', '', 66384),
(283686, 'zhCN', '我需要拿回我的法杖！要是在战斗里把它丢了，埃基尔松就再也不会庇佑我了！', '', 66384),
(283685, 'zhCN', '多谢你清理了道路，陌生人。', '', 66384),
(283684, 'zhCN', '', '但愿祖尔加这次能多带些光木回来。我受够了每天只能用这些边角料。', 66384),
(283682, 'zhCN', '嗯，要驱散掩蔽的迷雾，我是该请求埃基尔松的锐眼还是哈尔拉兹的神视呢？为什么不两个都试试？\n\n对，没错。为什么不两个都用呢？', '', 66384),
(283676, 'zhCN', '<托伦多警惕地打量着你，身体微微一动，似乎在身后藏了什么。>\n\n你是谁？\n\n是离开阿塔阿曼的时候到了吗？', '', 66384),
(283675, 'zhCN', '', '<长者多鲁正全神贯注地从一辆废弃货车上收集光木武器。>\n\n我听见战鼓声了，但这些武器一件也不能少。', 66384),
(283664, 'zhCN', '', '我们可以分头行动，扩大搜索范围。$n和我——', 66384),
(283662, 'zhCN', '', '不行。精灵在祖阿曼乱晃，背后少不了挨刀子。你跟我走。祖尔加，看好她的同伴。', 66384),
(283656, 'zhCN', '', '暮光之刃把纳拉丁赶进了我们的地盘。要想抵达神庙，就得从它们中间杀出一条血路。', 66384),
(283632, 'zhCN', '在寂静时代中，我们感到空虚，渴望获得使命。', '', 66384),
(283630, 'zhCN', '', '我们疲惫不堪，遍体鳞伤。虽然我们赢了莫尔杜恩，但也元气大伤。接下来的战斗我们怎么可能获胜？', 66384),
(283628, 'zhCN', '孩子，战场不是心软的地方。', '', 66384),
(283627, 'zhCN', '$p，海尔兰呢？他是不是……？', '', 66384),
(283620, 'zhCN', '先与最凶狠的猛兽交锋，再将它们驯服。', '', 66384),
(283619, 'zhCN', '我们成长为了森林中最伟大的猎手。', '', 66384),
(283615, 'zhCN', '我们必须优先撤出平民百姓！', '', 66384),
(283614, 'zhCN', '', '我们祈祷奇迹降临，圣光先锋军就响应了召唤。但这场战斗还在继续。', 66384),
(283604, 'zhCN', '无人知道我们存在，那撼动大地的巨人不曾知晓……她的庞然巨兽也不曾知晓。', '', 66384),
(283603, 'zhCN', '不知多少个世代以前，我们一族曾在高山的森林中漫步。', '', 66384),
(283589, 'zhCN', '看过字条了？看来我们又有……下一场“约会”了。', '看过字条了？看来我们又有……下一场“约会”了。', 66384),
(283549, 'zhCN', '我试着给大家争取机会。\n\n<海尔兰沉重地喘息着。>\n\n差点儿就成功了，结果又冒出来了几个。大家都还好吗？', '', 66384),
(283540, 'zhCN', '我已得知你会前来，$n。我们开始吧。', '', 66384),
(283531, 'zhCN', '', '要不是海尔兰引开了巨凶龙，我可能就要丧命了。\n\n他所揭露的虚空，就如同黑日一般。', 66384),
(283529, 'zhCN', '', '我们刚通过大门，巨凶龙就闻到了我们的气味。我们被隔开了，洛萨克森甚至头也没回过。', 66384),
(283528, 'zhCN', '听说了吗？暮翔出口部的船现在就停在港口。', '听说了吗？暮翔出口部的船现在就停在港口。', 66384),
(283527, 'zhCN', '你见过哪个潮生公司船员的家伙不是满身秘密的？', '你见过哪个潮生公司船员的家伙不是满身秘密的？', 66384),
(283503, 'zhCN', '更多的力量。万物终将归于虚空。', '', 66384),
(283462, 'zhCN', '', '我理解光绽的威胁，但我们必须安抚长老，不然你在哈籁恩达尔的敌人又要多一个了。', 66384),
(283437, 'zhCN', '纳鲁是从圣光中诞生的生物，它们是希望的道标——能够在凡人的软弱心灵中激发力量。它们如同凡人之中的神明，是远高于你我的存在。\n\n我不知道虚灵和吞噬军团是从哪里抓获纳鲁的——或许是从偏远的世界上绑架的，也可能是从历经万年的德莱尼分裂派系那里掳获的。那是一群该死的叛徒，但和眼前的局势相比，那只是微不足道的恶行。\n\n我们必须援救这个纳鲁，以免发生最糟糕的结果。只要争取到纳鲁的光辉，虚影风暴的覆灭指日可待。', '', 66384),
(283434, 'zhCN', '不能浪费时间了，流逝的每分每秒都在让我们走向失败。', '', 66384),
(283426, 'zhCN', '所谓的“光绽”不是真正的威胁，也不是你违逆的借口。', '', 66384),
(283423, 'zhCN', '', '$n会找到他们。我们送你去安全的地方。', 66384),
(283416, 'zhCN', '奥威娜？那是谁——你干了什么？', '', 66384),
(283414, 'zhCN', '我不记得上次被拘禁起来是什么时候的事了。这种手段还挺新颖的！\n\n你们说现在该怎么称呼这种材料呢？光接素材？这么一想，它其实和你们那些朋友的光铸手段不太一样。', '', 66384),
(283411, 'zhCN', '这话也该由我来问！在所有回忆之中，都不曾有外来者踏足这片深根区域。\n\n<他眯起了眼睛，随后瞥了一眼奥威娜。>\n\n我是库帕尔。哈拉希尔的护根者。我照料着那些新生的庞大根须——那些延伸至地表居民口中“阿梅达希尔”最远端的根系。', '', 66384),
(283407, 'zhCN', '啊，我才刚开始热身呢。', '', 66384),
(283406, 'zhCN', '', '好，但那些都是我的！别来抢功劳。', 66384),
(283404, 'zhCN', '', '你去啸影山脊的时候，我们自行侦察了一番。在这里聚集的虚空生物实在令人担忧。', 66384),
(283403, 'zhCN', '', '哈拉希尔聚落的人民照顾着这些根须，沿着这条路很快就到了。', 66384),
(283402, 'zhCN', '', '小心脚下，你会被当作入侵者。', 66384),
(283398, 'zhCN', '你做出了正确的，也是唯一的选择。现在我们终于可以反击了。', '', 66384),
(283379, 'zhCN', '', '我们必须阻止他。麦拉，带其他人撤回啸影山脊。', 66384),
(283378, 'zhCN', '如果他破坏了节点，引发的能量涌动会把你那宝贝银月城炸得粉碎。', '', 66384),
(283368, 'zhCN', '奥蕾莉亚，你疯了吗？', '', 66384),
(283367, 'zhCN', '', '这正是殆希莫斯的计划。把特泯纳斯的注意力引到我们身上来，$p。', 66384),
(283364, 'zhCN', '要么自相残杀，要么死。我会先清理掉这些碍事的渣滓。', '', 66384),
(283363, 'zhCN', '我就知道，你对虚空的诡计一无所知！', '', 66384),
(283362, 'zhCN', '', '不，不对劲。这种好戏，殆希莫斯是绝不会错过的。', 66384),
(283361, 'zhCN', '我想不通，他们随时都可以背叛我们，为什么是现在？', '', 66384),
(283360, 'zhCN', '当初就不该信殆希莫斯！', '', 66384),
(283357, 'zhCN', '', '准备好武器，我们这就杀出一条血路，随后再想办法对付殆希莫斯。', 66384),
(283356, 'zhCN', '', '我错过了什么？他们为什么非要等到现在才背叛我们？', 66384),
(283349, 'zhCN', '去拿披肩吧，我们掩护你。', '', 66384),
(283348, 'zhCN', '', '都靠拢。没有人会孤军奋战，没有人会被弃之不顾。', 66384),
(283347, 'zhCN', '那就不要对牺牲变得麻木！我们明明在为同一个目标而战。', '', 66384),
(283346, 'zhCN', '我侍奉圣光数千年。论及对“牺牲”的领悟，你永远无法与我相提并论。', '', 66384),
(283345, 'zhCN', '圣光也并非纯善无害。我亲身感受过它的怒火，目睹过它迫使我们做出的牺牲。', '', 66384),
(283344, 'zhCN', '它腐化一切，扰乱心智，让朋友反目成仇，让是非黑白颠倒。', '', 66384),
(283343, 'zhCN', '虚空不效忠于任何人！', '', 66384),
(283342, 'zhCN', '险境？你宁可相信一个多曼纳尔的鬼话，也不信我。', '', 66384),
(283341, 'zhCN', '', '你留在这里，洛萨克森。你已经让这次任务陷入险境了。', 66384),
(283339, 'zhCN', '无伤大雅的损失。虚空精灵从一开始就知道其中的风险。', '', 66384),
(283338, 'zhCN', '', '你就这样丢下他们了？', 66384),
(283337, 'zhCN', '真是感人肺腑啊。给你个忠告：永远别相信一个假意臣服的多曼纳尔。', '', 66384),
(283336, 'zhCN', '', '等等！我臣服于你的力量。让我为你效力，我们联手——', 66384),
(283335, 'zhCN', '', '向沱兰提亚发起挑战，拿到她的印记。阿拉托尔，我们去上层堡垒与其他人会合。', 66384),
(283333, 'zhCN', '这些俘虏中有些并非来自艾泽拉斯。虚空的暴行到底荼毒了多少个世界？', '', 66384),
(283332, 'zhCN', '', '我们跟着他，女士。朗多雷，随我来。', 66384),
(283331, 'zhCN', '', '现在不是单打独斗的时候！', 66384),
(283330, 'zhCN', '我去解决撕弗鲁姆，壕沟就交给你和这个空灵爪牙了。', '', 66384),
(283329, 'zhCN', '', '沱兰提亚镇守着壕沟，撕弗鲁姆守卫着上层堡垒。', 66384),
(283328, 'zhCN', '', '特泯纳斯不在时，他的副官们控制着宝库的入口。', 66384),
(283327, 'zhCN', '宇宙就是一场盛宴，圣光的小家伙。为何不尽情享用呢？', '', 66384),
(283326, 'zhCN', '我们中有些人的追求可比口腹之欲要高尚多了，野兽。', '', 66384),
(283325, 'zhCN', '我不需要什么主人。我们都应该忠于自己的欲望。', '', 66384),
(283324, 'zhCN', '忠诚这种东西与虚空格格不入，你竟能因为无聊就背叛主人？', '', 66384),
(283323, 'zhCN', '她会把一切都变成空洞的深渊。你能想象比这更无聊的结局吗？', '', 66384),
(283322, 'zhCN', '萨拉塔斯要吞噬你们的世界，以及所有的世界，甚至群星也不放过。', '', 66384),
(283321, 'zhCN', '看着你们在这冷漠的宇宙中奋力挣扎，像火焰一样燃烧——那滋味真是美妙。', '', 66384),
(283320, 'zhCN', '一个毫无目标的生物，和所有来自虚空的恶魔一样。', '', 66384),
(283319, 'zhCN', '我是个被激情驱使的生物。', '', 66384),
(283318, 'zhCN', '你为什么这么急着帮我们？', '', 66384),
(283316, 'zhCN', '偷走掠食披肩，我们就能进入节点，削弱风暴。哈，特泯纳斯必将颜面扫地。', '', 66384),
(283315, 'zhCN', '算我们运气好，他正忙得不可开交，宝库无人看守。', '', 66384),
(283314, 'zhCN', '“领主”特泯纳斯。他把披肩藏在胧影堡垒里。', '', 66384),
(283313, 'zhCN', '有了它，你就能进入并直接关闭节点。关掉一个，其他的就会因连锁反应接连失效。', '', 66384),
(283312, 'zhCN', '削弱风暴的关键，在于一件名为“掠食披肩”的神器。', '', 66384),
(283311, 'zhCN', '然后引发能量涌动，把你那宝贝银月城夷为平地？还是安全地关掉它们吧——放过你那可怜的城市。', '', 66384),
(283310, 'zhCN', '为什么只想着关闭节点？我们应该从内部将它们彻底摧毁。', '', 66384),
(283307, 'zhCN', '来吧，$p，我有许多东西要给你看看。', '', 66384),
(283306, 'zhCN', '别客气，就当自己家。然后，我们来谈谈怎么削弱这场风暴。', '', 66384),
(283305, 'zhCN', '啊，我们的其他队友总算到了。要不是时间紧迫，我真想邀请你们共进晚餐。', '', 66384),
(283303, 'zhCN', '你真要跟着这个生物，钻进它肮脏的巢穴里去？', '', 66384),
(283197, 'zhCN', '萨拉塔斯掌控了一切。我们的族人都迷失了。', '萨拉塔斯掌控了一切。我们的族人都迷失了。', 66384),
(283190, 'zhCN', '', '祖尔加，等战鼓响起，增援部队就会在中央祭坛集结。', 66384),
(283179, 'zhCN', '', '神圣烈焰在上，我们差点被吞噬军团淹没了。我拼命挡住黑暗浪潮，为安度因治疗伤者抢到了时机。\n\n欣慰的是还有其他人应召前来守护这片圣土。我能做什么？', 66384),
(283177, 'zhCN', '很高兴见到你，$p！\n\n在这黑暗与虚空笼罩之下，圣光燃烧得更炽烈了，你觉得呢？虽然我这不死之躯总是被它灼痛，但吞噬军团承受的痛苦远甚于我。', '', 66384),
(283169, 'zhCN', '是$p！圣光不只召来了信徒，连艾泽拉斯的勇士都应召而至。\n\n我原以为自己会孤军奋战、势单力薄，但有你加入，我们就能转守为攻了！', '', 66384),
(283168, 'zhCN', '', '是虚空野兽！当心！', 66384),
(283159, 'zhCN', '虚影风暴令整座城提心吊胆也是有理由的。', '', 66384),
(283125, 'zhCN', '恶魔，你敢耍任何花招，我就用圣光将你烧为灰烬。', '', 66384),
(283123, 'zhCN', '如此强大的力量，如此超凡的智慧！看来，违抗你的确是愚蠢的做法！', '', 66384),
(283120, 'zhCN', '不！别让它跑了！ ', '', 66384),
(283119, 'zhCN', '哎呀，真是一场酣畅淋漓的血浴！可惜，我恐怕得先失陪了。', '', 66384),
(283118, 'zhCN', '$p，先干掉它的宠物！ ', '', 66384),
(283117, 'zhCN', '艾泽拉斯人！哦，你们一定会成为我精美的战利品。', '', 66384),
(283113, 'zhCN', '你想活捉它？我宁愿一把火把它烧成灰。', '', 66384),
(283112, 'zhCN', '', '它们居然会囚禁自己的同类？真有意思。而且有些看起来还很心甘情愿。 ', 66384),
(283111, 'zhCN', '$p，这些邪恶的怪物根本不是我们的对手！ ', '', 66384),
(283110, 'zhCN', '$p，目标就在前方！让我们联手干掉它！', '', 66384),
(283109, 'zhCN', '', '我们必须小心。我之前试过单独潜入，但都失败了。', 66384),
(283108, 'zhCN', '已经没时间瞻前顾后了。我们要直捣他们的首领，从它嘴里撬出我们需要的情报！', '', 66384),
(283107, 'zhCN', '', '阿拉托尔，你不该来这里的。这里的虚空之力太强大了。', 66384),
(283105, 'zhCN', '你要搞清楚，奥蕾莉亚，这次任务由我指挥。当然，我很欢迎你的协助。 ', '', 66384),
(283099, 'zhCN', '阿拉托尔，这就是奥蕾莉亚拼命想让你远离的东西——彼端的黑暗。 ', '', 66384),
(283097, 'zhCN', '太痛苦了……比我们最初在泰洛古斯被虚空转化时还要痛苦。但我会——我一定会挺过去的，海尔兰。 ', '', 66384),
(283096, 'zhCN', '', '这感觉就像溺水，只能胡乱地挥舞手臂……但我们必须学会游泳。 ', 66384),
(283095, 'zhCN', '', '永晨——不！该死！', 66384),
(283094, 'zhCN', '', '我们得侦察……对。没错，侦察前方……', 66384),
(283093, 'zhCN', '我们必须先摸清地形。跟上！ ', '', 66384),
(283088, 'zhCN', '传送门打开了。鼓起勇气吧……对面只有无尽的黑暗在等着我们。', '', 66384),
(283085, 'zhCN', '你们朗多雷或许是我们对抗虚空最强大的利器。我发誓，我会拼尽全力保护你们。 ', '', 66384),
(283078, 'zhCN', '高阶指挥官洛萨克森曾征战过无数个异界，所以我请他来领导这次任务。 ', '', 66384),
(283077, 'zhCN', '过来，$p，帮我校准一下这个法术。一旦灾难发生，它能将我们传送回魔导师平台。', '', 66384),
(283076, 'zhCN', '你做了必须做的事，乌布里克。要阻止虚影风暴，我们只能冲进去。 ', '', 66384),
(283070, 'zhCN', '我好久都没见过这里的墙壁了。', '', 66384),
(283069, 'zhCN', '是有风险，摄政王阁下。但这也是为银月城解围的唯一方法。 ', '', 66384),
(283068, 'zhCN', '用一件虚空的遗物来突破风暴……风险似乎很高，乌布里克。', '', 66384),
(283067, 'zhCN', '$p，我找到了进入风暴的办法，就是稍微有些……难办。', '', 66384),
(283055, 'zhCN', '真了不起。你还在超越我的期望。', '', 66384),
(283054, 'zhCN', '', '你要的是力量，殆希莫斯。萨拉塔斯给不了你，她的失败却可以。和我们联手吧。', 66384),
(283053, 'zhCN', '……是看穿我了吗？', '', 66384),
(283052, 'zhCN', '', '我们更不能把潜在的盟友变成敌人。殆希莫斯不只是表面上那么简单。', 66384),
(283051, 'zhCN', '圣光慈悲，我命令你们两个住手！我们的敌人已经够多了！', '', 66384),
(283050, 'zhCN', '我已在圣光中重铸！是你看不清真相。', '', 66384),
(283049, 'zhCN', '对暗影心生不安，是因为恐惧还是欺诈呢？你真是个特别的纳斯雷兹姆啊，洛萨克森。', '', 66384),
(283048, 'zhCN', '阿拉托尔，你可是一名圣骑士啊！你难道看不出殆希莫斯这个怪物的真面目吗？', '', 66384),
(283046, 'zhCN', '我们必须行动！', '', 66384),
(283045, 'zhCN', '是你在暗地里分化我们！彻底消亡吧，殆希莫斯！', '', 66384),
(283044, 'zhCN', '你一定也感觉到了，$n。一场预谋的背叛。我知道该怎么做了。', '', 66384),
(283043, 'zhCN', '怎么会出了如此大错？我们毫无进展，如何才能将圣光军团带到这个世界？', '', 66384),
(283042, 'zhCN', '我很期待看到你们下一次展现的凶暴力量。', '', 66384),
(283041, 'zhCN', '你和风行者女士真是太奇妙了。我虽然见多识广，却还没见过这样神通广大的凡人。', '', 66384),
(283040, 'zhCN', '坚持住，阿斯崔。抓紧我的手。', '', 66384),
(283038, 'zhCN', '', '虚空的低语越来越诱人，但我们依旧意志坚定。这就是我们的使命。', 66384),
(283023, 'zhCN', '我会的，我一定。', '', 66384),
(283022, 'zhCN', '', '阿拉托尔，别让殆希莫斯受到任何伤害。我们需要的答案就在它身上，相信我。', 66384),
(283021, 'zhCN', '母亲，你承受的苦难……我们必须立即撤退休整。', '', 66384),
(283014, 'zhCN', '', '阿拉托尔！不！', 66384),
(283013, 'zhCN', '虚空！太强大了！', '', 66384),
(283012, 'zhCN', '', '不是她死就是我们亡！必须战斗到底！', 66384),
(283010, 'zhCN', '不！你……必须……！', '', 66384),
(283009, 'zhCN', '', '至明之光照耀，至暗之影降临。', 66384),
(283008, 'zhCN', '我绝不能容忍！', '', 66384),
(283004, 'zhCN', '', '不，洛萨克森！$n，我们需要你去盯着。', 66384),
(283003, 'zhCN', '已经拖得太久了。都让开，我来把这鬼东西砸开。', '', 66384),
(283002, 'zhCN', '我受够你的含沙射影了，萨拉塔斯！你会得到纳鲁，欠我的也都要给我！', '', 66384),
(283001, 'zhCN', '', '你的敌人速度很快，萨哈达尔。你最好加倍努力地转化纳鲁，否则就又要功亏一篑了。', 66384),
(283000, 'zhCN', '', '可惜奥蕾莉亚非死不可。和这个相比，她的黑暗纳鲁是一件更有效的武器。', 66384),
(282998, 'zhCN', '他们阻止不了我！这次不行！影卫，消灭他们！', '', 66384),
(282996, 'zhCN', '', '用你的热情对付敌人吧，洛萨克森。也别忘记了，我不是你的敌人。', 66384),
(282995, 'zhCN', '阿拉托尔，去盯紧你的母亲和她自命不凡的猎犬。我不想让它遮蔽圣光的气息。', '', 66384),
(282994, 'zhCN', '在那！就关在护盾里面！', '', 66384),
(282993, 'zhCN', '离纳鲁远点，空灵爪牙！你根本不配沐浴在它的光辉之下！', '', 66384),
(282991, 'zhCN', '他们休想得逞。我与你同在，洛萨克森。', '', 66384),
(282990, 'zhCN', '他们抓获了一个纳鲁？决不能让这些怪物控制纯粹的圣光造物！', '', 66384),
(282989, 'zhCN', '风行者休想阻止我转化纳鲁，倒向虚空。许诺给我的力量，我一定要得到！', '', 66384),
(282988, 'zhCN', '圣光必胜。我想殆希莫斯甚至都不会有还手之力。', '', 66384),
(282987, 'zhCN', '在圣光中燃烧吧，异端！', '', 66384),
(282986, 'zhCN', '', '这么说来，除掉她才最符合你的利益，对吧？你已经任由她在暗处作祟太久了。', 66384),
(282985, 'zhCN', '你以为我看不穿你设下的圈套吗？如果我们在米达尔的行动失败了，我的族人将面临怎样的危机？', '', 66384),
(282984, 'zhCN', '', '你这样的王者不该忘恩负义，萨哈达尔。我给你的礼物很珍贵：一个证明你有统治权的机会。', 66384),
(282983, 'zhCN', '这和给我的承诺不一样！我们无休无止地辛劳，却要遭到你们这些怪物的监视！', '', 66384),
(282982, 'zhCN', '那有什么关系？我们把需要的都夺走，然后将熔炉夷为平地。他们就带着秘密葬身火海吧。', '', 66384),
(282981, 'zhCN', '', '萨拉塔斯不会平白无故地放过敌人。去查明那些虚灵到底有什么企图。', 66384),
(282977, 'zhCN', '我也正想那么说呢。', '', 66384),
(282976, 'zhCN', '', '我们要夺取容器，再瓦解他们的行动。阿拉托尔，跟紧我。', 66384),
(282974, 'zhCN', '呵，虚灵。他们是萨拉塔斯不久之前才带到这里的。', '', 66384),
(282970, 'zhCN', '', '斥候发现南方有一处虚灵的法力熔炉。但他们的意图还不明朗。', 66384),
(282950, 'zhCN', '', '哈籁恩达尔是个危险的地方。', 66384),
(282688, 'zhCN', '', '射日者，你已经很走运了。都过了这么多年，我们也没有没收你的屋子。', 66384),
(282683, 'zhCN', '', '我需要通知你们，落毛凤凰不欢迎二位入内了。走好不送。', 66384),
(282544, 'zhCN', '呃，差不多吧。\n\n<他翻到了册子的后面。册子里贴着吉德文和塔伦纳在许多风景名胜、热门景点和酒吧留下的照片。每张照片下面还有一行简短的文字。>\n\n同时还是一本旅行日志。', '', 66384),
(282531, 'zhCN', '哦，就这本。\n\n<吉德文掏出了那本册子，随便翻开了一页。>\n\n我们详细记录了许多事情，比如我们点的每一杯酒……至少记得住的那些全都抄下来了。\n\n<他自豪地点着其中一条。>\n\n那一周啊，我接连三天喝趴了塔伦纳！', '', 66384),
(282529, 'zhCN', '你了解过房产的价格吗？我在利率不高的时候就买下了这里，现在行情大涨，它的价值远超我的买入价。\n\n不过我们一直都在路上，很难打理好这个地方。吉德文说我应该把房子卖了。\n\n我也许应该将房子短租出去，不如就叫“飞行租屋”吧。\n\n不对，这听起来就成马戏团了。我得再研究一下。', '', 66384),
(282522, 'zhCN', '再次感谢你的帮助，$p。我们把所有纪念品都邮寄出去了，接下来只要将这里收拾干净就好。', '', 66384),
(282516, 'zhCN', '这地方总算是打扫好了。我们还收到了一张金币支票，因为卖掉项链的钱在付清旧账后还有剩余。这你能信？\n\n<塔伦纳哈哈大笑。>\n\n看来支票的主人很高兴能把握商机。', '', 66384),
(282515, 'zhCN', '你是说为什么我们一走了之，而且没人把东西都收走？\n\n<吉德文思索了片刻。>\n\n他怎么不干脆卖掉这里？我们都没怎么待过，他却任由房子空置，还不停地为它掏钱。\n\n总之，第四次战争突然爆发的时候，我们匆忙间逃出了这座城，根本就来不及打扫。\n\n<他回过头去盯着蜘蛛。>\n\n那鬼东西肯定摆弄过我们的药水。', '', 66384),
(282512, 'zhCN', '我不会把这里全打扫干净，不过我得找些东西来结清旧账。', '', 66384),
(282498, 'zhCN', '噢，那咱们就去那儿吧！只要能喝杯麦酒，你的取笑听起来都悦耳多了。', '', 66384),
(282497, 'zhCN', '唔……他们估计会放我进去，你恐怕不行，你的身高不够格。', '', 66384),
(282496, 'zhCN', '是啊，我们上次来这儿是多久以前的事了？你说荆棘酒泉会放我们进去吗？', '', 66384),
(282495, 'zhCN', '噢！那里面记录着很多美好的回忆，还有几次不幸的遭遇。', '', 66384),
(282494, 'zhCN', '那屋子简直乱套了，但那本旅行时的日志可算是找着了。', '', 66384),
(282492, 'zhCN', '吉德文低声嘟囔着，仿佛在为自己辩解。', '', 66384),
(282491, 'zhCN', '所以……你们遇到了什么情况？吉德文，你胡子上粘着的是蛛网吗？', '', 66384),
(282490, 'zhCN', '', '终于结束了。谢谢，你们的陈年旧账到此为止了。', 66384),
(282487, 'zhCN', '给，这肯定足够结清我们欠的旧账……连本带利一起的。', '', 66384),
(282408, 'zhCN', '击倒我的不是虚空，而是圣光本身。我眼前一片模糊，却释放出一股力量……就像烈火在燃烧。等我回过神来，敌人全被摧毁了。\n\n抱歉，$p。但那种感觉已经过去了。现在我们必须全力援助银月城的人民。', '', 66384),
(282366, 'zhCN', '啊？！我得到教训了！要时刻提防黏糊的蛛网。', '', 66384),
(282365, 'zhCN', '嗷，这下好多了。', '', 66384),
(282338, 'zhCN', '这位朋友会帮助吉德文付账。看来不用等太久了。', '', 66384),
(282078, 'zhCN', '你看着不像学生。你来这儿做什么？', '你看着不像学生。你来这儿做什么？', 66384),
(282077, 'zhCN', '你难道看不出我正忙着吗？', '你难道看不出我正忙着吗？', 66384),
(282076, 'zhCN', '天哪，真希望泰特勒能注意到我！说不定我还能晋升到二级高级追随者呢！', '天哪，真希望泰特勒能注意到我！说不定我还能晋升到二级高级追随者呢！', 66384),
(282075, 'zhCN', '哼，想必你就是泰特勒新收的玩物吧？', '哼，想必你就是泰特勒新收的玩物吧？', 66384),
(282074, 'zhCN', '你这种货色找我有什么事？', '你这种货色找我有什么事？', 66384),
(282073, 'zhCN', '没看到我正忙着吗？你有什么事？', '没看到我正忙着吗？你有什么事？', 66384),
(281794, 'zhCN', '', '你想夺走这座城市渴求的力量？见识一下我的力量吧！', 66384),
(281787, 'zhCN', '', '混账！', 66384),
(281780, 'zhCN', '到此为止了，利希尔！', '', 66384),
(281764, 'zhCN', '', '只要银月城还需要邪能，我就要满足他们的需求。', 66384),
(281459, 'zhCN', '就为这个？', '', 66384),
(281458, 'zhCN', '又怎么了？', '', 66384),
(281425, 'zhCN', '', '干掉他们！要是他们跟上来，我拿你是问！', 66384),
(281394, 'zhCN', '我才没有输——我只是选择战略性撤退！', '', 66384),
(281393, 'zhCN', '不！这……这还没完！', '', 66384),
(281391, 'zhCN', '什么人？谁让你进来的？', '', 66384),
(281390, 'zhCN', '', '太大意了，赞恩。收拾好了再到楼上见我。', 66384),
(281369, 'zhCN', '', '行动起来，保护自己吧！', 66384),
(281368, 'zhCN', '', '我就用你来惩一儆百。', 66384),
(281223, 'zhCN', '', '你真的以为那么轻松就能逮住我？', 66384),
(280973, 'zhCN', '魔导师平台。\n\n我的青春岁月在此度过，还掌握了最早一批法术。仲夏舞会上，我和萨洛法·金纱共舞，那种感觉……\n\n<乌布里克长叹一口气。>\n\n那些日子一去不返了。这地方变了样，我也不是从前的我。我和我的族人不再受到欢迎。\n\n逝去的无法挽回。朗多雷必须开创自己的传统——组建自己的家庭。\n\n塑造我们自己的未来。', '', 66384),
(280965, 'zhCN', '我族的不朽回忆寄存于此，这是个迎接挑战与试炼的地方。\n\n在这里，你将沐浴在艾林哈籁的恩典之中，亦或被她毁灭。', '', 66384),
(280963, 'zhCN', '奥威娜违背了我们的律法和习俗。回响之穴会让你明白我们的法则，并让你在考验中证明自己。\n\n如果你能平安归来，那就意味着艾林哈籁允许你留在这里。我并不期待着重逢的那一天。', '', 66384),
(280955, 'zhCN', '回响之穴是存放我们族人回忆的秘库之一。我们会重新体验先祖的事迹与试炼，并由此学习和成长，确保历史不会反复上演。\n\n这些涂绘是通往回忆和试炼的大门。如果你能坚持到底，就能更深入地了解哈籁恩达尔和我的族人。\n\n触碰石头就能激活幻象了。愿艾林哈籁与你同在。', '', 66384),
(280860, 'zhCN', '', '如此纯粹的力量，连虚空也无法抗衡！', 66384),
(280686, 'zhCN', '这儿比平时还要繁忙。我们要赶快行动。', '', 66384),
(280669, 'zhCN', '<当你靠近时，祝福祭坛焕发了光彩。>', '<当你靠近时，祝福祭坛焕发了光彩。>', 66384),
(280626, 'zhCN', '$p，没想到这里的血色十字军这么活跃。\n\n血色十字军遭受了不少挫败，但看起来又在重新壮大了。', '', 66384),
(280596, 'zhCN', '', '我们动身去哈拉希尔吧。恐怕我们不会得到热情的接待。\n\n去找哈杜伦，看看他是否准备好出发了。', 66384),
(280573, 'zhCN', '你也瞧见了，不是每个人都适合干这一行的。', '', 66384),
(280572, 'zhCN', '我们的设备失灵了，有几名队员被意外传入了无拘之域中。你能把我们的相位潜者送回现实世界吗？', '', 66384),
(280528, 'zhCN', '密谋小径今天格外热闹——我们必须谨慎行事。\n\n我们必须终结这个走私集团。要做到这一点，就得找到“非法降雨”组织。有消息说附近一些混混可能知道最近邪能活动激增的内情。\n\n去找到他们，看能打听到什么线索。千万小心。密谋小径的这帮不法分子从来都靠不住。', '', 66384),
(280415, 'zhCN', '$p，你对太阳之井的帮助实在珍贵。不过我们还需要为阿拉托尔做更多的事。\n\n你愿意和我们一起去落锤镇，拜访一位朋友吗？', '', 66384),
(280340, 'zhCN', '', '虚空赐予了我们力量，可代价是什么呢？', 66384),
(280227, 'zhCN', '', '居然敢来瞎管闲事？出来面对我吧，偷窥狂！', 66384),
(280214, 'zhCN', '未来纷繁错乱……你真的做好准备窥探自己的宿命了吗？', '未来纷繁错乱……你真的做好准备窥探自己的宿命了吗？', 66384),
(280008, 'zhCN', '完美！报酬？你们可以凭借此事提高知名度的！', '', 66384),
(280003, 'zhCN', '', '他们丢下要塞落荒而逃了。但我很熟悉影卫，他们很快就会卷土重来的。', 66384),
(279791, 'zhCN', '解决了一个特工。很好。现在前往非法降雨酒吧。\n\n但你这副样子肯定会被拒之门外。幸运的是，我设法……弄到了一些伪装给你。\n\n穿上衣服然后进去。我会在外面挡住疑似的刺客。', '', 66384),
(279591, 'zhCN', '这些动物没有遭受永久性的伤害。感谢你把它们找了回来。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(279589, 'zhCN', '有些生物溜出了生态圆顶。它们没法在废土中生存下去，快去把它们找回来！', '', 66384),
(279487, 'zhCN', '你来晚了。没看见顾客都排队等着了吗？赶紧回到自己的位置上。', '', 66384),
(279110, 'zhCN', '而我……我会让音乐响彻这些大厅，直到她们回家。谢谢你们，勇士。', '', 66384),
(279109, 'zhCN', '我希望有朝一日，我的姐姐们也能如此宁静。', '', 66384),
(279108, 'zhCN', '终于……在大厅中徘徊不去的灵魂获得了宁静。', '', 66384),
(279102, 'zhCN', '在那！纠缠着我们的无眠之心！请你让它安息吧。', '', 66384),
(279051, 'zhCN', '我要用这些遗物，让高塔重获宁静，那样姐姐们也许就能回来了。', '', 66384),
(279050, 'zhCN', '成功了！就剩最后一个任务了。', '', 66384),
(279049, 'zhCN', '奥蕾莉亚的一张侦察地图就在里面。它似乎引来了昔日的复仇之灵。我们要从他们手里拿到地图。', '', 66384),
(279014, 'zhCN', '因为他们夺走了我的性命，蹂躏了我们的家。', '', 66384),
(279013, 'zhCN', '奥蕾莉亚狩猎旧部落的成员时凶狠无情，几近痴迷。', '', 66384),
(279011, 'zhCN', '来吧，还有一件遗物要找。', '', 66384),
(278997, 'zhCN', '太棒了！她让我想起了温蕾萨。如果家人受到威胁，姐姐也会和她一样奋不顾身。', '', 66384),
(278992, 'zhCN', '好吧，我的竖琴看来是被那只龙鹰偷走了。不打一场，它是不会让你靠近的。', '', 66384),
(278991, 'zhCN', '我用竖琴弹出的宁静曲调为温蕾萨带来过无法想象的喜悦。我需要这件遗物。', '', 66384),
(278990, 'zhCN', '温蕾萨维护着我们家族的和平。她花了很多时间打理这里的花园，可现在这里还是没入了荒野。', '', 66384),
(278985, 'zhCN', '来，我们去找下一个遗物。', '', 66384),
(278983, 'zhCN', '希尔瓦娜斯偶尔会有些自负，她喜欢受人仰慕，却从不希望受到崇拜。', '', 66384),
(278964, 'zhCN', '曾几何时，母亲的弓就是希尔瓦娜斯的一切。我需要它。', '', 66384),
(278959, 'zhCN', '她训练时用的是母亲送她的弓。狂热的亡灵入侵这里就是为了夺走它，还有其它曾经属于她的东西。', '', 66384),
(278952, 'zhCN', '希尔瓦娜斯本不想成为游侠将军，可她为这份职责献出了一切……乃至生命。', '', 66384),
(278951, 'zhCN', '游侠将军必须敏锐而忠诚，和平卫士则需要沉着冷静。你会选择哪条道路呢?', '', 66384),
(278948, 'zhCN', '姐姐们是最后才到访这些大厅的，但她们将家园和亲情都抛下了。如果我们能安抚这里的灵魂，她们也许还能回来。', '', 66384),
(268910, 'zhCN', '我似乎把新弄到的战利品搞丢了。你能不能晚点再来？', '', 66384),
(250693, 'zhCN', '', '有个大家伙已经冒头了，这可能是一辈子绝无仅有的发现。开始动手吧！', 66384),
(222843, 'zhCN', '', '这样就能给我们一丝喘息的空间。红龙军团欠你一份情。', 66384),
(222842, 'zhCN', '', '红玉新生圣地的守卫一直在抵挡拜荒者的进攻，形式越来越严峻。请你帮帮他们吧。', 66384);
